INSERT OR REPLACE INTO regions (id, slug, name, name_en, color, display_order) VALUES ('mekong-delta', 'mekong-delta', 'Đồng bằng sông Cửu Long', 'Mekong Delta', '#5d9e86', 7);
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('an-giang', 'mekong-delta', 'An Giang', 'An Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.1802, 10.5135, 'Miền đất Bảy Núi linh thiêng với rừng tràm Trà Sư, miếu Bà Chúa Xứ và mùa nước nổi trù phú.', 'An Giang là vùng đất đầu nguồn sông Cửu Long, nơi có vùng Bảy Núi (Thất Sơn) huyền bí và những cánh đồng lúa bát ngát. Rừng tràm Trà Sư xanh mướt mùa nước nổi, miếu Bà Chúa Xứ Núi Sam linh thiêng thu hút hàng triệu khách hành hương. Đây cũng là nơi giao thoa văn hóa của người Kinh, Khmer, Chăm và Hoa, tạo nên bản sắc đa dạng và những lễ hội đặc sắc.', 'Tháng 9–11, mùa nước nổi', '["Bún cá Châu Đốc","Mắm Châu Đốc","Bò bảy món Núi Sam","Đường thốt nốt","Bánh bò thốt nốt"]', '{"en":{"summary":"The sacred land of the Seven Mountains, with the Tra Su cajuput forest, Ba Chua Xu Temple and a bountiful flood season.","story":"An Giang is the headwater land of the Mekong River, home to the mystical Seven Mountains (That Son) region and vast rice fields. The lush Tra Su cajuput forest in flood season and the sacred Ba Chua Xu Temple of Sam Mountain draw millions of pilgrims. This is also a meeting point of the Kinh, Khmer, Cham and Hoa cultures, creating a diverse identity and distinctive festivals.","bestTime":"September–November, flood season","specialties":["Chau Doc fish noodle soup","Chau Doc fermented fish","Nui Sam seven-course beef","Palm sugar","Palm-sugar steamed cake"]},"ko":{"summary":"짜스 멜라루카 숲, 바쭈아쓰 사당, 풍요로운 물난리 철을 간직한 칠산(七山)의 성스러운 땅.","story":"안장은 메콩강 상류의 땅으로, 신비로운 칠산(텃선) 지역과 드넓은 논이 펼쳐집니다. 물난리 철 싱그러운 짜스 멜라루카 숲과 영험한 삼산 바쭈아쓰 사당이 수백만 순례객을 끌어모읍니다. 이곳은 또한 낀·크메르·짬·화 문화가 어우러지는 곳으로, 다채로운 정체성과 특색 있는 축제를 빚어냅니다.","bestTime":"9~11월, 물난리 시기","specialties":["쩌우독 생선 국수(분까)","쩌우독 발효 생선(맘)","누이삼 소고기 칠미","팔미라야자 설탕(드엉텃놋)","팔미라야자 찐빵(바인보텃놋)"]},"ja":{"summary":"チャースー・メラルーカ林、バーチュアスー廟、豊かな増水期を擁する七山の聖なる地。","story":"アンザンはメコン川上流の地で、神秘的な七山（タットソン）地域と広大な稲田が広がります。増水期のみずみずしいチャースー・メラルーカ林と、霊験あらたかなサム山バーチュアスー廟が数百万の巡礼者を引き寄せます。ここはまたキン・クメール・チャム・華の文化が交わる地で、多彩なアイデンティティと特色ある祭礼を織りなします。","bestTime":"9〜11月、増水期","specialties":["チャウドックの魚麺（ブンカー）","チャウドックの発酵魚（マム）","ヌイサムの牛肉七品","パルミラヤシの砂糖（ドゥオンタットノット）","パルミラヤシの蒸し菓子（バインボータットノット）"]},"zh":{"summary":"七山灵秀之地，拥有茶师白千层林、主处圣母庙和富饶的涨水季。","story":"安江是湄公河上游之地，拥有神秘的七山地区和辽阔的稻田。涨水季节翠绿的茶师白千层林，以及灵验的森山主处圣母庙，吸引着数百万朝圣者。这里也是京、高棉、占、华文化交汇之地，造就了多元的特色和独特的节庆。","bestTime":"9月至11月，涨水季节","specialties":["朱笃鱼米粉","朱笃鱼酱","森山牛肉七味","棕榈糖","棕榈糖发糕"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ba-ria-vung-tau', 'southeast', 'Bà Rịa - Vũng Tàu', 'Ba Ria - Vung Tau', 'Đông Nam Bộ', '#b07a4a', 107.2803, 10.5857, 'Tỉnh ven biển miền Đông với thành phố biển Vũng Tàu sầm uất và quần đảo Côn Đảo hoang sơ huyền thoại.', 'Bà Rịa – Vũng Tàu là cửa ngõ biển của miền Đông Nam Bộ, nơi thành phố Vũng Tàu hào sảng đón du khách bằng những bãi tắm dài, hải sản tươi ngon và tượng Chúa Kitô sừng sững trên núi. Ngoài khơi, quần đảo Côn Đảo vừa thiêng liêng với di tích lịch sử, vừa nguyên sơ với biển xanh và rùa biển. Đây là vùng đất của biển cả, dầu khí và những chuyến nghỉ dưỡng cuối tuần thân quen của người phương Nam.', 'Tháng 11 đến tháng 4 (mùa khô, biển êm)', '["Bánh khọt Vũng Tàu","Hải sản tươi sống","Mứt hạt bàng Côn Đảo"]', '{"en":{"summary":"A coastal southeastern province with the bustling seaside city of Vung Tau and the pristine, legendary Con Dao archipelago.","story":"Ba Ria–Vung Tau is the maritime gateway of the southeast, where the warm-hearted city of Vung Tau welcomes visitors with long beaches, fresh seafood and the Christ the King statue towering on the mountain. Offshore, the Con Dao archipelago is at once sacred with its historic relics and pristine with blue seas and sea turtles. This is a land of the sea, oil and gas, and the familiar weekend getaways of southerners.","bestTime":"November to April (dry season, calm seas)","specialties":["Vung Tau banh khot","Fresh live seafood","Con Dao sea-almond candy"]},"ko":{"summary":"번화한 해변 도시 붕따우와 청정하고 전설적인 꼰다오 군도를 품은 동남부 연안 성.","story":"바리아-붕따우는 동남부의 바다 관문으로, 호방한 붕따우시가 긴 해변과 싱싱한 해산물, 산 위에 우뚝 솟은 예수상으로 여행객을 맞이합니다. 앞바다의 꼰다오 군도는 역사 유적으로 영험하면서도 푸른 바다와 바다거북으로 원시적입니다. 이곳은 바다와 석유·가스의 땅이자, 남부 사람들의 친숙한 주말 휴양지입니다.","bestTime":"11월~4월 (건기, 잔잔한 바다)","specialties":["붕따우 반콧","싱싱한 활해산물","꼰다오 바다아몬드 잼"]},"ja":{"summary":"賑わう海辺の街ブンタウと、手つかずで伝説的なコンダオ群島を擁する東南部の沿岸省。","story":"バリア・ブンタウは東南部の海の玄関口で、大らかなブンタウ市が、長いビーチや新鮮な海の幸、山の上にそびえるキリスト像で旅人を迎えます。沖合のコンダオ群島は、歴史遺跡によって神聖でありながら、青い海とウミガメによって手つかずでもあります。ここは海と石油・ガスの地であり、南部の人々の馴染み深い週末の保養地です。","bestTime":"11月〜4月（乾季、海が穏やか）","specialties":["ブンタウのバインコット","新鮮な活魚介","コンダオの海アーモンドの砂糖漬け"]},"zh":{"summary":"东南部的滨海省份，拥有繁华的海滨城市头顿和原始而传奇的昆岛群岛。","story":"巴地头顿是东南部的海上门户，豪爽的头顿市以绵长的海滩、鲜美的海产和矗立山巅的基督像迎接游客。海面之外的昆岛群岛，既因历史遗迹而神圣，又因碧海与海龟而原始。这里是海洋与油气之乡，也是南方人熟悉的周末度假地。","bestTime":"11月至4月（旱季，海面平静）","specialties":["头顿小煎饼","鲜活海产","昆岛榄仁果脯"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('bac-giang', 'northeast', 'Bắc Giang', 'Bac Giang', 'Đông Bắc', '#4f7b6a', 106.4785, 21.3589, 'Vùng đất giàu di sản tâm linh với Tây Yên Tử, chùa Vĩnh Nghiêm chốn tổ Trúc Lâm và những vườn vải thiều Lục Ngạn trứ danh.', 'Bắc Giang là tỉnh trung du Đông Bắc giàu giá trị lịch sử và tâm linh. Nơi đây có Khu du lịch Tây Yên Tử gắn với con đường hoằng dương Phật pháp của Phật hoàng Trần Nhân Tông, chùa Vĩnh Nghiêm chốn tổ Thiền phái Trúc Lâm lưu giữ mộc bản được UNESCO ghi danh. Bắc Giang còn nổi tiếng với vải thiều Lục Ngạn ngọt lịm, những vườn cây trĩu quả và các lễ hội truyền thống đặc sắc, là điểm đến của hành trình về nguồn cội văn hóa.', 'Tháng 1 đến tháng 3 âm lịch', '["Vải thiều Lục Ngạn","Mỳ Chũ","Bánh đa Kế","Rượu làng Vân"]', '{"en":{"summary":"A land rich in spiritual heritage with Tay Yen Tu, Vinh Nghiem Pagoda — seat of Truc Lam — and the famous Luc Ngan lychee orchards.","story":"Bac Giang is a northeastern midland province rich in historical and spiritual value. Here lies the Tay Yen Tu tourism site, tied to the Dharma-spreading path of Buddha-King Tran Nhan Tong, and Vinh Nghiem Pagoda, seat of the Truc Lam Zen school, which holds UNESCO-inscribed woodblocks. Bac Giang is also famous for sweet Luc Ngan lychees, orchards heavy with fruit and distinctive traditional festivals, a destination on the journey back to cultural roots.","bestTime":"The first to third lunar month","specialties":["Luc Ngan lychees","Chu noodles","Ke rice crackers","Van village wine"]},"ko":{"summary":"떠이옌뜨, 쭉럼 본산 빈응이엠 사원, 유명한 룩응안 여지 과수원을 품은 영성 유산이 풍부한 땅.","story":"박장은 역사적·영성적 가치가 풍부한 동북부 구릉 성입니다. 이곳에는 쩐년똥 불황의 포교의 길과 얽힌 떠이옌뜨 관광지, 유네스코 등재 목판을 소장한 쭉럼 선종의 본산 빈응이엠 사원이 있습니다. 박장은 또한 달콤한 룩응안 여지, 주렁주렁 열매 맺은 과수원, 독특한 전통 축제로도 유명한, 문화의 근원을 찾는 여정의 명소입니다.","bestTime":"음력 1월부터 3월","specialties":["룩응안 여지","쭈 국수","께 쌀 과자","번 마을 술"]},"ja":{"summary":"タイイエントゥ、チュックラム本山ヴィンギエム寺、名高いルックガンのライチ果樹園を抱く、霊性の遺産に富んだ地。","story":"バックザンは歴史的・霊性的価値に富んだ東北部の丘陵省です。ここにはチャン・ニャン・トン仏皇の布教の道にゆかりのタイイエントゥ観光地、ユネスコ登録の木版を所蔵するチュックラム禅派の本山ヴィンギエム寺があります。バックザンはまた、甘いルックガンのライチ、実をたわわに実らせた果樹園、個性豊かな伝統の祭りでも有名な、文化の起源を訪ねる旅の名所です。","bestTime":"旧暦1月から3月","specialties":["ルックガンのライチ","チュー麺","ケーの米せんべい","ヴァン村の酒"]},"zh":{"summary":"灵性遗产丰富之地，拥有西安子、竹林祖庭永严寺和著名的陆岸荔枝园。","story":"北江是东北部的中游省份，历史与灵性价值丰厚。这里有与陈仁宗佛皇弘扬佛法之路相连的西安子旅游区，以及珍藏联合国教科文组织所列木刻经版、作为竹林禅派祖庭的永严寺。北江还以甘甜的陆岸荔枝、硕果累累的果园和独具特色的传统庙会闻名，是一处文化寻根之旅的目的地。","bestTime":"农历正月至三月","specialties":["陆岸荔枝","𤞭面","计薄饼","云村酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('bac-kan', 'northeast', 'Bắc Kạn', 'Bac Kan', 'Đông Bắc', '#4f7b6a', 105.825, 22.2621, 'Tỉnh núi rừng yên bình với Hồ Ba Bể - hồ nước ngọt tự nhiên lớn nhất Việt Nam và Vườn quốc gia nguyên sinh.', 'Bắc Kạn là tỉnh miền núi Đông Bắc nổi bật với Hồ Ba Bể - viên ngọc xanh giữa đại ngàn và là hồ nước ngọt tự nhiên trên núi lớn nhất nước. Vườn quốc gia Ba Bể với rừng nguyên sinh, hang động, thác nước cùng văn hóa người Tày tạo nên điểm đến sinh thái hấp dẫn. Đến Bắc Kạn, du khách được hòa mình vào thiên nhiên trong lành, ngồi thuyền độc mộc và trải nghiệm cuộc sống bản làng bình dị.', 'Tháng 4 đến tháng 11', '["Cá nướng Ba Bể","Tôm chua","Bánh trứng kiến","Miến dong Bắc Kạn"]', '{"en":{"summary":"A peaceful mountain-forest province with Ba Be Lake — Vietnam''s largest natural freshwater lake — and a primeval national park.","story":"Bac Kan is a northeastern mountain province standing out for Ba Be Lake — a blue jewel amid the great forest and the country''s largest natural mountain freshwater lake. Ba Be National Park, with its primeval forest, caves and waterfalls alongside Tay culture, makes for an appealing eco-destination. In Bac Kan, visitors immerse themselves in fresh nature, ride a dugout canoe and experience the simple life of the villages.","bestTime":"April to November","specialties":["Ba Be grilled fish","Sour shrimp","Ant-egg cake","Bac Kan arrowroot vermicelli"]},"ko":{"summary":"베트남 최대의 자연 담수호인 바베 호수와 원시 국립공원을 품은 평화로운 산림의 성.","story":"박깐은 바베 호수로 두드러지는 동북부 산악 성입니다. 바베 호수는 깊은 숲속의 푸른 보석이자 산 위의 자연 담수호 중 베트남 최대 규모입니다. 원시림, 동굴, 폭포와 따이족 문화를 품은 바베 국립공원은 매력적인 생태 관광지입니다. 박깐에서 여행객은 맑은 자연에 녹아들어 통나무배를 타고 소박한 마을의 삶을 체험합니다.","bestTime":"4월부터 11월","specialties":["바베 생선구이","새우 발효 젓갈","개미알 떡","박깐 칡 당면"]},"ja":{"summary":"ベトナム最大の自然淡水湖バーベー湖と原生の国立公園を抱く、穏やかな山林の省。","story":"バックカンはバーベー湖で際立つ東北部の山岳省です。バーベー湖は深い森の中の青い宝石であり、山上の自然淡水湖としてベトナム最大の規模です。原生林、洞窟、滝とターイ族の文化を抱くバーベー国立公園は、魅力的なエコ観光地です。バックカンで旅人は清らかな自然に溶け込み、丸木舟に乗り、素朴な村の暮らしを体験します。","bestTime":"4月から11月","specialties":["バーベーの焼き魚","エビの発酵漬け","アリの卵の餅","バックカンのくず春雨"]},"zh":{"summary":"宁静的山林之省，拥有越南最大的天然淡水湖巴贝湖和原始的国家公园。","story":"北𣴓是东北部的山区省份，以巴贝湖著称。巴贝湖是莽莽群山间的一颗碧绿明珠，也是越南最大的山上天然淡水湖。拥有原始森林、洞窟、瀑布和岱依族文化的巴贝国家公园，是一处颇具魅力的生态旅游地。来到北𣴓，游客得以融入清新的自然，乘坐独木舟，体验质朴的村寨生活。","bestTime":"4月至11月","specialties":["巴贝烤鱼","酸虾","蚁卵糕","北𣴓葛根粉丝"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('bac-lieu', 'mekong-delta', 'Bạc Liêu', 'Bac Lieu', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.4876, 9.3129, 'Quê hương bản Dạ cổ hoài lang và giai thoại Công tử Bạc Liêu, với cánh đồng điện gió ven biển độc đáo.', 'Bạc Liêu là vùng đất ven biển giàu bản sắc văn hóa, được biết đến là cái nôi của bản Dạ cổ hoài lang, khởi nguồn của nghệ thuật đờn ca tài tử và cải lương Nam Bộ. Tỉnh gắn liền với giai thoại nổi tiếng về Công tử Bạc Liêu ăn chơi khét tiếng một thời, cùng dinh thự cổ tráng lệ còn lưu giữ. Bạc Liêu ngày nay còn nổi bật với cánh đồng điện gió ven biển hùng vĩ, biểu tượng cho năng lượng xanh. Đến đây, du khách được hòa mình vào không gian văn hóa nghệ thuật và vẻ đẹp hiện đại đan xen truyền thống.', 'Tháng 11 đến tháng 4, mùa khô trời trong gió đẹp', '["Bún bò cay","Bánh tằm Ngan Dừa","Ba khía muối","Nhãn Bạc Liêu"]', '{"en":{"summary":"The home of ''Da co hoai lang'' and the legend of the Bac Lieu Playboy, with a unique coastal wind farm.","story":"Bac Lieu is a coastal land rich in cultural identity, known as the cradle of ''Da co hoai lang'', the origin of don ca tai tu and southern cai luong opera. The province is tied to the famous legend of the Bac Lieu Playboy, once a notorious high-liver, along with the magnificent old mansion still preserved. Today Bac Lieu also stands out for its grand coastal wind farm, a symbol of green energy. Here, visitors immerse themselves in a space of cultural artistry and a modern beauty interwoven with tradition.","bestTime":"November to April, the dry season with clear skies and lovely winds","specialties":["Spicy beef noodle soup (bun bo cay)","Ngan Dua banh tam","Salted ba khia","Bac Lieu longan"]},"ko":{"summary":"''자꼬호아이랑''과 박리에우 공자 일화의 고향, 독특한 해안 풍력발전 단지를 간직한 곳.","story":"박리에우는 문화 정체성이 풍부한 해안 땅으로, 던까따이뜨와 남부 까이르엉 오페라의 원천인 ''자꼬호아이랑''의 발상지로 알려져 있습니다. 한 시대를 풍미한 풍류객 박리에우 공자에 얽힌 유명한 일화와, 지금도 보존된 화려한 고택과 연결되어 있습니다. 오늘날 박리에우는 녹색 에너지의 상징인 웅장한 해안 풍력발전 단지로도 돋보입니다. 이곳에서 여행객은 문화 예술의 공간과, 전통이 어우러진 현대적 아름다움에 흠뻑 빠집니다.","bestTime":"11~4월, 하늘이 맑고 바람이 좋은 건기","specialties":["매운 소고기 국수(분보까이)","응안즈어 바인땀","바키아 절임","박리에우 용안"]},"ja":{"summary":"『ザーコー・ホアイラン』とバクリエウの貴公子の逸話の故郷、独特な沿岸風力発電所を擁する地。","story":"バクリエウは文化的アイデンティティ豊かな沿岸の地で、ドンカータイトゥと南部カイルオン歌劇の源である『ザーコー・ホアイラン』の発祥地として知られます。一時代を風靡した遊蕩の貴公子バクリエウの貴公子にまつわる有名な逸話と、今も保存される壮麗な古邸宅と結びついています。今日のバクリエウはグリーンエネルギーの象徴である雄大な沿岸風力発電所でも際立ちます。ここで旅人は文化芸術の空間と、伝統が織り込まれた現代的な美しさに浸ります。","bestTime":"11〜4月、空が澄み風の心地よい乾季","specialties":["辛い牛肉麺（ブンボーカイ）","ガンズアのバインタム","バーキアの塩漬け","バクリエウのリュウガン"]},"zh":{"summary":"《夜鼓怀郎》和薄辽公子轶事的故乡，拥有独特的沿海风电场。","story":"薄辽是一片文化底蕴深厚的沿海土地，被誉为《夜鼓怀郎》的摇篮——南部才子弹唱和改良剧的源头。该省与一时声名显赫的纨绔公子薄辽公子的著名轶事相连，至今仍保存着华丽的古宅邸。如今的薄辽还以雄伟的沿海风电场而引人注目，那是绿色能源的象征。来到这里，游客可沉浸在文化艺术的空间，以及传统与现代交织的美感之中。","bestTime":"11月至4月，天清风爽的旱季","specialties":["辣牛肉米粉","彦椰粉条","腌相手蟹","薄辽龙眼"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('bac-ninh', 'red-river-delta', 'Bắc Ninh', 'Bac Ninh', 'Đồng bằng sông Hồng', '#c7993f', 106.1056, 21.1104, 'Cái nôi của dân ca quan họ và vương triều Lý, vùng đất Kinh Bắc giàu di sản văn hóa và làng nghề.', 'Bắc Ninh là vùng đất Kinh Bắc địa linh nhân kiệt, quê hương của những làn điệu quan họ ngọt ngào đã được UNESCO ghi danh. Đây cũng là đất phát tích vương triều Lý với Đền Đô uy nghi thờ tám đời vua. Bắc Ninh còn nổi danh với những làng nghề truyền thống như tranh Đông Hồ, gốm Phù Lãng, đúc đồng Đại Bái. Về Bắc Ninh, du khách được đắm mình trong không gian văn hóa đậm đà bản sắc và nghe các liền anh liền chị say sưa hát canh.', 'Tháng 1 đến tháng 4 (mùa lễ hội)', '["Bánh phu thê Đình Bảng","Tranh Đông Hồ","Nem Bùi","Dân ca quan họ"]', '{"en":{"summary":"The cradle of quan ho folk song and the Ly Dynasty, the land of Kinh Bac rich in cultural heritage and craft villages.","story":"Bac Ninh is the storied land of Kinh Bac, the homeland of the sweet quan ho folk melodies inscribed by UNESCO. It is also the birthplace of the Ly Dynasty, with the imposing Do Temple honoring eight generations of kings. Bac Ninh is famed too for its traditional craft villages, such as Dong Ho painting, Phu Lang pottery, and Dai Bai bronze casting. In Bac Ninh, visitors immerse themselves in a culturally rich atmosphere and listen to the lien anh and lien chi singers passionately exchange their songs.","bestTime":"January to April (festival season)","specialties":["Dinh Bang husband-and-wife cake","Dong Ho paintings","Bui spring rolls","Quan ho folk song"]},"ko":{"summary":"꽌호 민요와 리 왕조의 발상지, 문화유산과 전통 마을이 풍성한 낀박 땅.","story":"박닌은 인재가 끊이지 않는 낀박 땅으로, 유네스코에 등재된 달콤한 꽌호 가락의 고향입니다. 이곳은 또한 여덟 대의 왕을 모시는 위엄 있는 덴도 사당과 함께 리 왕조의 발상지이기도 합니다. 박닌은 동호 그림, 푸랑 도자기, 다이바이 청동 주조 같은 전통 마을로도 이름났습니다. 박닌에 오면 짙은 정체성이 깃든 문화 공간에 흠뻑 빠져, 리엔아인과 리엔찌(꽌호 가수들)가 밤새 흥겹게 노래 부르는 소리를 들을 수 있습니다.","bestTime":"1월~4월(축제 철)","specialties":["딘방 부부떡","동호 그림","부이 넴","꽌호 민요"]},"ja":{"summary":"クアンホ民謡と李朝発祥の地。文化遺産と職人の里が豊かなキンバクの地。","story":"バクニンは人傑地霊のキンバクの地であり、ユネスコに登録された甘美なクアンホ民謡の故郷です。また、八代の王を祀る威厳あるデンドーを擁する、李朝発祥の地でもあります。バクニンはさらに、ドンホー版画、フーラン陶器、ダイバイの銅鋳物といった伝統の職人の里でも名高い地です。バクニンを訪れれば、個性豊かな文化の空間に浸り、歌い手たち（リエンアイン・リエンチ）が夢中で歌い交わす夜の宴を聴くことができます。","bestTime":"1月から4月（祭りの季節）","specialties":["ディンバンのフーテー餅","ドンホー版画","ブイの発酵肉（ネムブイ）","クアンホ民謡"]},"zh":{"summary":"官贺民歌与李朝王室的摇篮，京北之地遗产丰厚，手工艺村众多。","story":"北宁是人杰地灵的京北之地，是甜美官贺民歌的故乡，这一民歌已被联合国教科文组织列入名录。这里也是李朝王室的发祥地，巍峨的都庙供奉着八代皇帝。北宁还以东胡年画、扶朗陶瓷、大碓铜器等传统手工艺村闻名。来到北宁，游客可沉浸在浓郁的文化空间中，聆听缠绵哥姐们尽情对唱。","bestTime":"1月至4月（庙会季）","specialties":["亭榜夫妻饼","东胡年画","裴村肉卷","官贺民歌"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ben-tre', 'mekong-delta', 'Bến Tre', 'Ben Tre', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.4676, 10.1203, 'Xứ dừa của miền Tây với những cù lao xanh mát, làng nghề thủ công từ dừa và đặc sản kẹo dừa nức tiếng.', 'Bến Tre được mệnh danh là xứ dừa, nơi những rặng dừa xanh trải dài bất tận trên ba cù lao lớn giữa các nhánh sông Tiền. Cây dừa gắn bó mật thiết với đời sống người dân, từ nước dừa, kẹo dừa đến đồ thủ công mỹ nghệ tinh xảo làm từ thân, lá và xơ dừa. Du khách đến Bến Tre để đi xuồng qua rạch dừa nước, thăm các lò kẹo dừa thơm lừng và cảm nhận hồn quê mộc mạc, nghĩa tình của vùng đất ba dải cù lao Bảo, Minh và An Hóa.', 'Tháng 11 đến tháng 4, mùa khô mát mẻ', '["Kẹo dừa Bến Tre","Bánh tráng Mỹ Lồng","Bánh phồng Sơn Đốc","Đuông dừa"]', '{"en":{"summary":"The coconut land of the Mekong, with cool green islets, coconut handicraft villages and famous coconut candy.","story":"Ben Tre is dubbed the coconut land, where endless green coconut groves stretch across three large islets among the branches of the Tien River. The coconut tree is closely bound to people''s lives, from coconut water and coconut candy to exquisite handicrafts made from the trunk, leaves and fiber. Visitors come to Ben Tre to ride boats through water-coconut canals, visit fragrant coconut-candy workshops and feel the rustic, warm-hearted soul of the land of three islets — Bao, Minh and An Hoa.","bestTime":"November to April, the cool, dry season","specialties":["Ben Tre coconut candy","My Long rice paper","Son Doc puffed rice cake","Coconut worms"]},"ko":{"summary":"시원한 초록 섬, 코코넛 수공예 마을, 이름난 코코넛 캔디를 간직한 메콩의 코코넛 고장.","story":"벤쩨는 코코넛 고장이라 불리며, 띠엔강 갈래들 사이의 세 큰 섬에 끝없는 초록 코코넛 숲이 펼쳐집니다. 코코넛 나무는 코코넛 워터, 코코넛 캔디부터 줄기·잎·껍질로 만든 정교한 공예품까지 주민들의 삶과 긴밀히 얽혀 있습니다. 여행객은 벤쩨에서 물야자수 수로를 배로 누비고, 향긋한 코코넛 캔디 공방을 둘러보며, 바오·민·안호아 세 섬으로 이뤄진 이 땅의 소박하고 정 깊은 시골 정취를 느낍니다.","bestTime":"11~4월, 시원한 건기","specialties":["벤쩨 코코넛 캔디","미롱 라이스페이퍼","선독 뻥과자(바인퐁)","코코넛 굼벵이(두옹즈어)"]},"ja":{"summary":"涼しげな緑の島、ココナッツ手工芸の村、名高いココナッツキャンディーを擁するメコンのココナッツの里。","story":"ベンチェはココナッツの里と称され、ティエン川の支流に挟まれた三つの大きな島に果てしない緑のココナッツ林が広がります。ココナッツの木はココナッツウォーターやココナッツキャンディーから、幹・葉・繊維で作った精巧な工芸品まで、人々の暮らしと密接に結びついています。旅人はベンチェでニッパヤシの水路を舟で巡り、香ばしいココナッツキャンディー工房を訪れ、バオ・ミン・アンホアの三島から成るこの地の素朴で情に厚い田舎の趣を感じます。","bestTime":"11〜4月、涼しい乾季","specialties":["ベンチェのココナッツキャンディー","ミーロンのライスペーパー","ソンドックの煎餅（バインフォン）","ココナッツの幼虫（ドゥオンズア）"]},"zh":{"summary":"湄公的椰乡，拥有清凉翠绿的小岛、椰子手工艺村和名扬四方的椰子糖特产。","story":"槟椥被誉为椰乡，一片片翠绿的椰林在前江各支流间的三座大岛上绵延无际。椰树与百姓生活息息相关，从椰汁、椰子糖到用椰干、椰叶和椰丝制成的精美工艺品。游客来槟椥坐船穿行水椰水道，参观香气四溢的椰子糖作坊，感受由保洲、明洲和安化三岛组成的这片土地质朴重情的乡土风情。","bestTime":"11月至4月，凉爽的旱季","specialties":["槟椥椰子糖","美隆米纸","山笃米饼","椰子虫"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('binh-dinh', 'south-central-coast', 'Bình Định', 'Binh Dinh', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.947, 14.1238, 'Đất võ trời văn với biển Quy Nhơn tuyệt đẹp, những tháp Chăm cổ kính và tinh thần thượng võ Tây Sơn.', 'Bình Định là vùng đất giàu truyền thống thượng võ, quê hương của người anh hùng áo vải Quang Trung - Nguyễn Huệ. Tỉnh sở hữu bờ biển Quy Nhơn quyến rũ với Kỳ Co, Eo Gió và hệ thống tháp Chăm cổ kính như Bánh Ít, Dương Long. Nơi đây còn nổi tiếng với hát bội, võ cổ truyền Tây Sơn và ẩm thực phong phú, đậm đà hương vị xứ Nẫu.', 'Tháng 3 đến tháng 9', '["Bánh ít lá gai","Bún chả cá Quy Nhơn","Nem chợ Huyện","Rượu Bàu Đá","Bánh hỏi cháo lòng"]', '{"en":{"summary":"A land of martial arts and letters with the stunning Quy Nhon coast, ancient Cham towers, and the martial spirit of Tay Son.","story":"Binh Dinh is a land rich in martial tradition, homeland of the peasant hero Quang Trung - Nguyen Hue. The province boasts the alluring Quy Nhon coast with Ky Co, Eo Gio, and a system of ancient Cham towers like Banh It and Duong Long. It is also famous for hat boi opera, traditional Tay Son martial arts, and a rich cuisine full of the flavor of the Nau land.","bestTime":"March to September","specialties":["Banh it la gai rice cakes","Quy Nhon fish noodle soup","Cho Huyen spring rolls","Bau Da liquor","Banh hoi with pork offal porridge"]},"ko":{"summary":"아름다운 꾸이년 바다와 고풍스러운 참 탑, 떠이선의 무예 정신을 지닌 무(武)와 문(文)의 땅입니다.","story":"빈딘은 무예 전통이 깊은 땅으로, 평민 출신 영웅 꽝쭝-응우옌후에의 고향입니다. 끼꼬, 에오지오를 비롯한 매혹적인 꾸이년 해안과 반잇, 즈엉롱 같은 고풍스러운 참 탑 군을 품고 있습니다. 또한 핫보이(전통극), 떠이선 전통 무예, 그리고 너 지방 특유의 풍부한 음식으로도 유명합니다.","bestTime":"3월~9월","specialties":["반잇 라가이 떡","꾸이년 분짜까(생선국수)","쩌후옌 넴","바우다 술","반호이 짜오롱"]},"ja":{"summary":"美しいクイニョンの海、古風なチャム塔、そしてタイソンの尚武の精神を持つ武と文の地です。","story":"ビンディンは尚武の伝統が深い地で、平民出身の英雄クアンチュン＝グエンフエの故郷です。キーコー、エオジオをはじめとする魅惑的なクイニョン海岸と、バインイットやズオンロンといった古風なチャム塔群を擁します。また、ハットボイ（伝統劇）、タイソンの伝統武術、そしてナウ地方ならではの豊かな食でも有名です。","bestTime":"3月〜9月","specialties":["バインイット・ラーガイ餅","クイニョンのブンチャーカー（魚そば）","チョーフエンのネム","バウダー酒","バインホイ・チャオロン"]},"zh":{"summary":"文武之乡，拥有绝美的归仁海、古朴的占族塔与西山尚武精神。","story":"平定是一片尚武传统深厚的土地，是布衣英雄光中——阮惠的故乡。该省坐拥迷人的归仁海岸，有奇科、风坳，以及饼怡、阳龙等古朴的占族塔群。这里还以㗰剧、西山传统武术，以及浓郁乂地区风味的丰富美食而闻名。","bestTime":"3月至9月","specialties":["饼怡叶糕","归仁鱼饼粉","县市场酸肉","𤬰沱酒","粉饼配猪杂粥"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('binh-duong', 'southeast', 'Bình Dương', 'Binh Duong', 'Đông Nam Bộ', '#b07a4a', 106.6563, 11.2181, 'Thủ phủ công nghiệp miền Đông với lễ hội chùa Bà Thiên Hậu sôi động và khu du lịch Đại Nam khổng lồ.', 'Bình Dương là một trong những trung tâm công nghiệp và đô thị phát triển nhanh nhất Việt Nam, nhưng vẫn đậm chất văn hóa truyền thống. Thủ Dầu Một nổi tiếng với nghề gốm sứ, sơn mài lâu đời và miếu Bà Thiên Hậu, nơi diễn ra lễ rước kiệu rằm tháng Giêng tưng bừng nhất miền Đông. Khu du lịch Đại Nam quy mô khổng lồ là điểm vui chơi giải trí gia đình hấp dẫn, hòa quyện giữa tâm linh, thiên nhiên và giải trí hiện đại.', 'Tháng 11 đến tháng 4 (mùa khô) và rằm tháng Giêng', '["Gốm sứ Lái Thiêu","Sơn mài truyền thống","Trái cây Lái Thiêu"]', '{"en":{"summary":"The industrial capital of the southeast, with the lively Ba Thien Hau Temple festival and the colossal Dai Nam Tourist Park.","story":"Binh Duong is one of Vietnam''s fastest-growing industrial and urban centers, yet it remains rich in traditional culture. Thu Dau Mot is famous for its long-standing ceramics and lacquerware crafts and for Ba Thien Hau Temple, where the most exuberant palanquin procession in the southeast takes place on the 15th of the first lunar month. The colossal Dai Nam Tourist Park is an appealing family entertainment spot, blending the spiritual, the natural and modern fun.","bestTime":"November to April (dry season) and the 15th of the first lunar month","specialties":["Lai Thieu ceramics","Traditional lacquerware","Lai Thieu fruit"]},"ko":{"summary":"동남부의 공업 중심지로, 활기찬 바 티엔하우 사원 축제와 거대한 다이남 관광지가 있습니다.","story":"빈즈엉은 베트남에서 가장 빠르게 성장하는 공업·도시 중심지 중 하나이지만 여전히 전통 문화가 짙게 남아 있습니다. 투저우못은 오래된 도자기·옻칠 공예와 바 티엔하우 사원으로 유명하며, 그곳에서는 정월 대보름에 동남부에서 가장 흥겨운 가마 행렬이 펼쳐집니다. 거대한 다이남 관광지는 영적인 것과 자연, 현대적 오락이 어우러진 매력적인 가족 위락 명소입니다.","bestTime":"11월~4월 (건기)과 정월 대보름","specialties":["라이티에우 도자기","전통 옻칠 공예","라이티에우 과일"]},"ja":{"summary":"東南部の工業の中心地で、賑やかなバー・ティエンハウ廟の祭りと巨大なダイナム観光地があります。","story":"ビンズオンはベトナムで最も急成長する工業・都市の中心地のひとつですが、今なお伝統文化が色濃く残っています。トゥーザウモットは、古くからの陶磁器・漆器の工芸と、東南部で最も賑やかな神輿行列が小正月に行われるバー・ティエンハウ廟で有名です。巨大なダイナム観光地は、精神的なものと自然、近代的な娯楽が溶け合う、魅力的な家族向けの遊びの名所です。","bestTime":"11月〜4月（乾季）と小正月","specialties":["ライティエウの陶磁器","伝統的な漆器","ライティエウの果物"]},"zh":{"summary":"东南部的工业首府，拥有热闹的天后庙庙会和巨型的大南旅游区。","story":"平阳是越南发展最快的工业与城市中心之一，却依旧饱含传统文化底蕴。土龙木以悠久的陶瓷、漆器工艺和天后庙闻名，正月十五在此举行的抬轿巡游是东南部最热闹的庙会。规模宏大的大南旅游区是颇具吸引力的家庭娱乐去处，将灵性、自然与现代娱乐融为一体。","bestTime":"11月至4月（旱季）及正月十五","specialties":["赖梯陶瓷","传统漆器","赖梯水果"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('binh-phuoc', 'southeast', 'Bình Phước', 'Binh Phuoc', 'Đông Nam Bộ', '#b07a4a', 106.9061, 11.7562, 'Tỉnh biên giới với rừng nguyên sinh Bù Gia Mập, những trảng cỏ kỳ thú và văn hóa S''tiêng, M''nông đậm đà.', 'Bình Phước nằm ở vùng biên giới Tây Nam, là cửa ngõ nối Đông Nam Bộ với Tây Nguyên và Campuchia. Đây là xứ sở của những đồi điều, vườn tiêu bạt ngàn và những cánh rừng nguyên sinh quý giá như Bù Gia Mập. Thiên nhiên hoang sơ với trảng cỏ Bù Lạch, thác ghềnh, suối rừng cùng đời sống văn hóa cồng chiêng của đồng bào S''tiêng, M''nông tạo nên bản sắc riêng cho vùng đất biên cương trầm mặc mà cuốn hút này.', 'Tháng 11 đến tháng 4 (mùa khô)', '["Hạt điều rang muối","Tiêu Lộc Ninh","Cơm lam, rượu cần S''tiêng"]', '{"en":{"summary":"A border province with the Bu Gia Map primary forest, marvelous grasslands and rich S''tieng and M''nong cultures.","story":"Binh Phuoc lies along the southwestern border, the gateway linking the southeast with the Central Highlands and Cambodia. It is a land of endless cashew hills and pepper gardens and precious primary forests such as Bu Gia Map. Pristine nature—the Bu Lach grasslands, rapids and forest streams—together with the gong culture of the S''tieng and M''nong peoples gives this quietly captivating frontier land its own distinct character.","bestTime":"November to April (dry season)","specialties":["Salt-roasted cashews","Loc Ninh pepper","S''tieng bamboo-tube rice and rice wine"]},"ko":{"summary":"부자맙 원시림과 기묘한 초원, 짙은 스띠엥·므농 문화를 지닌 국경 성.","story":"빈프억은 서남부 국경 지대에 자리해 동남부와 떠이응우옌(중부 고원), 캄보디아를 잇는 관문입니다. 끝없는 캐슈 언덕과 후추 밭, 그리고 부자맙 같은 귀중한 원시림의 고장입니다. 부락 초원과 여울, 숲 계곡 같은 원시 자연과 스띠엥족·므농족의 공 문화가 어우러져, 고요하면서도 매혹적인 이 변경의 땅에 고유한 정체성을 부여합니다.","bestTime":"11월~4월 (건기)","specialties":["소금 볶음 캐슈너트","록닌 후추","스띠엥족 대통밥과 깐 술"]},"ja":{"summary":"ブザマップの原生林、不思議な草原、濃厚なストゥエン族・ムノン族の文化を持つ国境の省。","story":"ビンフオックは西南部の国境地帯に位置し、東南部とタイグエン（中部高原）、カンボジアを結ぶ玄関口です。果てしないカシューの丘や胡椒畑、そしてブザマップのような貴重な原生林の郷です。ブーラックの草原や早瀬、森の渓流といった手つかずの自然と、ストゥエン族・ムノン族の銅鑼文化が溶け合い、静かでありながら魅惑的なこの辺境の地に独自の個性を与えています。","bestTime":"11月〜4月（乾季）","specialties":["塩炒りカシューナッツ","ロックニンの胡椒","ストゥエン族の竹筒飯と壺酒"]},"zh":{"summary":"边境省份，拥有布嘉霉原始森林、奇妙的草甸，以及浓郁的斯丁族、墨侬族文化。","story":"平福位于西南边境地带，是连接东南部与西原（中部高原）及柬埔寨的门户。这里是漫山遍野的腰果林和胡椒园之乡，也拥有布嘉霉等珍贵的原始森林。布勒草甸、险滩、林溪等原始自然风光，与斯丁族、墨侬族的锣钲文化相互交融，为这片静谧而迷人的边陲之地赋予了独特的风韵。","bestTime":"11月至4月（旱季）","specialties":["盐焗腰果","禄宁胡椒","斯丁族竹筒饭、坛酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('binh-thuan', 'south-central-coast', 'Bình Thuận', 'Binh Thuan', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.0446, 11.12, 'Xứ sở nắng gió với đồi cát Mũi Né, biển xanh và những làng chài đậm chất Nam Trung Bộ.', 'Bình Thuận là vùng đất của nắng, gió và biển xanh. Mũi Né nổi tiếng với những đồi cát vàng, cát đỏ uốn lượn như sa mạc, cùng làng chài Mũi Né đầy sắc màu và bãi biển trải dài. Đây là thiên đường của các môn thể thao biển như lướt ván diều. Bình Thuận còn có tháp Chăm Po Sah Inư cổ kính và đặc sản hải sản tươi ngon, nước mắm Phan Thiết trứ danh.', 'Tháng 11–4, mùa khô ít mưa', '["Nước mắm Phan Thiết","Bánh canh chả cá","Gỏi cá mai","Mực một nắng","Thanh long"]', '{"en":{"summary":"A land of sun and wind with the Mui Ne sand dunes, blue seas, and fishing villages of the south-central coast.","story":"Binh Thuan is a land of sun, wind, and blue seas. Mui Ne is famous for rolling golden and red sand dunes like a desert, along with the colorful Mui Ne fishing village and a long stretch of beach. It is a paradise for water sports like kitesurfing. Binh Thuan also has the ancient Po Sah Inu Cham tower and delicious fresh seafood, with the famous Phan Thiet fish sauce.","bestTime":"November–April, the dry season with little rain","specialties":["Phan Thiet fish sauce","Fish-cake noodle soup","Anchovy salad","One-sun-dried squid","Dragon fruit"]},"ko":{"summary":"무이네 사구와 푸른 바다, 남중부 특유의 어촌을 지닌 햇볕과 바람의 고장입니다.","story":"빈투언은 햇볕과 바람, 푸른 바다의 땅입니다. 무이네는 사막처럼 굽이치는 황금빛·붉은빛 사구와 색채 가득한 무이네 어촌, 길게 펼쳐진 해변으로 유명합니다. 카이트서핑 같은 해양 스포츠의 천국이기도 합니다. 빈투언에는 또한 고풍스러운 포사인 참 탑과 맛있는 싱싱한 해산물, 이름난 판티엣 액젓이 있습니다.","bestTime":"11~4월, 비가 적은 건기","specialties":["판티엣 액젓","짜까 바인까인","까마이 회무침","한볕 말린 오징어","용과"]},"ja":{"summary":"ムイネー砂丘と青い海、南中部らしい漁村を持つ日差しと風の地です。","story":"ビントゥアンは日差しと風、青い海の地です。ムイネーは砂漠のようにうねる黄金と赤の砂丘、色彩あふれるムイネー漁村、長く広がるビーチで有名です。カイトサーフィンなどのマリンスポーツの楽園でもあります。ビントゥアンにはまた、古風なポーサーイヌーのチャム塔、美味しい新鮮な海の幸、名高いファンティエットの魚醤があります。","bestTime":"11〜4月、雨の少ない乾季","specialties":["ファンティエットの魚醤","魚のすり身のバインカイン","カマイの刺身和え","天日干しのイカ","ドラゴンフルーツ"]},"zh":{"summary":"阳光与风之乡，拥有美奈沙丘、碧海与南中部风情的渔村。","story":"平顺是阳光、风与碧海之地。美奈以沙漠般起伏的金沙、红沙丘，色彩缤纷的美奈渔村与绵长的海滩而闻名。这里是风筝冲浪等海上运动的天堂。平顺还有古朴的波萨努占族塔、鲜美的海产，以及闻名遐迩的潘切鱼露。","bestTime":"11至4月，少雨旱季","specialties":["潘切鱼露","鱼饼羹粉","梅鱼生拌","一阳晒鱿鱼","火龙果"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ca-mau', 'mekong-delta', 'Cà Mau', 'Ca Mau', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.0388, 9.0515, 'Vùng đất cực Nam thiêng liêng của Tổ quốc với rừng ngập mặn bạt ngàn, hải sản trù phú và đời sống sông nước mộc mạc.', 'Cà Mau là tỉnh cực Nam của Tổ quốc, vùng đất ba mặt giáp biển với hệ sinh thái rừng ngập mặn và rừng tràm độc đáo bậc nhất Việt Nam. Mũi Cà Mau thiêng liêng, vườn quốc gia U Minh Hạ và những cánh rừng đước, rừng mắm xanh thẳm tạo nên cảnh quan hoang sơ kỳ vĩ, được công nhận là khu dự trữ sinh quyển thế giới. Đất Mũi trù phú với cua, ba khía, tôm cá tươi rói cùng mật ong rừng U Minh nức tiếng. Con người Cà Mau chân chất, phóng khoáng, gắn bó với rừng, với biển nơi chót cùng đất nước.', 'Tháng 12 đến tháng 4, mùa khô biển êm thuận tiện đi lại', '["Cua Cà Mau","Ba khía muối","Mật ong rừng U Minh","Cá thòi lòi","Tôm khô Rạch Gốc"]', '{"en":{"summary":"The sacred southernmost land of the country, with vast mangrove forests, abundant seafood and a rustic river life.","story":"Ca Mau is the southernmost province of the country, a land bounded on three sides by the sea with a uniquely rich mangrove and cajuput forest ecosystem. The sacred Ca Mau Cape, U Minh Ha National Park and the deep-green rhizophora and avicennia forests create a wild, magnificent landscape recognized as a world biosphere reserve. The land of the cape is rich in crab, ba khia, fresh shrimp and fish, along with the famous U Minh wild honey. The people of Ca Mau are down-to-earth and free-spirited, bound to the forest and the sea at the very tip of the country.","bestTime":"December to April, the dry season with calm seas convenient for getting around","specialties":["Ca Mau crab","Salted ba khia","U Minh wild honey","Mudskipper fish","Rach Goc dried shrimp"]},"ko":{"summary":"드넓은 맹그로브 숲, 풍부한 해산물, 소박한 강변 생활을 간직한 조국의 성스러운 최남단 땅.","story":"까마우는 조국의 최남단 성으로, 삼면이 바다와 맞닿아 베트남에서 손꼽히게 독특한 맹그로브·멜라루카 숲 생태계를 지닙니다. 성스러운 까마우곶, 우민하 국립공원, 그리고 짙푸른 리조포라·아비센니아 숲이 야성적이고 웅장한 경관을 빚어내며, 세계 생물권보전지역으로 인정받았습니다. 곶의 땅은 게, 바키아, 싱싱한 새우와 물고기, 그리고 이름난 우민 야생 꿀로 풍요롭습니다. 까마우 사람들은 소박하고 자유로우며, 국토 맨 끝의 숲과 바다에 정을 붙이고 살아갑니다.","bestTime":"12~4월, 바다가 잔잔해 이동이 편한 건기","specialties":["까마우 게","바키아 절임","우민 야생 꿀","짱둥어(까토이로이)","랏곡 건새우"]},"ja":{"summary":"広大なマングローブ林、豊かなシーフード、素朴な川辺の暮らしを擁する祖国の聖なる最南端の地。","story":"カマウは祖国の最南端の省で、三方を海に接し、ベトナム屈指の独特なマングローブ・メラルーカ林の生態系を持ちます。聖なるカマウ岬、ウーミンハー国立公園、そして深緑のオヒルギ・ヒルギダマシの林が野性的で雄大な景観を織りなし、世界生物圏保存地域として認定されています。岬の地はカニ、バーキア、新鮮なエビや魚、そして名高いウーミンの野生の蜂蜜で豊かです。カマウの人々は素朴で自由闊達で、国土の最果ての林と海に親しんで暮らします。","bestTime":"12〜4月、海が穏やかで移動しやすい乾季","specialties":["カマウのカニ","バーキアの塩漬け","ウーミンの野生の蜂蜜","トビハゼ（カートイロイ）","ラックゴックの干しエビ"]},"zh":{"summary":"祖国神圣的最南端，拥有茫茫红树林、丰饶的海产和质朴的水乡生活。","story":"金瓯是祖国最南端的省份，三面环海，拥有越南屈指可数的独特红树林和白千层林生态系统。神圣的金瓯角、下游民国家公园，以及郁郁葱葱的水笔仔、海榄雌林，构成了原始雄奇的景观，被列为世界生物圈保护区。这片土地物产丰饶，盛产螃蟹、相手蟹、新鲜鱼虾，以及著名的下游民野生蜂蜜。金瓯人质朴豪爽，与国土最南端的林海相依相伴。","bestTime":"12月至4月，海面平静、出行便利的旱季","specialties":["金瓯蟹","腌相手蟹","下游民野生蜂蜜","弹涂鱼","泐𡴶虾干"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('can-tho', 'mekong-delta', 'Cần Thơ', 'Can Tho', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.5284, 10.1156, 'Thủ phủ miền Tây sông nước với chợ nổi Cái Răng, vườn trái cây trĩu quả và nhịp sống miệt vườn.', 'Cần Thơ — ''Tây Đô'' của Đồng bằng sông Cửu Long — là nơi nhịp sống sông nước hiện lên rõ nét nhất. Chợ nổi Cái Răng nhộn nhịp từ tinh mơ, bến Ninh Kiều thơ mộng bên dòng sông Hậu, những vườn trái cây trĩu quả và nhà cổ Bình Thủy trăm tuổi. Người miền Tây phóng khoáng, hiếu khách, đờn ca tài tử ngọt ngào trong đêm — tất cả tạo nên một Cần Thơ trù phú và đậm tình.', 'Quanh năm; mùa nước nổi tháng 9–11 đẹp nhất', '["Bánh xèo","Lẩu mắm","Bánh cống","Nem nướng Cái Răng","Trái cây miệt vườn"]', '{"en":{"summary":"The capital of the Mekong waterland, with the Cai Rang Floating Market, fruit-laden orchards and an orchard rhythm of life.","story":"Can Tho — the ''Western Capital'' of the Mekong Delta — is where river life appears most vividly. The Cai Rang Floating Market bustles from dawn, the poetic Ninh Kieu pier sits by the Hau River, orchards hang heavy with fruit and the century-old Binh Thuy ancient house stands proud. The Mekong people are free-spirited and hospitable, with sweet don ca tai tu in the night — all of it making for a Can Tho that is bountiful and full of warmth.","bestTime":"Year-round; the flood season from September to November is the most beautiful","specialties":["Banh xeo","Fermented-fish hotpot (lau mam)","Banh cong","Cai Rang grilled pork rolls","Orchard fruit"]},"ko":{"summary":"까이랑 수상시장, 과일이 주렁주렁 달린 과수원, 과수원 삶의 리듬을 간직한 메콩 물의 고장의 중심지.","story":"메콩델타의 ''서도(西都)'' 껀터는 강변 삶이 가장 뚜렷이 드러나는 곳입니다. 새벽부터 분주한 까이랑 수상시장, 후강변의 시적인 닌끼에우 선착장, 과일이 주렁주렁 달린 과수원, 백 년 된 빈투이 고택이 있습니다. 자유롭고 손님을 반기는 메콩 사람들, 밤을 수놓는 달콤한 던까따이뜨 — 이 모든 것이 풍요롭고 정 깊은 껀터를 이룹니다.","bestTime":"연중; 9~11월 물난리 철이 가장 아름다움","specialties":["바인쎄오","발효 생선 전골(러우맘)","바인꽁","까이랑 넴느엉","과수원 과일"]},"ja":{"summary":"カイラン水上市場、果実を実らせた果樹園、果樹園の暮らしのリズムを擁するメコンの水の里の中心地。","story":"メコンデルタの『西都』カントーは、川辺の暮らしが最も色濃く表れる場所です。夜明けから賑わうカイラン水上市場、ハウ川辺の詩情あふれるニンキエウ船着場、果実を実らせた果樹園、百年のビントゥイ古民家があります。自由でもてなしの心にあふれるメコンの人々、夜を彩る甘いドンカータイトゥ — そのすべてが豊かで情に厚いカントーを成しています。","bestTime":"通年。9〜11月の増水期が最も美しい","specialties":["バインセオ","発酵魚の鍋（ラウマム）","バインコン","カイランのネムヌオン","果樹園の果物"]},"zh":{"summary":"湄公水乡的首府，拥有丐冷水上市场、硕果累累的果园和悠然的果园生活节奏。","story":"芹苴——湄公河三角洲的「西都」——是水乡生活体现得最鲜明的地方。丐冷水上市场破晓即热闹非凡，宁桥码头诗意地依偎在后江畔，果园硕果累累，百年平水古宅古韵犹存。湄公人豪爽好客，夜晚甜美的才子弹唱悠扬婉转——这一切共同造就了一个富饶而充满人情味的芹苴。","bestTime":"全年；9至11月涨水季节最美","specialties":["煎饼","鱼酱火锅","炸虾饼","丐冷烤肉卷","果园水果"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('cao-bang', 'northeast', 'Cao Bằng', 'Cao Bang', 'Đông Bắc', '#4f7b6a', 106.0851, 22.7465, 'Vùng non nước biên cương với công viên địa chất toàn cầu, thác hùng vĩ, hang động kỳ ảo và bản làng Tày, Nùng.', 'Cao Bằng là miền đất địa đầu Tổ quốc nổi tiếng với Công viên địa chất toàn cầu UNESCO Non nước Cao Bằng. Nơi đây có Thác Bản Giốc hùng vĩ bậc nhất Đông Nam Á, Động Ngườm Ngao huyền bí cùng vô số núi đá vôi, hồ nước và bản làng dân tộc Tày, Nùng yên bình. Cao Bằng còn là cái nôi cách mạng với di tích Pác Bó lịch sử, mảnh đất giàu bản sắc văn hóa và cảnh quan thiên nhiên tươi đẹp.', 'Tháng 9 đến tháng 10', '["Bánh cuốn Cao Bằng","Hạt dẻ Trùng Khánh","Vịt quay 7 vị","Bánh khảo"]', '{"en":{"summary":"A frontier land of mountains and waters with a global geopark, magnificent waterfalls, magical caves and Tay and Nung villages.","story":"Cao Bang is a frontier land famous for the Non Nuoc Cao Bang UNESCO Global Geopark. Here lies Ban Gioc Waterfall, among the most magnificent in Southeast Asia, the mysterious Nguom Ngao Cave, and countless limestone mountains, lakes and peaceful Tay and Nung villages. Cao Bang is also a cradle of the revolution with the historic Pac Bo relic, a land rich in cultural identity and beautiful natural scenery.","bestTime":"September to October","specialties":["Cao Bang rolled rice rolls","Trung Khanh chestnuts","Seven-flavour roast duck","Khao cake"]},"ko":{"summary":"세계지질공원, 웅장한 폭포, 환상적인 동굴, 따이족·눙족 마을이 어우러진 변경 산수의 땅.","story":"까오방은 유네스코 세계지질공원 논느억 까오방으로 유명한 조국 최북단의 땅입니다. 이곳에는 동남아시아에서 손꼽히는 웅장한 반족 폭포, 신비로운 응으엄응아오 동굴과 함께 수많은 석회암 산, 호수, 그리고 평화로운 따이족·눙족 마을이 있습니다. 까오방은 또한 역사적인 빡보 유적을 품은 혁명의 요람으로, 문화적 정체성과 아름다운 자연 경관이 풍부한 땅입니다.","bestTime":"9월부터 10월","specialties":["까오방 반꾸온(쌀국수 말이)","쭝카인 밤","일곱 가지 맛 오리구이","반카오 과자"]},"ja":{"summary":"世界ジオパーク、雄大な滝、幻想的な洞窟、ターイ族・ヌン族の村が調和する辺境の山水の地。","story":"カオバンはユネスコ世界ジオパーク「ノンヌオック・カオバン」で有名な、祖国最北端の地です。ここには東南アジア屈指の雄大なバンゾック滝、神秘的なグオムガオ洞窟とともに、無数の石灰岩の山、湖、そして穏やかなターイ族・ヌン族の村があります。カオバンはまた、歴史的なパックボー遺跡を抱く革命の揺りかごであり、文化的な個性と美しい自然景観に富んだ地です。","bestTime":"9月から10月","specialties":["カオバンのバインクオン(米粉巻き)","チュンカインの栗","七味の鴨ロースト","バインカオ菓子"]},"zh":{"summary":"边陲山水之地，拥有世界地质公园、雄伟瀑布、奇幻洞窟和岱依族、侬族村寨。","story":"高平是祖国最北端的边陲之地，以联合国教科文组织世界地质公园「高平山水」闻名。这里有东南亚最雄伟的板约瀑布、神秘的嫩傲洞，以及无数石灰岩山峰、湖泊和宁静的岱依族、侬族村寨。高平还是革命的摇篮，拥有历史性的北坡遗迹，是一片文化个性鲜明、自然景观秀丽的土地。","bestTime":"9月至10月","specialties":["高平卷粉","重庆栗子","七味烤鸭","烤糕"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('da-nang', 'south-central-coast', 'Đà Nẵng', 'Da Nang', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.0578, 16.0683, 'Thành phố biển đáng sống với bãi Mỹ Khê, bán đảo Sơn Trà và Bà Nà Hills trên mây.', 'Đà Nẵng năng động và hiện đại, nhưng vẫn giữ được sự thư thái của một thành phố biển. Bãi biển Mỹ Khê trải dài cát trắng, cầu Rồng phun lửa cuối tuần, và Bà Nà Hills với Cầu Vàng nổi tiếng thế giới. Đây là điểm trung chuyển lý tưởng để khám phá miền Trung.', 'Tháng 3–8, biển đẹp và ít mưa', '["Mì Quảng","Bánh tráng cuốn thịt heo","Bún chả cá","Hải sản"]', '{"en":{"summary":"A livable coastal city with My Khe Beach, the Son Tra Peninsula, and Ba Na Hills in the clouds.","story":"Da Nang is dynamic and modern, yet keeps the ease of a seaside city. My Khe Beach stretches with white sand, the Dragon Bridge breathes fire on weekends, and Ba Na Hills features the world-famous Golden Bridge. It is an ideal transit hub for exploring central Vietnam.","bestTime":"March–August, beautiful seas and little rain","specialties":["Mi Quang","Pork rice-paper rolls","Fish noodle soup","Seafood"]},"ko":{"summary":"미케 해변, 선짜 반도, 구름 위 바나힐을 지닌 살기 좋은 해변 도시입니다.","story":"다낭은 역동적이고 현대적이면서도 해변 도시 특유의 여유를 간직하고 있습니다. 백사장이 길게 이어진 미케 해변, 주말이면 불을 뿜는 용교, 그리고 세계적으로 유명한 골든 브리지를 품은 바나힐. 중부를 탐험하기에 이상적인 거점 도시입니다.","bestTime":"3~8월, 바다가 아름답고 비가 적음","specialties":["미꽝","돼지고기 라이스페이퍼 쌈","분짜까","해산물"]},"ja":{"summary":"ミーケービーチ、ソンチャー半島、雲の上のバーナーヒルズを持つ住みよい海辺の都市です。","story":"ダナンは活気にあふれ近代的でありながら、海辺の都市ならではのゆとりを保っています。白砂が長く続くミーケービーチ、週末に火を噴くドラゴン橋、そして世界的に有名なゴールデンブリッジを擁するバーナーヒルズ。中部を巡るのに理想的な拠点都市です。","bestTime":"3〜8月、海が美しく雨が少ない","specialties":["ミークアン","豚肉のライスペーパー巻き","ブンチャーカー","海の幸"]},"zh":{"summary":"宜居的海滨城市，拥有美溪海滩、山茶半岛与云端的巴拿山。","story":"岘港充满活力又现代，却依然保有海滨城市的悠然。美溪海滩白沙绵延，龙桥周末喷火，巴拿山更有举世闻名的黄金桥。这里是探索越南中部的理想中转枢纽。","bestTime":"3至8月，海景优美、少雨","specialties":["广面","米纸卷猪肉","鱼饼粉","海鲜"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('dak-lak', 'central-highlands', 'Đắk Lắk', 'Dak Lak', 'Tây Nguyên', '#8a6e4b', 108.206, 12.826, 'Thủ phủ cà phê Tây Nguyên với những buôn làng, thác nước hùng vĩ và văn hóa cồng chiêng.', 'Đắk Lắk là trái tim của vùng đất đỏ bazan Tây Nguyên, thủ phủ cà phê của Việt Nam. Những đồi cà phê bạt ngàn, thác nước Dray Nur, Dray Sáp hùng vĩ, buôn làng Ê Đê, M''Nông với nhà sàn dài và tiếng cồng chiêng vang vọng. Đến với Buôn Ma Thuột và Buôn Đôn, bạn sẽ được sống trong không gian văn hóa cồng chiêng — Di sản của nhân loại — và cảm nhận sự hào sảng của con người đại ngàn.', 'Tháng 11–4, mùa khô Tây Nguyên', '["Cà phê Buôn Ma Thuột","Bún đỏ","Gà nướng cơm lam","Rượu cần","Bơ sáp"]', '{"en":{"summary":"The coffee capital of the Central Highlands with villages, majestic waterfalls, and gong culture.","story":"Dak Lak is the heart of the Central Highlands'' red basalt land, the coffee capital of Vietnam. Vast coffee hills, the majestic Dray Nur and Dray Sap waterfalls, and Ede and M''Nong villages with long stilt houses and echoing gongs. Visiting Buon Ma Thuot and Buon Don, you''ll live in the gong cultural space - a heritage of humanity - and feel the generosity of the wilderness people.","bestTime":"November–April, the Central Highlands dry season","specialties":["Buon Ma Thuot coffee","Red noodle soup","Grilled chicken with bamboo-tube rice","Rice wine","Butter avocado"]},"ko":{"summary":"마을과 웅장한 폭포, 공 문화를 지닌 떠이응우옌의 커피 수도입니다.","story":"닥락은 떠이응우옌 붉은 현무암 땅의 심장이자 베트남의 커피 수도입니다. 끝없는 커피밭, 웅장한 드라이누르·드라이삽 폭포, 긴 고상가옥과 울려 퍼지는 공 소리를 지닌 에데족·므농족 마을. 부온마투옷과 부온돈을 찾으면 인류 유산인 공 문화 공간에 머물며 대자연 사람들의 호방함을 느낄 수 있습니다.","bestTime":"11~4월, 떠이응우옌 건기","specialties":["부온마투옷 커피","분도(붉은 국수)","닭구이와 대통밥","깐 술","버터 아보카도"]},"ja":{"summary":"村々と雄大な滝、銅鑼文化を持つタイグエン高原のコーヒーの都です。","story":"ダクラクはタイグエン高原の赤い玄武岩の地の心臓であり、ベトナムのコーヒーの都です。果てしないコーヒー畑、雄大なドライヌル・ドライサップ滝、長い高床式家屋と響き渡る銅鑼の音を持つエデ族・ムノン族の村々。ブオンマトゥオットとブオンドンを訪れれば、人類の遺産である銅鑼文化空間に身を置き、大自然の人々の豪放さを感じられます。","bestTime":"11〜4月、タイグエン高原の乾季","specialties":["ブオンマトゥオットのコーヒー","ブンドー（赤いそば）","鶏の炭火焼きと竹筒飯","カン酒","バターアボカド"]},"zh":{"summary":"西原的咖啡之都，拥有村寨、雄伟瀑布与铜锣文化。","story":"得乐是西原红色玄武岩土地的心脏，是越南的咖啡之都。无边的咖啡丘，雄伟的德雷努、德雷萨瀑布，拥有长屋与回荡铜锣声的埃地族、墨侬族村寨。来到邦美蜀与本敦，你将置身于人类遗产铜锣文化空间，感受大山之人的豪迈。","bestTime":"11至4月，西原旱季","specialties":["邦美蜀咖啡","红米线","烤鸡配竹筒饭","竹竿酒","牛油果"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('dak-nong', 'central-highlands', 'Đắk Nông', 'Dak Nong', 'Tây Nguyên', '#8a6e4b', 107.6861, 12.2292, 'Vùng đất công viên địa chất toàn cầu UNESCO với hang động núi lửa, thác nước hùng vĩ và rừng nguyên sinh.', 'Đắk Nông là tỉnh phía nam Tây Nguyên, tự hào sở hữu Công viên địa chất toàn cầu UNESCO với hệ thống hang động núi lửa dài nhất Đông Nam Á. Vùng đất đỏ bazan này có nhiều thác nước hùng vĩ như Dray Sáp, Gia Long, cùng những hồ nước trong xanh và cánh rừng nguyên sinh trù phú. Nơi đây còn lưu giữ kho tàng văn hóa đặc sắc của đồng bào M''Nông, Mạ với cồng chiêng, sử thi và nghề dệt thổ cẩm truyền thống.', 'Tháng 11 đến tháng 4', '["Cà phê Đắk Nông","Hồ tiêu","Bơ sáp","Cơm lam","Rượu cần M''Nông"]', '{"en":{"summary":"A land of UNESCO Global Geopark with volcanic caves, majestic waterfalls, and primeval forests.","story":"Dak Nong is a southern province of the Central Highlands, proudly home to a UNESCO Global Geopark with the longest volcanic cave system in Southeast Asia. This red basalt land has many majestic waterfalls like Dray Sap and Gia Long, along with clear blue lakes and lush primeval forests. It also preserves the distinctive cultural treasures of the M''Nong and Ma peoples with gongs, epics, and the traditional brocade-weaving craft.","bestTime":"November to April","specialties":["Dak Nong coffee","Black pepper","Butter avocado","Bamboo-tube rice","M''Nong rice wine"]},"ko":{"summary":"화산 동굴과 웅장한 폭포, 원시림을 지닌 유네스코 세계지질공원의 땅입니다.","story":"닥농은 떠이응우옌 남부 성으로, 동남아시아에서 가장 긴 화산 동굴계를 지닌 유네스코 세계지질공원을 자랑합니다. 이 붉은 현무암 땅에는 드라이삽, 자롱 같은 웅장한 폭포와 맑고 푸른 호수, 울창한 원시림이 펼쳐집니다. 또한 공, 서사시, 전통 토금 직조 기술을 비롯한 므농족과 마족의 독특한 문화 보고를 간직하고 있습니다.","bestTime":"11월~4월","specialties":["닥농 커피","후추","버터 아보카도","껌람(대통밥)","므농 깐 술"]},"ja":{"summary":"火山洞窟と雄大な滝、原生林を持つユネスコ世界ジオパークの地です。","story":"ダクノンはタイグエン高原南部の省で、東南アジア最長の火山洞窟系を持つユネスコ世界ジオパークを誇ります。この赤い玄武岩の地には、ドライサップやザーロンといった雄大な滝、澄んだ青い湖、鬱蒼とした原生林が広がります。また、銅鑼、叙事詩、伝統的な錦織の技をはじめとするムノン族・マ族の独特な文化の宝庫を留めています。","bestTime":"11月〜4月","specialties":["ダクノンのコーヒー","胡椒","バターアボカド","コムラム（竹筒飯）","ムノンのカン酒"]},"zh":{"summary":"拥有火山洞穴、雄伟瀑布与原始森林的联合国教科文组织世界地质公园之地。","story":"得农是西原南部的省份，自豪地坐拥联合国教科文组织世界地质公园，拥有东南亚最长的火山洞穴系统。这片红色玄武岩土地有德雷萨、嘉龙等雄伟瀑布，还有碧蓝清湖与苍郁的原始森林。这里还留存着墨侬族、麻族独特的文化瑰宝，包括铜锣、史诗与传统的土锦织造技艺。","bestTime":"11月至4月","specialties":["得农咖啡","胡椒","牛油果","竹筒饭","墨侬竹竿酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('dien-bien', 'northwest', 'Điện Biên', 'Dien Bien', 'Tây Bắc', '#6e8c5a', 103.0216, 21.7106, 'Vùng đất lịch sử Tây Bắc với chiến trường Điện Biên Phủ lừng lẫy và cảnh sắc núi rừng hùng vĩ.', 'Điện Biên là vùng đất ghi dấu chiến thắng Điện Biên Phủ ''lừng lẫy năm châu, chấn động địa cầu'' năm 1954. Quần thể di tích chiến trường xưa — Đồi A1, Hầm De Castries, Bảo tàng Chiến thắng — là điểm đến thiêng liêng. Bên cạnh đó, Điện Biên còn có cánh đồng Mường Thanh rộng lớn, đèo Pha Đin hùng vĩ và sắc màu văn hóa của người Thái, Mông giữa núi rừng Tây Bắc.', 'Tháng 3–5; dịp 7/5 lễ kỷ niệm chiến thắng', '["Xôi nếp nương","Gạo Điện Biên","Pa pỉnh tộp (cá nướng)","Thịt trâu gác bếp","Rượu sâu chít"]', '{"en":{"summary":"A historic northwestern land with the renowned Dien Bien Phu battlefield and magnificent mountain scenery.","story":"Dien Bien is the land that marks the 1954 Dien Bien Phu victory ''renowned across five continents and shaking the globe''. The complex of old battlefield relics — Hill A1, De Castries'' bunker, the Victory Museum — is a sacred destination. Alongside this, Dien Bien also has the vast Muong Thanh plain, the magnificent Pha Din Pass and the vibrant culture of the Thai and Hmong amid the northwestern mountains.","bestTime":"March–May; around 7 May for the victory commemoration","specialties":["Upland sticky rice","Dien Bien rice","Pa pinh top (grilled fish)","Smoked buffalo meat","Sau chit worm wine"]},"ko":{"summary":"이름 높은 디엔비엔푸 전장과 웅장한 산림 경관을 품은 서북부 역사의 땅.","story":"디엔비엔은 1954년 ''5대륙에 이름을 떨치고 지구를 뒤흔든'' 디엔비엔푸 승리를 새긴 땅입니다. A1 고지, 드 카스트리 벙커, 승리 박물관 등 옛 전장 유적 단지는 신성한 명소입니다. 그 곁에는 드넓은 므엉타인 평야, 웅장한 파딘 고개, 그리고 서북부 산중 타이족·몽족의 다채로운 문화가 있습니다.","bestTime":"3~5월, 5월 7일 승리 기념식 무렵","specialties":["고원 찰밥","디엔비엔 쌀","파삔똡(생선구이)","물소고기 훈제","사우찟 벌레 술"]},"ja":{"summary":"名高いディエンビエンフーの戦場と雄大な山林景観を抱く、西北部の歴史の地。","story":"ディエンビエンは、1954年に「五大陸に名を轟かせ、地球を揺るがした」ディエンビエンフー勝利を刻んだ地です。A1高地、ド・カストリ壕、勝利博物館など、かつての戦場遺跡群は聖なる名所です。その傍らには広大なムオンタイン平野、雄大なファディン峠、そして西北部の山中のターイ族・モン族の彩り豊かな文化があります。","bestTime":"3〜5月、5月7日の勝利記念式典の頃","specialties":["高原のもち米飯","ディエンビエン米","パーピントップ(焼き魚)","水牛肉の燻製","サウチット虫の酒"]},"zh":{"summary":"西北历史之地，拥有名扬天下的奠边府战场和雄奇的山林景观。","story":"奠边是铭刻着1954年「扬名五大洲，震撼全球」奠边府大捷的土地。昔日战场遗迹群——A1高地、德卡斯特里地堡、大捷博物馆——是神圣的目的地。此外，奠边还有辽阔的孟青平原、雄奇的坡丁山口，以及西北山林间泰族、苗族绚丽多彩的文化。","bestTime":"3至5月；5月7日大捷纪念活动前后","specialties":["笼蒸糯米饭","奠边大米","巴丙𤐰（烤鱼）","炕熏水牛肉","竹虫酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('dong-nai', 'southeast', 'Đồng Nai', 'Dong Nai', 'Đông Nam Bộ', '#b07a4a', 107.1829, 11.0581, 'Vùng đất công nghiệp năng động bên sông Đồng Nai, ẩn chứa rừng quốc gia Cát Tiên và những thác nước sinh thái xanh mát.', 'Đồng Nai là tỉnh công nghiệp sầm uất bậc nhất phía Nam, nhưng vẫn giữ được những mảng xanh quý giá. Vườn quốc gia Cát Tiên với rừng nguyên sinh và khu dự trữ sinh quyển là điểm đến hàng đầu cho người yêu thiên nhiên. Bên cạnh đó, những thác nước như Giang Điền, các khu du lịch sinh thái và dòng sông Đồng Nai hiền hòa tạo nên không gian dã ngoại lý tưởng cho người dân Sài Gòn mỗi dịp cuối tuần.', 'Tháng 12 đến tháng 5 (mùa khô)', '["Bưởi Tân Triều","Chôm chôm Long Khánh","Gỏi cá Biên Hòa"]', '{"en":{"summary":"A dynamic industrial land along the Dong Nai River, harboring Cat Tien National Park and cool, green ecological waterfalls.","story":"Dong Nai is one of the most bustling industrial provinces in the South, yet it still keeps precious patches of green. Cat Tien National Park, with its primary forest and biosphere reserve, is a top destination for nature lovers. Alongside it, waterfalls like Giang Dien, eco-tourism areas and the gentle Dong Nai River create an ideal picnic setting for Saigon''s people every weekend.","bestTime":"December to May (dry season)","specialties":["Tan Trieu pomelo","Long Khanh rambutan","Bien Hoa fish salad"]},"ko":{"summary":"동나이강을 낀 역동적인 공업 지대로, 깟띠엔 국립공원과 시원하고 푸른 생태 폭포를 품고 있습니다.","story":"동나이는 남부에서 가장 번성한 공업 성 중 하나이지만 여전히 귀중한 녹지를 간직하고 있습니다. 원시림과 생물권 보전지역을 갖춘 깟띠엔 국립공원은 자연 애호가들의 최고 명소입니다. 그 곁으로 장디엔 같은 폭포들과 생태 관광지, 잔잔히 흐르는 동나이강이 주말마다 사이공 사람들에게 이상적인 소풍 공간을 만들어 줍니다.","bestTime":"12월~5월 (건기)","specialties":["떤찌에우 자몽","롱카잉 람부탄","비엔호아 회무침"]},"ja":{"summary":"ドンナイ川沿いの活気ある工業地帯で、カットティエン国立公園と涼やかで緑のエコ滝を擁します。","story":"ドンナイは南部で最も賑わう工業省のひとつですが、今なお貴重な緑を保っています。原生林と生物圏保護区を擁するカットティエン国立公園は、自然を愛する人々の一番の名所です。その傍らには、ザンディエンなどの滝やエコツーリズム地、穏やかに流れるドンナイ川があり、週末ごとにサイゴンの人々に理想的なピクニックの空間を生み出しています。","bestTime":"12月〜5月（乾季）","specialties":["タンチエウのザボン","ロンカインのランブータン","ビエンホアの魚のなます"]},"zh":{"summary":"同奈河畔充满活力的工业之地，蕴藏着吉仙国家公园和清凉翠绿的生态瀑布。","story":"同奈是南部最繁华的工业省份之一，却依然保留着珍贵的绿意。拥有原始森林和生物圈保护区的吉仙国家公园，是自然爱好者的首选去处。此外，江田等瀑布、众多生态旅游区，以及温柔流淌的同奈河，共同营造出西贡人每逢周末理想的郊游空间。","bestTime":"12月至5月（旱季）","specialties":["新潮柚子","隆庆红毛丹","边和鱼生拌"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('dong-thap', 'mekong-delta', 'Đồng Tháp', 'Dong Thap', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.6062, 10.5656, 'Đất sen hồng của miền Tây với vườn quốc gia Tràm Chim, làng hoa Sa Đéc rực rỡ và những cánh đồng sen bát ngát.', 'Đồng Tháp được mệnh danh là đất sen hồng, vùng đất thuần khiết với những cánh đồng sen bát ngát và hệ sinh thái Đồng Tháp Mười nổi tiếng. Tỉnh sở hữu vườn quốc gia Tràm Chim, ngôi nhà của sếu đầu đỏ quý hiếm, cùng làng hoa Sa Đéc trăm năm tuổi rực rỡ sắc màu. Con người Đồng Tháp chân chất, nghĩa tình, gắn bó với ruộng đồng và hoa sen. Đến đây, du khách được hòa mình vào thiên nhiên trong lành, thưởng thức ẩm thực từ sen và cảm nhận vẻ đẹp bình yên của miền sông nước.', 'Tháng 9 đến tháng 11 mùa nước nổi, hoặc tháng 12-4 mùa sếu về', '["Hủ tiếu Sa Đéc","Các món từ sen","Nem Lai Vung","Quýt hồng Lai Vung","Khô cá lóc"]', '{"en":{"summary":"The pink-lotus land of the Mekong, with Tram Chim National Park, the vibrant Sa Dec flower village and vast lotus fields.","story":"Dong Thap is dubbed the pink-lotus land, a pure land of vast lotus fields and the famous Plain of Reeds ecosystem. The province is home to Tram Chim National Park, where the rare red-crowned crane lives, and the century-old Sa Dec flower village ablaze with color. The people of Dong Thap are down-to-earth and warm-hearted, bound to their fields and lotus flowers. Here, visitors immerse themselves in fresh nature, enjoy lotus-based cuisine and feel the peaceful beauty of the waterland.","bestTime":"September to November for the flood season, or December–April for crane season","specialties":["Sa Dec hu tieu","Lotus dishes","Lai Vung fermented pork roll","Lai Vung pink tangerines","Dried snakehead fish"]},"ko":{"summary":"짬찜 국립공원, 화려한 사덱 꽃마을, 드넓은 연꽃 들판을 간직한 메콩의 분홍 연꽃 고장.","story":"동탑은 분홍 연꽃 고장이라 불리며, 드넓은 연꽃 들판과 이름난 동탑므어이 생태계를 간직한 청정한 땅입니다. 희귀한 붉은머리두루미의 보금자리인 짬찜 국립공원과, 색색으로 화려한 백 년 된 사덱 꽃마을을 품고 있습니다. 동탑 사람들은 소박하고 정 깊으며, 논과 연꽃에 정을 붙이고 살아갑니다. 이곳에서 여행객은 청정한 자연에 흠뻑 빠지고, 연꽃 음식을 맛보며, 물의 고장의 평온한 아름다움을 느낍니다.","bestTime":"9~11월 물난리 철, 또는 12~4월 두루미 철","specialties":["사덱 후띠에우","연꽃 요리","라이붕 넴(발효 돼지고기 롤)","라이붕 분홍 귤","가물치 건어물"]},"ja":{"summary":"チャムチム国立公園、華やかなサーデック花の村、広大な蓮の畑を擁するメコンのピンクの蓮の里。","story":"ドンタップはピンクの蓮の里と称され、広大な蓮の畑と名高いドンタップムオイ生態系を擁する清らかな地です。希少なオオヅルの住処であるチャムチム国立公園と、色とりどりに華やかな百年のサーデック花の村を抱きます。ドンタップの人々は素朴で情に厚く、田と蓮の花に親しんで暮らします。ここで旅人は清らかな自然に浸り、蓮を使った料理を味わい、水の里の穏やかな美しさを感じます。","bestTime":"9〜11月の増水期、または12〜4月のツルの季節","specialties":["サーデックのフーティウ","蓮の料理","ライヴンのネム（発酵豚肉ロール）","ライヴンのピンクみかん","雷魚の干物"]},"zh":{"summary":"湄公的粉红莲乡，拥有茶钦国家公园、绚烂的沙沥花村和一望无际的荷田。","story":"同塔被誉为粉红莲乡，是一片纯净的土地，拥有一望无际的荷田和著名的同塔梅生态系统。该省坐拥珍稀赤颈鹤的家园茶钦国家公园，以及色彩绚烂的百年沙沥花村。同塔人质朴重情，与田地和荷花相依相伴。来到这里，游客可融入清新的自然，品尝以莲为食材的美食，感受水乡宁静之美。","bestTime":"9月至11月涨水季，或12至4月观鹤季","specialties":["沙沥河粉","莲制美食","莱旺酸肉卷","莱旺红橘","雷鱼干"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('gia-lai', 'central-highlands', 'Gia Lai', 'Gia Lai', 'Tây Nguyên', '#8a6e4b', 108.2393, 13.7988, 'Cao nguyên đại ngàn với Biển Hồ T''Nưng xanh thẳm, đồi chè, thác nước và không gian văn hóa cồng chiêng.', 'Gia Lai là vùng cao nguyên bazan màu mỡ giữa Tây Nguyên, nổi tiếng với Biển Hồ T''Nưng được ví như đôi mắt Pleiku, những đồi chè, đồi cà phê bạt ngàn và các con thác hùng vĩ. Tỉnh là cái nôi của Không gian văn hóa cồng chiêng - di sản thế giới, với đời sống tinh thần phong phú của người Gia Rai, Ba Na. Cảnh sắc thiên nhiên trù phú cùng cà phê thơm ngon là niềm tự hào của phố núi Pleiku.', 'Tháng 11 đến tháng 4', '["Phở khô Gia Lai","Bún mắm cua","Cà phê Pleiku","Muối kiến vàng","Bò một nắng"]', '{"en":{"summary":"A vast highland plateau with the deep-blue T''Nung Sea Lake, tea hills, waterfalls, and gong cultural space.","story":"Gia Lai is a fertile basalt plateau in the heart of the Central Highlands, famous for T''Nung Sea Lake, likened to the eyes of Pleiku, vast tea and coffee hills, and majestic waterfalls. The province is the cradle of the Gong Cultural Space - a world heritage - with the rich spiritual life of the Jarai and Bahnar peoples. The bountiful natural scenery and fragrant coffee are the pride of the mountain town of Pleiku.","bestTime":"November to April","specialties":["Gia Lai dry pho","Crab-paste noodle soup","Pleiku coffee","Yellow ant salt","One-sun-dried beef"]},"ko":{"summary":"짙푸른 비엔호 트능 호수와 차밭, 폭포, 그리고 공 문화 공간을 지닌 대자연의 고원입니다.","story":"자라이는 떠이응우옌 한복판의 비옥한 현무암 고원으로, 쁠래이꾸의 두 눈이라 불리는 비엔호 트능 호수, 끝없는 차밭과 커피밭, 그리고 웅장한 폭포로 유명합니다. 이 성은 세계유산인 공 문화 공간의 요람으로, 자라이족과 바나족의 풍부한 정신생활을 간직하고 있습니다. 풍요로운 자연 경관과 향긋한 커피는 산간 도시 쁠래이꾸의 자랑입니다.","bestTime":"11월~4월","specialties":["자라이 마른 쌀국수","분맘꾸어(게장 국수)","쁠래이꾸 커피","노란 개미알 소금","한볕 말린 소고기"]},"ja":{"summary":"深く青いビエンホー・トゥヌン湖と茶畑、滝、そして銅鑼文化空間を持つ大自然の高原です。","story":"ジャライはタイグエン高原の真ん中の肥沃な玄武岩高原で、プレイクの両眼と称されるビエンホー・トゥヌン湖、果てしない茶畑とコーヒー畑、そして雄大な滝で有名です。この省は世界遺産である銅鑼文化空間の揺り籠で、ジャライ族とバナ族の豊かな精神生活を留めています。豊かな自然の景観と香り高いコーヒーは、山あいの町プレイクの誇りです。","bestTime":"11月〜4月","specialties":["ジャライの汁なしフォー","ブンマムクア（蟹味噌そば）","プレイクのコーヒー","黄色い蟻の卵の塩","天日干しの牛肉"]},"zh":{"summary":"大山深处的高原，拥有深蓝的特能海湖、茶丘、瀑布与铜锣文化空间。","story":"嘉莱是西原中部肥沃的玄武岩高原，以被誉为波来古之眼的特能海湖、无边的茶丘与咖啡丘，以及雄伟的瀑布而闻名。该省是世界遗产铜锣文化空间的摇篮，嘉莱族、巴拿族的精神生活丰富多彩。富饶的自然景观与香醇的咖啡，是山城波来古的骄傲。","bestTime":"11月至4月","specialties":["嘉莱干河粉","蟹酱米线","波来古咖啡","黄蚁卵盐","一阳晒牛肉"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ha-giang', 'northeast', 'Hà Giang', 'Ha Giang', 'Đông Bắc', '#4f7b6a', 104.9753, 22.7658, 'Vùng địa đầu Tổ quốc với cao nguyên đá hùng vĩ, những cung đèo huyền thoại và sắc màu văn hóa vùng cao.', 'Hà Giang là nơi đất trời gặp nhau ở tận cùng phía Bắc. Cao nguyên đá Đồng Văn — công viên địa chất toàn cầu — trải dài những dãy núi tai mèo trùng điệp. Mùa thu, hoa tam giác mạch phủ hồng các triền đồi; mùa lúa chín, ruộng bậc thang vàng rực. Đây là vùng đất của những con đường đẹp đến nghẹt thở và những con người mộc mạc, hiếu khách.', 'Tháng 9 (lúa chín) và tháng 10–12 (hoa tam giác mạch)', '["Thắng cố","Cháo ấu tẩu","Rượu ngô","Bánh tam giác mạch"]', '{"en":{"summary":"The northernmost frontier with a magnificent rocky plateau, legendary mountain passes and vibrant highland culture.","story":"Ha Giang is where heaven and earth meet at the very top of the north. The Dong Van Karst Plateau — a global geopark — stretches out in rolling ranges of jagged ''cat''s-ear'' rock. In autumn, buckwheat flowers blush pink across the hillsides; in the ripe rice season, the terraced fields blaze gold. This is a land of roads so beautiful they take your breath away, and of rustic, hospitable people.","bestTime":"September (ripe rice) and October–December (buckwheat flowers)","specialties":["Thang co stew","Au tau porridge","Corn wine","Buckwheat cake"]},"ko":{"summary":"웅장한 석회암 고원, 전설적인 고갯길, 다채로운 고원 문화를 품은 최북단 변경.","story":"하장은 북쪽 끝에서 하늘과 땅이 만나는 곳입니다. 세계지질공원인 동반 카르스트 고원은 첩첩한 톱니 바위산을 길게 펼쳐 보입니다. 가을이면 메밀꽃이 언덕을 분홍빛으로 물들이고, 벼 익는 시즌이면 계단식 논이 황금빛으로 타오릅니다. 이곳은 숨이 멎을 만큼 아름다운 길과 소박하고 손님을 반기는 사람들의 땅입니다.","bestTime":"9월(벼 익음)과 10~12월(메밀꽃)","specialties":["탕꼬 탕","어우떠우 죽","옥수수 술","메밀 떡"]},"ja":{"summary":"雄大な石灰岩高原、伝説的な峠道、彩り豊かな高原文化を抱く最北端の辺境。","story":"ハザンは、北の果てで天と地が出会う場所です。世界ジオパークであるドンヴァン・カルスト高原は、連なる鋸歯状の岩山を長く広げます。秋にはソバの花が丘陵を桃色に染め、稲の実る季節には棚田が黄金色に燃え上がります。ここは息をのむほど美しい道と、素朴でもてなし好きな人々の地です。","bestTime":"9月(稲の実り)と10〜12月(ソバの花)","specialties":["タンコー鍋","アウタウ粥","トウモロコシ酒","ソバの餅"]},"zh":{"summary":"祖国最北端的边陲，拥有雄奇的岩石高原、传奇的山口道路和绚丽多彩的高原文化。","story":"河江是天地在北部尽头相会之地。同文岩石高原——世界地质公园——绵延着层叠的猫耳岩山。秋天，荞麦花将山坡染成一片粉红；稻谷成熟季，梯田金黄灿烂。这是一片道路美得令人窒息、人民质朴好客的土地。","bestTime":"9月（稻谷成熟）和10至12月（荞麦花）","specialties":["胜火炖菜","乌头粥","玉米酒","荞麦糕"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ha-nam', 'red-river-delta', 'Hà Nam', 'Ha Nam', 'Đồng bằng sông Hồng', '#c7993f', 105.965, 20.5424, 'Vùng đất tâm linh với chùa Tam Chúc kỳ vĩ, non nước hữu tình và những làng nghề truyền thống lâu đời.', 'Hà Nam là cửa ngõ phía nam đồng bằng Bắc Bộ, vùng đất của núi non, sông nước và những công trình tâm linh đồ sộ. Nổi bật nhất là quần thể chùa Tam Chúc được mệnh danh ngôi chùa lớn nhất thế giới, tựa lưng vào núi mặt hướng ra hồ mênh mông. Hà Nam còn có những làng nghề trống Đọi Tam, lụa Nha Xá và đặc sản cá kho làng Vũ Đại nức tiếng. Phong cảnh hữu tình hòa quyện với chiều sâu văn hóa khiến Hà Nam ngày càng hấp dẫn du khách hành hương.', 'Tháng 1 đến tháng 3 (mùa lễ hội)', '["Cá kho làng Vũ Đại","Bánh cuốn Phủ Lý","Chuối ngự Đại Hoàng","Trống Đọi Tam"]', '{"en":{"summary":"A spiritual land with the majestic Tam Chuc Pagoda, harmonious mountains and water, and long-standing craft villages.","story":"Ha Nam is the southern gateway to the Northern delta, a land of mountains, rivers, and grand spiritual structures. Most striking is the Tam Chuc Pagoda complex, hailed as the largest pagoda in the world, backing onto mountains and facing a vast lake. Ha Nam also has the craft villages of Doi Tam drums and Nha Xa silk, and the famous specialty of Vu Dai village braised fish. Its harmonious scenery, blended with cultural depth, makes Ha Nam ever more appealing to pilgrim travelers.","bestTime":"January to March (festival season)","specialties":["Vu Dai village braised fish","Phu Ly steamed rice rolls","Dai Hoang royal bananas","Doi Tam drums"]},"ko":{"summary":"웅장한 땀쭉 사찰과 빼어난 산수, 유서 깊은 전통 마을을 지닌 영적인 땅.","story":"하남은 북부 평야의 남쪽 관문으로, 산과 강, 그리고 웅장한 영적 건축물의 땅입니다. 가장 돋보이는 것은 세계에서 가장 큰 사찰로 불리는 땀쭉 사찰군으로, 산을 등지고 드넓은 호수를 마주합니다. 하남에는 또한 도이땀 북 마을, 냐싸 비단, 그리고 이름난 부다이 마을 생선 조림 명물이 있습니다. 빼어난 풍경과 깊은 문화가 어우러져 하남은 점점 더 많은 순례 여행자를 사로잡고 있습니다.","bestTime":"1월~3월(축제 철)","specialties":["부다이 마을 생선 조림","푸리 바인꾸온","다이호앙 응으 바나나","도이땀 북"]},"ja":{"summary":"雄大なタムチュック寺、山紫水明の景色、そして古き伝統の職人の里を擁する、信仰の地。","story":"ハナムは北部デルタの南の玄関口で、山々、川や湖、そして壮大な信仰の建造物の地です。最も際立つのは世界最大の寺院と称されるタムチュック寺院群で、山を背に、広大な湖に面しています。ハナムにはまた、ドイタムの太鼓、ニャーサーの絹といった職人の里や、名高い名産のヴーダイ村の煮魚もあります。山紫水明の景色と文化の奥深さが溶け合い、ハナムは巡礼の旅行者をますます惹きつけています。","bestTime":"1月から3月（祭りの季節）","specialties":["ヴーダイ村の煮魚","フーリーのバインクオン","ダイホアンの献上バナナ（チュオイグ）","ドイタムの太鼓"]},"zh":{"summary":"灵性之地，拥有雄奇的三祝寺、秀美的山水和历史悠久的传统手工艺村。","story":"河南是北部平原南端的门户，是山峦、江河与宏伟灵性建筑之地。最为突出的是被誉为世界最大寺庙的三祝寺群，背靠青山，面朝浩瀚的湖泊。河南还有碓三鼓、芽舍丝绸等手工艺村和著名的武大村焖鱼特产。秀美的风光与深厚的文化交融，使河南日益吸引前来朝圣的游客。","bestTime":"1月至3月（庙会季）","specialties":["武大村焖鱼","府里卷粉","大黄御香蕉","碓三鼓"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ha-noi', 'red-river-delta', 'Hà Nội', 'Hanoi', 'Đồng bằng sông Hồng', '#c7993f', 105.6994, 20.9988, 'Thủ đô ngàn năm văn hiến, nơi giao thoa giữa nét cổ kính và nhịp sống hiện đại.', 'Hà Nội là nơi thời gian như chậm lại. Phố cổ rêu phong, hồ Hoàn Kiếm thơ mộng, những hàng cây cổ thụ và mùi hương hoa sữa mỗi độ thu về. Ẩm thực Hà Nội tinh tế với phở, bún chả, cà phê trứng. Mỗi góc phố đều có một câu chuyện đáng để lắng nghe.', 'Mùa thu (tháng 9–11), tiết trời mát dịu', '["Phở","Bún chả","Cà phê trứng","Bánh cuốn","Chả cá Lã Vọng"]', '{"en":{"summary":"A thousand-year-old capital of civilization, where the ancient and the modern intertwine.","story":"Hanoi is a place where time seems to slow. The moss-covered Old Quarter, the dreamy Hoan Kiem Lake, the rows of ancient trees, and the scent of milk-flower blossoms each autumn. Hanoi''s cuisine is refined, with pho, bun cha, and egg coffee. Every street corner holds a story worth listening to.","bestTime":"Autumn (September–November), when the weather is cool and mild","specialties":["Pho","Bun cha","Egg coffee","Steamed rice rolls","La Vong grilled fish"]},"ko":{"summary":"천년 문헌의 수도, 고풍스러운 정취와 현대의 활기가 어우러지는 곳.","story":"하노이는 시간이 느리게 흐르는 듯한 곳입니다. 이끼 낀 구시가지, 시적인 호안끼엠 호수, 노거수 가로수, 그리고 가을마다 풍기는 밀크우드 꽃향기. 하노이 음식은 퍼, 분짜, 에그 커피로 섬세합니다. 거리 모퉁이마다 귀 기울일 만한 이야기가 하나씩 담겨 있습니다.","bestTime":"가을(9~11월), 선선한 날씨","specialties":["퍼","분짜","에그 커피","바인꾸온","라봉 짜까"]},"ja":{"summary":"千年の文献の都。古き趣と現代の暮らしのリズムが交わる場所。","story":"ハノイは時がゆるやかに流れる場所。苔むした旧市街、詩情あふれるホアンキエム湖、老樹の並木、そして秋ごとに漂うニュウカ（牛乳花）の香り。ハノイの食はフォー、ブンチャー、エッグコーヒーと繊細です。街角のどこにも、耳を傾ける価値のある物語があります。","bestTime":"秋（9〜11月）、涼やかで心地よい気候","specialties":["フォー","ブンチャー","エッグコーヒー","バインクオン","チャーカー・ラヴォン"]},"zh":{"summary":"千年文献之都，古朴韵味与现代生活节奏交融之地。","story":"河内是时光仿佛放慢脚步的地方。长满青苔的古街、诗意的还剑湖、参天的古树，以及每到秋天弥漫的牛奶花香。河内饮食精致，有米粉、烤肉米线、鸡蛋咖啡。每一处街角都有一个值得聆听的故事。","bestTime":"秋季（9月至11月），天气凉爽宜人","specialties":["米粉","烤肉米线","鸡蛋咖啡","卷粉","罗望炸鱼"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ha-tinh', 'north-central-coast', 'Hà Tĩnh', 'Ha Tinh', 'Bắc Trung Bộ', '#5a8aa6', 105.735, 18.2917, 'Miền quê núi Hồng sông La, nơi giao hòa giữa danh lam cổ tự, biển hoang sơ và những trang sử bi tráng.', 'Hà Tĩnh là dải đất hẹp miền Trung gắn liền với núi Hồng Lĩnh và dòng sông La thơ mộng. Vùng đất hiếu học này tự hào với chùa Hương Tích linh thiêng, bãi biển Thiên Cầm êm đềm và ngã ba Đồng Lộc thấm đẫm những trang sử bi hùng. Người Hà Tĩnh chân chất, mến khách, gìn giữ kho tàng dân ca ví giặm được UNESCO vinh danh, làm say lòng bao du khách phương xa.', 'Tháng 4 đến tháng 8', '["Kẹo cu đơ","Bưởi Phúc Trạch","Mực một nắng Thiên Cầm","Bánh đa vừng"]', '{"en":{"summary":"A countryside of Hong Mountain and La River, where ancient temples, pristine beaches, and tragic-heroic history all converge.","story":"Ha Tinh is a narrow strip of central land bound to the Hong Linh Range and the poetic La River. This studious land takes pride in the sacred Huong Tich Pagoda, the gentle Thien Cam Beach and the Dong Loc Junction steeped in tragic, heroic history. The people of Ha Tinh are honest and hospitable, preserving the treasure of vi giam folk songs honored by UNESCO, captivating travelers from afar.","bestTime":"April to August","specialties":["Cu do candy","Phuc Trach pomelo","Thien Cam sun-dried squid","Sesame rice crackers (banh da vung)"]},"ko":{"summary":"홍산과 라강의 시골 고장으로, 고찰과 청정 해변, 비장한 역사가 어우러진 곳입니다.","story":"하띤은 홍린 산맥과 시적인 라강에 이어진 중부의 좁은 땅입니다. 학문을 숭상하는 이 고장은 신성한 흐엉띡 사원과 잔잔한 티엔껌 해변, 비장한 역사가 스민 동록 삼거리를 자랑합니다. 하띤 사람들은 소박하고 손님을 환대하며, 유네스코가 인정한 비잠 민요의 보고를 간직해 먼 곳에서 온 나그네의 마음을 사로잡습니다.","bestTime":"4월부터 8월까지","specialties":["꾸더 사탕","푹짝 자몽","티엔껌 반건조 오징어","반다븡(깨 라이스 크래커)"]},"ja":{"summary":"ホン山とラー川の田園の地。古寺、手つかずのビーチ、悲壮な歴史が溶け合う場所です。","story":"ハティンは、ホンリン山脈と詩情あふれるラー川につながる中部の細長い地です。学問を尊ぶこの地は、神聖なフオンティック寺、穏やかなティエンカムビーチ、悲壮な歴史が染みこんだドンロック三叉路を誇ります。ハティンの人々は素朴で客をもてなし、ユネスコが称えたヴィザム民謡の宝庫を守り伝え、遠方からの旅人の心をとらえます。","bestTime":"4月から8月まで","specialties":["クードー飴","フックチャックのザボン","ティエンカムの一夜干しイカ","バインダーヴング（ゴマの米せんべい）"]},"zh":{"summary":"鸿山蓝水的乡野之地，古寺名刹、原生海滩与悲壮史诗在此交融。","story":"河静是中部一条狭长的土地，与鸿岭山脉和诗意的蓝江相连。这片崇文重学的土地，以神圣的香迹寺、宁静的天琴海滩与浸透悲壮历史的同禄三岔路为荣。河静人淳朴好客，守护着被联合国教科文组织表彰的𠶚𠶚（vi giam）民歌宝库，令远方游人为之倾心。","bestTime":"4月至8月","specialties":["枯朵糖","福泽柚","天琴一夜干鱿鱼","芝麻米饼"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('hai-duong', 'red-river-delta', 'Hải Dương', 'Hai Duong', 'Đồng bằng sông Hồng', '#c7993f', 106.3572, 20.9298, 'Xứ Đông với quần thể Côn Sơn - Kiếp Bạc linh thiêng, đảo cò sinh thái và đặc sản bánh đậu xanh trứ danh.', 'Hải Dương là vùng đất xứ Đông giàu truyền thống lịch sử và văn hóa, nơi lưu dấu hai vị anh hùng Trần Hưng Đạo và Nguyễn Trãi qua quần thể Côn Sơn - Kiếp Bạc. Vùng đất này còn có Đảo Cò Chi Lăng Nam, điểm sinh thái độc đáo giữa đồng bằng. Hải Dương nổi tiếng với bánh đậu xanh thơm bùi, vải thiều Thanh Hà ngọt lịm và bánh gai Ninh Giang dẻo thơm. Sự kết hợp giữa di sản tâm linh, thiên nhiên trong lành và ẩm thực đặc sắc làm nên sức hút riêng của vùng quê này.', 'Tháng 1 đến tháng 4', '["Bánh đậu xanh","Vải thiều Thanh Hà","Bánh gai Ninh Giang","Bánh đa Kẻ Sặt"]', '{"en":{"summary":"The eastern land, with the sacred Con Son - Kiep Bac complex, an ecological stork island, and famous mung-bean cakes.","story":"Hai Duong is an eastern land rich in historical and cultural tradition, where two heroes — Tran Hung Dao and Nguyen Trai — left their mark through the Con Son - Kiep Bac complex. This land also has Chi Lang Nam Stork Island, a unique ecological spot in the heart of the delta. Hai Duong is famous for its fragrant mung-bean cakes, sweet Thanh Ha lychees, and chewy, fragrant Ninh Giang gai cakes. The blend of spiritual heritage, fresh nature, and distinctive cuisine gives this rural region its own special appeal.","bestTime":"January to April","specialties":["Mung-bean cake","Thanh Ha lychee","Ninh Giang gai cake","Ke Sat rice crackers"]},"ko":{"summary":"신성한 꼰선-끼엡박 유적군과 생태 백로섬, 그리고 이름난 녹두떡 명물을 지닌 동(東) 지방.","story":"하이즈엉은 역사와 문화 전통이 풍성한 동 지방으로, 꼰선-끼엡박 유적군을 통해 두 영웅 쩐흥다오와 응우옌짜이의 자취가 깃든 곳입니다. 이 땅에는 또한 평야 한가운데의 독특한 생태 명소인 찌랑남 백로섬이 있습니다. 하이즈엉은 고소하고 향긋한 녹두떡, 달콤한 타인하 여지, 쫄깃하고 향기로운 닌장 가이떡으로 유명합니다. 영적 유산과 맑은 자연, 빼어난 음식의 어우러짐이 이 고장만의 매력을 빚어냅니다.","bestTime":"1월~4월","specialties":["녹두떡","타인하 여지","닌장 가이떡","께삿 바인다"]},"ja":{"summary":"神聖なコンソン・キエプバク史跡群、生態観察の鷺島、そして名高い緑豆菓子を擁する東地方。","story":"ハイズオンは歴史と文化の伝統豊かな東地方であり、コンソン・キエプバク史跡群を通じて二人の英雄チャン・フン・ダオとグエン・チャイの足跡を留める地です。この地にはまた、デルタ地帯に佇む独特な生態観察地チランナム鷺島もあります。ハイズオンは香り高い緑豆菓子、とろけるように甘いタインハー産ライチ、もちもちと香ばしいニンザンのバインガイ（黒ゴマ団子）で名高い地です。精神的な遺産、澄んだ自然、そして特色ある食が織りなす魅力が、この里ならではの引力を生み出しています。","bestTime":"1月から4月","specialties":["緑豆菓子（バインダウサイン）","タインハー産ライチ","ニンザンのバインガイ","ケーサットのバインダー"]},"zh":{"summary":"拥有神圣的昆山-劫泊遗迹群、生态鹭岛和著名绿豆糕特产的东地区。","story":"海阳是历史与文化传统深厚的东地区，通过昆山-劫泊遗迹群留有陈兴道和阮廌两位英雄的足迹。这片土地还有支棱南鹭岛，是平原上独特的生态景点。海阳以香甜的绿豆糕、甘甜的青河荔枝和柔韧喷香的宁江麻饼闻名。灵性遗产、清新自然与特色美食的结合，造就了这片乡土独特的魅力。","bestTime":"1月至4月","specialties":["绿豆糕","青河荔枝","宁江麻饼","继䅵米脆饼"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('hai-phong', 'red-river-delta', 'Hải Phòng', 'Hai Phong', 'Đồng bằng sông Hồng', '#c7993f', 106.6156, 20.8033, 'Thành phố cảng năng động với đảo Cát Bà, vịnh Lan Hạ và những bãi biển truyền thống bên hoa phượng đỏ.', 'Hải Phòng là thành phố hoa phượng đỏ, cửa ngõ ra biển lớn của miền Bắc với cảng biển sầm uất bậc nhất cả nước. Nơi đây hội tụ vẻ đẹp của biển đảo Cát Bà, vịnh Lan Hạ thơ mộng cùng những bãi tắm Đồ Sơn quen thuộc. Ẩm thực đường phố Hải Phòng nức tiếng với bánh đa cua, bánh mì cay, nem cua bể khiến thực khách say lòng. Người dân đất Cảng phóng khoáng, mến khách, tạo nên nét duyên riêng cho thành phố biển sôi động này.', 'Tháng 4 đến tháng 9', '["Bánh đa cua","Bánh mì cay","Nem cua bể","Hải sản Cát Bà"]', '{"en":{"summary":"A dynamic port city with Cat Ba Island, Lan Ha Bay, and classic beaches beneath the red flame trees.","story":"Hai Phong is the city of red flame flowers, the North''s gateway to the open sea, home to one of the country''s busiest seaports. Here the beauty of Cat Ba''s islands, the dreamy Lan Ha Bay, and the familiar Do Son beaches all come together. Hai Phong''s street food is renowned, with crab noodle soup, spicy bread, and sea-crab spring rolls captivating every diner. The open-hearted, hospitable people of the port city give this lively coastal hub its own special charm.","bestTime":"April to September","specialties":["Crab noodle soup","Spicy bread","Sea-crab spring rolls","Cat Ba seafood"]},"ko":{"summary":"깟바섬과 란하만, 붉은 봉황화 곁의 전통 해변을 품은 활기찬 항구 도시.","story":"하이퐁은 붉은 봉황화의 도시로, 전국에서 손꼽히게 번화한 항구를 지닌 북부의 큰 바다 관문입니다. 이곳에는 깟바 섬바다와 시적인 란하만, 그리고 친숙한 도선 해변의 아름다움이 한데 모여 있습니다. 하이퐁의 길거리 음식은 바인다꾸어, 매운 바게트, 게살 넴으로 이름나 미식가의 마음을 사로잡습니다. 항구 도시 사람들은 호방하고 손님을 반겨, 이 활기찬 바다 도시만의 정취를 빚어냅니다.","bestTime":"4월~9월","specialties":["바인다꾸어(게 쌀국수)","매운 바게트","게살 넴","깟바 해산물"]},"ja":{"summary":"カットバ島、ランハ湾、そして赤い鳳凰木の咲く伝統の海辺を擁する、活気あふれる港湾都市。","story":"ハイフォンは赤い鳳凰木の街であり、国内随一の繁栄を誇る港を擁する北部の海への玄関口です。カットバ島の海と島の美しさ、詩情あふれるランハ湾、そして親しみ深いドーソンビーチが集う地です。ハイフォンの屋台料理はバインダークア、激辛バインミー、カニ春巻きで名高く、食通たちを虜にします。港町の人々はおおらかで客好きで、この活気あふれる海の街ならではの魅力を生み出しています。","bestTime":"4月から9月","specialties":["バインダークア（カニ入り米麺）","激辛バインミー","カニ春巻き","カットバの海の幸"]},"zh":{"summary":"充满活力的港口城市，拥有吉婆岛、兰下湾和凤凰花掩映下的传统海滩。","story":"海防是凤凰花之城，是北部通往大海的门户，拥有全国最繁忙的港口之一。这里汇聚了吉婆海岛、诗意的兰下湾和熟悉的图山海滩之美。海防的街头美食以蟹米线、辣味面包、海蟹卷闻名，令食客陶醉。港城的人们豪爽好客，为这座生机勃勃的海滨城市平添独特韵味。","bestTime":"4月至9月","specialties":["蟹米线","辣味面包","海蟹卷","吉婆海鲜"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('hau-giang', 'mekong-delta', 'Hậu Giang', 'Hau Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.6223, 9.7849, 'Vùng đất sông nước trù phú với chợ nổi Ngã Bảy huyền thoại, khu bảo tồn Lung Ngọc Hoàng và những vườn cây xanh mát.', 'Hậu Giang là tỉnh nằm ở trung tâm vùng Tây sông Hậu, mang đậm nét đẹp sông nước miệt vườn đồng bằng. Nơi đây có chợ nổi Ngã Bảy huyền thoại đi vào câu vọng cổ, khu bảo tồn thiên nhiên Lung Ngọc Hoàng được ví như lá phổi xanh và những vườn khóm, vườn cây trái xanh ngút ngàn. Người dân Hậu Giang phóng khoáng, nghĩa tình, gắn bó với nghề nông và sông nước. Đến Hậu Giang, du khách được trải nghiệm văn hóa thương hồ, ẩm thực đồng quê và vẻ đẹp yên bình của vùng đất phương Nam.', 'Tháng 11 đến tháng 4, mùa khô thuận tiện du lịch', '["Khóm Cầu Đúc","Cá thát lát Hậu Giang","Bưởi Năm Roi Phú Hữu","Đọt choại"]', '{"en":{"summary":"A fertile waterland with the legendary Nga Bay Floating Market, the Lung Ngoc Hoang Reserve and cool green orchards.","story":"Hau Giang is a province at the center of the western Hau River region, rich in the orchard-and-river beauty of the delta. Here lie the legendary Nga Bay Floating Market immortalized in vong co song, the Lung Ngoc Hoang Nature Reserve likened to a green lung, and endless pineapple and fruit orchards. The people of Hau Giang are free-spirited and warm-hearted, bound to farming and the rivers. In Hau Giang, visitors experience river-trader culture, country cuisine and the peaceful beauty of the southern land.","bestTime":"November to April, the dry season convenient for travel","specialties":["Cau Duc pineapple","Hau Giang clown knifefish","Phu Huu nam roi pomelo","Dot choai fern"]},"ko":{"summary":"전설의 응아바이 수상시장, 룽응옥호앙 보호구역, 시원한 초록 과수원을 간직한 비옥한 물의 고장.","story":"후장은 후강 서부 지역 중심에 자리한 성으로, 델타의 과수원·강변 정취가 짙게 배어 있습니다. 보꼬 노래에 길이 남은 전설의 응아바이 수상시장, 초록 허파에 비견되는 룽응옥호앙 자연보호구역, 끝없이 펼쳐진 파인애플·과수원이 있습니다. 후장 사람들은 자유롭고 정 깊으며, 농사와 강에 정을 붙이고 살아갑니다. 후장에서 여행객은 뱃사람 문화, 시골 음식, 남부 땅의 평온한 아름다움을 체험합니다.","bestTime":"11~4월, 여행하기 편한 건기","specialties":["꺼우둑 파인애플","후장 클라운나이프피시","푸흐우 남로이 포멜로","돗초아이 고사리"]},"ja":{"summary":"伝説のガーバイ水上市場、ルンゴックホアン保護区、涼しげな緑の果樹園を擁する肥沃な水の里。","story":"ハウザンはハウ川西部地域の中心に位置する省で、デルタの果樹園・川辺の趣が色濃く息づきます。ヴォンコーに歌い継がれた伝説のガーバイ水上市場、緑の肺にたとえられるルンゴックホアン自然保護区、そして果てしなく広がるパイナップル・果樹園があります。ハウザンの人々は自由で情に厚く、農業と川に親しんで暮らします。ハウザンで旅人は舟人の文化、田舎料理、南部の地の穏やかな美しさを体験します。","bestTime":"11〜4月、旅行しやすい乾季","specialties":["カウドゥックのパイナップル","ハウザンのナギナタナマズ","フーフウのナムロイ・ザボン","ドッチョアイ（シダ）"]},"zh":{"summary":"富饶的水乡，拥有传奇的七岔水上市场、玉皇洼保护区和清凉翠绿的果园。","story":"后江是位于后江西部地区中心的省份，浓郁地洋溢着三角洲的果园水乡之美。这里有被写进望古曲的传奇七岔水上市场、被誉为绿肺的玉皇洼自然保护区，以及一望无际的菠萝园和果园。后江人豪爽重情，与农事和水乡相依相伴。来到后江，游客可体验商旅文化、乡村美食和南方大地宁静之美。","bestTime":"11月至4月，便于旅游的旱季","specialties":["梂笃菠萝","后江刀鱼","富有五瓣柚","蕨菜嫩芽"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ho-chi-minh', 'southeast', 'TP. Hồ Chí Minh', 'Ho Chi Minh City', 'Đông Nam Bộ', '#b07a4a', 106.6954, 10.7405, 'Đầu tàu kinh tế sôi động, hào sảng và không bao giờ ngủ — nơi cũ và mới đan xen.', 'Sài Gòn — TP. Hồ Chí Minh là thành phố của năng lượng. Từ những tòa nhà chọc trời đến con hẻm nhỏ thơm mùi cà phê, từ chợ Bến Thành nhộn nhịp đến những quán ăn vỉa hè hấp dẫn. Người Sài Gòn phóng khoáng, hiếu khách. Đây là nơi mọi ước mơ đều có chỗ đứng.', 'Mùa khô tháng 12–4', '["Cơm tấm","Hủ tiếu","Bánh mì","Phá lấu","Cà phê sữa đá"]', '{"en":{"summary":"A vibrant, warm-hearted economic powerhouse that never sleeps—where the old and the new intertwine.","story":"Saigon—Ho Chi Minh City is a city of energy. From skyscrapers to little alleys fragrant with coffee, from the bustling Ben Thanh Market to enticing sidewalk eateries. The Saigonese are generous and hospitable. This is a place where every dream has its place.","bestTime":"Dry season, December to April","specialties":["Com tam (broken-rice plate)","Hu tieu noodles","Banh mi","Pha lau","Iced milk coffee"]},"ko":{"summary":"활기차고 호방하며 결코 잠들지 않는 경제 견인차 — 옛것과 새것이 뒤섞인 곳.","story":"사이공 — 호찌민시는 에너지의 도시입니다. 마천루에서 커피 향이 감도는 좁은 골목까지, 분주한 벤탄 시장에서 군침 도는 길거리 식당까지. 사이공 사람들은 너그럽고 손님을 환대합니다. 이곳은 모든 꿈이 자리를 잡을 수 있는 곳입니다.","bestTime":"12~4월 건기","specialties":["껌땀","후띠에우","반미","파러우","연유 아이스커피"]},"ja":{"summary":"活気にあふれ、大らかで、決して眠らない経済の牽引役 — 古きと新しきが交わる場所。","story":"サイゴン — ホーチミン市はエネルギーの街です。摩天楼からコーヒーの香る小さな路地まで、賑わうベンタイン市場から食欲をそそる路上の食堂まで。サイゴンの人々は大らかでもてなし好きです。ここはあらゆる夢が居場所を持てる場所です。","bestTime":"12〜4月の乾季","specialties":["コムタム","フーティウ","バインミー","ファーラウ","練乳アイスコーヒー"]},"zh":{"summary":"充满活力、豪爽而永不入眠的经济火车头——新旧在此交织之地。","story":"西贡——胡志明市是一座充满能量的城市。从摩天大楼到飘着咖啡香的小巷，从熙攘的滨城市场到诱人的街边食肆。西贡人豪爽好客。这里是每一个梦想都能扎根之处。","bestTime":"12月至4月旱季","specialties":["碎米饭","粿条","越式法包","卤什","炼乳冰咖啡"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('hoa-binh', 'northwest', 'Hòa Bình', 'Hoa Binh', 'Tây Bắc', '#6e8c5a', 105.3417, 20.6856, 'Cửa ngõ Tây Bắc với thung lũng Mai Châu thơ mộng, hồ Hòa Bình kỳ vĩ và cái nôi của nền Văn hóa Hòa Bình cổ.', 'Hòa Bình là cửa ngõ vùng Tây Bắc, quê hương của đồng bào Mường cùng nền Văn hóa Hòa Bình nổi tiếng trong khảo cổ học. Nơi đây có thung lũng Mai Châu thanh bình với bản làng người Thái, nhà sàn và điệu xòe say đắm; hồ Hòa Bình rộng lớn được ví như ''Hạ Long thu nhỏ'' cùng đền Thác Bờ linh thiêng. Hòa Bình hấp dẫn du khách bởi cảnh sắc núi rừng, suối khoáng nóng Kim Bôi và bản sắc văn hóa Mường, Thái đậm đà.', 'Tháng 9 đến tháng 12', '["Cơm lam","Thịt lợn mán","Cá nướng sông Đà","Rượu cần Mường"]', '{"en":{"summary":"The gateway to the northwest with the poetic Mai Chau Valley, the magnificent Hoa Binh Lake and the cradle of the ancient Hoa Binh Culture.","story":"Hoa Binh is the gateway to the northwest, homeland of the Muong people and of the Hoa Binh Culture famous in archaeology. Here lies the peaceful Mai Chau Valley with its Thai villages, stilt houses and captivating xoe dance; the vast Hoa Binh Lake likened to a ''miniature Ha Long Bay'' along with the sacred Thac Bo Temple. Hoa Binh draws visitors with its mountain scenery, the Kim Boi hot mineral springs and the rich cultural identity of the Muong and Thai.","bestTime":"September to December","specialties":["Bamboo-tube rice","Man pork","Da River grilled fish","Muong ruou can wine"]},"ko":{"summary":"시적인 마이쩌우 골짜기, 웅장한 호아빈 호수, 고대 호아빈 문화의 요람을 품은 서북부의 관문.","story":"호아빈은 서북부의 관문이자 므엉족의 고향으로, 고고학에서 유명한 호아빈 문화의 땅입니다. 이곳에는 타이족 마을과 수상가옥, 매혹적인 쏘에 춤이 있는 평화로운 마이쩌우 골짜기, ''미니 하롱베이''로 불리는 드넓은 호아빈 호수와 신성한 탁버 사당이 있습니다. 호아빈은 산림 경관, 낌보이 온천, 짙은 므엉족·타이족 문화 정체성으로 여행객을 끌어모읍니다.","bestTime":"9월부터 12월","specialties":["대통밥","만 돼지고기","다강 생선구이","므엉 르어우껀 술"]},"ja":{"summary":"詩情あふれるマイチャウ谷、雄大なホアビン湖、古代ホアビン文化の揺りかごを抱く西北部の玄関口。","story":"ホアビンは西北部の玄関口であり、ムオン族の故郷で、考古学で有名なホアビン文化の地です。ここにはターイ族の村や高床式家屋、魅惑的なソエ踊りのある穏やかなマイチャウ谷、「ミニ・ハロン湾」と称される広大なホアビン湖と聖なるタックボー廟があります。ホアビンは山林の景観、キムボイの温泉、色濃いムオン族・ターイ族の文化の個性で旅人を引き寄せます。","bestTime":"9月から12月","specialties":["竹筒飯","マン豚肉","ダー川の焼き魚","ムオンのルオウカン酒"]},"zh":{"summary":"西北门户，拥有诗意的梅州谷、雄奇的和平湖和古老和平文化的摇篮。","story":"和平是西北地区的门户，是芒族的故乡，也是考古学上著名的和平文化之地。这里有泰族村寨、高脚屋和令人沉醉的圈舞交相辉映的宁静梅州谷；有被誉为「微缩下龙湾」的辽阔和平湖和神圣的瀑坡庙。和平以山林景观、金锅温泉和浓郁的芒族、泰族文化风情吸引着游客。","bestTime":"9月至12月","specialties":["竹筒饭","蛮猪肉","沱江烤鱼","芒族坛酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('hung-yen', 'red-river-delta', 'Hưng Yên', 'Hung Yen', 'Đồng bằng sông Hồng', '#c7993f', 106.0584, 20.8151, 'Vùng đất Phố Hiến vang bóng một thời, quê hương nhãn lồng tiến vua với nhiều di tích cổ kính.', 'Hưng Yên là vùng đất giàu trầm tích lịch sử, từng có thương cảng Phố Hiến sầm uất với câu Thứ nhất Kinh Kỳ, thứ nhì Phố Hiến. Ngày nay, Hưng Yên lưu giữ quần thể di tích Phố Hiến với hàng trăm đền chùa cổ kính cùng những nét văn hóa giao thoa Đông Tây độc đáo. Đặc biệt, nhãn lồng Hưng Yên từng được chọn tiến vua, vị ngọt thanh khó quên. Về Hưng Yên, du khách như ngược dòng thời gian tìm về một đô thị cổ trầm mặc bên dòng sông Hồng.', 'Tháng 7 đến tháng 8 (mùa nhãn)', '["Nhãn lồng Hưng Yên","Tương Bần","Bún thang lươn","Ếch om Phượng Tường"]', '{"en":{"summary":"The land of Pho Hien, glorious in its day, homeland of the royal-tribute longan, dotted with ancient relics.","story":"Hung Yen is a land steeped in historical sediment, once home to the bustling Pho Hien port immortalized by the saying ''First the Capital, second Pho Hien.'' Today, Hung Yen preserves the Pho Hien relic complex with hundreds of ancient temples and pagodas, along with its distinctive blend of Eastern and Western culture. In particular, Hung Yen''s longan was once chosen as tribute to the king, its clear sweetness hard to forget. In Hung Yen, visitors feel as if they are traveling back in time to a quietly contemplative ancient town beside the Red River.","bestTime":"July to August (longan season)","specialties":["Hung Yen longan","Ban soy sauce","Eel bun thang","Phuong Tuong braised frog"]},"ko":{"summary":"한때 명성을 떨친 포히엔 땅, 임금께 진상하던 룽안 용안의 고향으로 고풍스러운 유적이 많은 곳.","story":"흥옌은 역사의 켜가 깊이 쌓인 땅으로, 한때 ‘첫째는 수도, 둘째는 포히엔’이라 불린 번화한 항구 포히엔이 있던 곳입니다. 오늘날 흥옌은 수백 개의 고풍스러운 사당과 사찰로 이루어진 포히엔 유적군과 함께 동서양이 어우러진 독특한 문화의 정취를 간직하고 있습니다. 특히 흥옌의 룽안 용안은 일찍이 임금께 진상되었으며, 그 맑고 달콤한 맛은 잊기 어렵습니다. 흥옌에 오면 여행자는 마치 시간을 거슬러 홍강 가에 고요히 자리한 고도를 찾아가는 듯합니다.","bestTime":"7월~8월(용안 철)","specialties":["흥옌 룽안 용안","번 된장","장어 분탕","프엉뜨엉 개구리 조림"]},"ja":{"summary":"往時を偲ばせるフォーヒエンの地。王に献上されたリュウガンの故郷で、古き趣の史跡が数多く残ります。","story":"フンイエンは歴史の堆積豊かな地で、かつては「第一は都、第二はフォーヒエン」と謳われた繁栄の商港フォーヒエンがありました。今日のフンイエンは、数百もの古き趣の寺社からなるフォーヒエンの史跡群と、東西文化が交わる独特な趣を留めています。とりわけ、フンイエン産リュウガン（ロンガン）はかつて王に献上され、その上品な甘みは忘れがたいものです。フンイエンを訪れれば、ホン川（紅河）のほとりに静かに佇む古都へと時をさかのぼるかのようです。","bestTime":"7月から8月（リュウガンの季節）","specialties":["フンイエン産リュウガン","バンの醤（トゥオンバン）","うなぎのブンタン","フオントゥオンの蛙煮込み"]},"zh":{"summary":"曾盛极一时的铺宪之地，是进贡皇室的笼眼龙眼之乡，古迹众多。","story":"兴安是历史积淀深厚的土地，曾拥有繁华的铺宪商港，留有\"一京城，二铺宪\"之说。如今，兴安保存着铺宪遗迹群，有数百座古朴的庙宇寺院，以及融汇东西方文化的独特风貌。尤其是兴安笼眼龙眼曾被选作贡品，那清甜的滋味令人难忘。来到兴安，游客仿佛逆流而上，回到红河畔那座沉静的古老都市。","bestTime":"7月至8月（龙眼季）","specialties":["兴安笼眼龙眼","盆酱","鳝鱼什锦米线","凤祥焖蛙"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('khanh-hoa', 'south-central-coast', 'Khánh Hòa', 'Khanh Hoa', 'Duyên hải Nam Trung Bộ', '#3e92a8', 109.0244, 12.3333, 'Thiên đường biển đảo miền Trung với vịnh Nha Trang trong xanh và những rạn san hô rực rỡ.', 'Khánh Hòa được thiên nhiên ưu ái ban tặng đường bờ biển dài tuyệt đẹp cùng vịnh Nha Trang thuộc hàng đẹp nhất thế giới. Làn nước xanh ngọc, bãi cát trắng mịn, những hòn đảo hoang sơ và rạn san hô đa sắc là thiên đường nghỉ dưỡng và lặn biển. Bên cạnh đó, Khánh Hòa còn có tháp Bà Ponagar cổ kính, suối khoáng nóng và nền ẩm thực hải sản phong phú.', 'Tháng 3–9, biển êm và nắng đẹp', '["Bún cá","Bún sứa","Nem nướng Ninh Hòa","Yến sào","Hải sản"]', '{"en":{"summary":"A coastal-island paradise of central Vietnam with the clear blue Nha Trang Bay and brilliant coral reefs.","story":"Khanh Hoa is blessed by nature with a long, stunning coastline and Nha Trang Bay, among the most beautiful in the world. The jade-green water, fine white sand, pristine islands, and multicolored coral reefs make a paradise for resorts and diving. Khanh Hoa also has the ancient Po Nagar Towers, hot mineral springs, and a rich seafood cuisine.","bestTime":"March–September, calm seas and lovely sun","specialties":["Fish noodle soup","Jellyfish noodle soup","Ninh Hoa grilled pork rolls","Bird''s nest","Seafood"]},"ko":{"summary":"맑고 푸른 나트랑 만과 화려한 산호초를 지닌 중부의 해변 섬 천국입니다.","story":"칸호아는 길고 빼어난 해안선과 세계에서 손꼽히는 나트랑 만을 자연으로부터 선사받았습니다. 비취빛 물, 곱고 흰 모래, 청정한 섬들, 형형색색의 산호초는 휴양과 다이빙의 천국입니다. 그 밖에도 칸호아에는 고풍스러운 포나가르 탑, 온천, 그리고 풍부한 해산물 음식이 있습니다.","bestTime":"3~9월, 잔잔한 바다와 화창한 햇살","specialties":["분까(생선국수)","분스어(해파리 국수)","닌호아 넴느엉","제비집","해산물"]},"ja":{"summary":"青く澄んだニャチャン湾と鮮やかなサンゴ礁を持つ中部の海と島の楽園です。","story":"カインホアは、長く見事な海岸線と、世界有数の美しさを誇るニャチャン湾を自然から授かりました。翡翠色の水、きめ細かい白砂、手つかずの島々、色とりどりのサンゴ礁は、リゾートとダイビングの楽園です。そのほかカインホアには、古風なポーナガル塔、温泉、そして豊かな海の幸の食があります。","bestTime":"3〜9月、穏やかな海と美しい日差し","specialties":["ブンカー（魚そば）","ブンスア（クラゲそば）","ニンホアのネムヌオン","ツバメの巣","海の幸"]},"zh":{"summary":"中部的海岛天堂，拥有碧蓝的芽庄湾与绚丽的珊瑚礁。","story":"庆和得天独厚，拥有绵长绝美的海岸线与跻身世界最美之列的芽庄湾。碧绿的海水、细白的沙滩、原始的岛屿与多彩的珊瑚礁，是度假与潜水的天堂。此外，庆和还有古朴的婆那加塔、温泉以及丰富的海鲜美食。","bestTime":"3至9月，海面平静、阳光明媚","specialties":["鱼粉","海蜇粉","宁和烤肉卷","燕窝","海鲜"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('kien-giang', 'mekong-delta', 'Kiên Giang', 'Kien Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.0421, 9.9743, 'Vùng biển đảo Tây Nam với đảo Ngọc Phú Quốc, quần đảo Nam Du và những bãi biển hoang sơ.', 'Kiên Giang là tỉnh có biển đảo trù phú nhất miền Tây Nam Bộ. Nổi bật là đảo Phú Quốc — hòn đảo lớn nhất Việt Nam với bãi biển tuyệt đẹp, rừng nguyên sinh và nước mắm trứ danh. Ngoài ra còn có quần đảo Nam Du hoang sơ, Hà Tiên thơ mộng với ''Hà Tiên thập cảnh''. Vùng đất này hội tụ vẻ đẹp biển trời cùng nền văn hóa giao thoa Kinh - Khmer - Hoa độc đáo.', 'Tháng 11–4, mùa khô biển đẹp', '["Nước mắm Phú Quốc","Hồ tiêu","Bún cá Kiên Giang","Hải sản","Gỏi cá trích"]', '{"en":{"summary":"The island region of the southwest, with the pearl island of Phu Quoc, the Nam Du archipelago and pristine beaches.","story":"Kien Giang is the province with the most abundant seas and islands in the southwestern Mekong region. The standout is Phu Quoc Island — Vietnam''s largest island, with gorgeous beaches, primeval forest and famous fish sauce. There is also the pristine Nam Du archipelago and poetic Ha Tien with its ''Ten Scenes of Ha Tien''. This land brings together the beauty of sea and sky with the unique blended culture of the Kinh, Khmer and Hoa peoples.","bestTime":"November–April, dry season with beautiful seas","specialties":["Phu Quoc fish sauce","Pepper","Kien Giang fish noodle soup","Seafood","Herring salad (goi ca trich)"]},"ko":{"summary":"진주섬 푸꾸옥, 남두 군도, 원시 해변을 간직한 남서부 섬 지역.","story":"끼엔장은 메콩 남서부에서 바다와 섬이 가장 풍부한 성입니다. 빼어난 해변과 원시림, 이름난 느억맘을 간직한 베트남 최대의 섬 푸꾸옥이 돋보입니다. 이 밖에도 원시 그대로의 남두 군도와 ''하띠엔 십경''을 간직한 시적인 하띠엔이 있습니다. 이 땅은 바다와 하늘의 아름다움에 낀·크메르·화의 독특한 융합 문화가 어우러져 있습니다.","bestTime":"11~4월, 바다가 아름다운 건기","specialties":["푸꾸옥 느억맘","후추","끼엔장 생선 국수(분까)","해산물","청어 회무침(고이까찟)"]},"ja":{"summary":"真珠の島フーコック、ナムズー諸島、手つかずのビーチを擁する南西の島嶼地域。","story":"キエンザンはメコン南西部で海と島が最も豊かな省です。美しいビーチと原生林、名高いヌクマムを擁するベトナム最大の島フーコックが際立ちます。このほか手つかずのナムズー諸島や、『ハーティエン十景』を擁する詩情あふれるハーティエンがあります。この地は海と空の美しさに、キン・クメール・華の独特な融合文化が交わっています。","bestTime":"11〜4月、海が美しい乾季","specialties":["フーコックのヌクマム","胡椒","キエンザンの魚麺（ブンカー）","シーフード","ニシンの和え物（ゴイカーチッ）"]},"zh":{"summary":"西南海岛地区，拥有明珠岛富国、南游群岛和原始的海滩。","story":"坚江是湄公西南部海岛最为富饶的省份。其中最突出的是富国岛——越南最大的岛屿，拥有绝美海滩、原始森林和著名鱼露。此外还有原始的南游群岛、诗意的河仙及其「河仙十景」。这片土地汇聚了海天之美，以及京、高棉、华独特交融的文化。","bestTime":"11月至4月，海景宜人的旱季","specialties":["富国鱼露","胡椒","坚江鱼米粉","海鲜","鲱鱼生拌"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('kon-tum', 'central-highlands', 'Kon Tum', 'Kon Tum', 'Tây Nguyên', '#8a6e4b', 107.8744, 14.6489, 'Phố núi Bắc Tây Nguyên với nhà thờ gỗ trăm tuổi, Măng Đen mát lạnh và văn hóa bản địa đặc sắc.', 'Kon Tum là tỉnh cực bắc Tây Nguyên, nơi đại ngàn hùng vĩ giao hòa với những giá trị văn hóa độc đáo của đồng bào Ba Na, Xơ Đăng, Gia Rai. Tỉnh nổi tiếng với nhà thờ gỗ trăm tuổi, cầu treo Kon Klor, nhà rông truyền thống và khu du lịch Măng Đen được ví như Đà Lạt thứ hai. Vùng đất này quyến rũ bởi khí hậu mát mẻ, thiên nhiên trong lành và những nét văn hóa cồng chiêng nguyên sơ.', 'Tháng 11 đến tháng 4', '["Gỏi lá","Cá chua","Rượu cần","Cà phê","Heo quay Măng Đen"]', '{"en":{"summary":"A northern Central Highlands mountain town with a century-old wooden church, cool Mang Den, and distinctive indigenous culture.","story":"Kon Tum is the northernmost province of the Central Highlands, where the majestic wilderness blends with the unique cultural values of the Bahnar, Xo Dang, and Jarai peoples. The province is famous for its century-old wooden church, the Kon Klor suspension bridge, traditional rong communal houses, and the Mang Den tourist area, likened to a second Da Lat. This land charms with its cool climate, fresh nature, and pristine gong culture.","bestTime":"November to April","specialties":["Leaf salad","Sour fish","Rice wine","Coffee","Mang Den roast pork"]},"ko":{"summary":"백 년 된 목조 성당과 서늘한 망덴, 특색 있는 토착 문화를 지닌 떠이응우옌 북부 산간 도시입니다.","story":"꼰뚬은 떠이응우옌 최북단 성으로, 웅장한 대자연이 바나족, 써당족, 자라이족의 독특한 문화 가치와 어우러진 곳입니다. 백 년 된 목조 성당, 꼰끄로 흔들다리, 전통 롱 공동주택, 그리고 제2의 달랏이라 불리는 망덴 관광지로 유명합니다. 이 땅은 서늘한 기후와 청정한 자연, 그리고 원시적인 공 문화로 사람들을 사로잡습니다.","bestTime":"11월~4월","specialties":["고이라(잎쌈)","신 생선","깐 술","커피","망덴 통돼지구이"]},"ja":{"summary":"百年の木造教会とひんやりしたマンデン、特色ある土着文化を持つ北タイグエン高原の山あいの町です。","story":"コントゥムはタイグエン高原最北の省で、雄大な大自然がバナ族、セダン族、ジャライ族の独特な文化の価値と溶け合う地です。百年の木造教会、コンクロー吊り橋、伝統的なロン共同家屋、そして第二のダラットと称されるマンデン観光地で有名です。この地は涼しい気候、清らかな自然、そして原初的な銅鑼文化で人々を魅了します。","bestTime":"11月〜4月","specialties":["ゴイラー（葉の包み）","酸味の魚","カン酒","コーヒー","マンデンの豚の丸焼き"]},"zh":{"summary":"北西原的山城，拥有百年木教堂、清凉的芒登与别具特色的本土文化。","story":"昆嵩是西原最北端的省份，雄伟大山与巴拿族、色登族、嘉莱族独特的文化价值在此交融。该省以百年木教堂、昆克罗吊桥、传统茸屋，以及被誉为第二大叻的芒登旅游区而闻名。这片土地以凉爽的气候、清新的自然与原初的铜锣文化令人着迷。","bestTime":"11月至4月","specialties":["叶包菜（Gỏi lá）","酸鱼","竹竿酒","咖啡","芒登烤乳猪"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('lai-chau', 'northwest', 'Lai Châu', 'Lai Chau', 'Tây Bắc', '#6e8c5a', 103.1866, 22.3171, 'Vùng biên viễn hoang sơ với tứ đại đỉnh đèo Ô Quy Hồ, bản du lịch cộng đồng Sin Suối Hồ và những đỉnh núi cao chót vót.', 'Lai Châu là tỉnh biên giới Tây Bắc còn giữ nét hoang sơ, hùng vĩ với những dãy núi cao và bản làng dân tộc thiểu số. Nơi đây có Đèo Ô Quy Hồ - một trong tứ đại đỉnh đèo, bản Sin Suối Hồ xanh sạch đẹp của người Mông, cùng những đỉnh núi Pu Ta Leng, Bạch Mộc Lương Tử hấp dẫn dân leo núi. Văn hóa các dân tộc Thái, Mông, Dao, Hà Nhì với chợ phiên, lễ hội đặc sắc làm nên sức hút riêng của miền đất biên viễn này.', 'Tháng 9 đến tháng 4', '["Lam nhọ","Cá bống vùi tro","Xôi tím","Rượu ngô Sùng Phài"]', '{"en":{"summary":"A wild frontier region with O Quy Ho, one of the four great passes, the Sin Suoi Ho community tourism village and soaring peaks.","story":"Lai Chau is a northwestern border province that still keeps its wild, magnificent character, with high mountain ranges and ethnic minority villages. Here lies O Quy Ho Pass — one of the four great passes — the green, clean and beautiful Hmong village of Sin Suoi Ho, and the peaks of Pu Ta Leng and Bach Moc Luong Tu that draw mountaineers. The cultures of the Thai, Hmong, Dao and Ha Nhi, with their markets and distinctive festivals, give this frontier land its own special appeal.","bestTime":"September to April","specialties":["Lam nho","Ash-roasted goby fish","Purple sticky rice","Sung Phai corn wine"]},"ko":{"summary":"4대 고개 중 하나인 오꾸이호, 신쑤오이호 공동체 관광 마을, 우뚝 솟은 봉우리들을 품은 야생의 변경 지역.","story":"라이쩌우는 높은 산맥과 소수민족 마을과 함께 야생적이고 웅장한 정취를 간직한 서북부 국경 성입니다. 이곳에는 4대 고개 중 하나인 오꾸이호 고개, 깨끗하고 아름다운 몽족 마을 신쑤오이호, 그리고 등산객을 끌어모으는 뿌따렝과 박목르엉뜨 봉우리가 있습니다. 장날과 독특한 축제를 지닌 타이족, 몽족, 자오족, 하니족의 문화는 이 변경의 땅만의 매력을 자아냅니다.","bestTime":"9월부터 4월","specialties":["람뇨","재에 묻은 망둑어","보라색 찰밥","쑹파이 옥수수 술"]},"ja":{"summary":"四大峠の一つオークイホー、シンスオイホーのコミュニティ観光村、そびえ立つ峰々を抱く野性的な辺境地域。","story":"ライチャウは、高い山脈と少数民族の村とともに野性的で雄大な趣を今に残す西北部の国境省です。ここには四大峠の一つオークイホー峠、清潔で美しいモン族の村シンスオイホー、そして登山客を引き寄せるプータレンやバックモックルオントゥの峰があります。市や個性豊かな祭りを持つターイ族、モン族、ザオ族、ハニ族の文化が、この辺境の地ならではの魅力を醸し出します。","bestTime":"9月から4月","specialties":["ラムニョ","灰に埋めたハゼ","紫のもち米飯","スンファイのトウモロコシ酒"]},"zh":{"summary":"原始荒野的边陲地区，拥有四大名山口之一的乌贵湖、辛水湖社区旅游村和高耸入云的山峰。","story":"莱州是西北部的边境省份，仍保留着原始而雄奇的风貌，拥有高耸的山脉和少数民族村寨。这里有四大名山口之一的乌贵湖山口、洁净美丽的苗族村寨辛水湖，以及吸引登山客的扶大棱、白沐良子等山峰。拥有集市与独特庙会的泰族、苗族、瑶族、哈尼族文化，构成这片边陲之地独有的魅力。","bestTime":"9月至4月","specialties":["蓝糯","灰煨鰕虎鱼","紫糯米饭","崇派玉米酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('lam-dong', 'central-highlands', 'Lâm Đồng', 'Lam Dong', 'Tây Nguyên', '#8a6e4b', 108.0942, 11.7521, 'Cao nguyên Đà Lạt ngàn hoa trong sương, lãng mạn với rừng thông và khí hậu mát quanh năm.', 'Lâm Đồng là xứ sở của Đà Lạt mộng mơ — thành phố ngàn hoa, ngàn thông trên cao nguyên Lang Biang. Khí hậu mát mẻ quanh năm, những đồi chè, vườn dâu, thác nước và hồ trong xanh khiến nơi đây trở thành điểm hẹn của những tâm hồn yêu sự lãng mạn và bình yên.', 'Quanh năm; đẹp nhất tháng 10–12 mùa dã quỳ', '["Bánh tráng nướng","Lẩu gà lá é","Dâu tây","Cà phê","Atisô"]', '{"en":{"summary":"The Da Lat plateau of a thousand flowers in the mist, romantic with pine forests and cool weather year-round.","story":"Lam Dong is the land of dreamy Da Lat — a city of a thousand flowers and a thousand pines on the Lang Biang plateau. With cool weather year-round, tea hills, strawberry gardens, waterfalls, and clear blue lakes, it has become a meeting point for souls who love romance and peace.","bestTime":"Year-round; best in October–December, the wild sunflower season","specialties":["Grilled rice paper","Chicken hotpot with é herb","Strawberries","Coffee","Artichokes"]},"ko":{"summary":"안개 속 꽃의 고원 달랏을 지닌, 소나무 숲과 사계절 서늘한 기후가 낭만적인 곳입니다.","story":"럼동은 몽환적인 달랏의 고장으로 — 랑비앙 고원 위 꽃과 소나무의 도시입니다. 사계절 서늘한 기후, 차밭, 딸기 농장, 폭포, 맑고 푸른 호수가 이곳을 낭만과 평온을 사랑하는 영혼들의 만남의 장소로 만들었습니다.","bestTime":"연중; 10~12월 들국화 철이 가장 아름다움","specialties":["구운 라이스페이퍼","에잎 닭 샤부샤부","딸기","커피","아티초크"]},"ja":{"summary":"霧に包まれた花の高原ダラットを持つ、松林と一年中涼しい気候がロマンチックな地です。","story":"ラムドンは夢見るようなダラットの地で——ランビアン高原の花と松の都です。一年中涼しい気候、茶畑、いちご農園、滝、澄んだ青い湖が、ここをロマンと安らぎを愛する魂の出会いの場にしています。","bestTime":"通年。10〜12月のヒマワリの季節が最も美しい","specialties":["焼きライスペーパー","エーの葉の鶏鍋","いちご","コーヒー","アーティチョーク"]},"zh":{"summary":"雾中千花的大叻高原，松林浪漫，四季气候凉爽。","story":"林同是梦幻大叻的故乡——朗比安高原上的千花千松之城。四季凉爽的气候、茶丘、草莓园、瀑布与碧蓝清湖，使这里成为热爱浪漫与宁静的灵魂的相约之地。","bestTime":"四季皆宜；10至12月野菊花季最美","specialties":["烤米纸","野紫苏叶鸡火锅","草莓","咖啡","洋蓟"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('lang-son', 'northeast', 'Lạng Sơn', 'Lang Son', 'Đông Bắc', '#4f7b6a', 106.6205, 21.8398, 'Xứ Lạng biên cương với động đá linh thiêng, đỉnh Mẫu Sơn mây phủ, chợ cửa khẩu sầm uất và bản sắc dân tộc đậm đà.', 'Lạng Sơn là tỉnh biên giới Đông Bắc với phong cảnh hữu tình và bề dày lịch sử. Vùng đất xứ Lạng nổi tiếng với Động Tam Thanh, nàng Tô Thị, thành nhà Mạc cùng đỉnh Mẫu Sơn mây mù quanh năm có băng tuyết mùa đông. Các chợ cửa khẩu Tân Thanh, Đông Kinh sầm uất thu hút du khách mua sắm. Văn hóa Tày, Nùng, Dao với những làn điệu sli, lượn làm nên nét quyến rũ riêng của xứ Lạng.', 'Tháng 9 đến tháng 12', '["Vịt quay lá mắc mật","Phở chua Lạng Sơn","Khâu nhục","Bánh cuốn trứng"]', '{"en":{"summary":"The frontier land of Lang with sacred limestone caves, cloud-covered Mau Son Peak, bustling border markets and rich ethnic identity.","story":"Lang Son is a northeastern border province with charming scenery and deep history. The land of Lang is famous for Tam Thanh Cave, the To Thi statue, the Mac dynasty citadel and the cloud-shrouded Mau Son Peak, which sees ice and frost in winter. The bustling Tan Thanh and Dong Kinh border markets draw shoppers. The Tay, Nung and Dao cultures, with their sli and luon folk songs, give the land of Lang its own special charm.","bestTime":"September to December","specialties":["Roast duck with mac mat leaves","Lang Son sour pho","Khau nhuc braised pork","Egg rice rolls"]},"ko":{"summary":"신성한 석회암 동굴, 구름 덮인 머우선 봉우리, 활기찬 국경 시장, 짙은 민족 정체성을 지닌 변경의 땅 랑.","story":"랑선은 정취 어린 풍경과 깊은 역사를 지닌 동북부 국경 성입니다. 랑 지방은 땀타인 동굴, 또티 상, 막 왕조 성과 함께 연중 구름에 덮여 겨울에 얼음과 서리가 내리는 머우선 봉우리로 유명합니다. 활기찬 떤타인과 동낀 국경 시장은 쇼핑객을 끌어모읍니다. 슬리와 르언 민요를 가진 따이족, 눙족, 자오족 문화는 랑 지방만의 매력을 자아냅니다.","bestTime":"9월부터 12월","specialties":["막맛잎 오리구이","랑선 새콤 쌀국수","카우늑(찜 돼지고기)","달걀 반꾸온"]},"ja":{"summary":"聖なる石灰岩の洞窟、雲に覆われたマウソンの峰、活気ある国境市場、色濃い民族の個性を持つ辺境の地ラン。","story":"ランソンは趣ある風景と深い歴史を持つ東北部の国境省です。ラン地方はタムタイン洞窟、トーティ像、マック朝の城とともに、一年中雲に覆われ冬に氷と霜が降りるマウソンの峰で有名です。活気あるタンタインとドンキンの国境市場が買い物客を引き寄せます。スリやルオンの民謡を持つターイ族、ヌン族、ザオ族の文化が、ラン地方ならではの魅力を醸し出します。","bestTime":"9月から12月","specialties":["マックマット葉の鴨ロースト","ランソンの酸っぱいフォー","カウヌック(蒸し豚)","卵入りバインクオン"]},"zh":{"summary":"边陲谅地，拥有神圣的石灰岩洞、云雾缭绕的母山、繁华的口岸集市和浓郁的民族风情。","story":"谅山是东北部的边境省份，风景秀丽、历史悠久。谅地以三清洞、苏氏望夫石、莫朝城以及终年云雾缭绕、冬季会结冰霜的母山闻名。新清、东京等繁华的口岸集市吸引着游客购物。岱依族、侬族、瑶族文化连同悉、卢恩等民歌，构成谅地独有的魅力。","bestTime":"9月至12月","specialties":["马蜜叶烤鸭","谅山酸粉","扣肉","鸡蛋卷粉"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('lao-cai', 'northeast', 'Lào Cai', 'Lao Cai', 'Đông Bắc', '#4f7b6a', 104.1103, 22.3663, 'Quê hương của Sa Pa mờ sương và đỉnh Fansipan — nóc nhà Đông Dương.', 'Lào Cai là vùng núi non hùng vĩ nơi Tây Bắc, nổi danh với thị trấn Sa Pa trong mây và những thửa ruộng bậc thang được xem là đẹp bậc nhất thế giới. Văn hóa của người Mông, Dao, Tày tạo nên bức tranh đa sắc, ấm áp giữa đại ngàn Hoàng Liên Sơn.', 'Tháng 9 (lúa chín) và tháng 3–5 (trời trong)', '["Thắng cố","Cá hồi Sa Pa","Đồ nướng","Rượu táo mèo"]', '{"en":{"summary":"Home of misty Sa Pa and Fansipan Peak — the Roof of Indochina.","story":"Lao Cai is a region of magnificent mountains in the northwest, famous for the cloud-wrapped town of Sa Pa and terraced fields regarded as among the most beautiful in the world. The cultures of the Hmong, Dao and Tay create a colourful, warm tapestry amid the great Hoang Lien Son range.","bestTime":"September (ripe rice) and March–May (clear skies)","specialties":["Thang co stew","Sa Pa salmon","Grilled dishes","Wild apple wine"]},"ko":{"summary":"안개에 싸인 사파와 인도차이나의 지붕 판시판 봉우리의 고향.","story":"라오까이는 서북부의 웅장한 산악 지대로, 구름에 싸인 사파 마을과 세계에서 손꼽히게 아름답다고 여겨지는 계단식 논으로 이름났습니다. 몽족, 자오족, 따이족의 문화는 드넓은 호앙리엔선 산맥 한가운데서 다채롭고 따뜻한 풍경을 자아냅니다.","bestTime":"9월(벼 익음)과 3~5월(맑은 하늘)","specialties":["탕꼬 탕","사파 연어","구이 요리","산사과 술"]},"ja":{"summary":"霧に包まれたサパと、インドシナの屋根ファンシーパン山の故郷。","story":"ラオカイは西北部の雄大な山岳地帯で、雲に包まれたサパの町と、世界屈指に美しいとされる棚田で名高い場所です。モン族、ザオ族、ターイ族の文化が、雄大なホアンリエンソン山脈の只中で彩り豊かで温かな光景を織りなします。","bestTime":"9月(稲の実り)と3〜5月(晴天)","specialties":["タンコー鍋","サパのサーモン","焼き物料理","野リンゴ酒"]},"zh":{"summary":"薄雾笼罩的沙巴和印度支那屋脊番西邦峰之乡。","story":"老街是西北部雄奇的山区，以云雾缭绕的沙巴小镇和被誉为世界最美之一的梯田闻名。苗族、瑶族、岱依族的文化，在莽莽黄连山脉之中织就一幅绚丽多彩、温暖动人的画卷。","bestTime":"9月（稻谷成熟）和3至5月（天空晴朗）","specialties":["胜火炖菜","沙巴三文鱼","烧烤","苹果酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('long-an', 'mekong-delta', 'Long An', 'Long An', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.1694, 10.7307, 'Cửa ngõ miền Tây giáp Sài Gòn, nổi tiếng với vùng Đồng Tháp Mười, rừng tràm và những cánh đồng lúa trải dài.', 'Long An là tỉnh cửa ngõ nối Thành phố Hồ Chí Minh với đồng bằng sông Cửu Long, mang đặc trưng vùng Đồng Tháp Mười với rừng tràm, đất ngập nước và đồng lúa bát ngát. Nơi đây có làng nổi Tân Lập thơ mộng và khu bảo tồn Láng Sen hoang sơ, là điểm đến lý tưởng cho du lịch sinh thái. Người Long An hiền hòa, mến khách, gìn giữ nếp sống nông nghiệp đậm chất miền Tây giữa nhịp phát triển hối hả của vùng kinh tế trọng điểm phía Nam.', 'Tháng 9 đến tháng 11, mùa nước nổi rừng tràm xanh tốt', '["Gạo nàng thơm Chợ Đào","Rượu đế Gò Đen","Lạp xưởng Cần Đước","Đậu phộng Đức Hòa"]', '{"en":{"summary":"The gateway to the Mekong bordering Saigon, famous for the Plain of Reeds, cajuput forests and stretches of rice fields.","story":"Long An is the gateway province linking Ho Chi Minh City with the Mekong Delta, with the character of the Plain of Reeds — cajuput forests, wetlands and vast rice fields. Here lie the poetic Tan Lap Floating Village and the pristine Lang Sen Reserve, ideal destinations for eco-tourism. The people of Long An are gentle and hospitable, preserving an agricultural way of life rich in Mekong character amid the bustling pace of the southern key economic region.","bestTime":"September to November, the flood season when the cajuput forest is lush green","specialties":["Nang Thom Cho Dao rice","Go Den rice wine","Can Duoc Chinese sausage","Duc Hoa peanuts"]},"ko":{"summary":"사이공과 맞닿은 메콩의 관문, 동탑므어이 지역과 멜라루카 숲, 끝없이 펼쳐진 논으로 유명한 곳.","story":"롱안은 호찌민시와 메콩델타를 잇는 관문 성으로, 멜라루카 숲과 습지, 드넓은 논이 펼쳐진 동탑므어이 지역의 특색을 지닙니다. 시적인 떤럽 수상마을과 원시 그대로의 랑센 보호구역이 있어 생태 관광의 이상적인 목적지입니다. 롱안 사람들은 온화하고 손님을 반기며, 남부 중점 경제권의 분주한 발전 속에서도 메콩 특유의 농업 생활을 지켜 갑니다.","bestTime":"9~11월, 멜라루카 숲이 푸르른 물난리 시기","specialties":["쩌다오 낭텀 쌀","고덴 소주(르어우데)","껀드억 중국식 소시지","득호아 땅콩"]},"ja":{"summary":"サイゴンに接するメコンの玄関口、ドンタップムオイ地域とメラルーカ林、果てしなく広がる稲田で有名な地。","story":"ロンアンはホーチミン市とメコンデルタを結ぶ玄関口の省で、メラルーカ林や湿地、広大な稲田が広がるドンタップムオイ地域の特色を持ちます。詩情あふれるタンラップ水上村と手つかずのランセン保護区があり、エコツーリズムの理想的な目的地です。ロンアンの人々は穏やかでもてなしの心にあふれ、南部重点経済圏の慌ただしい発展の中でもメコン特有の農業の暮らしを守り続けています。","bestTime":"9〜11月、メラルーカ林が緑豊かな増水期","specialties":["チョーダオのナンタム米","ゴーデンの蒸留酒","カンドゥックの中華ソーセージ","ドゥックホアの落花生"]},"zh":{"summary":"毗邻西贡的湄公门户，以同塔梅地区、白千层林和绵延的稻田闻名。","story":"隆安是连接胡志明市与湄公河三角洲的门户省份，具有同塔梅地区的特色——白千层林、湿地和辽阔的稻田。这里有诗意的新立浮村和原始的莨莲保护区，是生态旅游的理想目的地。隆安人温和好客，在南部重点经济区飞速发展的节奏中，依然守护着浓郁湄公风情的农业生活。","bestTime":"9月至11月，白千层林翠绿的涨水季节","specialties":["𠮾陶娘香米","鹅黑米酒","芹蒢腊肠","德和花生"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('nam-dinh', 'red-river-delta', 'Nam Định', 'Nam Dinh', 'Đồng bằng sông Hồng', '#c7993f', 106.2077, 20.2672, 'Đất học thành Nam với Đền Trần lịch sử, nhà thờ đổ ven biển nên thơ và món phở bò trứ danh.', 'Nam Định là vùng đất thành Nam giàu truyền thống khoa bảng và là quê hương phát tích vương triều Trần hiển hách. Đền Trần với lễ khai ấn đầu xuân thu hút hàng vạn người về cầu may. Vùng ven biển Nam Định còn nổi tiếng với nhà thờ đổ Hải Lý hoang hoải và những giáo đường nguy nga mang dáng dấp châu Âu. Đặc biệt, Nam Định được xem là cái nôi của phở bò Việt Nam với hương vị đậm đà, tinh tế làm say lòng bao thực khách gần xa.', 'Tháng Giêng âm lịch (mùa lễ hội)', '["Phở bò Nam Định","Bánh xíu páo","Nem nắm Giao Thủy","Kẹo Sìu Châu"]', '{"en":{"summary":"The scholarly land of Thanh Nam, with the historic Tran Temple, poetic seaside ruined church, and the famous beef pho.","story":"Nam Dinh is the land of Thanh Nam, rich in a tradition of scholarship and the illustrious ancestral homeland of the Tran Dynasty. Tran Temple, with its early-spring seal-opening ceremony, draws tens of thousands seeking good fortune. The coastal area of Nam Dinh is also famous for the desolate Hai Ly Ruined Church and magnificent cathedrals with a European air. Above all, Nam Dinh is regarded as the cradle of Vietnamese beef pho, with a rich, refined flavor that wins the hearts of diners far and near.","bestTime":"First lunar month (festival season)","specialties":["Nam Dinh beef pho","Xiu pao buns","Giao Thuy fermented pork","Siu Chau candy"]},"ko":{"summary":"역사적인 쩐 사당과 시적인 바닷가 폐성당, 이름난 소고기 퍼를 지닌 학문의 고장 타인남.","story":"남딘은 과거 급제 전통이 풍성한 타인남 땅이자, 빛나는 쩐 왕조의 발상지입니다. 쩐 사당의 정초 인장 개봉 의식은 수만 명을 불러 모아 행운을 빌게 합니다. 남딘 바닷가 지역은 또한 쓸쓸한 하이리 폐성당과 유럽풍의 웅장한 성당들로도 유명합니다. 특히 남딘은 깊고 섬세한 풍미로 각지의 수많은 미식가의 마음을 사로잡는 베트남 소고기 퍼의 발상지로 꼽힙니다.","bestTime":"음력 정월(축제 철)","specialties":["남딘 소고기 퍼","씨우빠오 빵","자오투이 넴남","시우쩌우 사탕"]},"ja":{"summary":"歴史あるデンチャン、詩情あふれる海辺の廃教会、そして名高い牛肉フォーを擁する、学問の地タインナム。","story":"ナムディンは科挙の伝統豊かな「タインナム（南の城）」の地であり、輝かしい陳朝発祥の故郷です。初春の開印祭を行うデンチャンには、幾万もの人々が福を願って訪れます。ナムディンの海辺地域はまた、物寂しいハイリーの廃教会と、ヨーロッパの趣を漂わせる荘厳な聖堂で名高い地です。とりわけ、ナムディンはベトナムの牛肉フォーの発祥地とされ、その深く繊細な味わいが遠近の食通たちを魅了してやみません。","bestTime":"旧暦1月（祭りの季節）","specialties":["ナムディンの牛肉フォー","バインシウパオ","ザオトゥイのネムナム","シウチャウ飴"]},"zh":{"summary":"成南学府之地，拥有历史悠久的陈庙、诗意的海边废弃教堂和著名的牛肉粉。","story":"南定是科举传统深厚的成南之地，是显赫的陈朝王室发祥的故乡。陈庙的初春开印典礼吸引数万人前来祈福。南定沿海地区还以荒凉的海理废弃教堂和带有欧洲风情的宏伟教堂闻名。尤其是，南定被视为越南牛肉粉的发源地，那浓郁精致的滋味令远近食客陶醉。","bestTime":"农历正月（庙会季）","specialties":["南定牛肉粉","烧包","交水生肉糜","潮州糖"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('nghe-an', 'north-central-coast', 'Nghệ An', 'Nghe An', 'Bắc Trung Bộ', '#5a8aa6', 104.9449, 19.2366, 'Quê hương Bác Hồ kính yêu, vùng đất nắng gió ân tình với biển Cửa Lò và đại ngàn Pù Mát hùng vĩ.', 'Nghệ An là vùng đất rộng lớn, đậm chất ân tình của con người xứ Nghệ. Tự hào là quê hương Chủ tịch Hồ Chí Minh, nơi đây gìn giữ khu di tích Kim Liên thiêng liêng. Từ bãi biển Cửa Lò sầm uất với mực nhảy trứ danh đến rừng nguyên sinh Pù Mát đa dạng sinh học, Nghệ An mang trong mình cả chiều sâu lịch sử lẫn vẻ đẹp thiên nhiên khoáng đạt, mời gọi bước chân lữ khách.', 'Tháng 4 đến tháng 8', '["Cháo lươn Vinh","Mực nhảy Cửa Lò","Cam Vinh","Bánh mướt"]', '{"en":{"summary":"The homeland of beloved Uncle Ho, a sun-and-wind land of warm sentiment, with Cua Lo Beach and the majestic Pu Mat wilderness.","story":"Nghe An is a vast land, imbued with the warm sentiment of its people. Proud to be the homeland of President Ho Chi Minh, it preserves the sacred Kim Lien relic site. From the bustling Cua Lo Beach with its famous ''jumping squid'' to the biologically diverse primeval forest of Pu Mat, Nghe An carries both a depth of history and an expansive natural beauty that beckons the traveler''s footsteps.","bestTime":"April to August","specialties":["Vinh eel congee","Cua Lo jumping squid","Vinh oranges","Banh muot (steamed rice rolls)"]},"ko":{"summary":"사랑하는 호 아저씨의 고향으로, 끄어로 해변과 웅장한 푸맛 야생을 품은 햇볕과 바람의 정 깊은 땅입니다.","story":"응에안은 응에 사람들의 깊은 정이 어린 광대한 땅입니다. 호찌민 주석의 고향임을 자랑하며 신성한 낌리엔 유적지를 간직하고 있습니다. 유명한 ''점핑 오징어''로 번화한 끄어로 해변부터 생물 다양성이 풍부한 푸맛 원시림까지, 응에안은 깊은 역사와 광활한 자연의 아름다움을 함께 지녀 나그네의 발길을 부릅니다.","bestTime":"4월부터 8월까지","specialties":["빈 장어죽","끄어로 점핑 오징어","빈 오렌지","반므엇(찐 쌀롤)"]},"ja":{"summary":"敬愛するホーおじさんの故郷。クアロービーチと雄大なプーマットの原野を擁する、日差しと風の情に厚い地です。","story":"ゲアンは、ゲアンの人々の厚い情がこもる広大な地です。ホー・チ・ミン主席の故郷であることを誇り、神聖なキムリエン史跡を守り伝えています。名高い「跳ねるイカ」で賑わうクアロービーチから、生物多様性に富むプーマットの原生林まで、ゲアンは歴史の深みと広大な自然の美しさを併せ持ち、旅人の足を誘います。","bestTime":"4月から8月まで","specialties":["ヴィンのウナギ粥","クアローの跳ねるイカ","ヴィンオレンジ","バインムオット（蒸し米ロール）"]},"zh":{"summary":"敬爱的胡伯伯故乡，是拥有门炉海滩与雄伟蒲茫林海、阳光多情的土地。","story":"乂安是一片辽阔的土地，饱含乂安人深厚的情谊。这里以身为胡志明主席的故乡为荣，守护着神圣的金莲遗迹。从以闻名「跳墨鱼」而繁华的门炉海滩，到生物多样的蒲茫原始森林，乂安兼具历史的深度与开阔的自然之美，召唤旅人的脚步。","bestTime":"4月至8月","specialties":["荣市鳝鱼粥","门炉跳墨鱼","荣市橙","越式蒸米卷"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ninh-binh', 'red-river-delta', 'Ninh Bình', 'Ninh Binh', 'Đồng bằng sông Hồng', '#c7993f', 105.9, 20.2234, '‘Hạ Long trên cạn’ với non nước hữu tình, cố đô Hoa Lư và những hang động kỳ vĩ.', 'Ninh Bình mê hoặc bằng vẻ đẹp của núi đá vôi soi bóng xuống những dòng sông lặng lờ. Tràng An, Tam Cốc, Hang Múa là những bức tranh thủy mặc sống động. Đây từng là kinh đô đầu tiên của nước Đại Cồ Việt, mang trong mình bề dày lịch sử ngàn năm.', 'Tháng 1–3 và mùa lúa chín tháng 5–6', '["Thịt dê núi","Cơm cháy","Ốc núi","Rượu Kim Sơn"]', '{"en":{"summary":"The ''Ha Long on land'' with harmonious mountains and water, the ancient capital of Hoa Lu, and majestic caves.","story":"Ninh Binh enchants with the beauty of limestone mountains mirrored in slow-flowing rivers. Trang An, Tam Coc, and Mua Cave are vivid living ink-wash paintings. This was once the first capital of the Dai Co Viet kingdom, carrying within it a thousand years of history.","bestTime":"January–March and the ripe-rice season in May–June","specialties":["Mountain goat meat","Crispy rice","Mountain snails","Kim Son wine"]},"ko":{"summary":"빼어난 산수와 호아르 고도, 웅장한 동굴을 지닌 ‘육지의 하롱베이’.","story":"닌빈은 잔잔히 흐르는 강물에 비친 석회암 산의 아름다움으로 사람을 사로잡습니다. 짱안, 땀꼭, 항무아는 생동감 넘치는 한 폭의 수묵화입니다. 이곳은 한때 다이꼬비엣의 첫 수도였으며, 천년의 깊은 역사를 품고 있습니다.","bestTime":"1~3월과 벼가 익는 5~6월","specialties":["산양 고기","꼼짜이(누룽지)","산달팽이","낌선 술"]},"ja":{"summary":"「陸のハロン湾」。山紫水明の景色、古都ホアルー、そして雄大な洞窟群を擁します。","story":"ニンビンは、静かに流れる川面に影を落とす石灰岩の山々の美しさで人々を魅了します。チャンアン、タムコック、ハンムアは、生き生きとした水墨画のようです。ここはかつて大瞿越国の最初の都であり、千年に及ぶ歴史の重みを宿しています。","bestTime":"1〜3月、および稲穂が実る5〜6月","specialties":["山羊の肉","おこげ（コムチャイ）","山のタニシ","キムソンの酒"]},"zh":{"summary":"陆上下龙湾\"，山水秀美，有华闾古都和雄奇的洞穴。","story":"宁平以石灰岩山峰倒映在静谧河流上的美景令人着迷。长安、三谷、卧龙山宛如一幅幅生动的水墨画。这里曾是大瞿越国的第一座都城，承载着千年的厚重历史。","bestTime":"1月至3月及5月至6月稻谷成熟时节","specialties":["山羊肉","锅巴饭","山螺","金山酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('ninh-thuan', 'south-central-coast', 'Ninh Thuận', 'Ninh Thuan', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.8675, 11.7061, 'Nắng gió đặc trưng với vịnh Vĩnh Hy tuyệt mỹ, tháp Chăm cổ, vườn nho trĩu quả và những đàn cừu.', 'Ninh Thuận mang vẻ đẹp riêng của vùng đất đầy nắng và gió, nơi hội tụ vịnh Vĩnh Hy trong xanh, vườn quốc gia Núi Chúa hoang dã và những cánh đồng nho, đồng cừu độc đáo. Đây cũng là trung tâm văn hóa Chăm với các đền tháp cổ như Po Klong Garai và lễ hội Katê đặc sắc. Khí hậu khô nóng tạo nên đặc sản nho, táo, dê cừu trứ danh của xứ này.', 'Tháng 1 đến tháng 8', '["Nho Ninh Thuận","Thịt dê, cừu","Bánh canh chả cá","Táo xanh","Nước mắm Cà Ná"]', '{"en":{"summary":"A land of distinctive sun and wind with the exquisite Vinh Hy Bay, ancient Cham towers, fruit-laden vineyards, and flocks of sheep.","story":"Ninh Thuan has the unique beauty of a land full of sun and wind, where the clear blue Vinh Hy Bay, the wild Nui Chua National Park, and distinctive vineyards and sheep fields all come together. It is also a center of Cham culture with ancient temple towers like Po Klong Garai and the remarkable Kate festival. The hot, dry climate gives rise to the famous grapes, apples, goats, and sheep of this land.","bestTime":"January to August","specialties":["Ninh Thuan grapes","Goat and sheep meat","Fish-cake noodle soup","Green apples","Ca Na fish sauce"]},"ko":{"summary":"빼어난 빈히 만과 고대 참 탑, 주렁주렁 열린 포도밭과 양 떼를 품은 햇볕과 바람의 고장입니다.","story":"닌투언은 햇볕과 바람 가득한 땅 특유의 아름다움을 지녔으며, 맑고 푸른 빈히 만, 야성적인 누이쭈아 국립공원, 그리고 독특한 포도밭과 양 목장이 한데 모인 곳입니다. 또한 포클롱가라이 같은 고대 사원탑과 특색 있는 카테 축제를 지닌 참 문화의 중심지이기도 합니다. 덥고 건조한 기후가 이 고장의 이름난 포도, 사과, 염소와 양을 길러냅니다.","bestTime":"1월~8월","specialties":["닌투언 포도","염소·양고기","짜까 바인까인","청사과","까나 액젓"]},"ja":{"summary":"見事なヴィンヒー湾と古代チャム塔、たわわに実るぶどう園と羊の群れを持つ日差しと風の地です。","story":"ニントゥアンは、日差しと風に満ちた地ならではの美しさを持ち、青く澄んだヴィンヒー湾、野性的なヌイチュア国立公園、そして独特なぶどう園と羊の牧場が一堂に会する場所です。また、ポークロンガライをはじめとする古代の寺塔と特色あるカテー祭を持つチャム文化の中心地でもあります。暑く乾いた気候が、この地の名高いぶどう、りんご、山羊や羊を育てます。","bestTime":"1月〜8月","specialties":["ニントゥアンのぶどう","山羊・羊肉","魚のすり身のバインカイン","青りんご","カナーの魚醤"]},"zh":{"summary":"阳光与风的独特之地，拥有绝美的永希湾、古老占族塔、硕果累累的葡萄园与成群的羊。","story":"宁顺有着阳光与风之地独有的美，这里汇聚了碧绿清澈的永希湾、野趣盎然的主山国家公园，以及独特的葡萄园与羊群草场。这里也是占族文化中心，拥有婆克朗加莱等古老庙塔与别具特色的卡特节。干热的气候孕育出这片土地闻名遐迩的葡萄、苹果与羊。","bestTime":"1月至8月","specialties":["宁顺葡萄","羊肉","鱼饼羹粉","青苹果","嘉那鱼露"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('phu-tho', 'northeast', 'Phú Thọ', 'Phu Tho', 'Đông Bắc', '#4f7b6a', 105.1151, 21.3199, 'Vùng đất Tổ cội nguồn dân tộc với Đền Hùng linh thiêng, hát Xoan di sản và những đồi cọ, đồi chè trung du.', 'Phú Thọ là vùng đất Tổ thiêng liêng, cội nguồn của dân tộc Việt Nam với Khu di tích Đền Hùng nơi thờ các Vua Hùng dựng nước. Hằng năm, hàng triệu người con đất Việt hành hương về dự Giỗ Tổ Hùng Vương. Phú Thọ còn lưu giữ hát Xoan - di sản văn hóa phi vật thể của nhân loại, cùng cảnh sắc trung du với đồi cọ, đồi chè và những lễ hội truyền thống đậm đà bản sắc. Đây là điểm đến gắn với hành trình tìm về nguồn cội.', 'Tháng 3 âm lịch', '["Bưởi Đoan Hùng","Thịt chua Thanh Sơn","Bánh tai","Cọ ỏm"]', '{"en":{"summary":"The ancestral land and cradle of the nation with the sacred Hung Kings Temple, Xoan singing heritage and midland palm and tea hills.","story":"Phu Tho is the sacred ancestral land, cradle of the Vietnamese people, with the Hung Kings Temple complex honouring the nation-founding Hung Kings. Each year, millions of Vietnamese make a pilgrimage here for the Hung Kings'' Commemoration. Phu Tho also preserves Xoan singing — an intangible cultural heritage of humanity — along with midland scenery of palm and tea hills and traditional festivals rich in identity. It is a destination tied to the journey back to one''s roots.","bestTime":"The third lunar month","specialties":["Doan Hung pomelo","Thanh Son sour pork","Tai cake","Boiled palm fruit"]},"ko":{"summary":"신성한 훙왕 사당, 쏘안 노래 유산, 구릉지의 종려나무·차밭을 품은 민족의 근원, 시조의 땅.","story":"푸토는 건국한 훙왕들을 모시는 훙왕 사당 단지를 품은, 베트남 민족의 근원인 신성한 시조의 땅입니다. 해마다 수백만 베트남 후손이 훙왕 기일 제사를 위해 순례를 옵니다. 푸토는 또한 인류 무형문화유산인 쏘안 노래와 함께 종려나무·차밭의 구릉 경관, 정체성이 짙은 전통 축제를 간직하고 있습니다. 근원을 찾아가는 여정과 얽힌 명소입니다.","bestTime":"음력 3월","specialties":["도안훙 자몽","타인선 새콤 돼지고기","따이 떡","삶은 종려 열매"]},"ja":{"summary":"聖なるフン王廟、ソアン歌の遺産、丘陵のヤシ・茶畑を抱く民族の起源、始祖の地。","story":"フートーは、建国したフン王を祀るフン王廟群を抱く、ベトナム民族の起源たる聖なる始祖の地です。毎年、数百万のベトナムの子孫がフン王命日祭のために巡礼に訪れます。フートーはまた、人類無形文化遺産であるソアン歌とともに、ヤシ・茶畑の丘陵景観、個性豊かな伝統の祭りを今に伝えています。起源を訪ねる旅にゆかりの名所です。","bestTime":"旧暦3月","specialties":["ドアンフンのザボン","タインソンの酸っぱい豚肉","タイ餅","茹でヤシの実"]},"zh":{"summary":"民族根源、祖地之乡，拥有神圣的雄王庙、春歌遗产和中游的棕榈林、茶山。","story":"富寿是神圣的祖地，越南民族的根源所在，拥有供奉开国雄王的雄王庙遗迹区。每年，数百万越南儿女前来朝圣，参加雄王祭祖大典。富寿还保留着春歌——人类非物质文化遗产，连同棕榈林、茶山的中游景致和浓郁的传统庙会。这是一处与寻根之旅紧密相连的目的地。","bestTime":"农历三月","specialties":["端雄柚","清山酸肉","耳糕","煮棕榈果"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('phu-yen', 'south-central-coast', 'Phú Yên', 'Phu Yen', 'Duyên hải Nam Trung Bộ', '#3e92a8', 109.0553, 13.1695, 'Xứ sở hoa vàng cỏ xanh với Gành Đá Đĩa kỳ vĩ, Bãi Xép thơ mộng và những bãi biển hoang sơ.', 'Phú Yên được mệnh danh là ''xứ hoa vàng trên cỏ xanh'', mảnh đất bình yên với cảnh sắc thiên nhiên tuyệt đẹp và còn nhiều nét hoang sơ. Tỉnh nổi tiếng với kỳ quan địa chất Gành Đá Đĩa, Bãi Xép thơ mộng, hải đăng Mũi Điện đón ánh bình minh đầu tiên trên đất liền. Người Phú Yên hiền hòa, chân chất, cùng nền ẩm thực biển tươi ngon làm say lòng du khách.', 'Tháng 1 đến tháng 8', '["Mắt cá ngừ đại dương","Sò huyết Ô Loan","Bánh canh hẹ","Bò một nắng","Ghẹ Sông Cầu"]', '{"en":{"summary":"The land of yellow flowers on green grass with the majestic Ganh Da Dia, poetic Bai Xep, and pristine beaches.","story":"Phu Yen is dubbed the ''land of yellow flowers on green grass'', a peaceful place with stunning natural scenery and much still untouched. The province is famous for the geological wonder of Ganh Da Dia, poetic Bai Xep, and Mui Dien lighthouse that greets the first sunrise on the mainland. The people of Phu Yen are gentle and genuine, with a fresh, delicious seafood cuisine that captivates visitors.","bestTime":"January to August","specialties":["Ocean tuna eye","O Loan blood cockles","Chive noodle soup","One-sun-dried beef","Song Cau swimming crabs"]},"ko":{"summary":"웅장한 간다디아와 서정적인 바이쎕, 청정 해변을 지닌 ''푸른 풀밭의 노란 꽃'' 고장입니다.","story":"푸옌은 ''푸른 풀밭의 노란 꽃'' 고장이라 불리는, 빼어난 자연 경관과 많은 청정함을 간직한 평화로운 땅입니다. 지질 절경 간다디아, 서정적인 바이쎕, 그리고 본토에서 첫 일출을 맞이하는 무이디엔 등대로 유명합니다. 푸옌 사람들은 온화하고 순박하며, 싱싱하고 맛있는 해산물 음식으로 여행객의 마음을 사로잡습니다.","bestTime":"1월~8월","specialties":["참치 눈알","오로안 새꼬막","부추 바인까인","한볕 말린 소고기","송꺼우 꽃게"]},"ja":{"summary":"雄大なガンダーディアと詩情あふれるバイセップ、手つかずのビーチを持つ「緑の草原の黄色い花」の地です。","story":"フーイエンは「緑の草原の黄色い花」の地と称される、見事な自然の景観と多くの手つかずの風情を留めた穏やかな地です。地質の絶景ガンダーディア、詩情あふれるバイセップ、そして本土で最初の日の出を迎えるムイディエン灯台で有名です。フーイエンの人々は温和で純朴、新鮮で美味しい海の幸の食で旅人を魅了します。","bestTime":"1月〜8月","specialties":["マグロの目玉","オーロアンの赤貝","ニラのバインカイン","天日干しの牛肉","ソンカウのワタリガニ"]},"zh":{"summary":"黄花绿草之乡，拥有雄伟的叠石滩、诗意的瑞滩与原始海滩。","story":"富安被誉为「黄花绿草」之乡，是一片自然景色绝美、仍保留诸多原始风貌的宁静土地。该省以地质奇观叠石滩、诗意的瑞滩，以及迎接大陆第一缕日出的大岭灯塔而闻名。富安人温和淳朴，新鲜美味的海鲜美食令游客倾心。","bestTime":"1月至8月","specialties":["金枪鱼眼","乌滩血蚶","韭菜羹粉","一阳晒牛肉","泾江梭子蟹"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('quang-binh', 'north-central-coast', 'Quảng Bình', 'Quang Binh', 'Bắc Trung Bộ', '#5a8aa6', 106.2914, 17.5332, 'Vương quốc hang động của thế giới với Phong Nha - Kẻ Bàng và hang Sơn Đoòng kỳ vĩ.', 'Quảng Bình là miền đất của những kỳ quan dưới lòng đất. Vườn quốc gia Phong Nha - Kẻ Bàng ẩn giấu hàng trăm hang động đá vôi tráng lệ, trong đó Sơn Đoòng là hang lớn nhất hành tinh. Bên cạnh đó là bãi biển Nhật Lệ cát trắng, sông Son trong xanh và những làng quê yên bình. Vùng đất khắc nghiệt nắng gió này đã sản sinh ra nhiều con người kiên cường, hiếu khách.', 'Tháng 2–8, mùa khô ráo', '["Cháo canh","Bánh bột lọc","Khoai deo","Hải sản Nhật Lệ"]', '{"en":{"summary":"The world''s kingdom of caves, with Phong Nha - Ke Bang and the magnificent Son Doong Cave.","story":"Quang Binh is a land of underground wonders. Phong Nha - Ke Bang National Park conceals hundreds of magnificent limestone caves, among them Son Doong, the largest cave on the planet. Alongside them are the white-sand Nhat Le Beach, the clear blue Son River and peaceful villages. This harsh land of sun and wind has given rise to many resilient, hospitable people.","bestTime":"February–August, the dry season","specialties":["Chao canh (thick noodle soup)","Banh bot loc (tapioca dumplings)","Khoai deo (dried sweet potato)","Nhat Le seafood"]},"ko":{"summary":"퐁냐-께방과 웅장한 선동 동굴을 품은 세계 동굴의 왕국입니다.","story":"꽝빈은 땅속 경이의 고장입니다. 퐁냐-께방 국립공원은 수백 개의 화려한 석회암 동굴을 품고 있으며, 그중 선동은 지구상에서 가장 큰 동굴입니다. 그 곁에는 흰 모래의 녓레 해변과 맑고 푸른 손강, 평화로운 시골 마을이 있습니다. 햇볕과 바람이 거친 이 땅은 굳세고 손님을 환대하는 많은 사람을 길러냈습니다.","bestTime":"2~8월, 건기","specialties":["짜오까인(걸쭉한 국수)","반봇록(타피오카 만두)","코아이제오(말린 고구마)","녓레 해산물"]},"ja":{"summary":"フォンニャ・ケバンと壮大なソンドン洞窟を擁する、世界の洞窟王国です。","story":"クアンビンは地中の驚異の地です。フォンニャ・ケバン国立公園は数百もの壮麗な石灰岩洞窟を秘め、その中でもソンドンは地球上で最大の洞窟です。そのそばには白砂のニャットレービーチ、澄んだ青いソン川、のどかな田舎の村があります。日差しと風の厳しいこの地は、たくましく客をもてなす多くの人々を育んできました。","bestTime":"2〜8月、乾季","specialties":["チャオカイン（とろみのある麺）","バインボットロック（タピオカ餃子）","コアイゼオ（干し芋）","ニャットレーの海の幸"]},"zh":{"summary":"世界洞穴王国，拥有风牙—格邦与宏伟的山水洞。","story":"广平是地底奇观的土地。风牙—格邦国家公园隐藏着数百座壮丽的石灰岩洞穴，其中山水洞是地球上最大的洞穴。此外还有白沙的日丽海滩、清澈碧蓝的山河与宁静的乡村。这片阳光与风都严酷的土地，孕育出许多坚韧好客的人们。","bestTime":"2月至8月，干季","specialties":["稠汤面","木薯粉饺","红薯干","日丽海鲜"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('quang-nam', 'south-central-coast', 'Quảng Nam', 'Quang Nam', 'Duyên hải Nam Trung Bộ', '#3e92a8', 107.9562, 15.5904, 'Vùng đất di sản với phố cổ Hội An và thánh địa Mỹ Sơn, đậm đà văn hóa và ẩm thực.', 'Quảng Nam là nơi hội tụ hai di sản văn hóa thế giới: phố cổ Hội An lung linh đèn lồng và thánh địa Mỹ Sơn của vương quốc Chăm Pa cổ. Những làng nghề, bãi biển An Bàng và đồng quê yên ả tạo nên một Quảng Nam vừa cổ kính vừa thanh bình.', 'Tháng 2–4, khô ráo dễ chịu', '["Cao lầu","Mì Quảng","Bánh mì Hội An","Cơm gà"]', '{"en":{"summary":"A land of heritage with Hoi An Ancient Town and the My Son Sanctuary, rich in culture and cuisine.","story":"Quang Nam is where two world cultural heritages converge: Hoi An Ancient Town shimmering with lanterns and the My Son Sanctuary of the ancient Champa kingdom. Craft villages, An Bang Beach, and peaceful countryside make a Quang Nam both ancient and serene.","bestTime":"February–April, dry and pleasant","specialties":["Cao Lau","Mi Quang","Hoi An banh mi","Chicken rice"]},"ko":{"summary":"호이안 구시가지와 미선 성지를 지닌, 문화와 음식이 짙게 밴 유산의 땅입니다.","story":"꽝남은 두 세계문화유산이 어우러진 곳입니다. 등불로 반짝이는 호이안 구시가지와 고대 참파 왕국의 미선 성지. 공예 마을, 안방 해변, 그리고 평온한 시골이 어우러져 꽝남은 고풍스러우면서도 평화롭습니다.","bestTime":"2~4월, 건조하고 쾌적","specialties":["까오러우","미꽝","호이안 반미","닭고기 덮밥"]},"ja":{"summary":"ホイアン旧市街とミーソン聖地を持つ、文化と食が色濃い遺産の地です。","story":"クアンナムは二つの世界文化遺産が溶け合う地です。ランタンできらめくホイアン旧市街と、古代チャンパ王国のミーソン聖地。工芸の村々、アンバンビーチ、そして穏やかな田園が、古風でありながら平穏なクアンナムを形作ります。","bestTime":"2〜4月、乾燥して過ごしやすい","specialties":["カオラウ","ミークアン","ホイアンのバインミー","鶏飯"]},"zh":{"summary":"遗产之地，拥有会安古镇与美山圣地，文化与美食底蕴深厚。","story":"广南是两处世界文化遗产交汇之地：灯笼璀璨的会安古镇，以及古占婆王国的美山圣地。手工艺村落、安邦海滩与宁静的乡野，共同织就一个既古朴又安宁的广南。","bestTime":"2至4月，干爽宜人","specialties":["高楼面","广面","会安法棍","鸡饭"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('quang-ngai', 'south-central-coast', 'Quảng Ngãi', 'Quang Ngai', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.6473, 14.9927, 'Vùng đất miền Trung với đảo núi lửa Lý Sơn, biển Sa Huỳnh và cội nguồn văn hóa Sa Huỳnh cổ.', 'Quảng Ngãi là dải đất ven biển miền Trung mang trong mình bề dày lịch sử và vẻ đẹp thiên nhiên hoang sơ. Nơi đây có đảo Lý Sơn được kiến tạo từ núi lửa, nổi danh với tỏi và hùng binh Hoàng Sa, cùng biển Sa Huỳnh gắn với nền văn hóa cổ rực rỡ. Người dân cần cù, mến khách, gìn giữ những giá trị truyền thống quý báu qua bao thế hệ.', 'Tháng 5 đến tháng 9', '["Tỏi Lý Sơn","Cá bống sông Trà","Don","Quế Trà Bồng","Mạch nha"]', '{"en":{"summary":"A central Vietnam land with the volcanic island of Ly Son, Sa Huynh beach, and the roots of the ancient Sa Huynh culture.","story":"Quang Ngai is a coastal strip of central Vietnam carrying a depth of history and pristine natural beauty. Here lies the volcano-formed island of Ly Son, famous for garlic and the Hoang Sa flotilla, along with Sa Huynh beach tied to a brilliant ancient culture. The people are diligent and hospitable, preserving precious traditional values through generations.","bestTime":"May to September","specialties":["Ly Son garlic","Tra River goby fish","Don clams","Tra Bong cinnamon","Malt syrup"]},"ko":{"summary":"리선 화산섬과 사후인 해변, 고대 사후인 문화의 뿌리를 지닌 중부의 땅입니다.","story":"꽝응아이는 두터운 역사와 청정한 자연의 아름다움을 품은 중부 해안의 땅입니다. 이곳에는 화산으로 빚어진 리선 섬이 있어 마늘과 호앙사 수군으로 이름났고, 찬란한 고대 문화와 얽힌 사후인 해변이 있습니다. 주민들은 부지런하고 손님을 반기며, 대를 이어 귀중한 전통 가치를 지켜 왔습니다.","bestTime":"5월~9월","specialties":["리선 마늘","짜강 망둑어","돈(작은 조개)","짜봉 계피","맥아엿"]},"ja":{"summary":"リーソン火山島とサーフインビーチ、古代サーフイン文化の源流を持つ中部の地です。","story":"クアンガイは、厚みのある歴史と手つかずの自然の美を秘めた中部沿岸の地です。ここには火山が形作ったリーソン島があり、ニンニクとホアンサ水軍で名を馳せ、栄華を誇った古代文化と結びつくサーフインビーチがあります。人々は勤勉で客を歓び、幾世代にもわたって貴重な伝統の価値を守ってきました。","bestTime":"5月〜9月","specialties":["リーソンのニンニク","チャー川のハゼ","ドン（小さな貝）","チャーボンのシナモン","麦芽飴"]},"zh":{"summary":"拥有李山火山岛、沙黄海滩与古老沙黄文化之源的中部之地。","story":"广义是一片承载厚重历史与原始自然之美的中部沿海土地。这里有由火山塑造的李山岛，以大蒜与黄沙雄兵闻名，还有与灿烂古文化相连的沙黄海滩。当地人勤劳好客，世代守护着珍贵的传统价值。","bestTime":"5月至9月","specialties":["李山大蒜","茶江鲈鱼（小型）","蚬（Don）","茶蓬肉桂","麦芽糖"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('quang-ninh', 'northeast', 'Quảng Ninh', 'Quang Ninh', 'Đông Bắc', '#4f7b6a', 107.2152, 21.2645, 'Nơi có kỳ quan thiên nhiên thế giới Vịnh Hạ Long và những bãi biển, hải đảo tuyệt đẹp.', 'Quảng Ninh là vùng đất của biển và đảo. Vịnh Hạ Long với hàng nghìn hòn đảo đá vôi là niềm tự hào của cả Việt Nam. Bên cạnh đó là Bái Tử Long hoang sơ, đảo Cô Tô cát trắng và nền văn hóa vùng mỏ giàu bản sắc.', 'Tháng 10–12, biển êm và trời trong', '["Chả mực Hạ Long","Sá sùng","Ngán","Bánh gật gù"]', '{"en":{"summary":"Home to the world natural wonder of Ha Long Bay and beautiful beaches and islands.","story":"Quang Ninh is a land of sea and islands. Ha Long Bay, with its thousands of limestone islands, is the pride of all Vietnam. Alongside it lie the pristine Bai Tu Long, the white sands of Co To Island and a coal-mining culture rich in identity.","bestTime":"October–December, calm seas and clear skies","specialties":["Ha Long grilled cuttlefish cake","Sandworms","Mud clams","Gat gu cake"]},"ko":{"summary":"세계 자연유산 하롱베이와 아름다운 해변·섬을 품은 곳.","story":"꽝닌은 바다와 섬의 땅입니다. 수천 개의 석회암 섬을 품은 하롱베이는 베트남 전체의 자랑입니다. 그 곁에는 때 묻지 않은 바이뜨롱, 하얀 모래의 꼬또 섬, 그리고 정체성이 짙은 탄광 문화가 있습니다.","bestTime":"10~12월, 바다가 잔잔하고 하늘이 맑은 시기","specialties":["하롱 갑오징어 어묵","사숭(개불)","응안(조개)","갓구 떡"]},"ja":{"summary":"世界自然遺産ハロン湾と、美しい浜辺・島々を抱く場所。","story":"クアンニンは海と島の地です。数千の石灰岩の島を抱くハロン湾は、ベトナム全土の誇りです。その傍らには手つかずのバイトゥロン、白砂のコート島、そして個性豊かな炭鉱の文化があります。","bestTime":"10〜12月、海が穏やかで空が澄む時期","specialties":["ハロンのイカのすり身揚げ","サースン(ユムシ)","ガン(貝)","ガットグー餅"]},"zh":{"summary":"拥有世界自然奇观下龙湾和绝美海滩、海岛之地。","story":"广宁是海与岛之地。拥有数千座石灰岩岛屿的下龙湾，是整个越南的骄傲。其旁还有原始的拜子龙、白沙的姑苏岛，以及个性鲜明的矿区文化。","bestTime":"10至12月，海面平静、天空晴朗","specialties":["下龙墨鱼饼","沙虫","蚬","点头糕"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('quang-tri', 'north-central-coast', 'Quảng Trị', 'Quang Tri', 'Bắc Trung Bộ', '#5a8aa6', 106.928, 16.7475, 'Mảnh đất thiêng của những chứng tích chiến tranh hào hùng, từ Thành cổ, địa đạo đến đảo tiền tiêu Cồn Cỏ.', 'Quảng Trị là vùng đất thiêng liêng, nơi ghi dấu biết bao trang sử bi tráng và hào hùng của dân tộc. Từ Thành cổ với 81 ngày đêm rực lửa, làng hầm Vịnh Mốc kỳ vĩ đến hòn đảo anh hùng Cồn Cỏ, mỗi địa danh đều là một bản hùng ca. Vượt lên đau thương, người Quảng Trị hôm nay kiên cường dựng xây cuộc sống mới, biến mảnh đất lửa năm xưa thành điểm đến tri ân đầy xúc động và ý nghĩa.', 'Tháng 2 đến tháng 8', '["Bún hến Mai Xá","Cháo bột Kẻ Diên","Cua đá Cồn Cỏ","Tiêu Cùa"]', '{"en":{"summary":"A sacred land of heroic war relics, from the Ancient Citadel and the tunnels to the frontier island of Con Co.","story":"Quang Tri is a sacred land, marking countless tragic and heroic chapters of the nation''s history. From the Ancient Citadel with its blazing 81 days and nights, to the magnificent Vinh Moc tunnel village, to the heroic Con Co Island, each landmark is an epic. Rising above the sorrow, the people of Quang Tri today resiliently build a new life, turning the land of fire of years past into a moving and meaningful destination of gratitude.","bestTime":"February to August","specialties":["Mai Xa clam noodle soup (bun hen)","Ke Dien rice-paste porridge (chao bot)","Con Co stone crab","Cua pepper"]},"ko":{"summary":"고성과 땅굴에서 최전방 섬 꼰꼬까지, 영웅적인 전쟁 증적이 깃든 신성한 땅입니다.","story":"꽝찌는 민족의 비장하고 영웅적인 수많은 역사를 새긴 신성한 땅입니다. 81일 밤낮 불탔던 고성부터 웅장한 빈목 땅굴 마을, 영웅의 섬 꼰꼬까지 모든 지명이 하나의 서사시입니다. 슬픔을 딛고 오늘날 꽝찌 사람들은 굳세게 새 삶을 일구며, 옛 불의 땅을 감동적이고 의미 있는 추모의 명소로 바꾸어 갑니다.","bestTime":"2월부터 8월까지","specialties":["마이사 조개 국수(분헨)","께지엔 쌀반죽 죽(짜오봇)","꼰꼬 바위게","꾸어 후추"]},"ja":{"summary":"古城やトンネルから最前線の島コンコーまで、英雄的な戦争の証が宿る神聖な地です。","story":"クアンチは、民族の数多の悲壮で英雄的な歴史を刻んだ神聖な地です。81昼夜燃え盛った古城から、壮大なヴィンモックのトンネルの村、英雄の島コンコーまで、どの地名もひとつの叙事詩です。悲しみを乗り越え、今日のクアンチの人々はたくましく新しい暮らしを築き、かつての炎の地を、心を打つ意義深い感謝の名所へと変えています。","bestTime":"2月から8月まで","specialties":["マイサーのシジミ麺（ブンヘン）","ケジエンの米だんご粥（チャオボット）","コンコーの岩ガニ","クア胡椒"]},"zh":{"summary":"战争英雄遗迹的圣地，从古城、地道到前哨岛屿昏果。","story":"广治是一片神圣的土地，铭刻着民族无数悲壮而英勇的史诗。从八十一昼夜烈火熊熊的古城，到宏伟的永麻地道村，再到英雄之岛昏果，每一处地名都是一曲壮歌。超越伤痛，今日的广治人坚韧地建设新生活，将昔日的烽火之地化为动人而深具意义的感恩之地。","bestTime":"2月至8月","specialties":["梅舍蚬粉","稽延米浆粥","昏果石蟹","箍胡椒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('soc-trang', 'mekong-delta', 'Sóc Trăng', 'Soc Trang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.9218, 9.5599, 'Vùng đất giao thoa văn hóa Kinh, Khmer, Hoa với những ngôi chùa độc đáo, lễ hội đua ghe ngo và đặc sản trứ danh.', 'Sóc Trăng là tỉnh ven biển nổi tiếng với sự giao thoa đặc sắc của ba dân tộc Kinh, Khmer và Hoa, thể hiện rõ qua hệ thống chùa chiền độc đáo bậc nhất miền Tây. Nơi đây có Chùa Dơi với hàng nghìn con dơi quạ, Chùa Đất Sét kỳ lạ cùng nhiều ngôi chùa Khmer rực rỡ. Lễ hội đua ghe ngo dịp Ok Om Bok thu hút đông đảo du khách mỗi năm. Sóc Trăng còn nổi tiếng với những đặc sản trứ danh như bánh pía, lạp xưởng, mang đến hành trình khám phá văn hóa và ẩm thực đầy thú vị.', 'Tháng 11 đến tháng 1, dịp lễ Ok Om Bok và đua ghe ngo', '["Bánh pía Sóc Trăng","Bún nước lèo","Lạp xưởng","Mè láo","Bánh cống"]', '{"en":{"summary":"A land where Kinh, Khmer and Hoa cultures meet, with unique pagodas, the ngo boat race festival and famous specialties.","story":"Soc Trang is a coastal province famous for the distinctive blending of three peoples — Kinh, Khmer and Hoa — clearly shown in its remarkable system of pagodas, among the finest in the Mekong. Here are the Bat Pagoda with its thousands of flying foxes, the curious Clay Pagoda and many brilliant Khmer pagodas. The ngo boat race festival during Ok Om Bok draws large crowds of visitors each year. Soc Trang is also famous for renowned specialties such as pia cake and Chinese sausage, offering a fascinating journey of cultural and culinary discovery.","bestTime":"November to January, around the Ok Om Bok festival and ngo boat races","specialties":["Soc Trang pia cake","Bun nuoc leo","Chinese sausage","Me lao (sesame puff)","Banh cong"]},"ko":{"summary":"독특한 사원, 응오 보트 경주 축제, 이름난 특산물을 간직한 낀·크메르·화 문화가 어우러지는 땅.","story":"속짱은 낀·크메르·화 세 민족이 특색 있게 어우러진 것으로 유명한 해안 성으로, 메콩에서 손꼽히는 독특한 사원군에서 이를 뚜렷이 엿볼 수 있습니다. 수천 마리 큰박쥐가 있는 박쥐 사원, 기이한 흙 사원, 그리고 찬란한 크메르 사원이 많습니다. 옥옴복 때의 응오 보트 경주 축제는 해마다 많은 여행객을 끌어모읍니다. 속짱은 또한 바인삐아, 중국식 소시지 같은 이름난 특산물로 유명해, 문화와 미식을 탐방하는 흥미로운 여정을 선사합니다.","bestTime":"11~1월, 옥옴복 축제와 응오 보트 경주 시기","specialties":["속짱 바인삐아","분느억레오","중국식 소시지","메라오(깨 과자)","바인꽁"]},"ja":{"summary":"独特な寺院、ゴーボートレース祭り、名高い特産品を擁する、キン・クメール・華の文化が交わる地。","story":"ソクチャンはキン・クメール・華の三民族が特色豊かに交わることで有名な沿岸の省で、メコン屈指の独特な寺院群にそれが色濃く表れています。数千匹のオオコウモリがいるコウモリ寺、奇妙な土の寺、そして鮮やかなクメール寺院が数多くあります。オクオムボクの時期のゴーボートレース祭りは毎年多くの旅人を引き寄せます。ソクチャンはまたバインピアや中華ソーセージなど名高い特産品で有名で、文化と美食を探訪する興味深い旅をもたらします。","bestTime":"11〜1月、オクオムボク祭りとゴーボートレースの時期","specialties":["ソクチャンのバインピア","ブンヌクレオ","中華ソーセージ","メーラオ（ごま菓子）","バインコン"]},"zh":{"summary":"京、高棉、华文化交融之地，拥有独特的寺庙、赛艇节和著名特产。","story":"朔庄是一个以京、高棉、华三族独特交融而闻名的沿海省份，这在其湄公屈指可数的独特寺庙群中体现得淋漓尽致。这里有拥有数千只狐蝠的蝙蝠寺、奇特的泥土寺，以及众多绚丽的高棉寺庙。送水节期间的赛艇节每年吸引众多游客。朔庄还以馅饼、腊肠等著名特产闻名，带来一段探索文化与美食的趣味之旅。","bestTime":"11月至1月，送水节和赛艇节期间","specialties":["朔庄馅饼","鱼汤米粉","腊肠","芝麻酥","炸虾饼"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('son-la', 'northwest', 'Sơn La', 'Son La', 'Tây Bắc', '#6e8c5a', 104.0702, 21.1945, 'Cao nguyên Tây Bắc với thảo nguyên Mộc Châu xanh mướt, đồi chè và những mùa hoa nối tiếp.', 'Sơn La là vùng cao nguyên rộng lớn của Tây Bắc, nổi tiếng nhất với cao nguyên Mộc Châu — thảo nguyên xanh mênh mông với đồi chè, rừng mận và các mùa hoa rực rỡ quanh năm. Khí hậu mát mẻ, cảnh sắc nên thơ cùng văn hóa các dân tộc Thái, Mông tạo nên sức hút đặc biệt. Đây cũng là vùng đất của những bản làng yên bình và đặc sản núi rừng độc đáo.', 'Tháng 11–2 (mùa hoa mận, hoa cải)', '["Bê chao Mộc Châu","Sữa tươi","Bắp cải mèo","Cá hồi, cá tầm","Thịt trâu gác bếp"]', '{"en":{"summary":"A northwestern plateau with the lush green Moc Chau grassland, tea hills and flower seasons one after another.","story":"Son La is a vast northwestern plateau, most famous for the Moc Chau plateau — a boundless green grassland with tea hills, plum forests and vibrant flower seasons all year round. Its cool climate, poetic scenery and the cultures of the Thai and Hmong create a special appeal. It is also a land of peaceful villages and unique mountain-forest specialties.","bestTime":"November–February (plum and mustard flower season)","specialties":["Moc Chau fried veal","Fresh milk","Hmong cabbage","Salmon and sturgeon","Smoked buffalo meat"]},"ko":{"summary":"푸른 목쩌우 초원, 차밭, 연이어 피는 꽃의 계절을 품은 서북부 고원.","story":"선라는 서북부의 드넓은 고원으로, 차밭과 매화숲, 사계절 화사한 꽃의 계절이 어우러진 광활한 초록 초원 목쩌우 고원으로 가장 유명합니다. 서늘한 기후, 시적인 경관, 그리고 타이족과 몽족의 문화가 특별한 매력을 자아냅니다. 평화로운 마을과 독특한 산림 특산물의 땅이기도 합니다.","bestTime":"11~2월(매화·유채꽃 시즌)","specialties":["목쩌우 송아지 튀김","생우유","몽족 양배추","연어, 철갑상어","물소고기 훈제"]},"ja":{"summary":"緑のモクチャウ草原、茶畑、次々と咲く花の季節を抱く西北部の高原。","story":"ソンラは西北部の広大な高原で、茶畑や梅林、一年中華やかな花の季節が調和する広大な緑の草原モクチャウ高原で最も有名です。涼しい気候、詩情あふれる景観、そしてターイ族とモン族の文化が特別な魅力を醸し出します。穏やかな村と独特な山林の特産品の地でもあります。","bestTime":"11〜2月(梅・アブラナの花の季節)","specialties":["モクチャウの子牛肉揚げ","搾りたて牛乳","モン族のキャベツ","サーモン、チョウザメ","水牛肉の燻製"]},"zh":{"summary":"西北高原，拥有苍翠的木州草原、茶山和接连不断的花季。","story":"山萝是西北部辽阔的高原，最以木州高原闻名——那是一片广袤的绿色草原，茶山、梅林与四季绚烂的花季交相辉映。凉爽的气候、诗意的景致连同泰族、苗族的文化，构成独特的魅力。这里也是宁静村寨与独特山林特产之地。","bestTime":"11至2月（梅花、油菜花季）","specialties":["木州炸牛犊肉","鲜牛奶","苗族卷心菜","三文鱼、鲟鱼","炕熏水牛肉"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('tay-ninh', 'southeast', 'Tây Ninh', 'Tay Ninh', 'Đông Nam Bộ', '#b07a4a', 106.1602, 11.4041, 'Vùng đất tâm linh miền Đông với ''nóc nhà Nam Bộ'' Núi Bà Đen và Tòa Thánh Cao Đài rực rỡ độc đáo.', 'Tây Ninh là tỉnh biên giới Tây Nam nổi danh là trung tâm tâm linh của miền Đông Nam Bộ. Núi Bà Đen – đỉnh cao nhất Nam Bộ – thu hút hàng triệu lượt hành hương và du khách mỗi năm với chùa chiền linh thiêng và cáp treo hiện đại. Tòa Thánh Cao Đài, trung tâm của một tôn giáo bản địa độc đáo, mang vẻ đẹp kiến trúc giao thoa Đông – Tây có một không hai. Tây Ninh còn nổi tiếng với bánh tráng phơi sương và muối tôm đậm đà.', 'Tháng 11 đến tháng 4 và mùa lễ hội tháng Giêng', '["Bánh tráng phơi sương Trảng Bàng","Muối tôm Tây Ninh","Bánh canh Trảng Bàng"]', '{"en":{"summary":"A spiritual land of the southeast with the ''rooftop of the South,'' Ba Den Mountain, and the dazzling, unique Cao Dai Holy See.","story":"Tay Ninh is a southwestern border province renowned as the spiritual center of the southeast. Ba Den Mountain—the highest peak in the South—draws millions of pilgrims and visitors each year with its sacred temples and modern cable car. The Cao Dai Holy See, center of a unique homegrown religion, carries a one-of-a-kind East–West blended architectural beauty. Tay Ninh is also famous for its dew-dried rice paper and savory shrimp salt.","bestTime":"November to April and the festival season in the first lunar month","specialties":["Trang Bang dew-dried rice paper","Tay Ninh shrimp salt","Trang Bang banh canh"]},"ko":{"summary":"''남부의 지붕'' 바덴산과 화려하고 독특한 까오다이교 대성전을 품은 동남부의 영적인 땅.","story":"떠이닌은 서남부 국경 성으로 동남부의 영적 중심지로 이름났습니다. 남부 최고봉인 바덴산은 영험한 사원과 현대식 케이블카로 해마다 수백만 명의 순례객과 여행객을 끌어모읍니다. 독특한 토착 종교의 중심인 까오다이교 대성전은 둘도 없는 동서 융합 건축의 아름다움을 지닙니다. 떠이닌은 또한 이슬에 말린 라이스페이퍼와 짭조름한 새우 소금으로도 유명합니다.","bestTime":"11월~4월과 음력 정월 축제철","specialties":["짱방 이슬 라이스페이퍼","떠이닌 새우 소금","짱방 반깐"]},"ja":{"summary":"「南部の屋根」バーデン山と、絢爛で独特なカオダイ教総本山を擁する東南部の精神の地。","story":"タイニンは西南部の国境の省で、東南部の精神的中心地として名高い地です。南部最高峰のバーデン山は、霊験あらたかな寺と近代的なロープウェイで、毎年数百万の巡礼者と旅人を集めます。独特な土着宗教の中心であるカオダイ教総本山は、唯一無二の東西融合建築の美しさを持ちます。タイニンはまた、露で乾かしたライスペーパーと、塩気のあるエビ塩でも有名です。","bestTime":"11月〜4月と旧暦正月の祭りの季節","specialties":["チャンバンの露干しライスペーパー","タイニンのエビ塩","チャンバンのバインカン"]},"zh":{"summary":"东南部的灵性之地，拥有「南部屋脊」婆田山和绚丽独特的高台教圣座。","story":"西宁是西南边境省份，以东南部灵性中心而闻名。婆田山——南部最高峰——凭借灵验的寺庙和现代缆车，每年吸引数百万香客与游客。作为一种独特本土宗教中心的高台教圣座，呈现出独一无二的东西融合建筑之美。西宁还以露晒米纸和咸香虾盐而著称。","bestTime":"11月至4月及正月庙会时节","specialties":["塍坊露晒米纸","西宁虾盐","塍坊粿条汤"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('thai-binh', 'red-river-delta', 'Thái Bình', 'Thai Binh', 'Đồng bằng sông Hồng', '#c7993f', 106.3862, 20.5075, 'Quê hương năm tấn với chùa Keo cổ kính, biển Cồn Vành hoang sơ và những cánh đồng lúa thẳng cánh cò bay.', 'Thái Bình là quê lúa thanh bình của đồng bằng sông Hồng, nơi những cánh đồng vàng óng trải dài tận chân trời. Vùng đất này tự hào với chùa Keo gần 400 năm tuổi, kiệt tác kiến trúc gỗ với gác chuông ba tầng độc nhất vô nhị. Bờ biển Thái Bình còn có Cồn Vành hoang sơ nằm trong khu dự trữ sinh quyển sông Hồng. Người Thái Bình hiền hòa, chân chất, gìn giữ những giá trị văn hóa làng quê và các lễ hội cổ truyền đậm đà bản sắc Bắc Bộ.', 'Tháng 4 đến tháng 9', '["Bánh cáy làng Nguyễn","Canh cá Quỳnh Côi","Gỏi nhệch","Nem chạo Vị Thủy"]', '{"en":{"summary":"The ''five-ton homeland'' with the ancient Keo Pagoda, pristine Con Vanh Beach, and rice fields stretching as far as the eye can see.","story":"Thai Binh is the peaceful rice country of the Red River Delta, where golden fields stretch to the horizon. This land takes pride in the nearly 400-year-old Keo Pagoda, a masterpiece of wooden architecture with a one-of-a-kind three-tier bell tower. The Thai Binh coast also has pristine Con Vanh within the Red River Biosphere Reserve. The people of Thai Binh are gentle and unpretentious, preserving the cultural values of village life and traditional festivals rich in the character of the North.","bestTime":"April to September","specialties":["Nguyen village cay cake","Quynh Coi fish soup","Goi nhech (raw eel salad)","Vi Thuy nem chao"]},"ko":{"summary":"고풍스러운 께오 사찰과 원시 그대로의 꼰바인 해변, 끝없이 펼쳐진 논을 지닌 ‘5톤의 고장’.","story":"타이빈은 홍강 삼각주의 평화로운 벼 고장으로, 황금빛 들녘이 지평선 끝까지 펼쳐진 곳입니다. 이 땅은 400년 가까운 역사의 께오 사찰을 자랑하는데, 유일무이한 3층 종루를 갖춘 목조 건축의 걸작입니다. 타이빈 해안에는 또한 홍강 생물권 보전지역 안에 자리한 원시 그대로의 꼰바인이 있습니다. 타이빈 사람들은 온화하고 순박하여, 시골 마을의 문화 가치와 북부의 짙은 정체성이 깃든 전통 축제를 지켜 갑니다.","bestTime":"4월~9월","specialties":["응우옌 마을 바인까이","꾸인꼬이 생선 국","고이넥(갯장어 회무침)","비투이 넴짜오"]},"ja":{"summary":"「五トンの里」。古き趣のケオ寺、手つかずのコンヴァインビーチ、そして見渡す限りの稲田が広がります。","story":"タイビンは紅河デルタの穏やかな稲作の里で、黄金色の田んぼが地平線まで続いています。この地は築400年近くのケオ寺を誇り、唯一無二の三層の鐘楼を持つ木造建築の傑作です。タイビンの海辺にはまた、紅河生物圏保護区内にある手つかずのコンヴァインがあります。タイビンの人々は穏やかで素朴で、農村の文化的価値と、北部の趣豊かな伝統の祭りを守り続けています。","bestTime":"4月から9月","specialties":["グエン村のバインカイ","クインコイの魚のスープ（カインカー）","うなぎの和え物（ゴイネック）","ヴィトゥイのネムチャオ"]},"zh":{"summary":"五吨之乡\"，拥有古朴的翘寺、原始的昆望海滩和一望无际的稻田。","story":"太平是红河三角洲安宁的稻乡，金黄的稻田绵延至天际。这片土地以近400年历史的翘寺为傲，那是木构建筑的杰作，拥有独一无二的三层钟楼。太平海岸还有位于红河生物圈保护区内的原始昆望海滩。太平人温和淳朴，守护着乡土文化的价值与浓郁北部特色的古老庙会。","bestTime":"4月至9月","specialties":["阮村饴糕","琼魁鱼汤","鳗鱼凉拌","渭水肉糜卷"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('thai-nguyen', 'northeast', 'Thái Nguyên', 'Thai Nguyen', 'Đông Bắc', '#4f7b6a', 105.8213, 21.692, 'Vùng đất ''đệ nhất danh trà'' với những đồi chè bát ngát, Hồ Núi Cốc huyền thoại và di tích ATK lịch sử.', 'Thái Nguyên là tỉnh trung du nổi danh khắp nước với những đồi chè Tân Cương xanh mướt, cái nôi của ''đệ nhất danh trà'' Việt Nam. Nơi đây còn có Hồ Núi Cốc gắn liền truyền thuyết tình yêu nàng Công - chàng Cốc, hang Phượng Hoàng kỳ vĩ và khu di tích ATK Định Hóa lịch sử. Thái Nguyên hài hòa giữa cảnh sắc thiên nhiên thanh bình, văn hóa trà đặc sắc và truyền thống cách mạng, là điểm đến hấp dẫn của vùng Việt Bắc.', 'Tháng 3 đến tháng 9', '["Trà Tân Cương","Cơm lam","Bánh chưng Bờ Đậu","Tương nếp Úc Kỳ"]', '{"en":{"summary":"The land of the ''finest tea'' with boundless tea hills, the legendary Nui Coc Lake and the historic ATK relic.","story":"Thai Nguyen is a midland province renowned nationwide for the lush green Tan Cuong tea hills, the cradle of Vietnam''s ''finest tea''. It also has Nui Coc Lake, tied to the love legend of Lady Cong and Mr Coc, the magnificent Phuong Hoang Cave and the historic Dinh Hoa ATK relic. Thai Nguyen harmonises peaceful natural scenery, a distinctive tea culture and revolutionary tradition, making it an appealing destination in the Viet Bac region.","bestTime":"March to September","specialties":["Tan Cuong tea","Bamboo-tube rice","Bo Dau sticky rice cake","Uc Ky glutinous-rice soy sauce"]},"ko":{"summary":"드넓은 차밭, 전설의 누이꼭 호수, 역사적인 ATK 유적을 품은 ''제일 명차''의 고장.","story":"타이응우옌은 푸른 떤끄엉 차밭으로 전국에 이름난 중부 구릉 성으로, 베트남 ''제일 명차''의 요람입니다. 이곳에는 꽁 낭자와 꼭 총각의 사랑 전설과 얽힌 누이꼭 호수, 웅장한 프엉호앙 동굴, 역사적인 딘호아 ATK 유적도 있습니다. 타이응우옌은 평화로운 자연 경관, 독특한 차 문화, 혁명 전통이 조화를 이루는 비엣박 지역의 매력적인 명소입니다.","bestTime":"3월부터 9월","specialties":["떤끄엉 차","대통밥","버더우 쯩떡(찰떡)","욱끼 찹쌀 간장"]},"ja":{"summary":"広大な茶畑、伝説のヌイコック湖、歴史的なATK遺跡を抱く「随一の名茶」の里。","story":"タイグエンは緑のタンクオン茶畑で全国に名高い中部丘陵省で、ベトナム「随一の名茶」の揺りかごです。ここにはコン姫とコック青年の恋の伝説にゆかりのヌイコック湖、雄大なフォンホアン洞窟、歴史的なディンホアATK遺跡もあります。タイグエンは穏やかな自然景観、独特の茶文化、革命の伝統が調和する、ベトバック地方の魅力的な名所です。","bestTime":"3月から9月","specialties":["タンクオン茶","竹筒飯","ボーダウのちまき餅","ウックキーのもち米味噌"]},"zh":{"summary":"「天下第一名茶」之乡，拥有无垠茶山、传奇的𡶀谷湖和历史性的ATK遗迹。","story":"太原是闻名全国的中游省份，拥有苍翠的新疆茶山，是越南「天下第一名茶」的摇篮。这里还有与公娘、谷郎爱情传说相连的𡶀谷湖、雄奇的凤凰洞和历史性的定化ATK遗迹。太原融汇了宁静的自然景观、独特的茶文化与革命传统，是越北地区颇具魅力的目的地。","bestTime":"3月至9月","specialties":["新疆茶","竹筒饭","𤖕豆粽子","郁奇糯米酱"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('thanh-hoa', 'north-central-coast', 'Thanh Hóa', 'Thanh Hoa', 'Bắc Trung Bộ', '#5a8aa6', 105.3171, 20.0465, 'Vùng đất địa linh nhân kiệt xứ Thanh, hội tụ di sản thành đá, bãi biển sầm uất và suối cá thần kỳ bí.', 'Thanh Hóa là mảnh đất giàu trầm tích lịch sử, quê hương của nhiều triều đại và anh hùng dân tộc. Nơi đây sở hữu Thành nhà Hồ - di sản thế giới bằng đá độc nhất vô nhị, bãi biển Sầm Sơn rộn ràng cùng suối cá thần Cẩm Lương huyền bí. Từ đồng bằng trù phú đến miền núi đại ngàn, xứ Thanh luôn níu chân du khách bởi bề dày văn hóa và thiên nhiên đa dạng, hào sảng.', 'Tháng 4 đến tháng 9', '["Nem chua Thanh Hóa","Bánh gai Tứ Trụ","Hải sản Sầm Sơn","Cơm lam"]', '{"en":{"summary":"A land of sacred ground and gifted people, Thanh Hoa brings together a stone heritage, a bustling beach, and a mysterious sacred fish stream.","story":"Thanh Hoa is a land rich in the sediment of history, the homeland of many dynasties and national heroes. Here stands the Ho Citadel — a one-of-a-kind stone World Heritage Site — alongside the lively Sam Son Beach and the mysterious Cam Luong Sacred Fish Stream. From fertile plains to mountainous wilderness, Thanh Hoa always holds visitors with its depth of culture and its diverse, generous nature.","bestTime":"April to September","specialties":["Thanh Hoa fermented pork roll (nem chua)","Tu Tru banh gai (gai-leaf cake)","Sam Son seafood","Bamboo-tube rice (com lam)"]},"ko":{"summary":"신령한 땅과 빼어난 인물의 고장 타인호아는 석조 유산과 번화한 해변, 신비로운 신어 계곡을 함께 품습니다.","story":"타인호아는 역사의 퇴적이 풍부한 땅으로, 여러 왕조와 민족 영웅의 고향입니다. 이곳에는 세상에 둘도 없는 석조 세계유산 호 왕조 성채와 흥겨운 삼손 해변, 신비로운 껌르엉 신어 계곡이 있습니다. 비옥한 평야에서 깊은 산속 야생까지, 타인호아는 깊은 문화와 다양하고 호방한 자연으로 언제나 방문객의 발길을 붙잡습니다.","bestTime":"4월부터 9월까지","specialties":["타인호아 넴쭈아(발효 돼지고기 롤)","뜨쭈 반자이(가이잎 떡)","삼손 해산물","껌람(대통밥)"]},"ja":{"summary":"霊地にして人傑の地タインホア。石造の遺産、賑やかなビーチ、神秘の神魚の渓流が集います。","story":"タインホアは歴史の堆積に富む地で、多くの王朝と民族の英雄の故郷です。ここには世界に二つとない石造の世界遺産、胡朝城があり、賑やかなサムソンビーチと神秘的なカムルオン神魚の渓流があります。肥沃な平野から山深い原野まで、タインホアは文化の厚みと多様で雄大な自然で、いつも訪れる人の足を引きとめます。","bestTime":"4月から9月まで","specialties":["タインホアのネムチュア（発酵豚肉ロール）","トゥーチューのバインガイ（ガイの葉の餅）","サムソンの海の幸","コムラム（竹筒飯）"]},"zh":{"summary":"人杰地灵的清化，汇聚石城遗产、繁华海滩与神奇的神鱼溪。","story":"清化是历史积淀深厚的土地，是众多王朝与民族英雄的故乡。这里拥有举世无双的石造世界遗产胡朝城、热闹的岑山海滩与神秘的锦良神鱼溪。从富饶平原到深山林海，清化总以深厚的文化与多样豪迈的自然，留住游人的脚步。","bestTime":"4月至9月","specialties":["清化酸肉卷","四柱gai叶饼","岑山海鲜","竹筒饭"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('thua-thien-hue', 'north-central-coast', 'Thừa Thiên Huế', 'Thua Thien Hue', 'Bắc Trung Bộ', '#5a8aa6', 107.5061, 16.3332, 'Cố đô trầm mặc bên dòng sông Hương, nơi lưu giữ di sản cung đình và ẩm thực tinh tế.', 'Huế mang vẻ đẹp cổ kính, hoài niệm. Quần thể di tích triều Nguyễn, lăng tẩm uy nghiêm, chùa Thiên Mụ soi bóng sông Hương. Người Huế nhẹ nhàng, giọng nói ngọt ngào, và ẩm thực cung đình cầu kỳ đến từng chi tiết. Đến Huế là để sống chậm và lắng nghe.', 'Tháng 1–4, tránh mùa mưa cuối năm', '["Bún bò Huế","Cơm hến","Bánh bèo, nậm, lọc","Chè Huế"]', '{"en":{"summary":"A serene former imperial capital by the Perfume River, preserving royal heritage and refined cuisine.","story":"Hue carries an ancient, nostalgic beauty. The complex of Nguyen Dynasty monuments, solemn royal tombs, and Thien Mu Pagoda mirrored in the Perfume River. The people of Hue are gentle, their speech sweet, and their royal-court cuisine elaborate down to the last detail. To come to Hue is to live slowly and to listen.","bestTime":"January–April, avoiding the late-year rainy season","specialties":["Bun bo Hue (Hue beef noodle soup)","Com hen (clam rice)","Banh beo, nam, loc","Hue sweet soups (che Hue)"]},"ko":{"summary":"흐엉강 곁의 고요한 옛 수도로, 궁정 유산과 정교한 음식을 간직한 곳입니다.","story":"후에는 고풍스럽고 그리움 어린 아름다움을 지녔습니다. 응우옌 왕조 기념물 복합지구와 위엄 있는 능묘, 흐엉강에 그림자를 드리운 티엔무 사원이 있습니다. 후에 사람들은 부드럽고 말씨가 다정하며, 궁중 요리는 세세한 부분까지 정교합니다. 후에에 오는 것은 천천히 살며 귀 기울이기 위함입니다.","bestTime":"1~4월, 연말 우기는 피하세요","specialties":["분보후에(후에 소고기 국수)","껌헨(조개밥)","반베오, 남, 록","후에식 째"]},"ja":{"summary":"フォン川のほとりに静かにたたずむ古都。宮廷の遺産と繊細な料理を守り伝えます。","story":"フエは古色蒼然とした、追憶の美しさをたたえます。グエン朝の建造物群、荘厳な陵墓、フォン川に影を映すティエンムー寺。フエの人々はおおらかで、言葉は甘やかに響き、宮廷料理は細部まで凝っています。フエを訪れることは、ゆっくりと暮らし、耳を澄ますためなのです。","bestTime":"1〜4月、年末の雨季は避けて","specialties":["ブンボーフエ（フエの牛肉麺）","コムヘン（シジミご飯）","バインベオ、ナム、ロック","フエのチェー"]},"zh":{"summary":"香江畔静谧的古都，珍藏着宫廷遗产与精致美食。","story":"顺化透着古朴而怀旧的美。阮朝古迹群、庄严的陵寝、倒映香江的天姥寺。顺化人温文尔雅，乡音甜柔，宫廷美食讲究到每一处细节。来到顺化，是为了放慢脚步、静心聆听。","bestTime":"1月至4月，避开年末雨季","specialties":["顺化牛肉粉","蚬饭","浮萍饼、糯米饼、粉卷","顺化甜羹"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('tien-giang', 'mekong-delta', 'Tiền Giang', 'Tien Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.3122, 10.3974, 'Vựa trái cây của miền Tây bên sông Tiền, với các cù lao trù phú, chợ nổi sầm uất và đờn ca tài tử ngọt ngào.', 'Tiền Giang nằm bên dòng sông Tiền hiền hòa, là một trong những vựa trái cây lớn nhất đồng bằng sông Cửu Long. Tỉnh nổi tiếng với các cù lao xanh mát như Thới Sơn, chợ nổi Cái Bè trăm năm tuổi và những vườn cây ăn trái sai trĩu quanh năm. Du lịch miệt vườn sông nước nơi đây gắn liền với đờn ca tài tử, ẩm thực dân dã và lòng hiếu khách của người miền Tây. Tiền Giang là điểm khởi đầu quen thuộc cho hành trình khám phá đồng bằng.', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', '["Hủ tiếu Mỹ Tho","Trái cây miệt vườn","Mắm còng","Bánh giá Gò Công"]', '{"en":{"summary":"The fruit basket of the Mekong by the Tien River, with fertile islets, busy floating markets and sweet don ca tai tu.","story":"Tien Giang lies along the gentle Tien River and is one of the largest fruit baskets in the Mekong Delta. The province is famous for cool green islets such as Thoi Son, the century-old Cai Be Floating Market and orchards heavy with fruit year-round. Its orchard-and-river tourism is tied to don ca tai tu, rustic cuisine and the hospitality of the Mekong people. Tien Giang is a familiar starting point for journeys to explore the delta.","bestTime":"May to August, when the fruit is in full season","specialties":["My Tho hu tieu","Orchard fruit","Cong (mud crab) sauce","Go Cong banh gia"]},"ko":{"summary":"비옥한 섬, 번화한 수상시장, 달콤한 던까따이뜨를 간직한 띠엔강변 메콩의 과일 곳간.","story":"띠엔장은 잔잔한 띠엔강변에 자리한, 메콩델타에서 가장 큰 과일 곳간 중 하나입니다. 터이선 같은 시원한 초록 섬, 백 년 된 까이베 수상시장, 일 년 내내 과일이 주렁주렁 달린 과수원으로 유명합니다. 이곳의 과수원·강변 관광은 던까따이뜨, 소박한 음식, 메콩 사람들의 손님 환대와 어우러져 있습니다. 띠엔장은 델타 탐방 여정의 친숙한 출발점입니다.","bestTime":"5~8월, 과일이 무르익는 철","specialties":["미토 후띠에우","과수원 과일","껌 게장(맘꽁)","고꽁 바인자"]},"ja":{"summary":"肥沃な島、賑わう水上市場、甘いドンカータイトゥを擁するティエン川辺のメコンの果物倉。","story":"ティエンザンは穏やかなティエン川辺に位置する、メコンデルタ最大級の果物倉の一つです。トイソンのような涼しげな緑の島、百年のカイベー水上市場、一年中果実を実らせる果樹園で有名です。ここの果樹園・川辺の観光はドンカータイトゥ、素朴な料理、メコンの人々のもてなしと結びついています。ティエンザンはデルタ探訪の旅の馴染み深い出発点です。","bestTime":"5〜8月、果物が熟す季節","specialties":["ミトーのフーティウ","果樹園の果物","シオマネキの塩辛（マムコン）","ゴーコンのバインザー"]},"zh":{"summary":"前江畔湄公的果仓，拥有富饶的小岛、繁华的水上市场和甜美的才子弹唱。","story":"前江省坐落于温和的前江畔，是湄公河三角洲最大的果仓之一。该省以泰山等清凉翠绿的小岛、百年历史的丐皮水上市场和常年硕果累累的果园闻名。这里的果园水乡旅游与才子弹唱、乡土美食和湄公人民的好客紧密相连。前江是探索三角洲之旅熟悉的起点。","bestTime":"5月至8月，水果成熟旺季","specialties":["美湫河粉","果园水果","招潮蟹酱","鹅贡炸饼"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('tra-vinh', 'mekong-delta', 'Trà Vinh', 'Tra Vinh', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.3155, 9.7977, 'Vùng đất văn hóa Khmer đặc sắc với những ngôi chùa cổ kính, hàng cây cổ thụ và lễ hội truyền thống độc đáo.', 'Trà Vinh là tỉnh ven biển mang đậm bản sắc văn hóa Khmer Nam Bộ, nổi tiếng với hàng trăm ngôi chùa cổ kính nằm giữa những hàng cây sao, dầu trăm tuổi. Thắng cảnh Ao Bà Om huyền thoại, chùa Vàm Ray dát vàng lộng lẫy cùng các lễ hội Ok Om Bok, Chôl Chnăm Thmây tạo nên một không gian văn hóa đặc sắc hiếm có. Người Kinh, Khmer và Hoa cùng sinh sống hòa thuận, gìn giữ những giá trị truyền thống và nét đẹp tâm linh độc đáo của vùng đất hiền hòa này.', 'Tháng 11 đến tháng 1, dịp lễ Ok Om Bok của người Khmer', '["Bún nước lèo","Bánh canh Bến Có","Dừa sáp Cầu Kè","Cốm dẹp"]', '{"en":{"summary":"A land of distinctive Khmer culture, with ancient pagodas, old-growth trees and unique traditional festivals.","story":"Tra Vinh is a coastal province steeped in southern Khmer culture, famous for hundreds of ancient pagodas set among centuries-old hopea and dipterocarp trees. The legendary Ba Om Pond, the dazzling gilded Vam Ray Pagoda and festivals such as Ok Om Bok and Chol Chnam Thmay create a rare and distinctive cultural space. The Kinh, Khmer and Hoa peoples live together in harmony, preserving traditional values and the unique spiritual beauty of this gentle land.","bestTime":"November to January, around the Khmer Ok Om Bok festival","specialties":["Bun nuoc leo","Ben Co banh canh","Cau Ke wax coconut","Flattened young rice (com dep)"]},"ko":{"summary":"고풍스러운 사원, 노거수, 독특한 전통 축제를 간직한 특색 있는 크메르 문화의 땅.","story":"짜빈은 남부 크메르 문화가 짙게 배인 해안 성으로, 수백 년 된 호페아·딥테로카르푸스 나무 사이에 자리한 수백 곳의 고풍스러운 사원으로 유명합니다. 전설의 바옴 연못, 눈부신 금박 밤라이 사원, 그리고 옥옴복과 쫄츠남트마이 축제가 보기 드문 특색 있는 문화 공간을 빚어냅니다. 낀·크메르·화족이 어우러져 화목하게 살며, 이 온화한 땅의 전통 가치와 독특한 영적 아름다움을 지켜 갑니다.","bestTime":"11~1월, 크메르족 옥옴복 축제 시기","specialties":["분느억레오","벤꼬 바인까인","꺼우께 왁스 코코넛","껌뎁(납작 햇곡물)"]},"ja":{"summary":"古色蒼然とした寺院、古木、独特な伝統祭礼を擁する特色あるクメール文化の地。","story":"チャヴィンは南部クメール文化が色濃く息づく沿岸の省で、数百年を経たホペア・フタバガキの木々の間に佇む数百の古色蒼然とした寺院で有名です。伝説のバーオム池、まばゆい金箔のヴァムライ寺院、そしてオクオムボクやチョルチュナムトマイの祭礼が、稀有で特色ある文化空間を織りなします。キン・クメール・華の人々が和やかに共に暮らし、この穏やかな地の伝統的価値と独特な霊的美しさを守り続けています。","bestTime":"11〜1月、クメール族のオクオムボク祭りの時期","specialties":["ブンヌクレオ","ベンコーのバインカイン","カウケーのワックスココナッツ","コムデップ（つぶし新米）"]},"zh":{"summary":"高棉文化独具特色的土地，拥有古朴的寺庙、参天古树和独特的传统节庆。","story":"茶荣是一个南部高棉文化浓郁的沿海省份，以坐落于百年桫木、龙脑香树间的数百座古朴寺庙闻名。传奇的婆嗡池、金碧辉煌的湾莱寺，以及送水节、初春新年等节庆，营造出难得而独特的文化空间。京、高棉和华族和睦共处，守护着这片温和土地的传统价值和独特的灵性之美。","bestTime":"11月至1月，高棉族送水节期间","specialties":["鱼汤米粉","边古粿条","梂稽蜡椰","扁青米"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('tuyen-quang', 'northeast', 'Tuyên Quang', 'Tuyen Quang', 'Đông Bắc', '#4f7b6a', 105.267, 22.1131, 'Thủ đô kháng chiến với di tích Tân Trào lịch sử, hồ thủy điện Nà Hang thơ mộng và những cánh rừng nguyên sinh.', 'Tuyên Quang là vùng đất cách mạng được mệnh danh ''Thủ đô khu giải phóng'' với cụm di tích lịch sử Tân Trào, cây đa Tân Trào và lán Nà Nưa gắn liền những ngày tiền khởi nghĩa năm 1945. Bên cạnh giá trị lịch sử, Tuyên Quang còn quyến rũ bởi hồ thủy điện Nà Hang xanh biếc, Thác Mơ thơ mộng và Khu bảo tồn thiên nhiên với rừng nguyên sinh trùng điệp. Lễ hội Thành Tuyên rước đèn khổng lồ độc đáo cũng là điểm nhấn không thể bỏ lỡ.', 'Tháng 5 đến tháng 11', '["Thịt trâu gác bếp","Cá lăng sông Lô","Bánh gai Chiêm Hóa","Rượu ngô"]', '{"en":{"summary":"The resistance capital with the historic Tan Trao relic, the poetic Na Hang hydropower lake and primeval forests.","story":"Tuyen Quang is a revolutionary land hailed as the ''capital of the liberated zone'', with the Tan Trao historic relic cluster, the Tan Trao banyan tree and the Na Nua hut tied to the days before the 1945 uprising. Beyond its historical value, Tuyen Quang also charms with the blue-green Na Hang hydropower lake, the poetic Mo Waterfall and a nature reserve of rolling primeval forest. The Thanh Tuyen Festival, with its parade of giant lanterns, is a highlight not to be missed.","bestTime":"May to November","specialties":["Smoked buffalo meat","Lo River catfish","Chiem Hoa gai cake","Corn wine"]},"ko":{"summary":"역사적인 떤짜오 유적, 시적인 나항 수력발전 호수, 원시림을 품은 항전 수도.","story":"뚜옌꽝은 1945년 봉기 직전의 나날과 얽힌 떤짜오 유적 단지, 떤짜오 보리수, 나느어 오두막을 품어 ''해방구 수도''로 불리는 혁명의 땅입니다. 역사적 가치와 더불어 뚜옌꽝은 짙푸른 나항 수력발전 호수, 시적인 모 폭포, 첩첩한 원시림의 자연보호구역으로도 매력을 발합니다. 거대한 등을 행진시키는 독특한 타인뚜옌 축제도 놓칠 수 없는 볼거리입니다.","bestTime":"5월부터 11월","specialties":["물소고기 훈제","로강 메기","찌엠호아 가이 떡","옥수수 술"]},"ja":{"summary":"歴史的なタンチャオ遺跡、詩情あふれるナーハン水力発電湖、原生林を抱く抗戦の首都。","story":"トゥエンクアンは、1945年の蜂起直前の日々にゆかりのタンチャオ遺跡群、タンチャオの菩提樹、ナーヌア小屋を抱き「解放区の首都」と称される革命の地です。歴史的価値に加え、トゥエンクアンは青緑のナーハン水力発電湖、詩情あふれるモー滝、連なる原生林の自然保護区でも魅力を放ちます。巨大な灯籠を行進させる独特のタイントゥエン祭りも見逃せない見どころです。","bestTime":"5月から11月","specialties":["水牛肉の燻製","ロー川のナマズ","チエムホアのガイ餅","トウモロコシ酒"]},"zh":{"summary":"抗战首都，拥有历史性的新潮遗迹、诗意的那杭水电湖和大片原始森林。","story":"宣光是革命之地，因拥有新潮历史遗迹群、新潮榕树和与1945年起义前夕紧密相连的那纳棚屋，被誉为「解放区首都」。除历史价值外，宣光还以碧绿的那杭水电湖、诗意的梦瀑布和拥有连绵原始森林的自然保护区令人着迷。游灯巡游巨型花灯的成宣节，独具特色，也是不容错过的一大亮点。","bestTime":"5月至11月","specialties":["炕熏水牛肉","泸江鲈鱼","占化粽叶糕","玉米酒"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('vinh-long', 'mekong-delta', 'Vĩnh Long', 'Vinh Long', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.9888, 10.1025, 'Trái tim miệt vườn của miền Tây giữa hai dòng sông, nổi tiếng với cù lao trái cây và làng nghề gạch gốm trăm năm.', 'Vĩnh Long nằm giữa sông Tiền và sông Hậu, là vùng đất phù sa trù phú bậc nhất đồng bằng sông Cửu Long. Tỉnh nổi tiếng với cù lao An Bình xanh mát, cái nôi của du lịch homestay miệt vườn, cùng vương quốc lò gạch gốm Mang Thít độc đáo ven sông Cổ Chiên. Vĩnh Long còn là quê hương của nhiều danh nhân và là vùng đất hiếu học. Đến đây, du khách được đắm mình trong những vườn trái cây sum suê, nghe đờn ca tài tử và cảm nhận nhịp sống sông nước chân chất, đậm đà tình người.', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', '["Cá tai tượng chiên xù","Bưởi năm roi Bình Minh","Khoai lang Bình Tân","Tàu hủ ky"]', '{"en":{"summary":"The orchard heart of the Mekong between two rivers, famous for fruit islets and a century-old brick-and-pottery craft village.","story":"Vinh Long lies between the Tien and Hau rivers, one of the most fertile alluvial lands in the Mekong Delta. The province is famous for the cool green An Binh Islet, the cradle of orchard-homestay tourism, and the unique kingdom of Mang Thit brick-and-pottery kilns by the Co Chien River. Vinh Long is also the homeland of many notable figures and a land of scholarly tradition. Here, visitors immerse themselves in lush orchards, listen to don ca tai tu and feel the down-to-earth, warm-hearted rhythm of river life.","bestTime":"May to August, when the fruit is in full season","specialties":["Crispy fried elephant-ear fish","Binh Minh nam roi pomelo","Binh Tan sweet potato","Tofu skin (tau hu ky)"]},"ko":{"summary":"과일 섬과 백 년 된 벽돌·도자기 공예 마을로 유명한, 두 강 사이 메콩의 과수원 심장.","story":"빈롱은 띠엔강과 후강 사이에 자리한, 메콩델타에서 손꼽히게 비옥한 충적토의 땅입니다. 과수원 홈스테이 관광의 발상지인 시원한 초록 안빈섬과 꼬찌엔강변의 독특한 망팃 벽돌·도자기 가마 왕국으로 유명합니다. 빈롱은 또한 여러 명인의 고향이자 학문을 숭상하는 땅입니다. 이곳에서 여행객은 무성한 과수원에 흠뻑 빠지고, 던까따이뜨를 들으며, 소박하고 정 깊은 강변 삶의 리듬을 느낍니다.","bestTime":"5~8월, 과일이 무르익는 철","specialties":["코끼리귀 물고기 튀김","빈민 남로이 포멜로","빈떤 고구마","두부 막(따우후끼)"]},"ja":{"summary":"果物の島と百年の煉瓦・陶器の工芸村で有名な、二つの川に挟まれたメコンの果樹園の心臓。","story":"ヴィンロンはティエン川とハウ川に挟まれた、メコンデルタ屈指の肥沃な沖積土の地です。果樹園ホームステイ観光の発祥地である涼しげな緑のアンビン島と、コーチエン川辺の独特なマンティット煉瓦・陶器窯の王国で有名です。ヴィンロンはまた多くの名士の故郷であり、学問を重んじる地でもあります。ここで旅人は茂った果樹園に浸り、ドンカータイトゥを聴き、素朴で情に厚い川辺の暮らしのリズムを感じます。","bestTime":"5〜8月、果物が熟す季節","specialties":["ゾウミミウオの揚げ物","ビンミンのナムロイ・ザボン","ビンタンのサツマイモ","湯葉（タウフーキー）"]},"zh":{"summary":"两江之间湄公的果园心脏，以果园小岛和百年砖陶手工艺村闻名。","story":"永隆位于前江与后江之间，是湄公河三角洲最富饶的沃土之一。该省以清凉翠绿的安平岛——果园民宿旅游的摇篮——以及古战江畔独特的莛织砖陶窑王国闻名。永隆还是众多名人的故乡，是崇文好学之地。来到这里，游客可沉醉于硕果累累的果园，聆听才子弹唱，感受质朴而充满人情味的水乡生活节奏。","bestTime":"5月至8月，水果成熟旺季","specialties":["酥炸象耳鱼","平明五瓣柚","平新红薯","腐竹"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('vinh-phuc', 'red-river-delta', 'Vĩnh Phúc', 'Vinh Phuc', 'Đồng bằng sông Hồng', '#c7993f', 105.5579, 21.3611, 'Cửa ngõ Tây Bắc Hà Nội với thị trấn mây Tam Đảo mát lành và khu danh thắng tâm linh Tây Thiên linh thiêng.', 'Vĩnh Phúc là vùng đất chuyển tiếp giữa đồng bằng và miền núi phía Bắc, nổi bật với thị trấn nghỉ mát Tam Đảo bồng bềnh trong mây. Quanh năm khí hậu mát mẻ, Tam Đảo trở thành điểm trốn nóng lý tưởng và là chốn check-in lãng mạn bậc nhất miền Bắc. Dưới chân núi là khu danh thắng Tây Thiên với thiền viện Trúc Lâm và tín ngưỡng thờ Quốc Mẫu ngàn năm. Vĩnh Phúc còn có đặc sản su su Tam Đảo, bánh trùng mật mía và các món gà đồi thơm ngon, níu chân du khách phương xa.', 'Tháng 4 đến tháng 10', '["Su su Tam Đảo","Bánh trùng mật mía","Gà đồi Tam Đảo","Bò tái kiến đốt"]', '{"en":{"summary":"The northwestern gateway of Hanoi, with the cool, cloud-wreathed town of Tam Dao and the sacred Tay Thien spiritual scenic area.","story":"Vinh Phuc is a transitional land between the delta and the northern mountains, standing out for the resort town of Tam Dao drifting among the clouds. Cool year-round, Tam Dao has become an ideal escape from the heat and one of the most romantic check-in spots in the North. At the foot of the mountain lies the Tay Thien scenic area, with the Truc Lam Zen monastery and the millennium-old worship of the National Mother. Vinh Phuc also boasts the specialty of Tam Dao chayote, sugarcane-syrup dumpling cakes, and delicious hill chicken dishes that keep travelers lingering.","bestTime":"April to October","specialties":["Tam Dao chayote","Sugarcane-syrup dumpling cake","Tam Dao hill chicken","Ant-grilled rare beef"]},"ko":{"summary":"서늘한 구름 마을 땀다오와 신성한 떠이티엔 영적 명승지를 지닌 하노이 북서쪽 관문.","story":"빈푹은 평야와 북부 산악 지대 사이의 전이 지대로, 구름 속에 두둥실 떠 있는 땀다오 휴양 마을이 돋보입니다. 일 년 내내 서늘한 기후 덕분에 땀다오는 이상적인 피서지이자 북부에서 가장 낭만적인 인증샷 명소가 되었습니다. 산기슭에는 쭉럼 선원과 천년 국모 신앙이 깃든 떠이티엔 명승지가 있습니다. 빈푹에는 또한 땀다오 차요테, 바인쭝 사탕수수 조청 떡, 향긋한 산닭 요리 같은 명물이 있어 먼 곳에서 온 여행자의 발길을 붙듭니다.","bestTime":"4월~10월","specialties":["땀다오 차요테","사탕수수 조청 떡","땀다오 산닭","보따이끼엔돗(개미 육회)"]},"ja":{"summary":"ハノイ北西の玄関口。涼やかな雲上の街タムダオと、神聖な信仰の景勝地タイティエンを擁します。","story":"ヴィンフックは平野と北部山岳地帯の移行地帯で、雲にたゆたう保養地タムダオが際立っています。一年中涼やかな気候のタムダオは、暑さを逃れる理想の地であり、北部随一のロマンチックな写真スポットでもあります。山の麓には、チュックラム禅院と千年に及ぶ国母信仰のタイティエン景勝地があります。ヴィンフックにはまた、名産のタムダオ産チャヨテ、糖蜜の白玉団子、香り豊かな地鶏料理があり、遠来の旅行者を引き留めます。","bestTime":"4月から10月","specialties":["タムダオ産チャヨテ","糖蜜の白玉団子","タムダオの地鶏","蟻焼きの牛タタキ"]},"zh":{"summary":"河内西北门户，拥有清凉的三岛云中小镇和神圣的西天灵性名胜区。","story":"永福是平原与北部山区之间的过渡之地，以飘浮在云雾中的三岛度假小镇最为突出。常年气候凉爽，三岛成为理想的避暑胜地和北部最浪漫的打卡之地。山脚下是西天名胜区，有竹林禅院和供奉国母的千年信仰。永福还有三岛佛手瓜、糖蜜汤圆和鲜美的山地走地鸡等特产，令远方游客流连忘返。","bestTime":"4月至10月","specialties":["三岛佛手瓜","糖蜜汤圆","三岛走地鸡","蚁咬生牛肉"]}}');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties, i18n) VALUES ('yen-bai', 'northeast', 'Yên Bái', 'Yen Bai', 'Đông Bắc', '#4f7b6a', 104.567, 21.7778, 'Miền Tây Bắc kỳ vĩ với ruộng bậc thang Mù Cang Chải vàng óng, hồ Thác Bà nghìn đảo và sắc màu văn hóa vùng cao.', 'Yên Bái là tỉnh miền núi Tây Bắc nổi danh với ruộng bậc thang Mù Cang Chải - di tích quốc gia đặc biệt và là kỳ quan do người Mông tạo nên. Mùa lúa chín, cả vùng nhuộm vàng óng ả đẹp ngỡ ngàng. Yên Bái còn có Hồ Thác Bà với hơn 1.300 hòn đảo xanh, đồi chè Suối Giàng, suối khoáng nóng và sắc màu văn hóa của người Mông, Thái, Tày. Đây là điểm đến lý tưởng cho những ai yêu thiên nhiên hùng vĩ và bản sắc vùng cao.', 'Tháng 9 đến tháng 10', '["Cốm Tú Lệ","Thịt trâu gác bếp","Chè Shan tuyết Suối Giàng","Cá nướng hồ Thác Bà"]', '{"en":{"summary":"A magnificent northwest with the golden Mu Cang Chai terraced fields, the thousand-island Thac Ba Lake and vibrant highland culture.","story":"Yen Bai is a northwestern mountain province renowned for the Mu Cang Chai terraced fields — a special national relic and a wonder shaped by the Hmong people. In the ripe rice season, the whole region turns a breathtaking gold. Yen Bai also has Thac Ba Lake with over 1,300 green islands, the Suoi Giang tea hills, hot mineral springs and the vibrant culture of the Hmong, Thai and Tay. It is an ideal destination for lovers of magnificent nature and highland identity.","bestTime":"September to October","specialties":["Tu Le green rice flakes","Smoked buffalo meat","Suoi Giang Shan Tuyet tea","Thac Ba Lake grilled fish"]},"ko":{"summary":"황금빛 무깡짜이 계단식 논, 천 개의 섬을 품은 탁바 호수, 다채로운 고원 문화가 어우러진 웅장한 서북부.","story":"옌바이는 특별 국가 유적이자 몽족이 빚어낸 절경인 무깡짜이 계단식 논으로 이름난 서북부 산악 성입니다. 벼 익는 시즌이면 일대 전체가 눈부신 황금빛으로 물듭니다. 옌바이에는 또한 1,300여 개의 푸른 섬을 품은 탁바 호수, 쑤오이장 차밭, 온천, 그리고 몽족·타이족·따이족의 다채로운 문화가 있습니다. 웅장한 자연과 고원의 정체성을 사랑하는 이들에게 이상적인 명소입니다.","bestTime":"9월부터 10월","specialties":["뚜레 햅쌀 콤(찐 햅쌀)","물소고기 훈제","쑤오이장 산뚜옛 차","탁바 호수 생선구이"]},"ja":{"summary":"黄金のムーカンチャイ棚田、千の島を抱くタックバー湖、彩り豊かな高原文化が調和する雄大な西北部。","story":"イエンバイは、特別国家遺跡でありモン族が築いた絶景であるムーカンチャイの棚田で名高い西北部の山岳省です。稲の実る季節には、一帯全体が目を見張る黄金色に染まります。イエンバイにはまた、1,300余りの緑の島を抱くタックバー湖、スオイザン茶畑、温泉、そしてモン族・ターイ族・ターイ族の彩り豊かな文化があります。雄大な自然と高原の個性を愛する人々に理想的な名所です。","bestTime":"9月から10月","specialties":["トゥーレの新米コム(蒸し新米)","水牛肉の燻製","スオイザンのシャンチュエット茶","タックバー湖の焼き魚"]},"zh":{"summary":"雄奇的西北之地，拥有金黄的木江界梯田、千岛的婆瀑湖和绚丽多彩的高原文化。","story":"安沛是西北部的山区省份，以木江界梯田闻名——这是特别国家遗迹，也是苗族开垦而成的奇观。稻谷成熟季，整片地区染成令人惊叹的金黄。安沛还有拥有1300余座绿岛的婆瀑湖、水羊茶山、温泉，以及苗族、泰族、岱依族绚丽多彩的文化。这是热爱雄奇自然与高原风情之人的理想目的地。","bestTime":"9月至10月","specialties":["秀丽扁米","炕熏水牛肉","水羊山雪茶","婆瀑湖烤鱼"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('lung-cu-flag-tower', 'lung-cu-flag-tower', 'ha-giang', 'Cột cờ Lũng Cú', 'Lung Cu Flag Tower', 'mountain', 105.3133, 23.3617, 'Điểm cực Bắc thiêng liêng của Tổ quốc, nơi lá cờ đỏ sao vàng tung bay giữa trời cao nguyên đá.', 'Đứng trên đỉnh Lũng Cú, gió từ biên giới thổi qua mang theo cái lạnh trong veo của vùng cao. Lá cờ rộng 54m² — tượng trưng cho 54 dân tộc anh em — kiêu hãnh phấp phới trên nền trời. Leo hết 839 bậc đá, cả cao nguyên đá Đồng Văn mở ra dưới chân bạn: những thửa ruộng bậc thang, bản làng người Mông, và đường biên giới uốn lượn theo dòng Nho Quế.', '["Cột cờ cao 33,15m, đặt trên đỉnh núi Rồng ở độ cao gần 1.470m.","Lá cờ có diện tích 54m², tượng trưng cho 54 dân tộc Việt Nam.","Từ đỉnh cột cờ có thể nhìn thấy hai hồ nước gọi là ''mắt rồng''."]', '["Mang theo áo ấm — đỉnh núi lộng gió và lạnh kể cả mùa hè.","Đi sáng sớm để tránh sương mù che tầm nhìn."]', 'Tháng 10–12 (mùa hoa tam giác mạch) hoặc tháng 9 (mùa lúa chín)', 'Nửa ngày', '25.000đ', '07:00 – 18:00', '["popular","verified"]', '["mountain","culture","photography"]', '[{"seed":"lungcu-1","caption":"Lá cờ Tổ quốc trên đỉnh núi Rồng","ratio":"16/9"},{"seed":"lungcu-2","caption":"Đường lên cột cờ","ratio":"4/3"},{"seed":"lungcu-3","caption":"Cao nguyên đá nhìn từ trên cao","ratio":"1/1"},{"seed":"lungcu-4","caption":"Cột cờ uy nghiêm, lá cờ đỏ tung bay trong sương","ratio":"4/3"}]', '["dong-van-old-town","ma-pi-leng-pass"]', 1, '{"en":{"name":"Lung Cu Flag Tower","summary":"The sacred northernmost point of the country, where the red flag with a golden star flies high above the rocky plateau.","story":"Standing atop Lung Cu, the wind sweeps in from the border carrying the crisp chill of the highlands. The 54-square-metre flag — symbolising Vietnam''s 54 ethnic groups — flutters proudly against the sky. After climbing all 839 stone steps, the entire Dong Van Karst Plateau unfolds beneath your feet: terraced fields, Hmong villages, and the border winding along the Nho Que River.","facts":["The tower stands 33.15m tall, set atop Dragon Mountain at nearly 1,470m above sea level.","The flag measures 54 square metres, symbolising Vietnam''s 54 ethnic groups.","From the top you can see two ponds known as the ''dragon''s eyes''."],"travelTips":["Bring a warm jacket — the summit is windy and cold even in summer.","Go early in the morning to avoid the fog that blocks the view."],"bestTime":"October–December (buckwheat flower season) or September (golden rice season)","visitDuration":"Half a day","ticket":"25,000 VND","openingHours":"07:00 – 18:00","galleryCaptions":["The national flag atop Dragon Mountain","The path up to the flag tower","The karst plateau seen from above","The majestic tower, the red flag flying in the mist"]},"ko":{"name":"룽꾸 국기탑","summary":"조국 최북단의 신성한 지점으로, 황금별이 새겨진 붉은 국기가 석회암 고원의 하늘 높이 펄럭이는 곳.","story":"룽꾸 정상에 서면 국경에서 불어오는 바람이 고원의 맑고 차가운 공기를 실어 옵니다. 베트남 54개 민족을 상징하는 54㎡ 크기의 국기가 하늘을 배경으로 자랑스럽게 휘날립니다. 839개의 돌계단을 모두 오르면 동반 카르스트 고원이 발아래 펼쳐집니다. 계단식 논, 몽족 마을, 그리고 뇨꾸에강을 따라 굽이치는 국경선이 한눈에 들어옵니다.","facts":["국기탑은 높이 33.15m로, 해발 약 1,470m의 룽(용) 산 정상에 세워져 있습니다.","국기는 면적 54㎡로 베트남 54개 민족을 상징합니다.","탑 정상에서는 ''용의 눈''이라 불리는 두 개의 연못을 볼 수 있습니다."],"travelTips":["따뜻한 외투를 챙기세요. 정상은 여름에도 바람이 세고 춥습니다.","시야를 가리는 안개를 피하려면 이른 아침에 가세요."],"bestTime":"10~12월(메밀꽃 시즌) 또는 9월(황금 벼 시즌)","visitDuration":"반나절","ticket":"25,000동","openingHours":"07:00 – 18:00","galleryCaptions":["룽(용) 산 정상의 조국 국기","국기탑으로 오르는 길","위에서 내려다본 석회암 고원","위엄 있는 국기탑, 안개 속에 휘날리는 붉은 깃발"]},"ja":{"name":"ルンクー国旗塔","summary":"祖国最北端の聖なる地。黄金の星を抱く赤い国旗が、石灰岩高原の空高くはためく場所。","story":"ルンクーの頂に立つと、国境から吹き抜ける風が高原の澄んだ冷気を運んできます。ベトナム54の民族を象徴する54平方メートルの国旗が、空を背に誇らしげに翻ります。839段の石段を登りきると、ドンヴァン・カルスト高原が足元に広がります。棚田、モン族の村々、そしてニョクエ川に沿って蛇行する国境線が一望できます。","facts":["塔は高さ33.15メートル、標高約1,470メートルの龍山の頂に建っています。","国旗は面積54平方メートルで、ベトナム54の民族を象徴します。","塔の頂上からは「龍の眼」と呼ばれる二つの池が見えます。"],"travelTips":["暖かい上着を持参しましょう。山頂は夏でも風が強く寒いです。","視界を遮る霧を避けるため、早朝に訪れましょう。"],"bestTime":"10〜12月（ソバの花の季節）または9月（黄金の稲の季節）","visitDuration":"半日","ticket":"25,000ドン","openingHours":"07:00 – 18:00","galleryCaptions":["龍山の頂にはためく祖国の国旗","国旗塔へ登る道","高みから見下ろす石灰岩高原","霧の中で赤旗を翻す荘厳な国旗塔"]},"zh":{"name":"龙古国旗塔","summary":"祖国最北端的神圣之地，金星红旗在石灰岩高原的高空中迎风招展。","story":"站在龙古之巅，来自边境的风带来高原清冽的寒意。这面54平方米的国旗——象征越南54个民族——在天空映衬下骄傲地飘扬。登完839级石阶，整个同文岩石高原便在脚下展开：层层梯田、苗族村寨，以及沿着纳奎河蜿蜒的边境线。","facts":["国旗塔高33.15米，矗立在海拔近1470米的龙山之巅。","国旗面积54平方米，象征越南54个民族。","从塔顶可以望见两个被称为「龙眼」的水潭。"],"travelTips":["请带上保暖外套——山顶风大，即便夏天也很冷。","请清晨前往，以避开遮挡视线的浓雾。"],"bestTime":"10至12月（荞麦花季）或9月（金色稻谷季）","visitDuration":"半天","ticket":"25,000越南盾","openingHours":"07:00 – 18:00","galleryCaptions":["龙山之巅的祖国国旗","通往国旗塔的山路","从高处俯瞰的岩石高原","庄严的国旗塔，红旗在薄雾中飘扬"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ma-pi-leng-pass', 'ma-pi-leng-pass', 'ha-giang', 'Đèo Mã Pì Lèng', 'Ma Pi Leng Pass', 'mountain', 105.2667, 23.2333, 'Một trong ''tứ đại đỉnh đèo'' của Việt Nam, vách đá dựng đứng bên dòng Nho Quế xanh ngọc.', 'Mã Pì Lèng là cung đường khiến mọi tay lái phải nín thở. Con đường Hạnh Phúc men theo vách núi, một bên là đá tai mèo sừng sững, một bên là vực sâu hun hút nơi dòng Nho Quế chảy như một dải lụa xanh. Người ta nói đứng ở đây mới thấy con người thật nhỏ bé, còn thiên nhiên thì vĩ đại đến nhường nào.', '["Đèo dài khoảng 20km, ở độ cao gần 1.500m.","Tên ''Mã Pì Lèng'' theo tiếng Mông nghĩa là ''sống mũi con ngựa''.","Hẻm vực Tu Sản bên dưới là hẻm vực sâu nhất Đông Nam Á."]', '["Thuê thuyền trên sông Nho Quế để ngắm đèo từ dưới lên — góc nhìn ngoạn mục.","Lái xe chậm và cẩn thận, đặc biệt khi trời mưa."]', 'Tháng 9–11, trời khô ráo, ít sương', '2–3 giờ', '', 'Cả ngày', '["trending","hidden-gem"]', '["mountain","photography"]', '[{"seed":"mapileng-1","caption":"Đường Hạnh Phúc vắt qua vách núi","ratio":"16/9"},{"seed":"mapileng-2","caption":"Dòng Nho Quế xanh ngọc","ratio":"4/3"},{"seed":"mapileng-3","caption":"Hẻm vực Tu Sản","ratio":"1/1"}]', '["lung-cu-flag-tower","dong-van-old-town"]', 0, '{"en":{"name":"Ma Pi Leng Pass","summary":"One of Vietnam''s ''four great mountain passes'', with sheer cliffs plunging to the jade-green Nho Que River.","story":"Ma Pi Leng is a road that takes every driver''s breath away. The Happiness Road clings to the mountainside — towering rocky crags on one side, a dizzying abyss on the other, where the Nho Que River flows like a ribbon of green silk. They say only here do you truly feel how small humans are, and how magnificent nature can be.","facts":["The pass is about 20km long, at nearly 1,500m above sea level.","''Ma Pi Leng'' means ''the bridge of a horse''s nose'' in the Hmong language.","The Tu San Canyon below is the deepest canyon in Southeast Asia."],"travelTips":["Rent a boat on the Nho Que River to admire the pass from below — a spectacular view.","Drive slowly and carefully, especially in the rain."],"bestTime":"September–November, dry weather with little fog","visitDuration":"2–3 hours","ticket":"Free","openingHours":"All day","galleryCaptions":["The Happiness Road etched across the cliff","The jade-green Nho Que River","Tu San Canyon"]},"ko":{"name":"마피렝 고개","summary":"베트남 ''4대 명품 고개'' 중 하나로, 옥빛 뇨꾸에강 위로 깎아지른 절벽이 솟아 있는 곳.","story":"마피렝은 모든 운전자가 숨을 죽이게 만드는 길입니다. ''행복의 길''이 산허리를 따라 이어지는데, 한쪽은 우뚝 솟은 바위 절벽이고 다른 한쪽은 뇨꾸에강이 초록 비단처럼 흐르는 아찔한 협곡입니다. 이곳에 서야 비로소 인간이 얼마나 작은지, 자연이 얼마나 위대한지를 느낄 수 있다고들 합니다.","facts":["고개는 길이 약 20km, 해발 약 1,500m에 있습니다.","''마피렝''은 몽족어로 ''말의 콧등''을 뜻합니다.","아래의 뚜산 협곡은 동남아시아에서 가장 깊은 협곡입니다."],"travelTips":["뇨꾸에강에서 배를 빌려 아래에서 고개를 올려다보세요. 장관입니다.","특히 비가 올 때는 천천히 조심해서 운전하세요."],"bestTime":"9~11월, 건조하고 안개가 적은 시기","visitDuration":"2~3시간","ticket":"무료","openingHours":"종일","galleryCaptions":["절벽을 가로지르는 행복의 길","옥빛 뇨꾸에강","뚜산 협곡"]},"ja":{"name":"マーピーレン峠","summary":"ベトナム「四大名峠」の一つ。翡翠色のニョクエ川のほとりに切り立った絶壁がそびえる場所。","story":"マーピーレンは、すべてのドライバーが息をのむ道です。「幸福の道」が山腹を縫うように続き、片側はそびえる岩の絶壁、もう片側はニョクエ川が緑の絹のように流れる目もくらむ渓谷です。ここに立ってこそ、人間がいかに小さく、自然がいかに雄大かを感じられると言われています。","facts":["峠は全長約20キロ、標高約1,500メートルにあります。","「マーピーレン」はモン族の言葉で「馬の鼻筋」を意味します。","眼下のトゥーサン渓谷は東南アジアで最も深い渓谷です。"],"travelTips":["ニョクエ川で船を借り、下から峠を見上げてみましょう。壮観です。","特に雨の日はゆっくり慎重に運転しましょう。"],"bestTime":"9〜11月、乾燥して霧の少ない時期","visitDuration":"2〜3時間","ticket":"無料","openingHours":"終日","galleryCaptions":["絶壁を横切る幸福の道","翡翠色のニョクエ川","トゥーサン渓谷"]},"zh":{"name":"马皮龙山口","summary":"越南「四大名山口」之一，悬崖峭壁矗立于翡翠般碧绿的纳奎河畔。","story":"马皮龙是一条令每位驾驶者都屏息凝神的道路。「幸福之路」沿着山腰盘旋，一侧是高耸的岩壁，另一侧是纳奎河如绿绸般流淌的深邃峡谷。人们说，站在这里才真正感到人之渺小，自然之伟大。","facts":["山口全长约20公里，海拔近1500米。","「马皮龙」在苗语中意为「马鼻梁」。","下方的徒山峡谷是东南亚最深的峡谷。"],"travelTips":["在纳奎河上租船，从下往上仰望山口——景色壮观无比。","请缓慢谨慎驾驶，尤其是雨天。"],"bestTime":"9至11月，天气干爽、少雾","visitDuration":"2至3小时","ticket":"免费","openingHours":"全天","galleryCaptions":["横贯山崖的幸福之路","翡翠般碧绿的纳奎河","徒山峡谷"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dong-van-old-town', 'dong-van-old-town', 'ha-giang', 'Phố cổ Đồng Văn', 'Dong Van Old Town', 'village', 105.3633, 23.2783, 'Khu phố cổ trăm tuổi giữa lòng cao nguyên đá, nơi nhịp sống vùng cao chậm rãi và ấm áp.', 'Khi màn đêm buông xuống, những ngôi nhà trình tường mái ngói âm dương ở Đồng Văn lên đèn lồng đỏ. Quán cà phê phố cổ tỏa hương, người Mông, người Tày, người Hoa ngồi bên nhau. Phiên chợ cuối tuần là cả một thế giới sắc màu — váy áo thổ cẩm, tiếng khèn, và những nụ cười hồn hậu của người vùng cao.', '["Khu phố cổ hình thành từ đầu thế kỷ 20.","Kiến trúc pha trộn giữa người Mông, Tày và Hoa.","Chợ phiên Đồng Văn họp vào Chủ nhật hằng tuần."]', '["Ở lại một đêm để cảm nhận phố cổ lên đèn.","Thử thắng cố và rượu ngô của người Mông."]', 'Cuối tuần để kịp phiên chợ', 'Nửa ngày', '', 'Cả ngày', '["hidden-gem"]', '["village","culture","food"]', '[{"seed":"dongvan-1","caption":"Phố cổ lên đèn lồng","ratio":"16/9"},{"seed":"dongvan-2","caption":"Phiên chợ vùng cao","ratio":"4/3"}]', '["ma-pi-leng-pass","lung-cu-flag-tower"]', 0, '{"en":{"name":"Dong Van Old Town","summary":"A century-old old town in the heart of the rocky plateau, where highland life moves slowly and warmly.","story":"When night falls, the rammed-earth houses with their yin-yang tiled roofs in Dong Van light up with red lanterns. The old-town cafés fill the air with aroma as Hmong, Tay and Hoa people sit side by side. The weekend market is a whole world of colour — brocade dresses, the sound of the khen pipe, and the warm smiles of the highland people.","facts":["The old town took shape in the early 20th century.","Its architecture blends Hmong, Tay and Hoa influences.","The Dong Van market is held every Sunday."],"travelTips":["Stay overnight to experience the old town lit by lanterns.","Try thang co stew and the Hmong people''s corn wine."],"bestTime":"Weekends to catch the market day","visitDuration":"Half a day","ticket":"Free","openingHours":"All day","galleryCaptions":["The old town aglow with lanterns","A highland market day"]},"ko":{"name":"동반 구시가지","summary":"석회암 고원 한가운데 자리한 백 년 된 구시가지로, 고원의 삶이 느리고 따뜻하게 흐르는 곳.","story":"밤이 내리면 음양 기와지붕을 얹은 동반의 흙다짐집들이 붉은 등불을 밝힙니다. 구시가지의 카페에서는 향이 퍼지고, 몽족, 따이족, 화족이 나란히 앉습니다. 주말 장날은 색채의 세계 그 자체입니다. 자수 의상, 켄(피리) 소리, 그리고 고원 사람들의 순박한 미소가 가득합니다.","facts":["구시가지는 20세기 초에 형성되었습니다.","건축 양식은 몽족, 따이족, 화족이 어우러져 있습니다.","동반 장날은 매주 일요일에 열립니다."],"travelTips":["하룻밤 묵으며 등불을 밝힌 구시가지를 느껴보세요.","탕꼬 탕과 몽족의 옥수수 술을 맛보세요."],"bestTime":"장날에 맞춘 주말","visitDuration":"반나절","ticket":"무료","openingHours":"종일","galleryCaptions":["등불을 밝힌 구시가지","고원의 장날"]},"ja":{"name":"ドンヴァン旧市街","summary":"石灰岩高原の中心にある百年の歴史を持つ旧市街。高原の暮らしがゆったりと温かく流れる場所。","story":"夜が訪れると、陰陽瓦の屋根を載せたドンヴァンの版築の家々に赤い提灯が灯ります。旧市街のカフェからは香りが漂い、モン族、ターイ族、ホア族が肩を並べて座ります。週末の市は色彩の世界そのもの。刺繍の衣装、ケン(笛)の音、そして高原の人々の素朴な笑顔があふれます。","facts":["旧市街は20世紀初頭に形成されました。","建築はモン族、ターイ族、ホア族が融合しています。","ドンヴァンの市は毎週日曜日に開かれます。"],"travelTips":["一泊して、提灯の灯る旧市街を感じてみましょう。","タンコー鍋とモン族のトウモロコシ酒を味わいましょう。"],"bestTime":"市の日に合わせた週末","visitDuration":"半日","ticket":"無料","openingHours":"終日","galleryCaptions":["提灯の灯る旧市街","高原の市の日"]},"zh":{"name":"同文古镇","summary":"岩石高原中心一座百年古镇，高原生活在此缓慢而温暖地流淌。","story":"夜幕降临时，同文那些覆着阴阳瓦的夯土房点亮了红灯笼。古镇的咖啡馆飘出香气，苗族、岱依族、华族人比邻而坐。周末的集市是一个色彩斑斓的世界——锦绣服饰、笙声悠扬，以及高原人淳朴的笑容。","facts":["古镇形成于20世纪初。","建筑融合了苗族、岱依族与华族的风格。","同文集市每周日开市。"],"travelTips":["在此留宿一晚，感受灯笼点亮的古镇。","品尝苗族的「胜火」炖菜和玉米酒。"],"bestTime":"赶上集市的周末","visitDuration":"半天","ticket":"免费","openingHours":"全天","galleryCaptions":["点亮灯笼的古镇","高原集市"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('sa-pa-town', 'sa-pa-town', 'lao-cai', 'Sa Pa', 'Sa Pa', 'mountain', 103.8438, 22.3361, 'Thị trấn trong mây, nơi ruộng bậc thang trải dài và những bản làng người Mông, Dao ẩn hiện trong sương.', 'Sa Pa đón bạn bằng một làn sương mỏng và cái se lạnh dễ chịu. Buổi sáng, mây luồn qua những thung lũng ruộng bậc thang vàng óng. Người phụ nữ Mông gùi rau xuống chợ, trẻ con má hồng cười giòn tan. Khi hoàng hôn nhuộm tím dãy Hoàng Liên Sơn, Sa Pa trở nên yên bình đến nao lòng.', '["Sa Pa nằm ở độ cao khoảng 1.500–1.650m.","Là cửa ngõ chinh phục Fansipan — ''nóc nhà Đông Dương'' cao 3.143m.","Ruộng bậc thang Sa Pa từng được tạp chí du lịch quốc tế bình chọn đẹp nhất thế giới."]', '["Mùa lúa chín (tháng 9) là thời điểm ruộng bậc thang đẹp nhất.","Đi cáp treo hoặc leo bộ lên Fansipan tùy sức khỏe."]', 'Tháng 9 (lúa chín) hoặc tháng 3–5 (trời trong)', '2 ngày', '', 'Cả ngày', '["popular","verified"]', '["mountain","culture","photography"]', '[{"seed":"sapa-1","caption":"Ruộng bậc thang mùa lúa chín","ratio":"16/9"},{"seed":"sapa-2","caption":"Sương sớm trên thung lũng Mường Hoa","ratio":"4/3"},{"seed":"sapa-3","caption":"Đỉnh Fansipan trong mây","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Sa Pa","summary":"A town in the clouds, where terraced fields stretch on and Hmong and Dao villages appear and vanish in the mist.","story":"Sa Pa greets you with a thin veil of mist and a pleasant chill. In the morning, clouds drift through valleys of golden terraced fields. Hmong women carry vegetables down to market, rosy-cheeked children laugh brightly. When sunset bathes the Hoang Lien Son range in purple, Sa Pa becomes achingly peaceful.","facts":["Sa Pa lies at an altitude of about 1,500–1,650m.","It is the gateway to conquering Fansipan — the ''Roof of Indochina'' at 3,143m.","Sa Pa''s terraced fields have been voted among the most beautiful in the world by international travel magazines."],"travelTips":["The ripe rice season (September) is when the terraced fields are at their most beautiful.","Take the cable car or hike up Fansipan depending on your fitness."],"bestTime":"September (ripe rice) or March–May (clear skies)","visitDuration":"2 days","ticket":"Free","openingHours":"All day","galleryCaptions":["Terraced fields in the ripe rice season","Morning mist over the Muong Hoa Valley","Fansipan peak in the clouds"]},"ko":{"name":"사파","summary":"구름 속의 마을로, 계단식 논이 끝없이 펼쳐지고 몽족과 자오족 마을이 안개 속에 나타났다 사라지는 곳.","story":"사파는 얇은 안개와 기분 좋은 서늘함으로 당신을 맞이합니다. 아침이면 구름이 황금빛 계단식 논의 골짜기 사이로 흘러듭니다. 몽족 여인들은 채소를 지고 장으로 내려가고, 볼이 발그레한 아이들은 맑게 웃습니다. 노을이 호앙리엔선 산맥을 보랏빛으로 물들이면 사파는 가슴 시리도록 평온해집니다.","facts":["사파는 해발 약 1,500~1,650m에 위치합니다.","''인도차이나의 지붕''인 해발 3,143m 판시판 등정의 관문입니다.","사파의 계단식 논은 국제 여행 잡지에서 세계 최고로 선정된 바 있습니다."],"travelTips":["벼가 익는 시기(9월)가 계단식 논이 가장 아름다운 때입니다.","체력에 따라 케이블카를 타거나 판시판을 걸어 오르세요."],"bestTime":"9월(벼 익음) 또는 3~5월(맑은 하늘)","visitDuration":"2일","ticket":"무료","openingHours":"종일","galleryCaptions":["벼가 익는 시기의 계단식 논","므엉호아 골짜기의 아침 안개","구름 속 판시판 봉우리"]},"ja":{"name":"サパ","summary":"雲の中の町。棚田が果てしなく広がり、モン族やザオ族の村が霧の中に現れては消える場所。","story":"サパは薄い霧と心地よい肌寒さで迎えてくれます。朝、雲が黄金色の棚田の谷間を流れていきます。モン族の女性が野菜を背負って市へ下り、頬を赤らめた子供たちが屈託なく笑います。夕陽がホアンリエンソン山脈を紫に染めると、サパは胸が締めつけられるほど穏やかになります。","facts":["サパは標高約1,500〜1,650メートルに位置します。","「インドシナの屋根」標高3,143メートルのファンシーパン征服の玄関口です。","サパの棚田は国際旅行誌で世界一美しいと選ばれたことがあります。"],"travelTips":["稲が実る時期(9月)が棚田の最も美しい時です。","体力に応じてケーブルカーで、または徒歩でファンシーパンに登りましょう。"],"bestTime":"9月(稲の実り)または3〜5月(晴天)","visitDuration":"2日","ticket":"無料","openingHours":"終日","galleryCaptions":["稲の実る季節の棚田","ムオンホア谷の朝霧","雲の中のファンシーパン山頂"]},"zh":{"name":"沙巴","summary":"云中小镇，梯田绵延无际，苗族、瑶族村寨在薄雾中若隐若现。","story":"沙巴以一层薄雾和宜人的微凉迎接你。清晨，云雾在金黄梯田的山谷间流转。苗族妇女背着蔬菜下山赶集，脸颊红润的孩童笑声清脆。当夕阳将黄连山脉染成紫色，沙巴便宁静得令人心醉。","facts":["沙巴位于海拔约1500至1650米处。","是征服番西邦峰的门户——这座「印度支那屋脊」高3143米。","沙巴梯田曾被国际旅游杂志评为世界最美。"],"travelTips":["稻谷成熟季（9月）是梯田最美的时节。","可视体力选择乘缆车或徒步登番西邦峰。"],"bestTime":"9月（稻谷成熟）或3至5月（天空晴朗）","visitDuration":"2天","ticket":"免费","openingHours":"全天","galleryCaptions":["稻谷成熟季的梯田","孟华谷的清晨薄雾","云中的番西邦峰"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ha-long-bay', 'ha-long-bay', 'quang-ninh', 'Vịnh Hạ Long', 'Ha Long Bay', 'unesco', 107, 20.9101, 'Kỳ quan thiên nhiên thế giới với hàng nghìn hòn đảo đá vôi nhô lên giữa làn nước xanh ngọc bích.', 'Truyền thuyết kể rằng Rồng Mẹ đã hạ xuống vùng biển này, nhả ra những viên ngọc hóa thành nghìn hòn đảo che chắn cho người dân. Hôm nay, khi con thuyền lướt nhẹ qua những khối đá vôi phủ rêu, len lỏi vào hang động kỳ ảo, bạn sẽ hiểu vì sao Hạ Long là niềm tự hào của Việt Nam. Bình minh trên vịnh, mặt nước phẳng lặng như gương, là khoảnh khắc khó quên.', '["Được UNESCO công nhận là Di sản thiên nhiên thế giới năm 1994.","Vịnh có khoảng 1.600 hòn đảo lớn nhỏ.","''Hạ Long'' nghĩa là ''rồng hạ xuống''."]', '["Ngủ đêm trên du thuyền để ngắm bình minh và hoàng hôn trên vịnh.","Chèo kayak vào các hang để khám phá những bãi tắm ẩn."]', 'Tháng 10–12, biển êm và trời trong', '1–2 ngày', '290.000đ', 'Cả ngày', '["unesco","popular","verified"]', '["beach","nature","photography"]', '[{"seed":"halong-1","caption":"Bình minh trên vịnh","ratio":"16/9"},{"seed":"halong-2","caption":"Thuyền giữa rừng đảo đá vôi","ratio":"4/3"},{"seed":"halong-3","caption":"Hang Sửng Sốt","ratio":"1/1"},{"seed":"halong-4","caption":"Làng chài trên vịnh","ratio":"4/3"}]', '[]', 1, '{"en":{"name":"Ha Long Bay","summary":"A natural wonder of the world, with thousands of limestone islands rising from emerald waters.","story":"Legend says that a Mother Dragon descended upon these waters, spitting out pearls that turned into a thousand islands to shield the people. Today, as your boat glides past moss-covered limestone formations and threads into magical caves, you will understand why Ha Long is Vietnam''s pride. Dawn over the bay, the water as still as a mirror, is an unforgettable moment.","facts":["Recognised by UNESCO as a World Natural Heritage Site in 1994.","The bay has around 1,600 islands large and small.","''Ha Long'' means ''descending dragon''."],"travelTips":["Stay overnight on a cruise to watch the sunrise and sunset over the bay.","Kayak into the caves to discover hidden beaches."],"bestTime":"October–December, calm seas and clear skies","visitDuration":"1–2 days","ticket":"290,000 VND","openingHours":"All day","galleryCaptions":["Dawn over the bay","A boat amid a forest of limestone islands","Sung Sot Cave","A fishing village on the bay"]},"ko":{"name":"하롱베이","summary":"에메랄드빛 바다 위로 수천 개의 석회암 섬이 솟아오른 세계 자연유산.","story":"전설에 따르면 어미 용이 이 바다에 내려와 진주를 뿜어냈고, 그것이 천 개의 섬이 되어 백성을 지켰다고 합니다. 오늘날 이끼 덮인 석회암 봉우리를 지나 신비로운 동굴 속으로 배가 미끄러져 들어가면, 왜 하롱베이가 베트남의 자랑인지 이해하게 됩니다. 거울처럼 잔잔한 수면 위로 떠오르는 만의 일출은 잊을 수 없는 순간입니다.","facts":["1994년 유네스코 세계자연유산으로 등재되었습니다.","만에는 크고 작은 약 1,600개의 섬이 있습니다.","''하롱''은 ''내려오는 용''을 뜻합니다."],"travelTips":["크루즈에서 하룻밤 묵으며 만의 일출과 일몰을 감상하세요.","카약을 타고 동굴로 들어가 숨겨진 해변을 찾아보세요."],"bestTime":"10~12월, 바다가 잔잔하고 하늘이 맑은 시기","visitDuration":"1~2일","ticket":"290,000동","openingHours":"종일","galleryCaptions":["만의 일출","석회암 섬의 숲 사이를 지나는 배","숭솟 동굴","만 위의 어촌 마을"]},"ja":{"name":"ハロン湾","summary":"エメラルド色の海に数千の石灰岩の島々がそびえ立つ、世界自然遺産。","story":"伝説によれば、母なる龍がこの海に降り立ち、吐き出した真珠が千の島となって人々を守ったといいます。今日、苔むした石灰岩の岩々を抜け、神秘的な洞窟へと船が滑り込むと、なぜハロン湾がベトナムの誇りなのかが分かります。鏡のように静まった水面に昇る湾の夜明けは、忘れがたい瞬間です。","facts":["1994年にユネスコ世界自然遺産に登録されました。","湾には大小約1,600の島々があります。","「ハロン」は「降りる龍」を意味します。"],"travelTips":["クルーズで一泊し、湾の日の出と日没を眺めましょう。","カヤックで洞窟に入り、隠れたビーチを探しましょう。"],"bestTime":"10〜12月、海が穏やかで空が澄む時期","visitDuration":"1〜2日","ticket":"290,000ドン","openingHours":"終日","galleryCaptions":["湾の夜明け","石灰岩の島々の森を進む船","スンソット洞窟","湾に浮かぶ漁村"]},"zh":{"name":"下龙湾","summary":"世界自然遗产，数千座石灰岩岛屿从碧绿如玉的海水中拔地而起。","story":"传说母龙降临这片海域，吐出珍珠化作千座岛屿，护佑百姓。如今，当小船轻掠过覆满青苔的石灰岩，穿入奇幻的洞窟，你便会明白下龙湾何以是越南的骄傲。湾上的日出，水面平静如镜，是难以忘怀的一刻。","facts":["1994年被联合国教科文组织列为世界自然遗产。","湾内有约1600座大小岛屿。","「下龙」意为「降龙」。"],"travelTips":["在游船上留宿一晚，欣赏湾上的日出与日落。","划皮划艇进入洞窟，探寻隐秘的海滩。"],"bestTime":"10至12月，海面平静、天空晴朗","visitDuration":"1至2天","ticket":"290,000越南盾","openingHours":"全天","galleryCaptions":["湾上的日出","穿行于石灰岩岛屿之林的船只","惊讶洞","湾上的渔村"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('trang-an', 'trang-an', 'ninh-binh', 'Tràng An', 'Trang An', 'unesco', 105.9167, 20.25, '‘Vịnh Hạ Long trên cạn’ — những dòng sông uốn lượn qua núi đá vôi và hang động huyền bí.', 'Ngồi trên chiếc thuyền nan, người lái đò khẽ khua mái chèo đưa bạn trôi giữa khung cảnh như tranh thủy mặc. Thuyền luồn qua những hang động tối, nơi thạch nhũ rủ xuống chạm mặt nước, rồi bất ngờ mở ra một thung lũng xanh mướt. Tiếng chim, tiếng nước, và sự tĩnh lặng tuyệt đối khiến Tràng An trở thành chốn bình yên hiếm có.', '["Di sản hỗn hợp văn hóa và thiên nhiên thế giới được UNESCO công nhận năm 2014.","Có hơn 30 hang động xuyên thủy.","Từng là kinh đô Hoa Lư của nước Đại Cồ Việt thế kỷ 10."]', '["Mỗi tuyến đò kéo dài 2–3 giờ, hãy mang nón và nước.","Ghé Hang Múa leo 500 bậc để ngắm toàn cảnh từ trên cao."]', 'Tháng 1–3 hoặc mùa lúa chín tháng 5–6', 'Nửa ngày', '250.000đ', '07:00 – 17:00', '["unesco","verified"]', '["nature","history","photography"]', '[{"seed":"trangan-1","caption":"Thuyền nan giữa núi đá","ratio":"16/9"},{"seed":"trangan-2","caption":"Thuyền nhỏ lướt giữa hồ nước phẳng dưới chân núi đá","ratio":"4/3"},{"seed":"trangan-3","caption":"Toàn cảnh từ Hang Múa","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Trang An","summary":"The ''Ha Long Bay on land'' — winding rivers threading through limestone karsts and mysterious caves.","story":"Seated in a small sampan, the boatwoman gently dips her oar and glides you through a landscape straight out of an ink-wash painting. The boat slips through dark caves where stalactites hang down to brush the water''s surface, then suddenly opens onto a lush green valley. Birdsong, the sound of water, and an absolute stillness make Trang An a rare haven of peace.","facts":["A UNESCO mixed cultural and natural World Heritage Site, recognized in 2014.","Home to more than 30 water-filled caves you can boat through.","Once the site of Hoa Lu, capital of the Dai Co Viet kingdom in the 10th century."],"travelTips":["Each boat route lasts 2–3 hours, so bring a hat and water.","Stop at Mua Cave and climb 500 steps for a panoramic view from above."],"bestTime":"January–March, or the ripe-rice season in May–June","visitDuration":"Half a day","ticket":"250,000 VND","openingHours":"07:00 – 17:00","galleryCaptions":["A sampan amid the limestone mountains","A small boat skimming across a glassy lake beneath the karst peaks","Panorama from Mua Cave"]},"ko":{"name":"짱안","summary":"‘육지의 하롱베이’ — 석회암 산과 신비로운 동굴 사이를 굽이굽이 흐르는 강줄기.","story":"작은 대나무 배에 올라타면 뱃사공이 노를 가볍게 저으며 한 폭의 수묵화 같은 풍경 속으로 당신을 데려갑니다. 배는 종유석이 수면에 닿을 듯 드리워진 어두운 동굴 사이를 빠져나가, 어느새 푸르른 계곡을 눈앞에 펼쳐 보입니다. 새소리와 물소리, 그리고 완전한 고요함이 어우러져 짱안은 보기 드문 평화의 안식처가 됩니다.","facts":["2014년 유네스코가 인정한 세계 복합 유산(문화·자연).","물길로 통하는 동굴이 30개 넘게 있습니다.","10세기 다이꼬비엣의 수도였던 호아르가 있던 곳입니다."],"travelTips":["각 뱃길 코스는 2~3시간 걸리므로 모자와 물을 챙기세요.","항무아에 들러 500개의 계단을 올라 높은 곳에서 전경을 감상하세요."],"bestTime":"1~3월 또는 벼가 익는 5~6월","visitDuration":"반나절","ticket":"250,000동","openingHours":"07:00 – 17:00","galleryCaptions":["석회암 산 사이의 대나무 배","석회암 산기슭, 잔잔한 호수 위를 미끄러지는 작은 배","항무아에서 바라본 전경"]},"ja":{"name":"チャンアン","summary":"「陸のハロン湾」——石灰岩の山々と神秘的な洞窟の間を縫って流れる、うねる川。","story":"小舟に揺られ、船頭が静かに櫂をひと漕ぎするたび、水墨画のような景色の中を滑るように進んでいきます。舟は暗い洞窟をくぐり抜け、鍾乳石が水面すれすれまで垂れ下がるかと思えば、突如として緑あふれる谷が開けます。鳥のさえずり、水の音、そして完全なる静寂が、チャンアンを稀有な安らぎの地にしています。","facts":["2014年にユネスコの複合遺産（文化・自然）として登録されました。","舟で通り抜けられる水中洞窟が30以上あります。","10世紀には大瞿越国の都ホアルーが置かれていました。"],"travelTips":["各舟ルートは2〜3時間ほどかかるので、帽子と水を持参しましょう。","ハンムア（ムア洞窟）に立ち寄り、500段の階段を上って眼下の全景を楽しみましょう。"],"bestTime":"1〜3月、または稲穂が実る5〜6月","visitDuration":"半日","ticket":"250,000ドン","openingHours":"07:00 – 17:00","galleryCaptions":["石山の間を行く小舟","石山の麓、鏡のような湖面を滑る小舟","ハンムアからの全景"]},"zh":{"name":"长安","summary":"陆上下龙湾\"——蜿蜒的河流穿行于石灰岩山峰与神秘的洞穴之间。","story":"坐在小竹篷船上，船夫轻轻划动船桨，载着你漂行在宛如水墨画的风景之中。船只穿过幽暗的溶洞，钟乳石垂落到几乎触及水面，转眼又豁然开朗，眼前展开一片郁郁葱葱的山谷。鸟鸣声、流水声以及那份绝对的宁静，让长安成为一处难得的安详之地。","facts":["于2014年被联合国教科文组织列入世界文化与自然双重遗产。","拥有超过30个穿水溶洞。","曾是10世纪大瞿越国的都城华闾。"],"travelTips":["每条游船线路约2至3小时，请带好遮阳帽和饮用水。","可前往卧龙山攀登500级台阶，从高处俯瞰全景。"],"bestTime":"1月至3月，或5月至6月稻谷成熟时节","visitDuration":"半天","ticket":"250,000越南盾","openingHours":"07:00 – 17:00","galleryCaptions":["竹篷船穿行于石山之间","小船在石山脚下平静的湖面上轻轻滑行","从卧龙山俯瞰全景"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hoan-kiem-lake', 'hoan-kiem-lake', 'ha-noi', 'Hồ Hoàn Kiếm', 'Hoan Kiem Lake', 'lake', 105.8525, 21.0287, 'Trái tim của Hà Nội ngàn năm, nơi Tháp Rùa soi bóng và truyền thuyết trả gươm còn vang vọng.', 'Sáng sớm, người Hà Nội tập thể dục quanh hồ, hàng liễu rủ soi bóng nước. Cầu Thê Húc đỏ rực dẫn vào đền Ngọc Sơn. Tương truyền vua Lê Lợi đã trả lại thanh gươm thần cho Rùa Vàng ở chính hồ này — vì thế hồ mang tên ''Hoàn Kiếm'', nghĩa là trả gươm. Tối cuối tuần, phố quanh hồ thành phố đi bộ, rộn ràng tiếng cười và âm nhạc.', '["Tên cũ là hồ Lục Thủy vì nước có màu xanh quanh năm.","Cầu Thê Húc nghĩa là ''nơi đậu ánh sáng ban mai''.","Đền Ngọc Sơn thờ Hưng Đạo Đại Vương Trần Quốc Tuấn."]', '["Đi dạo phố đi bộ vào tối thứ Sáu đến Chủ nhật.","Thử cà phê trứng và kem Tràng Tiền gần hồ."]', 'Mùa thu (tháng 9–11), tiết trời mát dịu', '1–2 giờ', '', 'Cả ngày', '["popular","verified"]', '["history","culture","city"]', '[{"seed":"hoankiem-1","caption":"Tháp Rùa giữa hồ","ratio":"16/9"},{"seed":"hoankiem-2","caption":"Chàng trai lặng ngồi ngắm mặt hồ bên gốc cây","ratio":"4/3"},{"seed":"hoankiem-3","caption":"Cành cây trơ lá in bóng trên mặt hồ mờ sương","ratio":"1/1"}]', '["old-quarter-hanoi"]', 1, '{"en":{"name":"Hoan Kiem Lake","summary":"The heart of thousand-year-old Hanoi, where the Turtle Tower casts its reflection and the legend of the returned sword still echoes.","story":"In the early morning, Hanoians exercise around the lake while rows of weeping willows mirror themselves in the water. The bright red The Huc Bridge leads to Ngoc Son Temple. Legend says King Le Loi returned a magic sword to the Golden Turtle in this very lake — which is why it is named ''Hoan Kiem'', meaning ''the returned sword''. On weekend evenings, the streets around the lake become a pedestrian zone, alive with laughter and music.","facts":["Its old name was Luc Thuy (''Green Water'') Lake, for the water that stays green year-round.","The Huc Bridge means ''where the morning sunlight alights''.","Ngoc Son Temple is dedicated to the great general Tran Hung Dao."],"travelTips":["Stroll the pedestrian streets from Friday to Sunday evening.","Try egg coffee and Trang Tien ice cream near the lake."],"bestTime":"Autumn (September–November), when the weather is cool and mild","visitDuration":"1–2 hours","ticket":"","openingHours":"All day","galleryCaptions":["The Turtle Tower in the middle of the lake","A young man sitting quietly by a tree trunk, gazing out over the water","Bare branches reflected on the mist-veiled surface of the lake"]},"ko":{"name":"호안끼엠 호수","summary":"천년 하노이의 심장, 거북 탑이 물에 비치고 검을 돌려준 전설이 여전히 메아리치는 곳.","story":"이른 아침이면 하노이 사람들은 호수를 따라 운동을 하고, 늘어진 버드나무가 수면에 그림자를 드리웁니다. 붉게 빛나는 테훅 다리는 응옥선 사당으로 이어집니다. 전설에 따르면 레러이 왕이 바로 이 호수에서 황금 거북에게 신검을 돌려주었다고 하여, 호수는 ‘검을 돌려주다’라는 뜻의 ‘호안끼엠’이라는 이름을 갖게 되었습니다. 주말 저녁이면 호수 주변 거리는 보행자 거리로 변해 웃음소리와 음악으로 활기가 넘칩니다.","facts":["옛 이름은 ‘룩투이 호수’로, 물빛이 일 년 내내 푸르렀기 때문입니다.","테훅 다리는 ‘아침 햇살이 머무는 곳’이라는 뜻입니다.","응옥선 사당은 흥다오 대왕 쩐꾸옥뚜언을 모십니다."],"travelTips":["금요일부터 일요일 저녁에 보행자 거리를 산책해 보세요.","호수 근처에서 에그 커피와 짱띠엔 아이스크림을 맛보세요."],"bestTime":"가을(9~11월), 선선한 날씨","visitDuration":"1~2시간","ticket":"","openingHours":"종일","galleryCaptions":["호수 가운데의 거북 탑","나무 그루터기 옆에서 조용히 앉아 호수를 바라보는 청년","안개 자욱한 수면에 비친 앙상한 나뭇가지"]},"ja":{"name":"ホアンキエム湖","summary":"千年の都ハノイの中心。亀の塔が水面に影を落とし、剣を返す伝説が今なお響く場所。","story":"早朝、ハノイの人々は湖のほとりで体操をし、しだれ柳が水面に影を映します。鮮やかな朱色のテーフック橋がゴクソン祠へと続いています。伝説によれば、レ・ロイ王はまさにこの湖で金色の亀に神剣を返したといいます——それゆえこの湖は「剣を返す」を意味する「ホアンキエム（還剣）」と呼ばれるのです。週末の夜には湖畔の通りが歩行者天国となり、笑い声と音楽でにぎわいます。","facts":["水が一年中緑色を帯びていたことから、かつてはルクトゥイ（緑水）湖と呼ばれていました。","テーフック橋は「朝の光が宿る場所」という意味です。","ゴクソン祠には興道大王チャン・クオック・トゥアンが祀られています。"],"travelTips":["金曜から日曜の夜は歩行者天国を散策しましょう。","湖の近くでエッグコーヒーやチャンティエンのアイスクリームを味わってみましょう。"],"bestTime":"秋（9〜11月）、涼やかで心地よい気候","visitDuration":"1〜2時間","ticket":"","openingHours":"終日","galleryCaptions":["湖の中央に佇む亀の塔","木の根もとで静かに湖面を眺める青年","霧にかすむ湖面に映る、葉を落とした枝"]},"zh":{"name":"还剑湖","summary":"千年河内的心脏，龟塔倒映水中，还剑的传说至今回响。","story":"清晨，河内人沿湖锻炼身体，垂柳依依，倒映水面。鲜红的栖旭桥通向玉山祠。相传黎利皇帝正是在这座湖里将神剑归还给金龟，因此湖得名「还剑」，意为归还宝剑。周末的夜晚，环湖街道变成步行街，到处洋溢着欢声笑语与音乐。","facts":["旧称绿水湖，因湖水常年呈碧绿色。","栖旭桥意为「栖息晨光之处」。","玉山祠供奉兴道大王陈国峻。"],"travelTips":["周五至周日的夜晚来此漫步步行街。","在湖边品尝鸡蛋咖啡和长前冰淇淋。"],"bestTime":"秋季（9月至11月），天气凉爽宜人","visitDuration":"1至2小时","ticket":"","openingHours":"全天","galleryCaptions":["湖中央的龟塔","青年静坐树下凝望湖面","光秃的枝条倒映在薄雾笼罩的湖面上"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('old-quarter-hanoi', 'old-quarter-hanoi', 'ha-noi', 'Phố cổ Hà Nội', 'Hanoi Old Quarter', 'city', 105.8497, 21.0333, 'Mê cung 36 phố phường, nơi mỗi con phố từng mang tên một nghề thủ công truyền thống.', 'Lạc vào phố cổ là lạc vào một Hà Nội của những thế kỷ trước. Hàng Bạc, Hàng Mã, Hàng Gai — mỗi cái tên kể một câu chuyện nghề. Mùi phở thơm lừng buổi sáng, tiếng rao hàng, những ngôi nhà ống mái rêu phong. Ngồi vỉa hè nhâm nhi cốc bia hơi, bạn sẽ thấy nhịp sống Hà Nội vừa hối hả vừa thong dong.', '["Khu phố cổ có 36 phố nghề hình thành từ thế kỷ 15.","Mỗi phố ''Hàng'' từng chuyên bán một mặt hàng riêng.","Phở, bún chả và cà phê trứng đều là đặc sản nơi đây."]', '["Khám phá bằng xích lô hoặc đi bộ.","Thử bún chả trưa và phở sáng."]', 'Mùa thu Hà Nội', 'Nửa ngày', '', 'Cả ngày', '["popular"]', '["city","food","culture"]', '[{"seed":"oldquarter-1","caption":"Phố nghề truyền thống","ratio":"16/9"},{"seed":"oldquarter-2","caption":"Gánh hàng rong","ratio":"4/3"}]', '["hoan-kiem-lake"]', 0, '{"en":{"name":"Hanoi Old Quarter","summary":"A labyrinth of 36 streets, where each lane once bore the name of a traditional handicraft.","story":"To get lost in the Old Quarter is to get lost in a Hanoi of centuries past. Hang Bac, Hang Ma, Hang Gai — each name tells the story of a trade. The fragrant aroma of pho in the morning, the calls of street vendors, the tube houses with their moss-covered roofs. Sitting on the sidewalk nursing a glass of fresh draft beer, you''ll sense the rhythm of Hanoi life — at once hurried and unhurried.","facts":["The Old Quarter''s 36 trade streets took shape from the 15th century.","Each ''Hang'' street once specialized in selling a single kind of goods.","Pho, bun cha, and egg coffee are all local specialties here."],"travelTips":["Explore by cyclo or on foot.","Try bun cha for lunch and pho for breakfast."],"bestTime":"Hanoi autumn","visitDuration":"Half a day","ticket":"","openingHours":"All day","galleryCaptions":["Traditional trade streets","A street vendor''s carrying pole"]},"ko":{"name":"하노이 구시가지","summary":"36개 거리의 미로, 각 거리마다 한때 전통 수공예 직종의 이름을 따 붙였던 곳.","story":"구시가지로 들어서는 것은 지난 세기의 하노이로 빠져드는 일입니다. 항박, 항마, 항자이 — 거리 하나하나의 이름이 직업의 이야기를 들려줍니다. 아침이면 향긋한 쌀국수 냄새, 행상의 외침, 이끼 낀 지붕의 좁고 긴 집들. 길가에 앉아 비아 허이 한 잔을 음미하다 보면, 분주하면서도 여유로운 하노이의 삶의 리듬을 느끼게 됩니다.","facts":["구시가지의 36개 직업 거리는 15세기부터 형성되었습니다.","‘항’이 붙은 각 거리는 한때 저마다 특정 물품을 전문으로 팔았습니다.","퍼, 분짜, 에그 커피 모두 이곳의 명물입니다."],"travelTips":["씨클로를 타거나 걸어서 둘러보세요.","점심에는 분짜, 아침에는 퍼를 맛보세요."],"bestTime":"하노이의 가을","visitDuration":"반나절","ticket":"","openingHours":"종일","galleryCaptions":["전통 직업 거리","행상의 멜대 짐"]},"ja":{"name":"ハノイ旧市街","summary":"36の通りからなる迷宮。かつてそれぞれの通りが伝統工芸の職人街の名を冠していました。","story":"旧市街に迷い込むことは、幾世紀も前のハノイに迷い込むこと。ハンバック、ハンマー、ハンザイ——それぞれの名がひとつの職人の物語を語っています。朝の香しいフォーの匂い、物売りの呼び声、苔むした瓦屋根のうなぎの寝床のような家々。歩道に腰かけて生ビールを一杯味わえば、せわしなくも悠然としたハノイの暮らしのリズムが感じられるでしょう。","facts":["旧市街は15世紀に形成された36の職人通りからなります。","「ハン（行）」のつく各通りは、かつてそれぞれ特定の品を専門に商っていました。","フォー、ブンチャー、エッグコーヒーはいずれもこの地の名物です。"],"travelTips":["シクロや徒歩で巡るのがおすすめです。","昼はブンチャー、朝はフォーを味わってみましょう。"],"bestTime":"ハノイの秋","visitDuration":"半日","ticket":"","openingHours":"終日","galleryCaptions":["伝統の職人通り","天秤棒を担ぐ物売り"]},"zh":{"name":"河内古街","summary":"三十六行街的迷宫，每一条街曾以一门传统手工艺命名。","story":"走进古街，便是走进了几个世纪前的河内。行银街、行马街、行麻街——每一个名字都讲述着一门手艺的故事。清晨米粉的浓香、沿街的叫卖声、长满青苔的筒子楼。坐在街边小凳上呷一杯鲜啤，你会感受到河内生活既匆忙又悠然的独特节奏。","facts":["古街区拥有自15世纪形成的三十六行街。","每一条「行」街曾专卖一种特定商品。","米粉、烤肉米线和鸡蛋咖啡都是这里的特色美食。"],"travelTips":["乘坐三轮车或步行游览。","中午品尝烤肉米线，早晨享用米粉。"],"bestTime":"河内的秋季","visitDuration":"半天","ticket":"","openingHours":"全天","galleryCaptions":["传统手工艺街","街头挑担小贩"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hue-imperial-city', 'hue-imperial-city', 'thua-thien-hue', 'Đại Nội Huế', 'Hue Imperial City', 'unesco', 107.5776, 16.4698, 'Kinh thành của 13 đời vua Nguyễn, trầm mặc và cổ kính bên dòng sông Hương thơ mộng.', 'Bước qua Ngọ Môn, bạn lùi về một thời vàng son của triều Nguyễn. Những điện rồng, sân chầu, tường thành rêu phong kể câu chuyện của một vương triều. Chiều Huế buông xuống chậm rãi, tiếng chuông chùa Thiên Mụ vọng qua sông Hương, một điệu Nam ai man mác. Huế không ồn ào — Huế khiến lòng người lắng lại.', '["Quần thể di tích Cố đô Huế được UNESCO công nhận năm 1993.","Là kinh đô Việt Nam thời nhà Nguyễn (1802–1945).","Kinh thành được xây theo nguyên tắc phong thủy với sông Hương làm minh đường."]', '["Đi thuyền rồng nghe ca Huế trên sông Hương buổi tối.","Thử các món cung đình: bún bò Huế, bánh bèo, chè Huế."]', 'Tháng 1–4, tránh mùa mưa cuối năm', 'Nửa ngày', '200.000đ', '07:00 – 17:30', '["unesco","verified"]', '["history","culture","temple"]', '[{"seed":"hue-1","caption":"Ngọ Môn uy nghi","ratio":"16/9"},{"seed":"hue-2","caption":"Ngọ Môn cổ kính nhìn từ lối vào lát đá","ratio":"4/3"},{"seed":"hue-3","caption":"Sông Hương chiều buông","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Hue Imperial City","summary":"The citadel of 13 Nguyen emperors, serene and ancient beside the poetic Perfume River.","story":"Stepping through Ngo Mon Gate, you slip back into the golden age of the Nguyen Dynasty. Dragon palaces, ceremonial courtyards and moss-covered ramparts tell the story of a royal house. Evening falls slowly over Hue, the bell of Thien Mu Pagoda echoing across the Perfume River alongside a wistful Nam Ai melody. Hue is never loud — Hue lets the heart grow still.","facts":["The Complex of Hue Monuments was recognized by UNESCO in 1993.","It was the capital of Vietnam during the Nguyen Dynasty (1802–1945).","The citadel was built according to feng shui principles, with the Perfume River as its bright frontal feature."],"travelTips":["Take a dragon boat and listen to Hue royal music on the Perfume River in the evening.","Try the royal-court dishes: bun bo Hue, banh beo, and Hue sweet soups."],"bestTime":"January–April, avoiding the late-year rainy season","visitDuration":"Half a day","ticket":"200,000 VND","openingHours":"07:00 – 17:30","galleryCaptions":["The majestic Ngo Mon Gate","The ancient Ngo Mon Gate seen from the stone-paved entrance","Evening falling over the Perfume River"]},"ko":{"name":"후에 황궁(다이노이)","summary":"응우옌 왕조 13대 황제의 궁성으로, 시적인 흐엉강(향강) 곁에서 고요하고 고풍스럽게 자리합니다.","story":"응오몬(오문)을 지나면 응우옌 왕조의 황금기로 거슬러 올라갑니다. 용 무늬 전각과 조정 마당, 이끼 낀 성벽이 한 왕조의 이야기를 들려줍니다. 후에의 저녁은 천천히 내려앉고, 티엔무 사원의 종소리가 흐엉강을 건너 울려 퍼지며 애틋한 남아이 가락이 흐릅니다. 후에는 결코 시끄럽지 않습니다 — 후에는 마음을 차분하게 가라앉힙니다.","facts":["후에 기념물 복합지구는 1993년 유네스코 세계유산으로 등재되었습니다.","응우옌 왕조 시대(1802~1945) 베트남의 수도였습니다.","궁성은 흐엉강을 명당으로 삼아 풍수 원리에 따라 지어졌습니다."],"travelTips":["저녁에 용선을 타고 흐엉강 위에서 후에 궁중악을 감상해 보세요.","궁중 요리를 맛보세요: 분보후에, 반베오, 후에식 째."],"bestTime":"1~4월, 연말 우기는 피하세요","visitDuration":"반나절","ticket":"200,000동","openingHours":"07:00 – 17:30","galleryCaptions":["위엄 있는 응오몬","돌로 포장된 입구에서 바라본 고풍스러운 응오몬","흐엉강에 내려앉는 저녁"]},"ja":{"name":"フエ王宮（大内）","summary":"グエン朝13代の皇帝が住んだ王城。詩情あふれるフォン川（香江）のほとりに、静かで古色蒼然とたたずみます。","story":"午門をくぐると、グエン朝の黄金時代へとさかのぼります。龍の宮殿、謁見の庭、苔むした城壁が、ひとつの王朝の物語を語りかけます。フエの夕暮れはゆっくりと訪れ、ティエンムー寺の鐘の音がフォン川を越えて響き、もの悲しいナムアイの調べが流れます。フエは決して騒がしくありません——フエは心を静かに沈めてくれます。","facts":["フエの建造物群は1993年にユネスコ世界遺産に登録されました。","グエン朝時代（1802〜1945年）のベトナムの首都でした。","王城はフォン川を明堂とし、風水の原理に従って築かれました。"],"travelTips":["夜にドラゴンボートに乗り、フォン川の上でフエの宮廷音楽を楽しみましょう。","宮廷料理を味わいましょう：ブンボーフエ、バインベオ、フエのチェー。"],"bestTime":"1〜4月、年末の雨季は避けて","visitDuration":"半日","ticket":"200,000ドン","openingHours":"07:00 – 17:30","galleryCaptions":["威風堂々たる午門","石畳の入口から望む古色蒼然たる午門","フォン川に訪れる夕暮れ"]},"zh":{"name":"顺化皇城（大内）","summary":"阮朝十三代帝王的京城，在诗意盎然的香江畔静谧而古朴。","story":"穿过午门，你便回到阮朝的黄金岁月。龙殿、朝堂与爬满青苔的城墙，诉说着一个王朝的故事。顺化的黄昏缓缓降临，天姥寺的钟声越过香江回荡，一曲哀婉的南哀缠绵流淌。顺化从不喧嚣——顺化让人心沉静下来。","facts":["顺化古迹群于1993年被联合国教科文组织列入世界遗产。","曾是阮朝时期（1802—1945）越南的都城。","皇城依风水原理而建，以香江为明堂。"],"travelTips":["夜晚乘龙船在香江上聆听顺化宫廷雅乐。","品尝宫廷美食：顺化牛肉粉、浮萍饼、顺化甜羹。"],"bestTime":"1月至4月，避开年末雨季","visitDuration":"半天","ticket":"200,000越南盾","openingHours":"07:00 – 17:30","galleryCaptions":["巍峨的午门","从石板路入口望见的古朴午门","暮色降临的香江"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('golden-bridge', 'golden-bridge', 'da-nang', 'Cầu Vàng', 'Golden Bridge', 'bridge', 107.9883, 15.9953, 'Cây cầu được nâng đỡ bởi đôi bàn tay khổng lồ, lơ lửng giữa mây trên đỉnh Bà Nà.', 'Xuất hiện như trong một giấc mơ, Cầu Vàng vươn ra giữa không trung, được nâng bởi hai bàn tay đá rêu phong khổng lồ. Đứng giữa cầu, mây trôi dưới chân, cả vùng núi Bà Nà trải ra mênh mông. Khoảnh khắc ấy khiến cả thế giới phải trầm trồ khi những bức ảnh đầu tiên lan truyền năm 2018.', '["Khánh thành năm 2018, dài gần 150m.","Nằm ở độ cao khoảng 1.400m trên núi Bà Nà.","Gây sốt truyền thông toàn cầu ngay khi xuất hiện."]', '["Đi cáp treo sớm để tránh đông và mây mù.","Kết hợp tham quan Làng Pháp và vườn hoa Le Jardin."]', 'Tháng 3–8, trời nắng đẹp', '1 ngày', '900.000đ (vé Bà Nà)', '08:00 – 22:00', '["trending","popular"]', '["mountain","photography","bridge"]', '[{"seed":"goldenbridge-1","caption":"Cầu Vàng giữa mây","ratio":"16/9"},{"seed":"goldenbridge-2","caption":"Đôi bàn tay nâng cầu","ratio":"4/3"}]', '[]', 1, '{"en":{"name":"Golden Bridge","summary":"A bridge held aloft by a pair of giant hands, suspended among the clouds atop Ba Na Hills.","story":"Appearing like something out of a dream, the Golden Bridge stretches out into the open air, cradled by two colossal moss-covered stone hands. Standing in its middle, with clouds drifting beneath your feet, the whole of Ba Na''s mountains unfolds before you. The moment took the world''s breath away when the first photos spread in 2018.","facts":["Inaugurated in 2018, nearly 150m long.","Sits at an altitude of about 1,400m on Ba Na Hills.","Became a global media sensation the instant it appeared."],"travelTips":["Take the cable car early to avoid crowds and fog.","Combine your visit with the French Village and Le Jardin flower garden."],"bestTime":"March–August, sunny and clear","visitDuration":"1 day","ticket":"900,000 VND (Ba Na ticket)","openingHours":"08:00 – 22:00","galleryCaptions":["The Golden Bridge among the clouds","The pair of hands holding the bridge"]},"ko":{"name":"골든 브리지","summary":"거대한 두 손이 떠받친 다리가 바나힐 정상 구름 사이에 떠 있습니다.","story":"꿈속 풍경처럼 나타난 골든 브리지는 이끼 낀 거대한 돌손 두 개에 떠받쳐져 허공으로 뻗어 나갑니다. 다리 한가운데 서면 발밑으로 구름이 흐르고 바나산 일대가 광활하게 펼쳐집니다. 2018년 첫 사진이 퍼지자 전 세계가 감탄을 금치 못한 순간이었습니다.","facts":["2018년 개통, 길이 약 150m.","바나힐 해발 약 1,400m에 위치.","공개되자마자 전 세계 미디어를 강타."],"travelTips":["혼잡과 안개를 피하려면 케이블카를 일찍 타세요.","프랑스 마을과 르 자르댕 꽃정원 관람을 함께 즐기세요."],"bestTime":"3~8월, 맑고 화창한 날씨","visitDuration":"1일","ticket":"900,000동 (바나힐 입장권)","openingHours":"08:00 – 22:00","galleryCaptions":["구름 사이의 골든 브리지","다리를 떠받친 두 손"]},"ja":{"name":"ゴールデンブリッジ","summary":"巨大な両手に支えられた橋が、バーナー山頂の雲の合間に浮かびます。","story":"夢の中の光景のように現れたゴールデンブリッジは、苔むした巨大な石の両手に支えられて宙へと伸びていきます。橋の中央に立つと足元を雲が流れ、バーナー山一帯が果てしなく広がります。2018年に最初の写真が広まると、その光景は世界中を驚嘆させました。","facts":["2018年開通、全長約150m。","バーナー山の標高約1,400mに位置。","公開と同時に世界中のメディアを席巻。"],"travelTips":["混雑と霧を避けるためロープウェイは早めに乗りましょう。","フレンチビレッジとル・ジャルダン花園の観光も合わせて楽しみましょう。"],"bestTime":"3〜8月、晴れて美しい天気","visitDuration":"1日","ticket":"900,000ドン（バーナー入場券）","openingHours":"08:00 – 22:00","galleryCaptions":["雲の合間のゴールデンブリッジ","橋を支える両手"]},"zh":{"name":"黄金桥","summary":"一座由巨手托起的桥，悬于巴拿山顶的云雾之间。","story":"黄金桥宛如梦境中浮现，由两只布满青苔的巨型石手托起，向空中延伸。站在桥中央，云在脚下流淌，整片巴拿山尽收眼底。2018年首批照片传开时，这一幕令全世界惊叹不已。","facts":["2018年落成，长约150米。","位于巴拿山海拔约1400米处。","一经亮相便引爆全球媒体。"],"travelTips":["趁早乘缆车，避开人潮与浓雾。","可结合游览法国村与勒贾丁花园。"],"bestTime":"3至8月，晴朗明媚","visitDuration":"1天","ticket":"900,000越南盾（巴拿山门票）","openingHours":"08:00 – 22:00","galleryCaptions":["云雾中的黄金桥","托起桥身的巨手"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hoi-an-ancient-town', 'hoi-an-ancient-town', 'quang-nam', 'Phố cổ Hội An', 'Hoi An Ancient Town', 'unesco', 108.3266, 15.8801, 'Thương cảng cổ vàng son, lung linh sắc đèn lồng mỗi khi đêm về bên dòng sông Hoài.', 'Khi mặt trời lặn, Hội An khoác lên mình tấm áo huyền ảo. Hàng nghìn chiếc đèn lồng đủ màu thắp sáng từng con phố, in bóng xuống dòng sông Hoài. Du khách thả những chiếc đèn hoa đăng mang theo điều ước. Nếu đến Hội An vào khoảng 18:30, khi đèn lồng vừa được thắp lên, bạn sẽ hiểu vì sao nơi này khiến biết bao người phải lòng.', '["Được UNESCO công nhận Di sản văn hóa thế giới năm 1999.","Từng là thương cảng sầm uất thế kỷ 16–17.","Chùa Cầu là biểu tượng do thương nhân Nhật Bản xây dựng."]', '["Đến khoảng 17:30–18:30 để ngắm phố lên đèn.","Thử cao lầu và bánh mì Hội An — ngon trứ danh."]', 'Tháng 2–4, khô ráo dễ chịu', 'Nửa ngày đến 1 ngày', '120.000đ', 'Cả ngày', '["unesco","popular","verified"]', '["culture","history","food","photography"]', '[{"seed":"hoian-1","caption":"Đèn lồng đêm phố cổ","ratio":"16/9"},{"seed":"hoian-2","caption":"Bóng dừa đổ dài trên tường vàng, người đội nón lá đi qua","ratio":"4/3"},{"seed":"hoian-3","caption":"Thả đèn hoa đăng trên sông Hoài","ratio":"1/1"},{"seed":"hoian-4","caption":"Phố cổ ban ngày","ratio":"4/3"}]', '[]', 1, '{"en":{"name":"Hoi An Ancient Town","summary":"A golden-age trading port, shimmering with lantern light each evening along the Hoai River.","story":"As the sun sets, Hoi An slips on a magical cloak. Thousands of lanterns in every color light up each street, their reflections rippling on the Hoai River. Visitors float flower lanterns carrying their wishes. Arrive in Hoi An around 18:30, just as the lanterns are lit, and you''ll understand why so many have fallen in love with this place.","facts":["Recognized as a UNESCO World Heritage Site in 1999.","Once a bustling trading port in the 16th–17th centuries.","The Japanese Covered Bridge, a symbol built by Japanese merchants."],"travelTips":["Arrive around 17:30–18:30 to watch the streets light up.","Try Cao Lau and the famous Hoi An banh mi."],"bestTime":"February–April, dry and pleasant","visitDuration":"Half a day to 1 day","ticket":"120,000 VND","openingHours":"All day","galleryCaptions":["Lanterns lighting the old town at night","Coconut shadows on a yellow wall as a woman in a conical hat passes by","Floating flower lanterns on the Hoai River","The ancient town by day"]},"ko":{"name":"호이안 구시가지","summary":"황금기를 누린 옛 무역항으로, 밤이 오면 호아이강을 따라 등불 빛으로 반짝입니다.","story":"해가 지면 호이안은 신비로운 옷을 입습니다. 형형색색의 등불 수천 개가 골목마다 불을 밝히고 그 그림자가 호아이강에 비칩니다. 여행객들은 소원을 담아 연꽃등을 띄웁니다. 등불이 막 켜지는 18시 30분 무렵 호이안에 도착한다면, 왜 이토록 많은 이들이 이곳에 반했는지 알게 될 것입니다.","facts":["1999년 유네스코 세계문화유산으로 등재.","16~17세기 번성했던 무역항.","일본 상인이 세운 내원교가 상징물."],"travelTips":["17:30~18:30 무렵 도착해 등불 켜지는 거리를 감상하세요.","유명한 까오러우와 호이안 반미를 맛보세요."],"bestTime":"2~4월, 건조하고 쾌적","visitDuration":"반나절~1일","ticket":"120,000동","openingHours":"종일","galleryCaptions":["밤 구시가지를 밝히는 등불","노란 벽에 길게 드리운 야자수 그림자, 농라를 쓴 사람이 지나갑니다","호아이강에 연꽃등 띄우기","낮의 구시가지"]},"ja":{"name":"ホイアン旧市街","summary":"黄金時代を誇った古い貿易港。夜が訪れるとホアイ川沿いにランタンの光がきらめきます。","story":"日が沈むと、ホイアンは幻想的な装いをまといます。色とりどりのランタンが何千と街路を照らし、その影がホアイ川に映ります。旅人は願いを込めて灯籠を流します。ランタンが灯り始める18時30分頃にホイアンへ着けば、なぜこれほど多くの人がこの地に魅了されるのか分かるでしょう。","facts":["1999年にユネスコ世界文化遺産に登録。","16〜17世紀に栄えた貿易港。","日本商人が築いた来遠橋（日本橋）が象徴。"],"travelTips":["17:30〜18:30頃に着いて、灯りがともる街並みを楽しみましょう。","名物のカオラウとホイアンのバインミーを味わいましょう。"],"bestTime":"2〜4月、乾燥して過ごしやすい","visitDuration":"半日〜1日","ticket":"120,000ドン","openingHours":"終日","galleryCaptions":["夜の旧市街を照らすランタン","黄色い壁に長く伸びる椰子の影、ノンラーを被った人が通り過ぎる","ホアイ川に灯籠を流す","昼の旧市街"]},"zh":{"name":"会安古镇","summary":"昔日繁华的古商港，每当夜幕降临，怀河畔便点亮灯笼，流光溢彩。","story":"日落时分，会安披上一袭梦幻的衣裳。成千上万盏五彩灯笼照亮每条街巷，倒影映在怀河之上。游人放下载着心愿的花灯。若在18点30分左右抵达会安，正逢灯笼初亮，你便会明白为何这里令无数人倾心。","facts":["1999年被联合国教科文组织列为世界文化遗产。","曾是16至17世纪繁盛的商港。","来远桥（日本桥）是由日本商人建造的标志性建筑。"],"travelTips":["约17:30至18:30抵达，欣赏古镇点灯。","品尝会安名吃高楼面与会安法棍。"],"bestTime":"2至4月，干爽宜人","visitDuration":"半天至1天","ticket":"120,000越南盾","openingHours":"全天","galleryCaptions":["夜晚点亮古镇的灯笼","椰影斜映黄墙，头戴斗笠的人走过","在怀河上放花灯","白天的古镇"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('da-lat-city', 'da-lat-city', 'lam-dong', 'Đà Lạt', 'Da Lat', 'city', 108.4583, 11.9404, 'Thành phố ngàn hoa trong sương, lãng mạn với rừng thông, hồ nước và những sớm mai săn mây.', 'Đà Lạt chào bạn bằng cái lạnh dịu dàng và hương cà phê thoảng trong gió. Những đồi thông xanh ngút ngàn, hồ Xuân Hương phẳng lặng, và muôn loài hoa khoe sắc quanh năm. Bình minh, từng lớp mây bồng bềnh trôi qua thung lũng — khoảnh khắc ''săn mây'' khiến người ta nín thở. Một ly cà phê nóng bên hồ buổi sáng là đủ để yêu Đà Lạt.', '["Nằm ở độ cao khoảng 1.500m, khí hậu mát quanh năm.","Được người Pháp quy hoạch thành nơi nghỉ dưỡng đầu thế kỷ 20.","Nổi tiếng với hoa, cà phê, dâu tây và atisô."]', '["Dậy sớm lên Cầu Đất hoặc đồi Đa Phú để săn mây.","Mang theo áo khoác nhẹ — đêm Đà Lạt khá lạnh."]', 'Quanh năm; đẹp nhất tháng 10–12 mùa dã quỳ', '2–3 ngày', '', 'Cả ngày', '["popular","verified"]', '["mountain","nature","food","photography"]', '[{"seed":"dalat-1","caption":"Săn mây bình minh","ratio":"16/9"},{"seed":"dalat-2","caption":"Hồ Xuân Hương","ratio":"4/3"},{"seed":"dalat-3","caption":"Đồi thông trong sương","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Da Lat","summary":"A misty city of a thousand flowers, romantic with pine forests, lakes, and cloud-hunting dawns.","story":"Da Lat greets you with a gentle chill and the scent of coffee drifting on the breeze. Endless green pine hills, the placid Xuan Huong Lake, and countless flowers blooming all year round. At dawn, layers of clouds float through the valleys — the ''cloud-hunting'' moment that leaves you breathless. A hot cup of coffee by the lake in the morning is all it takes to fall for Da Lat.","facts":["Sits at about 1,500m altitude, with cool weather year-round.","Planned by the French as a resort town in the early 20th century.","Famous for flowers, coffee, strawberries, and artichokes."],"travelTips":["Rise early to Cau Dat or Da Phu hill for cloud-hunting.","Bring a light jacket — Da Lat nights are quite cold."],"bestTime":"Year-round; best in October–December, the wild sunflower season","visitDuration":"2–3 days","ticket":"","openingHours":"All day","galleryCaptions":["Cloud-hunting at dawn","Xuan Huong Lake","Pine hills in the mist"]},"ko":{"name":"달랏","summary":"안개 속 꽃의 도시로, 소나무 숲과 호수, 구름을 좇는 새벽이 낭만적입니다.","story":"달랏은 부드러운 추위와 바람결에 스미는 커피 향으로 당신을 맞이합니다. 끝없이 푸른 소나무 언덕, 잔잔한 쑤언흐엉 호수, 그리고 사계절 피어나는 온갖 꽃들. 새벽이면 구름이 골짜기를 두둥실 흐르고 — ''구름 사냥''의 순간은 숨을 멎게 합니다. 아침 호숫가에서 마시는 따뜻한 커피 한 잔이면 달랏에 반하기에 충분합니다.","facts":["해발 약 1,500m, 일년 내내 서늘한 기후.","20세기 초 프랑스인이 휴양지로 계획.","꽃, 커피, 딸기, 아티초크로 유명."],"travelTips":["구름 사냥을 위해 꺼우닷이나 다푸 언덕에 일찍 오르세요.","달랏의 밤은 꽤 추우니 가벼운 외투를 챙기세요."],"bestTime":"연중; 10~12월 들국화 철이 가장 아름다움","visitDuration":"2~3일","ticket":"","openingHours":"종일","galleryCaptions":["새벽 구름 사냥","쑤언흐엉 호수","안개 속 소나무 언덕"]},"ja":{"name":"ダラット","summary":"霧に包まれた花の都。松林や湖、雲海を狙う朝がロマンチックです。","story":"ダラットは穏やかな涼しさと、風に漂うコーヒーの香りであなたを迎えます。果てしなく続く緑の松の丘、静かなスアンフオン湖、そして一年中咲き誇る数多の花々。夜明けには雲が層をなして谷を漂い——「雲海狩り」の瞬間は息を呑むほどです。朝、湖畔で味わう一杯のホットコーヒーだけで、ダラットに恋してしまいます。","facts":["標高約1,500mに位置し、一年中涼しい気候。","20世紀初頭にフランス人が避暑地として計画。","花、コーヒー、いちご、アーティチョークで有名。"],"travelTips":["雲海を狙うならカウダットやダフーの丘へ早朝に登りましょう。","ダラットの夜はかなり冷えるので、軽い上着を持参しましょう。"],"bestTime":"通年。10〜12月のヒマワリの季節が最も美しい","visitDuration":"2〜3日","ticket":"","openingHours":"終日","galleryCaptions":["夜明けの雲海狩り","スアンフオン湖","霧の中の松の丘"]},"zh":{"name":"大叻","summary":"雾中的千花之城，松林、湖泊与追云的清晨共绘浪漫。","story":"大叻以温柔的清凉和随风飘来的咖啡香迎接你。无边的青翠松丘，平静的春香湖，还有四季绽放的繁花。清晨，层层云雾飘过山谷——那「追云」的瞬间令人屏息。湖畔晨间的一杯热咖啡，便足以让人爱上大叻。","facts":["位于海拔约1500米处，四季凉爽。","20世纪初由法国人规划为度假胜地。","以鲜花、咖啡、草莓和洋蓟闻名。"],"travelTips":["早起登上球山或多富丘追云。","带件薄外套——大叻的夜晚相当寒凉。"],"bestTime":"四季皆宜；10至12月野菊花季最美","visitDuration":"2至3天","ticket":"","openingHours":"全天","galleryCaptions":["清晨追云","春香湖","雾中的松丘"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ben-thanh-market', 'ben-thanh-market', 'ho-chi-minh', 'Chợ Bến Thành', 'Ben Thanh Market', 'market', 106.698, 10.7721, 'Khu chợ biểu tượng của Sài Gòn, nơi nhịp sống sôi động và hương vị ẩm thực hội tụ.', 'Bến Thành là trái tim náo nhiệt của Sài Gòn. Từ sáng sớm, tiếng mời chào rộn ràng, sạp hàng đầy ắp trái cây, vải vóc, đặc sản. Khi đêm xuống, khu chợ đêm bên ngoài lại bừng lên với hàng quán ăn vặt: bánh xèo, gỏi cuốn, chè ba màu. Một vòng Bến Thành là cảm nhận trọn vẹn sự phóng khoáng, hào sảng của người Sài Gòn.', '["Chợ hiện tại được xây dựng năm 1914 thời Pháp thuộc.","Tháp đồng hồ cửa Nam là biểu tượng quen thuộc của thành phố.","Là điểm đến ẩm thực và mua sắm hàng đầu Sài Gòn."]', '["Mạnh dạn trả giá khi mua sắm.","Ghé chợ đêm sau 19:00 để thưởng thức ẩm thực đường phố."]', 'Quanh năm; mùa khô tháng 12–4 dễ chịu nhất', '1–2 giờ', '', '06:00 – 24:00 (chợ đêm)', '["popular"]', '["city","food","market"]', '[{"seed":"benthanh-1","caption":"Cửa Nam chợ Bến Thành","ratio":"16/9"},{"seed":"benthanh-2","caption":"Chợ đêm rực rỡ","ratio":"4/3"}]', '[]', 0, '{"en":{"name":"Ben Thanh Market","summary":"An iconic Saigon market where vibrant city life and the city''s culinary flavors come together.","story":"Ben Thanh is the bustling heart of Saigon. From early morning, lively calls of vendors fill the air and stalls overflow with fruit, fabrics and local specialties. When night falls, the outdoor night market lights up with street-food stands serving banh xeo, fresh spring rolls and three-colored che. A loop around Ben Thanh is to feel the full warmth and generous spirit of the Saigonese.","facts":["The current market was built in 1914 during the French colonial era.","The South Gate clock tower is a familiar symbol of the city.","It is Saigon''s leading destination for food and shopping."],"travelTips":["Don''t be shy about bargaining when you shop.","Visit the night market after 19:00 to enjoy street food."],"bestTime":"Year-round; the dry season from December to April is the most pleasant","visitDuration":"1–2 hours","ticket":"","openingHours":"06:00 – 24:00 (night market)","galleryCaptions":["The South Gate of Ben Thanh Market","The dazzling night market"]},"ko":{"name":"벤탄 시장","summary":"활기찬 도시의 삶과 미식의 맛이 어우러지는 사이공의 상징적인 시장.","story":"벤탄은 사이공의 분주한 심장입니다. 이른 아침부터 상인들의 흥겨운 호객 소리가 울려 퍼지고, 좌판은 과일과 직물, 특산물로 가득 찹니다. 밤이 내리면 바깥의 야시장이 반세오, 월남쌈, 삼색 째 같은 길거리 음식 노점으로 환하게 빛납니다. 벤탄을 한 바퀴 도는 것은 사이공 사람들의 너그럽고 호방한 정서를 온전히 느끼는 일입니다.","facts":["현재의 시장은 프랑스 식민지 시기인 1914년에 지어졌습니다.","남문 시계탑은 이 도시의 친숙한 상징입니다.","사이공 최고의 미식·쇼핑 명소입니다."],"travelTips":["쇼핑할 때는 과감하게 흥정해 보세요.","19:00 이후 야시장에 들러 길거리 음식을 즐겨 보세요."],"bestTime":"연중; 12~4월 건기가 가장 쾌적합니다","visitDuration":"1~2시간","ticket":"","openingHours":"06:00 – 24:00 (야시장)","galleryCaptions":["벤탄 시장 남문","화려한 야시장"]},"ja":{"name":"ベンタイン市場","summary":"活気あふれる街の暮らしとグルメの味が交わる、サイゴンの象徴的な市場。","story":"ベンタインはサイゴンの賑やかな心臓部です。早朝から商人たちの威勢のよい呼び込みが響き、屋台は果物や織物、特産品で溢れかえります。夜になると外のナイトマーケットが、バインセオや生春巻き、三色チェーといった屋台料理の店で華やかに灯ります。ベンタインを一巡りすれば、サイゴンの人々の大らかで気前のよい気質を余すところなく感じられます。","facts":["現在の市場はフランス植民地時代の1914年に建てられました。","南門の時計塔は街のおなじみのシンボルです。","サイゴン随一のグルメ・ショッピングの名所です。"],"travelTips":["買い物の際は思い切って値切ってみましょう。","19:00以降にナイトマーケットへ立ち寄り、屋台料理を楽しみましょう。"],"bestTime":"通年。12〜4月の乾季が最も快適です","visitDuration":"1〜2時間","ticket":"","openingHours":"06:00 – 24:00（ナイトマーケット）","galleryCaptions":["ベンタイン市場の南門","きらびやかなナイトマーケット"]},"zh":{"name":"滨城市场","summary":"西贡的标志性市场，活力四射的城市生活与美食滋味在此交汇。","story":"滨城是西贡热闹的心脏。一大早，商贩的吆喝声此起彼伏，摊位上摆满了水果、布料和各色特产。夜幕降临，外围的夜市亮起灯火，街头小吃摊一字排开：越式煎饼、生春卷、三色甜品。绕滨城走上一圈，便能尽情感受西贡人豪爽大方的性情。","facts":["现在的市场建于法国殖民时期的1914年。","南门钟楼是这座城市熟悉的象征。","它是西贡首屈一指的美食与购物胜地。"],"travelTips":["购物时不妨大胆地讨价还价。","19:00之后去逛夜市，品尝街头小吃。"],"bestTime":"全年皆宜；12月至4月旱季最为舒适","visitDuration":"1–2小时","ticket":"","openingHours":"06:00 – 24:00（夜市）","galleryCaptions":["滨城市场南门","璀璨的夜市"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('phong-nha-cave', 'phong-nha-cave', 'quang-binh', 'Động Phong Nha', 'Phong Nha Cave', 'cave', 106.2833, 17.5833, 'Trái tim của vương quốc hang động, nơi dòng sông ngầm len lỏi qua những thạch nhũ lộng lẫy.', 'Ngồi trên chiếc thuyền nhỏ trôi vào lòng Động Phong Nha, ánh sáng dần tắt sau lưng, nhường chỗ cho một thế giới huyền ảo. Dòng sông ngầm Son lặng lẽ đưa bạn qua những vòm hang cao vút, nơi thạch nhũ hàng triệu năm tuổi rủ xuống lấp lánh như cung điện pha lê. Tiếng nước nhỏ giọt vọng trong không gian tĩnh mịch, mỗi khối đá mang một hình hài kỳ lạ do tạo hóa khắc nên. Đây là một phần của di sản Phong Nha - Kẻ Bàng, nơi thiên nhiên kể câu chuyện về thời gian bằng đá và nước.', '["Thuộc Vườn quốc gia Phong Nha - Kẻ Bàng, Di sản thiên nhiên thế giới UNESCO (2003).","Sông ngầm trong động dài khoảng 1.500m có thể đi thuyền tham quan.","Khu vực này có hệ thống hang động đá vôi karst hơn 400 triệu năm tuổi."]', '["Đi thuyền trên sông Son để vào động — trải nghiệm không thể bỏ lỡ.","Mang giày chống trượt vì nền hang ẩm ướt."]', 'Tháng 2–8, mùa khô ráo, nước sông trong', 'Nửa ngày', '150.000đ', '07:30 – 16:30', '["unesco","popular","verified"]', '["nature","history","photography"]', '[{"seed":"phongnha-1","caption":"Vòm hang sâu thẳm ánh lên sắc đá nâu đỏ","ratio":"16/9"},{"seed":"phongnha-2","caption":"Thạch nhũ huyền ảo trong lòng hang tĩnh lặng","ratio":"4/3"},{"seed":"phongnha-3","caption":"Dòng sông ngầm Son","ratio":"1/1"}]', '["son-doong-cave"]', 1, '{"en":{"name":"Phong Nha Cave","summary":"The heart of a kingdom of caves, where an underground river winds through dazzling stalactites.","story":"Drifting into the depths of Phong Nha Cave aboard a small boat, the daylight fades behind you, giving way to an enchanted world. The quiet underground Son River carries you beneath soaring cave vaults, where stalactites millions of years old hang glittering like a crystal palace. The drip of water echoes through the silence, and every block of stone bears a strange shape carved by nature itself. This is part of the Phong Nha - Ke Bang heritage, where nature tells the story of time in stone and water.","facts":["Part of Phong Nha - Ke Bang National Park, a UNESCO World Natural Heritage Site (2003).","The underground river inside the cave runs about 1,500m and can be explored by boat.","The area holds a karst limestone cave system more than 400 million years old."],"travelTips":["Take a boat along the Son River to enter the cave — an experience not to be missed.","Wear non-slip shoes, as the cave floor is damp."],"bestTime":"February–August, the dry season when the river runs clear","visitDuration":"Half a day","ticket":"150,000 VND","openingHours":"07:30 – 16:30","galleryCaptions":["A deep cave vault glowing with reddish-brown rock","Ethereal stalactites within the silent cave","The underground Son River"]},"ko":{"name":"퐁냐 동굴","summary":"동굴 왕국의 심장으로, 지하강이 화려한 종유석 사이를 굽이쳐 흐릅니다.","story":"작은 배를 타고 퐁냐 동굴 속으로 흘러 들어가면 등 뒤로 햇빛이 점차 사라지고 환상적인 세계가 펼쳐집니다. 고요한 지하강 손강이 높이 솟은 동굴 천장 아래로 당신을 데려가고, 수백만 년 된 종유석이 수정 궁전처럼 반짝이며 드리워집니다. 물방울 떨어지는 소리가 정적 속에 울리고, 모든 바위는 자연이 빚어낸 기이한 형상을 띱니다. 이곳은 퐁냐-께방 유산의 일부로, 자연이 돌과 물로 시간의 이야기를 들려주는 곳입니다.","facts":["퐁냐-께방 국립공원에 속하며, 유네스코 세계자연유산(2003)입니다.","동굴 안 지하강은 약 1,500m 길이로 배를 타고 둘러볼 수 있습니다.","이 지역에는 4억 년이 넘은 카르스트 석회암 동굴 시스템이 있습니다."],"travelTips":["손강에서 배를 타고 동굴로 들어가는 것은 놓칠 수 없는 경험입니다.","동굴 바닥이 축축하니 미끄럼 방지 신발을 신으세요."],"bestTime":"2~8월, 건기로 강물이 맑은 시기","visitDuration":"반나절","ticket":"150,000동","openingHours":"07:30 – 16:30","galleryCaptions":["붉은빛 도는 바위로 빛나는 깊은 동굴 천장","고요한 동굴 속 환상적인 종유석","지하강 손강"]},"ja":{"name":"フォンニャ洞窟","summary":"洞窟王国の心臓部。地下河川がきらびやかな鍾乳石の間を縫って流れます。","story":"小舟に乗ってフォンニャ洞窟の奥へ漂い入ると、背後で日の光が次第に消え、幻想的な世界が広がります。静かな地下河川ソン川が、高くそびえる洞窟の天井の下へとあなたを運び、何百万年もの歳月を経た鍾乳石が水晶宮のようにきらめきながら垂れ下がります。水滴の音が静寂の中に響き、すべての岩が自然の刻んだ奇妙な形をまといます。ここはフォンニャ・ケバン遺産の一部であり、自然が石と水で時の物語を語る場所です。","facts":["フォンニャ・ケバン国立公園に属し、ユネスコ世界自然遺産（2003年）です。","洞窟内の地下河川は約1,500mの長さで、ボートで巡れます。","この一帯には4億年以上前のカルスト石灰岩洞窟群があります。"],"travelTips":["ソン川をボートで進んで洞窟へ入る——見逃せない体験です。","洞窟の床が湿っているので滑り止めの靴を履きましょう。"],"bestTime":"2〜8月、乾季で川の水が澄む時期","visitDuration":"半日","ticket":"150,000ドン","openingHours":"07:30 – 16:30","galleryCaptions":["赤褐色の岩が照り映える深い洞窟の天井","静寂の洞窟内に広がる幻想的な鍾乳石","地下河川ソン川"]},"zh":{"name":"风牙洞","summary":"洞穴王国的心脏，地下河蜿蜒穿过璀璨的钟乳石。","story":"乘小船漂入风牙洞深处，身后日光渐渐隐没，让位于一个梦幻世界。静谧的地下河——山河，载你穿过高耸的洞穹，数百万年的钟乳石如水晶宫般晶莹垂落。水滴声在静寂中回响，每一块岩石都被造化雕刻出奇异的形态。这里是风牙—格邦遗产的一部分，自然在此以石与水讲述时间的故事。","facts":["属风牙—格邦国家公园，联合国教科文组织世界自然遗产（2003年）。","洞内地下河长约1,500米，可乘船游览。","此地拥有逾4亿年历史的喀斯特石灰岩洞穴系统。"],"travelTips":["乘船沿山河进洞——不容错过的体验。","洞内地面潮湿，请穿防滑鞋。"],"bestTime":"2月至8月，干燥少雨、河水清澈的季节","visitDuration":"半天","ticket":"150,000越南盾","openingHours":"07:30 – 16:30","galleryCaptions":["深邃的洞穹映出红棕色岩石光泽","静谧洞中梦幻的钟乳石","地下河山河"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('son-doong-cave', 'son-doong-cave', 'quang-binh', 'Hang Sơn Đoòng', 'Son Doong Cave', 'cave', 106.2872, 17.4475, 'Hang động tự nhiên lớn nhất thế giới, một vũ trụ riêng với rừng nguyên sinh và mây trôi trong lòng đất.', 'Sơn Đoòng không giống bất cứ nơi nào trên Trái Đất. Trong lòng hang khổng lồ ấy có cả một khu rừng nguyên sinh, có sông chảy, có những đám mây hình thành rồi tan biến, và những giếng trời rọi xuống cột sáng huyền diệu. Đứng dưới vòm hang cao tới gần 200m, con người chỉ như một chấm nhỏ giữa kỳ quan vĩ đại của tạo hóa. Khám phá Sơn Đoòng là một hành trình phiêu lưu thực sự, dành cho những ai khao khát chạm tới điều phi thường.', '["Là hang động tự nhiên lớn nhất thế giới, được phát hiện năm 1990 và khảo sát năm 2009.","Vòm hang có chỗ cao gần 200m, đủ chứa cả một tòa nhà chọc trời.","Bên trong có rừng nguyên sinh và hệ sinh thái riêng biệt."]', '["Chỉ tham quan qua tour thám hiểm được cấp phép, đặt trước nhiều tháng.","Cần sức khỏe tốt cho hành trình trekking nhiều ngày."]', 'Tháng 1–8, ngoài mùa mưa lũ', 'Tour 4 ngày 3 đêm', 'Tour từ 70 triệu đồng', 'Theo lịch tour', '["hidden-gem","trending","verified"]', '["nature","mountain","photography"]', '[{"seed":"sondoong-1","caption":"Cột sáng giếng trời trong hang","ratio":"16/9"},{"seed":"sondoong-2","caption":"Lòng hang đá nâu đỏ uốn cong dẫn vào sâu","ratio":"4/3"},{"seed":"sondoong-3","caption":"Đoàn người nhỏ bé dưới giếng trời rừng xanh trong hang","ratio":"1/1"}]', '["phong-nha-cave"]', 0, '{"en":{"name":"Son Doong Cave","summary":"The largest natural cave in the world, a universe of its own with primeval forest and clouds drifting underground.","story":"Son Doong is like nowhere else on Earth. Within its colossal chamber lies an entire primeval forest, a flowing river, clouds that form and dissolve, and skylights that pour down shafts of magical light. Standing beneath a vault nearly 200m high, a person is but a tiny dot amid one of nature''s grandest wonders. Exploring Son Doong is a true adventure, reserved for those who long to touch the extraordinary.","facts":["The largest natural cave in the world, discovered in 1990 and surveyed in 2009.","Its vault reaches nearly 200m high in places — tall enough to hold a skyscraper.","Inside lies a primeval forest with its own distinct ecosystem."],"travelTips":["Accessible only via a licensed expedition tour, booked many months in advance.","Good physical fitness is required for the multi-day trekking journey."],"bestTime":"January–August, outside the flood season","visitDuration":"4-day, 3-night tour","ticket":"Tours from 70 million VND","openingHours":"By tour schedule","galleryCaptions":["A shaft of light from a skylight inside the cave","The reddish-brown cave interior curving deeper inward","A tiny group of people beneath the green-forested skylight in the cave"]},"ko":{"name":"선동(썬도옹) 동굴","summary":"세계에서 가장 큰 자연 동굴로, 원시림과 땅속을 떠다니는 구름이 있는 하나의 우주입니다.","story":"선동은 지구상 어느 곳과도 닮지 않았습니다. 거대한 동굴 안에는 원시림 전체가 있고, 강이 흐르며, 생겼다 사라지는 구름과 신비로운 빛기둥을 쏟아내는 천창이 있습니다. 거의 200m 높이의 천장 아래 서면 사람은 자연의 위대한 경이 속 작은 점에 불과합니다. 선동 탐험은 비범한 것에 닿기를 갈망하는 이들을 위한 진정한 모험입니다.","facts":["세계에서 가장 큰 자연 동굴로, 1990년 발견되어 2009년 조사되었습니다.","천장은 일부 구간에서 거의 200m에 달해 초고층 빌딩도 들어갈 수 있습니다.","내부에는 독자적인 생태계를 지닌 원시림이 있습니다."],"travelTips":["허가된 탐험 투어로만 방문할 수 있으며, 수개월 전에 예약해야 합니다.","여러 날에 걸친 트레킹 여정에는 좋은 체력이 필요합니다."],"bestTime":"1~8월, 홍수기를 제외한 시기","visitDuration":"3박 4일 투어","ticket":"투어 7천만 동부터","openingHours":"투어 일정에 따름","galleryCaptions":["동굴 속 천창에서 쏟아지는 빛기둥","안쪽으로 굽이쳐 들어가는 붉은빛 동굴 내부","동굴 속 푸른 숲 천창 아래 작아 보이는 사람들"]},"ja":{"name":"ソンドン洞窟","summary":"世界最大の自然洞窟。原生林と地中を漂う雲を抱く、ひとつの独立した宇宙です。","story":"ソンドンは地球上のどことも似ていません。その巨大な空間の中には原生林がまるごとあり、川が流れ、生まれては消える雲があり、天窓から神秘的な光の柱が降り注ぎます。高さ約200mの天井の下に立つと、人はこの大いなる自然の驚異の中のちっぽけな点に過ぎません。ソンドンの探検は、非凡なものに触れたいと願う者のための、真の冒険です。","facts":["世界最大の自然洞窟で、1990年に発見され、2009年に調査されました。","天井は場所によって高さ約200mに達し、超高層ビルもすっぽり収まります。","内部には独自の生態系を持つ原生林があります。"],"travelTips":["許可された探検ツアーでのみ訪問でき、数か月前の予約が必要です。","数日間のトレッキングには十分な体力が必要です。"],"bestTime":"1〜8月、増水期を除く","visitDuration":"3泊4日のツアー","ticket":"ツアーは7,000万ドンから","openingHours":"ツアー日程による","galleryCaptions":["洞窟内の天窓から差し込む光の柱","奥へと湾曲して続く赤褐色の洞窟内部","洞窟内の緑の森の天窓の下にたたずむ小さな人々"]},"zh":{"name":"山水洞（韩松洞）","summary":"世界最大的天然洞穴，自成一方天地，地底有原始森林，更有云雾流转。","story":"山水洞与地球上任何地方都不相同。在它庞大的洞腔里，有一整片原始森林，有河流奔涌，有云雾生成又消散，天窗洒下神奇的光柱。站在近200米高的洞穹之下，人不过是这造化伟大奇观中的一个小点。探索山水洞是一场真正的冒险，专属于那些渴望触及非凡的人。","facts":["世界最大的天然洞穴，1990年被发现，2009年完成勘测。","洞穹局部高近200米，足以容纳一座摩天大楼。","洞内有原始森林与独特的生态系统。"],"travelTips":["仅可通过获得许可的探险团游览，须提前数月预订。","多日徒步行程需要良好的体能。"],"bestTime":"1月至8月，避开洪汛期","visitDuration":"4天3晚行程","ticket":"行程7,000万越南盾起","openingHours":"按行程安排","galleryCaptions":["洞内天窗洒下的光柱","向深处弯曲延伸的红棕色洞腔","洞中绿林天窗下渺小的人群"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('nha-trang-beach', 'nha-trang-beach', 'khanh-hoa', 'Biển Nha Trang', 'Nha Trang Beach', 'beach', 109.1967, 12.2388, 'Vịnh biển xanh trong vắt với bãi cát trắng cong mềm, một trong những vịnh đẹp nhất thế giới.', 'Nha Trang mở ra trước mắt bạn một dải biển xanh ngọc bích ôm lấy bờ cát trắng dài. Buổi sáng, mặt trời lên từ phía biển nhuộm hồng cả vịnh, người dân tắm biển sớm, thuyền thúng dập dềnh. Hàng dừa nghiêng mình theo gió, và xa xa là những hòn đảo nhô lên giữa làn nước trong đến mức nhìn thấy đáy. Lặn biển ngắm san hô, thưởng thức hải sản tươi rói bên bờ — Nha Trang là thiên đường nghỉ dưỡng của miền Trung.', '["Vịnh Nha Trang là thành viên Câu lạc bộ các vịnh đẹp nhất thế giới.","Bãi biển trải dài khoảng 6km dọc thành phố.","Vùng biển có nhiều rạn san hô đa dạng để lặn ngắm."]', '["Đi tour 4 đảo để lặn ngắm san hô và tắm biển.","Thưởng thức hải sản tươi và bún cá Nha Trang."]', 'Tháng 3–9, biển êm và nắng đẹp', '1–2 ngày', '', 'Cả ngày', '["popular","verified"]', '["beach","nature","food"]', '[{"seed":"nhatrang-1","caption":"Bình minh trên vịnh Nha Trang","ratio":"16/9"},{"seed":"nhatrang-2","caption":"Bãi cát trắng cong mềm","ratio":"4/3"},{"seed":"nhatrang-3","caption":"Hàng dừa ven biển","ratio":"1/1"}]', '["hon-mun-island"]', 1, '{"en":{"name":"Nha Trang Beach","summary":"A crystal-clear blue bay with a softly curving white-sand beach, one of the world''s most beautiful bays.","story":"Nha Trang opens before you with a stretch of emerald sea embracing a long white-sand shore. In the morning, the sun rises from the sea and tints the whole bay pink; locals bathe early and round basket boats bob on the water. Coconut palms lean with the wind, and in the distance islands rise from water so clear you can see the bottom. Diving among coral, savoring fresh seafood by the shore — Nha Trang is central Vietnam''s resort paradise.","facts":["Nha Trang Bay is a member of the World''s Most Beautiful Bays Club.","The beach stretches about 6km along the city.","The waters hold diverse coral reefs perfect for snorkeling."],"travelTips":["Take a 4-island tour to snorkel over coral and swim.","Enjoy fresh seafood and Nha Trang''s bun ca fish noodle soup."],"bestTime":"March–September, calm seas and lovely sun","visitDuration":"1–2 days","ticket":"","openingHours":"All day","galleryCaptions":["Sunrise over Nha Trang Bay","The softly curving white-sand beach","Coconut palms along the shore"]},"ko":{"name":"나트랑 해변","summary":"맑고 푸른 만과 부드럽게 굽은 백사장이 어우러진, 세계에서 손꼽히는 아름다운 만입니다.","story":"나트랑은 긴 백사장을 감싸 안은 에메랄드빛 바다를 펼쳐 보입니다. 아침이면 바다에서 떠오른 해가 만 전체를 분홍빛으로 물들이고, 주민들은 일찍 해수욕을 즐기며 대바구니배가 물결에 흔들립니다. 야자수는 바람에 몸을 기울이고, 멀리 바닥이 보일 만큼 맑은 물 사이로 섬들이 솟아 있습니다. 산호를 감상하는 스쿠버다이빙, 해변에서 즐기는 싱싱한 해산물 — 나트랑은 중부의 휴양 천국입니다.","facts":["나트랑 만은 세계에서 가장 아름다운 만 클럽 회원.","도시를 따라 약 6km 이어진 해변.","다이빙하기 좋은 다양한 산호초가 분포."],"travelTips":["4개 섬 투어로 산호를 감상하고 해수욕을 즐기세요.","싱싱한 해산물과 나트랑 분짜 생선국수를 맛보세요."],"bestTime":"3~9월, 잔잔한 바다와 화창한 햇살","visitDuration":"1~2일","ticket":"","openingHours":"종일","galleryCaptions":["나트랑 만의 일출","부드럽게 굽은 백사장","해안가 야자수"]},"ja":{"name":"ニャチャンビーチ","summary":"澄み切った青い湾と柔らかく弧を描く白い砂浜。世界有数の美しい湾です。","story":"ニャチャンは、長い白砂の浜を抱くエメラルド色の海を目の前に広げます。朝には海から昇った太陽が湾全体を桃色に染め、人々は早朝の海水浴を楽しみ、丸い籠舟が波に揺れます。椰子の木は風になびき、遠くには底が見えるほど澄んだ水の中から島々が浮かびます。サンゴを眺めるダイビング、浜辺で味わう新鮮な海の幸——ニャチャンは中部のリゾート天国です。","facts":["ニャチャン湾は世界で最も美しい湾クラブの会員。","市街沿いに約6km続くビーチ。","ダイビングに最適な多様なサンゴ礁が分布。"],"travelTips":["4島ツアーでサンゴを眺め、海水浴を楽しみましょう。","新鮮な海の幸とニャチャンのブンカー（魚そば）を味わいましょう。"],"bestTime":"3〜9月、穏やかな海と美しい日差し","visitDuration":"1〜2日","ticket":"","openingHours":"終日","galleryCaptions":["ニャチャン湾の日の出","柔らかく弧を描く白い砂浜","海辺の椰子並木"]},"zh":{"name":"芽庄海滩","summary":"湛蓝清澈的海湾，配以柔和弯曲的白色沙滩，是世界上最美的海湾之一。","story":"芽庄在你眼前展开一片碧绿的海，环抱着绵长的白沙岸。清晨，太阳从海上升起，将整个海湾染成粉色，居民早早下海，圆形竹篮船在水面起伏。椰树随风摇曳，远处岛屿从清澈见底的海水中浮现。潜水赏珊瑚，在岸边享用新鲜海鲜——芽庄是中部的度假天堂。","facts":["芽庄湾是世界最美海湾俱乐部成员。","沿城市绵延约6公里的海滩。","海域珊瑚礁丰富多样，适合潜水观赏。"],"travelTips":["参加四岛游，潜水赏珊瑚并畅游大海。","品尝新鲜海鲜与芽庄鱼粉。"],"bestTime":"3至9月，海面平静、阳光明媚","visitDuration":"1至2天","ticket":"","openingHours":"全天","galleryCaptions":["芽庄湾的日出","柔和弯曲的白色沙滩","海边的椰树"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hon-mun-island', 'hon-mun-island', 'khanh-hoa', 'Đảo Hòn Mun', 'Hon Mun Island', 'island', 109.2833, 12.1667, 'Khu bảo tồn biển với rạn san hô rực rỡ, thiên đường lặn biển bậc nhất Việt Nam.', 'Hòn Mun mang tên loài đá đen óng ánh ven đảo, nhưng điều khiến nơi đây nổi tiếng lại nằm dưới mặt nước. Lặn xuống làn nước trong vắt, cả một thế giới san hô muôn màu hiện ra: những rặng san hô đỏ, vàng, tím, đàn cá nhỏ tung tăng len lỏi. Đây là khu bảo tồn biển đầu tiên của Việt Nam, nơi đa dạng sinh học biển phong phú bậc nhất. Một ngày ở Hòn Mun là một ngày lạc vào khu vườn cổ tích giữa đại dương.', '["Là khu bảo tồn biển đầu tiên của Việt Nam, thành lập năm 2001.","Có khoảng 350 loài san hô và đa dạng sinh vật biển.","Tên ''Hòn Mun'' bắt nguồn từ loại đá đen như gỗ mun ven đảo."]', '["Mang theo kính lặn hoặc thuê tại bến để ngắm san hô.","Đi sớm để nước trong và tránh đông khách."]', 'Tháng 3–9, biển lặng nước trong', 'Nửa ngày', '22.000đ (phí tham quan)', '07:00 – 17:00', '["hidden-gem","verified"]', '["island","beach","nature"]', '[{"seed":"honmun-1","caption":"Rạn san hô rực rỡ dưới nước","ratio":"16/9"},{"seed":"honmun-2","caption":"Làn nước trong vắt quanh đảo","ratio":"4/3"},{"seed":"honmun-3","caption":"Lặn ngắm san hô","ratio":"1/1"}]', '["nha-trang-beach"]', 0, '{"en":{"name":"Hon Mun Island","summary":"A marine reserve with brilliant coral reefs, Vietnam''s premier diving paradise.","story":"Hon Mun takes its name from the glossy black stone along its shores, but what makes it famous lies beneath the water. Dive into the crystal-clear sea and a whole world of multicolored coral appears: reefs of red, yellow, and purple, with schools of little fish darting through them. This is Vietnam''s first marine reserve, home to some of the country''s richest marine biodiversity. A day at Hon Mun is a day lost in a fairy-tale garden in the middle of the ocean.","facts":["Vietnam''s first marine reserve, established in 2001.","Home to about 350 coral species and diverse marine life.","The name ''Hon Mun'' comes from the ebony-black stone along its shores."],"travelTips":["Bring a diving mask or rent one at the dock to see the coral.","Go early for clear water and to avoid the crowds."],"bestTime":"March–September, calm seas and clear water","visitDuration":"Half a day","ticket":"22,000 VND (entrance fee)","openingHours":"07:00 – 17:00","galleryCaptions":["Brilliant coral reefs underwater","Crystal-clear water around the island","Snorkeling among the coral"]},"ko":{"name":"혼문 섬","summary":"화려한 산호초를 품은 해양보호구역으로, 베트남 최고의 다이빙 천국입니다.","story":"혼문은 해안가의 윤기 나는 검은 돌에서 이름을 얻었지만, 정작 명성의 비밀은 물속에 있습니다. 맑은 바닷속으로 내려가면 형형색색의 산호 세계가 펼쳐집니다. 붉고 노랗고 보랏빛인 산호초 사이로 작은 물고기 떼가 헤엄칩니다. 이곳은 베트남 최초의 해양보호구역으로, 해양 생물 다양성이 가장 풍부한 곳 중 하나입니다. 혼문에서의 하루는 바다 한가운데 동화 속 정원에서 보내는 하루입니다.","facts":["2001년 설립된 베트남 최초의 해양보호구역.","약 350종의 산호와 다양한 해양 생물이 서식.","''혼문''이라는 이름은 해안가 흑단처럼 검은 돌에서 유래."],"travelTips":["산호를 보려면 물안경을 챙기거나 선착장에서 빌리세요.","물이 맑고 혼잡을 피하려면 일찍 가세요."],"bestTime":"3~9월, 잔잔한 바다와 맑은 물","visitDuration":"반나절","ticket":"22,000동 (관람료)","openingHours":"07:00 – 17:00","galleryCaptions":["물속의 화려한 산호초","섬 주변의 맑은 바닷물","산호를 감상하는 스쿠버다이빙"]},"ja":{"name":"ホンムン島","summary":"鮮やかなサンゴ礁を抱く海洋保護区。ベトナム随一のダイビング天国です。","story":"ホンムンは岸辺の艶やかな黒い石にちなんで名づけられましたが、その名声の秘密は水面下にあります。澄み切った海に潜れば、色とりどりのサンゴの世界が広がります。赤や黄、紫のサンゴ礁の間を小魚の群れが泳ぎ抜けていきます。ここはベトナム初の海洋保護区で、海洋生物の多様性が最も豊かな場所の一つです。ホンムンでの一日は、大海原の真ん中のおとぎの庭で過ごす一日です。","facts":["2001年に設立されたベトナム初の海洋保護区。","約350種のサンゴと多様な海洋生物が生息。","「ホンムン」の名は岸辺の黒檀のように黒い石に由来。"],"travelTips":["サンゴを見るには水中眼鏡を持参するか、桟橋で借りましょう。","水が澄んでいて混雑を避けられる早朝に行きましょう。"],"bestTime":"3〜9月、穏やかな海と澄んだ水","visitDuration":"半日","ticket":"22,000ドン（観覧料）","openingHours":"07:00 – 17:00","galleryCaptions":["水中の鮮やかなサンゴ礁","島周辺の澄んだ海水","サンゴを眺めるダイビング"]},"zh":{"name":"黑岛（蚝岛）","summary":"拥有绚丽珊瑚礁的海洋保护区，是越南首屈一指的潜水天堂。","story":"黑岛因岸边那油亮的黑色岩石而得名，但令其声名远扬的却藏在水下。潜入清澈的海水，一个色彩斑斓的珊瑚世界便展现眼前：红、黄、紫的珊瑚丛中，小鱼成群穿梭。这是越南首个海洋保护区，海洋生物多样性极为丰富。在黑岛度过的一天，仿佛置身大海中央的童话花园。","facts":["越南首个海洋保护区，成立于2001年。","拥有约350种珊瑚及多样的海洋生物。","「黑岛」之名源于岸边乌木般漆黑的岩石。"],"travelTips":["携带潜水镜或在码头租用，以便观赏珊瑚。","趁早前往，水质清澈又能避开人潮。"],"bestTime":"3至9月，海面平静、水质清澈","visitDuration":"半天","ticket":"22,000越南盾（参观费）","openingHours":"07:00 – 17:00","galleryCaptions":["水下绚丽的珊瑚礁","环岛清澈的海水","潜水赏珊瑚"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('phu-quoc-island', 'phu-quoc-island', 'kien-giang', 'Đảo Phú Quốc', 'Phu Quoc Island', 'island', 103.9667, 10.2167, 'Đảo Ngọc lớn nhất Việt Nam với bãi biển hoang sơ, rừng nguyên sinh và hoàng hôn tuyệt mỹ.', 'Phú Quốc — hòn đảo lớn nhất nước — chào đón bạn bằng những bãi biển cát vàng trải dài và làn nước ấm áp. Hoàng hôn trên Bãi Trường nhuộm cả trời biển một màu cam rực, khoảnh khắc khiến ai cũng phải dừng bước. Rừng nguyên sinh phủ xanh trung tâm đảo, làng chài bình dị tỏa hương nước mắm trứ danh, và cáp treo vượt biển dài nhất thế giới nối ra hòn đảo phía Nam. Phú Quốc vừa hoang sơ vừa hiện đại, là viên ngọc của vùng biển Tây Nam.', '["Là đảo lớn nhất Việt Nam với diện tích khoảng 574km².","Cáp treo Hòn Thơm dài hơn 7,8km — từng là cáp treo vượt biển dài nhất thế giới.","Nổi tiếng với nước mắm Phú Quốc và hồ tiêu thơm nồng."]', '["Ngắm hoàng hôn ở Bãi Trường hoặc Dinh Cậu.","Thử nước mắm, hải sản và đi cáp treo Hòn Thơm."]', 'Tháng 11–4, mùa khô biển đẹp', '2–3 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["island","beach","nature","food"]', '[{"seed":"phuquoc-1","caption":"Hoàng hôn trên Bãi Trường","ratio":"16/9"},{"seed":"phuquoc-2","caption":"Cáp treo vượt biển Hòn Thơm","ratio":"4/3"},{"seed":"phuquoc-3","caption":"Cáp treo vượt biển xanh ngắt giữa những hòn đảo","ratio":"1/1"}]', '["bai-sao-beach"]', 1, '{"en":{"name":"Phu Quoc Island","summary":"Vietnam''s largest pearl island, with pristine beaches, primeval forest and breathtaking sunsets.","story":"Phu Quoc — the country''s largest island — welcomes you with long stretches of golden-sand beaches and warm, gentle waters. Sunset over Long Beach paints the whole sky and sea a fiery orange, a moment that stops everyone in their tracks. Primeval forest cloaks the heart of the island in green, humble fishing villages release the aroma of the famous fish sauce, and the world''s longest over-sea cable car links to an island to the south. At once wild and modern, Phu Quoc is the jewel of Vietnam''s southwestern sea.","facts":["It is Vietnam''s largest island, covering around 574 km².","The Hon Thom cable car stretches over 7.8 km — once the world''s longest over-sea cable car.","Famous for its fragrant Phu Quoc fish sauce and pepper."],"travelTips":["Watch the sunset at Long Beach or Dinh Cau.","Try the fish sauce and seafood, and ride the Hon Thom cable car."],"bestTime":"November–April, dry season with beautiful seas","visitDuration":"2–3 days","ticket":"","openingHours":"All day","galleryCaptions":["Sunset over Long Beach","The Hon Thom over-sea cable car","The over-sea cable car gliding above turquoise waters between islands"]},"ko":{"name":"푸꾸옥섬","summary":"원시 해변과 원시림, 절경의 일몰을 간직한 베트남 최대의 진주섬.","story":"베트남에서 가장 큰 섬 푸꾸옥은 길게 펼쳐진 황금빛 모래 해변과 따뜻하고 잔잔한 바닷물로 여행객을 맞이합니다. 롱비치 위로 지는 노을은 하늘과 바다를 온통 붉은 주황빛으로 물들여 누구나 발걸음을 멈추게 합니다. 섬 한가운데를 뒤덮은 원시림, 유명한 느억맘 향이 감도는 소박한 어촌, 그리고 남쪽 섬으로 이어지는 세계 최장의 해상 케이블카가 있습니다. 야성적이면서도 현대적인 푸꾸옥은 베트남 남서부 바다의 보석입니다.","facts":["면적 약 574km²로 베트남에서 가장 큰 섬입니다.","혼톰 케이블카는 길이 7.8km가 넘어 한때 세계에서 가장 긴 해상 케이블카였습니다.","향이 진한 푸꾸옥 느억맘과 후추로 유명합니다."],"travelTips":["롱비치나 딘꺼우에서 일몰을 감상하세요.","느억맘과 해산물을 맛보고 혼톰 케이블카를 타 보세요."],"bestTime":"11~4월, 바다가 아름다운 건기","visitDuration":"2~3일","ticket":"","openingHours":"종일","galleryCaptions":["롱비치 위로 지는 일몰","혼톰 해상 케이블카","섬들 사이 에메랄드빛 바다 위를 가로지르는 해상 케이블카"]},"ja":{"name":"フーコック島","summary":"手つかずのビーチと原生林、絶景の夕日を擁するベトナム最大の真珠の島。","story":"ベトナム最大の島フーコックは、長く延びる黄金の砂浜と温かく穏やかな海で旅人を迎えます。ロングビーチに沈む夕日は空と海を一面の燃えるようなオレンジに染め、誰もが足を止める瞬間です。島の中心を覆う原生林、名高いヌクマムの香り漂う素朴な漁村、そして南の島へと続く世界最長の海上ロープウェイがあります。野性的でありながら現代的なフーコックは、ベトナム南西の海の宝石です。","facts":["面積約574km²で、ベトナム最大の島です。","ホントム・ロープウェイは全長7.8kmを超え、かつて世界最長の海上ロープウェイでした。","香り高いフーコックのヌクマムと胡椒で有名です。"],"travelTips":["ロングビーチやディンカウで夕日を眺めましょう。","ヌクマムやシーフードを味わい、ホントム・ロープウェイに乗ってみましょう。"],"bestTime":"11〜4月、海が美しい乾季","visitDuration":"2〜3日","ticket":"","openingHours":"終日","galleryCaptions":["ロングビーチに沈む夕日","ホントムの海上ロープウェイ","島々の間のエメラルドの海上を渡る海上ロープウェイ"]},"zh":{"name":"富国岛","summary":"越南最大的明珠岛，拥有原始海滩、原始森林和绝美夕阳。","story":"富国岛——越南最大的岛屿——以绵延的金色沙滩和温暖柔和的海水迎接你。长滩上的落日将海天染成一片火红的橙色，让人不禁驻足。原始森林覆盖着岛屿中心，质朴的渔村飘散着著名鱼露的香气，跨海而建的世界最长跨海缆车通往南面的小岛。富国岛既原始又现代，是越南西南海域的瑰宝。","facts":["面积约574平方公里，是越南最大的岛屿。","和潭缆车全长超过7.8公里，曾是世界最长的跨海缆车。","以香浓的富国鱼露和胡椒闻名。"],"travelTips":["在长滩或镇咎观赏落日。","品尝鱼露和海鲜，乘坐和潭缆车。"],"bestTime":"11月至4月，海景宜人的旱季","visitDuration":"2至3天","ticket":"","openingHours":"全天","galleryCaptions":["长滩上的落日","和潭跨海缆车","在岛屿间碧蓝海面上空滑行的跨海缆车"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bai-sao-beach', 'bai-sao-beach', 'kien-giang', 'Bãi Sao', 'Sao Beach', 'beach', 104.0306, 10.0461, 'Bãi biển cát trắng mịn như bột, làn nước xanh ngọc — viên ngọc đẹp nhất Phú Quốc.', 'Bãi Sao được nhiều người gọi là bãi biển đẹp nhất Phú Quốc, và chỉ cần đặt chân tới là hiểu vì sao. Cát ở đây trắng mịn như bột, mềm mại dưới chân, ôm lấy một vịnh nước xanh ngọc trong vắt và lặng êm. Hàng dừa nghiêng bóng, những chiếc xích đu gỗ thả mình trên mặt nước, và biển hiền hòa quanh năm. Nằm dài trên cát, nghe sóng vỗ nhẹ và ngắm chân trời xanh ngắt, Bãi Sao cho bạn cảm giác bình yên tuyệt đối.', '["Tên ''Bãi Sao'' tương truyền vì xưa sao biển dạt vào bờ rất nhiều.","Cát trắng mịn và nước biển trong vào loại đẹp nhất đảo.","Nằm ở phía Nam đảo Phú Quốc, gần thị trấn An Thới."]', '["Đến buổi sáng để biển lặng và ít người.","Thuê xích đu, ghế gỗ và thử hải sản nướng tại bãi."]', 'Tháng 11–4, mùa khô nước trong', 'Nửa ngày', '', 'Cả ngày', '["popular","hidden-gem"]', '["beach","island","photography"]', '[{"seed":"baisao-1","caption":"Bãi cát trắng mịn ven biển xanh","ratio":"16/9"},{"seed":"baisao-2","caption":"Xích đu trên mặt nước","ratio":"4/3"}]', '["phu-quoc-island"]', 0, '{"en":{"name":"Sao Beach","summary":"A beach of powder-soft white sand and emerald water — the most beautiful jewel of Phu Quoc.","story":"Many call Sao Beach the most beautiful beach in Phu Quoc, and one step onto the sand makes it clear why. The sand here is as fine as powder, soft underfoot, cradling a calm, crystal-clear emerald bay. Coconut palms lean their shadows over the water, wooden swings sit half-submerged in the sea, and the water stays gentle all year round. Lying on the sand, listening to the soft lapping of the waves and gazing at the deep-blue horizon, Sao Beach gives you a feeling of absolute peace.","facts":["The name ''Sao'' (Starfish) comes from legend, as starfish once washed ashore here in great numbers.","Its fine white sand and clear water are among the most beautiful on the island.","Located in the south of Phu Quoc Island, near An Thoi town."],"travelTips":["Come in the morning for calm seas and fewer crowds.","Rent a swing or wooden chair and try grilled seafood on the beach."],"bestTime":"November–April, dry season with clear water","visitDuration":"Half a day","ticket":"","openingHours":"All day","galleryCaptions":["Powder-soft white sand by a blue sea","A swing standing in the water"]},"ko":{"name":"사오 해변","summary":"분처럼 고운 백사장과 에메랄드빛 바다 — 푸꾸옥에서 가장 아름다운 보석.","story":"많은 이가 사오 해변을 푸꾸옥에서 가장 아름다운 해변이라 부르는데, 모래에 발을 딛는 순간 그 이유를 알게 됩니다. 이곳의 모래는 분처럼 곱고 발밑이 부드러우며, 잔잔하고 투명한 에메랄드빛 만을 감싸 안습니다. 야자수가 물 위로 그늘을 드리우고, 나무 그네가 바다에 반쯤 잠겨 있으며, 바다는 일 년 내내 잔잔합니다. 모래에 누워 잔잔히 부서지는 파도 소리를 듣고 짙푸른 수평선을 바라보면, 사오 해변은 더없는 평온함을 선사합니다.","facts":["''사오(불가사리)''라는 이름은 옛날 이곳에 불가사리가 많이 떠밀려 왔다는 전설에서 유래했습니다.","고운 백사장과 맑은 바닷물은 섬에서 가장 아름다운 축에 듭니다.","푸꾸옥섬 남쪽, 안터이 마을 인근에 위치합니다."],"travelTips":["바다가 잔잔하고 사람이 적은 오전에 가세요.","그네나 나무 의자를 빌리고 해변에서 해산물 구이를 맛보세요."],"bestTime":"11~4월, 물이 맑은 건기","visitDuration":"반나절","ticket":"","openingHours":"종일","galleryCaptions":["푸른 바다와 분처럼 고운 백사장","물 위에 놓인 그네"]},"ja":{"name":"サオビーチ","summary":"粉のように細かい白砂とエメラルドの海 — フーコックで最も美しい宝石。","story":"多くの人がサオビーチをフーコックで最も美しいビーチと呼びますが、砂に足を踏み入れた瞬間その理由がわかります。ここの砂は粉のように細かく足元が柔らかく、穏やかで透き通ったエメラルドの入江を抱きます。ヤシの木が水面に影を落とし、木製のブランコが海に半ば浸かり、海は一年を通して穏やかです。砂に寝そべり、静かに砕ける波の音を聞き、紺碧の水平線を眺めれば、サオビーチはこの上ない安らぎをもたらしてくれます。","facts":["「サオ（ヒトデ）」という名は、かつてここに多くのヒトデが打ち寄せたという言い伝えに由来します。","細かい白砂と澄んだ海水は島で最も美しい部類に入ります。","フーコック島の南、アントイの町近くに位置します。"],"travelTips":["海が穏やかで人が少ない午前中に訪れましょう。","ブランコや木製の椅子を借り、ビーチで焼きシーフードを味わいましょう。"],"bestTime":"11〜4月、水が澄む乾季","visitDuration":"半日","ticket":"","openingHours":"終日","galleryCaptions":["青い海辺の粉のように細かい白砂","水面に立つブランコ"]},"zh":{"name":"星滩","summary":"细如粉末的洁白沙滩、碧绿如玉的海水——富国岛最美的瑰宝。","story":"许多人称星滩为富国岛最美的海滩，只要踏上沙滩便明白其中缘由。这里的沙细如粉末，踩上去柔软无比，环抱着一片平静清澈、碧绿如玉的海湾。椰树将影子斜映在水面，木秋千半浸在海中，海水常年温和。躺在沙滩上，听着轻柔拍岸的浪声，望着深蓝的天际线，星滩带给你绝对的宁静。","facts":["「星滩」之名相传源于昔日大量海星被冲上岸。","细白的沙滩和清澈的海水堪称岛上最美。","位于富国岛南部，靠近安泰镇。"],"travelTips":["上午前来，海面平静、人少。","租一架秋千或木椅，在海滩上品尝烤海鲜。"],"bestTime":"11月至4月，海水清澈的旱季","visitDuration":"半天","ticket":"","openingHours":"全天","galleryCaptions":["碧海边细如粉末的洁白沙滩","立于水中的秋千"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tra-su-forest', 'tra-su-forest', 'an-giang', 'Rừng tràm Trà Sư', 'Tra Su Cajuput Forest', 'park', 105.05, 10.5833, 'Khu rừng tràm ngập nước với thảm bèo xanh mướt, thiên đường chim nước của miền Tây.', 'Chiếc xuồng ba lá khẽ rẽ nước, đưa bạn vào một thế giới xanh huyền diệu. Mặt nước phủ kín bèo tấm xanh non như tấm thảm nhung, hai bên là rừng tràm soi bóng. Đàn cò trắng, chim nước bay rợp trời, tiếng chim ríu rít vang khắp không gian. Trà Sư là khu rừng ngập nước tiêu biểu của vùng Tây sông Hậu, nơi hệ sinh thái đa dạng và cảnh sắc bình yên đến lạ. Ngồi xuồng trôi giữa rừng tràm mùa nước nổi là một trải nghiệm khó quên của miền Tây.', '["Rừng tràm rộng khoảng 845ha, là khu bảo tồn thiên nhiên đất ngập nước.","Là nơi cư trú của nhiều loài chim nước quý hiếm.","Đẹp nhất vào mùa nước nổi tháng 9–11 khi bèo xanh phủ kín mặt nước."]', '["Đi xuồng máy rồi chuyển xuồng chèo tay để vào sâu rừng.","Leo đài quan sát để ngắm toàn cảnh rừng tràm."]', 'Tháng 9–11, mùa nước nổi', 'Nửa ngày', '100.000đ', '07:00 – 17:00', '["hidden-gem","verified"]', '["nature","photography"]', '[{"seed":"trasu-1","caption":"Xuồng trôi giữa thảm bèo xanh","ratio":"16/9"},{"seed":"trasu-2","caption":"Rừng tràm soi bóng nước","ratio":"4/3"},{"seed":"trasu-3","caption":"Rừng tràm soi bóng trên thảm bèo xanh mướt","ratio":"1/1"}]', '["mieu-ba-chua-xu"]', 1, '{"en":{"name":"Tra Su Cajuput Forest","summary":"A flooded cajuput forest carpeted in lush green duckweed — a waterbird paradise of the Mekong Delta.","story":"A small sampan parts the water gently, carrying you into a magical green world. The water is blanketed with tender green duckweed like a velvet carpet, framed on both sides by cajuput trees mirrored in the surface. Flocks of white storks and waterbirds fill the sky, their chirping echoing through the air. Tra Su is a quintessential flooded forest of the western Hau River region, a place of rich biodiversity and surprisingly serene scenery. Drifting in a boat through the cajuput forest during flood season is an unforgettable experience of the Mekong Delta.","facts":["The cajuput forest covers around 845 ha and is a wetland nature reserve.","It is home to many rare species of waterbird.","It is most beautiful during the flood season from September to November, when green duckweed covers the water."],"travelTips":["Take a motorboat, then switch to a hand-paddled sampan to go deeper into the forest.","Climb the observation tower for a panorama of the cajuput forest."],"bestTime":"September–November, flood season","visitDuration":"Half a day","ticket":"100,000 VND","openingHours":"07:00 – 17:00","galleryCaptions":["A sampan drifting over a carpet of green duckweed","Cajuput trees mirrored in the water","Cajuput forest reflected on a lush green duckweed carpet"]},"ko":{"name":"짜스 멜라루카 숲","summary":"싱그러운 초록 부평초가 뒤덮인 침수 멜라루카 숲 — 메콩델타의 물새 천국.","story":"작은 나룻배가 물살을 가르며 신비로운 초록의 세계로 여러분을 인도합니다. 수면은 벨벳 융단처럼 여린 초록 부평초로 뒤덮이고, 양옆으로는 물에 비친 멜라루카 숲이 펼쳐집니다. 흰 두루미와 물새 떼가 하늘을 가득 메우고, 지저귀는 소리가 사방에 울려 퍼집니다. 짜스는 후강 서부 지역을 대표하는 침수림으로, 생물 다양성이 풍부하고 경관이 놀랍도록 평온합니다. 물이 불어나는 시기에 멜라루카 숲 사이를 배로 떠도는 것은 메콩델타에서 잊지 못할 경험입니다.","facts":["멜라루카 숲은 약 845헥타르 규모로, 습지 자연보호구역입니다.","여러 희귀 물새 종의 서식지입니다.","초록 부평초가 수면을 뒤덮는 9~11월 물난리 시기에 가장 아름답습니다."],"travelTips":["모터보트를 탄 뒤 손으로 젓는 나룻배로 갈아타 숲 깊숙이 들어가세요.","전망대에 올라 멜라루카 숲의 전경을 감상하세요."],"bestTime":"9~11월, 물난리 시기","visitDuration":"반나절","ticket":"100,000동","openingHours":"07:00 – 17:00","galleryCaptions":["초록 부평초 융단 위를 떠가는 나룻배","물에 비친 멜라루카 숲","싱그러운 초록 부평초 융단에 비친 멜라루카 숲"]},"ja":{"name":"チャースー・メラルーカ林","summary":"みずみずしい緑の浮草に覆われた冠水メラルーカ林 — メコンデルタの水鳥の楽園。","story":"小さな小舟が水面をそっと分け、神秘的な緑の世界へと誘います。水面はビロードの絨毯のような若緑の浮草に覆われ、両岸には水面に映るメラルーカの林が広がります。白いコウノトリや水鳥の群れが空を埋め、鳴き声があたりに響き渡ります。チャースーはハウ川西部地域を代表する冠水林で、生物多様性に富み、驚くほど穏やかな景観を見せます。増水期にメラルーカ林の間を舟で漂うのは、メコンデルタの忘れがたい体験です。","facts":["メラルーカ林は約845haの広さで、湿地自然保護区です。","多くの希少な水鳥の生息地です。","緑の浮草が水面を覆う9〜11月の増水期に最も美しくなります。"],"travelTips":["モーターボートに乗った後、手漕ぎの小舟に乗り換えて林の奥へ進みましょう。","展望台に登り、メラルーカ林の全景を眺めましょう。"],"bestTime":"9〜11月、増水期","visitDuration":"半日","ticket":"100,000ドン","openingHours":"07:00 〜 17:00","galleryCaptions":["緑の浮草の絨毯の上を漂う小舟","水面に映るメラルーカ林","みずみずしい緑の浮草の絨毯に映るメラルーカ林"]},"zh":{"name":"茶师白千层林","summary":"铺满翠绿浮萍的水淹白千层林，湄公河三角洲的水鸟天堂。","story":"一叶小舟轻轻划开水面，带你进入一个神奇的绿色世界。水面铺满嫩绿的浮萍，宛如丝绒地毯，两岸是倒映水中的白千层林。白鹭和水鸟成群飞过，鸣叫声响彻空间。茶师是后江西部地区典型的水淹林，生态多样，景色出奇宁静。在涨水季节坐船漂荡在白千层林间，是湄公河三角洲难忘的体验。","facts":["白千层林面积约845公顷，是湿地自然保护区。","是多种珍稀水鸟的栖息地。","9月至11月涨水季节最美，绿浮萍铺满水面。"],"travelTips":["先乘机动船，再换乘手划小舟深入林中。","登上观景塔俯瞰白千层林全景。"],"bestTime":"9月至11月，涨水季节","visitDuration":"半天","ticket":"100,000越南盾","openingHours":"07:00 – 17:00","galleryCaptions":["漂荡在翠绿浮萍地毯上的小舟","倒映水中的白千层林","倒映在翠绿浮萍地毯上的白千层林"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('mieu-ba-chua-xu', 'mieu-ba-chua-xu', 'an-giang', 'Miếu Bà Chúa Xứ Núi Sam', 'Ba Chua Xu Temple', 'temple', 105.0747, 10.6792, 'Ngôi miếu linh thiêng dưới chân Núi Sam, điểm hành hương lớn bậc nhất miền Tây Nam Bộ.', 'Dưới chân Núi Sam, Miếu Bà Chúa Xứ uy nghi với mái cong vút và sắc vàng son rực rỡ. Mỗi năm, hàng triệu người hành hương về đây cầu bình an, tài lộc, đặc biệt trong dịp Lễ hội Vía Bà tháng tư âm lịch. Khói nhang nghi ngút, tiếng cầu khấn thành kính hòa cùng nhịp sống tâm linh sôi động. Đây không chỉ là điểm tín ngưỡng mà còn là nét văn hóa đặc sắc của vùng đất Châu Đốc, nơi giao thoa của người Kinh, Khmer, Chăm và Hoa.', '["Lễ hội Vía Bà Chúa Xứ Núi Sam là Di sản văn hóa phi vật thể quốc gia.","Thu hút hàng triệu lượt khách hành hương mỗi năm.","Nằm dưới chân Núi Sam, gần thành phố Châu Đốc."]', '["Đi vào dịp Lễ hội Vía Bà (tháng 4 âm lịch) để cảm nhận không khí lễ hội.","Ăn mặc lịch sự khi vào miếu và cẩn thận tư trang nơi đông người."]', 'Tháng 4 âm lịch (mùa lễ hội)', '1–2 giờ', '', 'Cả ngày', '["festival","popular"]', '["temple","culture","history"]', '[{"seed":"bachuaxu-1","caption":"Miếu Bà Chúa Xứ uy nghi","ratio":"16/9"},{"seed":"bachuaxu-2","caption":"Khói nhang ngày lễ hội","ratio":"4/3"}]', '["tra-su-forest"]', 0, '{"en":{"name":"Ba Chua Xu Temple of Sam Mountain","summary":"A sacred temple at the foot of Sam Mountain, one of the greatest pilgrimage sites in the southwestern Mekong region.","story":"At the foot of Sam Mountain, the Ba Chua Xu Temple stands majestic with its soaring curved roofs and brilliant gold-and-vermilion hues. Each year, millions of pilgrims travel here to pray for peace and prosperity, especially during the Lady Temple Festival in the fourth lunar month. Incense smoke swirls, and devout prayers blend with a vibrant spiritual rhythm. This is not only a place of worship but also a distinctive cultural feature of the Chau Doc region, a meeting point of the Kinh, Khmer, Cham and Hoa peoples.","facts":["The Ba Chua Xu Festival of Sam Mountain is a national intangible cultural heritage.","It draws millions of pilgrims every year.","It sits at the foot of Sam Mountain, near Chau Doc city."],"travelTips":["Visit during the Lady Temple Festival (fourth lunar month) to feel the festival atmosphere.","Dress respectfully when entering the temple and mind your belongings in the crowds."],"bestTime":"Fourth lunar month (festival season)","visitDuration":"1–2 hours","ticket":"","openingHours":"All day","galleryCaptions":["The majestic Ba Chua Xu Temple","Incense smoke on festival day"]},"ko":{"name":"삼산 바쭈아쓰 사당","summary":"삼산 기슭의 영험한 사당, 메콩 남서부 지역 최대 순례지 중 하나.","story":"삼산 기슭에 자리한 바쭈아쓰 사당은 하늘로 치솟은 곡선 지붕과 찬란한 금빛·주홍빛으로 위엄을 뽐냅니다. 해마다 수백만 명의 순례객이 평안과 재물을 빌러 이곳을 찾으며, 특히 음력 4월의 바님 축제 때 더욱 붐빕니다. 자욱한 향 연기와 경건한 기도 소리가 활기찬 영적 리듬과 어우러집니다. 이곳은 신앙의 장소일 뿐 아니라, 낀·크메르·짬·화족이 어우러진 쩌우독 지역의 독특한 문화적 명소입니다.","facts":["삼산 바쭈아쓰 축제는 국가 무형문화유산입니다.","매년 수백만 명의 순례객이 찾습니다.","쩌우독시 인근, 삼산 기슭에 위치합니다."],"travelTips":["축제 분위기를 느끼려면 바님 축제(음력 4월) 때 방문하세요.","사당에 들어갈 때는 단정히 입고, 사람이 많은 곳에서 소지품에 유의하세요."],"bestTime":"음력 4월(축제 시기)","visitDuration":"1~2시간","ticket":"","openingHours":"종일","galleryCaptions":["위엄 있는 바쭈아쓰 사당","축제일의 향 연기"]},"ja":{"name":"サム山バーチュアスー廟","summary":"サム山の麓にある霊験あらたかな廟、メコン南西地域屈指の巡礼地。","story":"サム山の麓に佇むバーチュアスー廟は、天へ反り上がる屋根と鮮やかな金と朱の色で威厳を放ちます。毎年、数百万人の巡礼者が平安と財運を祈ってここを訪れ、とくに旧暦4月のバー祭りの時期はいっそう賑わいます。立ちこめる線香の煙と敬虔な祈りの声が、活気ある霊的なリズムと溶け合います。ここは信仰の場であるだけでなく、キン・クメール・チャム・華の人々が交わるチャウドック地域の独特な文化の名所でもあります。","facts":["サム山バーチュアスー祭りは国家無形文化遺産です。","毎年数百万人の巡礼者が訪れます。","チャウドック市近く、サム山の麓に位置します。"],"travelTips":["祭りの雰囲気を感じるにはバー祭り（旧暦4月）の時期に訪れましょう。","廟に入る際は端正な服装をし、人混みでは所持品に注意しましょう。"],"bestTime":"旧暦4月（祭りの時期）","visitDuration":"1〜2時間","ticket":"","openingHours":"終日","galleryCaptions":["威厳あるバーチュアスー廟","祭りの日の線香の煙"]},"zh":{"name":"森山主处圣母庙","summary":"森山脚下的灵验庙宇，湄公河西南地区数一数二的朝圣地。","story":"在森山脚下，主处圣母庙以高耸的飞檐和金朱辉映的色彩巍然矗立。每年有数百万人前来朝圣，祈求平安与财运，尤其是农历四月的圣母诞庙会期间。香烟缭绕，虔诚的祈祷声与活跃的灵性氛围交融。这里不仅是信仰场所，更是朱笃地区——京、高棉、占、华各族交汇之地——独特的文化名胜。","facts":["森山主处圣母诞庙会是国家级非物质文化遗产。","每年吸引数百万朝圣者。","位于朱笃市附近的森山脚下。"],"travelTips":["在圣母诞庙会（农历四月）期间前来，感受庙会气氛。","进庙时着装得体，人多处注意随身财物。"],"bestTime":"农历四月（庙会季节）","visitDuration":"1至2小时","ticket":"","openingHours":"全天","galleryCaptions":["巍然庄严的主处圣母庙","庙会日缭绕的香烟"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('buon-don', 'buon-don', 'dak-lak', 'Buôn Đôn', 'Buon Don', 'village', 107.7833, 12.9, 'Quê hương của nghề săn và thuần dưỡng voi, đậm đà bản sắc văn hóa Tây Nguyên.', 'Buôn Đôn là vùng đất huyền thoại bên dòng Sêrêpốk cuộn chảy, nơi gắn liền với nghề săn bắt và thuần dưỡng voi rừng lâu đời. Những cây cầu treo bằng tre nứa đung đưa nối các cồn đảo giữa sông, nhà sàn dài của người Ê Đê, M''Nông ẩn dưới tán cây cổ thụ. Bên ánh lửa bập bùng, tiếng cồng chiêng vang vọng, chén rượu cần truyền tay nhau, người Tây Nguyên kể cho bạn nghe những câu chuyện về rừng, về voi và về một nền văn hóa hào sảng giữa đại ngàn.', '["Nổi tiếng với nghề săn và thuần dưỡng voi rừng truyền thống.","Nằm bên dòng sông Sêrêpốk chảy ngược về hướng Tây.","Là nơi sinh sống của người Ê Đê, M''Nông, Lào với văn hóa cồng chiêng."]', '["Trải nghiệm văn hóa cồng chiêng và rượu cần cùng người bản địa.","Đi cầu treo qua sông và tham quan nhà sàn truyền thống."]', 'Tháng 11–4, mùa khô Tây Nguyên', 'Nửa ngày', '20.000đ', '07:00 – 17:00', '["hidden-gem","verified"]', '["village","culture","nature"]', '[{"seed":"buondon-1","caption":"Cầu treo bằng tre qua sông Sêrêpốk","ratio":"16/9"},{"seed":"buondon-2","caption":"Nhà sàn dài Tây Nguyên","ratio":"4/3"},{"seed":"buondon-3","caption":"Đêm cồng chiêng bên lửa","ratio":"1/1"}]', '["dray-nur-waterfall"]', 0, '{"en":{"name":"Buon Don","summary":"Homeland of elephant hunting and taming, rich in the cultural identity of the Central Highlands.","story":"Buon Don is a legendary land beside the surging Serepok River, long tied to the tradition of hunting and taming wild elephants. Swaying bamboo suspension bridges link the river''s islets, and the long stilt houses of the Ede and M''Nong people hide beneath ancient trees. By the flickering fire, the sound of gongs echoes, jars of rice wine pass from hand to hand, and the Central Highlands people tell you stories of the forest, of elephants, and of a generous culture in the heart of the great wilderness.","facts":["Famous for the traditional craft of hunting and taming wild elephants.","Lies beside the Serepok River, which flows westward against the usual course.","Home to the Ede, M''Nong, and Lao peoples with their gong culture."],"travelTips":["Experience gong culture and rice wine with the local people.","Cross the suspension bridges over the river and visit traditional stilt houses."],"bestTime":"November–April, the Central Highlands dry season","visitDuration":"Half a day","ticket":"20,000 VND","openingHours":"07:00 – 17:00","galleryCaptions":["Bamboo suspension bridge over the Serepok River","Long stilt house of the Central Highlands","Gong night by the fire"]},"ko":{"name":"부온돈","summary":"코끼리 사냥과 사육의 고향으로, 떠이응우옌의 문화 정체성이 짙게 배어 있습니다.","story":"부온돈은 굽이치는 세레폭강 곁의 전설적인 땅으로, 야생 코끼리를 사냥하고 길들이는 오랜 전통과 깊이 얽혀 있습니다. 대나무 흔들다리가 강 가운데 섬들을 잇고, 에데족과 므농족의 긴 고상가옥이 고목 아래 숨어 있습니다. 일렁이는 불빛 곁으로 공 소리가 울려 퍼지고, 깐 술잔이 손에서 손으로 건네지며, 떠이응우옌 사람들은 숲과 코끼리, 그리고 대자연 속 호방한 문화 이야기를 들려줍니다.","facts":["야생 코끼리를 사냥하고 길들이는 전통 풍습으로 유명.","서쪽으로 거슬러 흐르는 세레폭강 곁에 위치.","공 문화를 지닌 에데족, 므농족, 라오족의 터전."],"travelTips":["현지인과 함께 공 문화와 깐 술을 체험하세요.","강을 가로지르는 흔들다리를 건너고 전통 고상가옥을 둘러보세요."],"bestTime":"11~4월, 떠이응우옌 건기","visitDuration":"반나절","ticket":"20,000동","openingHours":"07:00 – 17:00","galleryCaptions":["세레폭강을 가로지르는 대나무 흔들다리","떠이응우옌의 긴 고상가옥","불 곁의 공 연주 밤"]},"ja":{"name":"ブオンドン","summary":"象狩りと象使いの故郷。タイグエン高原の文化的個性が色濃く漂います。","story":"ブオンドンは、うねるセレポック川のほとりにある伝説の地で、野生の象を狩り、飼い慣らす古い伝統と深く結びついています。竹の吊り橋が川の中州を揺れながらつなぎ、エデ族やムノン族の長い高床式家屋が古木の下に隠れています。揺らめく炎のそばで銅鑼の音が響き、カン酒の杯が手から手へ渡され、タイグエンの人々は森や象、そして大自然の中の豪放な文化の物語を語ってくれます。","facts":["野生の象を狩り、飼い慣らす伝統で有名。","西へと逆流するセレポック川のほとりに位置。","銅鑼文化を持つエデ族、ムノン族、ラオ族の暮らす地。"],"travelTips":["現地の人々と銅鑼文化やカン酒を体験しましょう。","川を渡る吊り橋を渡り、伝統的な高床式家屋を訪ねましょう。"],"bestTime":"11〜4月、タイグエン高原の乾季","visitDuration":"半日","ticket":"20,000ドン","openingHours":"07:00 – 17:00","galleryCaptions":["セレポック川を渡る竹の吊り橋","タイグエン高原の長い高床式家屋","火のそばでの銅鑼の夜"]},"zh":{"name":"本敦","summary":"驯象与捕象之乡，浓郁地承载着西原的文化特色。","story":"本敦是奔涌的色雷波河畔一片传奇之地，与捕猎、驯养野象的悠久传统紧密相连。竹制吊桥摇曳着连起江中的沙洲，埃地族、墨侬族的长屋掩映在古树之下。在跳动的火光旁，铜锣声回荡，竹竿酒杯传递于手中，西原人向你讲述森林、大象，以及大山深处那豪迈文化的故事。","facts":["以捕猎、驯养野象的传统技艺闻名。","坐落于向西逆流而上的色雷波河畔。","是拥有铜锣文化的埃地族、墨侬族、老族的聚居地。"],"travelTips":["与当地人一同体验铜锣文化与竹竿酒。","走过跨江吊桥，参观传统长屋。"],"bestTime":"11至4月，西原旱季","visitDuration":"半天","ticket":"20,000越南盾","openingHours":"07:00 – 17:00","galleryCaptions":["跨越色雷波河的竹制吊桥","西原的长屋","火旁的铜锣之夜"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dray-nur-waterfall', 'dray-nur-waterfall', 'dak-lak', 'Thác Dray Nur', 'Dray Nur Waterfall', 'waterfall', 107.9847, 12.5375, 'Thác nước hùng vĩ rộng nhất Tây Nguyên, tung bọt trắng xóa giữa đại ngàn xanh.', 'Thác Dray Nur đổ xuống như một bức tường nước khổng lồ, tiếng gầm vang dội cả một vùng. Dòng Sêrêpốk hung dữ lao mình qua vách đá, tung bọt trắng xóa, hơi nước mát lạnh phủ kín không gian. Phía sau màn nước là một hang động bí ẩn gắn với truyền thuyết tình yêu của người Ê Đê. Bao quanh thác là rừng cây xanh mướt, dây leo chằng chịt. Đứng trước Dray Nur, bạn cảm nhận trọn vẹn sức mạnh hoang dã và vẻ đẹp dữ dội của thiên nhiên Tây Nguyên.', '["Là thác nước rộng nhất Tây Nguyên, rộng khoảng 250m.","Tên ''Dray Nur'' theo tiếng Ê Đê nghĩa là ''thác cái''.","Phía sau thác có hang động lớn gắn với truyền thuyết của người Ê Đê."]', '["Mang dép chống trượt vì đường quanh thác trơn ướt.","Khám phá hang động phía sau màn nước nếu nước cạn."]', 'Tháng 6–11, mùa mưa thác cuộn nước', '2–3 giờ', '30.000đ', '07:00 – 17:00', '["hidden-gem"]', '["nature","photography"]', '[{"seed":"draynur-1","caption":"Bức tường nước tung bọt trắng","ratio":"16/9"},{"seed":"draynur-2","caption":"Dòng Sêrêpốk hùng vĩ","ratio":"4/3"}]', '["buon-don"]', 0, '{"en":{"name":"Dray Nur Waterfall","summary":"The widest, most majestic waterfall in the Central Highlands, sending up white spray amid the green wilderness.","story":"Dray Nur Waterfall tumbles down like a colossal wall of water, its roar echoing across the whole region. The fierce Serepok River hurls itself over the cliffs, throwing up white spray, with cool mist filling the air. Behind the curtain of water lies a mysterious cave tied to an Ede love legend. The falls are surrounded by lush green forest and tangled vines. Standing before Dray Nur, you feel the full wild power and fierce beauty of Central Highlands nature.","facts":["The widest waterfall in the Central Highlands, about 250m across.","The name ''Dray Nur'' means ''female waterfall'' in the Ede language.","A large cave behind the falls is tied to an Ede legend."],"travelTips":["Bring non-slip sandals as the path around the falls is wet and slippery.","Explore the cave behind the curtain of water when the water is low."],"bestTime":"June–November, the rainy season when the falls surge","visitDuration":"2–3 hours","ticket":"30,000 VND","openingHours":"07:00 – 17:00","galleryCaptions":["A wall of water throwing up white spray","The majestic Serepok River"]},"ko":{"name":"드라이누르 폭포","summary":"떠이응우옌에서 가장 넓은 웅장한 폭포로, 푸른 대자연 속에 하얀 물보라를 흩뿌립니다.","story":"드라이누르 폭포는 거대한 물의 벽처럼 쏟아져 내리며 그 굉음이 온 지역에 울려 퍼집니다. 사나운 세레폭강이 절벽으로 몸을 던져 하얀 물보라를 흩뿌리고, 차가운 물안개가 공간을 가득 채웁니다. 물 장막 뒤에는 에데족의 사랑 전설이 깃든 신비로운 동굴이 있습니다. 폭포를 둘러싼 짙푸른 숲과 얽힌 덩굴. 드라이누르 앞에 서면 떠이응우옌 자연의 야성적인 힘과 거친 아름다움을 온전히 느낄 수 있습니다.","facts":["떠이응우옌에서 가장 넓은 폭포로 폭 약 250m.","''드라이누르''는 에데어로 ''암컷 폭포''를 뜻함.","폭포 뒤에는 에데족 전설이 깃든 큰 동굴이 있음."],"travelTips":["폭포 주변 길이 미끄러우니 미끄럼 방지 샌들을 신으세요.","물이 적을 때 물 장막 뒤 동굴을 탐험해 보세요."],"bestTime":"6~11월, 폭포가 거세지는 우기","visitDuration":"2~3시간","ticket":"30,000동","openingHours":"07:00 – 17:00","galleryCaptions":["하얀 물보라를 흩뿌리는 물의 벽","웅장한 세레폭강"]},"ja":{"name":"ドライヌル滝","summary":"タイグエン高原で最も幅広く雄大な滝。緑の大自然の中に白い飛沫を散らします。","story":"ドライヌル滝は巨大な水の壁のように流れ落ち、その轟音が一帯に響き渡ります。荒々しいセレポック川が断崖へと身を投げ、白い飛沫を散らし、冷たい水煙が空間を満たします。水のとばりの奥には、エデ族の愛の伝説にまつわる神秘的な洞窟があります。滝を囲むのは青々とした森と絡み合う蔓。ドライヌルの前に立てば、タイグエン高原の自然が持つ野性的な力と荒々しい美しさを余すところなく感じられます。","facts":["タイグエン高原で最も幅広い滝で、幅約250m。","「ドライヌル」はエデ語で「雌の滝」を意味する。","滝の奥にはエデ族の伝説にまつわる大きな洞窟がある。"],"travelTips":["滝周辺の道は濡れて滑りやすいので滑り止めのサンダルを持参しましょう。","水量が少ない時には水のとばりの奥の洞窟を探検しましょう。"],"bestTime":"6〜11月、滝が激しくなる雨季","visitDuration":"2〜3時間","ticket":"30,000ドン","openingHours":"07:00 – 17:00","galleryCaptions":["白い飛沫を散らす水の壁","雄大なセレポック川"]},"zh":{"name":"德雷努瀑布","summary":"西原最宽阔、最雄伟的瀑布，在苍翠大山间溅起雪白水花。","story":"德雷努瀑布如一面巨大的水墙倾泻而下，轰鸣声回荡整片山野。狂野的色雷波河纵身越过崖壁，溅起雪白水花，清凉的水雾弥漫四周。水帘之后藏着一处神秘的洞穴，与埃地族的爱情传说相连。瀑布四周青林环绕，藤蔓交织。站在德雷努面前，你能尽情感受西原大自然那狂野的力量与磅礴的美。","facts":["西原最宽阔的瀑布，宽约250米。","「德雷努」在埃地语中意为「母瀑布」。","瀑布后方有一处大洞穴，与埃地族传说相连。"],"travelTips":["瀑布周边湿滑，请穿防滑凉鞋。","水量较少时，可探访水帘后方的洞穴。"],"bestTime":"6至11月，雨季水势磅礴","visitDuration":"2至3小时","ticket":"30,000越南盾","openingHours":"07:00 – 17:00","galleryCaptions":["溅起雪白水花的水墙","雄伟的色雷波河"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('moc-chau-plateau', 'moc-chau-plateau', 'son-la', 'Cao nguyên Mộc Châu', 'Moc Chau Plateau', 'mountain', 104.6833, 20.8333, 'Cao nguyên xanh mướt với đồi chè, rừng mận trắng và những mùa hoa nối tiếp quanh năm.', 'Mộc Châu trải ra trước mắt bạn một thảo nguyên xanh mênh mông, nơi những đồi chè uốn lượn như sóng và không khí trong lành mát rượi. Mùa xuân, hoa mận, hoa cải nở trắng cả triền đồi; mùa thu, cao nguyên ngập trong sắc dã quỳ vàng. Đàn bò sữa thong dong gặm cỏ, bản làng người Mông, Thái nép mình bên sườn núi. Một ly sữa tươi nóng giữa cái se lạnh cao nguyên, ngắm sương sớm giăng mờ trên đồi chè — Mộc Châu khiến lòng người dịu lại.', '["Cao nguyên ở độ cao trung bình khoảng 1.050m, khí hậu mát quanh năm.","Nổi tiếng với đồi chè trái tim, rừng mận Nà Ka và bò sữa Mộc Châu.","Mùa hoa mận, hoa cải trắng đẹp nhất vào tháng 11–2."]', '["Ghé đồi chè trái tim và thác Dải Yếm để chụp ảnh.","Thử bê chao, sữa tươi và bắp cải mèo đặc sản."]', 'Tháng 11–2 (mùa hoa) và tháng 9 (hoa cải)', '2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["mountain","nature","photography"]', '[{"seed":"mocchau-1","caption":"Đồi chè trái tim","ratio":"16/9"},{"seed":"mocchau-2","caption":"Rừng mận nở trắng triền đồi","ratio":"4/3"},{"seed":"mocchau-3","caption":"Sương sớm trên thảo nguyên","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Moc Chau Plateau","summary":"A lush green plateau of tea hills, white plum blossoms and flower seasons that follow one after another all year round.","story":"Moc Chau spreads before you as a vast green grassland, where tea hills roll like waves and the air is cool and fresh. In spring, plum and mustard blossoms turn the hillsides white; in autumn, the plateau is awash with the gold of wild sunflowers. Dairy cows graze leisurely, and Hmong and Thai villages nestle against the slopes. A hot glass of fresh milk in the cool highland air, watching morning mist drift over the tea hills — Moc Chau soothes the soul.","facts":["The plateau sits at an average altitude of about 1,050m, with a cool climate year-round.","Famous for its heart-shaped tea hill, the Na Ka plum forest and Moc Chau dairy cattle.","The plum and white mustard blossom season is most beautiful from November to February."],"travelTips":["Visit the heart-shaped tea hill and Dai Yem Waterfall for photos.","Try the local fried veal, fresh milk and Hmong cabbage."],"bestTime":"November–February (blossom season) and September (mustard flowers)","visitDuration":"2 days","ticket":"Free","openingHours":"All day","galleryCaptions":["The heart-shaped tea hill","Plum trees blossoming white across the hillside","Morning mist over the grassland"]},"ko":{"name":"목쩌우 고원","summary":"차밭과 하얀 매화숲, 그리고 사계절 이어지는 꽃의 계절이 가득한 푸른 고원.","story":"목쩌우는 눈앞에 광활한 초록 초원을 펼쳐 보입니다. 차밭이 파도처럼 굽이치고 공기는 시원하고 맑습니다. 봄이면 매화와 유채꽃이 언덕을 하얗게 물들이고, 가을이면 고원이 노란 들국화로 뒤덮입니다. 젖소들이 한가로이 풀을 뜯고, 몽족과 타이족 마을이 산비탈에 자리합니다. 서늘한 고원의 공기 속에서 따뜻한 생우유 한 잔을 마시며 차밭에 깔린 아침 안개를 바라보면, 목쩌우는 마음을 가라앉혀 줍니다.","facts":["고원은 평균 해발 약 1,050m로, 연중 서늘한 기후입니다.","하트 모양 차밭, 나까 매화숲, 목쩌우 젖소로 유명합니다.","매화와 하얀 유채꽃 시즌은 11~2월이 가장 아름답습니다."],"travelTips":["하트 모양 차밭과 자이옘 폭포에 들러 사진을 찍으세요.","특산물인 송아지 튀김, 생우유, 몽족 양배추를 맛보세요."],"bestTime":"11~2월(꽃 시즌)과 9월(유채꽃)","visitDuration":"2일","ticket":"무료","openingHours":"종일","galleryCaptions":["하트 모양 차밭","언덕을 하얗게 물들인 매화숲","초원의 아침 안개"]},"ja":{"name":"モクチャウ高原","summary":"茶畑と白い梅林、そして一年中続く花の季節にあふれた緑の高原。","story":"モクチャウは目の前に広大な緑の草原を広げます。茶畑が波のようにうねり、空気はひんやりと澄んでいます。春には梅やアブラナの花が丘陵を白く染め、秋には高原が黄色いツワブキで覆われます。乳牛がのんびりと草を食み、モン族やターイ族の村が山腹に寄り添います。ひんやりとした高原の空気の中、温かい搾りたての牛乳を一杯味わいながら茶畑にかかる朝霧を眺めると、モクチャウは心を和ませてくれます。","facts":["高原は平均標高約1,050メートルで、一年中涼しい気候です。","ハート形の茶畑、ナーカーの梅林、モクチャウの乳牛で有名です。","梅と白いアブラナの花の季節は11〜2月が最も美しいです。"],"travelTips":["ハート形の茶畑とザイイエム滝に立ち寄って写真を撮りましょう。","名物の子牛肉揚げ、搾りたて牛乳、モン族のキャベツを味わいましょう。"],"bestTime":"11〜2月(花の季節)と9月(アブラナの花)","visitDuration":"2日","ticket":"無料","openingHours":"終日","galleryCaptions":["ハート形の茶畑","丘陵を白く染める梅林","草原の朝霧"]},"zh":{"name":"木州高原","summary":"一片苍翠的高原，茶山起伏、白色梅林，四季花期接连不断。","story":"木州在你眼前铺展开一片辽阔的绿色草原，茶山如波浪般起伏，空气清新凉爽。春天，梅花、油菜花将山坡染成一片洁白；秋天，高原沉浸在金黄的野菊花海中。奶牛悠然吃草，苗族、泰族村寨依偎在山坡。在高原微凉中品一杯温热的鲜牛奶，凝望茶山上弥漫的晨雾——木州让人的心都柔软下来。","facts":["高原平均海拔约1050米，全年气候凉爽。","以心形茶山、那卡梅林和木州奶牛闻名。","梅花、白色油菜花季以11月至2月最为美丽。"],"travelTips":["前往心形茶山和野缨瀑布拍照。","品尝特产的炸牛犊肉、鲜牛奶和苗族卷心菜。"],"bestTime":"11月至2月（花季）和9月（油菜花）","visitDuration":"2天","ticket":"免费","openingHours":"全天","galleryCaptions":["心形茶山","梅花将山坡染成一片洁白","草原上的晨雾"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('mui-ne-sand-dunes', 'mui-ne-sand-dunes', 'binh-thuan', 'Đồi cát Mũi Né', 'Mui Ne Sand Dunes', 'beach', 108.2917, 10.9472, 'Sa mạc thu nhỏ với đồi cát vàng và cát đỏ uốn lượn, nơi hoàng hôn nhuộm cát rực rỡ.', 'Đồi cát Mũi Né như một mảnh sa mạc lạc giữa miền biển Bình Thuận. Những đụn cát vàng, cát đỏ uốn lượn vô tận, đổi hình theo gió mỗi ngày. Bình minh và hoàng hôn là lúc đẹp nhất, khi ánh nắng xiên nghiêng nhuộm cát thành màu cam đỏ huyền ảo, đổ bóng những gợn sóng cát mềm mại. Trượt cát từ đỉnh đồi xuống, để gió biển mơn man, ngắm chân trời mở rộng — Mũi Né mang đến cảm giác phiêu lưu giữa khung cảnh siêu thực hiếm có ở Việt Nam.', '["Gồm hai khu nổi tiếng: Đồi cát Bay (cát vàng) và Đồi cát Hồng (cát đỏ).","Hình dạng đụn cát thay đổi liên tục theo hướng gió.","Là điểm chụp ảnh bình minh và hoàng hôn nổi tiếng của Bình Thuận."]', '["Đi lúc sáng sớm hoặc chiều muộn để tránh nắng gắt và ngắm ánh sáng đẹp.","Thuê ván trượt cát và mang theo nước uống."]', 'Tháng 11–4, mùa khô ít mưa', '2–3 giờ', '', 'Cả ngày', '["popular","verified"]', '["beach","nature","photography"]', '[{"seed":"muine-1","caption":"Làng chài tấp nập thuyền ghe neo đậu ven biển","ratio":"16/9"},{"seed":"muine-2","caption":"Cát đỏ Mũi Né","ratio":"4/3"},{"seed":"muine-3","caption":"Trượt cát trên đỉnh đồi","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Mui Ne Sand Dunes","summary":"A miniature desert of rolling golden and red sand dunes, where sunset sets the sand ablaze.","story":"The Mui Ne sand dunes are like a patch of desert lost in the coastal land of Binh Thuan. Endless rolling dunes of golden and red sand shift their shape with the wind each day. Dawn and dusk are the most beautiful, when slanting light dyes the sand a magical orange-red and casts shadows over the soft ripples. Sliding down from the dune tops, letting the sea breeze caress you, gazing at the wide horizon — Mui Ne offers a sense of adventure amid a surreal scenery rarely found in Vietnam.","facts":["Comprises two famous areas: the Flying Dunes (golden sand) and the Pink Dunes (red sand).","The dune shapes change constantly with the wind direction.","A famous sunrise and sunset photo spot in Binh Thuan."],"travelTips":["Go in early morning or late afternoon to avoid harsh sun and catch the best light.","Rent a sandboard and bring drinking water."],"bestTime":"November–April, the dry season with little rain","visitDuration":"2–3 hours","ticket":"","openingHours":"All day","galleryCaptions":["A bustling fishing village with boats moored along the shore","The red sand of Mui Ne","Sandboarding atop the dunes"]},"ko":{"name":"무이네 사구","summary":"굽이치는 황금빛·붉은빛 사구가 펼쳐진 작은 사막으로, 노을이 모래를 붉게 물들입니다.","story":"무이네 사구는 빈투언 해안에 자리한 한 조각 사막 같습니다. 끝없이 굽이치는 황금빛·붉은빛 모래언덕은 날마다 바람을 따라 모양을 바꿉니다. 일출과 일몰이 가장 아름다워, 비스듬히 비치는 햇살이 모래를 신비로운 주황빛으로 물들이고 부드러운 모래 물결에 그림자를 드리웁니다. 모래언덕 정상에서 미끄러져 내려오며 바닷바람을 맞고 드넓은 지평선을 바라보면 — 무이네는 베트남에서 보기 드문 초현실적 풍경 속 모험을 선사합니다.","facts":["유명한 두 구역으로 구성: 화이트 사구(황금 모래)와 핑크 사구(붉은 모래).","모래언덕의 모양은 바람 방향에 따라 끊임없이 변함.","빈투언의 유명한 일출·일몰 촬영 명소."],"travelTips":["강한 햇볕을 피하고 아름다운 빛을 보려면 이른 아침이나 늦은 오후에 가세요.","모래 썰매를 빌리고 마실 물을 챙기세요."],"bestTime":"11~4월, 비가 적은 건기","visitDuration":"2~3시간","ticket":"","openingHours":"종일","galleryCaptions":["해안가에 배들이 정박한 분주한 어촌","무이네의 붉은 모래","모래언덕 정상에서의 모래 썰매"]},"ja":{"name":"ムイネー砂丘","summary":"うねる黄金と赤の砂丘が広がるミニ砂漠。夕日が砂を鮮やかに染め上げます。","story":"ムイネーの砂丘は、ビントゥアンの海辺に迷い込んだ一片の砂漠のようです。果てしなくうねる黄金と赤の砂丘は、日々風に従って形を変えます。日の出と日の入りが最も美しく、斜めに射す光が砂を幻想的なオレンジ色に染め、柔らかな砂の波紋に影を落とします。砂丘の頂から滑り降り、潮風に身を委ね、広がる地平線を眺める——ムイネーは、ベトナムでは稀なシュールな景色の中での冒険を届けてくれます。","facts":["有名な2つの区域からなる：飛ぶ砂丘（黄金の砂）とピンク砂丘（赤い砂）。","砂丘の形は風向きによって絶えず変化する。","ビントゥアンで有名な日の出・日の入りの撮影スポット。"],"travelTips":["強い日差しを避け美しい光を見るには、早朝か夕方遅くに行きましょう。","サンドボードを借り、飲み水を持参しましょう。"],"bestTime":"11〜4月、雨の少ない乾季","visitDuration":"2〜3時間","ticket":"","openingHours":"終日","galleryCaptions":["海辺に船が停泊する賑わう漁村","ムイネーの赤い砂","砂丘の頂でのサンドボーディング"]},"zh":{"name":"美奈沙丘","summary":"一片微缩沙漠，金沙与红沙的沙丘起伏蜿蜒，夕阳将沙染得绚烂夺目。","story":"美奈沙丘宛如一片误落于平顺海滨的沙漠。无尽起伏的金沙、红沙丘，每天随风变换形态。日出与日落最为动人，斜射的阳光将沙染成梦幻的橙红，为柔和的沙波投下光影。从沙丘之巅滑沙而下，任海风轻抚，眺望开阔的天际线——美奈带来一场置身越南罕有的超现实景致中的奇妙冒险。","facts":["由两处著名沙丘组成：飞沙丘（金沙）与红沙丘（红沙）。","沙丘的形态随风向不断变化。","是平顺著名的日出与日落摄影胜地。"],"travelTips":["清晨或傍晚前往，避开烈日并欣赏绝美光线。","租用滑沙板，并随身携带饮用水。"],"bestTime":"11至4月，少雨旱季","visitDuration":"2至3小时","ticket":"","openingHours":"全天","galleryCaptions":["渔船停泊岸边、热闹繁忙的渔村","美奈的红沙","在沙丘顶端滑沙"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('cai-rang-floating-market', 'cai-rang-floating-market', 'can-tho', 'Chợ nổi Cái Răng', 'Cai Rang Floating Market', 'market', 105.7639, 10.0086, 'Chợ nổi sầm uất nhất miền Tây, nơi cuộc sống sông nước hội tụ trên những ghe thuyền đầy ắp.', 'Khi trời còn tờ mờ sáng, Chợ nổi Cái Răng đã rộn ràng trên dòng sông Hậu. Hàng trăm ghe thuyền tụ về, mỗi chiếc treo lên ''cây bẹo'' cắm các loại hàng để rao bán — khóm, dưa hấu, khoai, rau củ chất đầy khoang. Tiếng máy ghe, tiếng mua bán, tiếng cười nói hòa vào nhau tạo nên bản giao hưởng sông nước đặc trưng. Ngồi trên ghe nhỏ, nhâm nhi tô hủ tiếu nóng và ly cà phê giữa chợ nổi, bạn cảm nhận trọn vẹn nhịp sống phóng khoáng, chân chất của người miền Tây.', '["Là chợ nổi lớn và sầm uất nhất Đồng bằng sông Cửu Long.","Người bán treo hàng lên ''cây bẹo'' để khách từ xa biết bán gì.","Văn hóa chợ nổi Cái Răng là Di sản văn hóa phi vật thể quốc gia."]', '["Đi từ 5–7h sáng khi chợ đông và nhộn nhịp nhất.","Thử ăn sáng trên ghe: hủ tiếu, bún và cà phê."]', 'Quanh năm; sáng sớm là đẹp nhất', 'Nửa ngày', '', '05:00 – 09:00', '["popular","verified"]', '["market","culture","food"]', '[{"seed":"cairang-1","caption":"Ghe thuyền tụ về chợ nổi sáng sớm","ratio":"16/9"},{"seed":"cairang-2","caption":"Ghe hàng treo cây bẹo dập dềnh trên sông buổi sớm","ratio":"4/3"},{"seed":"cairang-3","caption":"Người phụ nữ chèo ghe chở đầy bắp cải đi bán","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Cai Rang Floating Market","summary":"The Mekong Delta''s busiest floating market, where river life converges on boats brimming with goods.","story":"While the sky is still dim before dawn, Cai Rang Floating Market is already bustling on the Hau River. Hundreds of boats gather, each hoisting a ''beo pole'' hung with samples of its wares — pineapples, watermelons, sweet potatoes and vegetables piled high in the holds. The hum of boat engines, the bargaining and the laughter blend into the river''s signature symphony. Sitting on a small boat, savoring a hot bowl of hu tieu and a cup of coffee amid the floating market, you fully feel the free-spirited, down-to-earth rhythm of life in the Mekong Delta.","facts":["It is the largest and busiest floating market in the Mekong Delta.","Vendors hang their goods on a ''beo pole'' so buyers can see from afar what''s for sale.","The culture of Cai Rang Floating Market is a national intangible cultural heritage."],"travelTips":["Go between 5–7 a.m. when the market is most crowded and lively.","Try breakfast on a boat: hu tieu, bun and coffee."],"bestTime":"Year-round; early morning is best","visitDuration":"Half a day","ticket":"","openingHours":"05:00 – 09:00","galleryCaptions":["Boats gathering at the floating market at dawn","Vendor boats with beo poles bobbing on the river at daybreak","A woman rowing a boat laden with cabbages to sell"]},"ko":{"name":"까이랑 수상시장","summary":"메콩델타에서 가장 번화한 수상시장, 물자를 가득 실은 배 위에 강 생활이 어우러지는 곳.","story":"동트기 전 하늘이 아직 어스름할 때, 까이랑 수상시장은 이미 후강 위에서 분주합니다. 수백 척의 배가 모여들고, 저마다 ''베오 장대''를 세워 파는 물건의 견본을 매달아 둡니다 — 파인애플, 수박, 고구마, 채소가 선창에 가득합니다. 배 엔진 소리, 흥정 소리, 웃음소리가 어우러져 강 특유의 교향곡을 이룹니다. 작은 배에 앉아 따끈한 후띠에우 한 그릇과 커피 한 잔을 즐기며, 메콩델타 사람들의 자유롭고 소박한 삶의 리듬을 온전히 느낄 수 있습니다.","facts":["메콩델타에서 가장 크고 번화한 수상시장입니다.","상인들은 멀리서도 무엇을 파는지 알 수 있도록 ''베오 장대''에 물건을 매답니다.","까이랑 수상시장 문화는 국가 무형문화유산입니다."],"travelTips":["시장이 가장 붐비고 활기찬 오전 5~7시에 가세요.","배 위에서 후띠에우, 분, 커피로 아침을 즐겨 보세요."],"bestTime":"연중; 이른 아침이 가장 좋음","visitDuration":"반나절","ticket":"","openingHours":"05:00 – 09:00","galleryCaptions":["새벽 수상시장에 모여드는 배들","동틀 무렵 강 위에서 베오 장대를 단 채 출렁이는 상선들","양배추를 가득 싣고 노를 젓는 여인"]},"ja":{"name":"カイラン水上市場","summary":"メコンデルタで最も賑わう水上市場、品物を満載した舟の上に川の暮らしが集う場所。","story":"夜明け前、空がまだ薄暗いうちから、カイラン水上市場はすでにハウ川の上で賑わっています。何百艘もの舟が集まり、それぞれ「ベオ竿」を立てて売る品物の見本を吊るします — パイナップル、スイカ、サツマイモ、野菜が船倉に山と積まれています。エンジン音、値段交渉、笑い声が溶け合い、川ならではの交響曲を奏でます。小さな舟に座り、熱々のフーティウとコーヒーを水上市場の中で味わえば、メコンデルタの人々の自由で素朴な暮らしのリズムを存分に感じられます。","facts":["メコンデルタで最も大きく賑わう水上市場です。","売り手は遠くからでも何を売っているかわかるよう「ベオ竿」に品物を吊るします。","カイラン水上市場の文化は国家無形文化遺産です。"],"travelTips":["市場が最も賑わう午前5〜7時に行きましょう。","舟の上でフーティウ、ブン、コーヒーの朝食を楽しんでみましょう。"],"bestTime":"通年。早朝が最も良い","visitDuration":"半日","ticket":"","openingHours":"05:00 〜 09:00","galleryCaptions":["夜明けの水上市場に集まる舟","明け方、川の上でベオ竿を立てて揺れる商い舟","キャベツを満載して舟を漕ぐ女性"]},"zh":{"name":"丐冷水上市场","summary":"湄公河三角洲最繁华的水上市场，河上生活汇聚于满载货物的船只之上。","story":"天还蒙蒙亮时，丐冷水上市场已在后江上热闹起来。数百艘船只汇聚而来，每艘都竖起一根「吆喝竿」，挂上货样招揽生意——菠萝、西瓜、红薯、蔬菜堆满船舱。船只马达声、买卖声、谈笑声交织成河上特有的交响曲。坐在小船上，在水上市场中品一碗热腾腾的河粉、一杯咖啡，便能尽情感受湄公河三角洲人民豪爽质朴的生活节奏。","facts":["是湄公河三角洲最大、最繁华的水上市场。","卖家把货物挂在「吆喝竿」上，让远处的顾客知道卖什么。","丐冷水上市场文化是国家级非物质文化遗产。"],"travelTips":["在早晨5至7点前来，此时市场最热闹拥挤。","在船上品尝早餐：河粉、米粉和咖啡。"],"bestTime":"全年；清晨最佳","visitDuration":"半天","ticket":"","openingHours":"05:00 – 09:00","galleryCaptions":["清晨汇聚到水上市场的船只","破晓时分河上挂着吆喝竿起伏的货船","划着满载卷心菜小船的妇女"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dien-bien-phu-battlefield', 'dien-bien-phu-battlefield', 'dien-bien', 'Di tích Chiến trường Điện Biên Phủ', 'Dien Bien Phu Battlefield', 'museum', 103.0167, 21.3833, 'Chiến trường lịch sử lừng lẫy năm châu, nơi làm nên chiến thắng ''chấn động địa cầu'' năm 1954.', 'Đặt chân tới Điện Biên Phủ là chạm vào một trang sử hào hùng của dân tộc. Đồi A1 còn nguyên dấu tích chiến hào, hố bộc phá khổng lồ, nơi diễn ra trận đánh ác liệt nhất. Hầm De Castries — sở chỉ huy quân Pháp — vẫn lặng im như một chứng nhân. Bảo tàng Chiến thắng Điện Biên Phủ tái hiện sống động 56 ngày đêm ''khoét núi, ngủ hầm'' của quân và dân ta. Đứng giữa thung lũng Mường Thanh xanh mướt hôm nay, bạn cảm nhận sâu sắc giá trị của hòa bình và sự hy sinh anh dũng đã làm nên chiến thắng lừng lẫy năm châu.', '["Chiến thắng Điện Biên Phủ ngày 7/5/1954 ''lừng lẫy năm châu, chấn động địa cầu''.","Đồi A1 là điểm cao chiến lược với trận đánh khốc liệt nhất chiến dịch.","Tượng đài Chiến thắng Điện Biên Phủ là tượng đài bằng đồng lớn nhất Việt Nam."]', '["Ghé Bảo tàng, Đồi A1 và Hầm De Castries để hiểu trọn câu chuyện.","Đến dịp 7/5 để dự lễ kỷ niệm Chiến thắng Điện Biên Phủ."]', 'Tháng 3–5; dịp 7/5 lễ kỷ niệm', '1 ngày', '100.000đ', '07:00 – 17:00', '["verified","popular"]', '["history","culture","museum"]', '[{"seed":"dienbienphu-1","caption":"Tượng đài Chiến thắng Điện Biên Phủ","ratio":"16/9"},{"seed":"dienbienphu-2","caption":"Chiến hào trên Đồi A1","ratio":"4/3"},{"seed":"dienbienphu-3","caption":"Hầm De Castries","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Dien Bien Phu Battlefield Relic","summary":"A historic battlefield renowned across five continents, where the 1954 victory that ''shook the globe'' was won.","story":"To set foot in Dien Bien Phu is to touch a heroic page of the nation''s history. Hill A1 still bears the traces of trenches and the giant mine crater, where the fiercest battle took place. De Castries'' bunker — the French command post — remains silent as a witness. The Dien Bien Phu Victory Museum vividly recreates the 56 days and nights of ''carving mountains, sleeping in trenches''. Standing in the lush Muong Thanh Valley today, you feel deeply the value of peace and the heroic sacrifice that won this victory renowned across five continents.","facts":["The Dien Bien Phu victory on 7 May 1954 was ''renowned across five continents and shook the globe''.","Hill A1 was the strategic high point of the campaign''s fiercest battle.","The Dien Bien Phu Victory Monument is the largest bronze statue in Vietnam."],"travelTips":["Visit the museum, Hill A1 and De Castries'' bunker to grasp the whole story.","Come around 7 May to attend the Dien Bien Phu Victory commemoration."],"bestTime":"March–May; around 7 May for the commemoration","visitDuration":"1 day","ticket":"100,000 VND","openingHours":"07:00 – 17:00","galleryCaptions":["The Dien Bien Phu Victory Monument","Trenches on Hill A1","De Castries'' bunker"]},"ko":{"name":"디엔비엔푸 전적지","summary":"5대륙에 이름을 떨친 역사적 전장으로, 1954년 ''지구를 뒤흔든'' 승리를 이룬 곳.","story":"디엔비엔푸에 발을 들이는 것은 민족의 영웅적 역사 한 페이지에 닿는 일입니다. A1 고지에는 가장 치열한 전투가 벌어진 참호와 거대한 폭파구의 흔적이 그대로 남아 있습니다. 프랑스군 지휘소였던 드 카스트리 벙커는 증인처럼 고요히 남아 있습니다. 디엔비엔푸 승리 박물관은 ''산을 파고 참호에서 자던'' 56일 밤낮을 생생하게 재현합니다. 오늘날 푸른 므엉타인 골짜기에 서면, 평화의 가치와 5대륙에 이름을 떨친 이 승리를 이룬 영웅적 희생을 깊이 느끼게 됩니다.","facts":["1954년 5월 7일 디엔비엔푸 승리는 ''5대륙에 이름을 떨치고 지구를 뒤흔들었습니다''.","A1 고지는 작전 중 가장 치열한 전투가 벌어진 전략 고지였습니다.","디엔비엔푸 승리 기념탑은 베트남 최대의 청동상입니다."],"travelTips":["박물관, A1 고지, 드 카스트리 벙커를 둘러보며 이야기 전체를 이해하세요.","5월 7일 무렵에 방문해 디엔비엔푸 승리 기념식에 참석하세요."],"bestTime":"3~5월, 5월 7일 기념식 무렵","visitDuration":"1일","ticket":"100,000동","openingHours":"07:00 – 17:00","galleryCaptions":["디엔비엔푸 승리 기념탑","A1 고지의 참호","드 카스트리 벙커"]},"ja":{"name":"ディエンビエンフー古戦場跡","summary":"五大陸に名を轟かせた歴史的戦場。1954年、「地球を揺るがした」勝利を成し遂げた地。","story":"ディエンビエンフーに足を踏み入れることは、民族の英雄的な歴史の一頁に触れることです。A1高地には、最も激しい戦闘が繰り広げられた塹壕や巨大な爆破跡が今も残ります。フランス軍司令部だったド・カストリ壕は、証人のように静かにたたずんでいます。ディエンビエンフー勝利博物館は、「山を掘り、塹壕に眠った」56日間の昼夜を生き生きと再現しています。今日、緑のムオンタイン谷に立つと、平和の尊さと、五大陸に名を轟かせたこの勝利を成し遂げた英雄的な犠牲を深く感じます。","facts":["1954年5月7日のディエンビエンフー勝利は「五大陸に名を轟かせ、地球を揺るがしました」。","A1高地は作戦中最も激しい戦闘の戦略的高地でした。","ディエンビエンフー勝利記念碑はベトナム最大の青銅像です。"],"travelTips":["博物館、A1高地、ド・カストリ壕を巡り、物語の全容を理解しましょう。","5月7日頃に訪れ、ディエンビエンフー勝利記念式典に参加しましょう。"],"bestTime":"3〜5月、5月7日の記念式典の頃","visitDuration":"1日","ticket":"100,000ドン","openingHours":"07:00 – 17:00","galleryCaptions":["ディエンビエンフー勝利記念碑","A1高地の塹壕","ド・カストリ壕"]},"zh":{"name":"奠边府战场遗址","summary":"扬名五大洲的历史战场，1954年在此成就「震撼全球」的胜利。","story":"踏上奠边府，便是触摸民族一段壮烈的历史。A1高地上仍保留着战壕和巨大的爆破坑的痕迹，那里曾发生最激烈的战斗。德卡斯特里地堡——法军指挥部——静静矗立，宛如一位见证者。奠边府大捷博物馆生动再现了「凿山而进、宿于壕中」的56个日夜。如今站在苍翠的孟青谷中，你会深切感受到和平的珍贵，以及成就这场扬名五大洲胜利的英勇牺牲。","facts":["1954年5月7日的奠边府大捷「扬名五大洲，震撼全球」。","A1高地是战役中最激烈战斗的战略高地。","奠边府大捷纪念碑是越南最大的青铜雕像。"],"travelTips":["参观博物馆、A1高地和德卡斯特里地堡，了解完整的故事。","于5月7日前后前往，参加奠边府大捷纪念活动。"],"bestTime":"3至5月；5月7日纪念活动前后","visitDuration":"1天","ticket":"100,000越南盾","openingHours":"07:00 – 17:00","galleryCaptions":["奠边府大捷纪念碑","A1高地上的战壕","德卡斯特里地堡"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ban-gioc-waterfall', 'thac-ban-gioc', 'cao-bang', 'Thác Bản Giốc', 'Ban Gioc Waterfall', 'waterfall', 106.7227, 22.8536, 'Thác nước biên giới hùng vĩ bậc nhất Đông Nam Á, nước đổ tầng tầng giữa núi đá vôi và ruộng lúa xanh.', 'Nằm nơi địa đầu Tổ quốc, Thác Bản Giốc đổ xuống ba tầng nước trắng xóa giữa khung cảnh núi non trùng điệp của Cao Bằng. Vào mùa nước, dòng Quây Sơn cuộn chảy rộng tới hàng trăm mét, tung bọt mịt mù trong nắng tạo nên cầu vồng lung linh. Du khách thường ngồi bè tre lướt sát chân thác, cảm nhận hơi nước mát lạnh phả vào mặt. Quanh thác là những thửa ruộng bậc thang, bản làng người Tày, Nùng yên bình. Bình minh và hoàng hôn nơi đây đẹp đến nao lòng, khiến Bản Giốc trở thành biểu tượng của vùng non nước Cao Bằng.', '["Là thác nước tự nhiên lớn nhất Đông Nam Á và lớn thứ tư thế giới nằm trên đường biên giới.","Dòng sông Quây Sơn tạo thành thác, chia ranh giới tự nhiên giữa Việt Nam và Trung Quốc.","Thác cao khoảng 30m, trải rộng trên 200m với ba tầng nước.","Nằm trong Công viên địa chất toàn cầu UNESCO Non nước Cao Bằng."]', '["Đi vào tháng 9–10 khi nước nhiều và lúa chín vàng quanh thác.","Thuê bè tre để tới gần chân thác và chụp ảnh đẹp nhất."]', 'Tháng 9 đến tháng 10', 'Nửa ngày', '45.000đ', '07:00 - 17:00', '["popular","verified","trending"]', '["nature","photography","mountain"]', '[{"seed":"ban-gioc-waterfall-1","caption":"Ba tầng thác Bản Giốc mùa nước đổ","ratio":"16/9"},{"seed":"ban-gioc-waterfall-2","caption":"Du khách tắm mát dưới chân thác trắng xóa","ratio":"4/3"},{"seed":"ban-gioc-waterfall-3","caption":"Dòng thác đổ trắng xóa giữa rừng xanh","ratio":"1/1"}]', '["nguom-ngao-cave"]', 1, '{"en":{"name":"Ban Gioc Waterfall","summary":"One of the most magnificent border waterfalls in Southeast Asia, its waters cascading in tiers between limestone mountains and green rice fields.","story":"Set at the nation''s frontier, Ban Gioc Waterfall tumbles down three tiers of foaming white water amid the rolling mountains of Cao Bang. In the high-water season, the Quay Son River surges across hundreds of metres, spraying mist that catches the sun to form shimmering rainbows. Visitors often ride bamboo rafts up to the foot of the falls, feeling the cool spray on their faces. Around the falls lie terraced fields and peaceful Tay and Nung villages. Dawn and dusk here are achingly beautiful, making Ban Gioc a symbol of Cao Bang''s land of mountains and waters.","facts":["It is the largest natural waterfall in Southeast Asia and the fourth-largest in the world lying on a border.","The Quay Son River forms the falls, marking the natural boundary between Vietnam and China.","The falls are about 30m high and span over 200m across three tiers.","It lies within the Non Nuoc Cao Bang UNESCO Global Geopark."],"travelTips":["Go in September–October when the water is high and the rice ripens gold around the falls.","Rent a bamboo raft to reach the foot of the falls for the best photos."],"bestTime":"September to October","visitDuration":"Half a day","ticket":"45,000 VND","openingHours":"07:00 – 17:00","galleryCaptions":["The three tiers of Ban Gioc Waterfall in the high-water season","Visitors cooling off below the white cascade","The waterfall tumbling white amid green forest"]},"ko":{"name":"반족 폭포","summary":"동남아시아에서 손꼽히는 웅장한 국경 폭포로, 석회암 산과 푸른 논 사이로 물이 층층이 쏟아져 내리는 곳.","story":"조국의 변경에 자리한 반족 폭포는 까오방의 첩첩 산중에서 세 단으로 하얀 물줄기를 쏟아냅니다. 물이 많은 계절이면 꿰이선강이 수백 미터 너비로 굽이쳐 흐르며 햇빛 속에 물보라를 흩뿌려 영롱한 무지개를 만듭니다. 여행객들은 흔히 대나무 뗏목을 타고 폭포 발치까지 다가가 차가운 물보라를 얼굴에 맞습니다. 폭포 주변에는 계단식 논과 따이족, 눙족의 평화로운 마을이 있습니다. 이곳의 일출과 일몰은 가슴 시리도록 아름다워, 반족 폭포는 까오방 산수의 상징이 되었습니다.","facts":["동남아시아 최대이자 국경에 걸친 폭포 중 세계 4위의 자연 폭포입니다.","꿰이선강이 폭포를 이루며 베트남과 중국의 자연 경계를 나눕니다.","폭포는 높이 약 30m, 너비 200m 이상으로 세 단의 물줄기로 이루어져 있습니다.","유네스코 세계지질공원 논느억 까오방에 속해 있습니다."],"travelTips":["물이 많고 폭포 주변 벼가 노랗게 익는 9~10월에 가세요.","대나무 뗏목을 빌려 폭포 발치까지 다가가 최고의 사진을 찍으세요."],"bestTime":"9월부터 10월","visitDuration":"반나절","ticket":"45,000동","openingHours":"07:00 – 17:00","galleryCaptions":["물이 많은 계절의 반족 폭포 세 단","하얀 폭포 발치에서 더위를 식히는 여행객들","푸른 숲 사이로 하얗게 쏟아지는 폭포"]},"ja":{"name":"バンゾック滝","summary":"東南アジア屈指の雄大な国境の滝。石灰岩の山々と緑の田んぼの間を、幾段にも水が流れ落ちる場所。","story":"祖国の辺境に位置するバンゾック滝は、カオバンの連なる山々の中で三段の白い水を流れ落とします。増水期にはクイソン川が数百メートルの幅でうねり流れ、日差しの中に水しぶきを散らして煌めく虹を生み出します。旅人はよく竹の筏に乗って滝壺まで近づき、冷たい水しぶきを顔に受けます。滝の周りには棚田と、ターイ族・ヌン族の穏やかな村々が広がります。ここの日の出と日没は胸が締めつけられるほど美しく、バンゾック滝はカオバンの山水の象徴となっています。","facts":["東南アジア最大、国境にまたがる滝としては世界第4位の自然の滝です。","クイソン川が滝を形成し、ベトナムと中国の自然の境界を分けています。","滝は高さ約30メートル、幅200メートル以上で三段に分かれています。","ユネスコ世界ジオパーク「ノンヌオック・カオバン」に属します。"],"travelTips":["水量が多く、滝の周りで稲が黄金に実る9〜10月に訪れましょう。","竹の筏を借りて滝壺まで近づき、最高の写真を撮りましょう。"],"bestTime":"9月から10月","visitDuration":"半日","ticket":"45,000ドン","openingHours":"07:00 – 17:00","galleryCaptions":["増水期のバンゾック滝の三段","白い滝の麓で涼をとる旅人たち","緑の森の中を白く流れ落ちる滝"]},"zh":{"name":"板约瀑布","summary":"东南亚最雄伟的边境瀑布之一，瀑水层层跌落于石灰岩山峦与碧绿稻田之间。","story":"板约瀑布位于祖国边陲，在高平连绵起伏的群山中跌落三层雪白的瀑水。丰水季节，归春河奔涌而下，宽达数百米，在阳光中溅起迷蒙水雾，幻化出绚丽彩虹。游客常乘竹筏掠近瀑布脚下，让清凉的水雾扑面而来。瀑布四周是层层梯田和岱依族、侬族宁静的村寨。这里的日出与日落美得令人心醉，使板约瀑布成为高平山水的象征。","facts":["是东南亚最大、世界上位于边境线上第四大的天然瀑布。","归春河形成此瀑，是越南与中国的天然分界。","瀑布高约30米，宽逾200米，分三层跌落。","位于联合国教科文组织世界地质公园「高平山水」之内。"],"travelTips":["于9至10月前往，此时水量充沛、瀑布周围稻谷金黄。","租乘竹筏靠近瀑布脚下，拍摄最美的照片。"],"bestTime":"9月至10月","visitDuration":"半天","ticket":"45,000越南盾","openingHours":"07:00 – 17:00","galleryCaptions":["丰水季节板约瀑布的三层瀑水","在雪白瀑布脚下纳凉的游客","雪白瀑布在青翠山林间倾泻而下"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('nguom-ngao-cave', 'dong-nguom-ngao', 'cao-bang', 'Động Ngườm Ngao', 'Nguom Ngao Cave', 'cave', 106.7081, 22.8419, 'Hang động đá vôi kỳ ảo dài hàng cây số với vô vàn nhũ đá hình thù độc đáo, ngay cạnh Thác Bản Giốc.', 'Ẩn mình trong lòng núi bản Gun, Động Ngườm Ngao mở ra một thế giới ngầm huyền bí với những khối nhũ đá rủ xuống lấp lánh như châu báu. Tên gọi theo tiếng Tày nghĩa là ''hang hổ'', gắn với truyền thuyết xưa từng có hổ trú ngụ. Đi sâu vào lòng động, du khách gặp những măng đá hình cây tơ hồng, đài sen úp ngược, ruộng bậc thang thu nhỏ được kiến tạo qua hàng triệu năm. Không khí mát lạnh, tiếng nước nhỏ tí tách vang vọng tạo cảm giác lạc vào chốn tiên cảnh. Hệ thống đèn nghệ thuật làm nổi bật vẻ kỳ vĩ của từng phiến đá.', '["Tên ''Ngườm Ngao'' theo tiếng Tày nghĩa là động hổ.","Tổng chiều dài hệ thống hang khoảng 2.144m.","Được phát hiện năm 1921 và đưa vào khai thác du lịch từ năm 1996.","Thuộc Công viên địa chất toàn cầu UNESCO Non nước Cao Bằng."]', '["Mang giày chống trượt vì nền động ẩm ướt.","Kết hợp tham quan cùng Thác Bản Giốc chỉ cách vài cây số."]', 'Quanh năm', '1 - 2 giờ', '45.000đ', '07:30 - 17:00', '["verified","hidden-gem"]', '["nature","photography"]', '[{"seed":"nguom-ngao-cave-1","caption":"Rừng nhũ đá trong lòng động","ratio":"16/9"},{"seed":"nguom-ngao-cave-2","caption":"Măng đá hình đài sen","ratio":"4/3"},{"seed":"nguom-ngao-cave-3","caption":"Lối đi ánh đèn nghệ thuật","ratio":"1/1"}]', '["ban-gioc-waterfall"]', 0, '{"en":{"name":"Nguom Ngao Cave","summary":"A magical limestone cave stretching for kilometres with countless uniquely shaped stalactites, right next to Ban Gioc Waterfall.","story":"Hidden within the mountain of Gun village, Nguom Ngao Cave opens onto a mysterious underground world where stalactites hang down glittering like treasure. Its name means ''tiger cave'' in the Tay language, tied to an old legend that tigers once dwelt here. Deep inside, visitors encounter stone formations shaped like dodder vines, upturned lotus thrones and miniature terraced fields, sculpted over millions of years. The cool air and the soft drip of water echoing within feel like a fairyland. Artistic lighting highlights the grandeur of each stone.","facts":["''Nguom Ngao'' means tiger cave in the Tay language.","The cave system runs about 2,144m in total.","It was discovered in 1921 and opened to tourism in 1996.","It belongs to the Non Nuoc Cao Bang UNESCO Global Geopark."],"travelTips":["Wear non-slip shoes as the cave floor is damp.","Combine your visit with Ban Gioc Waterfall, just a few kilometres away."],"bestTime":"Year-round","visitDuration":"1–2 hours","ticket":"45,000 VND","openingHours":"07:30 – 17:00","galleryCaptions":["A forest of stalactites within the cave","A stone formation shaped like a lotus throne","A path lit with artistic lighting"]},"ko":{"name":"응으엄응아오 동굴","summary":"반족 폭포 바로 옆에 있는, 독특한 모양의 종유석이 가득한 수 킬로미터 길이의 환상적인 석회암 동굴.","story":"군 마을의 산속에 숨겨진 응으엄응아오 동굴은 보석처럼 반짝이며 드리워진 종유석으로 이루어진 신비로운 지하 세계를 펼쳐 보입니다. 이름은 따이족어로 ''호랑이 동굴''을 뜻하며, 예전에 호랑이가 살았다는 옛 전설과 얽혀 있습니다. 동굴 깊숙이 들어가면 새삼 덩굴 모양 석순, 거꾸로 뒤집힌 연꽃 좌대, 축소된 계단식 논 등 수백만 년에 걸쳐 빚어진 형상을 만납니다. 서늘한 공기와 똑똑 떨어지는 물소리가 메아리치며 선경에 든 듯한 느낌을 줍니다. 예술 조명이 바위 하나하나의 장엄함을 돋보이게 합니다.","facts":["''응으엄응아오''는 따이족어로 호랑이 동굴을 뜻합니다.","동굴 시스템의 총 길이는 약 2,144m입니다.","1921년에 발견되어 1996년부터 관광지로 개발되었습니다.","유네스코 세계지질공원 논느억 까오방에 속해 있습니다."],"travelTips":["동굴 바닥이 축축하므로 미끄럼 방지 신발을 신으세요.","몇 킬로미터 거리에 있는 반족 폭포와 함께 둘러보세요."],"bestTime":"연중","visitDuration":"1~2시간","ticket":"45,000동","openingHours":"07:30 – 17:00","galleryCaptions":["동굴 속 종유석의 숲","연꽃 좌대 모양의 석순","예술 조명이 비추는 통로"]},"ja":{"name":"グオムガオ洞窟","summary":"バンゾック滝のすぐそばにある、独特な形の鍾乳石で満ちた数キロにわたる幻想的な石灰岩の洞窟。","story":"グン村の山中に隠れたグオムガオ洞窟は、宝石のように煌めいて垂れ下がる鍾乳石の神秘的な地下世界を広げます。名はターイ族の言葉で「虎の洞窟」を意味し、かつて虎が棲んだという古い伝説に由来します。洞窟の奥へ進むと、ネナシカズラ形の石筍、逆さの蓮華座、ミニチュアの棚田など、数百万年かけて形作られた造形に出会います。ひんやりとした空気と、ぽたぽたと滴る水音の反響が、仙境に迷い込んだような感覚を与えます。芸術的な照明が一つ一つの岩の雄大さを際立たせます。","facts":["「グオムガオ」はターイ族の言葉で虎の洞窟を意味します。","洞窟系の総延長は約2,144メートルです。","1921年に発見され、1996年から観光地として開発されました。","ユネスコ世界ジオパーク「ノンヌオック・カオバン」に属します。"],"travelTips":["洞窟の床は湿っているので、滑りにくい靴を履きましょう。","数キロの距離にあるバンゾック滝と合わせて巡りましょう。"],"bestTime":"通年","visitDuration":"1〜2時間","ticket":"45,000ドン","openingHours":"07:30 – 17:00","galleryCaptions":["洞窟内の鍾乳石の森","蓮華座の形をした石筍","芸術的な照明が照らす通路"]},"zh":{"name":"嫩傲洞","summary":"紧邻板约瀑布、绵延数公里的奇幻石灰岩洞，洞中遍布形态各异的钟乳石。","story":"嫩傲洞隐于群村的山腹之中，展开一个神秘的地下世界，那些垂悬的钟乳石如珠宝般闪烁。其名在岱依语中意为「虎洞」，与昔日有虎栖居的古老传说相关。深入洞中，游客会遇见菟丝藤状的石笋、倒扣的莲座，以及历经数百万年雕琢而成的微缩梯田。清凉的空气与滴答回响的水声，令人仿佛误入仙境。艺术灯光衬托出每一块石头的雄奇。","facts":["「嫩傲」在岱依语中意为虎洞。","洞穴系统全长约2144米。","1921年被发现，1996年起开发为旅游景点。","属于联合国教科文组织世界地质公园「高平山水」。"],"travelTips":["洞内地面潮湿，请穿防滑鞋。","可与仅数公里之遥的板约瀑布一同游览。"],"bestTime":"全年","visitDuration":"1至2小时","ticket":"45,000越南盾","openingHours":"07:30 – 17:00","galleryCaptions":["洞中的钟乳石之林","莲座状的石笋","艺术灯光映照的通道"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ba-be-lake', 'ho-ba-be', 'bac-kan', 'Hồ Ba Bể', 'Ba Be Lake', 'lake', 105.6181, 22.4022, 'Hồ nước ngọt tự nhiên lớn nhất Việt Nam, mặt nước xanh ngắt ôm trọn núi rừng nguyên sinh Vườn quốc gia Ba Bể.', 'Giữa đại ngàn Bắc Kạn, Hồ Ba Bể trải dài như một dải lụa xanh phẳng lặng được bao bọc bởi những vách núi đá vôi và rừng nguyên sinh. Đây là hồ nước ngọt tự nhiên trên núi lớn nhất nước, hình thành cách đây hơn 200 triệu năm. Ngồi thuyền độc mộc lướt trên mặt hồ, du khách nghe tiếng chèo khua nhẹ, ngắm Ao Tiên, đảo Bà Góa và động Puông kỳ vĩ. Hai bên bờ là bản làng người Tày với những nếp nhà sàn cổ kính. Hoàng hôn buông, mặt hồ nhuộm vàng cam, đàn cò bay về tổ tạo nên khung cảnh thanh bình hiếm có.', '["Là một trong 20 hồ nước ngọt tự nhiên đẹp nhất thế giới.","Diện tích mặt hồ khoảng 650 ha, độ sâu trung bình 20–25m.","Nằm trong Vườn quốc gia Ba Bể, khu Ramsar thứ ba của Việt Nam.","Được tạo bởi ba nhánh sông nên có tên ''Ba Bể''."]', '["Đi thuyền độc mộc do người Tày chèo để khám phá lòng hồ.","Nghỉ homestay nhà sàn ở bản Pác Ngòi để trải nghiệm văn hóa địa phương."]', 'Tháng 4 đến tháng 11', '1 - 2 ngày', '25.000đ', '06:00 - 18:00', '["popular","verified","trending"]', '["nature","photography","culture"]', '[{"seed":"ba-be-lake-1","caption":"Thuyền độc mộc trên hồ Ba Bể","ratio":"16/9"},{"seed":"ba-be-lake-2","caption":"Mặt hồ lấp lánh ôm đảo nhỏ trong sương sớm","ratio":"4/3"},{"seed":"ba-be-lake-3","caption":"Hồ nước phẳng lặng giữa núi non mờ sương","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Ba Be Lake","summary":"Vietnam''s largest natural freshwater lake, its blue waters embracing the primeval forest of Ba Be National Park.","story":"Amid the great forests of Bac Kan, Ba Be Lake stretches like a calm ribbon of blue silk, framed by limestone cliffs and primeval forest. It is the country''s largest natural mountain freshwater lake, formed over 200 million years ago. Riding a dugout canoe across the lake, visitors hear the gentle splash of the paddle while gazing at the Fairy Pond, Widow Island and the magnificent Puong Cave. Along both banks lie Tay villages with their ancient stilt houses. As dusk falls, the lake turns golden-orange and flocks of storks return to roost, creating a rare scene of peace.","facts":["It is one of the 20 most beautiful natural freshwater lakes in the world.","The lake covers about 650 hectares, with an average depth of 20–25m.","It lies within Ba Be National Park, Vietnam''s third Ramsar site.","It was formed by three river branches, hence the name ''Ba Be'' (three lakes)."],"travelTips":["Take a dugout canoe paddled by Tay locals to explore the lake.","Stay in a stilt-house homestay in Pac Ngoi village to experience local culture."],"bestTime":"April to November","visitDuration":"1–2 days","ticket":"25,000 VND","openingHours":"06:00 – 18:00","galleryCaptions":["A dugout canoe on Ba Be Lake","The shimmering lake embracing a small island in the morning mist","The still lake amid mist-shrouded mountains"]},"ko":{"name":"바베 호수","summary":"베트남 최대의 자연 담수호로, 푸른 물이 바베 국립공원의 원시림을 온전히 감싸 안은 곳.","story":"박깐의 깊은 산중에서 바베 호수는 석회암 절벽과 원시림에 둘러싸여 잔잔한 푸른 비단처럼 펼쳐집니다. 이곳은 2억 년 전에 형성된, 산 위의 자연 담수호 중 베트남 최대 규모입니다. 통나무배를 타고 호수 위를 미끄러지면 노 젓는 소리가 들리고, 선녀 연못, 과부 섬, 웅장한 뿌옹 동굴을 감상할 수 있습니다. 양쪽 기슭에는 고풍스러운 수상가옥을 가진 따이족 마을이 있습니다. 노을이 지면 호수가 황금빛 주황으로 물들고 백로 떼가 둥지로 돌아와 보기 드문 평화로운 풍경을 자아냅니다.","facts":["세계에서 가장 아름다운 20대 자연 담수호 중 하나입니다.","호수 면적은 약 650헥타르, 평균 수심은 20~25m입니다.","베트남의 세 번째 람사르 습지인 바베 국립공원에 속해 있습니다.","세 갈래 강이 만들어 ''바베(세 호수)''라는 이름이 붙었습니다."],"travelTips":["따이족이 노 젓는 통나무배를 타고 호수를 탐험하세요.","빡응오이 마을의 수상가옥 홈스테이에 묵으며 현지 문화를 체험하세요."],"bestTime":"4월부터 11월","visitDuration":"1~2일","ticket":"25,000동","openingHours":"06:00 – 18:00","galleryCaptions":["바베 호수 위의 통나무배","아침 안개 속 작은 섬을 감싸 안고 반짝이는 호수","안개 낀 산 사이의 잔잔한 호수"]},"ja":{"name":"バーベー湖","summary":"ベトナム最大の自然淡水湖。青い水がバーベー国立公園の原生林をすっぽりと抱きしめる場所。","story":"バックカンの深い山中で、バーベー湖は石灰岩の絶壁と原生林に囲まれ、静かな青い絹のように広がります。ここは2億年以上前に形成された、山上の自然淡水湖としてベトナム最大の規模です。丸木舟で湖を滑ると、櫂の音が聞こえ、仙女の池、未亡人島、雄大なプオン洞窟を眺められます。両岸には、古風な高床式家屋を持つターイ族の村が広がります。夕暮れには湖が黄金の橙色に染まり、鷺の群れが巣へ帰り、稀に見る穏やかな光景を生み出します。","facts":["世界で最も美しい20の自然淡水湖の一つです。","湖の面積は約650ヘクタール、平均水深は20〜25メートルです。","ベトナム第3のラムサール条約登録地、バーベー国立公園に属します。","三つの川の流れが形作ったため「バーベー(三つの湖)」と名付けられました。"],"travelTips":["ターイ族が漕ぐ丸木舟に乗って湖を探検しましょう。","パックゴイ村の高床式ホームステイに泊まり、地元文化を体験しましょう。"],"bestTime":"4月から11月","visitDuration":"1〜2日","ticket":"25,000ドン","openingHours":"06:00 – 18:00","galleryCaptions":["バーベー湖の丸木舟","朝霧の中、小島を抱いて煌めく湖面","霧に包まれた山々の間の静かな湖"]},"zh":{"name":"巴贝湖","summary":"越南最大的天然淡水湖，碧蓝的湖水将巴贝国家公园的原始森林尽数环抱。","story":"在北𣴓的莽莽群山之中，巴贝湖如一条平静的蓝色绸带铺展开来，四周被石灰岩绝壁和原始森林环绕。这是越南最大的山上天然淡水湖，形成于两亿多年前。乘独木舟掠过湖面，游客可听见轻轻的桨声，眺望仙池、寡妇岛和雄奇的蓬洞。两岸是岱依族村寨，古朴的高脚屋错落其间。暮色降临，湖面染成金橙，白鹭归巢，构成一幅难得的宁静画卷。","facts":["是世界上20个最美的天然淡水湖之一。","湖面面积约650公顷，平均水深20至25米。","位于巴贝国家公园内，是越南第三个拉姆萨尔湿地。","由三条河流汇成，故名「巴贝（三湖）」。"],"travelTips":["乘坐岱依族人划的独木舟探索湖区。","在白俄村的高脚屋民宿留宿，体验当地文化。"],"bestTime":"4月至11月","visitDuration":"1至2天","ticket":"25,000越南盾","openingHours":"06:00 – 18:00","galleryCaptions":["巴贝湖上的独木舟","晨雾中环抱小岛、波光粼粼的湖面","薄雾笼罩的群山间平静的湖泊"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tam-thanh-cave', 'dong-tam-thanh', 'lang-son', 'Động Tam Thanh', 'Tam Thanh Cave', 'cave', 106.7558, 21.8567, 'Động đá vôi linh thiêng giữa lòng thành phố Lạng Sơn, nổi tiếng với chùa cổ trong hang và ''Đệ nhất bát cảnh xứ Lạng''.', 'Nằm trong dãy núi đá vôi ngay giữa phố phường Lạng Sơn, Động Tam Thanh từ lâu được mệnh danh là ''Đệ nhất bát cảnh xứ Lạng''. Bước qua cổng đá, du khách lạc vào không gian linh thiêng với ngôi chùa Tam Thanh được tạc thẳng vào vách hang từ thời Lê. Bên trong, tượng Phật A Di Đà khắc nổi trên đá, hồ Âm Ti nước trong vắt quanh năm và những khối thạch nhũ buông rủ huyền ảo. Qua khe núi, du khách phóng tầm mắt ngắm ''cửa trời'' đón ánh sáng tự nhiên. Tiếng chuông chùa ngân vang trong động tạo nên cảm giác tĩnh tại, thiêng liêng giữa lòng thành phố biên cương.', '["Được người xưa xếp vào ''Trấn doanh bát cảnh'' của xứ Lạng.","Chùa Tam Thanh trong động được xây dựng từ thời nhà Lê.","Có bức phù điêu tượng Phật A Di Đà tạc vào vách đá cao gần 2m.","Trong động có hồ Âm Ti nước không bao giờ cạn."]', '["Ghé thăm cùng nàng Tô Thị và thành nhà Mạc ngay gần đó.","Đi buổi sáng để ánh sáng từ ''cửa trời'' đẹp nhất."]', 'Quanh năm', '1 - 2 giờ', '20.000đ', '07:00 - 18:00', '["verified","popular"]', '["culture","history","nature"]', '[{"seed":"tam-thanh-cave-1","caption":"Chùa cổ trong động Tam Thanh","ratio":"16/9"},{"seed":"tam-thanh-cave-2","caption":"Phù điêu Phật A Di Đà trên vách đá","ratio":"4/3"},{"seed":"tam-thanh-cave-3","caption":"Cửa trời đón nắng","ratio":"1/1"}]', '["mau-son-mountain"]', 1, '{"en":{"name":"Tam Thanh Cave","summary":"A sacred limestone cave in the heart of Lang Son city, famous for its ancient cave temple and as the ''finest of the eight scenic wonders of Lang''.","story":"Set in a limestone range right in the heart of Lang Son city, Tam Thanh Cave has long been hailed as the ''finest of the eight scenic wonders of Lang''. Stepping through the stone gate, visitors enter a sacred space with the Tam Thanh Temple carved straight into the cave wall in the Le dynasty. Inside, a relief of Amitabha Buddha is etched into the rock, the Am Ti Pond stays crystal-clear year-round, and ethereal stalactites hang down. Through a crevice, visitors gaze at the ''gate of heaven'' that lets in natural light. The temple bell echoing through the cave brings a sense of stillness and sanctity in the heart of this frontier city.","facts":["The ancients counted it among the ''eight scenic wonders of the Lang garrison''.","The Tam Thanh Temple within the cave was built in the Le dynasty.","It holds a relief of Amitabha Buddha carved into the rock, nearly 2m tall.","The cave contains the Am Ti Pond, whose waters never run dry."],"travelTips":["Visit together with the To Thi statue and the Mac dynasty citadel nearby.","Go in the morning when the light from the ''gate of heaven'' is most beautiful."],"bestTime":"Year-round","visitDuration":"1–2 hours","ticket":"20,000 VND","openingHours":"07:00 – 18:00","galleryCaptions":["The ancient temple within Tam Thanh Cave","The relief of Amitabha Buddha on the rock wall","The gate of heaven catching the sunlight"]},"ko":{"name":"땀타인 동굴","summary":"랑선시 한복판에 자리한 신성한 석회암 동굴로, 동굴 속 고찰과 ''랑 지방 제일의 절경''으로 유명한 곳.","story":"랑선시 한복판 석회암 산자락에 자리한 땀타인 동굴은 오래전부터 ''랑 지방 제일의 절경''으로 불려 왔습니다. 돌문을 지나면 레 왕조 때 동굴 벽에 직접 새긴 땀타인 사원이 있는 신성한 공간으로 들어섭니다. 안에는 바위에 양각된 아미타불상, 사계절 맑은 음티 연못, 그리고 환상적으로 드리워진 종유석이 있습니다. 바위 틈새로는 자연광을 받아들이는 ''천문(天門)''을 바라볼 수 있습니다. 동굴 안에 울려 퍼지는 사찰의 종소리는 변경 도시 한복판에서 고요하고 신성한 느낌을 자아냅니다.","facts":["옛사람들이 랑 지방의 ''진영팔경(鎭營八景)''에 꼽았습니다.","동굴 속 땀타인 사원은 레 왕조 때 지어졌습니다.","바위에 새긴 높이 약 2m의 아미타불 부조가 있습니다.","동굴 안에는 결코 마르지 않는 음티 연못이 있습니다."],"travelTips":["바로 근처의 또티 상과 막 왕조 성과 함께 둘러보세요.","''천문''의 빛이 가장 아름다운 오전에 가세요."],"bestTime":"연중","visitDuration":"1~2시간","ticket":"20,000동","openingHours":"07:00 – 18:00","galleryCaptions":["땀타인 동굴 속 고찰","바위 벽의 아미타불 부조","햇빛을 받아들이는 천문"]},"ja":{"name":"タムタイン洞窟","summary":"ランソン市の中心にある聖なる石灰岩の洞窟。洞窟内の古寺と「ラン地方随一の絶景」で名高い場所。","story":"ランソン市の中心にある石灰岩の山裾に位置するタムタイン洞窟は、古くから「ラン地方随一の絶景」と称えられてきました。石の門をくぐると、レ朝の時代に洞窟の壁に直接彫られたタムタイン寺のある聖なる空間に入ります。内には岩に浮き彫りされた阿弥陀仏像、一年中澄んだアムティ池、そして幻想的に垂れ下がる鍾乳石があります。岩の隙間からは、自然光を取り込む「天門」を眺められます。洞窟内に響く寺の鐘の音は、辺境の街の中心で静寂と神聖さを醸し出します。","facts":["古人によりラン地方の「鎮営八景」に数えられました。","洞窟内のタムタイン寺はレ朝の時代に建てられました。","岩に彫られた高さ約2メートルの阿弥陀仏の浮き彫りがあります。","洞窟内には決して涸れることのないアムティ池があります。"],"travelTips":["すぐ近くのトーティ像とマック朝の城と合わせて巡りましょう。","「天門」の光が最も美しい午前中に訪れましょう。"],"bestTime":"通年","visitDuration":"1〜2時間","ticket":"20,000ドン","openingHours":"07:00 – 18:00","galleryCaptions":["タムタイン洞窟内の古寺","岩壁の阿弥陀仏の浮き彫り","日差しを取り込む天門"]},"zh":{"name":"三清洞","summary":"谅山市中心一座神圣的石灰岩洞，以洞中古寺和「谅地八景之首」闻名。","story":"三清洞坐落于谅山市中心的石灰岩山中，自古被誉为「谅地八景之首」。穿过石门，游客便步入一处神圣空间，黎朝时期直接凿于洞壁的三清寺便在其中。洞内有岩壁上浮雕的阿弥陀佛像、终年清澈的阴司潭，以及奇幻垂悬的钟乳石。透过山缝，游客可眺望迎入自然光的「天门」。寺中钟声在洞内回响，在这座边境城市的中心营造出一种宁静而神圣的氛围。","facts":["古人将其列入谅地的「镇营八景」。","洞中的三清寺建于黎朝时期。","有一尊凿于岩壁、高近2米的阿弥陀佛浮雕。","洞中有终年不涸的阴司潭。"],"travelTips":["可与近旁的苏氏望夫石和莫朝城一同游览。","于上午前往，此时「天门」的光线最为优美。"],"bestTime":"全年","visitDuration":"1至2小时","ticket":"20,000越南盾","openingHours":"07:00 – 18:00","galleryCaptions":["三清洞中的古寺","岩壁上的阿弥陀佛浮雕","迎入阳光的天门"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('mau-son-mountain', 'nui-mau-son', 'lang-son', 'Núi Mẫu Sơn', 'Mau Son Mountain', 'mountain', 107.0228, 21.8581, 'Đỉnh núi mây phủ quanh năm, nơi hiếm hoi miền Bắc có băng tuyết mùa đông và những đồi đào, chè cổ thụ.', 'Cao hơn 1.500m so với mực nước biển, Mẫu Sơn là vùng núi mây mù bao phủ quanh năm nơi biên giới Lạng Sơn. Mùa đông, nhiệt độ có khi xuống dưới 0 độ, băng giá phủ trắng cây cối tạo nên cảnh tượng kỳ ảo hiếm thấy ở miền Bắc. Trên đỉnh núi còn dấu tích những biệt thự nghỉ dưỡng cổ thời Pháp rêu phong giữa biển mây. Người Dao đỏ sinh sống nơi đây gìn giữ nghề thuốc tắm lá truyền thống và những vườn đào, chè cổ thụ. Du khách lên Mẫu Sơn để săn mây, ngắm bình minh và thưởng thức gà sáu cựa, rượu Mẫu Sơn nồng ấm.', '["Gồm khoảng 80 ngọn núi lớn nhỏ, đỉnh cao nhất hơn 1.500m.","Là một trong số ít nơi miền Bắc xuất hiện băng tuyết vào mùa đông.","Nổi tiếng với rượu Mẫu Sơn ủ men lá của người Dao.","Còn lưu giữ phế tích biệt thự nghỉ dưỡng từ thời Pháp thuộc."]', '["Mang áo ấm dày kể cả mùa hè vì đỉnh núi rất lạnh.","Trải nghiệm tắm lá thuốc của người Dao đỏ để thư giãn."]', 'Tháng 12 đến tháng 2', '1 ngày', '', 'Cả ngày', '["hidden-gem","verified"]', '["mountain","nature","photography"]', '[{"seed":"mau-son-mountain-1","caption":"Biển mây trên đỉnh Mẫu Sơn","ratio":"16/9"},{"seed":"mau-son-mountain-2","caption":"Băng giá phủ trắng cây mùa đông","ratio":"4/3"},{"seed":"mau-son-mountain-3","caption":"Phế tích biệt thự Pháp cổ","ratio":"1/1"}]', '["tam-thanh-cave"]', 0, '{"en":{"name":"Mau Son Mountain","summary":"A peak shrouded in cloud all year, one of the rare places in the north to see winter ice and frost, with peach orchards and ancient tea trees.","story":"Rising over 1,500m above sea level, Mau Son is a mountain region cloaked in cloud all year on the Lang Son border. In winter, temperatures can drop below zero, and frost coats the trees white in a magical scene rarely seen in the north. On the summit remain the moss-covered ruins of old French-era villas amid a sea of clouds. The Red Dao people who live here preserve their traditional herbal-bath craft and their orchards of peach and ancient tea trees. Visitors climb Mau Son to chase the clouds, watch the sunrise and savour six-spurred chicken and the warming Mau Son wine.","facts":["It comprises about 80 peaks large and small, the highest over 1,500m.","It is one of the few places in the north where ice and frost appear in winter.","Famous for Mau Son wine, fermented with leaf yeast by the Dao people.","It still holds the ruins of resort villas from the French colonial era."],"travelTips":["Bring a thick warm jacket even in summer, as the summit is very cold.","Try the Red Dao people''s herbal bath to relax."],"bestTime":"December to February","visitDuration":"1 day","ticket":"Free","openingHours":"All day","galleryCaptions":["A sea of clouds atop Mau Son","Frost coating the trees white in winter","The ruins of an old French villa"]},"ko":{"name":"머우선 산","summary":"연중 구름에 덮인 봉우리로, 북부에서 보기 드물게 겨울에 얼음과 서리가 내리며 복숭아밭과 오래된 차나무가 있는 곳.","story":"해발 1,500m가 넘는 머우선은 랑선 국경에서 연중 구름에 덮인 산악 지대입니다. 겨울이면 기온이 영하로 떨어지기도 하고, 서리가 나무를 하얗게 덮어 북부에서 보기 드문 환상적인 풍경을 자아냅니다. 정상에는 구름 바다 속에 이끼 낀 프랑스 시대의 옛 휴양 별장 터가 남아 있습니다. 이곳에 사는 붉은 자오족은 전통 약초 목욕 풍습과 복숭아밭, 오래된 차나무 정원을 지켜 오고 있습니다. 여행객들은 머우선에 올라 구름을 보고 일출을 감상하며 발가락이 여섯 개인 닭과 따뜻한 머우선 술을 즐깁니다.","facts":["크고 작은 약 80개의 봉우리로 이루어졌으며, 최고봉은 1,500m가 넘습니다.","북부에서 겨울에 얼음과 서리가 나타나는 몇 안 되는 곳 중 하나입니다.","자오족이 잎 누룩으로 빚는 머우선 술로 유명합니다.","프랑스 식민지 시대의 휴양 별장 폐허가 여전히 남아 있습니다."],"travelTips":["정상이 매우 추우니 여름에도 두꺼운 외투를 챙기세요.","붉은 자오족의 약초 목욕을 체험하며 휴식을 취하세요."],"bestTime":"12월부터 2월","visitDuration":"1일","ticket":"무료","openingHours":"종일","galleryCaptions":["머우선 정상의 구름 바다","겨울에 나무를 하얗게 덮은 서리","옛 프랑스 별장의 폐허"]},"ja":{"name":"マウソン山","summary":"一年中雲に覆われた峰。北部では稀に冬に氷と霜が降り、桃畑や古い茶の木がある場所。","story":"標高1,500メートルを超えるマウソンは、ランソン国境で一年中雲に覆われた山地です。冬には気温が氷点下に下がることもあり、霜が木々を白く覆い、北部では稀に見る幻想的な光景を生み出します。山頂には、雲海の中に苔むしたフランス時代の古い保養別荘の跡が残ります。ここに暮らす赤ザオ族は、伝統的な薬草風呂の風習と、桃畑や古い茶の木の庭を守り続けています。旅人はマウソンに登って雲を眺め、日の出を見て、六本指の鶏や温かいマウソン酒を楽しみます。","facts":["大小約80の峰からなり、最高峰は1,500メートルを超えます。","北部で冬に氷と霜が現れる数少ない場所の一つです。","ザオ族が葉麹で醸すマウソン酒で有名です。","フランス植民地時代の保養別荘の廃墟が今も残ります。"],"travelTips":["山頂は非常に寒いので、夏でも厚い上着を持参しましょう。","赤ザオ族の薬草風呂を体験してくつろぎましょう。"],"bestTime":"12月から2月","visitDuration":"1日","ticket":"無料","openingHours":"終日","galleryCaptions":["マウソン山頂の雲海","冬に木々を白く覆う霜","古いフランス別荘の廃墟"]},"zh":{"name":"母山","summary":"终年云雾缭绕的山峰，是北部少有的冬季会结冰霜之地，山上有桃园和古老的茶树。","story":"母山海拔超过1500米，是谅山边境一片终年云雾笼罩的山区。冬季气温有时降至零度以下，冰霜将树木覆成一片洁白，构成北部罕见的奇幻景象。山顶还残留着法国时期古老度假别墅的遗迹，斑驳地伫立于云海之中。居住于此的红瑶族守护着传统的草药沐浴技艺，以及桃园和古老的茶树。游客登母山追云、赏日出，品尝六趾鸡和暖人的母山酒。","facts":["由约80座大小山峰组成，最高峰逾1500米。","是北部少数冬季会出现冰霜的地方之一。","以瑶族用叶曲酿造的母山酒闻名。","至今仍保留着法国殖民时期度假别墅的遗迹。"],"travelTips":["即便夏天也请带上厚外套，因为山顶非常寒冷。","体验红瑶族的草药沐浴，舒缓身心。"],"bestTime":"12月至2月","visitDuration":"1天","ticket":"免费","openingHours":"全天","galleryCaptions":["母山之巅的云海","冬季将树木覆成一片洁白的冰霜","古老法国别墅的遗迹"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tan-trao-relic', 'khu-di-tich-tan-trao', 'tuyen-quang', 'Khu di tích Tân Trào', 'Tan Trao Historical Site', 'village', 105.4017, 21.8472, 'Thủ đô kháng chiến giữa rừng Tuyên Quang, nơi gắn liền cây đa Tân Trào, lán Nà Nưa và Quốc dân Đại hội năm 1945.', 'Giữa đại ngàn Tuyên Quang, Tân Trào được khắc ghi như ''Thủ đô khu giải phóng'' của cách mạng Việt Nam. Dưới bóng cây đa Tân Trào cổ thụ, Việt Nam Giải phóng quân từng làm lễ xuất quân tiến về giải phóng Thái Nguyên năm 1945. Cách đó không xa là lán Nà Nưa đơn sơ bằng tre nứa, nơi Chủ tịch Hồ Chí Minh sống và làm việc trong những ngày tiền khởi nghĩa. Đình Tân Trào lưu dấu Quốc dân Đại hội lịch sử. Đến đây, du khách lặng mình giữa rừng cọ, đồi chè, lắng nghe câu chuyện hào hùng của một thời dựng nước giữa núi rừng Việt Bắc.', '["Là nơi diễn ra Quốc dân Đại hội tháng 8 năm 1945.","Cây đa Tân Trào là nơi Việt Nam Giải phóng quân làm lễ xuất quân.","Lán Nà Nưa là nơi Bác Hồ ở và làm việc năm 1945.","Được xếp hạng Di tích quốc gia đặc biệt."]', '["Thuê hướng dẫn viên để hiểu trọn vẹn câu chuyện lịch sử.","Kết hợp tham quan các điểm trong cụm di tích bằng xe điện."]', 'Quanh năm', 'Nửa ngày', '', '07:00 - 17:00', '["verified","popular"]', '["history","culture"]', '[{"seed":"tan-trao-relic-1","caption":"Cây đa Tân Trào cổ thụ","ratio":"16/9"},{"seed":"tan-trao-relic-2","caption":"Lán Nà Nưa giữa rừng","ratio":"4/3"},{"seed":"tan-trao-relic-3","caption":"Đình Tân Trào lịch sử","ratio":"1/1"}]', '["mo-na-hang-waterfall"]', 1, '{"en":{"name":"Tan Trao Relic Site","summary":"The resistance capital amid the forests of Tuyen Quang, tied to the Tan Trao banyan tree, the Na Nua hut and the 1945 National Congress.","story":"Amid the great forests of Tuyen Quang, Tan Trao is enshrined as the ''capital of the liberated zone'' of the Vietnamese revolution. Beneath the ancient Tan Trao banyan tree, the Vietnam Liberation Army once held its departure ceremony before marching to liberate Thai Nguyen in 1945. Not far away stands the simple bamboo Na Nua hut, where President Ho Chi Minh lived and worked in the days before the uprising. The Tan Trao communal house bears the mark of the historic National Congress. Here, visitors fall silent among palm forests and tea hills, listening to the heroic story of a nation-building era in the mountains of the Viet Bac.","facts":["It was the site of the National Congress in August 1945.","The Tan Trao banyan tree was where the Vietnam Liberation Army held its departure ceremony.","The Na Nua hut was where Uncle Ho lived and worked in 1945.","It is ranked as a Special National Relic."],"travelTips":["Hire a guide to fully understand the historical story.","Use an electric cart to visit the sites within the relic cluster."],"bestTime":"Year-round","visitDuration":"Half a day","ticket":"Free","openingHours":"07:00 – 17:00","galleryCaptions":["The ancient Tan Trao banyan tree","The Na Nua hut amid the forest","The historic Tan Trao communal house"]},"ko":{"name":"떤짜오 유적지","summary":"뚜옌꽝의 숲속 항전 수도로, 떤짜오 보리수, 나느어 오두막, 1945년 국민대회와 얽힌 곳.","story":"뚜옌꽝의 깊은 숲속에서 떤짜오는 베트남 혁명의 ''해방구 수도''로 새겨져 있습니다. 오래된 떤짜오 보리수 아래에서 베트남 해방군은 1945년 타이응우옌 해방을 위해 진군하기 전 출정식을 열었습니다. 멀지 않은 곳에는 대나무로 지은 소박한 나느어 오두막이 있는데, 호찌민 주석이 봉기 직전 이곳에서 생활하며 일했습니다. 떤짜오 정자에는 역사적인 국민대회의 흔적이 남아 있습니다. 이곳에서 여행객은 종려나무 숲과 차밭 사이에서 고요히 머물며, 비엣박 산중에서 펼쳐진 건국의 영웅적 이야기에 귀 기울입니다.","facts":["1945년 8월 국민대회가 열린 곳입니다.","떤짜오 보리수는 베트남 해방군이 출정식을 연 곳입니다.","나느어 오두막은 1945년 호 아저씨가 머물며 일하던 곳입니다.","특별 국가 유적으로 지정되었습니다."],"travelTips":["역사 이야기를 온전히 이해하려면 가이드를 고용하세요.","유적 단지 내 명소들을 전동차로 둘러보세요."],"bestTime":"연중","visitDuration":"반나절","ticket":"무료","openingHours":"07:00 – 17:00","galleryCaptions":["오래된 떤짜오 보리수","숲속의 나느어 오두막","역사적인 떤짜오 정자"]},"ja":{"name":"タンチャオ遺跡群","summary":"トゥエンクアンの森の中の抗戦の首都。タンチャオの菩提樹、ナーヌア小屋、1945年の国民大会にゆかりの地。","story":"トゥエンクアンの深い森の中で、タンチャオはベトナム革命の「解放区の首都」として刻まれています。古いタンチャオの菩提樹の下で、ベトナム解放軍は1945年にタイグエン解放へ進軍する前の出陣式を行いました。そこから遠くない場所には竹造りの素朴なナーヌア小屋があり、ホー・チ・ミン主席が蜂起直前の日々をここで過ごし働きました。タンチャオの集会所には歴史的な国民大会の跡が残ります。ここで旅人は、ヤシの森と茶畑の間で静かにたたずみ、ベトバックの山中で繰り広げられた建国の英雄的な物語に耳を傾けます。","facts":["1945年8月の国民大会が開かれた地です。","タンチャオの菩提樹はベトナム解放軍が出陣式を行った場所です。","ナーヌア小屋は1945年にホーおじさんが滞在し働いた場所です。","特別国家遺跡に指定されています。"],"travelTips":["歴史の物語を余すところなく理解するため、ガイドを雇いましょう。","遺跡群内の名所を電動カートで巡りましょう。"],"bestTime":"通年","visitDuration":"半日","ticket":"無料","openingHours":"07:00 – 17:00","galleryCaptions":["古いタンチャオの菩提樹","森の中のナーヌア小屋","歴史的なタンチャオの集会所"]},"zh":{"name":"新潮遗址区","summary":"宣光森林中的抗战首都，与新潮榕树、那纳棚屋和1945年国民大会紧密相连。","story":"在宣光的莽莽森林中，新潮被铭记为越南革命的「解放区首都」。在古老的新潮榕树下，越南解放军曾在1945年挺进解放太原前举行誓师仪式。不远处是一座以竹子搭成的简朴的那纳棚屋，胡志明主席曾在起义前夕在此生活与工作。新潮亭留有历史性国民大会的印记。来到这里，游客在棕榈林与茶山间静静伫立，聆听越北山林间一段建国的壮烈故事。","facts":["是1945年8月国民大会的召开地。","新潮榕树是越南解放军举行誓师仪式的地方。","那纳棚屋是胡伯伯1945年生活与工作的地方。","被列为特别国家遗迹。"],"travelTips":["雇一名导游，以充分了解这段历史故事。","乘电瓶车游览遗迹群内的各个景点。"],"bestTime":"全年","visitDuration":"半天","ticket":"免费","openingHours":"07:00 – 17:00","galleryCaptions":["古老的新潮榕树","森林中的那纳棚屋","历史性的新潮亭"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('mo-na-hang-waterfall', 'thac-mo-na-hang', 'tuyen-quang', 'Thác Mơ Nà Hang', 'Mo Na Hang Waterfall', 'waterfall', 105.3839, 22.3389, 'Dòng thác trắng mềm mại đổ từ đỉnh núi Pắc Ban, ẩn mình giữa rừng nguyên sinh và hồ thủy điện xanh ngắt Nà Hang.', 'Nép mình dưới chân núi Pắc Ban giữa khu bảo tồn thiên nhiên Nà Hang, Thác Mơ tuôn chảy như dải lụa trắng vắt ngang sườn núi xanh thẫm. Đi qua con đường rừng rợp bóng cây, du khách bắt gặp dòng nước mát lành đổ qua nhiều tầng đá, tạo nên những hồ nước trong vắt để tắm mát. Truyền thuyết kể về đôi trai gái yêu nhau hóa thành dòng thác, khiến nơi đây thêm phần thơ mộng. Kết hợp đi thuyền trên hồ thủy điện Nà Hang xanh biếc, ngắm những vách núi soi bóng nước, hành trình tới Thác Mơ là một trải nghiệm thiên nhiên trong trẻo, đậm chất núi rừng Tuyên Quang.', '["Thác bắt nguồn từ đỉnh núi Pắc Ban cao gần 1.000m.","Nằm trong Khu bảo tồn thiên nhiên Nà Hang - Lâm Bình.","Gắn với truyền thuyết tình yêu đôi trai gái hóa dòng thác.","Thường kết hợp với tour du thuyền hồ thủy điện Nà Hang."]', '["Đi vào mùa mưa để thác nhiều nước và hùng vĩ nhất.","Kết hợp du thuyền ngắm hồ Nà Hang và núi Pắc Tạ."]', 'Tháng 5 đến tháng 9', 'Nửa ngày', '', '07:00 - 18:00', '["hidden-gem","verified"]', '["nature","photography","mountain"]', '[{"seed":"mo-na-hang-waterfall-1","caption":"Thác Mơ buông xuống sườn núi","ratio":"16/9"},{"seed":"mo-na-hang-waterfall-2","caption":"Hồ nước trong dưới chân thác","ratio":"4/3"},{"seed":"mo-na-hang-waterfall-3","caption":"Du thuyền hồ Nà Hang","ratio":"1/1"}]', '["tan-trao-relic"]', 0, '{"en":{"name":"Mo Na Hang Waterfall","summary":"A soft white waterfall tumbling from the peak of Pac Ban Mountain, hidden among primeval forest and the blue Na Hang hydropower lake.","story":"Nestled at the foot of Pac Ban Mountain within the Na Hang Nature Reserve, Mo Waterfall flows like a ribbon of white silk draped across the dark green slope. Along a shaded forest path, visitors meet the cool water tumbling over many tiers of rock, forming crystal-clear pools for a refreshing dip. A legend tells of a young couple in love who turned into the waterfall, lending the place an added romance. Combined with a boat ride on the blue-green Na Hang hydropower lake, gazing at cliffs mirrored in the water, the journey to Mo Waterfall is a clear, refreshing nature experience steeped in the mountain spirit of Tuyen Quang.","facts":["The falls originate from the peak of Pac Ban Mountain, nearly 1,000m high.","It lies within the Na Hang – Lam Binh Nature Reserve.","It is tied to the legend of a young couple in love who turned into the waterfall.","It is often combined with a cruise tour of the Na Hang hydropower lake."],"travelTips":["Go in the rainy season when the falls are at their fullest and most magnificent.","Combine it with a cruise to view Na Hang Lake and Pac Ta Mountain."],"bestTime":"May to September","visitDuration":"Half a day","ticket":"Free","openingHours":"07:00 – 18:00","galleryCaptions":["Mo Waterfall tumbling down the mountainside","A clear pool at the foot of the falls","A cruise on Na Hang Lake"]},"ko":{"name":"나항 모 폭포","summary":"빡반산 정상에서 흘러내리는 부드러운 하얀 폭포로, 원시림과 푸른 나항 수력발전 호수 사이에 숨어 있는 곳.","story":"나항 자연보호구역 안 빡반산 기슭에 자리한 모 폭포는 짙푸른 산비탈에 드리운 하얀 비단처럼 흘러내립니다. 나무 그늘이 드리운 숲길을 지나면, 여러 단의 바위를 따라 흘러내려 멱 감기 좋은 맑은 웅덩이를 이루는 시원한 물줄기를 만납니다. 서로 사랑하던 젊은 남녀가 폭포로 변했다는 전설이 이곳에 한층 낭만을 더합니다. 짙푸른 나항 수력발전 호수에서 배를 타고 물에 비친 절벽을 바라보는 일정과 어우러져, 모 폭포로 가는 여정은 뚜옌꽝 산수의 정취가 가득한 맑고 청량한 자연 체험이 됩니다.","facts":["폭포는 해발 약 1,000m의 빡반산 정상에서 발원합니다.","나항-럼빈 자연보호구역에 속해 있습니다.","젊은 남녀가 폭포로 변했다는 사랑 전설과 얽혀 있습니다.","흔히 나항 수력발전 호수 크루즈 투어와 함께 즐깁니다."],"travelTips":["폭포에 물이 가장 많고 웅장한 우기에 가세요.","나항 호수와 빡따산을 감상하는 크루즈와 함께 즐기세요."],"bestTime":"5월부터 9월","visitDuration":"반나절","ticket":"무료","openingHours":"07:00 – 18:00","galleryCaptions":["산비탈로 흘러내리는 모 폭포","폭포 발치의 맑은 웅덩이","나항 호수 크루즈"]},"ja":{"name":"ナーハン・モー滝","summary":"パックバン山の頂から流れ落ちる柔らかな白い滝。原生林と青いナーハン水力発電湖の間に隠れた場所。","story":"ナーハン自然保護区のパックバン山の麓に佇むモー滝は、深緑の山腹に掛かる白い絹のように流れ落ちます。木陰の続く森の道を抜けると、幾段もの岩を伝って流れ落ち、水浴びに適した澄んだ淵を作る冷たい水流に出会います。愛し合った若い男女が滝に姿を変えたという伝説が、この地に一層の浪漫を添えます。青緑のナーハン水力発電湖で船に乗り、水に映る絶壁を眺める行程と相まって、モー滝への旅はトゥエンクアンの山水の趣にあふれた、清らかで爽やかな自然体験となります。","facts":["滝は標高約1,000メートルのパックバン山の頂を源とします。","ナーハン・ラムビン自然保護区に属します。","若い男女が滝に姿を変えたという恋の伝説にゆかりがあります。","よくナーハン水力発電湖のクルーズツアーと合わせて楽しまれます。"],"travelTips":["滝の水量が最も多く雄大になる雨季に訪れましょう。","ナーハン湖とパックター山を眺めるクルーズと合わせて楽しみましょう。"],"bestTime":"5月から9月","visitDuration":"半日","ticket":"無料","openingHours":"07:00 – 18:00","galleryCaptions":["山腹を流れ落ちるモー滝","滝の麓の澄んだ淵","ナーハン湖のクルーズ"]},"zh":{"name":"那杭梦瀑布","summary":"从北班山顶倾泻而下的柔美白瀑，隐于原始森林与碧绿的那杭水电湖之间。","story":"梦瀑布依偎在那杭自然保护区北班山脚下，如一条白绸般垂挂于深绿的山坡。沿着绿荫如盖的林间小路前行，游客会遇见这股清凉的水流，它越过层层岩石跌落，形成一汪汪可供戏水的清澈水潭。一对相爱的青年男女化作瀑布的传说，为此地更添几分诗意。再与碧绿的那杭水电湖游船相结合，凝望倒映水中的绝壁，前往梦瀑布的旅程便成为一次清澈爽朗、饱含宣光山水气韵的自然体验。","facts":["瀑布发源于海拔近1000米的北班山顶。","位于那杭—林平自然保护区内。","与青年男女化作瀑布的爱情传说相关。","通常与那杭水电湖的游船之旅相结合。"],"travelTips":["于雨季前往，此时瀑布水量充沛、最为雄伟。","可与游览那杭湖和北沱山的游船相结合。"],"bestTime":"5月至9月","visitDuration":"半天","ticket":"免费","openingHours":"07:00 – 18:00","galleryCaptions":["垂落山坡的梦瀑布","瀑布脚下的清澈水潭","那杭湖游船"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('nui-coc-lake', 'ho-nui-coc', 'thai-nguyen', 'Hồ Núi Cốc', 'Nui Coc Lake', 'lake', 105.7236, 21.5439, 'Hồ nước thơ mộng với hàng chục hòn đảo nhỏ, gắn liền huyền thoại nàng Công - chàng Cốc và những đồi chè bát ngát.', 'Hồ Núi Cốc trải rộng mênh mông dưới chân dãy Tam Đảo, mặt nước xanh êm điểm xuyết hàng chục đảo nhỏ nhấp nhô như tranh thủy mặc. Hồ gắn liền truyền thuyết tình yêu bi thương của nàng Công và chàng Cốc, nước mắt nàng chảy thành dòng sông Công tạo nên hồ. Du khách lên thuyền dạo quanh các đảo Cò, đảo Núi Cái, ghé khu du lịch với động Huyền Thoại Cung và những công trình mô phỏng câu chuyện tình. Bao quanh hồ là đồi chè Thái Nguyên ngút ngàn, nơi sản sinh thứ trà thơm nức tiếng. Buổi sớm sương giăng trên mặt hồ tạo nên khung cảnh huyền ảo, lãng mạn.', '["Là hồ nhân tạo hình thành từ đập sông Công, hoàn thành năm 1978.","Lòng hồ có hơn 89 hòn đảo lớn nhỏ.","Gắn với huyền thoại tình yêu nàng Công - chàng Cốc.","Nằm gần vùng chè đặc sản Tân Cương nổi tiếng."]', '["Đi thuyền dạo quanh các đảo nhỏ trên hồ.","Kết hợp thưởng trà tại các đồi chè Tân Cương lân cận."]', 'Tháng 4 đến tháng 9', 'Nửa ngày đến 1 ngày', '50.000đ', '07:00 - 18:00', '["popular","verified"]', '["nature","culture","photography"]', '[{"seed":"nui-coc-lake-1","caption":"Đảo nhỏ giữa lòng hồ Núi Cốc","ratio":"16/9"},{"seed":"nui-coc-lake-2","caption":"Sương sớm trên mặt hồ","ratio":"4/3"},{"seed":"nui-coc-lake-3","caption":"Thuyền dạo quanh hồ","ratio":"1/1"}]', '["tan-cuong-tea-hills"]', 1, '{"en":{"name":"Nui Coc Lake","summary":"A poetic lake dotted with dozens of small islands, tied to the legend of Lady Cong and Mr Coc and surrounded by boundless tea hills.","story":"Nui Coc Lake spreads vast beneath the Tam Dao range, its calm blue waters dotted with dozens of small islands rising like an ink-wash painting. The lake is tied to the tragic love legend of Lady Cong and Mr Coc, whose tears flowed into the Cong River that formed the lake. Visitors take a boat around Co Island and Nui Cai Island, stopping at the resort with the Legend Cave and structures recreating the love story. Around the lake roll the endless tea hills of Thai Nguyen, birthplace of its famously fragrant tea. In the early morning, mist drifts over the water to create a magical, romantic scene.","facts":["It is a man-made lake formed by damming the Cong River, completed in 1978.","The lake holds more than 89 islands large and small.","It is tied to the love legend of Lady Cong and Mr Coc.","It lies near the famous Tan Cuong specialty tea region."],"travelTips":["Take a boat around the small islands on the lake.","Combine it with tea tasting at the nearby Tan Cuong tea hills."],"bestTime":"April to September","visitDuration":"Half a day to 1 day","ticket":"50,000 VND","openingHours":"07:00 – 18:00","galleryCaptions":["A small island in the heart of Nui Coc Lake","Morning mist over the water","A boat cruising around the lake"]},"ko":{"name":"누이꼭 호수","summary":"수십 개의 작은 섬이 점점이 떠 있는 시적인 호수로, 꽁 낭자와 꼭 총각의 전설과 드넓은 차밭이 얽힌 곳.","story":"누이꼭 호수는 땀다오 산맥 아래로 광활하게 펼쳐지며, 잔잔한 푸른 수면에 수십 개의 작은 섬이 수묵화처럼 점점이 솟아 있습니다. 호수는 꽁 낭자와 꼭 총각의 비극적인 사랑 전설과 얽혀 있는데, 낭자의 눈물이 꽁강이 되어 호수를 이루었다고 합니다. 여행객은 배를 타고 꼬 섬, 누이까이 섬을 돌고, 전설 동굴과 사랑 이야기를 재현한 구조물이 있는 관광지에 들릅니다. 호수를 둘러싼 타이응우옌의 끝없는 차밭은 이름난 향긋한 차를 길러냅니다. 이른 아침 안개가 수면에 깔리면 환상적이고 낭만적인 풍경이 펼쳐집니다.","facts":["꽁강을 막아 만든 인공 호수로, 1978년에 완공되었습니다.","호수 안에는 크고 작은 89개가 넘는 섬이 있습니다.","꽁 낭자와 꼭 총각의 사랑 전설과 얽혀 있습니다.","유명한 떤끄엉 특산 차 산지 인근에 있습니다."],"travelTips":["배를 타고 호수의 작은 섬들을 돌아보세요.","인근 떤끄엉 차밭에서의 차 시음과 함께 즐기세요."],"bestTime":"4월부터 9월","visitDuration":"반나절에서 1일","ticket":"50,000동","openingHours":"07:00 – 18:00","galleryCaptions":["누이꼭 호수 한가운데의 작은 섬","수면 위의 아침 안개","호수를 도는 배"]},"ja":{"name":"ヌイコック湖","summary":"数十の小島が点在する詩情あふれる湖。コン姫とコック青年の伝説と、広大な茶畑にゆかりの場所。","story":"ヌイコック湖はタムダオ山脈の麓に広大に広がり、穏やかな青い水面に数十の小島が水墨画のように点在します。湖は、コン姫とコック青年の悲しい恋の伝説にゆかりがあり、姫の涙がコン川となって流れ、湖を形作ったといいます。旅人は船でコー島、ヌイカイ島を巡り、伝説の洞窟や恋物語を再現した施設のある観光地に立ち寄ります。湖を囲むタイグエンの果てしない茶畑は、名高い芳しい茶を育みます。早朝、霧が水面に立ちこめ、幻想的で浪漫的な光景が広がります。","facts":["コン川をせき止めて造られた人造湖で、1978年に完成しました。","湖内には大小89を超える島があります。","コン姫とコック青年の恋の伝説にゆかりがあります。","有名なタンクオン特産の茶の産地の近くにあります。"],"travelTips":["船で湖の小島を巡りましょう。","近くのタンクオン茶畑での茶の試飲と合わせて楽しみましょう。"],"bestTime":"4月から9月","visitDuration":"半日から1日","ticket":"50,000ドン","openingHours":"07:00 – 18:00","galleryCaptions":["ヌイコック湖の中ほどの小島","水面の朝霧","湖を巡る船"]},"zh":{"name":"𡶀谷湖","summary":"一座点缀着数十座小岛的诗意湖泊，与公娘和谷郎的传说以及无垠茶山紧密相连。","story":"𡶀谷湖在三岛山脉脚下辽阔铺展，平静碧蓝的湖面上点缀着数十座起伏的小岛，宛如一幅水墨画。湖泊与公娘和谷郎的凄美爱情传说相连，相传公娘的泪水化作公河，汇成此湖。游客乘船环游鹭岛、𡶀蓋岛，并前往设有「传说宫」洞和重现爱情故事的建筑的旅游区。环湖是太原无垠的茶山，孕育着远近闻名的香茗。清晨薄雾笼罩湖面，构成一幅奇幻而浪漫的景象。","facts":["是拦截公河而成的人工湖，1978年建成。","湖中有89座以上的大小岛屿。","与公娘和谷郎的爱情传说相连。","邻近著名的新疆特产茶区。"],"travelTips":["乘船环游湖上的小岛。","可与邻近新疆茶山的品茶之行相结合。"],"bestTime":"4月至9月","visitDuration":"半天至1天","ticket":"50,000越南盾","openingHours":"07:00 – 18:00","galleryCaptions":["𡶀谷湖中央的小岛","湖面上的清晨薄雾","环游湖区的船只"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tan-cuong-tea-hills', 'doi-che-tan-cuong', 'thai-nguyen', 'Đồi chè Tân Cương', 'Tan Cuong Tea Hills', 'park', 105.7619, 21.55, 'Vùng đất ''đệ nhất danh trà'' với những đồi chè xanh mướt uốn lượn, nơi sản sinh trà Thái Nguyên trứ danh cả nước.', 'Cách thành phố Thái Nguyên không xa, Tân Cương hiện ra với những đồi chè xanh mướt trải dài, uốn lượn mềm mại như sóng dưới ánh nắng ban mai. Đây là cái nôi của trà Thái Nguyên, thứ ''đệ nhất danh trà'' với hương cốm thanh tao và vị chát dịu hậu ngọt đặc trưng. Du khách dạo bước giữa các luống chè, ngắm những người nông dân khéo léo hái búp non, rồi ghé thăm xưởng sao trà để tận mắt chứng kiến quy trình thủ công truyền thống. Một chén trà nóng nhâm nhi giữa đồi chè bát ngát, gió mát lành thổi qua, là trải nghiệm bình yên khó quên nơi miền trung du Thái Nguyên.', '["Tân Cương được mệnh danh là vùng ''đệ nhất danh trà'' của Việt Nam.","Cây chè được trồng tại đây từ những năm 1920.","Trà Tân Cương nổi tiếng với hương cốm và vị chát hậu ngọt.","Có Không gian văn hóa trà giới thiệu nghề làm trà truyền thống."]', '["Đến sáng sớm để ngắm đồi chè còn đọng sương.","Ghé hộ làm trà để xem sao trà và mua trà chính gốc."]', 'Tháng 3 đến tháng 5', 'Nửa ngày', '', 'Cả ngày', '["verified","hidden-gem"]', '["nature","food","photography"]', '[{"seed":"tan-cuong-tea-hills-1","caption":"Đồi chè xanh mướt uốn lượn","ratio":"16/9"},{"seed":"tan-cuong-tea-hills-2","caption":"Hái búp chè non buổi sớm","ratio":"4/3"},{"seed":"tan-cuong-tea-hills-3","caption":"Chén trà giữa đồi chè","ratio":"1/1"}]', '["nui-coc-lake"]', 0, '{"en":{"name":"Tan Cuong Tea Hills","summary":"The land of the ''finest tea'', with lush rolling tea hills that produce the nation''s renowned Thai Nguyen tea.","story":"Not far from Thai Nguyen city, Tan Cuong reveals lush green tea hills rolling softly like waves in the morning sun. This is the cradle of Thai Nguyen tea, the ''finest tea'' with its delicate green-rice aroma and a mild astringency with a sweet aftertaste. Visitors stroll among the rows of tea, watching farmers deftly pick the young buds, then visit a tea-roasting workshop to witness the traditional handcrafted process. A hot cup of tea savoured amid the boundless tea hills, with a cool breeze blowing through, is an unforgettably peaceful experience in the midlands of Thai Nguyen.","facts":["Tan Cuong is hailed as the land of Vietnam''s ''finest tea''.","Tea has been grown here since the 1920s.","Tan Cuong tea is famous for its green-rice aroma and sweet-aftertaste astringency.","It has a Tea Culture Space introducing the traditional tea-making craft."],"travelTips":["Come early in the morning to see the tea hills still dewy.","Visit a tea-making household to watch tea roasting and buy authentic tea."],"bestTime":"March to May","visitDuration":"Half a day","ticket":"Free","openingHours":"All day","galleryCaptions":["Lush green rolling tea hills","Picking young tea buds in the morning","A cup of tea amid the tea hills"]},"ko":{"name":"떤끄엉 차밭","summary":"''제일 명차''의 고장으로, 푸르게 굽이치는 차밭이 전국적으로 이름난 타이응우옌 차를 길러내는 곳.","story":"타이응우옌시에서 멀지 않은 떤끄엉은 아침 햇살 속에 파도처럼 부드럽게 굽이치는 푸른 차밭을 펼쳐 보입니다. 이곳은 타이응우옌 차의 요람으로, 은은한 햅쌀 향과 부드러운 떫은맛 뒤에 단맛이 감도는 ''제일 명차''입니다. 여행객은 차밭 이랑 사이를 거닐며 농부들이 솜씨 있게 어린 순을 따는 모습을 보고, 차 덖는 작업장에 들러 전통 수제 공정을 직접 봅니다. 드넓은 차밭에서 시원한 바람을 맞으며 따뜻한 차 한 잔을 음미하는 것은 타이응우옌 중부 구릉지에서의 잊지 못할 평화로운 체험입니다.","facts":["떤끄엉은 베트남 ''제일 명차''의 고장으로 불립니다.","이곳에서는 1920년대부터 차나무를 재배해 왔습니다.","떤끄엉 차는 햅쌀 향과 단맛이 감도는 떫은맛으로 유명합니다.","전통 제차 기술을 소개하는 차 문화 공간이 있습니다."],"travelTips":["이슬 머금은 차밭을 보려면 이른 아침에 가세요.","차 만드는 농가에 들러 차 덖는 모습을 보고 정통 차를 사세요."],"bestTime":"3월부터 5월","visitDuration":"반나절","ticket":"무료","openingHours":"종일","galleryCaptions":["푸르게 굽이치는 차밭","이른 아침 어린 찻순 따기","차밭 한가운데의 차 한 잔"]},"ja":{"name":"タンクオン茶畑","summary":"「随一の名茶」の里。緑にうねる茶畑が、全国に名高いタイグエン茶を育む場所。","story":"タイグエン市から遠くないタンクオンは、朝日の中で波のように柔らかくうねる緑の茶畑を広げます。ここはタイグエン茶の揺りかごで、ほのかな新米の香りと、まろやかな渋みの後に甘みが残る「随一の名茶」です。旅人は茶畑の畝の間を歩き、農夫が手際よく若芽を摘む様子を眺め、茶を炒る作業場に立ち寄って伝統的な手作業の工程を間近に見ます。広大な茶畑で涼やかな風を受けながら温かい一杯の茶を味わうことは、タイグエンの中部丘陵での忘れがたい穏やかな体験です。","facts":["タンクオンはベトナム「随一の名茶」の里と称されます。","ここでは1920年代から茶の木が栽培されてきました。","タンクオン茶は新米の香りと、甘い後味の渋みで有名です。","伝統的な製茶の技を紹介する茶文化空間があります。"],"travelTips":["露を含んだ茶畑を見るため、早朝に訪れましょう。","茶づくりの農家に立ち寄り、茶を炒る様子を見て本物の茶を買いましょう。"],"bestTime":"3月から5月","visitDuration":"半日","ticket":"無料","openingHours":"終日","galleryCaptions":["緑にうねる茶畑","早朝の若い茶芽摘み","茶畑の中の一杯の茶"]},"zh":{"name":"新疆茶山","summary":"「天下第一名茶」之乡，苍翠茶山蜿蜒起伏，孕育出全国闻名的太原茶。","story":"距太原市不远的新疆，呈现出一片苍翠的茶山，在晨光中如波浪般柔和起伏、绵延铺展。这里是太原茶的摇篮，那「天下第一名茶」带着清雅的青米香，入口微涩、回味甘甜，独具一格。游客漫步于茶垄之间，看农人灵巧地采摘嫩芽，再走进炒茶作坊，亲眼见证传统的手工工艺。在无垠茶山间品一杯热茶，凉风拂过，是太原中游丘陵地带一段难忘的宁静体验。","facts":["新疆被誉为越南「天下第一名茶」之乡。","此地自20世纪20年代起便种植茶树。","新疆茶以青米香和回甘的微涩闻名。","设有茶文化空间，介绍传统制茶技艺。"],"travelTips":["清晨前往，观赏挂着露珠的茶山。","走访制茶农户，观看炒茶并购买正宗好茶。"],"bestTime":"3月至5月","visitDuration":"半天","ticket":"免费","openingHours":"全天","galleryCaptions":["苍翠蜿蜒的茶山","清晨采摘嫩茶芽","茶山间的一杯香茗"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('den-hung-temple', 'den-hung', 'phu-tho', 'Đền Hùng', 'Hung Kings Temple', 'temple', 105.3239, 21.3658, 'Khu di tích thiêng liêng thờ các Vua Hùng trên núi Nghĩa Lĩnh, cội nguồn dân tộc và nơi diễn ra Giỗ Tổ Hùng Vương.', 'Tọa lạc trên núi Nghĩa Lĩnh, Khu di tích Đền Hùng là nơi cội nguồn thiêng liêng của dân tộc Việt, thờ các Vua Hùng đã có công dựng nước. Từ chân núi, du khách leo qua hàng trăm bậc đá rợp bóng cây cổ thụ, lần lượt viếng Đền Hạ, Đền Trung, Đền Thượng rồi tới Lăng Vua Hùng. Mỗi ngôi đền cổ kính phủ rêu phong là một dấu son trong truyền thuyết dựng nước. Vào ngày mùng 10 tháng 3 âm lịch, hàng triệu người con đất Việt hành hương về đây dự Giỗ Tổ, dâng hương tưởng nhớ tổ tiên. Câu ca ''Dù ai đi ngược về xuôi, nhớ ngày Giỗ Tổ mùng mười tháng ba'' vang vọng ngàn đời.', '["Thờ 18 đời Vua Hùng, được coi là quốc tổ của người Việt.","Tín ngưỡng thờ cúng Hùng Vương được UNESCO ghi danh Di sản văn hóa phi vật thể năm 2012.","Giỗ Tổ Hùng Vương diễn ra ngày mùng 10 tháng 3 âm lịch hằng năm.","Khu di tích trải trên núi Nghĩa Lĩnh với hệ thống Đền Hạ, Trung, Thượng."]', '["Đến dịp Giỗ Tổ mùng 10/3 âm lịch để dự lễ hội lớn nhất.","Mặc trang phục lịch sự và chuẩn bị sức khỏe để leo bậc đá."]', 'Tháng 3 âm lịch', 'Nửa ngày', '', '06:00 - 18:00', '["unesco","festival","verified","popular"]', '["temple","history","culture"]', '[{"seed":"den-hung-temple-1","caption":"Đền Thượng trên núi Nghĩa Lĩnh","ratio":"16/9"},{"seed":"den-hung-temple-2","caption":"Bậc đá rợp bóng cây cổ thụ","ratio":"4/3"},{"seed":"den-hung-temple-3","caption":"Dòng người hành hương Giỗ Tổ","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Hung Kings Temple","summary":"A sacred relic site honouring the Hung Kings on Nghia Linh Mountain, the cradle of the nation and home of the Hung Kings'' Commemoration.","story":"Set on Nghia Linh Mountain, the Hung Kings Temple is the sacred cradle of the Vietnamese people, honouring the Hung Kings who founded the nation. From the foot of the mountain, visitors climb hundreds of stone steps shaded by ancient trees, paying respects in turn at the Lower, Middle and Upper Temples before reaching the Hung Kings'' Tomb. Each moss-covered ancient temple is a milestone in the legend of nation-building. On the 10th day of the third lunar month, millions of Vietnamese make a pilgrimage here for the Commemoration, offering incense to their ancestors. The folk verse ''Wherever you go, remember the Ancestors'' Day, the tenth of the third month'' echoes through the ages.","facts":["It honours 18 generations of Hung Kings, regarded as the founding ancestors of the Vietnamese.","The worship of the Hung Kings was inscribed by UNESCO as Intangible Cultural Heritage in 2012.","The Hung Kings'' Commemoration takes place on the 10th day of the third lunar month each year.","The relic site spans Nghia Linh Mountain with its Lower, Middle and Upper Temples."],"travelTips":["Come for the Ancestors'' Day on the 10th of the third lunar month for the biggest festival.","Dress respectfully and be prepared for the climb up the stone steps."],"bestTime":"The third lunar month","visitDuration":"Half a day","ticket":"Free","openingHours":"06:00 – 18:00","galleryCaptions":["The Upper Temple on Nghia Linh Mountain","Stone steps shaded by ancient trees","The stream of pilgrims at the Commemoration"]},"ko":{"name":"훙왕 사당","summary":"응이아린산에서 훙왕들을 모시는 신성한 유적지로, 민족의 근원이자 훙왕 기일 제사가 열리는 곳.","story":"응이아린산에 자리한 훙왕 사당은 건국 공로를 세운 훙왕들을 모시는, 베트남 민족의 신성한 근원입니다. 산기슭에서부터 여행객은 오래된 나무 그늘이 드리운 수백 개의 돌계단을 올라 하사당, 중사당, 상사당을 차례로 참배하고 훙왕릉에 이릅니다. 이끼 낀 고풍스러운 사당 하나하나가 건국 전설의 이정표입니다. 음력 3월 10일이면 수백만 베트남 후손이 이곳으로 순례를 와 제사에 참여하고 조상께 향을 올립니다. ''어디를 오가든 음력 3월 10일 조상 기일을 기억하라''는 민요가 천 년을 두고 울려 퍼집니다.","facts":["베트남인의 시조로 여겨지는 18대 훙왕을 모십니다.","훙왕 숭배 신앙은 2012년 유네스코 무형문화유산으로 등재되었습니다.","훙왕 기일 제사는 매년 음력 3월 10일에 열립니다.","유적지는 응이아린산에 걸쳐 하·중·상 사당 체계를 이룹니다."],"travelTips":["가장 큰 축제를 보려면 음력 3월 10일 조상 기일에 맞춰 오세요.","단정한 옷차림을 하고 돌계단을 오를 체력을 준비하세요."],"bestTime":"음력 3월","visitDuration":"반나절","ticket":"무료","openingHours":"06:00 – 18:00","galleryCaptions":["응이아린산의 상사당","오래된 나무 그늘이 드리운 돌계단","조상 기일에 순례하는 인파"]},"ja":{"name":"フン王廟","summary":"ギアリン山でフン王を祀る聖なる遺跡。民族の起源であり、フン王命日祭が行われる場所。","story":"ギアリン山に位置するフン王廟は、建国の功を立てたフン王を祀る、ベトナム民族の聖なる起源です。山麓から、旅人は古木の木陰が続く数百段の石段を登り、下廟、中廟、上廟を順に参拝し、フン王陵へと至ります。苔むした古風な廟一つ一つが、建国伝説の道標です。旧暦3月10日には、数百万のベトナムの子孫がここへ巡礼に訪れ、祭に参加し、祖先に線香を捧げます。「どこを行き来しようとも、旧暦3月10日の祖先の命日を忘れるな」という民謡が、千年を越えて響き渡ります。","facts":["ベトナム人の始祖とされる18代のフン王を祀ります。","フン王崇拝の信仰は2012年にユネスコ無形文化遺産に登録されました。","フン王命日祭は毎年旧暦3月10日に行われます。","遺跡はギアリン山にまたがり、下・中・上廟の体系をなします。"],"travelTips":["最大の祭を見るため、旧暦3月10日の祖先の命日に合わせて訪れましょう。","礼儀正しい服装をし、石段を登る体力を準備しましょう。"],"bestTime":"旧暦3月","visitDuration":"半日","ticket":"無料","openingHours":"06:00 – 18:00","galleryCaptions":["ギアリン山の上廟","古木の木陰が続く石段","命日祭に巡礼する人々の流れ"]},"zh":{"name":"雄王庙","summary":"义岭山上供奉雄王的神圣遗迹，是民族的根源，也是雄王祭祖大典的举办地。","story":"坐落于义岭山的雄王庙，是越南民族神圣的根源，供奉着开国有功的历代雄王。从山脚起，游客登上数百级古树掩映的石阶，依次拜谒下庙、中庙、上庙，最后抵达雄王陵。每一座斑驳古朴的庙宇，都是建国传说中的一个印记。每逢农历三月初十，数百万越南儿女前来朝圣、参加祭典、上香缅怀祖先。「无论南来北往，勿忘三月初十祭祖之日」的民谣千古回响。","facts":["供奉被尊为越南人始祖的18代雄王。","雄王崇拜信仰于2012年被联合国教科文组织列为非物质文化遗产。","雄王祭祖大典于每年农历三月初十举行。","遗迹区横跨义岭山，设有下、中、上庙体系。"],"travelTips":["于农历三月初十祭祖之日前往，参加最盛大的庆典。","请着装得体，并做好攀登石阶的体力准备。"],"bestTime":"农历三月","visitDuration":"半天","ticket":"免费","openingHours":"06:00 – 18:00","galleryCaptions":["义岭山上的上庙","古树掩映的石阶","祭祖大典上朝圣的人流"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tay-yen-tu', 'tay-yen-tu', 'bac-giang', 'Tây Yên Tử', 'Tay Yen Tu', 'mountain', 106.725, 21.1789, 'Sườn tây dãy Yên Tử với hệ thống chùa chiền, cáp treo lên chùa Đồng và con đường hoằng dương Phật pháp của Phật hoàng Trần Nhân Tông.', 'Nằm trên sườn tây dãy núi Yên Tử thuộc Bắc Giang, Khu du lịch tâm linh Tây Yên Tử là cửa ngõ tìm về cõi Phật giữa rừng già nguyên sinh. Đây chính là con đường mà Phật hoàng Trần Nhân Tông cùng các thiền sư xưa kia hoằng dương Phật pháp, dựng nên hệ thống chùa tháp dọc sườn núi. Du khách đi cáp treo vượt rừng trúc, suối thác để lên chùa Thượng, chùa Đồng linh thiêng trên đỉnh non thiêng. Không gian chùa Hạ, chùa Trung mới được tôn tạo nguy nga giữa thiên nhiên hùng vĩ. Hành hương Tây Yên Tử, lòng người như lắng lại giữa tiếng chuông chùa và mây núi bồng bềnh.', '["Là sườn tây của dãy Yên Tử, gắn với Thiền phái Trúc Lâm.","Gắn liền hành trình tu hành của Phật hoàng Trần Nhân Tông.","Có tuyến cáp treo đưa du khách lên gần đỉnh chùa Đồng.","Nằm trong quần thể di tích và danh thắng Yên Tử."]', '["Đi lễ hội xuân Tây Yên Tử khai hội đầu năm âm lịch.","Kết hợp đi cáp treo và leo bộ để cảm nhận trọn vẹn không gian."]', 'Tháng 1 đến tháng 3 âm lịch', '1 ngày', '', '06:00 - 18:00', '["festival","verified","trending"]', '["temple","mountain","culture"]', '[{"seed":"tay-yen-tu-1","caption":"Cáp treo vượt rừng lên đỉnh núi","ratio":"16/9"},{"seed":"tay-yen-tu-2","caption":"Chùa giữa mây núi Tây Yên Tử","ratio":"4/3"},{"seed":"tay-yen-tu-3","caption":"Lễ hội xuân Tây Yên Tử","ratio":"1/1"}]', '["vinh-nghiem-pagoda"]', 1, '{"en":{"name":"Tay Yen Tu","summary":"The western slope of the Yen Tu range, with its temples, a cable car up to Dong Pagoda, and the Buddhist path of Buddha-King Tran Nhan Tong.","story":"Set on the western slope of the Yen Tu range in Bac Giang, the Tay Yen Tu spiritual tourism site is a gateway to the Buddhist realm amid old primeval forest. This is the very path along which Buddha-King Tran Nhan Tong and the Zen masters of old spread the Dharma, building a system of temples and stupas along the mountainside. Visitors take the cable car over bamboo forests, streams and waterfalls to reach the sacred Upper Pagoda and Dong Pagoda atop the holy peak. The newly restored Lower and Middle Pagodas stand majestic amid grand nature. On a pilgrimage to Tay Yen Tu, the heart settles amid the temple bells and drifting mountain clouds.","facts":["It is the western slope of the Yen Tu range, tied to the Truc Lam Zen school.","It is associated with the spiritual journey of Buddha-King Tran Nhan Tong.","A cable car carries visitors up close to Dong Pagoda at the summit.","It lies within the Yen Tu complex of relics and scenic sites."],"travelTips":["Come for the Tay Yen Tu spring festival, held at the start of the lunar year.","Combine the cable car and a hike to fully take in the space."],"bestTime":"The first to third lunar month","visitDuration":"1 day","ticket":"Free","openingHours":"06:00 – 18:00","galleryCaptions":["The cable car over the forest to the summit","A pagoda amid the clouds of Tay Yen Tu","The Tay Yen Tu spring festival"]},"ko":{"name":"떠이옌뜨","summary":"옌뜨 산맥의 서쪽 비탈로, 사찰들과 동(銅) 사원으로 가는 케이블카, 그리고 쩐년똥 불황의 포교의 길이 있는 곳.","story":"박장 옌뜨 산맥 서쪽 비탈에 자리한 떠이옌뜨 영성 관광지는 오래된 원시림 속 불계로 가는 관문입니다. 이곳은 쩐년똥 불황과 옛 선사들이 불법을 펼치며 산비탈을 따라 사찰과 탑을 세운 바로 그 길입니다. 여행객은 대나무 숲과 시내, 폭포를 넘는 케이블카를 타고 신성한 봉우리 정상의 상사원과 동 사원으로 오릅니다. 새로 단장한 하사원과 중사원은 웅장한 자연 속에 화려하게 서 있습니다. 떠이옌뜨로 순례를 떠나면 사찰의 종소리와 떠도는 산 구름 속에서 마음이 가라앉습니다.","facts":["옌뜨 산맥의 서쪽 비탈로, 쭉럼 선종과 얽혀 있습니다.","쩐년똥 불황의 수행 여정과 연결되어 있습니다.","케이블카가 여행객을 정상의 동 사원 가까이까지 데려다줍니다.","옌뜨 유적·명승 단지에 속해 있습니다."],"travelTips":["음력 새해 초에 열리는 떠이옌뜨 봄 축제에 가세요.","케이블카와 도보를 함께해 공간을 온전히 느껴보세요."],"bestTime":"음력 1월부터 3월","visitDuration":"1일","ticket":"무료","openingHours":"06:00 – 18:00","galleryCaptions":["숲을 넘어 정상으로 오르는 케이블카","떠이옌뜨 산 구름 속의 사찰","떠이옌뜨 봄 축제"]},"ja":{"name":"タイイエントゥ","summary":"イエントゥ山脈の西斜面。寺院群と銅寺へのケーブルカー、そしてチャン・ニャン・トン仏皇の布教の道がある場所。","story":"バックザンのイエントゥ山脈の西斜面に位置するタイイエントゥの霊性観光地は、古い原生林の中の仏界への玄関口です。ここは、チャン・ニャン・トン仏皇と昔の禅師たちが仏法を広め、山腹に沿って寺院や塔を築いた、まさにその道です。旅人は竹林や渓流、滝を越えるケーブルカーに乗り、聖なる峰の頂の上寺と銅寺へ登ります。新たに整えられた下寺と中寺は、雄大な自然の中に華麗にたたずみます。タイイエントゥへの巡礼では、寺の鐘の音と漂う山の雲の中で、心が静まります。","facts":["イエントゥ山脈の西斜面で、チュックラム禅派にゆかりがあります。","チャン・ニャン・トン仏皇の修行の旅とつながっています。","ケーブルカーが旅人を頂の銅寺の近くまで運びます。","イエントゥの遺跡・名勝群に属します。"],"travelTips":["旧暦新年初めに開かれるタイイエントゥの春祭りに訪れましょう。","ケーブルカーと徒歩を組み合わせ、空間を余すところなく感じましょう。"],"bestTime":"旧暦1月から3月","visitDuration":"1日","ticket":"無料","openingHours":"06:00 – 18:00","galleryCaptions":["森を越えて頂へ登るケーブルカー","タイイエントゥの山の雲の中の寺","タイイエントゥの春祭り"]},"zh":{"name":"西安子","summary":"安子山脉西坡，设有寺庙群、通往铜寺的缆车，以及陈仁宗佛皇弘扬佛法的道路。","story":"西安子灵性旅游区位于北江安子山脉西坡，是莽莽原始森林中通往佛界的门户。这正是陈仁宗佛皇与昔日禅师们弘扬佛法、沿山坡修建寺塔的那条道路。游客乘缆车越过竹林、溪流与瀑布，登上圣峰之巅神圣的上寺与铜寺。新近修缮的下寺与中寺，巍峨矗立于雄奇的自然之中。朝圣西安子，人心在寺钟与缥缈的山云间渐渐沉静。","facts":["是安子山脉的西坡，与竹林禅派相关。","与陈仁宗佛皇的修行之旅紧密相连。","有缆车将游客送至峰顶铜寺附近。","位于安子遗迹名胜群之内。"],"travelTips":["于农历新年初举行的西安子春季庙会期间前往。","缆车与徒步相结合，以充分感受这片空间。"],"bestTime":"农历正月至三月","visitDuration":"1天","ticket":"免费","openingHours":"06:00 – 18:00","galleryCaptions":["越过森林登上峰顶的缆车","西安子山云间的寺庙","西安子春季庙会"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('vinh-nghiem-pagoda', 'chua-vinh-nghiem', 'bac-giang', 'Chùa Vĩnh Nghiêm', 'Vinh Nghiem Pagoda', 'temple', 106.3197, 21.2542, 'Cổ tự nghìn năm, chốn tổ của Thiền phái Trúc Lâm, nơi lưu giữ kho mộc bản được UNESCO ghi danh Di sản tư liệu.', 'Bên dòng sông Thương hiền hòa, Chùa Vĩnh Nghiêm uy nghi tọa lạc như chốn tổ của Thiền phái Trúc Lâm Yên Tử. Ngôi cổ tự có lịch sử gần nghìn năm này từng là trung tâm Phật giáo lớn, nơi ba vị Tổ Trúc Lâm là Trần Nhân Tông, Pháp Loa và Huyền Quang tu hành, đào tạo tăng đồ. Kiến trúc chùa cổ kính với những nếp nhà gỗ lim, tượng Phật trầm mặc dưới tán cây cổ thụ. Đặc biệt, chùa còn lưu giữ kho mộc bản hơn 3.000 bản khắc kinh Phật bằng gỗ thị, được UNESCO công nhận Di sản tư liệu ký ức thế giới. Vĩnh Nghiêm là nơi tìm về cội nguồn văn hóa, tâm linh dân tộc.', '["Được mệnh danh là chốn tổ của Thiền phái Trúc Lâm.","Kho mộc bản chùa Vĩnh Nghiêm được UNESCO ghi danh Di sản tư liệu năm 2012.","Lưu giữ hơn 3.000 mộc bản khắc kinh Phật bằng gỗ thị.","Có lịch sử khởi dựng từ thời Lý, được mở mang dưới thời Trần."]', '["Tham quan nhà lưu giữ mộc bản để hiểu giá trị di sản.","Ghé vào dịp lễ hội chùa Vĩnh Nghiêm rằm tháng 2 âm lịch."]', 'Quanh năm', '1 - 2 giờ', '', '06:00 - 18:00', '["unesco","verified","festival"]', '["temple","history","culture"]', '[{"seed":"vinh-nghiem-pagoda-1","caption":"Cổng tam quan chùa Vĩnh Nghiêm","ratio":"16/9"},{"seed":"vinh-nghiem-pagoda-2","caption":"Kho mộc bản kinh Phật cổ","ratio":"4/3"},{"seed":"vinh-nghiem-pagoda-3","caption":"Sân chùa dưới tán cây cổ thụ","ratio":"1/1"}]', '["tay-yen-tu"]', 0, '{"en":{"name":"Vinh Nghiem Pagoda","summary":"A thousand-year-old ancient temple, ancestral seat of the Truc Lam Zen school, holding a collection of woodblocks inscribed by UNESCO as Documentary Heritage.","story":"By the gentle Thuong River, Vinh Nghiem Pagoda stands majestic as the ancestral seat of the Truc Lam Yen Tu Zen school. This ancient temple, nearly a thousand years old, was once a great centre of Buddhism, where the three Truc Lam Patriarchs — Tran Nhan Tong, Phap Loa and Huyen Quang — practised and trained monks. The temple''s ancient architecture features ironwood houses and serene Buddha statues beneath ancient trees. Most remarkably, it preserves a collection of over 3,000 woodblocks of Buddhist scriptures carved in persimmon wood, recognised by UNESCO as Memory of the World Documentary Heritage. Vinh Nghiem is a place to return to the roots of the nation''s culture and spirit.","facts":["It is hailed as the ancestral seat of the Truc Lam Zen school.","The Vinh Nghiem woodblock collection was inscribed by UNESCO as Documentary Heritage in 2012.","It preserves over 3,000 woodblocks of Buddhist scriptures carved in persimmon wood.","It was founded in the Ly dynasty and expanded under the Tran dynasty."],"travelTips":["Visit the woodblock repository to understand the value of this heritage.","Come during the Vinh Nghiem Pagoda festival on the full moon of the second lunar month."],"bestTime":"Year-round","visitDuration":"1–2 hours","ticket":"Free","openingHours":"06:00 – 18:00","galleryCaptions":["The triple gate of Vinh Nghiem Pagoda","The ancient repository of Buddhist scripture woodblocks","The temple courtyard beneath ancient trees"]},"ko":{"name":"빈응이엠 사원","summary":"천 년 고찰이자 쭉럼 선종의 본산으로, 유네스코 기록유산으로 등재된 목판을 소장한 곳.","story":"잔잔한 트엉강 가에 자리한 빈응이엠 사원은 쭉럼 옌뜨 선종의 본산으로 위풍당당하게 서 있습니다. 천 년에 가까운 역사를 지닌 이 고찰은 한때 큰 불교 중심지로, 쭉럼 삼조인 쩐년똥, 팝로아, 후옌꽝이 수행하며 승려를 양성한 곳입니다. 사원의 고풍스러운 건축은 철목 전각과 오래된 나무 아래의 고요한 불상으로 이루어져 있습니다. 특히 사원은 감나무로 새긴 3,000여 점의 불경 목판을 소장하고 있으며, 이는 유네스코 세계기록유산으로 인정받았습니다. 빈응이엠은 민족의 문화와 영성의 근원으로 돌아가는 곳입니다.","facts":["쭉럼 선종의 본산으로 불립니다.","빈응이엠 목판은 2012년 유네스코 기록유산으로 등재되었습니다.","감나무로 새긴 3,000여 점의 불경 목판을 소장하고 있습니다.","리 왕조 때 창건되어 쩐 왕조 때 확장되었습니다."],"travelTips":["목판 보관소를 둘러보며 이 유산의 가치를 이해하세요.","음력 2월 보름의 빈응이엠 사원 축제에 맞춰 가세요."],"bestTime":"연중","visitDuration":"1~2시간","ticket":"무료","openingHours":"06:00 – 18:00","galleryCaptions":["빈응이엠 사원의 삼문","오래된 불경 목판 보관소","오래된 나무 아래의 사원 마당"]},"ja":{"name":"ヴィンギエム寺","summary":"千年の古寺にしてチュックラム禅派の本山。ユネスコ記録遺産に登録された木版を所蔵する場所。","story":"穏やかなトゥオン川のほとりに位置するヴィンギエム寺は、チュックラム・イエントゥ禅派の本山として威風堂々とたたずみます。千年近い歴史を持つこの古寺はかつて大きな仏教の中心地で、チュックラム三祖であるチャン・ニャン・トン、ファップロア、フエンクアンが修行し僧を育てた場所です。寺の古風な建築は、鉄木の堂と古木の下の静謐な仏像からなります。とりわけ、寺は柿の木に彫られた3,000余りの仏典木版を所蔵し、これはユネスコの世界の記憶・記録遺産に認められています。ヴィンギエムは、民族の文化と霊性の源へ立ち返る場所です。","facts":["チュックラム禅派の本山と称されます。","ヴィンギエムの木版は2012年にユネスコ記録遺産に登録されました。","柿の木に彫られた3,000余りの仏典木版を所蔵します。","リー朝に創建され、チャン朝に拡張されました。"],"travelTips":["木版の保管所を巡り、この遺産の価値を理解しましょう。","旧暦2月の満月のヴィンギエム寺祭りに合わせて訪れましょう。"],"bestTime":"通年","visitDuration":"1〜2時間","ticket":"無料","openingHours":"06:00 – 18:00","galleryCaptions":["ヴィンギエム寺の三門","古い仏典木版の保管所","古木の下の寺の境内"]},"zh":{"name":"永严寺","summary":"千年古寺，竹林禅派的祖庭，珍藏着被联合国教科文组织列为记忆遗产的木刻经版。","story":"永严寺坐落于平静的常江之畔，作为竹林安子禅派的祖庭巍然矗立。这座近千年历史的古寺曾是佛教重镇，竹林三祖陈仁宗、法螺、玄光曾在此修行、教化僧徒。寺院古朴的建筑由铁木殿宇和古树下静穆的佛像构成。尤为难得的是，寺中珍藏着3000余块以柿木雕刻的佛经木版，被联合国教科文组织列为世界记忆记录遗产。永严寺是回溯民族文化与灵性根源之地。","facts":["被誉为竹林禅派的祖庭。","永严寺木刻经版于2012年被联合国教科文组织列为记忆遗产。","珍藏3000余块以柿木雕刻的佛经木版。","始建于李朝，于陈朝时期扩建。"],"travelTips":["参观木刻经版收藏处，体会这份遗产的价值。","于农历二月十五永严寺庙会期间前往。"],"bestTime":"全年","visitDuration":"1至2小时","ticket":"免费","openingHours":"06:00 – 18:00","galleryCaptions":["永严寺的三关门","古老的佛经木版收藏处","古树掩映下的寺院庭院"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('mu-cang-chai-terraces', 'ruong-bac-thang-mu-cang-chai', 'yen-bai', 'Ruộng bậc thang Mù Cang Chải', 'Mu Cang Chai Rice Terraces', 'mountain', 104.09, 21.7167, 'Kỳ quan ruộng bậc thang vàng óng mùa lúa chín, di tích quốc gia đặc biệt do người Mông tạo tác qua bao thế hệ.', 'Vắt mình trên những sườn núi cao của Yên Bái, ruộng bậc thang Mù Cang Chải là bản trường ca lao động do người Mông tạo nên qua hàng trăm năm. Mùa nước đổ tháng 5–6, từng thửa ruộng lấp lánh ánh trời như những tấm gương khổng lồ. Đến mùa lúa chín tháng 9–10, cả vùng La Pán Tẩn, Chế Cu Nha, Dế Xu Phình rực lên sắc vàng óng ả tầng tầng lớp lớp, đẹp đến ngỡ ngàng. Du khách trekking giữa các thửa ruộng, ngắm ''mâm xôi'' tròn trịa nổi tiếng, hòa mình vào nhịp sống bản làng vùng cao. Mù Cang Chải mùa lúa chín là điểm hẹn của bao tay máy và lữ khách yêu thiên nhiên.', '["Ruộng bậc thang Mù Cang Chải là Di tích quốc gia đặc biệt.","Do đồng bào dân tộc Mông canh tác qua nhiều thế hệ.","Đồi ''mâm xôi'' ở La Pán Tẩn là điểm chụp ảnh nổi tiếng.","Đẹp nhất vào mùa nước đổ và mùa lúa chín."]', '["Đi tháng 9–10 để ngắm lúa chín vàng rực cả thung lũng.","Vượt đèo Khau Phạ - một trong tứ đại đỉnh đèo - trên đường tới."]', 'Tháng 9 đến tháng 10', '1 - 2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["mountain","nature","photography","culture"]', '[{"seed":"mu-cang-chai-terraces-1","caption":"Ruộng bậc thang vàng óng mùa lúa chín","ratio":"16/9"},{"seed":"mu-cang-chai-terraces-2","caption":"Đồi mâm xôi La Pán Tẩn","ratio":"4/3"},{"seed":"mu-cang-chai-terraces-3","caption":"Mùa nước đổ lấp lánh ánh trời","ratio":"1/1"}]', '["thac-ba-lake"]', 1, '{"en":{"name":"Mu Cang Chai Terraced Fields","summary":"A wonder of terraced fields golden with ripe rice, a special national relic crafted by the Hmong people over generations.","story":"Draped across the high mountainsides of Yen Bai, the terraced fields of Mu Cang Chai are an epic of labour shaped by the Hmong people over hundreds of years. In the water-pouring season of May–June, each field glitters with the sky''s reflection like a giant mirror. In the ripe rice season of September–October, the whole region of La Pan Tan, Che Cu Nha and De Xu Phinh blazes with golden tiers of breathtaking beauty. Visitors trek among the fields, admiring the famous rounded ''sticky-rice mound'' hill and immersing themselves in highland village life. Mu Cang Chai in the ripe rice season is a rendezvous for photographers and nature-loving travellers.","facts":["The Mu Cang Chai terraced fields are a Special National Relic.","They have been cultivated by the Hmong people over many generations.","The ''sticky-rice mound'' hill at La Pan Tan is a famous photo spot.","They are most beautiful in the water-pouring and ripe rice seasons."],"travelTips":["Go in September–October to see the rice ripen golden across the valley.","Cross the Khau Pha Pass — one of the four great passes — on the way there."],"bestTime":"September to October","visitDuration":"1–2 days","ticket":"Free","openingHours":"All day","galleryCaptions":["Terraced fields golden with ripe rice","The sticky-rice mound hill at La Pan Tan","The water-pouring season glittering with the sky''s reflection"]},"ko":{"name":"무깡짜이 계단식 논","summary":"벼가 익어 황금빛으로 물드는 계단식 논의 절경으로, 몽족이 여러 세대에 걸쳐 빚어낸 특별 국가 유적.","story":"옌바이의 높은 산비탈에 걸친 무깡짜이 계단식 논은 몽족이 수백 년에 걸쳐 빚어낸 노동의 서사시입니다. 5~6월 물대기 시즌이면 논 하나하나가 거대한 거울처럼 하늘빛을 반짝입니다. 9~10월 벼 익는 시즌이면 라빤떤, 쩨꾸냐, 제쑤핀 일대 전체가 층층이 황금빛으로 타올라 눈이 부시도록 아름답습니다. 여행객은 논 사이를 트레킹하며 유명한 둥근 ''찰밥 봉우리''를 감상하고 고원 마을의 삶 속에 녹아듭니다. 벼 익는 시즌의 무깡짜이는 사진작가와 자연을 사랑하는 여행객의 만남의 장입니다.","facts":["무깡짜이 계단식 논은 특별 국가 유적입니다.","몽족이 여러 세대에 걸쳐 경작해 왔습니다.","라빤떤의 ''찰밥 봉우리''는 유명한 사진 명소입니다.","물대기 시즌과 벼 익는 시즌에 가장 아름답습니다."],"travelTips":["골짜기 전체가 황금빛으로 익는 9~10월에 가세요.","가는 길에 4대 고개 중 하나인 카우파 고개를 넘으세요."],"bestTime":"9월부터 10월","visitDuration":"1~2일","ticket":"무료","openingHours":"종일","galleryCaptions":["벼가 익어 황금빛으로 물든 계단식 논","라빤떤의 찰밥 봉우리","하늘빛을 반짝이는 물대기 시즌"]},"ja":{"name":"ムーカンチャイ棚田","summary":"稲が実り黄金に染まる棚田の絶景。モン族が幾世代にもわたって築いた特別国家遺跡。","story":"イエンバイの高い山腹に掛かるムーカンチャイの棚田は、モン族が数百年かけて築いた労働の叙事詩です。5〜6月の水張りの季節には、田の一枚一枚が巨大な鏡のように空の色を煌めかせます。9〜10月の稲の実る季節には、ラーパンタン、チェークーニャ、ゼースーフィン一帯全体が幾段もの黄金色に燃え上がり、目を見張るほど美しくなります。旅人は田の間をトレッキングし、有名な丸い「おこわ山」を眺め、高原の村の暮らしに溶け込みます。稲の実る季節のムーカンチャイは、写真家と自然を愛する旅人の出会いの場です。","facts":["ムーカンチャイの棚田は特別国家遺跡です。","モン族が幾世代にもわたって耕してきました。","ラーパンタンの「おこわ山」は有名な撮影スポットです。","水張りの季節と稲の実る季節が最も美しいです。"],"travelTips":["谷全体が黄金に実る9〜10月に訪れましょう。","途中、四大峠の一つカウファ峠を越えましょう。"],"bestTime":"9月から10月","visitDuration":"1〜2日","ticket":"無料","openingHours":"終日","galleryCaptions":["稲が実り黄金に染まる棚田","ラーパンタンのおこわ山","空の色を煌めかせる水張りの季節"]},"zh":{"name":"木江界梯田","summary":"稻谷成熟时金黄一片的梯田奇观，是苗族世代开垦而成的特别国家遗迹。","story":"木江界梯田蜿蜒于安沛的高山陡坡之上，是苗族历经数百年开垦而成的一曲劳动史诗。5至6月灌水季节，每一块田都如巨大的镜子般映出天光。到了9至10月稻谷成熟季，罗板潭、制句牙、夜须平一带层层叠叠燃起金黄，美得令人惊叹。游客在田间徒步，欣赏著名圆润的「糯米饭山」，融入高原村寨的生活节奏。稻谷成熟季的木江界，是摄影爱好者与热爱自然的旅人之约。","facts":["木江界梯田是特别国家遗迹。","由苗族同胞世代耕作而成。","罗板潭的「糯米饭山」是著名的拍照地点。","以灌水季节和稻谷成熟季最为美丽。"],"travelTips":["于9至10月前往，欣赏整个山谷金黄灿烂的稻谷。","前往途中翻越四大名山口之一的高巴山口。"],"bestTime":"9月至10月","visitDuration":"1至2天","ticket":"免费","openingHours":"全天","galleryCaptions":["稻谷成熟时金黄一片的梯田","罗板潭的糯米饭山","映出天光的灌水季节"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('thac-ba-lake', 'ho-thac-ba', 'yen-bai', 'Hồ Thác Bà', 'Thac Ba Lake', 'lake', 104.9, 21.9667, 'Một trong ba hồ nước nhân tạo lớn nhất Việt Nam với hơn 1.300 hòn đảo xanh, được ví như ''Hạ Long trên núi''.', 'Hình thành từ công trình thủy điện đầu tiên của miền Bắc, Hồ Thác Bà trải rộng mênh mông với hơn 1.300 hòn đảo lớn nhỏ phủ kín màu xanh, được ví như ''vịnh Hạ Long trên núi''. Mặt hồ phẳng lặng phản chiếu mây trời, len lỏi giữa những dãy núi đá vôi và rừng cây bạt ngàn. Du khách lênh đênh trên thuyền khám phá động Thủy Tiên huyền ảo, đền Thác Bà linh thiêng, hay ghé bản làng người Dao, Tày, Cao Lan ven hồ. Bình minh trên hồ, sương mờ giăng mặt nước, tiếng chim rừng vọng lại tạo nên khung cảnh thanh bình, thơ mộng hiếm nơi nào có được giữa miền núi Yên Bái.', '["Là một trong ba hồ nước nhân tạo lớn nhất Việt Nam.","Hình thành khi xây Nhà máy thủy điện Thác Bà năm 1971.","Có hơn 1.300 hòn đảo lớn nhỏ trên mặt hồ.","Được ví là ''Hạ Long trên núi'' của vùng Tây Bắc."]', '["Thuê thuyền khám phá các đảo và động Thủy Tiên.","Nghỉ homestay ven hồ để ngắm bình minh và hoàng hôn."]', 'Tháng 8 đến tháng 11', '1 ngày', '', '06:00 - 18:00', '["verified","hidden-gem"]', '["nature","photography","culture"]', '[{"seed":"thac-ba-lake-1","caption":"Hàng nghìn đảo xanh trên hồ Thác Bà","ratio":"16/9"},{"seed":"thac-ba-lake-2","caption":"Sương sớm giăng mặt hồ","ratio":"4/3"},{"seed":"thac-ba-lake-3","caption":"Thuyền khám phá lòng hồ","ratio":"1/1"}]', '["mu-cang-chai-terraces"]', 0, '{"en":{"name":"Thac Ba Lake","summary":"One of Vietnam''s three largest man-made lakes, with over 1,300 green islands, likened to a ''Ha Long Bay in the mountains''.","story":"Formed by the first hydropower project in northern Vietnam, Thac Ba Lake spreads vast with over 1,300 islands large and small cloaked in green, likened to a ''Ha Long Bay in the mountains''. The still water mirrors the sky and clouds as it threads among limestone ranges and boundless forest. Visitors drift by boat to explore the magical Thuy Tien Cave, the sacred Thac Ba Temple, or stop at Dao, Tay and Cao Lan villages along the shore. At dawn, mist veils the water and the calls of forest birds echo, creating a peaceful, poetic scene rarely found in the mountains of Yen Bai.","facts":["It is one of the three largest man-made lakes in Vietnam.","It was formed when the Thac Ba Hydropower Plant was built in 1971.","It has over 1,300 islands large and small on its surface.","It is likened to the ''Ha Long Bay in the mountains'' of the northwest."],"travelTips":["Rent a boat to explore the islands and Thuy Tien Cave.","Stay in a lakeside homestay to watch the sunrise and sunset."],"bestTime":"August to November","visitDuration":"1 day","ticket":"Free","openingHours":"06:00 – 18:00","galleryCaptions":["Thousands of green islands on Thac Ba Lake","Morning mist veiling the lake","A boat exploring the lake"]},"ko":{"name":"탁바 호수","summary":"베트남 3대 인공 호수 중 하나로, 1,300여 개의 푸른 섬이 있어 ''산속의 하롱베이''로 불리는 곳.","story":"북부 최초의 수력발전 사업으로 형성된 탁바 호수는 푸르게 뒤덮인 1,300여 개의 크고 작은 섬과 함께 광활하게 펼쳐져 ''산속의 하롱베이''로 불립니다. 잔잔한 수면은 하늘과 구름을 비추며 석회암 산맥과 드넓은 숲 사이로 굽이칩니다. 여행객은 배를 타고 환상적인 투이띠엔 동굴과 신성한 탁바 사당을 둘러보거나, 호숫가의 자오족, 따이족, 까오란족 마을에 들릅니다. 새벽이면 안개가 수면을 덮고 숲새 소리가 메아리쳐, 옌바이 산중에서 보기 드문 평화롭고 시적인 풍경을 자아냅니다.","facts":["베트남 3대 인공 호수 중 하나입니다.","1971년 탁바 수력발전소 건설로 형성되었습니다.","수면 위에 크고 작은 1,300여 개의 섬이 있습니다.","서북부의 ''산속의 하롱베이''로 불립니다."],"travelTips":["배를 빌려 섬들과 투이띠엔 동굴을 탐험하세요.","호숫가 홈스테이에 묵으며 일출과 일몰을 감상하세요."],"bestTime":"8월부터 11월","visitDuration":"1일","ticket":"무료","openingHours":"06:00 – 18:00","galleryCaptions":["탁바 호수 위 수천 개의 푸른 섬","호수를 덮은 아침 안개","호수를 탐험하는 배"]},"ja":{"name":"タックバー湖","summary":"ベトナム三大人造湖の一つ。1,300余りの緑の島々があり、「山の中のハロン湾」と称される場所。","story":"北部初の水力発電事業によって形成されたタックバー湖は、緑に覆われた大小1,300余りの島々とともに広大に広がり、「山の中のハロン湾」と称されます。静かな水面は空と雲を映し、石灰岩の山脈と果てしない森の間を縫って流れます。旅人は船で幻想的なトゥイティエン洞窟や聖なるタックバー廟を巡り、湖畔のザオ族、ターイ族、カオラン族の村に立ち寄ります。夜明けには霧が水面を覆い、森の鳥の声が響き、イエンバイの山中では稀な、穏やかで詩情あふれる光景を生み出します。","facts":["ベトナム三大人造湖の一つです。","1971年にタックバー水力発電所が建設されて形成されました。","湖面には大小1,300余りの島があります。","西北部の「山の中のハロン湾」と称されます。"],"travelTips":["船を借りて島々とトゥイティエン洞窟を探検しましょう。","湖畔のホームステイに泊まり、日の出と日没を眺めましょう。"],"bestTime":"8月から11月","visitDuration":"1日","ticket":"無料","openingHours":"06:00 – 18:00","galleryCaptions":["タックバー湖の数千の緑の島々","湖を覆う朝霧","湖を探検する船"]},"zh":{"name":"婆瀑湖","summary":"越南三大人工湖之一，拥有1300余座绿岛，被誉为「山中下龙湾」。","story":"婆瀑湖由北部第一座水电工程形成，辽阔铺展，1300余座大小岛屿覆满绿意，被誉为「山中下龙湾」。平静的湖面倒映云天，在石灰岩山脉与无垠林海间蜿蜒。游客乘船探索奇幻的水仙洞、神圣的婆瀑庙，或在湖畔的瑶族、岱依族、高栏族村寨驻足。清晨湖上薄雾弥漫，林鸟啼鸣回荡，构成一幅安沛山区难得一见的宁静诗意画卷。","facts":["是越南三大人工湖之一。","1971年修建婆瀑水电站时形成。","湖面上有1300余座大小岛屿。","被誉为西北地区的「山中下龙湾」。"],"travelTips":["租船探索岛屿和水仙洞。","在湖畔民宿留宿，欣赏日出与日落。"],"bestTime":"8月至11月","visitDuration":"1天","ticket":"免费","openingHours":"06:00 – 18:00","galleryCaptions":["婆瀑湖上数千座绿岛","笼罩湖面的清晨薄雾","探索湖区的船只"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('o-quy-ho-pass', 'deo-o-quy-ho', 'lai-chau', 'Đèo Ô Quy Hồ', 'O Quy Ho Pass', 'mountain', 103.7733, 22.3528, 'Một trong tứ đại đỉnh đèo Tây Bắc, cung đường mây phủ ngoạn mục nối Lai Châu với Sa Pa qua đỉnh Hoàng Liên Sơn.', 'Vắt qua đỉnh Hoàng Liên Sơn ở độ cao gần 2.000m, Đèo Ô Quy Hồ là một trong ''tứ đại đỉnh đèo'' hùng vĩ nhất Tây Bắc, nối liền Lai Châu và Lào Cai. Cung đường dài gần 50km uốn lượn quanh co bên vách núi dựng đứng, một bên là vực sâu thăm thẳm, một bên là rừng già nguyên sinh. Người ta còn gọi đây là ''đèo Mây'' bởi quanh năm mây mù bao phủ, tạo nên biển mây bồng bềnh mê hoặc. Từ đỉnh đèo phía Lai Châu, du khách phóng tầm mắt ngắm trọn dãy Hoàng Liên Sơn trùng điệp, săn mây, đón hoàng hôn rực rỡ. Mùa đông, đỉnh đèo đôi khi phủ băng tuyết trắng xóa.', '["Là một trong tứ đại đỉnh đèo của vùng núi Tây Bắc.","Đỉnh đèo cao gần 2.000m, dài khoảng 50km.","Còn được gọi là ''đèo Mây'' vì quanh năm mây phủ.","Nối liền hai tỉnh Lai Châu và Lào Cai qua dãy Hoàng Liên Sơn."]', '["Dừng ở Cổng Trời phía Lai Châu để săn mây và ngắm cảnh.","Lái xe cẩn thận vì đường đèo nhiều khúc cua nguy hiểm."]', 'Tháng 9 đến tháng 4', 'Nửa ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["mountain","nature","photography"]', '[{"seed":"o-quy-ho-pass-1","caption":"Biển mây trên đỉnh Ô Quy Hồ","ratio":"16/9"},{"seed":"o-quy-ho-pass-2","caption":"Cung đèo uốn lượn bên vách núi","ratio":"4/3"},{"seed":"o-quy-ho-pass-3","caption":"Hoàng hôn nhìn từ Cổng Trời","ratio":"1/1"}]', '["sin-suoi-ho-village"]', 1, '{"en":{"name":"O Quy Ho Pass","summary":"One of the four great passes of the northwest, a spectacular cloud-covered road linking Lai Chau and Sa Pa over the Hoang Lien Son range.","story":"Crossing the Hoang Lien Son range at nearly 2,000m, O Quy Ho Pass is one of the most magnificent of the northwest''s ''four great passes'', linking Lai Chau and Lao Cai. The nearly 50km road winds along sheer cliffs — a fathomless abyss on one side, old primeval forest on the other. It is also called the ''Cloud Pass'' because it is shrouded in cloud all year, forming a mesmerising sea of cloud. From the summit on the Lai Chau side, visitors gaze across the rolling Hoang Lien Son range, chase clouds and watch glorious sunsets. In winter, the summit is sometimes coated white with ice and frost.","facts":["It is one of the four great passes of the northwestern mountains.","Its summit reaches nearly 2,000m, and it runs about 50km.","It is also known as the ''Cloud Pass'' because it is cloud-covered all year.","It links the two provinces of Lai Chau and Lao Cai across the Hoang Lien Son range."],"travelTips":["Stop at Heaven''s Gate on the Lai Chau side to chase clouds and admire the view.","Drive carefully, as the pass has many dangerous bends."],"bestTime":"September to April","visitDuration":"Half a day","ticket":"Free","openingHours":"All day","galleryCaptions":["A sea of clouds atop O Quy Ho","The winding pass along the cliffside","Sunset seen from Heaven''s Gate"]},"ko":{"name":"오꾸이호 고개","summary":"서북부 4대 고개 중 하나로, 호앙리엔선 산맥을 넘어 라이쩌우와 사파를 잇는 장관의 구름 덮인 길.","story":"해발 약 2,000m에서 호앙리엔선 산맥을 넘는 오꾸이호 고개는 라이쩌우와 라오까이를 잇는, 서북부 ''4대 고개'' 중 가장 웅장한 곳 중 하나입니다. 약 50km에 이르는 길은 깎아지른 절벽을 따라 굽이치는데, 한쪽은 가늠할 수 없는 협곡이고 다른 한쪽은 오래된 원시림입니다. 연중 구름에 덮여 매혹적인 구름 바다를 이루기에 ''구름 고개''라고도 불립니다. 라이쩌우 쪽 정상에서 여행객은 첩첩한 호앙리엔선 산맥을 한눈에 바라보며 구름을 쫓고 찬란한 일몰을 맞습니다. 겨울이면 정상이 얼음과 서리로 하얗게 덮이기도 합니다.","facts":["서북부 산악 지대 4대 고개 중 하나입니다.","고개 정상은 해발 약 2,000m, 길이는 약 50km입니다.","연중 구름에 덮여 ''구름 고개''라고도 불립니다.","호앙리엔선 산맥을 넘어 라이쩌우와 라오까이 두 성을 잇습니다."],"travelTips":["라이쩌우 쪽 천문(天門)에 들러 구름을 쫓고 경치를 감상하세요.","위험한 커브가 많은 고갯길이니 조심해서 운전하세요."],"bestTime":"9월부터 4월","visitDuration":"반나절","ticket":"무료","openingHours":"종일","galleryCaptions":["오꾸이호 정상의 구름 바다","절벽을 따라 굽이치는 고갯길","천문에서 바라본 일몰"]},"ja":{"name":"オークイホー峠","summary":"西北部四大峠の一つ。ホアンリエンソン山脈を越え、ライチャウとサパを結ぶ、雲に覆われた壮観な道。","story":"標高約2,000メートルでホアンリエンソン山脈を越えるオークイホー峠は、ライチャウとラオカイを結ぶ、西北部「四大峠」の中でも最も雄大な峠の一つです。約50キロに及ぶ道は切り立った絶壁を縫ってうねり、片側は計り知れない渓谷、もう片側は古い原生林です。一年中雲に覆われ、魅惑的な雲海を生むことから「雲の峠」とも呼ばれます。ライチャウ側の頂から、旅人は連なるホアンリエンソン山脈を一望し、雲を追い、輝かしい夕陽を迎えます。冬には頂が氷と霜で白く覆われることもあります。","facts":["西北部山地の四大峠の一つです。","峠の頂は標高約2,000メートル、長さは約50キロです。","一年中雲に覆われることから「雲の峠」とも呼ばれます。","ホアンリエンソン山脈を越えてライチャウとラオカイの二省を結びます。"],"travelTips":["ライチャウ側の天門に立ち寄り、雲を追って景色を眺めましょう。","危険なカーブが多い峠道なので、慎重に運転しましょう。"],"bestTime":"9月から4月","visitDuration":"半日","ticket":"無料","openingHours":"終日","galleryCaptions":["オークイホー頂の雲海","絶壁を縫ってうねる峠道","天門から眺める夕陽"]},"zh":{"name":"乌贵湖山口","summary":"西北四大名山口之一，云雾缭绕、景色壮观的道路，越过黄连山脉连接莱州与沙巴。","story":"乌贵湖山口在海拔近2000米处越过黄连山脉，是西北「四大名山口」中最雄伟的山口之一，连接莱州与老街。这条近50公里的道路沿着峭壁蜿蜒盘旋，一侧是深不见底的峡谷，另一侧是古老的原始森林。它还被称为「云之山口」，因为终年云雾缭绕，幻化出令人陶醉的云海。从莱州一侧的山顶，游客可一览连绵的黄连山脉，追云、迎接绚烂的落日。冬季，山顶有时被冰霜覆成一片洁白。","facts":["是西北山区四大名山口之一。","山口顶部海拔近2000米，全长约50公里。","因终年云雾缭绕，又被称为「云之山口」。","越过黄连山脉连接莱州与老街两省。"],"travelTips":["在莱州一侧的天门驻足，追云赏景。","山口弯道险峻众多，请谨慎驾驶。"],"bestTime":"9月至4月","visitDuration":"半天","ticket":"免费","openingHours":"全天","galleryCaptions":["乌贵湖之巅的云海","沿峭壁蜿蜒的山口道路","从天门眺望的落日"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('sin-suoi-ho-village', 'ban-sin-suoi-ho', 'lai-chau', 'Bản Sin Suối Hồ', 'Sin Suoi Ho Village', 'village', 103.6228, 22.4419, 'Bản làng người Mông xanh sạch đẹp giữa núi rừng Lai Châu, nổi tiếng với du lịch cộng đồng, hoa địa lan và thác Trái Tim.', 'Nằm cheo leo trên độ cao hơn 1.500m dưới chân dãy Hoàng Liên Sơn, Sin Suối Hồ là bản làng người Mông được mệnh danh đẹp như cổ tích. Từ một bản nghèo, người dân nơi đây đã cùng nhau làm du lịch cộng đồng, biến bản thành điểm đến xanh - sạch - đẹp nức tiếng. Những nếp nhà gỗ pơ mu nép mình giữa vườn hoa địa lan, đào, mận khoe sắc. Du khách trekking tới thác Trái Tim thơ mộng, ghé chợ phiên rực rỡ sắc màu thổ cẩm, thưởng thức ẩm thực bản địa và nghỉ trong homestay ấm cúng. Người Mông hiền hậu, mến khách khiến hành trình tới Sin Suối Hồ thêm phần ấm áp, đáng nhớ.', '["Bản của người Mông nằm ở độ cao hơn 1.500m.","Được vinh danh là Làng du lịch cộng đồng ASEAN.","Nổi tiếng với nghề trồng hoa địa lan và thác Trái Tim.","Là điểm du lịch cộng đồng xanh - sạch - đẹp tiêu biểu của Lai Châu."]', '["Ghé vào chợ phiên cuối tuần để trải nghiệm văn hóa Mông.","Đi mùa xuân để ngắm hoa địa lan và hoa đào nở rộ."]', 'Tháng 12 đến tháng 3', '1 ngày', '', 'Cả ngày', '["hidden-gem","verified","new"]', '["culture","nature","photography"]', '[{"seed":"sin-suoi-ho-village-1","caption":"Bản Mông giữa núi rừng Lai Châu","ratio":"16/9"},{"seed":"sin-suoi-ho-village-2","caption":"Vườn hoa địa lan khoe sắc","ratio":"4/3"},{"seed":"sin-suoi-ho-village-3","caption":"Thác Trái Tim thơ mộng","ratio":"1/1"}]', '["o-quy-ho-pass"]', 0, '{"en":{"name":"Sin Suoi Ho Village","summary":"A clean, beautiful Hmong village amid the mountains of Lai Chau, famous for community tourism, wild orchids and Heart Waterfall.","story":"Perched at over 1,500m at the foot of the Hoang Lien Son range, Sin Suoi Ho is a Hmong village said to be as beautiful as a fairy tale. From a poor village, its people came together to build community tourism, transforming it into a renowned green, clean and beautiful destination. Po-mu timber houses nestle among gardens of wild orchids, peach and plum blossoms. Visitors trek to the poetic Heart Waterfall, visit the colourful brocade market, savour local cuisine and stay in cosy homestays. The gentle, hospitable Hmong people make the journey to Sin Suoi Ho all the warmer and more memorable.","facts":["A Hmong village set at over 1,500m above sea level.","It was honoured as an ASEAN Community-Based Tourism Village.","Famous for growing wild orchids and for Heart Waterfall.","It is a model green, clean and beautiful community tourism site of Lai Chau."],"travelTips":["Visit the weekend market to experience Hmong culture.","Come in spring to see the wild orchids and peach blossoms in full bloom."],"bestTime":"December to March","visitDuration":"1 day","ticket":"Free","openingHours":"All day","galleryCaptions":["A Hmong village amid the mountains of Lai Chau","A garden of wild orchids in bloom","The poetic Heart Waterfall"]},"ko":{"name":"신쑤오이호 마을","summary":"라이쩌우 산중의 깨끗하고 아름다운 몽족 마을로, 공동체 관광과 야생 난, 하트 폭포로 유명한 곳.","story":"호앙리엔선 산맥 기슭 해발 1,500m가 넘는 곳에 아슬아슬하게 자리한 신쑤오이호는 동화처럼 아름답다고 불리는 몽족 마을입니다. 가난한 마을에서 시작해 주민들이 함께 공동체 관광을 일구어, 깨끗하고 아름답기로 이름난 친환경 명소로 탈바꿈했습니다. 포무 목조 가옥들이 야생 난, 복숭아꽃, 매화가 만발한 정원 사이에 자리합니다. 여행객은 시적인 하트 폭포로 트레킹하고, 색색의 자수가 가득한 장날 시장에 들르며, 향토 음식을 맛보고 아늑한 홈스테이에 묵습니다. 온화하고 손님을 반기는 몽족 사람들 덕분에 신쑤오이호로의 여정은 한층 따뜻하고 기억에 남습니다.","facts":["해발 1,500m가 넘는 곳에 자리한 몽족 마을입니다.","아세안 공동체 관광 마을로 선정되었습니다.","야생 난 재배와 하트 폭포로 유명합니다.","라이쩌우를 대표하는 깨끗하고 아름다운 공동체 관광지입니다."],"travelTips":["몽족 문화를 체험하려면 주말 장날에 들르세요.","야생 난과 복숭아꽃이 만발하는 봄에 가세요."],"bestTime":"12월부터 3월","visitDuration":"1일","ticket":"무료","openingHours":"종일","galleryCaptions":["라이쩌우 산중의 몽족 마을","활짝 핀 야생 난 정원","시적인 하트 폭포"]},"ja":{"name":"シンスオイホー村","summary":"ライチャウの山中にある、清潔で美しいモン族の村。コミュニティ観光、野生のシンビジウム、ハートの滝で有名な場所。","story":"ホアンリエンソン山脈の麓、標高1,500メートルを超える場所に切り立つように位置するシンスオイホーは、おとぎ話のように美しいと称されるモン族の村です。貧しい村から始まり、住民たちが力を合わせてコミュニティ観光を築き、清潔で美しいことで名高い環境配慮型の名所へと生まれ変わらせました。プムーの木造家屋が、野生のシンビジウム、桃の花、梅の花が咲き誇る庭の間に佇みます。旅人は詩情あふれるハートの滝へトレッキングし、色とりどりの刺繍の市に立ち寄り、郷土料理を味わい、居心地のよいホームステイに泊まります。穏やかでもてなし好きなモン族の人々のおかげで、シンスオイホーへの旅は一層温かく、記憶に残るものとなります。","facts":["標高1,500メートルを超える場所に位置するモン族の村です。","ASEANコミュニティ観光村に選ばれました。","野生のシンビジウム栽培とハートの滝で有名です。","ライチャウを代表する清潔で美しいコミュニティ観光地です。"],"travelTips":["モン族の文化を体験するため、週末の市に立ち寄りましょう。","野生のシンビジウムと桃の花が咲き誇る春に訪れましょう。"],"bestTime":"12月から3月","visitDuration":"1日","ticket":"無料","openingHours":"終日","galleryCaptions":["ライチャウの山中のモン族の村","咲き誇る野生のシンビジウムの庭","詩情あふれるハートの滝"]},"zh":{"name":"辛水湖村","summary":"莱州山林中一座洁净美丽的苗族村寨，以社区旅游、地兰花和心形瀑布闻名。","story":"辛水湖坐落于黄连山脉脚下海拔逾1500米的险峻之处，是一座被誉为美如童话的苗族村寨。从一个贫困的村庄起步，这里的村民齐心发展社区旅游，将村寨变为远近闻名、洁净美丽的环保目的地。一栋栋杉木屋依偎在盛放着地兰花、桃花、梅花的花园之间。游客徒步前往诗意的心形瀑布，逛逛锦绣斑斓的集市，品尝本地美食，并在温馨的民宿留宿。淳朴好客的苗族人，让前往辛水湖的旅程更添温暖、令人难忘。","facts":["是一座海拔逾1500米的苗族村寨。","被评为东盟社区旅游村。","以种植地兰花和心形瀑布闻名。","是莱州具代表性的洁净美丽社区旅游地。"],"travelTips":["于周末集市时前往，体验苗族文化。","于春季前往，观赏盛放的地兰花和桃花。"],"bestTime":"12月至3月","visitDuration":"1天","ticket":"免费","openingHours":"全天","galleryCaptions":["莱州山林中的苗族村寨","竞相绽放的地兰花园","诗意的心形瀑布"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('mai-chau-valley', 'thung-lung-mai-chau', 'hoa-binh', 'Thung lũng Mai Châu', 'Mai Chau Valley', 'village', 105.0533, 20.6597, 'Thung lũng xanh mướt với bản làng người Thái, nhà sàn, ruộng lúa và điệu xòe rộn ràng giữa lòng Hòa Bình.', 'Sau khi vượt đèo Thung Khe mây phủ, Thung lũng Mai Châu hiện ra như bức tranh thanh bình với những thửa ruộng xanh mướt trải dài dưới chân núi. Đây là vùng đất của người Thái trắng, nơi những nếp nhà sàn truyền thống ẩn mình giữa hàng cau, lũy tre. Du khách đạp xe quanh bản Lác, bản Pom Coọng, ghé thăm các khung dệt thổ cẩm rực rỡ và thưởng thức cơm lam, rượu cần. Khi đêm xuống, bên ánh lửa bập bùng, điệu xòe Thái uyển chuyển cùng tiếng khèn, tiếng trống khiến lòng người ngất ngây. Mai Châu mộc mạc, hiếu khách là chốn dừng chân lý tưởng để tận hưởng nhịp sống chậm rãi vùng cao.', '["Là quê hương của đồng bào dân tộc Thái trắng.","Bản Lác là điểm du lịch cộng đồng lâu đời và nổi tiếng nhất.","Nổi tiếng với nghề dệt thổ cẩm truyền thống.","Đường vào thung lũng phải qua đèo Thung Khe (đèo Đá Trắng)."]', '["Thuê xe đạp dạo quanh các bản để cảm nhận nhịp sống.","Nghỉ homestay nhà sàn và xem biểu diễn múa xòe buổi tối."]', 'Tháng 9 đến tháng 11', '1 - 2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["culture","nature","photography","food"]', '[{"seed":"mai-chau-valley-1","caption":"Thung lũng Mai Châu nhìn từ đèo","ratio":"16/9"},{"seed":"mai-chau-valley-2","caption":"Nhà sàn người Thái bản Lác","ratio":"4/3"},{"seed":"mai-chau-valley-3","caption":"Điệu xòe bên ánh lửa","ratio":"1/1"}]', '["hoa-binh-lake"]', 1, '{"en":{"name":"Mai Chau Valley","summary":"A lush green valley of Thai villages, stilt houses, rice fields and the lively xoe dance in the heart of Hoa Binh.","story":"After crossing the cloud-covered Thung Khe Pass, Mai Chau Valley appears like a peaceful painting, with green rice fields stretching out at the foot of the mountains. This is the land of the White Thai people, where traditional stilt houses nestle among areca palms and bamboo groves. Visitors cycle around Lac village and Pom Coong village, visit the vibrant brocade looms and savour bamboo-tube rice and ruou can wine. When night falls, by the flickering firelight, the graceful Thai xoe dance with the sound of pipes and drums enchants the heart. Rustic, hospitable Mai Chau is an ideal stop to enjoy the slow pace of highland life.","facts":["It is the homeland of the White Thai people.","Lac village is the oldest and most famous community tourism spot.","It is famous for the traditional craft of brocade weaving.","The road into the valley crosses the Thung Khe Pass (White Stone Pass)."],"travelTips":["Rent a bicycle to ride around the villages and feel the rhythm of life.","Stay in a stilt-house homestay and watch the evening xoe dance performance."],"bestTime":"September to November","visitDuration":"1–2 days","ticket":"Free","openingHours":"All day","galleryCaptions":["Mai Chau Valley seen from the pass","Thai stilt houses in Lac village","The xoe dance by the firelight"]},"ko":{"name":"마이쩌우 골짜기","summary":"타이족 마을과 수상가옥, 논, 그리고 흥겨운 쏘에 춤이 어우러진, 호아빈 한복판의 푸른 골짜기.","story":"구름에 덮인 퉁케 고개를 넘으면, 산기슭에 푸른 논이 길게 펼쳐진 평화로운 그림 같은 마이쩌우 골짜기가 나타납니다. 이곳은 백타이족의 땅으로, 전통 수상가옥이 빈랑나무와 대나무 숲 사이에 자리합니다. 여행객은 락 마을과 뽐꼬옹 마을을 자전거로 돌며 색색의 자수 베틀을 구경하고 대통밥과 르어우껀 술을 맛봅니다. 밤이 내리면 일렁이는 불빛 곁에서 우아한 타이족 쏘에 춤이 피리와 북소리와 어우러져 마음을 사로잡습니다. 소박하고 손님을 반기는 마이쩌우는 고원의 느린 삶을 즐기기에 이상적인 쉼터입니다.","facts":["백타이족의 고향입니다.","락 마을은 가장 오래되고 유명한 공동체 관광지입니다.","전통 자수 직조 기술로 유명합니다.","골짜기로 들어가는 길은 퉁케 고개(다짱 고개)를 넘습니다."],"travelTips":["자전거를 빌려 마을을 돌며 삶의 리듬을 느껴보세요.","수상가옥 홈스테이에 묵으며 저녁 쏘에 춤 공연을 감상하세요."],"bestTime":"9월부터 11월","visitDuration":"1~2일","ticket":"무료","openingHours":"종일","galleryCaptions":["고개에서 바라본 마이쩌우 골짜기","락 마을의 타이족 수상가옥","불빛 곁의 쏘에 춤"]},"ja":{"name":"マイチャウ谷","summary":"ターイ族の村、高床式家屋、田んぼ、そして賑やかなソエ踊りが調和する、ホアビンの中心の緑の谷。","story":"雲に覆われたトゥンケー峠を越えると、山裾に緑の田んぼが長く広がる、穏やかな絵のようなマイチャウ谷が現れます。ここは白ターイ族の地で、伝統的な高床式家屋がビンロウやしと竹林の間に佇みます。旅人はラック村やポムコーン村を自転車で巡り、色鮮やかな刺繍の機織りを眺め、竹筒飯やルオウカン酒を味わいます。夜が訪れると、揺らめく火明かりのそばで、優雅なターイ族のソエ踊りが笛や太鼓の音と調和し、心を魅了します。素朴でもてなし好きなマイチャウは、高原のゆったりとした暮らしを楽しむのに理想的な憩いの場です。","facts":["白ターイ族の故郷です。","ラック村は最も古く有名なコミュニティ観光地です。","伝統的な刺繍織りの技で有名です。","谷へ入る道はトゥンケー峠(白石峠)を越えます。"],"travelTips":["自転車を借りて村々を巡り、暮らしのリズムを感じましょう。","高床式ホームステイに泊まり、夜のソエ踊りの公演を鑑賞しましょう。"],"bestTime":"9月から11月","visitDuration":"1〜2日","ticket":"無料","openingHours":"終日","galleryCaptions":["峠から眺めるマイチャウ谷","ラック村のターイ族の高床式家屋","火明かりのそばのソエ踊り"]},"zh":{"name":"梅州谷","summary":"一座苍翠的山谷，泰族村寨、高脚屋、稻田与欢快的圈舞交相辉映，坐落于和平省腹地。","story":"翻过云雾缭绕的通溪山口，梅州谷便如一幅宁静的画卷展现眼前，苍翠的稻田在山脚下绵延铺展。这里是白泰族之乡，传统的高脚屋掩映于槟榔树与翠竹之间。游客骑车环游摆寨、波贡寨，走访色彩斑斓的锦绣织机，品尝竹筒饭和坛酒。夜幕降临，在跳动的火光旁，泰族婀娜的圈舞伴着笙鼓之声，令人沉醉。质朴好客的梅州，是享受高原悠然慢生活的理想驿站。","facts":["是白泰族的故乡。","摆寨是历史最悠久、最著名的社区旅游地。","以传统的锦绣织造技艺闻名。","进入山谷的道路须翻越通溪山口（白石山口）。"],"travelTips":["租一辆自行车环游各村寨，感受生活的节奏。","在高脚屋民宿留宿，观赏夜晚的圈舞表演。"],"bestTime":"9月至11月","visitDuration":"1至2天","ticket":"免费","openingHours":"全天","galleryCaptions":["从山口眺望的梅州谷","摆寨的泰族高脚屋","火光旁的圈舞"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hoa-binh-lake', 'ho-hoa-binh', 'hoa-binh', 'Hồ Hòa Bình', 'Hoa Binh Lake', 'lake', 105.15, 20.7833, 'Hồ thủy điện rộng lớn ôm trọn núi non sông Đà, được ví như ''Hạ Long thu nhỏ'' với đền Thác Bờ linh thiêng.', 'Trải dài trên dòng sông Đà hùng vĩ, Hồ Hòa Bình là hồ nhân tạo rộng lớn hình thành từ công trình thủy điện Hòa Bình. Mặt hồ xanh thẳm len lỏi giữa hàng trăm hòn đảo và những dãy núi đá vôi trùng điệp, tạo nên cảnh sắc được ví như ''vịnh Hạ Long thu nhỏ'' giữa núi rừng Tây Bắc. Du khách lên thuyền dạo hồ, viếng đền Thác Bờ linh thiêng thờ Bà Chúa Thác, khám phá động Thác Bờ với nhũ đá kỳ ảo. Ven hồ, các bản làng người Mường, Thái cùng những điểm du lịch cộng đồng mời gọi du khách nghỉ dưỡng. Bình minh và hoàng hôn trên hồ Hòa Bình mang vẻ đẹp tĩnh lặng, thơ mộng đắm say lòng người.', '["Hình thành từ Nhà máy thủy điện Hòa Bình trên sông Đà.","Được ví như ''vịnh Hạ Long thu nhỏ'' của vùng Tây Bắc.","Có đền Thác Bờ và động Thác Bờ nổi tiếng linh thiêng.","Ven hồ là các bản làng người Mường, Thái."]', '["Đi thuyền tham quan đền và động Thác Bờ.","Kết hợp nghỉ dưỡng tại các khu du lịch cộng đồng ven hồ."]', 'Tháng 9 đến tháng 12', '1 ngày', '', '06:00 - 18:00', '["verified","popular"]', '["nature","culture","photography"]', '[{"seed":"hoa-binh-lake-1","caption":"Hồ Hòa Bình giữa núi non sông Đà","ratio":"16/9"},{"seed":"hoa-binh-lake-2","caption":"Đền Thác Bờ bên hồ","ratio":"4/3"},{"seed":"hoa-binh-lake-3","caption":"Thuyền dạo trên lòng hồ","ratio":"1/1"}]', '["mai-chau-valley"]', 0, '{"en":{"name":"Hoa Binh Lake","summary":"A vast hydropower lake embracing the mountains of the Da River, likened to a ''miniature Ha Long Bay'', with the sacred Thac Bo Temple.","story":"Stretching along the mighty Da River, Hoa Binh Lake is a vast man-made lake formed by the Hoa Binh hydropower project. Its deep blue waters thread among hundreds of islands and rolling limestone ranges, creating scenery likened to a ''miniature Ha Long Bay'' amid the northwestern mountains. Visitors take a boat across the lake, pay respects at the sacred Thac Bo Temple honouring the Lady of the Falls, and explore Thac Bo Cave with its magical stalactites. Along the shore, Muong and Thai villages and community tourism sites invite visitors to unwind. Dawn and dusk over Hoa Binh Lake carry a still, poetic beauty that captivates the heart.","facts":["It was formed by the Hoa Binh Hydropower Plant on the Da River.","It is likened to a ''miniature Ha Long Bay'' of the northwest.","It has the famously sacred Thac Bo Temple and Thac Bo Cave.","Along its shores lie Muong and Thai villages."],"travelTips":["Take a boat to visit Thac Bo Temple and Cave.","Combine it with a stay at the lakeside community tourism sites."],"bestTime":"September to December","visitDuration":"1 day","ticket":"Free","openingHours":"06:00 – 18:00","galleryCaptions":["Hoa Binh Lake amid the mountains of the Da River","Thac Bo Temple by the lake","A boat cruising the lake"]},"ko":{"name":"호아빈 호수","summary":"다강의 산수를 온전히 감싸 안은 드넓은 수력발전 호수로, ''미니 하롱베이''로 불리며 신성한 탁버 사당이 있는 곳.","story":"웅장한 다강을 따라 길게 뻗은 호아빈 호수는 호아빈 수력발전 사업으로 형성된 드넓은 인공 호수입니다. 짙푸른 수면이 수백 개의 섬과 첩첩한 석회암 산맥 사이로 굽이쳐, 서북부 산중의 ''미니 하롱베이''로 불리는 경관을 자아냅니다. 여행객은 배를 타고 호수를 돌며 폭포의 여신을 모시는 신성한 탁버 사당을 참배하고, 환상적인 종유석이 있는 탁버 동굴을 탐험합니다. 호숫가에는 므엉족, 타이족 마을과 공동체 관광지가 여행객에게 휴식을 권합니다. 호아빈 호수의 일출과 일몰은 고요하고 시적인 아름다움으로 마음을 사로잡습니다.","facts":["다강의 호아빈 수력발전소로 형성되었습니다.","서북부의 ''미니 하롱베이''로 불립니다.","신성하기로 유명한 탁버 사당과 탁버 동굴이 있습니다.","호숫가에는 므엉족, 타이족 마을이 있습니다."],"travelTips":["배를 타고 탁버 사당과 동굴을 둘러보세요.","호숫가 공동체 관광지에서의 휴식과 함께 즐기세요."],"bestTime":"9월부터 12월","visitDuration":"1일","ticket":"무료","openingHours":"06:00 – 18:00","galleryCaptions":["다강의 산수 사이의 호아빈 호수","호숫가의 탁버 사당","호수를 도는 배"]},"ja":{"name":"ホアビン湖","summary":"ダー川の山水をすっぽりと抱く広大な水力発電湖。「ミニ・ハロン湾」と称され、聖なるタックボー廟がある場所。","story":"雄大なダー川に沿って長く伸びるホアビン湖は、ホアビン水力発電事業によって形成された広大な人造湖です。深い青の水面が数百の島々と連なる石灰岩の山脈の間をうねり、西北部の山中の「ミニ・ハロン湾」と称される景観を生み出します。旅人は船で湖を巡り、滝の女神を祀る聖なるタックボー廟を参拝し、幻想的な鍾乳石のあるタックボー洞窟を探検します。湖畔では、ムオン族、ターイ族の村やコミュニティ観光地が旅人にくつろぎを誘います。ホアビン湖の日の出と日没は、静かで詩情あふれる美しさで心を魅了します。","facts":["ダー川のホアビン水力発電所によって形成されました。","西北部の「ミニ・ハロン湾」と称されます。","聖なることで有名なタックボー廟とタックボー洞窟があります。","湖畔にはムオン族、ターイ族の村があります。"],"travelTips":["船でタックボー廟と洞窟を巡りましょう。","湖畔のコミュニティ観光地での休息と合わせて楽しみましょう。"],"bestTime":"9月から12月","visitDuration":"1日","ticket":"無料","openingHours":"06:00 – 18:00","galleryCaptions":["ダー川の山水の間のホアビン湖","湖畔のタックボー廟","湖を巡る船"]},"zh":{"name":"和平湖","summary":"一座辽阔的水电湖，将沱江的山水尽数环抱，被誉为「微缩下龙湾」，湖畔有神圣的瀑坡庙。","story":"和平湖沿雄伟的沱江绵延铺展，是由和平水电工程形成的辽阔人工湖。深蓝的湖水在数百座岛屿与连绵的石灰岩山脉间蜿蜒，构成西北山林间被誉为「微缩下龙湾」的景致。游客乘船游湖，拜谒供奉瀑坡圣母的神圣瀑坡庙，探索拥有奇幻钟乳石的瀑坡洞。湖畔的芒族、泰族村寨与社区旅游地，邀请游客前来休憩。和平湖的日出与日落，带着静谧诗意之美，令人沉醉。","facts":["由沱江上的和平水电站形成。","被誉为西北地区的「微缩下龙湾」。","拥有以灵验著称的瀑坡庙与瀑坡洞。","湖畔是芒族、泰族村寨。"],"travelTips":["乘船游览瀑坡庙与瀑坡洞。","可与湖畔社区旅游地的休憩相结合。"],"bestTime":"9月至12月","visitDuration":"1天","ticket":"免费","openingHours":"06:00 – 18:00","galleryCaptions":["沱江山水间的和平湖","湖畔的瀑坡庙","游湖的船只"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hp-cat-ba-island', 'dao-cat-ba', 'hai-phong', 'Đảo Cát Bà', 'Cat Ba Island', 'island', 107.0489, 20.7281, 'Hòn đảo lớn nhất vịnh Lan Hạ với rừng nguyên sinh, bãi tắm trong xanh và những vịnh đá vôi kỳ vĩ.', 'Cát Bà là viên ngọc xanh của Hải Phòng, nơi rừng quốc gia ôm lấy biển và những dãy núi đá vôi nhô lên giữa làn nước ngọc bích. Đảo nổi tiếng với loài voọc Cát Bà quý hiếm chỉ còn vài chục cá thể trên thế giới. Du khách có thể chèo kayak luồn lách qua vịnh Lan Hạ, leo lên đỉnh Ngự Lâm ngắm toàn cảnh, hay thả mình trên những bãi cát trắng mịn. Năm 2023, quần thể vịnh Hạ Long - Cát Bà được UNESCO vinh danh Di sản Thiên nhiên Thế giới, khẳng định vẻ đẹp vượt thời gian của vùng đất này.', '["Là đảo lớn nhất trong quần đảo Cát Bà gồm 367 hòn đảo lớn nhỏ.","Rừng quốc gia Cát Bà là nơi cư trú của voọc Cát Bà cực kỳ nguy cấp.","Được UNESCO công nhận Di sản Thiên nhiên Thế giới năm 2023.","Vịnh Lan Hạ có hơn 130 bãi tắm nhỏ ẩn mình giữa núi đá vôi."]', '["Đặt tour kayak buổi sáng sớm để tránh nắng và đông đúc.","Mang giày bám tốt nếu muốn leo đỉnh Ngự Lâm hoặc trekking trong rừng quốc gia."]', 'Tháng 4 đến tháng 9', '2 ngày 1 đêm', '80.000đ', 'Cả ngày', '["unesco","trending","popular","verified"]', '["island","nature","beach","photography"]', '[{"seed":"hp-cat-ba-island-1","caption":"Vịnh Lan Hạ nhìn từ trên cao","ratio":"16/9"},{"seed":"hp-cat-ba-island-2","caption":"Bãi tắm Cát Cò trong xanh","ratio":"4/3"},{"seed":"hp-cat-ba-island-3","caption":"Rừng quốc gia Cát Bà","ratio":"1/1"}]', '["hp-do-son-beach"]', 1, '{"en":{"name":"Cat Ba Island","summary":"The largest island in Lan Ha Bay, with primeval forest, crystal-clear beaches, and majestic limestone bays.","story":"Cat Ba is Hai Phong''s emerald jewel, where the national park embraces the sea and limestone ranges rise from emerald waters. The island is famous for the rare Cat Ba langur, of which only a few dozen remain in the world. Visitors can kayak through the maze of Lan Ha Bay, climb to the summit of Ngu Lam peak for sweeping views, or unwind on soft white-sand beaches. In 2023, the Ha Long Bay – Cat Ba complex was honored by UNESCO as a Natural World Heritage Site, affirming the timeless beauty of this land.","facts":["It is the largest island in the Cat Ba archipelago of 367 islands large and small.","Cat Ba National Park is home to the critically endangered Cat Ba langur.","Recognized by UNESCO as a Natural World Heritage Site in 2023.","Lan Ha Bay has more than 130 small beaches tucked among the limestone karsts."],"travelTips":["Book a kayak tour in the early morning to avoid the heat and crowds.","Wear shoes with good grip if you plan to climb Ngu Lam peak or trek in the national park."],"bestTime":"April to September","visitDuration":"2 days, 1 night","ticket":"80,000 VND","openingHours":"All day","galleryCaptions":["Lan Ha Bay seen from above","The clear waters of Cat Co Beach","Cat Ba National Park"]},"ko":{"name":"깟바섬","summary":"원시림과 맑고 푸른 해변, 웅장한 석회암 만을 품은 란하만에서 가장 큰 섬.","story":"깟바는 하이퐁의 푸른 보석으로, 국립공원이 바다를 감싸 안고 비취빛 물 사이로 석회암 산맥이 솟아오른 곳입니다. 이 섬은 전 세계에 수십 마리밖에 남지 않은 희귀종 깟바랑구르로 유명합니다. 여행자는 카약을 타고 란하만을 누비거나, 응으럼 봉우리에 올라 전경을 감상하거나, 곱고 흰 모래사장에 몸을 맡길 수 있습니다. 2023년 하롱베이-깟바 군도가 유네스코 세계 자연 유산으로 등재되어, 이 땅의 시대를 초월한 아름다움을 다시 한번 확인시켜 주었습니다.","facts":["크고 작은 367개의 섬으로 이루어진 깟바 군도에서 가장 큰 섬입니다.","깟바 국립공원은 멸종 위기에 처한 깟바랑구르의 서식지입니다.","2023년 유네스코 세계 자연 유산으로 등재되었습니다.","란하만에는 석회암 산 사이에 숨은 130개가 넘는 작은 해변이 있습니다."],"travelTips":["이른 아침 카약 투어를 예약하면 더위와 혼잡을 피할 수 있습니다.","응으럼 봉우리를 오르거나 국립공원에서 트레킹하려면 접지력 좋은 신발을 챙기세요."],"bestTime":"4월~9월","visitDuration":"1박 2일","ticket":"80,000동","openingHours":"종일","galleryCaptions":["높은 곳에서 내려다본 란하만","맑고 푸른 깟꼬 해변","깟바 국립공원"]},"ja":{"name":"カットバ島","summary":"原生林、透き通った海水浴場、そして雄大な石灰岩の入り江を擁する、ランハ湾最大の島。","story":"カットバ島はハイフォンの緑の宝石。国立公園が海を抱き、エメラルド色の水面に石灰岩の山並みがそびえ立ちます。この島は、世界に数十頭しか残っていない希少なカットバラングール（キンシコウの仲間）で知られています。旅行者はカヤックでランハ湾の入り江を縫うように進んだり、グーラム山の頂に登って全景を眺めたり、きめ細やかな白砂のビーチで身を委ねたりできます。2023年、ハロン湾・カットバ群島はユネスコ世界自然遺産に登録され、この地の時を超えた美しさが認められました。","facts":["大小367の島々からなるカットバ群島で最大の島です。","カットバ国立公園は、絶滅危惧種カットバラングールの生息地です。","2023年にユネスコ世界自然遺産として登録されました。","ランハ湾には石灰岩の山々に隠れた小さな海水浴場が130以上あります。"],"travelTips":["日差しと混雑を避けるため、カヤックツアーは早朝に予約しましょう。","グーラム山に登ったり国立公園でトレッキングをするなら、グリップのよい靴を持参しましょう。"],"bestTime":"4月から9月","visitDuration":"1泊2日","ticket":"80,000ドン","openingHours":"終日","galleryCaptions":["上空から眺めるランハ湾","透き通ったカットコー海水浴場","カットバ国立公園"]},"zh":{"name":"吉婆岛","summary":"兰下湾最大的岛屿，拥有原始森林、清澈的海滩和雄奇壮丽的石灰岩海湾。","story":"吉婆岛是海防的一颗绿色明珠，国家森林环抱海洋，一座座石灰岩山峰从碧绿的海水中拔地而起。岛上以珍稀的吉婆叶猴闻名，这一物种全世界仅存数十只。游客可以划皮划艇穿梭于兰下湾之间，攀登御林峰俯瞰全景，或在洁白细腻的沙滩上尽情放松。2023年，下龙湾—吉婆岛景观群被联合国教科文组织列入世界自然遗产，彰显了这片土地超越时间的美。","facts":["是由367座大小岛屿组成的吉婆群岛中最大的岛屿。","吉婆国家森林是极度濒危的吉婆叶猴的栖息地。","于2023年被联合国教科文组织列入世界自然遗产。","兰下湾拥有130多处隐藏在石灰岩山间的小海滩。"],"travelTips":["预订清晨的皮划艇行程，可避开烈日和人群。","若想攀登御林峰或在国家森林中徒步，请穿防滑性能好的鞋子。"],"bestTime":"4月至9月","visitDuration":"两天一夜","ticket":"80,000越南盾","openingHours":"全天","galleryCaptions":["俯瞰兰下湾","碧绿清澈的吉哥海滩","吉婆国家森林"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hp-do-son-beach', 'bai-bien-do-son', 'hai-phong', 'Bãi biển Đồ Sơn', 'Do Son Beach', 'beach', 106.7872, 20.7142, 'Bãi biển truyền thống của miền Bắc với hàng phi lao rì rào, sóng êm và lễ hội chọi trâu nức tiếng.', 'Đồ Sơn là điểm nghỉ mát quen thuộc của người Hải Phòng và du khách miền Bắc suốt hơn một thế kỷ. Bán đảo nhô ra biển với ba khu bãi tắm trải dài dưới hàng phi lao xanh, từng là nơi nghỉ dưỡng của vua Bảo Đại và giới thượng lưu thời Pháp. Nơi đây còn nổi tiếng với lễ hội chọi trâu diễn ra mùng 9 tháng 8 âm lịch, một di sản văn hóa phi vật thể quốc gia đầy khí thế. Buổi chiều, du khách dạo bến Nghiêng lịch sử, thưởng thức hải sản tươi rói và ngắm hoàng hôn buông xuống cửa biển.', '["Lễ hội chọi trâu Đồ Sơn là Di sản văn hóa phi vật thể quốc gia.","Từng là khu nghỉ dưỡng của vua Bảo Đại với biệt thự trên đồi.","Bến Nghiêng là nơi lính Pháp cuối cùng rút khỏi miền Bắc năm 1955.","Bãi biển chia thành ba khu I, II, III với cảnh quan khác nhau."]', '["Đến vào dịp lễ hội chọi trâu tháng 8 âm lịch để cảm nhận không khí náo nhiệt.","Thưởng thức hải sản tại các nhà hàng ven bãi II để có giá hợp lý nhất."]', 'Tháng 5 đến tháng 8', '1 ngày', '', 'Cả ngày', '["festival","popular","verified"]', '["beach","culture","food"]', '[{"seed":"hp-do-son-beach-1","caption":"Bãi tắm Đồ Sơn dưới hàng phi lao","ratio":"16/9"},{"seed":"hp-do-son-beach-2","caption":"Lễ hội chọi trâu truyền thống","ratio":"4/3"},{"seed":"hp-do-son-beach-3","caption":"Hoàng hôn trên bán đảo Đồ Sơn","ratio":"1/1"}]', '["hp-cat-ba-island"]', 0, '{"en":{"name":"Do Son Beach","summary":"Northern Vietnam''s classic seaside resort, with rustling casuarina trees, gentle waves, and a famous buffalo-fighting festival.","story":"Do Son has been a beloved seaside escape for the people of Hai Phong and northern travelers for over a century. The peninsula juts out into the sea with three stretches of beach lined by green casuarinas, once a holiday retreat for Emperor Bao Dai and the elite of the French era. It is also famed for its buffalo-fighting festival held on the 9th day of the 8th lunar month, a spirited national intangible cultural heritage. In the afternoon, visitors stroll along the historic Nghieng Wharf, savor fresh seafood, and watch the sunset settle over the river mouth.","facts":["The Do Son buffalo-fighting festival is a national intangible cultural heritage.","Once a resort of Emperor Bao Dai, with villas on the hillside.","Nghieng Wharf is where the last French troops withdrew from the North in 1955.","The beach is divided into three areas — I, II, and III — each with distinct scenery."],"travelTips":["Come during the buffalo-fighting festival in the 8th lunar month to feel the lively atmosphere.","Enjoy seafood at the restaurants along Beach II for the most reasonable prices."],"bestTime":"May to August","visitDuration":"1 day","ticket":"","openingHours":"All day","galleryCaptions":["Do Son Beach beneath the rows of casuarinas","The traditional buffalo-fighting festival","Sunset over the Do Son peninsula"]},"ko":{"name":"도선 해변","summary":"사각거리는 목마황 가로수와 잔잔한 파도, 그리고 유명한 물소 싸움 축제를 간직한 북부의 전통 해변.","story":"도선은 한 세기가 넘도록 하이퐁 사람들과 북부 여행자들에게 친숙한 휴양지입니다. 바다로 뻗어 나온 반도에는 푸른 목마황 가로수 아래 세 구역의 해변이 길게 펼쳐져 있으며, 한때 바오다이 황제와 프랑스 시대 상류층의 휴양지였습니다. 이곳은 또한 음력 8월 9일에 열리는 물소 싸움 축제로도 유명한데, 이는 기백 넘치는 국가 무형문화유산입니다. 오후에는 역사적인 응이엥 부두를 거닐고, 싱싱한 해산물을 맛보며 바다 어귀로 지는 노을을 감상할 수 있습니다.","facts":["도선 물소 싸움 축제는 국가 무형문화유산입니다.","한때 언덕 위 별장과 함께 바오다이 황제의 휴양지였습니다.","응이엥 부두는 1955년 마지막 프랑스 군대가 북부에서 철수한 곳입니다.","해변은 풍경이 서로 다른 1, 2, 3구역으로 나뉩니다."],"travelTips":["음력 8월 물소 싸움 축제 기간에 방문하면 떠들썩한 분위기를 느낄 수 있습니다.","2구역 해변가 식당에서 해산물을 맛보면 가장 합리적인 가격에 즐길 수 있습니다."],"bestTime":"5월~8월","visitDuration":"1일","ticket":"","openingHours":"종일","galleryCaptions":["목마황 가로수 아래 도선 해변","전통 물소 싸움 축제","도선 반도의 노을"]},"ja":{"name":"ドーソンビーチ","summary":"そよぐモクマオウの並木、穏やかな波、そして名高い闘水牛祭りで知られる、北部伝統の海辺。","story":"ドーソンは、一世紀以上にわたってハイフォンの人々や北部の旅行者に親しまれてきた避暑地です。海に突き出た半島には、青々としたモクマオウの並木の下に三つの海水浴場が広がり、かつてはバオダイ帝やフランス統治時代の上流階級の保養地でもありました。また、旧暦8月9日に行われる闘水牛祭りでも知られ、活気あふれるこの国家無形文化遺産は一見の価値があります。午後には歴史あるニエン埠頭を散策し、新鮮な海の幸を味わい、河口に沈む夕日を眺めることができます。","facts":["ドーソンの闘水牛祭りは国家無形文化遺産です。","かつては丘の上に別荘を構えたバオダイ帝の保養地でした。","ニエン埠頭は1955年にフランス兵が北部から最後に撤退した地です。","ビーチはそれぞれ趣の異なる第一・第二・第三の三区域に分かれています。"],"travelTips":["活気あふれる雰囲気を味わうなら、旧暦8月の闘水牛祭りの時期に訪れましょう。","海の幸を最もお手頃に楽しむなら、第二ビーチ沿いのレストランがおすすめです。"],"bestTime":"5月から8月","visitDuration":"1日","ticket":"","openingHours":"終日","galleryCaptions":["モクマオウ並木の下のドーソンビーチ","伝統の闘水牛祭り","ドーソン半島の夕暮れ"]},"zh":{"name":"图山海滩","summary":"北部传统的海滩，木麻黄沙沙作响、海浪平缓，更有名扬四方的斗牛节。","story":"图山一个多世纪以来都是海防人和北部游客熟悉的避暑胜地。半岛伸入海中，三处沙滩在青翠的木麻黄树下绵延铺展，这里曾是保大皇帝和法国时期上流社会的度假之地。此地还以农历八月初九举行的斗牛节闻名，那是一项气势磅礴的国家级非物质文化遗产。傍晚时分，游客漫步于历史悠久的倾斜码头，品尝鲜活的海鲜，欣赏夕阳沉入海口的美景。","facts":["图山斗牛节是国家级非物质文化遗产。","曾是保大皇帝的度假区，山丘上建有别墅。","倾斜码头是1955年最后一批法军撤离北部之地。","海滩分为一、二、三三个区域，各具不同景观。"],"travelTips":["在农历八月斗牛节期间前来，感受热闹喧腾的氛围。","在二区海滩边的餐馆品尝海鲜，价格最为合理。"],"bestTime":"5月至8月","visitDuration":"一天","ticket":"","openingHours":"全天","galleryCaptions":["木麻黄树下的图山海滩","传统斗牛节","图山半岛上的夕阳"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bn-den-do', 'den-do', 'bac-ninh', 'Đền Đô', 'Do Temple', 'temple', 105.9686, 21.1239, 'Ngôi đền cổ thờ tám vị vua nhà Lý, kiến trúc bề thế giữa vùng đất Kinh Bắc địa linh nhân kiệt.', 'Đền Đô, hay Cổ Pháp điện, là nơi thờ phụng tám vị vua triều Lý, vương triều khai mở nền văn minh Đại Việt rực rỡ. Tọa lạc tại làng Đình Bảng, đền được xây dựng từ thời Lý Công Uẩn và trùng tu qua nhiều thế kỷ với lối kiến trúc đăng đối, mái cong uy nghi soi bóng xuống hồ bán nguyệt. Mỗi độ rằm tháng ba âm lịch, lễ hội Đền Đô tưng bừng tái hiện cảnh vua Lý Thái Tổ rời đô về Thăng Long. Đây là nơi hội tụ tinh hoa văn hóa Kinh Bắc, gắn liền với những làn quan họ ngọt ngào say đắm lòng người.', '["Thờ tám vị vua triều Lý, bắt đầu từ Lý Thái Tổ Lý Công Uẩn.","Còn được gọi là Cổ Pháp điện, thuộc làng Đình Bảng cổ kính.","Lễ hội Đền Đô diễn ra ngày 15 tháng 3 âm lịch hằng năm.","Nhà Thủy đình trên hồ bán nguyệt là nơi diễn xướng quan họ."]', '["Kết hợp nghe hát quan họ vào dịp lễ hội tháng ba âm lịch.","Ghé thăm đình Đình Bảng gần đó để thưởng lãm kiến trúc gỗ tuyệt mỹ."]', 'Tháng 3 đến tháng 4 âm lịch', 'Nửa ngày', '', '07:00 - 18:00', '["festival","verified","popular"]', '["temple","history","culture"]', '[{"seed":"bn-den-do-1","caption":"Cổng tam quan Đền Đô uy nghi","ratio":"16/9"},{"seed":"bn-den-do-2","caption":"Thủy đình trên hồ bán nguyệt","ratio":"4/3"},{"seed":"bn-den-do-3","caption":"Lễ hội Đền Đô tháng ba","ratio":"1/1"}]', '["bn-dong-ho"]', 1, '{"en":{"name":"Do Temple","summary":"An ancient temple honoring eight Ly Dynasty kings, an imposing structure in the storied land of Kinh Bac.","story":"Do Temple, also known as Co Phap Palace, is dedicated to the eight kings of the Ly Dynasty, the royal house that opened Dai Viet''s brilliant civilization. Located in Dinh Bang village, the temple was built in the time of Ly Cong Uan and restored over many centuries, with symmetrical architecture and majestic curved roofs reflected in a crescent-shaped pond. Each year on the full moon of the third lunar month, the Do Temple Festival vividly re-enacts King Ly Thai To''s move of the capital to Thang Long. This is where the cultural essence of Kinh Bac converges, bound up with the sweet, captivating melodies of quan ho folk song.","facts":["Honors eight kings of the Ly Dynasty, beginning with Ly Thai To (Ly Cong Uan).","Also called Co Phap Palace, in the ancient village of Dinh Bang.","The Do Temple Festival is held on the 15th day of the third lunar month each year.","The Water Pavilion on the crescent pond is where quan ho singing is performed."],"travelTips":["Pair your visit with quan ho singing during the festival in the third lunar month.","Visit the nearby Dinh Bang communal house to admire its exquisite woodwork."],"bestTime":"Third to fourth lunar month","visitDuration":"Half a day","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["The imposing triple gate of Do Temple","The Water Pavilion on the crescent pond","The Do Temple Festival in the third lunar month"]},"ko":{"name":"덴도 사당","summary":"리 왕조 여덟 왕을 모시는 고찰, 인재가 끊이지 않는 낀박 땅 한가운데 우뚝 선 장엄한 건축물.","story":"덴도, 또는 꼬팝 전(殿)은 찬란한 다이비엣 문명을 연 리 왕조 여덟 왕을 모시는 곳입니다. 딘방 마을에 자리 잡은 이 사당은 리꽁우언 시대에 지어져 여러 세기에 걸쳐 보수되었으며, 좌우 대칭의 건축과 위엄 있게 휘어진 지붕이 반월형 연못에 그림자를 드리웁니다. 음력 3월 보름이면 덴도 축제가 성대하게 열려 리타이또 왕이 탕롱으로 천도하는 장면을 재현합니다. 이곳은 낀박 문화의 정수가 모인 곳으로, 사람의 마음을 사로잡는 달콤한 꽌호 가락과 깊이 얽혀 있습니다.","facts":["리타이또 리꽁우언을 시작으로 리 왕조 여덟 왕을 모십니다.","꼬팝 전이라고도 불리며, 고풍스러운 딘방 마을에 속합니다.","덴도 축제는 매년 음력 3월 15일에 열립니다.","반월형 연못 위의 수상 정자는 꽌호를 공연하는 곳입니다."],"travelTips":["음력 3월 축제 기간에 맞춰 꽌호 노래를 함께 감상하세요.","근처 딘방 정자에 들러 빼어난 목조 건축을 감상하세요."],"bestTime":"음력 3월~4월","visitDuration":"반나절","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["위엄 있는 덴도 삼문","반월형 연못 위의 수상 정자","음력 3월의 덴도 축제"]},"ja":{"name":"デンドー（李朝廟）","summary":"李朝八代の王を祀る古廟。人傑地霊の地キンバクに、堂々たる威容を誇ります。","story":"デンドー、別名コーファップ殿は、輝かしい大越文明を切り開いた王朝・李朝の八代の王を祀る場所です。ディンバン村に位置するこの廟は、李公蘊（リー・コンウアン）の時代に建立され、幾世紀にもわたって修復を重ねながら、左右対称の建築と威厳ある反り返った屋根を半月池の水面に映してきました。旧暦3月15日には、デンドー祭りがにぎやかに催され、李太祖がタンロンへ遷都した光景が再現されます。ここはキンバク文化の精華が集う地であり、人々の心を酔わせる甘美なクアンホ民謡と深く結びついています。","facts":["李太祖・李公蘊をはじめとする李朝八代の王を祀っています。","コーファップ殿とも呼ばれ、古き趣のディンバン村に位置します。","デンドー祭りは毎年旧暦3月15日に行われます。","半月池の上に建つ水亭は、クアンホ民謡が演じられる場所です。"],"travelTips":["旧暦3月の祭りの時期に合わせて、クアンホ民謡の鑑賞も楽しみましょう。","近くのディンバン村の亭（ディン）にも立ち寄り、見事な木造建築を堪能しましょう。"],"bestTime":"旧暦3月から4月","visitDuration":"半日","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["威厳あるデンドーの三関門","半月池の上の水亭","旧暦3月のデンドー祭り"]},"zh":{"name":"都庙","summary":"供奉李朝八位皇帝的古庙，气势恢宏，坐落于人杰地灵的京北之地。","story":"都庙，又称古法殿，是供奉李朝八位皇帝的地方，正是这一王朝开创了辉煌的大越文明。它坐落于亭榜村，自李公蕴时期建成，历经数个世纪重修，建筑布局对称，巍峨的飞檐倒映在半月形池塘上。每逢农历三月十五，都庙庙会热闹非凡，重现李太祖迁都升龙的盛景。这里汇聚了京北文化的精华，与缠绵动人的官贺民歌交相辉映。","facts":["供奉李朝八位皇帝，始于李太祖李公蕴。","又称古法殿，位于古朴的亭榜村。","都庙庙会于每年农历三月十五举行。","半月池上的水亭是演唱官贺民歌的场所。"],"travelTips":["在农历三月庙会期间前来，可一并欣赏官贺民歌。","顺道参观附近的亭榜亭，欣赏精美绝伦的木构建筑。"],"bestTime":"农历三月至四月","visitDuration":"半天","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["庄严的都庙三关门","半月池上的水亭","三月的都庙庙会"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bn-dong-ho', 'lang-tranh-dong-ho', 'bac-ninh', 'Làng tranh Đông Hồ', 'Dong Ho Painting Village', 'village', 106.0631, 21.0561, 'Làng nghề tranh dân gian trứ danh bên dòng sông Đuống, lưu giữ hồn Việt qua từng bản khắc gỗ.', 'Làng Đông Hồ nằm bên bờ sông Đuống thơ mộng, là cái nôi của dòng tranh dân gian độc đáo bậc nhất Việt Nam. Tranh Đông Hồ được in trên giấy điệp lấp lánh vỏ sò, màu sắc hoàn toàn từ thiên nhiên: đỏ son, vàng hoa hòe, xanh lá chàm, đen than lá tre. Những bức Đám cưới chuột, Lợn đàn, Gà đại cát không chỉ đẹp mà còn gửi gắm triết lý nhân sinh và ước vọng no ấm của người nông dân. Trải qua bao thăng trầm, các nghệ nhân nơi đây vẫn miệt mài giữ lửa nghề. Nghề làm tranh Đông Hồ đang được đề nghị UNESCO ghi danh Di sản văn hóa phi vật thể cần bảo vệ khẩn cấp.', '["Tranh được in trên giấy điệp làm từ vỏ sò nghiền pha hồ nếp.","Màu sắc hoàn toàn từ nguyên liệu thiên nhiên truyền thống.","Mỗi bức tranh cần nhiều bản khắc gỗ, mỗi bản một màu riêng.","Nghề tranh Đông Hồ là Di sản văn hóa phi vật thể quốc gia."]', '["Ghé nhà nghệ nhân để tự tay in thử một bức tranh làm kỷ niệm.","Mua tranh trực tiếp tại làng để ủng hộ các gia đình giữ nghề."]', 'Tháng 11 đến tháng 1 (cận Tết)', 'Nửa ngày', '', '08:00 - 17:00', '["verified","hidden-gem","ai-recommended"]', '["village","culture","history"]', '[{"seed":"bn-dong-ho-1","caption":"Nghệ nhân in tranh trên giấy điệp","ratio":"16/9"},{"seed":"bn-dong-ho-2","caption":"Tranh thờ Táo Quân rực rỡ sắc màu dân gian","ratio":"4/3"},{"seed":"bn-dong-ho-3","caption":"Tranh đàn cá chép bơi giữa sen","ratio":"1/1"}]', '["bn-den-do"]', 0, '{"en":{"name":"Dong Ho Painting Village","summary":"A celebrated folk-painting craft village on the banks of the Duong River, preserving the Vietnamese soul through each woodblock print.","story":"Dong Ho village lies along the poetic banks of the Duong River, the cradle of one of Vietnam''s most distinctive folk-painting traditions. Dong Ho paintings are printed on diep paper that glitters with crushed seashell, their colors entirely natural: vermilion red, sophora yellow, indigo green, and the black of burnt bamboo leaves. Pieces like ''The Rats'' Wedding'', ''The Pig Family'', and ''Rooster of Prosperity'' are not only beautiful but also convey a philosophy of life and the farmer''s wish for plenty. Through all its ups and downs, the artisans here still tirelessly keep the craft alive. The Dong Ho painting craft is being proposed to UNESCO for inscription as intangible cultural heritage in urgent need of safeguarding.","facts":["The paintings are printed on diep paper made from ground seashell mixed with glutinous-rice paste.","The colors come entirely from traditional natural materials.","Each painting requires several woodblocks, one for each color.","The Dong Ho painting craft is a national intangible cultural heritage."],"travelTips":["Visit an artisan''s home to try printing a painting yourself as a keepsake.","Buy paintings directly in the village to support the families keeping the craft alive."],"bestTime":"November to January (the lead-up to Tet)","visitDuration":"Half a day","ticket":"","openingHours":"08:00 - 17:00","galleryCaptions":["An artisan printing a painting on diep paper","A worship painting of the Kitchen Gods, radiant with folk colors","A painting of carp swimming among lotus flowers"]},"ko":{"name":"동호 그림 마을","summary":"두옹강 가에 자리한 이름난 민화 마을, 목판 하나하나에 베트남의 혼을 담아 전하는 곳.","story":"동호 마을은 시적인 두옹강 기슭에 자리해, 베트남에서 가장 독특한 민화의 발상지입니다. 동호 그림은 조개껍데기로 반짝이는 디엡 종이에 인쇄되며, 색은 모두 자연에서 나옵니다. 주홍빛은 진사(辰砂), 노란빛은 회화나무꽃, 푸른빛은 쪽, 검은빛은 대나무 잎 숯에서 얻습니다. 「쥐의 결혼식」, 「돼지 가족」, 「대길(大吉) 닭」 같은 그림은 아름다울 뿐 아니라 인생철학과 풍요를 바라는 농민의 소망을 담고 있습니다. 수많은 부침을 겪으면서도 이곳 장인들은 묵묵히 가업의 불씨를 지켜 왔습니다. 동호 그림 제작 기술은 현재 긴급 보호가 필요한 무형문화유산으로 유네스코에 등재 신청 중입니다.","facts":["그림은 조개껍데기를 갈아 찹쌀 풀에 섞어 만든 디엡 종이에 인쇄됩니다.","색은 모두 전통적인 천연 재료에서 얻습니다.","그림 한 장에는 여러 개의 목판이 필요하며, 판 하나가 색 하나를 맡습니다.","동호 그림 제작 기술은 국가 무형문화유산입니다."],"travelTips":["장인의 집에 들러 직접 그림 한 장을 찍어 기념으로 만들어 보세요.","마을에서 직접 그림을 구입해 가업을 잇는 가정을 후원하세요."],"bestTime":"11월~1월(설 즈음)","visitDuration":"반나절","ticket":"","openingHours":"08:00 - 17:00","galleryCaptions":["디엡 종이에 그림을 찍는 장인","민화의 화려한 색감이 살아 있는 부엌신(竈神) 그림","연꽃 사이를 헤엄치는 잉어 떼 그림"]},"ja":{"name":"ドンホー版画村","summary":"ドゥオン川のほとりに伝わる名高い民間版画の里。一枚一枚の木版にベトナムの魂を留めています。","story":"ドンホー村は詩情あふれるドゥオン川のほとりに位置し、ベトナム随一の独創的な民間版画の発祥地です。ドンホー版画は貝殻の輝きを宿すゼップ紙に刷られ、その色彩はすべて自然由来——朱の赤、エンジュの黄、藍の緑、竹炭の黒。「ねずみの婚礼」「群豚」「大吉鶏」といった作品は美しいだけでなく、農民の人生観と豊かな暮らしへの願いを託しています。幾多の浮き沈みを経てもなお、この地の職人たちはひたむきに技を守り続けています。ドンホー版画の技は、緊急に保護を要する無形文化遺産としてユネスコへの登録が提案されています。","facts":["版画は、貝殻を砕いてもち米糊と混ぜたゼップ紙に刷られます。","色彩はすべて伝統的な天然素材から作られます。","一枚の版画には複数の木版が必要で、それぞれ一色を担います。","ドンホー版画の技は国家無形文化遺産です。"],"travelTips":["職人の家に立ち寄り、自分の手で一枚刷って記念にしましょう。","技を守る家々を応援するため、版画は村で直接購入しましょう。"],"bestTime":"11月から1月（テト前）","visitDuration":"半日","ticket":"","openingHours":"08:00 - 17:00","galleryCaptions":["ゼップ紙に版画を刷る職人","鮮やかな民間色の竈神（タオクアン）祭祀画","蓮の間を泳ぐ鯉の群れの版画"]},"zh":{"name":"东胡画村","summary":"潄江畔声名远扬的民间年画村，以一块块木刻版留住越南之魂。","story":"东胡村坐落在风景如画的潄江岸边，是越南最独特的民间年画的发源地。东胡画印在闪烁着贝壳光泽的蚌粉纸上，色彩全部取自天然：朱砂红、槐花黄、靛蓝、竹叶炭黑。《老鼠娶亲》《群猪》《大吉鸡》等画作不仅美观，更寄托着农民对人生的哲思与对温饱的祈愿。历经岁月沉浮，这里的艺人依然孜孜不倦地守护着这门手艺。东胡年画技艺正被申报列入联合国教科文组织亟需保护的非物质文化遗产名录。","facts":["画作印在以贝壳研磨掺糯米浆制成的蚌粉纸上。","色彩全部取自传统天然原料。","每幅画需要多块木刻版，每块对应一种颜色。","东胡年画技艺是国家级非物质文化遗产。"],"travelTips":["前往艺人家中，亲手印制一幅画作留作纪念。","在村中直接购画，支持坚守手艺的家庭。"],"bestTime":"11月至次年1月（临近春节）","visitDuration":"半天","ticket":"","openingHours":"08:00 - 17:00","galleryCaptions":["艺人在蚌粉纸上印画","色彩绚丽的灶君祭祀年画","群鲤戏莲年画"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hd-con-son-kiep-bac', 'con-son-kiep-bac', 'hai-duong', 'Côn Sơn - Kiếp Bạc', 'Con Son - Kiep Bac', 'temple', 106.3892, 21.1336, 'Quần thể di tích quốc gia đặc biệt gắn với Trần Hưng Đạo và Nguyễn Trãi, ẩn mình giữa rừng thông xanh.', 'Côn Sơn - Kiếp Bạc là quần thể di tích linh thiêng bậc nhất xứ Đông, nơi lưu dấu hai vị anh hùng dân tộc. Đền Kiếp Bạc thờ Hưng Đạo Đại Vương Trần Quốc Tuấn, người ba lần đánh tan quân Nguyên Mông, tọa lạc bên dòng Lục Đầu Giang hùng vĩ. Cách đó không xa, chùa Côn Sơn nép mình dưới rừng thông bạt ngàn, gắn với danh nhân văn hóa thế giới Nguyễn Trãi cùng câu thơ Côn Sơn suối chảy rì rầm. Mỗi mùa thu, lễ hội Kiếp Bạc và lễ hội Côn Sơn thu hút hàng vạn người về dâng hương, tưởng nhớ công đức tiền nhân giữa khung cảnh non nước hữu tình.', '["Đền Kiếp Bạc thờ Hưng Đạo Đại Vương Trần Quốc Tuấn.","Chùa Côn Sơn gắn liền với danh nhân văn hóa Nguyễn Trãi.","Được xếp hạng Di tích quốc gia đặc biệt năm 2012.","Lễ hội mùa thu Kiếp Bạc diễn ra rằm tháng tám âm lịch."]', '["Leo bộ lên Bàn Cờ Tiên trên đỉnh núi Côn Sơn để ngắm toàn cảnh.","Về dự lễ hội mùa xuân và mùa thu để cảm nhận không khí linh thiêng."]', 'Tháng 1 và tháng 8 âm lịch', '1 ngày', '', '06:30 - 18:00', '["festival","verified","popular"]', '["temple","history","nature","culture"]', '[{"seed":"hd-con-son-kiep-bac-1","caption":"Đền Kiếp Bạc bên Lục Đầu Giang","ratio":"16/9"},{"seed":"hd-con-son-kiep-bac-2","caption":"Chùa Côn Sơn giữa rừng thông","ratio":"4/3"},{"seed":"hd-con-son-kiep-bac-3","caption":"Lễ hội mùa thu truyền thống","ratio":"1/1"}]', '["hd-dao-co"]', 1, '{"en":{"name":"Con Son - Kiep Bac","summary":"A special national relic complex linked to Tran Hung Dao and Nguyen Trai, hidden among green pine forests.","story":"Con Son - Kiep Bac is one of the most sacred relic complexes of the eastern region, where two national heroes left their mark. Kiep Bac Temple honors Hung Dao Dai Vuong Tran Quoc Tuan, who thrice defeated the Mongol-Yuan invaders, standing beside the majestic Luc Dau River. Not far away, Con Son Pagoda nestles beneath vast pine forests, tied to the world cultural figure Nguyen Trai and his verse, ''At Con Son the stream murmurs as it flows.'' Each autumn, the Kiep Bac and Con Son festivals draw tens of thousands to offer incense and honor the merits of their forebears amid the harmonious beauty of mountains and water.","facts":["Kiep Bac Temple honors Hung Dao Dai Vuong Tran Quoc Tuan.","Con Son Pagoda is closely tied to the cultural figure Nguyen Trai.","Ranked as a special national relic in 2012.","The Kiep Bac autumn festival takes place on the full moon of the eighth lunar month."],"travelTips":["Hike up to the Immortals'' Chessboard atop Con Son mountain for a panoramic view.","Come for the spring and autumn festivals to feel the sacred atmosphere."],"bestTime":"First and eighth lunar months","visitDuration":"1 day","ticket":"","openingHours":"06:30 - 18:00","galleryCaptions":["Kiep Bac Temple beside the Luc Dau River","Con Son Pagoda amid the pine forest","The traditional autumn festival"]},"ko":{"name":"꼰선-끼엡박","summary":"쩐흥다오와 응우옌짜이와 얽힌 국가 특별 유적지로, 푸른 소나무 숲 속에 자리한 유적군.","story":"꼰선-끼엡박은 동(東) 지방에서 가장 신성한 유적군으로, 두 민족 영웅의 자취가 깃든 곳입니다. 끼엡박 사당은 원나라 몽골군을 세 차례 물리친 흥다오 대왕 쩐꾸옥뚜언을 모시며, 웅장한 룩더우강 가에 자리합니다. 그곳에서 멀지 않은 곳에 끝없이 펼쳐진 소나무 숲 아래 꼰선 사찰이 자리하는데, 세계 문화 위인 응우옌짜이와 그의 시구 「꼰선의 시냇물은 잔잔히 흐르고」와 얽혀 있습니다. 가을마다 끼엡박 축제와 꼰선 축제가 수만 명을 불러 모아, 빼어난 산수 속에서 선조의 공덕을 기리며 향을 올립니다.","facts":["끼엡박 사당은 흥다오 대왕 쩐꾸옥뚜언을 모십니다.","꼰선 사찰은 문화 위인 응우옌짜이와 깊이 얽혀 있습니다.","2012년 국가 특별 유적으로 지정되었습니다.","끼엡박 가을 축제는 음력 8월 보름에 열립니다."],"travelTips":["꼰선산 정상의 반꼬띠엔까지 걸어 올라 전경을 감상하세요.","봄과 가을 축제에 참석해 신성한 분위기를 느껴 보세요."],"bestTime":"음력 1월과 8월","visitDuration":"1일","ticket":"","openingHours":"06:30 - 18:00","galleryCaptions":["룩더우강 가의 끼엡박 사당","소나무 숲 속의 꼰선 사찰","전통 가을 축제"]},"ja":{"name":"コンソン・キエプバク","summary":"チャン・フン・ダオとグエン・チャイゆかりの国家特別史跡群。青々とした松林の中に静かに佇みます。","story":"コンソン・キエプバクは東地方随一の神聖な史跡群であり、二人の民族的英雄の足跡を留める地です。キエプバク祠は、元（モンゴル）の軍を三度退けた興道大王チャン・クオック・トゥアンを祀り、雄大なルクダウ川のほとりに位置します。そこからほど近く、コンソン寺は果てしない松林の下に佇み、世界的文化人グエン・チャイと、その詩句「コンソンの泉はさらさらと流れる」にゆかりがあります。秋になるとキエプバク祭りとコンソン祭りが催され、山紫水明の景色の中、幾万もの人々が線香を手向け先人の功徳を偲びに訪れます。","facts":["キエプバク祠には興道大王チャン・クオック・トゥアンが祀られています。","コンソン寺は文化人グエン・チャイと深く結びついています。","2012年に国家特別史跡に格付けされました。","キエプバクの秋祭りは旧暦8月15日に行われます。"],"travelTips":["コンソン山頂のバンコーティエン（仙人の碁盤）まで歩いて登り、全景を眺めましょう。","春と秋の祭りに参列し、神聖な雰囲気を体感しましょう。"],"bestTime":"旧暦1月と8月","visitDuration":"1日","ticket":"","openingHours":"06:30 - 18:00","galleryCaptions":["ルクダウ川のほとりのキエプバク祠","松林の中のコンソン寺","伝統の秋祭り"]},"zh":{"name":"昆山-劫泊","summary":"与陈兴道和阮廌相关的国家特级遗迹群，隐于青翠的松林之间。","story":"昆山-劫泊是东地区最为神圣的遗迹群，留有两位民族英雄的足迹。劫泊庙供奉三次大败元蒙军的兴道大王陈国峻，坐落在雄伟的六头江畔。不远处，昆山寺掩映在茫茫松林之下，与世界文化名人阮廌及其诗句「昆山泉流潺潺」紧密相连。每到秋季，劫泊庙会与昆山庙会吸引成千上万的人前来上香，在山水如画的景致中缅怀先贤的功德。","facts":["劫泊庙供奉兴道大王陈国峻。","昆山寺与文化名人阮廌紧密相连。","于2012年被列为国家特级遗迹。","劫泊秋季庙会于农历八月十五举行。"],"travelTips":["徒步登上昆山顶的仙人棋盘，俯瞰全景。","在春季和秋季庙会期间前来，感受神圣庄严的氛围。"],"bestTime":"农历正月和八月","visitDuration":"一天","ticket":"","openingHours":"06:30 - 18:00","galleryCaptions":["六头江畔的劫泊庙","松林之中的昆山寺","传统的秋季庙会"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hd-dao-co', 'dao-co-chi-lang-nam', 'hai-duong', 'Đảo Cò Chi Lăng Nam', 'Chi Lang Nam Stork Island', 'park', 106.2289, 20.8067, 'Hòn đảo giữa hồ An Dương là thiên đường của hàng vạn cánh cò vạc, điểm sinh thái độc đáo của đồng bằng.', 'Giữa lòng hồ An Dương xanh biếc, Đảo Cò Chi Lăng Nam hiện lên như một ốc đảo của tự nhiên, nơi trú ngụ của hàng vạn con cò, vạc, diệc, mòng két. Hình thành từ những trận lụt vỡ đê hàng thế kỷ trước, hai gò đất nổi dần trở thành chốn an cư cho đàn chim trời. Bình minh và hoàng hôn là khoảnh khắc kỳ diệu nhất, khi từng đàn cò trắng rợp trời bay về tổ tạo nên bức tranh thiên nhiên sống động. Du khách lên thuyền nan lướt nhẹ quanh đảo, lắng nghe tiếng chim ríu rít và hít hà bầu không khí trong lành hiếm có giữa đồng bằng Bắc Bộ.', '["Nơi cư trú của khoảng 15.000 con cò và 5.000 con vạc.","Hình thành tự nhiên từ những lần vỡ đê hàng trăm năm trước.","Có tới chín loài cò và ba loài vạc cùng nhiều loài chim nước.","Được công nhận là Di tích danh thắng cấp quốc gia."]', '["Đi thuyền lúc bình minh hoặc hoàng hôn để ngắm cò bay rợp trời.","Mang ống nhòm và máy ảnh tele để quan sát chim mà không làm chúng hoảng sợ."]', 'Tháng 9 đến tháng 4', 'Nửa ngày', '30.000đ', '06:00 - 18:00', '["hidden-gem","verified","ai-recommended"]', '["nature","photography"]', '[{"seed":"hd-dao-co-1","caption":"Đàn cò bay về tổ lúc hoàng hôn","ratio":"16/9"},{"seed":"hd-dao-co-2","caption":"Thuyền nan dạo quanh đảo","ratio":"4/3"},{"seed":"hd-dao-co-3","caption":"Hồ An Dương xanh biếc","ratio":"1/1"}]', '["hd-con-son-kiep-bac"]', 0, '{"en":{"name":"Chi Lang Nam Stork Island","summary":"An island in the middle of An Duong Lake is a paradise for tens of thousands of storks and night herons, a unique ecological spot of the delta.","story":"In the heart of the blue-green An Duong Lake, Chi Lang Nam Stork Island appears like an oasis of nature, a refuge for tens of thousands of storks, night herons, egrets, and teals. Formed by dyke breaches and floods centuries ago, two islets gradually rose to become a home for the birds of the sky. Dawn and dusk are the most magical moments, when flocks of white storks fill the sky on their way back to their nests, painting a vivid picture of nature. Visitors glide gently around the island on bamboo boats, listening to the chatter of birds and breathing in the rare fresh air of the Northern delta.","facts":["Home to about 15,000 storks and 5,000 night herons.","Formed naturally by dyke breaches hundreds of years ago.","Hosts up to nine species of stork and three species of night heron, along with many waterbirds.","Recognized as a national scenic relic."],"travelTips":["Take a boat at dawn or dusk to watch the storks fill the sky.","Bring binoculars and a telephoto lens to observe the birds without startling them."],"bestTime":"September to April","visitDuration":"Half a day","ticket":"30,000 VND","openingHours":"06:00 - 18:00","galleryCaptions":["Storks returning to their nests at dusk","A bamboo boat circling the island","The blue-green An Duong Lake"]},"ko":{"name":"찌랑남 백로섬","summary":"안즈엉 호수 한가운데의 섬은 수만 마리 백로와 해오라기의 낙원, 평야의 독특한 생태 명소.","story":"푸르른 안즈엉 호수 한가운데에 찌랑남 백로섬이 자연의 오아시스처럼 떠올라, 수만 마리의 백로와 해오라기, 왜가리, 쇠오리의 보금자리가 됩니다. 수백 년 전 둑이 터진 홍수로 생겨난 두 개의 흙더미가 점차 새들의 안식처가 되었습니다. 새벽과 해 질 녘이 가장 경이로운 순간으로, 하얀 백로 떼가 하늘을 뒤덮으며 둥지로 돌아와 생동감 넘치는 자연의 그림을 그려냅니다. 여행자는 대나무 배에 올라 섬 주위를 가볍게 미끄러지며, 지저귀는 새소리에 귀 기울이고 북부 평야에서는 보기 드문 맑은 공기를 마음껏 들이마실 수 있습니다.","facts":["약 15,000마리의 백로와 5,000마리의 해오라기가 서식하는 곳입니다.","수백 년 전 둑이 여러 차례 터지며 자연적으로 형성되었습니다.","아홉 종의 백로와 세 종의 해오라기를 비롯해 여러 물새가 서식합니다.","국가급 명승 유적으로 인정받았습니다."],"travelTips":["새벽이나 해 질 녘에 배를 타면 하늘을 뒤덮는 백로 떼를 볼 수 있습니다.","쌍안경과 망원 렌즈를 챙겨 새들을 놀라게 하지 않고 관찰하세요."],"bestTime":"9월~4월","visitDuration":"반나절","ticket":"30,000동","openingHours":"06:00 - 18:00","galleryCaptions":["해 질 녘 둥지로 돌아오는 백로 떼","섬 주위를 도는 대나무 배","푸르른 안즈엉 호수"]},"ja":{"name":"チランナム鷺島","summary":"アンズオン湖に浮かぶ島は、幾万羽もの鷺と五位鷺の楽園。デルタ地帯ならではの貴重な生態観察地です。","story":"青く澄んだアンズオン湖の真ん中に、チランナム鷺島は自然のオアシスのように浮かび、幾万羽もの鷺、五位鷺、青鷺、コガモの棲み処となっています。幾世紀も前の決壊した堤防の洪水によって生まれた二つの土の小山は、やがて空を飛ぶ鳥たちの安住の地となりました。夜明けと夕暮れこそが最も幻想的なひととき。白鷺の群れが空を覆って巣へと帰る様は、生き生きとした自然の絵巻を織りなします。旅行者は小舟に乗って島の周りをそっと滑り、鳥たちのさえずりに耳を傾け、北部デルタには稀な澄んだ空気を胸いっぱいに吸い込むことができます。","facts":["およそ15,000羽の鷺と5,000羽の五位鷺の棲み処です。","数百年前の度重なる堤防の決壊によって自然に形成されました。","九種の鷺と三種の五位鷺、その他多くの水鳥が生息しています。","国家級の景勝史跡に認定されています。"],"travelTips":["空を覆う鷺の飛翔を見るなら、夜明けか夕暮れに舟に乗りましょう。","鳥を驚かさず観察するため、双眼鏡と望遠レンズのカメラを持参しましょう。"],"bestTime":"9月から4月","visitDuration":"半日","ticket":"30,000ドン","openingHours":"06:00 - 18:00","galleryCaptions":["夕暮れに巣へ帰る鷺の群れ","島を巡る小舟","青く澄んだアンズオン湖"]},"zh":{"name":"支棱南鹭岛","summary":"安阳湖中央的小岛是成千上万只鹭与夜鹭的天堂，是平原上独特的生态景点。","story":"在碧绿的安阳湖中央，支棱南鹭岛宛如一座大自然的绿洲，是数以万计的鹭、夜鹭、苍鹭、绿头鸭栖息的家园。它由几个世纪前决堤洪水冲积而成，两座隆起的土丘逐渐成为飞鸟安居之所。黎明与黄昏是最神奇的时刻，一群群白鹭遮天蔽日地归巢，构成一幅生动的自然画卷。游客乘坐小竹篷船轻轻绕岛而行，聆听啁啾的鸟鸣，呼吸北部平原难得的清新空气。","facts":["约有15,000只鹭和5,000只夜鹭在此栖息。","由数百年前数次决堤自然冲积形成。","拥有多达九种鹭和三种夜鹭以及众多水鸟。","被认定为国家级风景名胜遗迹。"],"travelTips":["在黎明或黄昏乘船，欣赏鹭鸟漫天飞舞的景象。","携带望远镜和长焦相机观察鸟类，以免惊扰它们。"],"bestTime":"9月至次年4月","visitDuration":"半天","ticket":"30,000越南盾","openingHours":"06:00 - 18:00","galleryCaptions":["黄昏时分归巢的鹭群","绕岛而行的竹篷船","碧绿的安阳湖"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hy-pho-hien', 'pho-hien', 'hung-yen', 'Phố Hiến', 'Pho Hien', 'city', 106.0511, 20.6394, 'Thương cảng sầm uất một thời với câu Thứ nhất Kinh Kỳ, thứ nhì Phố Hiến, nay là quần thể di tích cổ kính.', 'Phố Hiến từng là thương cảng phồn hoa bậc nhất Đàng Ngoài thế kỷ XVII, nơi thuyền buôn Trung Hoa, Nhật Bản, Hà Lan tấp nập cập bến trên dòng sông Hồng. Câu ca Thứ nhất Kinh Kỳ, thứ nhì Phố Hiến đã khắc ghi vị thế của vùng đất này trong tâm thức người Việt. Dạo bước qua phố cổ Hưng Yên hôm nay, du khách gặp lại dấu xưa qua đền Mây, chùa Chuông, Văn Miếu Xích Đằng và đền Mẫu rêu phong. Mỗi mùa hè, hương nhãn lồng tiến vua tỏa ngát khắp phố phường, gợi nhớ thời vàng son của một đô thị cổ giàu bản sắc giao thoa Đông Tây.', '["Từng là thương cảng quốc tế sầm uất nhất Đàng Ngoài thế kỷ XVII.","Quần thể di tích Phố Hiến gồm hơn 100 di tích lớn nhỏ.","Nổi tiếng với đặc sản nhãn lồng từng được tiến vua.","Văn Miếu Xích Đằng là biểu tượng hiếu học của vùng đất."]', '["Tham quan cụm di tích bằng xe đạp để khám phá trọn vẹn phố cổ.","Đến mùa hè để thưởng thức nhãn lồng Hưng Yên chính gốc."]', 'Tháng 7 đến tháng 8 (mùa nhãn)', '1 ngày', '', '07:00 - 18:00', '["verified","popular","ai-recommended"]', '["history","culture","city","food"]', '[{"seed":"hy-pho-hien-1","caption":"Văn Miếu Xích Đằng cổ kính","ratio":"16/9"},{"seed":"hy-pho-hien-2","caption":"Đền Mẫu Phố Hiến","ratio":"4/3"},{"seed":"hy-pho-hien-3","caption":"Nhãn lồng Hưng Yên mùa thu hoạch","ratio":"1/1"}]', '["hy-chua-chuong"]', 1, '{"en":{"name":"Pho Hien","summary":"A once-bustling trading port immortalized by the saying ''First the Capital, second Pho Hien,'' now a complex of ancient relics.","story":"Pho Hien was once the most flourishing trading port of Dang Ngoai (the northern realm) in the 17th century, where merchant ships from China, Japan, and Holland thronged the banks of the Red River. The folk saying ''First the Capital, second Pho Hien'' has etched this land''s standing into the Vietnamese consciousness. Wandering through the old town of Hung Yen today, visitors rediscover traces of the past at May Temple, Chuong Pagoda, Xich Dang Temple of Literature, and the moss-covered Mau Temple. Each summer, the fragrance of the royal-tribute longan wafts through the streets, evoking the golden age of an ancient town rich in the blend of East and West.","facts":["Once the most bustling international trading port of Dang Ngoai in the 17th century.","The Pho Hien relic complex comprises more than 100 relics large and small.","Famed for its longan, once presented as tribute to the king.","Xich Dang Temple of Literature is a symbol of the region''s love of learning."],"travelTips":["Tour the relic cluster by bicycle to explore the old town fully.","Come in summer to enjoy authentic Hung Yen longan."],"bestTime":"July to August (longan season)","visitDuration":"1 day","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["The ancient Xich Dang Temple of Literature","Mau Temple of Pho Hien","Hung Yen longan at harvest time"]},"ko":{"name":"포히엔","summary":"‘첫째는 수도, 둘째는 포히엔’이라 불리던 한때 번성한 항구, 이제는 고풍스러운 유적군.","story":"포히엔은 17세기 당응와이(북부)에서 으뜸가는 번화한 항구로, 중국, 일본, 네덜란드 상선이 홍강을 따라 분주히 드나들던 곳입니다. ‘첫째는 수도, 둘째는 포히엔’이라는 민요는 이 땅의 위상을 베트남 사람들의 마음에 깊이 새겼습니다. 오늘날 흥옌 구시가지를 거니는 여행자는 머이 사당, 쭈옹 사찰, 씩당 문묘, 이끼 낀 머우 사당에서 옛 자취를 다시 만납니다. 여름마다 임금께 진상하던 룽안 용안의 향기가 거리 곳곳에 그윽이 퍼져, 동서양의 정취가 어우러진 고도(古都)의 황금기를 떠올리게 합니다.","facts":["17세기 당응와이에서 가장 번성한 국제 무역항이었습니다.","포히엔 유적군은 크고 작은 100여 개의 유적으로 이루어져 있습니다.","한때 임금께 진상하던 룽안 용안 명물로 유명합니다.","씩당 문묘는 이 땅의 학문 숭상을 상징합니다."],"travelTips":["자전거로 유적군을 둘러보면 구시가지를 온전히 탐방할 수 있습니다.","여름에 방문해 진짜 흥옌 룽안 용안을 맛보세요."],"bestTime":"7월~8월(용안 철)","visitDuration":"1일","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["고풍스러운 씩당 문묘","포히엔 머우 사당","수확철의 흥옌 룽안 용안"]},"ja":{"name":"フォーヒエン","summary":"「第一は都、第二はフォーヒエン」と謳われた往時の繁栄の商港。今は古き趣の史跡群です。","story":"フォーヒエンはかつて17世紀の北圻（ダンゴアイ）随一の繁栄を誇った商港で、中国、日本、オランダの商船がホン川（紅河）の岸辺に絶え間なく入港していました。「第一は都、第二はフォーヒエン」という歌句は、この地がベトナム人の心に刻んだ地位を物語っています。今日のフンイエン旧市街を歩けば、苔むしたマイ祠、チュオン寺、シックダン文廟、マウ祠を通じて往時の面影に出会えます。夏になると王に献上されたリュウガン（ロンガン）の香りが街じゅうに漂い、東西文化が交わる個性豊かな古都の黄金時代を偲ばせます。","facts":["17世紀の北圻で最も繁栄した国際商港でした。","フォーヒエンの史跡群は大小100以上の史跡からなります。","かつて王に献上された名産リュウガン（ロンガン）で知られます。","シックダン文廟は、この地の向学心の象徴です。"],"travelTips":["旧市街を余すことなく巡るなら、自転車で史跡群を見て回りましょう。","本場のフンイエン産リュウガンを味わうなら、夏に訪れましょう。"],"bestTime":"7月から8月（リュウガンの季節）","visitDuration":"1日","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["古き趣のシックダン文廟","フォーヒエンのマウ祠","収穫期のフンイエン産リュウガン"]},"zh":{"name":"铺宪","summary":"曾经繁华一时的商港，留有''一京城，二铺宪\"之说，如今已是古朴的遗迹群。''","story":"铺宪曾是17世纪外塘地区最为繁华的商港，中国、日本、荷兰的商船络绎不绝地停泊在红河之上。\"一京城，二铺宪\"的民谣道出了这片土地在越南人心中的地位。漫步于今日的兴安古街，游客可从云庙、钟寺、赤鳗文庙和长满青苔的母庙中重觅旧时遗韵。每到夏季，曾进贡皇室的笼眼龙眼香气弥漫街巷，让人忆起这座融汇东西方文化的古老都市的黄金岁月。","facts":["曾是17世纪外塘地区最繁华的国际商港。","铺宪遗迹群包含一百多处大小遗迹。","以曾进贡皇室的笼眼龙眼特产闻名。","赤鳗文庙是这片土地崇文好学的象征。"],"travelTips":["骑自行车游览遗迹群，可尽情探索古街。","夏季前来，品尝地道的兴安笼眼龙眼。"],"bestTime":"7月至8月（龙眼季）","visitDuration":"一天","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["古朴的赤鳗文庙","铺宪母庙","收获季节的兴安笼眼龙眼"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hy-chua-chuong', 'chua-chuong', 'hung-yen', 'Chùa Chuông', 'Chuong Pagoda', 'temple', 106.0533, 20.6433, 'Ngôi chùa cổ được mệnh danh Phố Hiến đệ nhất danh lam với cầu đá, vườn tháp và tượng pháp tinh xảo.', 'Chùa Chuông, tên chữ Kim Chung Tự, được người xưa ca tụng là Phố Hiến đệ nhất danh lam, ngôi chùa đẹp nhất chốn thương cảng phồn hoa. Truyền thuyết kể rằng một quả chuông vàng trôi dạt theo dòng nước về đây, dân làng lập chùa thờ phụng nên thành tên. Bước qua cây cầu đá xanh bắc ngang ao mắt rồng, du khách lạc vào không gian thanh tịnh với hành lang La Hán mười tám pho tượng sống động và cây hương đá khắc chữ Hán cổ. Kiến trúc nội công ngoại quốc hài hòa cùng những mảng chạm khắc gỗ tinh xảo khiến chùa Chuông trở thành viên ngọc kiến trúc Phật giáo quý giá của vùng đất Hưng Yên.', '["Tên chữ là Kim Chung Tự, nghĩa là chùa Chuông Vàng.","Được xây dựng từ thời Hậu Lê thế kỷ XV.","Có hành lang mười tám vị La Hán chạm khắc sống động.","Cầu đá và ao mắt rồng tạo nên lối vào độc đáo."]', '["Kết hợp tham quan cùng cụm di tích Phố Hiến trong một buổi.","Ghé vào sáng sớm để tận hưởng không gian tĩnh lặng, thanh tịnh."]', 'Quanh năm', '1-2 giờ', '', '06:00 - 18:00', '["verified","hidden-gem"]', '["temple","history","culture"]', '[{"seed":"hy-chua-chuong-1","caption":"Cầu đá bắc qua ao mắt rồng","ratio":"16/9"},{"seed":"hy-chua-chuong-2","caption":"Hành lang mười tám vị La Hán","ratio":"4/3"},{"seed":"hy-chua-chuong-3","caption":"Tam quan chùa Chuông cổ kính","ratio":"1/1"}]', '["hy-pho-hien"]', 0, '{"en":{"name":"Chuong Pagoda","summary":"An ancient pagoda hailed as ''Pho Hien''s finest landscape,'' with a stone bridge, a tower garden, and exquisite statuary.","story":"Chuong Pagoda, known by its literary name Kim Chung Tu, was praised by the ancients as ''Pho Hien''s finest landscape'' — the most beautiful pagoda of the flourishing port. Legend tells of a golden bell that drifted ashore here on the current, and the villagers built the pagoda to enshrine it, giving it its name. Crossing the bluestone bridge spanning the Dragon''s Eye Pond, visitors enter a serene space with a corridor of eighteen lifelike Arhat statues and a stone incense pillar carved with ancient Chinese characters. Its harmonious ''inner-gong, outer-frame'' layout and exquisite woodcarvings make Chuong Pagoda a precious gem of Buddhist architecture in the land of Hung Yen.","facts":["Its literary name is Kim Chung Tu, meaning ''Golden Bell Pagoda.''","Built in the Later Le period in the 15th century.","Features a corridor of eighteen Arhats, vividly carved.","The stone bridge and Dragon''s Eye Pond form a distinctive entrance."],"travelTips":["Combine your visit with the Pho Hien relic cluster in a single outing.","Come early in the morning to enjoy the quiet, serene atmosphere."],"bestTime":"Year-round","visitDuration":"1-2 hours","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["The stone bridge across the Dragon''s Eye Pond","The corridor of eighteen Arhats","The ancient triple gate of Chuong Pagoda"]},"ko":{"name":"쭈옹 사찰","summary":"‘포히엔 제일의 명찰’로 불리는 고찰, 돌다리와 탑 정원, 정교한 불상을 간직한 곳.","story":"쭈옹 사찰은 한자 이름이 김종사(金鐘寺)로, 옛사람들이 ‘포히엔 제일의 명찰’이라 칭송한, 번화한 항구에서 가장 아름다운 사찰입니다. 전설에 따르면 황금 종 하나가 물길을 따라 이곳으로 떠내려와, 마을 사람들이 사찰을 세워 모시며 이런 이름이 붙었다고 합니다. 용 눈 연못을 가로지르는 푸른 돌다리를 건너면, 생생한 십팔 나한상이 늘어선 회랑과 고대 한자가 새겨진 돌 향대가 있는 청정한 공간으로 들어섭니다. 안팎이 조화로운 내공외국(內工外國) 구조와 정교한 목조 조각이 어우러져, 쭈옹 사찰은 흥옌 땅의 귀한 불교 건축의 보석이 됩니다.","facts":["한자 이름은 김종사로, ‘황금 종 사찰’이라는 뜻입니다.","15세기 후레 시대에 지어졌습니다.","생생하게 조각된 십팔 나한이 늘어선 회랑이 있습니다.","돌다리와 용 눈 연못이 독특한 입구를 이룹니다."],"travelTips":["한나절 동안 포히엔 유적군과 함께 둘러보세요.","이른 아침에 들르면 고요하고 청정한 분위기를 만끽할 수 있습니다."],"bestTime":"사계절 내내","visitDuration":"1~2시간","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["용 눈 연못을 가로지르는 돌다리","십팔 나한이 늘어선 회랑","고풍스러운 쭈옹 사찰 삼문"]},"ja":{"name":"チュオン寺（鐘寺）","summary":"「フォーヒエン随一の名刹」と称される古寺。石橋、塔の庭、精緻な仏像を擁します。","story":"チュオン寺、漢字名キムチュン寺（金鐘寺）は、繁栄した商港で最も美しい寺として「フォーヒエン随一の名刹」と古くから讃えられてきました。伝説によれば、金色の鐘が水の流れに乗ってここへ漂着し、村人がそれを祀って寺を建てたことから、その名がついたといいます。竜の目の池に架かる青石の橋を渡ると、生き生きとした十八羅漢像が並ぶ回廊や、漢字が刻まれた石の香炉柱のある清浄な空間へと誘われます。内功外国（左右対称）の調和ある建築と精緻な木彫りの数々が、チュオン寺をフンイエンの貴重な仏教建築の宝玉にしています。","facts":["漢字名はキムチュン寺、すなわち金鐘寺を意味します。","15世紀の後黎朝の時代に建立されました。","生き生きと彫られた十八羅漢の回廊があります。","石橋と竜の目の池が独特な入り口を生み出しています。"],"travelTips":["フォーヒエンの史跡群とあわせて半日で巡りましょう。","静寂で清らかな空間を楽しむなら、早朝に立ち寄りましょう。"],"bestTime":"一年を通じて","visitDuration":"1〜2時間","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["竜の目の池に架かる石橋","十八羅漢の回廊","古き趣のチュオン寺の三関門"]},"zh":{"name":"钟寺","summary":"被誉为「铺宪第一名刹」的古寺，拥有石桥、塔园和精美的佛像。''","story":"钟寺，汉名金钟寺，被古人盛赞为「铺宪第一名刹」，是繁华商港中最美的寺庙。传说一口金钟随水流漂至此地，村民便建寺供奉，由此得名。走过横跨龙眼池的青石桥，游客便步入一片清净的天地，那里有十八罗汉栩栩如生的长廊和刻着古汉字的石香炉。内工外国的和谐布局与精美的木雕，使钟寺成为兴安这片土地上一颗珍贵的佛教建筑明珠。","facts":["汉名金钟寺，意为金钟之寺。","建于15世纪后黎朝时期。","拥有雕刻生动的十八罗汉长廊。","石桥与龙眼池构成了独特的入口。"],"travelTips":["可与铺宪遗迹群一并游览，用半天时间即可。","清晨前来，享受静谧清净的氛围。"],"bestTime":"全年","visitDuration":"1至2小时","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["横跨龙眼池的石桥","十八罗汉长廊","古朴的钟寺三关门"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hn-tam-chuc', 'chua-tam-chuc', 'ha-nam', 'Chùa Tam Chúc', 'Tam Chuc Pagoda', 'temple', 105.8847, 20.4642, 'Ngôi chùa lớn bậc nhất thế giới, tọa lạc giữa hồ nước mênh mông và núi đá vôi trùng điệp ở Hà Nam.', 'Chùa Tam Chúc được mệnh danh là ngôi chùa lớn nhất thế giới, trải rộng trên vùng non nước kỳ vĩ phía nam Hà Nam. Quần thể tựa lưng vào núi Thất Tinh, mặt hướng ra hồ Lục Nhạc với sáu hòn đảo đá nổi như sáu chiếc chuông trời. Trục thần đạo nối tiếp từ cổng Tam Quan, vườn Cột Kinh, điện Quan Âm, điện Pháp Chủ đến điện Tam Thế nguy nga, nơi đặt ba pho tượng Phật bằng đồng nặng hàng trăm tấn. Tương truyền đây là vùng đất gắn với truyền thuyết Tiền Lục Nhạc, Hậu Thất Tinh huyền bí. Hành hương về Tam Chúc, lòng người như lắng lại giữa khung cảnh thiên nhiên hùng vĩ và không gian tâm linh thanh tịnh.', '["Được xem là một trong những ngôi chùa lớn nhất thế giới.","Điện Tam Thế đặt ba pho tượng Phật đồng nặng khoảng 80 tấn mỗi pho.","Vườn Cột Kinh có 32 cột đá khổng lồ khắc kinh Phật.","Hồ Lục Nhạc có sáu hòn đảo đá tự nhiên giữa lòng hồ."]', '["Đi thuyền hoặc xe điện để di chuyển giữa các điện trong quần thể rộng lớn.","Đến sớm buổi sáng để tránh nắng và đông đúc, kịp ngắm sương trên hồ."]', 'Tháng 1 đến tháng 3 (mùa lễ hội)', '1 ngày', '', '06:00 - 21:00', '["trending","popular","verified","ai-recommended"]', '["temple","nature","culture","photography"]', '[{"seed":"hn-tam-chuc-1","caption":"Điện Tam Thế bên hồ Lục Nhạc","ratio":"16/9"},{"seed":"hn-tam-chuc-2","caption":"Vườn Cột Kinh khắc kinh Phật","ratio":"4/3"},{"seed":"hn-tam-chuc-3","caption":"Toàn cảnh chùa giữa núi non","ratio":"1/1"}]', '[]', 1, '{"en":{"name":"Tam Chuc Pagoda","summary":"One of the largest pagodas in the world, set amid a vast lake and rolling limestone mountains in Ha Nam.","story":"Tam Chuc Pagoda is hailed as the largest pagoda in the world, sprawling across a region of majestic mountains and water in southern Ha Nam. The complex backs onto That Tinh (Seven Stars) Mountain and faces Luc Nhac Lake, where six rocky islands rise like six heavenly bells. The spiritual axis runs from the Tam Quan gate through the Sutra Pillar Garden, the Quan Am Hall, the Phap Chu Hall, and on to the magnificent Tam The Hall, where three bronze Buddha statues weighing hundreds of tons are enshrined. Legend ties this land to the mystical tale of ''Six Bells in Front, Seven Stars Behind.'' On a pilgrimage to Tam Chuc, the heart settles amid the grand natural scenery and the serene spiritual space.","facts":["Considered one of the largest pagodas in the world.","The Tam The Hall houses three bronze Buddha statues, each weighing about 80 tons.","The Sutra Pillar Garden has 32 giant stone pillars carved with Buddhist scriptures.","Luc Nhac Lake has six natural rocky islands rising from the water."],"travelTips":["Take a boat or electric shuttle to move between the halls of this vast complex.","Arrive early in the morning to avoid the heat and crowds and catch the mist over the lake."],"bestTime":"January to March (festival season)","visitDuration":"1 day","ticket":"","openingHours":"06:00 - 21:00","galleryCaptions":["The Tam The Hall beside Luc Nhac Lake","The Sutra Pillar Garden carved with Buddhist scriptures","A panorama of the pagoda amid the mountains"]},"ko":{"name":"땀쭉 사찰","summary":"하남의 드넓은 호수와 겹겹이 솟은 석회암 산 한가운데 자리한, 세계에서 손꼽히게 큰 사찰.","story":"땀쭉 사찰은 세계에서 가장 큰 사찰로 불리며, 하남 남쪽의 웅장한 산수에 넓게 펼쳐져 있습니다. 사찰군은 텃띤산을 등지고 여섯 개의 돌섬이 마치 여섯 개의 하늘 종처럼 떠 있는 룩냑 호수를 마주합니다. 신도(神道) 축은 삼문에서 시작해 경전 기둥 정원, 관음전, 법주전을 거쳐 웅장한 삼세전으로 이어지며, 그곳에는 수백 톤에 달하는 청동 불상 세 좌가 모셔져 있습니다. 전설에 따르면 이곳은 ‘앞에는 룩냑, 뒤에는 텃띤’이라는 신비로운 설화와 얽힌 땅입니다. 땀쭉으로 순례를 떠나면, 웅장한 자연 풍경과 청정한 영적 공간 속에서 마음이 차분히 가라앉습니다.","facts":["세계에서 가장 큰 사찰 중 하나로 꼽힙니다.","삼세전에는 각각 약 80톤에 달하는 청동 불상 세 좌가 모셔져 있습니다.","경전 기둥 정원에는 불경을 새긴 거대한 돌기둥 32개가 있습니다.","룩냑 호수에는 호수 한가운데 여섯 개의 천연 돌섬이 있습니다."],"travelTips":["드넓은 사찰군 안의 전각 사이를 배나 전동차로 이동하세요.","이른 아침에 도착하면 더위와 혼잡을 피하고 호수 위 안개를 감상할 수 있습니다."],"bestTime":"1월~3월(축제 철)","visitDuration":"1일","ticket":"","openingHours":"06:00 - 21:00","galleryCaptions":["룩냑 호수 가의 삼세전","불경을 새긴 경전 기둥 정원","산 속 사찰의 전경"]},"ja":{"name":"タムチュック寺","summary":"世界屈指の大寺院。ハナム省の広大な湖と連なる石灰岩の山々の間に位置します。","story":"タムチュック寺は世界最大の寺院と称され、ハナム省南部の雄大な山水の地に広がっています。寺院群はタットティン山を背に、天の六つの鐘のように浮かぶ六つの岩島を擁するルックニャック湖に面しています。三関門から始まり、経柱の庭、観音殿、法主殿、そして荘厳な三世殿へと連なる中軸の参道。三世殿には、それぞれ数百トンもの銅製の仏像三体が安置されています。この地は「前は六楽、後ろは七星」という神秘的な伝説と結びついていると伝えられます。タムチュックへの巡礼では、雄大な自然と清浄な聖域の中で、人々の心が静まっていきます。","facts":["世界最大級の寺院のひとつとされています。","三世殿には、それぞれおよそ80トンの銅製仏像三体が安置されています。","経柱の庭には、仏典を刻んだ巨大な石柱が32本あります。","ルックニャック湖には、湖の中に六つの自然の岩島があります。"],"travelTips":["広大な寺院群の各殿を巡るには、舟か電動カートを利用しましょう。","日差しと混雑を避け、湖にかかる霧を眺めるため、朝早く訪れましょう。"],"bestTime":"1月から3月（祭りの季節）","visitDuration":"1日","ticket":"","openingHours":"06:00 - 21:00","galleryCaptions":["ルックニャック湖のほとりの三世殿","仏典を刻んだ経柱の庭","山々に囲まれた寺院の全景"]},"zh":{"name":"三祝寺","summary":"世界上最大的寺庙之一，坐落于河南省浩瀚的湖泊与层叠的石灰岩山峰之间。","story":"三祝寺被誉为世界上最大的寺庙，绵延铺展在河南省南部雄奇的山水之间。寺庙群背靠七星山，面朝六乐湖，湖中六座石岛宛如六口天钟。神道贯穿三关门、经柱园、观音殿、法主殿直至巍峨的三世殿，殿中安放着重达数百吨的三尊铜佛像。相传这里正是与\"前六乐，后七星\"神秘传说相关的土地。前来三祝寺朝圣，置身雄伟的自然景观与清净的灵性空间中，人心仿佛随之沉静下来。","facts":["被视为世界上最大的寺庙之一。","三世殿安放三尊铜佛像，每尊约重80吨。","经柱园内有32根刻着佛经的巨型石柱。","六乐湖中有六座天然石岛。"],"travelTips":["乘船或电瓶车在广阔的寺庙群各殿之间往返。","清晨早早前来，避开烈日与人群，还能赶上欣赏湖上晨雾。"],"bestTime":"1月至3月（庙会季）","visitDuration":"一天","ticket":"","openingHours":"06:00 - 21:00","galleryCaptions":["六乐湖畔的三世殿","刻着佛经的经柱园","群山环抱中的寺庙全景"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('nd-den-tran', 'den-tran', 'nam-dinh', 'Đền Trần', 'Tran Temple', 'temple', 106.1747, 20.4561, 'Khu di tích thờ các vua Trần và Trần Hưng Đạo, nổi danh với lễ khai ấn đầu xuân thu hút hàng vạn người.', 'Đền Trần Nam Định là nơi thờ phụng mười bốn vị hoàng đế nhà Trần cùng các quan lại có công, dựng trên nền Thái miếu xưa của hương Tức Mặc, quê hương phát tích vương triều. Quần thể gồm ba ngôi đền chính: đền Thiên Trường, đền Cố Trạch và đền Trùng Hoa, mang đậm dấu ấn kiến trúc cổ với cổng ngũ môn uy nghi và những hàng cây cổ thụ rợp bóng. Nổi tiếng nhất là lễ khai ấn đêm 14 rạng sáng 15 tháng Giêng, khi hàng vạn người về xin ấn cầu mong công danh, tài lộc một năm hanh thông. Đền Trần không chỉ là chốn linh thiêng mà còn là biểu tượng hào khí Đông A bất diệt của dân tộc.', '["Thờ mười bốn vị vua triều Trần tại nền Thái miếu cổ.","Lễ khai ấn diễn ra đêm 14 rạng sáng 15 tháng Giêng âm lịch.","Vùng Tức Mặc là quê hương phát tích của nhà Trần.","Quần thể gồm ba đền: Thiên Trường, Cố Trạch và Trùng Hoa."]', '["Tránh chen lấn đêm khai ấn, có thể xin ấn vào các ngày sau đó.","Kết hợp thăm chùa Phổ Minh gần kề với tháp cổ thời Trần."]', 'Tháng Giêng âm lịch', 'Nửa ngày', '', '07:00 - 18:00', '["festival","popular","verified"]', '["temple","history","culture"]', '[{"seed":"nd-den-tran-1","caption":"Cổng ngũ môn Đền Trần uy nghi","ratio":"16/9"},{"seed":"nd-den-tran-2","caption":"Lễ khai ấn đầu xuân","ratio":"4/3"},{"seed":"nd-den-tran-3","caption":"Đền Thiên Trường cổ kính","ratio":"1/1"}]', '["nd-nha-tho-do"]', 1, '{"en":{"name":"Tran Temple","summary":"A relic site honoring the Tran kings and Tran Hung Dao, famed for its early-spring seal-opening ceremony that draws tens of thousands.","story":"Tran Temple in Nam Dinh honors the fourteen emperors of the Tran Dynasty along with meritorious mandarins, built on the former royal ancestral temple of Tuc Mac, the cradle of the dynasty. The complex comprises three main temples: Thien Truong, Co Trach, and Trung Hoa, deeply marked by ancient architecture with an imposing five-gate entrance and rows of shady old trees. Most famous is the seal-opening ceremony on the night of the 14th into the 15th of the first lunar month, when tens of thousands come to receive a seal in hopes of a year of success and fortune. Tran Temple is not only a sacred place but also a symbol of the dynasty''s indomitable martial spirit.","facts":["Honors fourteen kings of the Tran Dynasty on the site of the ancient royal ancestral temple.","The seal-opening ceremony takes place on the night of the 14th into the 15th of the first lunar month.","The Tuc Mac area is the ancestral homeland of the Tran Dynasty.","The complex consists of three temples: Thien Truong, Co Trach, and Trung Hoa."],"travelTips":["Avoid the crush of the seal-opening night; you can receive a seal on the following days instead.","Combine your visit with the nearby Pho Minh Pagoda and its ancient Tran-era tower."],"bestTime":"First lunar month","visitDuration":"Half a day","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["The imposing five-gate entrance of Tran Temple","The early-spring seal-opening ceremony","The ancient Thien Truong Temple"]},"ko":{"name":"쩐 사당","summary":"쩐 왕조 왕들과 쩐흥다오를 모시는 유적지로, 수만 명을 불러 모으는 정초 인장 개봉 의식으로 유명한 곳.","story":"남딘 쩐 사당은 쩐 왕조 열네 명의 황제와 공을 세운 신하들을 모시는 곳으로, 왕조 발상지인 뜩막 마을의 옛 종묘 터에 세워졌습니다. 사당군은 티엔쯔엉 사당, 꼬짝 사당, 쭝호아 사당 세 곳으로 이루어지며, 위엄 있는 오문(五門)과 그늘을 드리운 노거수 가로수가 고풍스러운 건축의 정취를 짙게 풍깁니다. 가장 유명한 것은 음력 정월 14일 밤에서 15일 새벽으로 넘어가는 인장 개봉 의식으로, 수만 명이 모여 한 해의 출세와 재물운이 형통하기를 빌며 인장을 받습니다. 쩐 사당은 신성한 성소일 뿐 아니라, 민족의 불멸하는 동아(東阿) 기개를 상징합니다.","facts":["옛 종묘 터에서 쩐 왕조 열네 명의 왕을 모십니다.","인장 개봉 의식은 음력 정월 14일 밤에서 15일 새벽에 열립니다.","뜩막 지역은 쩐 왕조의 발상지입니다.","사당군은 티엔쯔엉, 꼬짝, 쭝호아 세 사당으로 이루어집니다."],"travelTips":["인장 개봉 의식 밤의 혼잡을 피하려면 이후 날짜에 인장을 받을 수 있습니다.","쩐 왕조의 옛 탑이 있는 인근 포민 사찰과 함께 둘러보세요."],"bestTime":"음력 정월","visitDuration":"반나절","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["위엄 있는 쩐 사당 오문","정초 인장 개봉 의식","고풍스러운 티엔쯔엉 사당"]},"ja":{"name":"デンチャン（陳朝廟）","summary":"陳朝の王とチャン・フン・ダオを祀る史跡。初春の開印祭で幾万もの人を集めることで知られます。","story":"ナムディンのデンチャンは、陳朝十四代の皇帝と功臣たちを祀る場所で、王朝発祥の地トゥックマック郷のかつての太廟の跡に建てられました。寺院群はティエンチュオン祠、コーチャック祠、チュンホア祠の三つの主要な祠からなり、威厳ある五門の門と木陰を作る老樹の並木に、古き建築の趣を色濃く留めています。最も名高いのは旧暦1月14日深夜から15日未明にかけての開印祭で、幾万もの人々が一年の立身出世と財運の安泰を願って印を求めに訪れます。デンチャンは神聖な地であるだけでなく、民族の不滅の「東阿（ドンア）の気概」の象徴でもあります。","facts":["古き太廟の跡に、陳朝十四代の王を祀っています。","開印祭は旧暦1月14日深夜から15日未明にかけて行われます。","トゥックマックの地は陳朝発祥の故郷です。","寺院群はティエンチュオン、コーチャック、チュンホアの三つの祠からなります。"],"travelTips":["開印祭の夜の混雑を避けるなら、後日に印を求めることもできます。","近くの、陳朝時代の古塔があるフォーミン寺もあわせて訪れましょう。"],"bestTime":"旧暦1月","visitDuration":"半日","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["威厳あるデンチャンの五門の門","初春の開印祭","古き趣のティエンチュオン祠"]},"zh":{"name":"陈庙","summary":"供奉陈朝诸帝和陈兴道的遗迹区，以吸引数万人的初春开印典礼而闻名。","story":"南定陈庙是供奉陈朝十四位皇帝及功臣的地方，建于即墨乡昔日太庙的旧址上，那里正是王朝发祥的故乡。庙群由三座主庙组成：天长庙、故宅庙和重华庙，带有浓厚的古建筑韵味，五门门楼巍峨庄严，古树成荫。最为著名的是农历正月十四深夜至十五凌晨的开印典礼，届时数万人前来求印，祈愿一年功名亨通、财运昌盛。陈庙不仅是神圣之地，更是民族不灭的东阿豪气的象征。","facts":["在古太庙旧址上供奉陈朝十四位皇帝。","开印典礼于农历正月十四深夜至十五凌晨举行。","即墨地区是陈朝发祥的故乡。","庙群由三座庙组成：天长庙、故宅庙和重华庙。"],"travelTips":["避开开印之夜的拥挤，可在随后几日前来求印。","顺道参观邻近的普明寺，欣赏陈朝古塔。"],"bestTime":"农历正月","visitDuration":"半天","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["庄严的陈庙五门门楼","初春的开印典礼","古朴的天长庙"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('nd-nha-tho-do', 'nha-tho-do-hai-ly', 'nam-dinh', 'Nhà thờ đổ Hải Lý', 'Hai Ly Ruined Church', 'city', 106.2783, 19.9744, 'Tàn tích nhà thờ ven biển bị sóng biển bào mòn, mang vẻ đẹp hoang hoải đầy mê hoặc với giới nhiếp ảnh.', 'Nhà thờ đổ Hải Lý là di tích nhà thờ Trái Tim đổ, chứng nhân lặng lẽ của cuộc chiến giữa con người và biển cả. Được xây dựng đầu thế kỷ XX, nhà thờ từng là nơi sinh hoạt của giáo dân vùng Xương Điền, nhưng nạn xâm thực biển khiến cả làng phải lùi sâu vào đất liền, bỏ lại ngôi thánh đường trơ trọi giữa bãi cát. Tháp chuông rêu phong sừng sững trước sóng gió, lúc ẩn lúc hiện theo con nước thủy triều, tạo nên khung cảnh vừa hoang tàn vừa thi vị. Bình minh và hoàng hôn nơi đây trở thành điểm hẹn lý tưởng của những tay máy săn tìm khoảnh khắc đẹp ma mị giữa trời nước bao la.', '["Nguyên là nhà thờ Trái Tim, xây đầu thế kỷ XX.","Bị bỏ hoang do nạn xâm thực biển nuốt dần làng Xương Điền.","Tháp chuông cổ vẫn đứng vững giữa sóng gió sau hơn một thế kỷ.","Là điểm chụp ảnh bình minh nổi tiếng của Nam Định."]', '["Canh thủy triều rút để có thể ra sát chân nhà thờ chụp ảnh.","Đến lúc bình minh để bắt trọn khoảnh khắc ánh sáng đẹp nhất."]', 'Tháng 10 đến tháng 4', '1-2 giờ', '', 'Cả ngày', '["hidden-gem","trending","ai-recommended"]', '["history","photography","beach"]', '[{"seed":"nd-nha-tho-do-1","caption":"Tháp chuông đổ giữa bãi biển","ratio":"16/9"},{"seed":"nd-nha-tho-do-2","caption":"Bình minh trên nhà thờ đổ","ratio":"4/3"},{"seed":"nd-nha-tho-do-3","caption":"Sóng vỗ chân tường rêu phong","ratio":"1/1"}]', '["nd-den-tran"]', 0, '{"en":{"name":"Hai Ly Ruined Church","summary":"The seaside ruins of a church worn away by the waves, with a hauntingly desolate beauty beloved by photographers.","story":"The Hai Ly Ruined Church is the remnant of the Sacred Heart Church, a silent witness to the struggle between people and the sea. Built in the early 20th century, the church once served the parishioners of the Xuong Dien area, but coastal erosion forced the whole village to retreat inland, leaving the sanctuary standing alone on the sand. Its moss-covered bell tower stands firm against wind and waves, appearing and vanishing with the tides, creating a scene at once desolate and poetic. Dawn and dusk here have become an ideal rendezvous for photographers hunting beautiful, haunting moments between the vast sky and sea.","facts":["Originally the Sacred Heart Church, built in the early 20th century.","Abandoned as coastal erosion gradually swallowed Xuong Dien village.","The old bell tower still stands firm against wind and waves after more than a century.","A famous sunrise photography spot in Nam Dinh."],"travelTips":["Time your visit to low tide so you can get right up to the base of the church for photos.","Arrive at dawn to capture the most beautiful light."],"bestTime":"October to April","visitDuration":"1-2 hours","ticket":"","openingHours":"All day","galleryCaptions":["The ruined bell tower amid the beach","Sunrise over the ruined church","Waves lapping at the moss-covered walls"]},"ko":{"name":"하이리 폐성당","summary":"파도에 깎여 나간 바닷가 성당 폐허, 사진작가들을 사로잡는 쓸쓸하고도 매혹적인 아름다움.","story":"하이리 폐성당은 ‘무너진 성심 성당’ 유적으로, 인간과 바다의 싸움을 묵묵히 지켜본 증인입니다. 20세기 초에 지어진 이 성당은 한때 쓰엉디엔 지역 신자들의 신앙 생활 터전이었으나, 해안 침식으로 마을 전체가 내륙 깊숙이 물러나면서 모래밭 위에 외로이 남겨졌습니다. 이끼 낀 종탑은 비바람 앞에 우뚝 서서 밀물과 썰물에 따라 모습을 감췄다 드러내며, 황량하면서도 시적인 풍경을 자아냅니다. 이곳의 새벽과 해 질 녘은 광활한 하늘과 바다 사이에서 환상적인 순간을 좇는 사진가들의 이상적인 약속의 장소가 됩니다.","facts":["본래 20세기 초에 지어진 성심 성당이었습니다.","해안 침식이 쓰엉디엔 마을을 점차 삼키면서 버려졌습니다.","고풍스러운 종탑은 한 세기가 넘도록 비바람 속에 여전히 굳건히 서 있습니다.","남딘에서 유명한 새벽 촬영 명소입니다."],"travelTips":["썰물 시간을 맞추면 성당 발치까지 다가가 사진을 찍을 수 있습니다.","새벽에 방문해 가장 아름다운 빛의 순간을 온전히 담아 보세요."],"bestTime":"10월~4월","visitDuration":"1~2시간","ticket":"","openingHours":"종일","galleryCaptions":["해변 한가운데 무너진 종탑","폐성당 위로 떠오르는 새벽","이끼 낀 담장 발치를 때리는 파도"]},"ja":{"name":"ハイリーの廃教会","summary":"波に削られた海辺の教会跡。物寂しくも妖しい美しさで、写真愛好家を魅了します。","story":"ハイリーの廃教会は「崩れた聖心教会」の遺構で、人と海との闘いの静かな証人です。20世紀初頭に建てられたこの教会は、かつてはスオンディエン地区の信者たちの集いの場でしたが、海の浸食によって村全体が内陸へと退き、聖堂は砂浜にぽつんと取り残されました。苔むした鐘楼は風波の前に屹立し、潮の満ち引きにつれて見え隠れし、荒涼としつつも詩情あふれる景色を生み出しています。夜明けと夕暮れのこの地は、果てしない天と海の間に妖しく美しい一瞬を求める写真家たちの絶好の集いの場となっています。","facts":["もとは聖心教会で、20世紀初頭に建てられました。","海の浸食がスオンディエン村を徐々に呑み込み、廃墟となりました。","古い鐘楼は一世紀以上を経た今も風波の中に立ち続けています。","ナムディンで名高い、夜明けの写真撮影スポットです。"],"travelTips":["教会の足元まで近づいて撮影できるよう、引き潮の時間を見計らいましょう。","最も美しい光の一瞬を捉えるため、夜明けに訪れましょう。"],"bestTime":"10月から4月","visitDuration":"1〜2時間","ticket":"","openingHours":"終日","galleryCaptions":["砂浜に佇む崩れた鐘楼","廃教会に昇る朝日","苔むした壁の足元に打ち寄せる波"]},"zh":{"name":"海理废弃教堂","summary":"被海浪侵蚀的海边教堂遗迹，带着令摄影爱好者着迷的荒凉之美。","story":"海理废弃教堂是「圣心废墟」教堂遗迹，是人类与海洋之争的无声见证。它建于20世纪初，曾是昌田地区教徒活动的场所，但海水侵蚀迫使整个村庄向内陆退缩，留下这座孤零零矗立在沙滩上的圣堂。长满青苔的钟楼在风浪中傲然屹立，随潮水涨落时隐时现，构成一幅既荒凉又充满诗意的景象。这里的黎明与黄昏成为摄影爱好者捕捉天水苍茫间那份迷离美感的理想之地。","facts":["原为圣心教堂，建于20世纪初。","因海水侵蚀逐渐吞噬昌田村而被废弃。","历经一个多世纪，古老的钟楼仍在风浪中屹立不倒。","是南定著名的拍摄日出地点。"],"travelTips":["看准退潮时机，便可走近教堂脚下拍照。","在黎明时分前来，捕捉光线最美的瞬间。"],"bestTime":"10月至次年4月","visitDuration":"1至2小时","ticket":"","openingHours":"全天","galleryCaptions":["沙滩上的废弃钟楼","废弃教堂上的日出","海浪拍打长满青苔的墙根"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tb-chua-keo', 'chua-keo', 'thai-binh', 'Chùa Keo', 'Keo Pagoda', 'temple', 106.5497, 20.5306, 'Ngôi chùa cổ gần 400 năm với gác chuông gỗ ba tầng tuyệt mỹ, kiệt tác kiến trúc Phật giáo Việt Nam.', 'Chùa Keo, tên chữ Thần Quang Tự, là một trong những ngôi cổ tự đẹp và còn nguyên vẹn nhất Việt Nam, tọa lạc bên dòng sông Hồng hiền hòa. Được xây dựng năm 1632 thời Hậu Lê, chùa thờ Phật và Thiền sư Không Lộ, người có công chữa bệnh cho vua Lý. Điểm nhấn tuyệt mỹ là gác chuông gỗ ba tầng cao gần mười hai mét, dựng hoàn toàn bằng mộng gỗ không dùng đinh, mái cong vút như cánh chim sắp bay. Toàn bộ quần thể với hàng trăm gian nhà gỗ lim sắp xếp đăng đối là minh chứng cho tài hoa của người thợ xưa. Lễ hội chùa Keo mùa thu với những nghi thức cổ truyền độc đáo luôn thu hút đông đảo du khách thập phương.', '["Tên chữ Thần Quang Tự, xây dựng năm 1632 thời Hậu Lê.","Gác chuông gỗ ba tầng dựng bằng mộng gỗ không dùng một chiếc đinh.","Thờ Thiền sư Không Lộ, người chữa bệnh cho vua Lý Thần Tông.","Là Di tích quốc gia đặc biệt với gần 400 năm tuổi."]', '["Về dự lễ hội chùa Keo mùa thu rằm tháng chín âm lịch.","Quan sát kỹ kết cấu gác chuông để cảm nhận tài hoa nghề mộc cổ."]', 'Tháng 9 âm lịch (mùa lễ hội)', 'Nửa ngày', '', '07:00 - 18:00', '["festival","verified","popular"]', '["temple","history","culture","photography"]', '[{"seed":"tb-chua-keo-1","caption":"Gác chuông gỗ ba tầng nổi tiếng","ratio":"16/9"},{"seed":"tb-chua-keo-2","caption":"Lễ hội chùa Keo mùa thu","ratio":"4/3"},{"seed":"tb-chua-keo-3","caption":"Quần thể nhà gỗ lim đăng đối","ratio":"1/1"}]', '["tb-con-vanh"]', 1, '{"en":{"name":"Keo Pagoda","summary":"A nearly 400-year-old pagoda with a stunning three-tier wooden bell tower, a masterpiece of Vietnamese Buddhist architecture.","story":"Keo Pagoda, known by its literary name Than Quang Tu, is one of the most beautiful and best-preserved ancient pagodas in Vietnam, standing beside the gentle Red River. Built in 1632 during the Later Le period, the pagoda honors the Buddha and the Zen master Khong Lo, who is credited with curing the Ly king''s illness. Its crowning glory is the three-tier wooden bell tower, nearly twelve meters tall, assembled entirely with mortise-and-tenon joints without a single nail, its roofs curving up like the wings of a bird about to take flight. The entire complex, with hundreds of symmetrically arranged ironwood structures, is a testament to the skill of artisans of old. The autumn Keo Pagoda Festival, with its unique traditional rites, always draws crowds of visitors from far and wide.","facts":["Its literary name is Than Quang Tu, built in 1632 during the Later Le period.","The three-tier wooden bell tower is built with mortise-and-tenon joints, without a single nail.","Honors the Zen master Khong Lo, who cured King Ly Than Tong''s illness.","A special national relic, nearly 400 years old."],"travelTips":["Come for the autumn Keo Pagoda Festival on the full moon of the ninth lunar month.","Look closely at the bell tower''s structure to appreciate the skill of ancient woodworking."],"bestTime":"Ninth lunar month (festival season)","visitDuration":"Half a day","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["The famous three-tier wooden bell tower","The autumn Keo Pagoda Festival","The symmetrical complex of ironwood structures"]},"ko":{"name":"께오 사찰","summary":"3층 목조 종루가 빼어난 400년 가까운 고찰, 베트남 불교 건축의 걸작.","story":"께오 사찰은 한자 이름이 신광사(神光寺)로, 베트남에서 가장 아름답고 온전히 보존된 고찰 중 하나이며, 잔잔한 홍강 가에 자리합니다. 1632년 후레 시대에 지어진 이 사찰은 부처와, 리 왕의 병을 고친 공로가 있는 콩로 선사를 모십니다. 빼어난 백미는 못 하나 쓰지 않고 오로지 목재 장부 이음만으로 세운 12미터에 가까운 3층 목조 종루로, 휘어진 지붕이 막 날아오르려는 새의 날개처럼 솟구칩니다. 좌우 대칭으로 배치된 수백 칸의 임 목재 건물로 이루어진 전체 사찰군은 옛 장인의 솜씨를 증명합니다. 독특한 전통 의식이 펼쳐지는 께오 사찰 가을 축제는 늘 각지의 수많은 여행자를 불러 모읍니다.","facts":["한자 이름은 신광사이며, 1632년 후레 시대에 지어졌습니다.","3층 목조 종루는 못 하나 쓰지 않고 목재 장부 이음만으로 세워졌습니다.","리턴똥 왕의 병을 고친 콩로 선사를 모십니다.","400년 가까운 역사를 지닌 국가 특별 유적입니다."],"travelTips":["음력 9월 보름의 께오 사찰 가을 축제에 참석해 보세요.","종루의 구조를 꼼꼼히 살펴 옛 목공 솜씨를 느껴 보세요."],"bestTime":"음력 9월(축제 철)","visitDuration":"반나절","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["유명한 3층 목조 종루","께오 사찰 가을 축제","좌우 대칭의 임 목재 건물군"]},"ja":{"name":"ケオ寺","summary":"築400年近くの古寺。三層の木造鐘楼が見事な、ベトナム仏教建築の傑作です。","story":"ケオ寺、漢字名タンクアン寺（神光寺）は、ベトナムで最も美しく、最も完全な姿で残る古寺のひとつで、穏やかなホン川（紅河）のほとりに位置します。1632年、後黎朝の時代に建立され、仏と、李朝の王を治療した功績のある禅師ホン・ロー（空路）を祀っています。最も見事な見どころは高さ約12メートルの三層の木造鐘楼で、釘を一本も使わず木組みだけで建てられ、屋根は今にも飛び立つ鳥の翼のように反り返っています。鉄刀木（リム材）の数百間の建物が左右対称に配された寺院群全体は、いにしえの職人の卓越した技の証です。独特な伝統儀式を伴うケオ寺の秋祭りは、いつも四方から多くの旅行者を集めます。","facts":["漢字名はタンクアン寺（神光寺）で、1632年、後黎朝の時代に建立されました。","三層の木造鐘楼は、釘を一本も使わず木組みだけで建てられています。","李神宗を治療した禅師ホン・ロー（空路）を祀っています。","築400年近くの国家特別史跡です。"],"travelTips":["旧暦9月15日のケオ寺の秋祭りに参列しましょう。","鐘楼の構造をじっくり観察し、いにしえの木工技術の妙を感じ取りましょう。"],"bestTime":"旧暦9月（祭りの季節）","visitDuration":"半日","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["名高い三層の木造鐘楼","ケオ寺の秋祭り","左右対称に配された鉄刀木の建物群"]},"zh":{"name":"翘寺","summary":"近400年历史的古寺，拥有美轮美奂的三层木钟楼，是越南佛教建筑的杰作。","story":"翘寺，汉名神光寺，是越南最美且保存最完整的古寺之一，坐落于温柔的红河之畔。它建于1632年后黎朝时期，供奉佛祖与曾为李朝皇帝治病的空路禅师。其美轮美奂的亮点是一座近十二米高的三层木钟楼，全部以木榫卯接而成，不用一根钉子，飞檐高翘如展翅欲飞的鸟。整座庙群由数百间排列对称的铁木房屋组成，是古代匠人才华的明证。翘寺秋季庙会以独特的古老仪式吸引着四方游客。","facts":["汉名神光寺，建于1632年后黎朝时期。","三层木钟楼以木榫卯接而成，不用一根钉子。","供奉曾为李神宗皇帝治病的空路禅师。","是近400年历史的国家特级遗迹。"],"travelTips":["在农历九月十五的翘寺秋季庙会期间前来。","仔细观察钟楼结构，感受古代木工的精湛技艺。"],"bestTime":"农历九月（庙会季）","visitDuration":"半天","ticket":"","openingHours":"07:00 - 18:00","galleryCaptions":["著名的三层木钟楼","翘寺秋季庙会","排列对称的铁木建筑群"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tb-con-vanh', 'bien-con-vanh', 'thai-binh', 'Biển Cồn Vành', 'Con Vanh Beach', 'beach', 106.5836, 20.2392, 'Bãi biển hoang sơ trong khu dự trữ sinh quyển, với rừng phi lao, rừng ngập mặn và bình minh tuyệt đẹp.', 'Cồn Vành là dải đất bồi hoang sơ vươn ra biển Đông, nằm trong Khu dự trữ sinh quyển châu thổ sông Hồng được UNESCO công nhận. Khác với những bãi tắm ồn ào, nơi đây giữ trọn vẻ mộc mạc với bãi cát phẳng lì trải dài hàng cây số, rừng phi lao vi vu trong gió và những cánh rừng ngập mặn xanh ngắt. Cồn Vành là thiên đường của các loài chim di cư và là nơi mưu sinh của ngư dân với nghề cào ngao, bắt còng. Du khách về đây để cắm trại, đón bình minh rực rỡ trên biển, thưởng thức hải sản tươi ngon và tận hưởng không gian trong lành, yên bình hiếm có của miền quê lúa Thái Bình.', '["Nằm trong Khu dự trữ sinh quyển châu thổ sông Hồng của UNESCO.","Có hệ sinh thái rừng ngập mặn và rừng phi lao phong phú.","Là điểm dừng chân của nhiều loài chim di cư quý hiếm.","Bãi cát phẳng dài, thích hợp cắm trại và đón bình minh."]', '["Mang theo lều và đồ dùng cá nhân vì dịch vụ nơi đây còn hoang sơ.","Dậy sớm đón bình minh và trải nghiệm cào ngao cùng ngư dân."]', 'Tháng 4 đến tháng 8', '1 ngày', '', 'Cả ngày', '["hidden-gem","new","ai-recommended"]', '["beach","nature","photography"]', '[{"seed":"tb-con-vanh-1","caption":"Bình minh trên biển Cồn Vành","ratio":"16/9"},{"seed":"tb-con-vanh-2","caption":"Rừng phi lao ven biển","ratio":"4/3"},{"seed":"tb-con-vanh-3","caption":"Rừng ngập mặn xanh ngắt","ratio":"1/1"}]', '["tb-chua-keo"]', 0, '{"en":{"name":"Con Vanh Beach","summary":"A pristine beach within a biosphere reserve, with casuarina groves, mangrove forests, and stunning sunrises.","story":"Con Vanh is a pristine spit of alluvial land reaching out into the East Sea, set within the UNESCO-recognized Red River Delta Biosphere Reserve. Unlike noisy resort beaches, it preserves a rustic charm with kilometers of flat sand, casuarinas whispering in the wind, and lush green mangrove forests. Con Vanh is a paradise for migratory birds and a livelihood for fishermen who rake for clams and catch fiddler crabs. Visitors come to camp, watch the brilliant sunrise over the sea, savor fresh seafood, and enjoy the rare, peaceful, fresh air of Thai Binh''s rice-farming countryside.","facts":["Lies within the UNESCO Red River Delta Biosphere Reserve.","Boasts rich ecosystems of mangrove and casuarina forests.","A stopover for many rare migratory birds.","Its long, flat sandy beach is ideal for camping and watching the sunrise."],"travelTips":["Bring a tent and personal supplies, as services here are still undeveloped.","Rise early for the sunrise and try raking for clams with the fishermen."],"bestTime":"April to August","visitDuration":"1 day","ticket":"","openingHours":"All day","galleryCaptions":["Sunrise over Con Vanh Beach","The casuarina forest along the shore","The lush green mangrove forest"]},"ko":{"name":"꼰바인 해변","summary":"목마황 숲과 맹그로브 숲, 아름다운 일출을 품은 생물권 보전지역 안의 원시 해변.","story":"꼰바인은 동해로 뻗어 나온 원시 그대로의 퇴적지로, 유네스코가 인정한 홍강 삼각주 생물권 보전지역 안에 자리합니다. 시끌벅적한 해변과 달리 이곳은 수 킬로미터에 걸쳐 평평하게 펼쳐진 모래밭, 바람에 사각거리는 목마황 숲, 푸르른 맹그로브 숲과 함께 소박한 정취를 온전히 간직하고 있습니다. 꼰바인은 철새들의 낙원이자 어민들이 조개를 캐고 게를 잡으며 생계를 잇는 터전입니다. 여행자는 이곳에서 캠핑을 하고, 바다 위로 떠오르는 화려한 일출을 맞이하며, 싱싱한 해산물을 맛보고, 타이빈 벼 고장의 보기 드문 맑고 평화로운 공기를 만끽합니다.","facts":["유네스코 홍강 삼각주 생물권 보전지역 안에 자리합니다.","맹그로브 숲과 목마황 숲의 풍부한 생태계를 갖추고 있습니다.","희귀 철새들이 거쳐 가는 중간 기착지입니다.","평평하고 긴 모래밭은 캠핑과 일출 감상에 적합합니다."],"travelTips":["이곳은 편의 시설이 아직 갖춰지지 않았으니 텐트와 개인 용품을 챙겨 가세요.","일찍 일어나 일출을 맞이하고 어민들과 함께 조개잡이를 체험해 보세요."],"bestTime":"4월~8월","visitDuration":"1일","ticket":"","openingHours":"종일","galleryCaptions":["꼰바인 바다 위로 떠오르는 일출","바닷가 목마황 숲","푸르른 맹그로브 숲"]},"ja":{"name":"コンヴァインビーチ","summary":"生物圏保護区にある手つかずのビーチ。モクマオウ林、マングローブ林、そして美しい朝日が広がります。","story":"コンヴァインは東の海へと伸びる手つかずの堆積地で、ユネスコに認定された紅河デルタ生物圏保護区内に位置します。にぎやかな海水浴場とは違い、ここは何キロメートルにもわたって続く平らな砂浜、風にそよぐモクマオウ林、そして青々としたマングローブの森が広がる素朴な趣をそのまま留めています。コンヴァインは渡り鳥たちの楽園であり、漁師たちがハマグリ掘りやシオマネキ採りで生計を立てる場でもあります。旅行者はここでキャンプをし、海に昇る鮮やかな朝日を迎え、新鮮な海の幸を味わい、稲作の里タイビンに稀な澄んだ空気と安らぎを満喫します。","facts":["ユネスコの紅河デルタ生物圏保護区内に位置します。","マングローブ林とモクマオウ林の豊かな生態系があります。","多くの希少な渡り鳥の中継地です。","長く平らな砂浜は、キャンプや朝日を迎えるのにぴったりです。"],"travelTips":["ここはまだ手つかずでサービスが乏しいため、テントや身の回り品を持参しましょう。","早起きして朝日を迎え、漁師とともにハマグリ掘りを体験しましょう。"],"bestTime":"4月から8月","visitDuration":"1日","ticket":"","openingHours":"終日","galleryCaptions":["コンヴァインビーチに昇る朝日","海辺のモクマオウ林","青々としたマングローブ林"]},"zh":{"name":"昆望海滩","summary":"生物圈保护区内原始的海滩，拥有木麻黄林、红树林和绝美的日出。","story":"昆望是一片伸入东海的原始冲积地带，位于被联合国教科文组织认定的红河三角洲生物圈保护区内。与喧闹的海滩不同，这里保持着质朴本色，平整的沙滩绵延数公里，木麻黄林在风中沙沙作响，红树林郁郁葱葱。昆望是候鸟的天堂，也是渔民耙蛤、捉招潮蟹谋生之地。游客来此露营，迎接海上绚烂的日出，品尝鲜美的海鲜，享受太平稻乡难得的清新与宁静。","facts":["位于联合国教科文组织红河三角洲生物圈保护区内。","拥有丰富的红树林和木麻黄林生态系统。","是许多珍稀候鸟的栖息驿站。","沙滩平坦宽广，适合露营和迎接日出。"],"travelTips":["由于这里服务设施仍较原始，请自带帐篷和个人用品。","早起迎接日出，体验与渔民一同耙蛤的乐趣。"],"bestTime":"4月至8月","visitDuration":"一天","ticket":"","openingHours":"全天","galleryCaptions":["昆望海滩上的日出","海边的木麻黄林","郁郁葱葱的红树林"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('vp-tam-dao', 'tam-dao', 'vinh-phuc', 'Tam Đảo', 'Tam Dao', 'mountain', 105.6447, 21.4561, 'Thị trấn nghỉ mát trên mây ở độ cao 900m, khí hậu mát lành quanh năm với sương mù bảng lảng huyền ảo.', 'Tam Đảo là thị trấn nghỉ dưỡng nằm vắt vẻo trên dãy núi cùng tên ở độ cao gần 900 mét, được người Pháp khám phá và xây dựng từ đầu thế kỷ XX. Quanh năm mây mù bao phủ, khí hậu se lạnh khiến nơi đây được ví như Đà Lạt của miền Bắc. Du khách lên Tam Đảo để trốn cái nóng oi ả, dạo bước trên những con dốc quanh co, chinh phục 1.300 bậc thang xuống Thác Bạc, hay check-in nhà thờ đá cổ kính phủ rêu phong. Khi màn sương buông xuống, cả thị trấn chìm trong không gian mờ ảo, lãng mạn như chốn bồng lai. Đặc sản su su xanh mướt và những bữa lẩu gà nóng hổi càng làm chuyến đi thêm trọn vẹn.', '["Nằm ở độ cao gần 900m, khí hậu mát mẻ quanh năm.","Được người Pháp xây dựng làm khu nghỉ dưỡng từ năm 1904.","Nhà thờ đá Tam Đảo là biểu tượng kiến trúc cổ kính.","Đặc sản su su Tam Đảo nổi tiếng xanh non, giòn ngọt."]', '["Mang theo áo ấm vì nhiệt độ ban đêm có thể xuống rất thấp.","Đi giữa tuần để tránh đông đúc và đặt phòng giá tốt hơn."]', 'Tháng 4 đến tháng 10', '2 ngày 1 đêm', '', 'Cả ngày', '["trending","popular","verified","ai-recommended"]', '["mountain","nature","photography","food"]', '[{"seed":"vp-tam-dao-1","caption":"Thị trấn Tam Đảo trong sương mù","ratio":"16/9"},{"seed":"vp-tam-dao-2","caption":"Nhà thờ đá cổ kính","ratio":"4/3"},{"seed":"vp-tam-dao-3","caption":"Thác Bạc giữa rừng xanh","ratio":"1/1"}]', '["vp-tay-thien"]', 1, '{"en":{"name":"Tam Dao","summary":"A resort town in the clouds at 900m, with cool air year-round and dreamy, drifting mist.","story":"Tam Dao is a resort town perched on the mountain range of the same name at nearly 900 meters, discovered and developed by the French in the early 20th century. Wrapped in mist year-round and pleasantly cool, it has earned the nickname ''the Da Lat of the North.'' Visitors come up to Tam Dao to escape the sweltering heat, stroll its winding slopes, conquer the 1,300 steps down to the Silver Waterfall, or check in at the moss-covered ancient stone church. When the mist descends, the whole town sinks into a dreamy, romantic haze like a fairyland. The vivid green chayote and steaming hot chicken hotpot make the trip all the more complete.","facts":["Sits at nearly 900m, with cool weather year-round.","Built by the French as a resort starting in 1904.","The Tam Dao stone church is an iconic piece of ancient architecture.","Tam Dao''s chayote is famed for being tender, green, and sweetly crisp."],"travelTips":["Bring warm clothing, as nighttime temperatures can drop quite low.","Visit midweek to avoid the crowds and get better room rates."],"bestTime":"April to October","visitDuration":"2 days, 1 night","ticket":"","openingHours":"All day","galleryCaptions":["The town of Tam Dao shrouded in mist","The ancient stone church","The Silver Waterfall amid the green forest"]},"ko":{"name":"땀다오","summary":"해발 900m 구름 위 휴양 마을, 일 년 내내 서늘한 기후와 은은히 감도는 안개가 환상적인 곳.","story":"땀다오는 같은 이름의 산맥 해발 900미터 가까이에 걸터앉은 휴양 마을로, 20세기 초 프랑스인들이 발견해 조성했습니다. 일 년 내내 구름과 안개에 덮여 서늘한 기후 덕분에 이곳은 ‘북부의 달랏’으로 불립니다. 여행자는 무더위를 피해 땀다오에 올라, 구불구불한 비탈길을 거닐고, 1,300개의 계단을 내려가 박 폭포를 정복하거나, 이끼 낀 고풍스러운 돌 성당에서 인증샷을 남깁니다. 안개가 내려앉으면 마을 전체가 신선 세계처럼 몽환적이고 낭만적인 분위기에 잠깁니다. 푸르고 싱싱한 차요테와 따뜻한 닭 샤브샤브 명물이 여행을 한층 더 알차게 채워 줍니다.","facts":["해발 900m 가까이에 자리해 일 년 내내 서늘합니다.","1904년 프랑스인들이 휴양지로 조성했습니다.","땀다오 돌 성당은 고풍스러운 건축의 상징입니다.","땀다오 차요테 명물은 푸르고 아삭달콤하기로 유명합니다."],"travelTips":["밤에는 기온이 매우 낮아질 수 있으니 따뜻한 옷을 챙기세요.","주중에 가면 혼잡을 피하고 더 저렴하게 숙소를 예약할 수 있습니다."],"bestTime":"4월~10월","visitDuration":"1박 2일","ticket":"","openingHours":"종일","galleryCaptions":["안개에 잠긴 땀다오 마을","고풍스러운 돌 성당","푸른 숲 속의 박 폭포"]},"ja":{"name":"タムダオ","summary":"標高900mの雲上の避暑地。一年中涼やかで、たなびく霧が幻想的な雰囲気を醸します。","story":"タムダオは、同名の山脈の標高約900メートルに張り付くように位置する保養地で、20世紀初頭にフランス人によって発見・建設されました。一年中雲と霧に覆われ、ひんやりとした気候から「北部のダラット」とも呼ばれています。旅行者は蒸し暑さを逃れてタムダオに登り、曲がりくねった坂道を散策したり、1,300段の階段を下ってバック滝へ向かったり、苔むした古い石造教会で写真を撮ったりします。霧が下りてくると、街全体がおぼろげでロマンチックな空間に包まれ、まるで仙境のよう。青々としたチャヨテの名産や、熱々の地鶏鍋が、旅をいっそう満ち足りたものにしてくれます。","facts":["標高約900mに位置し、一年中涼やかな気候です。","1904年にフランス人によって保養地として建設されました。","タムダオの石造教会は、古き趣の建築の象徴です。","名産のタムダオ産チャヨテは、みずみずしく歯ごたえと甘みがあると評判です。"],"travelTips":["夜間は気温がかなり下がることがあるので、防寒着を持参しましょう。","混雑を避け、宿をお得に予約するなら、平日に訪れましょう。"],"bestTime":"4月から10月","visitDuration":"1泊2日","ticket":"","openingHours":"終日","galleryCaptions":["霧に包まれたタムダオの街","古き趣の石造教会","緑の森に流れるバック滝"]},"zh":{"name":"三岛","summary":"海拔900米的云中避暑小镇，常年气候凉爽，薄雾缭绕，如梦如幻。","story":"三岛是坐落在同名山脉上、海拔近900米的度假小镇，自20世纪初由法国人发现并开发。这里常年云雾缭绕，气候微凉，被誉为「北部的大叻」。游客登上三岛躲避酷暑，漫步于蜿蜒曲折的山坡，挑战1300级台阶下到银瀑布，或在长满青苔的古朴石教堂打卡。当暮霭降临，整座小镇笼罩在朦胧的氛围中，浪漫得宛如仙境。翠绿的佛手瓜特产和热气腾腾的鸡肉火锅，更让旅程圆满。","facts":["海拔近900米，常年气候凉爽。","1904年由法国人建为度假区。","三岛石教堂是古朴建筑的象征。","三岛佛手瓜特产以鲜嫩青翠、爽脆甘甜闻名。"],"travelTips":["请携带保暖衣物，因为夜间气温可能降得很低。","选择工作日前来，可避开人群并以更优惠的价格订房。"],"bestTime":"4月至10月","visitDuration":"两天一夜","ticket":"","openingHours":"全天","galleryCaptions":["薄雾中的三岛小镇","古朴的石教堂","青翠森林中的银瀑布"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('vp-tay-thien', 'thien-vien-truc-lam-tay-thien', 'vinh-phuc', 'Thiền viện Trúc Lâm Tây Thiên', 'Truc Lam Tay Thien Zen Monastery', 'temple', 105.5961, 21.4392, 'Thiền viện lớn dưới chân Tam Đảo, chốn tu hành thanh tịnh gắn với khu danh thắng Tây Thiên linh thiêng.', 'Thiền viện Trúc Lâm Tây Thiên tọa lạc dưới chân núi Tam Đảo, là một trong những thiền viện lớn nhất Việt Nam, nơi kế thừa và phát huy dòng thiền Trúc Lâm Yên Tử do Phật hoàng Trần Nhân Tông sáng lập. Quần thể uy nghi với chính điện, lầu chuông, lầu trống và vườn tượng nằm giữa rừng núi xanh mát, không gian tĩnh lặng đưa lòng người vào cõi an nhiên. Tây Thiên còn được xem là một trong những cái nôi của Phật giáo Việt Nam, gắn với truyền thuyết Quốc Mẫu Tây Thiên Lăng Thị Tiêu. Hành hương lên đền Thượng qua những bậc đá rêu phong giữa rừng già, du khách vừa vãn cảnh vừa cảm nhận chiều sâu tâm linh ngàn năm của vùng đất thiêng.', '["Là một trong những thiền viện lớn nhất cả nước.","Kế thừa dòng thiền Trúc Lâm do Phật hoàng Trần Nhân Tông khai sáng.","Khu danh thắng Tây Thiên gắn với tín ngưỡng thờ Quốc Mẫu.","Có thể đi cáp treo lên đền Thượng giữa rừng nguyên sinh."]', '["Kết hợp đi cáp treo lên Tây Thiên để tiết kiệm sức khi viếng đền Thượng.","Mặc trang phục kín đáo, lịch sự khi vào khu vực thiền viện."]', 'Tháng 2 đến tháng 4 (mùa lễ hội)', 'Nửa ngày', '', '06:00 - 18:00', '["festival","verified","popular"]', '["temple","nature","culture"]', '[{"seed":"vp-tay-thien-1","caption":"Chính điện thiền viện uy nghi","ratio":"16/9"},{"seed":"vp-tay-thien-2","caption":"Đường lên đền Thượng Tây Thiên","ratio":"4/3"},{"seed":"vp-tay-thien-3","caption":"Vườn tượng giữa rừng xanh","ratio":"1/1"}]', '["vp-tam-dao"]', 0, '{"en":{"name":"Truc Lam Tay Thien Zen Monastery","summary":"A large Zen monastery at the foot of Tam Dao, a serene place of practice tied to the sacred Tay Thien scenic area.","story":"Truc Lam Tay Thien Zen Monastery sits at the foot of Tam Dao mountain, one of the largest Zen monasteries in Vietnam, carrying on and developing the Truc Lam Yen Tu Zen tradition founded by Buddha-King Tran Nhan Tong. The majestic complex, with its main hall, bell tower, drum tower, and statue garden, lies amid cool green mountains and forests, its quiet space drawing the heart into serenity. Tay Thien is also regarded as one of the cradles of Vietnamese Buddhism, tied to the legend of the National Mother of Tay Thien, Lang Thi Tieu. On a pilgrimage up to the Upper Temple along moss-covered stone steps through old-growth forest, visitors take in the scenery while sensing the millennium-deep spirituality of this sacred land.","facts":["One of the largest Zen monasteries in the country.","Carries on the Truc Lam Zen tradition founded by Buddha-King Tran Nhan Tong.","The Tay Thien scenic area is tied to the worship of the National Mother.","You can take a cable car up to the Upper Temple through primeval forest."],"travelTips":["Take the cable car up Tay Thien to save energy when visiting the Upper Temple.","Dress modestly and respectfully when entering the monastery grounds."],"bestTime":"February to April (festival season)","visitDuration":"Half a day","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["The majestic main hall of the monastery","The path up to the Upper Temple of Tay Thien","The statue garden amid the green forest"]},"ko":{"name":"쭉럼 떠이티엔 선원","summary":"땀다오 기슭의 큰 선원, 신성한 떠이티엔 명승지와 얽힌 청정한 수행처.","story":"쭉럼 떠이티엔 선원은 땀다오산 기슭에 자리한 베트남에서 손꼽히게 큰 선원으로, 불황(佛皇) 쩐년똥이 창시한 쭉럼 옌뜨 선맥을 계승하고 널리 떨치는 곳입니다. 본전, 종루, 고루(鼓樓), 불상 정원으로 이루어진 장엄한 사찰군이 푸르른 산림 한가운데 자리해, 고요한 공간이 사람의 마음을 평안의 경지로 이끕니다. 떠이티엔은 또한 베트남 불교의 발상지 가운데 하나로 꼽히며, 떠이티엔 국모(國母) 랑티띠에우 전설과 얽혀 있습니다. 울창한 숲 속 이끼 낀 돌계단을 따라 트엉 사당으로 순례하며, 여행자는 풍경을 감상하는 동시에 신성한 땅의 천년 영적 깊이를 느낍니다.","facts":["전국에서 손꼽히게 큰 선원 중 하나입니다.","불황 쩐년똥이 창시한 쭉럼 선맥을 계승합니다.","떠이티엔 명승지는 국모를 모시는 신앙과 얽혀 있습니다.","원시림 한가운데를 지나 케이블카로 트엉 사당까지 오를 수 있습니다."],"travelTips":["트엉 사당을 참배할 때 케이블카를 타면 떠이티엔까지 힘을 아낄 수 있습니다.","선원 구역에 들어갈 때는 단정하고 예의 바른 복장을 갖추세요."],"bestTime":"2월~4월(축제 철)","visitDuration":"반나절","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["위엄 있는 선원 본전","떠이티엔 트엉 사당으로 가는 길","푸른 숲 속의 불상 정원"]},"ja":{"name":"チュックラム・タイティエン禅院","summary":"タムダオの麓にある大禅院。神聖なタイティエン景勝地と結びついた、清浄な修行の場です。","story":"チュックラム・タイティエン禅院はタムダオ山の麓に位置するベトナム屈指の大禅院で、仏皇チャン・ニャン・トンが開いたイエントゥのチュックラム禅の流れを受け継ぎ、発展させています。本殿、鐘楼、太鼓楼、仏像の庭からなる威厳ある寺院群は、緑あふれる山林の中に静かに佇み、その静寂が人の心を安らぎの境地へと誘います。タイティエンはまた、ベトナム仏教発祥の地のひとつとされ、国母タイティエン・ラン・ティ・ティエウの伝説と結びついています。原生林の中、苔むした石段を上って上祠（デントゥオン）へ巡礼すれば、景色を愛でながら、この聖地の千年に及ぶ精神的な奥深さを感じ取ることができます。","facts":["ベトナム屈指の大禅院のひとつです。","仏皇チャン・ニャン・トンが開いたチュックラム禅の流れを受け継いでいます。","タイティエン景勝地は、国母を祀る信仰と結びついています。","ケーブルカーで原生林の中の上祠（デントゥオン）まで上ることができます。"],"travelTips":["上祠を参拝する際は、体力を節約するためケーブルカーの利用とあわせましょう。","禅院の区域に入る際は、控えめで礼儀正しい服装を心がけましょう。"],"bestTime":"2月から4月（祭りの季節）","visitDuration":"半日","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["威厳ある禅院の本殿","タイティエンの上祠へ向かう道","緑の森の中の仏像の庭"]},"zh":{"name":"西天竹林禅院","summary":"三岛山脚下的大型禅院，是清净的修行之地，与神圣的西天名胜区紧密相连。","story":"西天竹林禅院坐落于三岛山脚下，是越南最大的禅院之一，传承并弘扬由佛皇陈仁宗创立的安子竹林禅派。庄严的建筑群有大殿、钟楼、鼓楼和雕像园，坐落于青翠的山林之间，静谧的空间引人进入安然之境。西天还被视为越南佛教的发源地之一，与西天国母棱氏苗的传说紧密相连。沿着原始森林中长满青苔的石阶朝圣前往上庙，游客既能赏景，又能感受这片圣地千年的灵性深度。","facts":["是全国最大的禅院之一。","传承由佛皇陈仁宗开创的竹林禅派。","西天名胜区与供奉国母的信仰紧密相连。","可乘缆车穿越原始森林前往上庙。"],"travelTips":["前往西天时可乘缆车，省力地参拜上庙。","进入禅院区域时请穿着端庄得体的服装。"],"bestTime":"2月至4月（庙会季）","visitDuration":"半天","ticket":"","openingHours":"06:00 - 18:00","galleryCaptions":["庄严的禅院大殿","通往西天上庙的山路","青翠森林中的雕像园"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('thanh-nha-ho', 'thanh-nha-ho', 'thanh-hoa', 'Thành nhà Hồ', 'Ho Citadel', 'unesco', 105.6038, 20.0773, 'Tòa thành đá đồ sộ cuối thế kỷ 14, kỳ quan kiến trúc quân sự được UNESCO vinh danh giữa vùng quê xứ Thanh.', 'Được vua Hồ Quý Ly cho xây dựng năm 1397, Thành nhà Hồ là tòa thành đá hiếm hoi còn lại ở Đông Nam Á. Những khối đá xanh nặng hàng chục tấn được ghép khít nhau không cần chất kết dính, dựng nên bốn cổng vòm uy nghi sừng sững qua hơn sáu thế kỷ mưa nắng. Đứng dưới cổng Nam, du khách như chạm vào tài hoa của cha ông và những toan tính cải cách táo bạo một thời. Năm 2011, UNESCO ghi danh nơi đây là Di sản Văn hóa Thế giới, khẳng định giá trị độc đáo của một biểu tượng quyền lực và trí tuệ Đại Việt.', '["Được xây trong khoảng 3 tháng đầu năm 1397.","Tường thành ghép từ những phiến đá nặng tới 20 tấn.","UNESCO công nhận Di sản Văn hóa Thế giới năm 2011.","Từng là kinh đô của nhà Hồ trong giai đoạn ngắn ngủi."]', '["Đi sớm buổi sáng để chụp ảnh cổng đá trong nắng dịu.","Kết hợp thuê xe điện tham quan vành đai thành và đàn tế Nam Giao."]', 'Tháng 10 đến tháng 4', 'Nửa ngày', '40.000đ', '07:00 - 17:30', '["unesco","verified","popular"]', '["history","culture","photography"]', '[{"seed":"thanh-nha-ho-cong-nam","caption":"Cổng Nam đá xanh uy nghi","ratio":"16/9"},{"seed":"thanh-nha-ho-tuong-thanh","caption":"Tường thành ghép đá hàng thế kỷ","ratio":"4/3"},{"seed":"thanh-nha-ho-canh-dong","caption":"Thành cổ giữa đồng quê xứ Thanh","ratio":"1/1"}]', '["suoi-ca-than-cam-luong"]', 1, '{"en":{"name":"Ho Citadel","summary":"A massive late-14th-century stone citadel, a wonder of military architecture honored by UNESCO amid the Thanh Hoa countryside.","story":"Built in 1397 by order of King Ho Quy Ly, the Ho Citadel is one of the few remaining stone citadels in Southeast Asia. Blue-stone blocks weighing dozens of tons were fitted together without any binding mortar, raising four majestic arched gates that have stood through more than six centuries of sun and rain. Beneath the South Gate, visitors seem to touch the craftsmanship of the ancestors and the bold reformist ambitions of a bygone era. In 2011, UNESCO inscribed it as a World Cultural Heritage Site, affirming the unique value of a symbol of Dai Viet''s power and intellect.","facts":["Built within about three months in early 1397.","The walls are assembled from stone slabs weighing up to 20 tons.","Recognized as a UNESCO World Cultural Heritage Site in 2011.","It briefly served as the capital of the Ho Dynasty."],"travelTips":["Come early in the morning to photograph the stone gates in soft light.","Rent an electric cart to tour the citadel perimeter and the Nam Giao esplanade."],"bestTime":"October to April","visitDuration":"Half a day","ticket":"40,000 VND","openingHours":"07:00 - 17:30","galleryCaptions":["The majestic blue-stone South Gate","Centuries-old stone-assembled walls","The ancient citadel amid the Thanh Hoa countryside"]},"ko":{"name":"호 왕조 성채","summary":"14세기 말의 거대한 석조 성채로, 타인호아 시골 한가운데 유네스코가 인정한 군사 건축의 경이입니다.","story":"1397년 호꾸이리 왕의 명으로 지어진 호 왕조 성채는 동남아시아에 남은 몇 안 되는 석조 성채입니다. 수십 톤에 달하는 청석 블록을 접착제 없이 빈틈없이 맞물려, 600여 년의 비바람을 견딘 네 개의 웅장한 아치형 성문을 세웠습니다. 남문 아래 서면 방문객은 선조의 솜씨와 한 시대의 대담한 개혁의 야망에 닿는 듯합니다. 2011년 유네스코는 이곳을 세계문화유산으로 등재하며 대월의 권력과 지혜를 상징하는 독특한 가치를 인정했습니다.","facts":["1397년 초 약 3개월 만에 지어졌습니다.","성벽은 최대 20톤에 달하는 석판을 맞물려 쌓았습니다.","2011년 유네스코 세계문화유산으로 인정되었습니다.","짧은 기간 호 왕조의 수도였습니다."],"travelTips":["부드러운 햇빛 속 석조 성문을 촬영하려면 이른 아침에 가세요.","전동차를 빌려 성채 외곽과 남자오 제단을 둘러보세요."],"bestTime":"10월부터 4월까지","visitDuration":"반나절","ticket":"40,000동","openingHours":"07:00 - 17:30","galleryCaptions":["위엄 있는 청석 남문","수 세기 된 석조 성벽","타인호아 시골 한가운데의 고성"]},"ja":{"name":"胡朝城（ホー城）","summary":"14世紀末の巨大な石造城。タインホアの田園に立つ、ユネスコが称えた軍事建築の驚異です。","story":"1397年に胡季犛（ホー・クイ・リー）王の命で築かれた胡朝城は、東南アジアに残る数少ない石造城のひとつです。数十トンもの青石のブロックを接着剤なしで隙間なく組み合わせ、600年以上の風雨に耐えてきた四つの荘厳なアーチ門を立ち上げました。南門の下に立つと、訪れる者は先人の技と、ある時代の大胆な改革の野望に触れるかのようです。2011年、ユネスコはここを世界文化遺産に登録し、大越の権力と知性を象徴する独自の価値を認めました。","facts":["1397年初頭、約3か月で築かれました。","城壁は最大20トンの石板を組み合わせて造られています。","2011年にユネスコ世界文化遺産に認定されました。","短い間、胡朝の首都でした。"],"travelTips":["柔らかな光の中で石門を撮影するなら早朝に訪れましょう。","電動カートを借りて城の外周と南郊の祭壇を巡りましょう。"],"bestTime":"10月から4月まで","visitDuration":"半日","ticket":"40,000ドン","openingHours":"07:00 - 17:30","galleryCaptions":["威厳ある青石の南門","何世紀も前から組まれた石の城壁","タインホアの田園に立つ古城"]},"zh":{"name":"胡朝城","summary":"十四世纪末的宏伟石城，矗立于清化乡野之间，是联合国教科文组织表彰的军事建筑奇迹。","story":"胡朝城由胡季犛王下令于1397年建造，是东南亚现存少有的石城。重达数十吨的青石块未用任何黏合剂便严丝合缝地拼砌，立起四座巍峨的拱门，历经六百余年风雨而屹立不倒。站在南门之下，游人仿佛触及先人的巧手与那个时代大胆的改革雄心。2011年，联合国教科文组织将此地列为世界文化遗产，肯定了这座象征大越权力与智慧的独特价值。","facts":["于1397年初约三个月内建成。","城墙以重达20吨的石板拼砌而成。","2011年被联合国教科文组织认定为世界文化遗产。","曾短暂作为胡朝的都城。"],"travelTips":["清晨前往，可在柔和阳光下拍摄石门。","可租电瓶车游览城郭外圈与南郊祭坛。"],"bestTime":"10月至4月","visitDuration":"半天","ticket":"40,000越南盾","openingHours":"07:00 - 17:30","galleryCaptions":["巍峨的青石南门","历经数百年的拼石城墙","矗立于清化乡野间的古城"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bien-sam-son', 'bien-sam-son', 'thanh-hoa', 'Biển Sầm Sơn', 'Sam Son Beach', 'beach', 105.9069, 19.7497, 'Bãi biển trứ danh xứ Thanh với bờ cát thoải, sóng êm và không khí lễ hội rộn ràng suốt mùa hè.', 'Sầm Sơn từ lâu đã là điểm nghỉ mát yêu thích của người dân miền Bắc, nơi bãi cát trải dài thoai thoải và làn nước trong xanh mời gọi. Từ thời Pháp thuộc, vùng biển này đã được chọn làm nơi an dưỡng nhờ khí hậu mát lành. Bình minh trên hòn Trống Mái, dạo chân lên đền Độc Cước linh thiêng tựa lưng vào núi Trường Lệ, rồi thưởng thức hải sản tươi rói bên bờ sóng, tất cả tạo nên một Sầm Sơn vừa náo nhiệt vừa đậm đà bản sắc. Mỗi độ hè về, các lễ hội biển lại thắp sáng cả một vùng trời.', '["Bãi biển dài khoảng 9km với cát mịn thoai thoải.","Hòn Trống Mái gắn với truyền thuyết tình yêu nổi tiếng.","Đền Độc Cước thờ vị thần tự xẻ đôi thân mình cứu dân.","Được người Pháp khai thác du lịch từ năm 1906."]', '["Tắm biển vào sáng sớm hoặc chiều muộn để tránh nắng gắt.","Thỏa thuận giá hải sản trước khi gọi món tại các quán ven biển."]', 'Tháng 5 đến tháng 8', '1 - 2 ngày', '', 'Cả ngày', '["popular","trending","festival"]', '["beach","nature","food"]', '[{"seed":"sam-son-binh-minh","caption":"Bình minh trên bãi tắm Sầm Sơn","ratio":"16/9"},{"seed":"sam-son-trong-mai","caption":"Hòn Trống Mái lừng danh","ratio":"4/3"},{"seed":"sam-son-hai-san","caption":"Bãi tắm rợp dù che nhìn từ trên cao","ratio":"1/1"}]', '["thanh-nha-ho"]', 0, '{"en":{"name":"Sam Son Beach","summary":"Thanh Hoa''s famous beach with its gently sloping sands, calm waves, and lively festival atmosphere all summer long.","story":"Sam Son has long been a favorite retreat for northern Vietnamese, where the gently sloping sands stretch on and clear blue waters beckon. As far back as French colonial times, this stretch of coast was chosen as a wellness resort for its cool, fresh climate. Watching dawn break over the Trong Mai (Cock and Hen) rocks, climbing to the sacred Doc Cuoc Temple set against Truong Le Mountain, then savoring fresh seafood by the surf — together these make a Sam Son both bustling and rich in character. Each summer, the sea festivals light up the whole sky.","facts":["The beach stretches about 9km with fine, gently sloping sand.","The Trong Mai rocks are linked to a famous legend of love.","Doc Cuoc Temple honors a deity who split his own body in two to save the people.","The French began developing it for tourism in 1906."],"travelTips":["Swim in the early morning or late afternoon to avoid the harsh sun.","Agree on seafood prices before ordering at the beachside eateries."],"bestTime":"May to August","visitDuration":"1 - 2 days","ticket":"Free","openingHours":"All day","galleryCaptions":["Dawn over Sam Son beach","The renowned Trong Mai rocks","The beach dotted with parasols seen from above"]},"ko":{"name":"삼손 해변","summary":"완만한 모래사장과 잔잔한 파도, 여름 내내 흥겨운 축제 분위기로 유명한 타인호아의 명소 해변입니다.","story":"삼손은 오래전부터 북부 베트남 사람들이 즐겨 찾는 휴양지로, 완만하게 펼쳐진 모래사장과 맑고 푸른 바닷물이 손짓합니다. 프랑스 식민지 시절부터 시원하고 상쾌한 기후 덕에 이 해안은 요양지로 선택되었습니다. 쫑마이(수탉과 암탉) 바위 위로 떠오르는 일출을 바라보고, 쯔엉레산을 등진 신성한 독꿕 사원에 오르며, 파도 곁에서 신선한 해산물을 맛보는 것 — 이 모두가 활기차면서도 정취 가득한 삼손을 빚어냅니다. 여름마다 바다 축제가 온 하늘을 밝힙니다.","facts":["해변은 약 9km 길이로 곱고 완만한 모래사장입니다.","쫑마이 바위는 유명한 사랑의 전설과 얽혀 있습니다.","독꿕 사원은 백성을 구하려 제 몸을 둘로 가른 신을 모십니다.","프랑스인이 1906년부터 관광지로 개발했습니다."],"travelTips":["강한 햇볕을 피해 이른 아침이나 늦은 오후에 해수욕하세요.","해변가 식당에서 주문하기 전에 해산물 가격을 흥정하세요."],"bestTime":"5월부터 8월까지","visitDuration":"1~2일","ticket":"무료","openingHours":"종일","galleryCaptions":["삼손 해변의 일출","이름난 쫑마이 바위","위에서 본 파라솔 가득한 해변"]},"ja":{"name":"サムソンビーチ","summary":"なだらかな砂浜、穏やかな波、夏じゅう続く賑やかな祭りの雰囲気で名高い、タインホア屈指のビーチです。","story":"サムソンは古くから北部ベトナムの人々に愛される避暑地で、なだらかに広がる砂浜と澄んだ青い海が誘います。フランス統治時代から、この海辺は涼やかな気候ゆえに保養地に選ばれてきました。チョンマイ（雄鶏と雌鶏）岩の上に昇る朝日を眺め、チュオンレ山を背にした神聖なドックオック寺に登り、波打ち際で新鮮な海の幸を味わう——それらすべてが、賑やかでありながら情緒豊かなサムソンを作り上げます。夏が来るたび、海の祭りが空いっぱいを照らします。","facts":["ビーチは約9kmにわたり、きめ細かくなだらかな砂浜です。","チョンマイ岩は有名な愛の伝説と結びついています。","ドックオック寺は、民を救うため自らの体を二つに裂いた神を祀ります。","フランス人が1906年から観光地として開発しました。"],"travelTips":["強い日差しを避け、早朝か夕方遅くに海水浴を。","海辺の食堂で注文する前に海の幸の値段を交渉しましょう。"],"bestTime":"5月から8月まで","visitDuration":"1〜2日","ticket":"無料","openingHours":"終日","galleryCaptions":["サムソンビーチの朝日","名高いチョンマイ岩","上空から見たパラソルが立ち並ぶ砂浜"]},"zh":{"name":"岑山海滩","summary":"清化著名海滩，沙坡平缓、海浪温和，整个夏天洋溢着热闹的节庆气氛。","story":"岑山早已是北方人钟爱的避暑胜地，平缓绵长的沙滩与清澈碧蓝的海水声声相邀。早在法属时期，这片海域便因气候清凉而被选为疗养之地。在雄雌石上看日出，登临背靠长丽山的圣地独脚庙，再在浪涛边品尝鲜活的海味，这一切共同造就了既热闹又风情浓郁的岑山。每逢夏日，海滨节庆便点亮整片天空。","facts":["海滩长约9公里，沙质细腻、坡度平缓。","雄雌石与一则著名的爱情传说相连。","独脚庙供奉一位自剖己身以救百姓的神祇。","法国人于1906年起开发其旅游。"],"travelTips":["清晨或傍晚下水，避开烈日。","在海边餐馆点海鲜前先谈好价格。"],"bestTime":"5月至8月","visitDuration":"1至2天","ticket":"免费","openingHours":"全天","galleryCaptions":["岑山海滩的日出","闻名的雄雌石","俯瞰遮阳伞遍布的海滩"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('suoi-ca-than-cam-luong', 'suoi-ca-than-cam-luong', 'thanh-hoa', 'Suối cá thần Cẩm Lương', 'Cam Luong Fish Stream', 'park', 105.3711, 20.2542, 'Dòng suối kỳ lạ nơi hàng nghìn con cá thần quây quần dưới chân núi đá vôi, gắn với tín ngưỡng người Mường.', 'Ẩn mình dưới chân núi Trường Sinh ở huyện Cẩm Thủy, suối cá thần Cẩm Lương khiến bao du khách kinh ngạc bởi hàng nghìn con cá to lớn bơi lượn dày đặc trong làn nước trong vắt. Người Mường nơi đây tin rằng đàn cá là thần giữ bình yên cho bản làng, nên không ai dám đánh bắt. Cá ở đây thân tròn, vây hồng, có con nặng tới vài cân, ung dung sống qua bao đời. Bên dòng suối mát lành còn có hang động kỳ thú và những nếp nhà sàn mộc mạc, tạo nên một bức tranh thiên nhiên và văn hóa hài hòa, bình yên đến lạ.', '["Ước tính có hàng nghìn con cá sinh sống trong đoạn suối ngắn.","Người Mường coi đàn cá là cá thần, tuyệt đối không đánh bắt.","Cá thuộc họ cá chép, có con nặng vài kilôgam.","Suối chảy ra từ một hang động trong lòng núi đá vôi."]', '["Mang giày chống trượt vì lối đi ven suối khá ẩm.","Ghé bản Mường gần đó để thưởng thức cơm lam và rượu cần."]', 'Tháng 3 đến tháng 9', 'Nửa ngày', '20.000đ', '07:00 - 18:00', '["hidden-gem","verified"]', '["nature","culture","photography"]', '[{"seed":"cam-luong-dan-ca","caption":"Đàn cá thần dưới chân núi","ratio":"16/9"},{"seed":"cam-luong-suoi-trong","caption":"Dòng suối trong vắt","ratio":"4/3"},{"seed":"cam-luong-nha-san","caption":"Bản Mường ven suối","ratio":"1/1"}]', '["thanh-nha-ho"]', 0, '{"en":{"name":"Cam Luong Sacred Fish Stream","summary":"A remarkable stream where thousands of sacred fish gather at the foot of a limestone mountain, tied to the beliefs of the Muong people.","story":"Tucked at the foot of Truong Sinh Mountain in Cam Thuy District, the Cam Luong Sacred Fish Stream astonishes visitors with thousands of large fish swimming in dense schools through its crystal-clear water. The local Muong people believe the fish are guardian spirits that keep the village at peace, so no one dares to catch them. The fish here have round bodies and pink fins, some weighing several kilograms, living serenely across generations. Along the cool stream are also fascinating caves and rustic stilt houses, forming a harmonious picture of nature and culture, strangely peaceful.","facts":["An estimated several thousand fish live within a short stretch of the stream.","The Muong people regard the fish as sacred and never catch them.","The fish belong to the carp family, some weighing several kilograms.","The stream flows from a cave inside the limestone mountain."],"travelTips":["Wear non-slip shoes, as the streamside path is quite damp.","Visit a nearby Muong village to enjoy bamboo-tube rice and can wine."],"bestTime":"March to September","visitDuration":"Half a day","ticket":"20,000 VND","openingHours":"07:00 - 18:00","galleryCaptions":["The sacred fish at the foot of the mountain","The crystal-clear stream","A Muong village beside the stream"]},"ko":{"name":"껌르엉 신어 계곡","summary":"석회암 산기슭에 수천 마리의 신성한 물고기가 모여드는 신비로운 계곡으로, 므엉족의 신앙과 얽혀 있습니다.","story":"껌투이현 쯔엉신산 기슭에 숨은 껌르엉 신어 계곡은 맑디맑은 물속을 빽빽이 헤엄치는 수천 마리의 큰 물고기로 방문객을 놀라게 합니다. 이곳 므엉족은 이 물고기들이 마을의 평안을 지키는 수호신이라 믿어 아무도 감히 잡지 않습니다. 이곳 물고기는 몸이 둥글고 지느러미가 분홍빛이며, 몇 킬로그램에 달하는 것도 있어 대대로 유유히 살아갑니다. 시원한 계곡 곁에는 신비로운 동굴과 소박한 고상가옥도 있어, 자연과 문화가 어우러진 묘하게 평화로운 풍경을 이룹니다.","facts":["짧은 계곡 구간에 수천 마리의 물고기가 산다고 추정됩니다.","므엉족은 이 물고기를 신어로 여겨 절대 잡지 않습니다.","잉어과에 속하며 몇 킬로그램에 달하는 것도 있습니다.","계곡은 석회암 산속 동굴에서 흘러나옵니다."],"travelTips":["계곡가 길이 꽤 축축하니 미끄럼 방지 신발을 신으세요.","근처 므엉족 마을에 들러 껌람(대통밥)과 껀술을 즐겨 보세요."],"bestTime":"3월부터 9월까지","visitDuration":"반나절","ticket":"20,000동","openingHours":"07:00 - 18:00","galleryCaptions":["산기슭의 신어 떼","맑디맑은 계곡","계곡가의 므엉족 마을"]},"ja":{"name":"カムルオン神魚の渓流","summary":"石灰岩の山のふもとに数千匹の神聖な魚が集う不思議な渓流。ムオン族の信仰と結びついています。","story":"カムトゥイ県のチュオンシン山のふもとに隠れたカムルオン神魚の渓流は、澄み切った水の中をびっしりと泳ぐ数千匹の大きな魚で訪れる人を驚かせます。地元のムオン族は、この魚たちが村の平安を守る神だと信じ、誰も捕らえようとしません。ここの魚は体が丸く、ひれは桃色で、数キロにもなるものもおり、代々悠々と生きてきました。涼やかな渓流のほとりには不思議な洞窟や素朴な高床式の家もあり、自然と文化が調和した、不思議なほど穏やかな風景を織りなします。","facts":["短い渓流の一帯に数千匹の魚が生息すると推定されます。","ムオン族は魚を神魚とみなし、決して捕らえません。","コイの仲間で、数キログラムになるものもいます。","渓流は石灰岩の山の中の洞窟から流れ出ています。"],"travelTips":["渓流沿いの道はかなり湿っているので滑り止めの靴を。","近くのムオン族の村に立ち寄り、コムラム（竹筒飯）とカン酒を楽しみましょう。"],"bestTime":"3月から9月まで","visitDuration":"半日","ticket":"20,000ドン","openingHours":"07:00 - 18:00","galleryCaptions":["山のふもとの神魚の群れ","澄み切った渓流","渓流沿いのムオン族の村"]},"zh":{"name":"锦良神鱼溪","summary":"石灰岩山脚下，数千尾神鱼聚集的奇异溪流，与芒族的信仰息息相关。","story":"锦良神鱼溪隐于锦水县长生山脚下，清澈见底的溪水中数千尾大鱼密集游弋，令无数游人惊叹。当地芒族相信这群鱼是守护村寨安宁的神灵，因而无人敢捕。这里的鱼体圆鳍红，有的重达数斤，世代悠然栖息。清凉的溪畔还有奇趣的洞穴与朴素的高脚屋，构成一幅自然与文化交融、宁静得出奇的画卷。","facts":["据估计，短短一段溪流中栖息着数千尾鱼。","芒族视其为神鱼，绝不捕捞。","鱼属鲤科，有的重达数公斤。","溪水从石灰岩山中的洞穴流出。"],"travelTips":["溪畔小路颇为潮湿，请穿防滑鞋。","顺道走访附近芒族村寨，品尝竹筒饭与杆酒。"],"bestTime":"3月至9月","visitDuration":"半天","ticket":"20,000越南盾","openingHours":"07:00 - 18:00","galleryCaptions":["山脚下的神鱼群","清澈见底的溪流","溪畔的芒族村寨"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('khu-di-tich-kim-lien', 'khu-di-tich-kim-lien', 'nghe-an', 'Khu di tích Kim Liên - quê Bác', 'Kim Lien Relic Site', 'museum', 105.5611, 18.6797, 'Làng Sen, làng Hoàng Trù - nơi Chủ tịch Hồ Chí Minh sinh ra và lớn lên, điểm hành hương thiêng liêng của triệu trái tim.', 'Về Kim Liên, huyện Nam Đàn, ta như được trở lại tuổi thơ của Bác Hồ kính yêu. Trong ngôi nhà tranh đơn sơ ở làng Hoàng Trù, cậu bé Nguyễn Sinh Cung cất tiếng khóc chào đời; còn ở làng Sen, mái nhà lá giản dị in dấu những năm tháng Người sống cùng cha. Khung cửi, võng đay, chiếc phản gỗ mộc mạc vẫn còn đó, gợi nhắc nếp sống thanh bạch của một gia đình nhà Nho yêu nước. Hàng năm, hàng triệu người con đất Việt tìm về đây, lặng đứng bên giếng Cốc, cây đa, mái nhà xưa, để tưởng nhớ và tri ân vị lãnh tụ vĩ đại của dân tộc.', '["Gồm hai cụm di tích chính: làng Sen và làng Hoàng Trù.","Là nơi Chủ tịch Hồ Chí Minh sinh năm 1890.","Được công nhận là Di tích Quốc gia đặc biệt.","Đón hàng triệu lượt khách hành hương mỗi năm."]', '["Ăn mặc lịch sự, giữ trật tự khi tham quan khu di tích.","Đến vào dịp 19/5 để hòa mình vào lễ hội Làng Sen."]', 'Tháng 4 đến tháng 5', 'Nửa ngày', '', '07:00 - 17:00', '["verified","popular","festival"]', '["history","culture"]', '[{"seed":"kim-lien-nha-tranh","caption":"Ngôi nhà tranh quê Bác","ratio":"16/9"},{"seed":"kim-lien-gieng-coc","caption":"Giếng Cốc làng Sen","ratio":"4/3"},{"seed":"kim-lien-cay-da","caption":"Cây đa cổ thụ đầu làng","ratio":"1/1"}]', '["bien-cua-lo"]', 1, '{"en":{"name":"Kim Lien Relic Site - Uncle Ho''s Homeland","summary":"Sen Village and Hoang Tru Village — where President Ho Chi Minh was born and raised, a sacred pilgrimage site for millions of hearts.","story":"Returning to Kim Lien in Nam Dan District, we step back into the childhood of beloved Uncle Ho. In a humble thatched house in Hoang Tru Village, the boy Nguyen Sinh Cung gave his first cry; in Sen Village, a simple leaf-roofed home bears the marks of the years he lived with his father. The loom, the jute hammock and the plain wooden plank bed remain, recalling the frugal life of a patriotic Confucian family. Each year, millions of Vietnamese return here, standing quietly beside Coc Well, the banyan tree and the old house, to remember and honor the nation''s great leader.","facts":["It comprises two main relic clusters: Sen Village and Hoang Tru Village.","It is where President Ho Chi Minh was born in 1890.","Recognized as a Special National Relic.","It welcomes millions of pilgrims each year."],"travelTips":["Dress modestly and keep quiet while visiting the relic site.","Come around May 19 to join the Sen Village Festival."],"bestTime":"April to May","visitDuration":"Half a day","ticket":"Free","openingHours":"07:00 - 17:00","galleryCaptions":["Uncle Ho''s thatched childhood house","Coc Well in Sen Village","The ancient banyan tree at the village entrance"]},"ko":{"name":"낌리엔 유적지 - 호 아저씨의 고향","summary":"센 마을과 호앙쭈 마을 — 호찌민 주석이 태어나고 자란 곳으로, 수백만 마음의 신성한 순례지입니다.","story":"남단현 낌리엔으로 돌아가면 사랑하는 호 아저씨의 어린 시절로 거슬러 갑니다. 호앙쭈 마을의 소박한 초가집에서 소년 응우옌신꿍이 첫 울음을 터뜨렸고, 센 마을의 단순한 잎 지붕 집에는 그가 아버지와 함께 산 세월의 흔적이 남아 있습니다. 베틀과 황마 해먹, 소박한 나무 평상이 그대로 남아 애국적인 유학자 집안의 검소한 삶을 떠올리게 합니다. 해마다 수백만 베트남인이 이곳을 찾아 꼭 우물, 보리수, 옛집 곁에 조용히 서서 민족의 위대한 지도자를 추모하고 기립니다.","facts":["센 마을과 호앙쭈 마을, 두 주요 유적군으로 이루어집니다.","호찌민 주석이 1890년 태어난 곳입니다.","특별 국가 유적으로 인정되었습니다.","해마다 수백만 명의 순례객이 찾습니다."],"travelTips":["유적지를 둘러볼 때는 단정히 입고 질서를 지키세요.","5월 19일경에 방문해 센 마을 축제에 함께해 보세요."],"bestTime":"4월부터 5월까지","visitDuration":"반나절","ticket":"무료","openingHours":"07:00 - 17:00","galleryCaptions":["호 아저씨의 초가 생가","센 마을의 꼭 우물","마을 어귀의 오래된 보리수"]},"ja":{"name":"キムリエン史跡 - ホーおじさんの故郷","summary":"セン村とホアンチュー村——ホー・チ・ミン主席が生まれ育った地。数百万の心が訪れる神聖な巡礼地です。","story":"ナムダン県のキムリエンに戻ると、敬愛するホーおじさんの幼少期へとさかのぼるかのようです。ホアンチュー村の質素な茅葺きの家で、少年グエン・シン・クンは産声をあげました。セン村では、簡素な葉葺きの家が、彼が父と暮らした歳月の跡を残します。機織り機、ジュートのハンモック、素朴な木の寝台が今も残り、愛国的な儒者一家の質素な暮らしを思い起こさせます。毎年、数百万のベトナムの人々がここを訪れ、コック井戸、菩提樹、古い家のそばに静かにたたずみ、民族の偉大な指導者を偲び、感謝を捧げます。","facts":["セン村とホアンチュー村、二つの主要な史跡群からなります。","ホー・チ・ミン主席が1890年に生まれた地です。","特別国家史跡に認定されています。","毎年、数百万人の巡礼者が訪れます。"],"travelTips":["史跡を見学する際は身なりを整え、静粛を保ちましょう。","5月19日頃に訪れてセン村の祭りに参加しましょう。"],"bestTime":"4月から5月まで","visitDuration":"半日","ticket":"無料","openingHours":"07:00 - 17:00","galleryCaptions":["ホーおじさんの茅葺きの生家","セン村のコック井戸","村の入口の古い菩提樹"]},"zh":{"name":"金莲遗迹区 - 胡伯伯故乡","summary":"莲村与黄柱村——胡志明主席出生与成长之地，是千万颗心灵的圣地。","story":"回到南坛县的金莲，仿佛重返敬爱的胡伯伯的童年。在黄柱村简朴的茅屋里，男孩阮生恭呱呱坠地；在莲村，朴素的叶顶小屋留下了他与父亲共同生活的岁月印记。织机、麻吊床、素朴的木榻仍在，唤起一个爱国儒生之家清贫的生活。每年，数百万越南儿女回到这里，静静伫立在谷井、榕树与旧居旁，缅怀并感念民族的伟大领袖。","facts":["由两大遗迹群组成：莲村与黄柱村。","胡志明主席于1890年在此出生。","被认定为国家特别遗迹。","每年迎来数百万朝圣者。"],"travelTips":["参观遗迹区时着装得体、保持安静。","可于5月19日前后前往，融入莲村庙会。"],"bestTime":"4月至5月","visitDuration":"半天","ticket":"免费","openingHours":"07:00 - 17:00","galleryCaptions":["胡伯伯故乡的茅屋","莲村的谷井","村口的古榕树"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bien-cua-lo', 'bien-cua-lo', 'nghe-an', 'Biển Cửa Lò', 'Cua Lo Beach', 'beach', 105.7178, 18.8047, 'Bãi biển sầm uất bậc nhất xứ Nghệ với cát trắng, nước trong và đặc sản mực nhảy trứ danh.', 'Cửa Lò là viên ngọc du lịch của Nghệ An, nơi bờ cát trắng mịn trải dài hơn mười cây số ôm lấy biển xanh lồng lộng gió. Buổi sớm, ngư dân trở về với những khoang thuyền đầy ắp, mang theo món mực nhảy tươi roi rói khiến thực khách mê mẩn. Du khách có thể chèo thuyền ra đảo Lan Châu, ngắm đảo Ngư xa xa, hay thong dong dạo bộ trên con đường ven biển lộng gió lúc hoàng hôn. Về đêm, các khu phố ẩm thực và quảng trường lại bừng sáng, mang đến một Cửa Lò vừa thơ mộng vừa náo nhiệt, xứng danh điểm đến mùa hè được yêu thích nhất miền Trung.', '["Bãi biển dài hơn 10km, cát trắng mịn và nước trong.","Mực nhảy Cửa Lò là đặc sản nổi tiếng khắp cả nước.","Đảo Lan Châu nằm sát bờ, nối liền lúc thủy triều xuống.","Được quy hoạch thành đô thị du lịch biển từ năm 1994."]', '["Thưởng thức mực nhảy hấp ngay tại bến cá lúc sáng sớm.","Đặt phòng trước vào cuối tuần hè vì lượng khách rất đông."]', 'Tháng 5 đến tháng 8', '1 - 2 ngày', '', 'Cả ngày', '["popular","trending"]', '["beach","food","nature"]', '[{"seed":"cua-lo-bai-cat","caption":"Đại lộ ven biển rợp bóng cây buổi sớm","ratio":"16/9"},{"seed":"cua-lo-muc-nhay","caption":"Phố biển lên đèn lung linh lúc hoàng hôn","ratio":"4/3"},{"seed":"cua-lo-dao-lan-chau","caption":"Đảo Lan Châu sát bờ","ratio":"1/1"}]', '["khu-di-tich-kim-lien"]', 0, '{"en":{"name":"Cua Lo Beach","summary":"One of Nghe An''s busiest beaches, with white sand, clear water, and its famous ''jumping squid'' delicacy.","story":"Cua Lo is Nghe An''s tourism gem, where soft white sands stretch for more than ten kilometers, embracing a wind-swept blue sea. In the early morning, fishermen return with holds full of catch, bringing the freshest ''jumping squid'' that enchants every diner. Visitors can paddle out to Lan Chau Island, gaze at Ngu Island in the distance, or stroll leisurely along the breezy seaside road at sunset. By night, the food streets and the square light up, giving Cua Lo a charm both dreamy and lively — well deserving its name as central Vietnam''s most beloved summer destination.","facts":["The beach stretches more than 10km with fine white sand and clear water.","Cua Lo''s ''jumping squid'' is a delicacy famous throughout the country.","Lan Chau Island lies close to shore, connected at low tide.","It was planned as a coastal tourism town starting in 1994."],"travelTips":["Enjoy steamed ''jumping squid'' right at the fishing wharf in the early morning.","Book rooms in advance on summer weekends, as crowds are very large."],"bestTime":"May to August","visitDuration":"1 - 2 days","ticket":"Free","openingHours":"All day","galleryCaptions":["The tree-lined seaside boulevard in the early morning","The seaside town aglow at sunset","Lan Chau Island close to shore"]},"ko":{"name":"끄어로 해변","summary":"흰 모래와 맑은 물, 유명한 ''점핑 오징어'' 별미로 손꼽히는 응에안 최고의 번화한 해변입니다.","story":"끄어로는 응에안의 관광 보석으로, 부드러운 흰 모래가 10여 킬로미터 펼쳐지며 바람 부는 푸른 바다를 감쌉니다. 이른 아침이면 어부들이 가득 찬 어창을 싣고 돌아와 식객을 사로잡는 가장 신선한 ''점핑 오징어''를 가져옵니다. 방문객은 란쩌우섬으로 노 저어 가거나 멀리 응으섬을 바라보고, 노을 질 무렵 바람 부는 해안 길을 한가로이 거닐 수 있습니다. 밤이 되면 먹거리 거리와 광장이 환히 빛나며, 꿈결 같으면서도 활기찬 끄어로를 선사해 중부에서 가장 사랑받는 여름 명소라는 이름값을 합니다.","facts":["해변은 10km 넘게 펼쳐지며 곱고 흰 모래와 맑은 물을 자랑합니다.","끄어로의 ''점핑 오징어''는 전국적으로 유명한 별미입니다.","란쩌우섬은 해안에 가까이 있어 썰물 때 연결됩니다.","1994년부터 해변 관광 도시로 계획되었습니다."],"travelTips":["이른 아침 어선 부두에서 갓 잡은 ''점핑 오징어'' 찜을 즐기세요.","여름 주말에는 관광객이 매우 많으니 미리 객실을 예약하세요."],"bestTime":"5월부터 8월까지","visitDuration":"1~2일","ticket":"무료","openingHours":"종일","galleryCaptions":["이른 아침 가로수 우거진 해안 대로","노을 질 무렵 반짝이는 바닷가 도시","해안에 가까운 란쩌우섬"]},"ja":{"name":"クアロービーチ","summary":"白い砂、澄んだ水、名高い「跳ねるイカ」の珍味で知られる、ゲアン屈指の賑やかなビーチです。","story":"クアローはゲアンの観光の宝石。柔らかな白砂が10キロ以上にわたって伸び、風吹く青い海を抱きます。早朝には漁師たちが満載の船倉を抱えて戻り、食通を魅了する獲れたての「跳ねるイカ」を運んできます。訪れる人はランチャウ島へ漕ぎ出し、遠くのグー島を眺め、夕暮れに風吹く海辺の道をのんびり歩けます。夜になるとグルメ街と広場が明るく輝き、夢のようでありながら賑やかなクアローを見せ、中部で最も愛される夏の名所の名にふさわしい姿を見せます。","facts":["ビーチは10km以上にわたり、きめ細かな白砂と澄んだ水を誇ります。","クアローの「跳ねるイカ」は全国的に有名な珍味です。","ランチャウ島は岸に近く、干潮時に陸続きになります。","1994年から海辺の観光都市として計画されました。"],"travelTips":["早朝に漁港でとれたての「跳ねるイカ」の蒸し料理を味わいましょう。","夏の週末は観光客が非常に多いので、宿は早めに予約を。"],"bestTime":"5月から8月まで","visitDuration":"1〜2日","ticket":"無料","openingHours":"終日","galleryCaptions":["早朝の並木が茂る海辺の大通り","夕暮れに輝く海辺の街","岸に近いランチャウ島"]},"zh":{"name":"门炉海滩","summary":"乂安数一数二的繁华海滩，沙白水清，更有闻名的「跳虾」（活墨鱼）特产。","story":"门炉是乂安的旅游明珠，绵软的白沙滩延伸十余公里，环抱着海风浩荡的碧海。清晨，渔民满载而归，带回令食客痴迷的鲜活「跳墨鱼」。游客可划船前往兰洲岛，远眺渔岛，或在夕阳下漫步于海风习习的滨海大道。入夜后，美食街与广场又灯火璀璨，呈现出一个既诗意又热闹的门炉，无愧于中部最受欢迎夏日胜地之名。","facts":["海滩长逾10公里，白沙细腻、海水清澈。","门炉「跳墨鱼」是闻名全国的特产。","兰洲岛紧邻海岸，退潮时与陆相连。","自1994年起被规划为滨海旅游城市。"],"travelTips":["清晨在渔港品尝刚捕的清蒸「跳墨鱼」。","夏季周末客流极大，请提前订房。"],"bestTime":"5月至8月","visitDuration":"1至2天","ticket":"免费","openingHours":"全天","galleryCaptions":["清晨绿树成荫的滨海大道","夕阳下灯火璀璨的海滨小城","紧邻海岸的兰洲岛"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('vuon-quoc-gia-pu-mat', 'vuon-quoc-gia-pu-mat', 'nghe-an', 'Vườn quốc gia Pù Mát', 'Pu Mat National Park', 'park', 104.8833, 18.9667, 'Khu rừng nguyên sinh rộng lớn miền Tây Nghệ An với thác Khe Kèm hùng vĩ và hệ sinh thái đa dạng bậc nhất.', 'Trải dài trên dãy Trường Sơn hùng vĩ, Vườn quốc gia Pù Mát là kho báu xanh của miền Tây xứ Nghệ với hơn chín mươi nghìn hecta rừng nguyên sinh. Nơi đây là mái nhà của sao la quý hiếm, voi rừng, vượn đen và vô vàn loài thực vật cổ thụ. Du khách có thể men theo dòng sông Giăng trong vắt bằng thuyền, đắm mình dưới thác Khe Kèm trắng xóa đổ từ độ cao hơn trăm mét, hay ghé thăm bản người Đan Lai sống biệt lập giữa đại ngàn. Tiếng chim rừng, hương cây cỏ và làn nước mát lạnh nơi đây mang đến trải nghiệm hoang sơ, thanh tịnh hiếm có cho những ai yêu thiên nhiên.', '["Diện tích vùng lõi hơn 94.000 hecta rừng nguyên sinh.","Là nơi cư trú của sao la, loài thú quý hiếm bậc nhất thế giới.","Thác Khe Kèm cao hơn 100m, được ví như nàng tiên giữa rừng.","Thuộc Khu dự trữ sinh quyển miền Tây Nghệ An của UNESCO."]', '["Đi cùng hướng dẫn viên bản địa khi vào sâu trong rừng.","Mang theo áo mưa và giày leo núi cho hành trình khám phá."]', 'Tháng 9 đến tháng 12', '1 - 2 ngày', '50.000đ', '07:00 - 17:00', '["hidden-gem","verified","ai-recommended"]', '["nature","mountain","photography"]', '[{"seed":"pu-mat-thac-khe-kem","caption":"Nhà sàn mái lá nép bên đại ngàn xanh thẳm","ratio":"16/9"},{"seed":"pu-mat-rung-nguyen-sinh","caption":"Rừng nguyên sinh đại ngàn","ratio":"4/3"},{"seed":"pu-mat-song-giang","caption":"Dòng sông Giăng trong vắt","ratio":"1/1"}]', '["khu-di-tich-kim-lien"]', 0, '{"en":{"name":"Pu Mat National Park","summary":"A vast primeval forest in western Nghe An with the majestic Khe Kem Waterfall and one of the country''s most diverse ecosystems.","story":"Spreading across the mighty Truong Son Range, Pu Mat National Park is the green treasure of western Nghe An, with more than ninety thousand hectares of primeval forest. It is home to the rare saola, wild elephants, black gibbons and countless ancient plant species. Visitors can follow the crystal-clear Giang River by boat, bathe beneath the white cascade of Khe Kem Waterfall plunging from over a hundred meters, or visit the Dan Lai people who live in isolation deep in the wilderness. The birdsong, the scent of plants and the cool waters here offer a rare experience of pristine serenity for nature lovers.","facts":["Its core zone spans more than 94,000 hectares of primeval forest.","It is home to the saola, one of the rarest mammals in the world.","Khe Kem Waterfall is over 100m high, likened to a fairy in the forest.","It belongs to UNESCO''s Western Nghe An Biosphere Reserve."],"travelTips":["Go with a local guide when heading deep into the forest.","Bring a raincoat and hiking shoes for the exploration."],"bestTime":"September to December","visitDuration":"1 - 2 days","ticket":"50,000 VND","openingHours":"07:00 - 17:00","galleryCaptions":["A leaf-roofed stilt house nestled beside the deep green wilderness","The vast primeval forest","The crystal-clear Giang River"]},"ko":{"name":"푸맛 국립공원","summary":"웅장한 케켐 폭포와 손꼽히게 다양한 생태계를 지닌, 응에안 서부의 광대한 원시림입니다.","story":"웅장한 쯔엉선 산맥에 걸쳐 펼쳐진 푸맛 국립공원은 9만 헥타르가 넘는 원시림을 지닌 응에안 서부의 푸른 보고입니다. 희귀한 사올라, 야생 코끼리, 검은긴팔원숭이와 수많은 고목이 깃든 보금자리입니다. 방문객은 맑디맑은 장강을 배로 거슬러 오르고, 100m가 넘는 높이에서 쏟아지는 케켐 폭포의 새하얀 물줄기 아래에 몸을 담그며, 깊은 숲속에 고립되어 사는 단라이족을 찾아갈 수 있습니다. 새소리와 풀 향기, 시원한 물은 자연을 사랑하는 이에게 보기 드문 원시의 고요한 경험을 선사합니다.","facts":["핵심 구역은 9만 4천 헥타르가 넘는 원시림에 이릅니다.","세계에서 가장 희귀한 포유류 중 하나인 사올라의 서식지입니다.","케켐 폭포는 100m가 넘으며 숲속의 선녀에 비유됩니다.","유네스코 응에안 서부 생물권 보전지역에 속합니다."],"travelTips":["숲 깊숙이 들어갈 때는 현지 가이드와 동행하세요.","탐험 여정을 위해 우비와 등산화를 챙기세요."],"bestTime":"9월부터 12월까지","visitDuration":"1~2일","ticket":"50,000동","openingHours":"07:00 - 17:00","galleryCaptions":["짙푸른 숲 곁에 자리한 잎 지붕 고상가옥","광대한 원시림","맑디맑은 장강"]},"ja":{"name":"プーマット国立公園","summary":"雄大なケケム滝と屈指の多様な生態系を擁する、ゲアン西部の広大な原生林です。","story":"雄大なチュオンソン山脈にまたがって広がるプーマット国立公園は、9万ヘクタールを超える原生林を擁するゲアン西部の緑の宝庫です。希少なサオラ、野生のゾウ、クロテナガザル、そして数えきれない古木の住処です。訪れる人は澄み切ったザン川をボートでたどり、100メートル超の高さから流れ落ちるケケム滝の真っ白な水しぶきに身を浸し、深い森の奥に孤立して暮らすダンライ族を訪ねられます。鳥の声、草木の香り、冷たい水が、自然を愛する人に、稀有な原始の静けさの体験をもたらします。","facts":["中核地域は9万4千ヘクタールを超える原生林に及びます。","世界で最も希少な哺乳類のひとつ、サオラの生息地です。","ケケム滝は高さ100m超で、森の妖精にたとえられます。","ユネスコのゲアン西部生物圏保護区に属します。"],"travelTips":["森の奥へ入る際は地元のガイドと同行しましょう。","探検の旅にはレインコートと登山靴を持参しましょう。"],"bestTime":"9月から12月まで","visitDuration":"1〜2日","ticket":"50,000ドン","openingHours":"07:00 - 17:00","galleryCaptions":["深い緑の原野に寄り添う葉葺きの高床式の家","広大な原生林","澄み切ったザン川"]},"zh":{"name":"蒲茫国家公园","summary":"乂安西部辽阔的原始森林，拥有雄伟的溪槛瀑布与数一数二的多样生态。","story":"横亘于雄伟的长山山脉之上，蒲茫国家公园是乂安西部的绿色宝库，拥有逾九万公顷的原始森林。这里是珍稀中南大羚、野象、黑长臂猿及无数古老植物的家园。游客可乘船沿清澈的㵢江而上，浸身于自百余米高处倾泻而下的溪槛瀑布的雪白水花中，或走访世代隐居于深林之中的丹莱人。鸟鸣、草木清香与清凉溪水，为热爱自然者带来难得的原始与宁静体验。","facts":["核心区逾9.4万公顷原始森林。","是世界上最珍稀哺乳动物之一中南大羚的栖息地。","溪槛瀑布高逾100米，被誉为林中仙子。","属联合国教科文组织乂安西部生物圈保护区。"],"travelTips":["深入森林时请与当地向导同行。","探险行程请携带雨衣与登山鞋。"],"bestTime":"9月至12月","visitDuration":"1至2天","ticket":"50,000越南盾","openingHours":"07:00 - 17:00","galleryCaptions":["依偎在苍翠林海旁的叶顶高脚屋","辽阔的原始森林","清澈的㵢江"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('chua-huong-tich', 'chua-huong-tich', 'ha-tinh', 'Chùa Hương Tích', 'Huong Tich Pagoda', 'temple', 105.7197, 18.3539, 'Ngôi chùa cổ linh thiêng trên đỉnh Hồng Lĩnh, được mệnh danh Hoan Châu đệ nhất danh lam của xứ Nghệ Tĩnh.', 'Tọa lạc trên lưng chừng đỉnh Hương Tích thuộc dãy Hồng Lĩnh, ngôi chùa cổ này gắn liền với truyền thuyết về công chúa Diệu Thiện tu hành đắc đạo thành Phật Bà Quan Âm. Được dựng từ thời nhà Trần, chùa ẩn mình giữa rừng cây cổ thụ, mây trắng vờn quanh, mang vẻ u tịch và linh thiêng. Hành trình lên chùa đưa du khách qua suối Hương Tuyền róc rách, am Thánh Mẫu và những bậc đá rêu phong. Từ trên cao nhìn xuống, cả vùng quê Hà Tĩnh hiện ra trùng điệp xanh ngát. Mỗi độ xuân về, lễ hội chùa Hương Tích lại thu hút hàng vạn Phật tử và du khách hành hương.', '["Được xây dựng từ thời nhà Trần, thế kỷ 13.","Gắn với truyền thuyết công chúa Diệu Thiện hóa Phật Bà.","Mệnh danh là Hoan Châu đệ nhất danh lam.","Lễ hội chính diễn ra vào ngày 18 tháng 2 âm lịch."]', '["Đi cáp treo nếu ngại leo bộ đoạn dốc lên chùa.","Tránh ngày khai hội nếu không thích cảnh đông đúc chen lấn."]', 'Tháng 1 đến tháng 3 âm lịch', 'Nửa ngày', '30.000đ', '06:00 - 18:00', '["festival","verified","popular"]', '["temple","culture","history"]', '[{"seed":"huong-tich-chua-co","caption":"Chùa cổ giữa rừng Hồng Lĩnh","ratio":"16/9"},{"seed":"huong-tich-bac-da","caption":"Bậc đá rêu phong lên chùa","ratio":"4/3"},{"seed":"huong-tich-may-trang","caption":"Bậc đá rêu phong khuất trong sương mờ","ratio":"1/1"}]', '["bien-thien-cam"]', 0, '{"en":{"name":"Huong Tich Pagoda","summary":"An ancient, sacred pagoda atop the Hong Linh Range, hailed as the foremost scenic spot of Hoan Chau in the Nghe Tinh region.","story":"Set on the slopes of Huong Tich Peak in the Hong Linh Range, this ancient pagoda is tied to the legend of Princess Dieu Thien, who attained enlightenment to become the Bodhisattva Avalokitesvara. Built during the Tran Dynasty, the pagoda hides among ancient forest trees, white clouds drifting around it, lending an air of secluded sanctity. The journey up takes visitors past the babbling Huong Tuyen Stream, the Holy Mother shrine and moss-covered stone steps. From the heights, the Ha Tinh countryside unfolds in layers of lush green. Each spring, the Huong Tich Pagoda Festival draws tens of thousands of Buddhists and pilgrims.","facts":["Built during the Tran Dynasty in the 13th century.","Tied to the legend of Princess Dieu Thien becoming the Bodhisattva.","Hailed as the foremost scenic spot of Hoan Chau.","The main festival takes place on the 18th day of the second lunar month."],"travelTips":["Take the cable car if you prefer not to climb the steep stretch to the pagoda.","Avoid the festival opening day if you dislike crowds and jostling."],"bestTime":"First to third lunar month","visitDuration":"Half a day","ticket":"30,000 VND","openingHours":"06:00 - 18:00","galleryCaptions":["The ancient pagoda amid the Hong Linh forest","Moss-covered stone steps up to the pagoda","Moss-covered stone steps fading into the mist"]},"ko":{"name":"흐엉띡 사원","summary":"홍린 산맥 정상의 신성한 고찰로, 응에띤 지방에서 ''환쩌우 제일의 명승''으로 불립니다.","story":"홍린 산맥 흐엉띡 봉우리 중턱에 자리한 이 고찰은 수행 끝에 깨달음을 얻어 관세음보살이 된 지에우티엔 공주의 전설과 얽혀 있습니다. 쩐 왕조 때 지어진 사원은 고목 숲 사이에 숨어 흰 구름이 감돌며 그윽하고 신성한 정취를 풍깁니다. 사원으로 오르는 길은 졸졸 흐르는 흐엉뚜옌 계곡과 성모암, 이끼 낀 돌계단을 지납니다. 높은 곳에서 내려다보면 하띤의 시골이 겹겹이 푸르게 펼쳐집니다. 봄마다 흐엉띡 사원 축제는 수만 명의 불자와 순례객을 불러 모읍니다.","facts":["13세기 쩐 왕조 때 지어졌습니다.","지에우티엔 공주가 보살이 된 전설과 얽혀 있습니다.","''환쩌우 제일의 명승''으로 불립니다.","주요 축제는 음력 2월 18일에 열립니다."],"travelTips":["사원까지 가파른 구간을 걷기 부담스러우면 케이블카를 이용하세요.","붐비는 인파를 좋아하지 않으면 개막일은 피하세요."],"bestTime":"음력 1월부터 3월까지","visitDuration":"반나절","ticket":"30,000동","openingHours":"06:00 - 18:00","galleryCaptions":["홍린 숲속의 고찰","사원으로 오르는 이끼 낀 돌계단","안개 속에 가린 이끼 낀 돌계단"]},"ja":{"name":"フオンティック寺","summary":"ホンリン山脈の頂に立つ神聖な古刹。ゲティン地方で「ホアンチャウ随一の名勝」と称えられます。","story":"ホンリン山脈のフオンティック峰の中腹に建つこの古刹は、修行の末に悟りを開き観音菩薩となったジエウティエン姫の伝説と結びついています。陳朝の時代に建てられた寺は古木の森に隠れ、白い雲がたなびき、幽玄で神聖な趣をたたえます。寺への道のりは、せせらぎのフオントゥエン渓流、聖母庵、苔むした石段を通っていきます。高みから見下ろせば、ハティンの田園が幾重にも緑に広がります。春が来るたび、フオンティック寺の祭りは数万の仏教徒と巡礼者を引き寄せます。","facts":["13世紀、陳朝の時代に建てられました。","ジエウティエン姫が菩薩となった伝説と結びついています。","「ホアンチャウ随一の名勝」と称えられます。","主要な祭りは旧暦2月18日に行われます。"],"travelTips":["寺への急な坂を歩くのが負担なら、ケーブルカーを利用しましょう。","混雑が苦手なら開幕日は避けましょう。"],"bestTime":"旧暦1月から3月まで","visitDuration":"半日","ticket":"30,000ドン","openingHours":"06:00 - 18:00","galleryCaptions":["ホンリンの森の中の古刹","寺へ続く苔むした石段","霧にかすむ苔むした石段"]},"zh":{"name":"香迹寺","summary":"鸿岭山巅上的神圣古刹，被誉为乂静地区「驩州第一名胜」。","story":"这座古刹坐落于鸿岭山脉香迹峰半山腰，与妙善公主修行得道、化为观音菩萨的传说紧密相连。寺院建于陈朝，隐于古木林间，白云缭绕，透着幽静与神圣。登寺之路引领游人穿过潺潺的香泉溪、圣母庵与爬满青苔的石阶。从高处俯瞰，河静的乡野层峦叠翠。每逢春日，香迹寺庙会便吸引成千上万的信众与朝圣者。","facts":["建于13世纪陈朝时期。","与妙善公主化为菩萨的传说相连。","被誉为「驩州第一名胜」。","主庙会于农历二月十八举行。"],"travelTips":["若不愿步行登寺的陡坡，可乘缆车。","若不喜人潮拥挤，请避开开庙日。"],"bestTime":"农历正月至三月","visitDuration":"半天","ticket":"30,000越南盾","openingHours":"06:00 - 18:00","galleryCaptions":["鸿岭林间的古刹","登寺的青苔石阶","隐没于薄雾中的青苔石阶"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bien-thien-cam', 'bien-thien-cam', 'ha-tinh', 'Biển Thiên Cầm', 'Thien Cam Beach', 'beach', 106.0356, 18.1306, 'Bãi biển hoang sơ tựa cây đàn trời, nơi sóng và gió hòa thành bản nhạc du dương bên bờ cát mịn Hà Tĩnh.', 'Cái tên Thiên Cầm gợi nhắc tiếng đàn trời, bởi tương truyền vua Hồ Quý Ly khi qua đây đã nghe gió biển và sóng vỗ vào vách núi tạo nên âm thanh tựa khúc nhạc thiêng. Bãi biển trải dài hơn ba cây số với làn cát trắng mịn, nước trong xanh và độ dốc thoải an toàn. Khác với những bãi biển náo nhiệt, Thiên Cầm vẫn giữ nét hoang sơ, bình yên hiếm có. Du khách có thể leo núi Thiên Cầm ngắm toàn cảnh, viếng chùa Cầm Sơn cổ kính, rồi thưởng thức mực một nắng và cá trích nướng thơm lừng. Một điểm dừng chân lý tưởng cho những ai tìm kiếm sự thư thái.', '["Tên gọi nghĩa là đàn trời, gắn với vua Hồ Quý Ly.","Bãi biển dài hơn 3km, cát mịn và sóng êm.","Núi Thiên Cầm có chùa Cầm Sơn cổ kính.","Mực một nắng là đặc sản nổi tiếng của vùng."]', '["Mua mực một nắng làm quà tại các quầy hải sản địa phương.","Leo núi Thiên Cầm buổi chiều để ngắm hoàng hôn trên biển."]', 'Tháng 5 đến tháng 8', '1 ngày', '', 'Cả ngày', '["hidden-gem","new"]', '["beach","nature","food"]', '[{"seed":"thien-cam-bai-bien","caption":"Bãi biển hoang sơ Thiên Cầm","ratio":"16/9"},{"seed":"thien-cam-nui","caption":"Núi Thiên Cầm bên bờ sóng","ratio":"4/3"},{"seed":"thien-cam-muc-mot-nang","caption":"Mực một nắng đặc sản","ratio":"1/1"}]', '["chua-huong-tich","nga-ba-dong-loc"]', 0, '{"en":{"name":"Thien Cam Beach","summary":"A pristine beach like a celestial lute, where waves and wind blend into a melody along Ha Tinh''s fine sands.","story":"The name Thien Cam evokes a celestial lute, for legend says that when King Ho Quy Ly passed by, he heard the sea wind and waves striking the cliffs to create a sound like sacred music. The beach stretches more than three kilometers with fine white sand, clear blue water and a safe, gentle slope. Unlike the bustling beaches, Thien Cam retains a rare pristine peace. Visitors can climb Thien Cam Mountain for panoramic views, pay respects at the ancient Cam Son Pagoda, then savor sun-dried squid and fragrant grilled herring. It is an ideal stop for those seeking relaxation.","facts":["The name means ''celestial lute,'' linked to King Ho Quy Ly.","The beach stretches more than 3km with fine sand and gentle waves.","Thien Cam Mountain holds the ancient Cam Son Pagoda.","Sun-dried squid is the region''s famous specialty."],"travelTips":["Buy sun-dried squid as a gift from the local seafood stalls.","Climb Thien Cam Mountain in the afternoon to watch the sunset over the sea."],"bestTime":"May to August","visitDuration":"1 day","ticket":"Free","openingHours":"All day","galleryCaptions":["The pristine Thien Cam beach","Thien Cam Mountain by the surf","Sun-dried squid, a local specialty"]},"ko":{"name":"티엔껌 해변","summary":"하늘의 거문고 같은 청정 해변으로, 하띤의 고운 모래사장 곁에서 파도와 바람이 선율을 이룹니다.","story":"티엔껌이라는 이름은 하늘의 거문고를 떠올리게 합니다. 전하는 바에 따르면 호꾸이리 왕이 이곳을 지날 때 절벽에 부딪치는 바닷바람과 파도가 신성한 음악 같은 소리를 냈다고 합니다. 해변은 3킬로미터 넘게 펼쳐지며 곱고 흰 모래와 맑고 푸른 물, 안전하고 완만한 경사를 자랑합니다. 번화한 해변들과 달리 티엔껌은 보기 드문 청정함과 평온함을 간직합니다. 방문객은 티엔껌산에 올라 전경을 감상하고, 고풍스러운 껌선 사원을 참배한 뒤 반건조 오징어와 향긋한 청어구이를 맛볼 수 있습니다. 휴식을 찾는 이들에게 이상적인 쉼터입니다.","facts":["이름은 ''하늘의 거문고''를 뜻하며 호꾸이리 왕과 얽혀 있습니다.","해변은 3km 넘게 펼쳐지며 고운 모래와 잔잔한 파도를 자랑합니다.","티엔껌산에는 고풍스러운 껌선 사원이 있습니다.","반건조 오징어는 이 지역의 유명한 별미입니다."],"travelTips":["현지 해산물 가판대에서 반건조 오징어를 선물용으로 사세요.","오후에 티엔껌산에 올라 바다 위 노을을 감상하세요."],"bestTime":"5월부터 8월까지","visitDuration":"1일","ticket":"무료","openingHours":"종일","galleryCaptions":["청정한 티엔껌 해변","파도 곁의 티엔껌산","별미 반건조 오징어"]},"ja":{"name":"ティエンカムビーチ","summary":"天の琴のような手つかずのビーチ。ハティンのきめ細かな砂浜のほとりで、波と風が旋律を奏でます。","story":"ティエンカムという名は天の琴を思わせます。伝えによれば、胡季犛王がここを通った折、崖に打ち寄せる潮風と波が神聖な音楽のような音を奏でたといいます。ビーチは3キロ以上にわたって伸び、きめ細かな白砂、澄んだ青い水、安全でなだらかな傾斜を誇ります。賑やかなビーチとは違い、ティエンカムは稀有な手つかずの静けさを保ちます。訪れる人はティエンカム山に登って全景を眺め、古色蒼然たるカムソン寺に参り、一夜干しのイカと香ばしいニシンの炭火焼きを味わえます。安らぎを求める人にとって理想的な憩いの地です。","facts":["名は「天の琴」を意味し、胡季犛王と結びついています。","ビーチは3km以上にわたり、きめ細かな砂と穏やかな波を誇ります。","ティエンカム山には古色蒼然たるカムソン寺があります。","一夜干しのイカはこの地方の有名な名物です。"],"travelTips":["地元の海産物の屋台で一夜干しのイカを土産に買いましょう。","午後にティエンカム山に登り、海に沈む夕日を眺めましょう。"],"bestTime":"5月から8月まで","visitDuration":"1日","ticket":"無料","openingHours":"終日","galleryCaptions":["手つかずのティエンカムビーチ","波打ち際のティエンカム山","名物の一夜干しイカ"]},"zh":{"name":"天琴海滩","summary":"宛若天琴的原生态海滩，浪与风在河静细沙之畔合奏出悠扬乐章。","story":"天琴之名令人联想到天上的琴音，相传胡季犛王途经此地时，听见海风与浪涛拍打崖壁，奏出如圣乐般的声响。海滩绵延三公里有余，白沙细腻、海水清碧、坡度平缓而安全。与喧闹的海滩不同，天琴保留着难得的原始与宁静。游客可登天琴山饱览全景，参拜古朴的琴山寺，再品尝一夜干鱿鱼与喷香的烤鲱鱼。这里是寻求闲适者的理想驿站。","facts":["「天琴」意为天上的琴，与胡季犛王相连。","海滩长逾3公里，沙质细腻、海浪温和。","天琴山上有古朴的琴山寺。","一夜干鱿鱼是当地的著名特产。"],"travelTips":["在当地海鲜摊买一夜干鱿鱼作伴手礼。","下午登天琴山，欣赏海上落日。"],"bestTime":"5月至8月","visitDuration":"1天","ticket":"免费","openingHours":"全天","galleryCaptions":["原生态的天琴海滩","浪涛畔的天琴山","特产一夜干鱿鱼"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('nga-ba-dong-loc', 'nga-ba-dong-loc', 'ha-tinh', 'Ngã ba Đồng Lộc', 'Dong Loc Junction', 'museum', 105.6042, 18.4878, 'Tọa độ lửa thời chống Mỹ, nơi mười nữ thanh niên xung phong anh dũng hy sinh, trở thành biểu tượng bất tử.', 'Ngã ba Đồng Lộc là nơi máu lửa của tuyến đường Trường Sơn huyền thoại, từng hứng chịu hàng nghìn tấn bom đạn trong những năm chống Mỹ ác liệt. Tại chính nơi đây, ngày 24 tháng 7 năm 1968, mười cô gái thanh niên xung phong tuổi đôi mươi đã ngã xuống khi đang san lấp hố bom, giữ cho mạch máu giao thông không bao giờ ngừng chảy. Khu di tích hôm nay lặng lẽ với mười ngôi mộ trắng, tháp chuông ngân vang và bảo tàng ghi dấu một thời hoa lửa. Đến đây, mỗi người con đất Việt đều cúi đầu xúc động trước sự hy sinh cao cả của những đóa hoa bất tử Đồng Lộc.', '["Là trọng điểm đánh phá trên tuyến đường Trường Sơn.","Mười nữ thanh niên xung phong hy sinh ngày 24/7/1968.","Được xếp hạng Di tích Lịch sử Quốc gia đặc biệt.","Có tháp chuông cao 37m và nhà bia tưởng niệm."]', '["Dâng hương tưởng niệm và giữ thái độ trang nghiêm.","Kết hợp tham quan bảo tàng để hiểu rõ lịch sử nơi đây."]', 'Quanh năm', 'Nửa ngày', '', '07:00 - 17:30', '["verified","popular"]', '["history","culture"]', '[{"seed":"dong-loc-mo-liet-si","caption":"Mười ngôi mộ nữ thanh niên xung phong","ratio":"16/9"},{"seed":"dong-loc-thap-chuong","caption":"Hàng mộ trắng phủ hoa cúc tưởng niệm","ratio":"4/3"},{"seed":"dong-loc-ho-bom","caption":"Dấu tích hố bom năm xưa","ratio":"1/1"}]', '["bien-thien-cam"]', 0, '{"en":{"name":"Dong Loc Junction","summary":"A fiery hotspot of the anti-American war, where ten young volunteer women heroically died, becoming an immortal symbol.","story":"Dong Loc Junction was a blood-and-fire point on the legendary Truong Son Trail, having endured thousands of tons of bombs and shells during the fierce years of the anti-American war. Here, on July 24, 1968, ten young volunteer women in their twenties fell while filling bomb craters, keeping the lifeline of transport flowing without pause. The relic site today lies quiet with ten white graves, a ringing bell tower and a museum marking that age of fire. Coming here, every Vietnamese bows their head, moved before the noble sacrifice of the immortal flowers of Dong Loc.","facts":["It was a key target on the Truong Son Trail.","Ten young volunteer women died on July 24, 1968.","Ranked as a Special National Historical Relic.","It has a 37m-high bell tower and a memorial stele house."],"travelTips":["Offer incense in remembrance and maintain a solemn demeanor.","Combine your visit with the museum to fully understand the site''s history."],"bestTime":"Year-round","visitDuration":"Half a day","ticket":"Free","openingHours":"07:00 - 17:30","galleryCaptions":["The ten graves of the young volunteer women","Rows of white graves covered with memorial chrysanthemums","Traces of the bomb craters of years past"]},"ko":{"name":"동록 삼거리","summary":"항미 전쟁의 불의 격전지로, 열 명의 여성 청년돌격대원이 장렬히 산화해 불멸의 상징이 된 곳입니다.","story":"동록 삼거리는 전설적인 쯔엉선 길의 피와 불의 요충지로, 치열한 항미 전쟁 시기 수천 톤의 폭탄과 포탄을 견뎠습니다. 바로 이곳에서 1968년 7월 24일, 스무 살 안팎의 여성 청년돌격대원 열 명이 폭탄 구덩이를 메우다 산화하며 교통의 생명선을 멈추지 않게 지켰습니다. 오늘날 유적지는 열 기의 하얀 묘와 울려 퍼지는 종탑, 그 불의 시대를 기록한 박물관과 함께 고요히 자리합니다. 이곳에 오면 모든 베트남인이 동록의 불멸의 꽃들이 바친 숭고한 희생 앞에 고개 숙입니다.","facts":["쯔엉선 길의 주요 폭격 요충지였습니다.","1968년 7월 24일 여성 청년돌격대원 열 명이 산화했습니다.","특별 국가 역사 유적으로 지정되었습니다.","37m 높이의 종탑과 기념비각이 있습니다."],"travelTips":["추모 향을 올리고 엄숙한 태도를 지키세요.","박물관 관람을 곁들여 이곳의 역사를 깊이 이해하세요."],"bestTime":"연중","visitDuration":"반나절","ticket":"무료","openingHours":"07:00 - 17:30","galleryCaptions":["여성 청년돌격대원 열 명의 묘","추모 국화로 덮인 하얀 묘 행렬","그 시절 폭탄 구덩이의 흔적"]},"ja":{"name":"ドンロック三叉路","summary":"抗米戦争の激戦地。10人の若き女性青年突撃隊員が勇敢に散り、不滅の象徴となった地です。","story":"ドンロック三叉路は、伝説のチュオンソン街道の血と炎の要衝で、激しい抗米戦争の時代に数千トンの爆弾と砲弾に耐えました。まさにこの地で、1968年7月24日、二十歳前後の10人の女性青年突撃隊員が爆弾の穴を埋めながら散り、交通の生命線を絶えることなく守りました。今日、史跡は10基の白い墓、鳴り響く鐘楼、その炎の時代を刻む博物館とともに静かにたたずみます。ここを訪れると、すべてのベトナムの人が、ドンロックの不滅の花々が捧げた崇高な犠牲の前に頭を垂れます。","facts":["チュオンソン街道の重要な爆撃の要衝でした。","10人の女性青年突撃隊員が1968年7月24日に散りました。","特別国家史跡に指定されています。","高さ37mの鐘楼と記念碑堂があります。"],"travelTips":["追悼の線香を捧げ、厳粛な態度を保ちましょう。","博物館の見学と組み合わせ、この地の歴史を深く理解しましょう。"],"bestTime":"通年","visitDuration":"半日","ticket":"無料","openingHours":"07:00 - 17:30","galleryCaptions":["10人の女性青年突撃隊員の墓","追悼の菊で覆われた白い墓の列","かつての爆弾の穴の跡"]},"zh":{"name":"同禄三岔路","summary":"抗美战争的火线焦点，十位女青年突击队员英勇牺牲于此，化为不朽的象征。","story":"同禄三岔路是传奇长山公路上的血火要冲，在惨烈的抗美岁月中承受了数千吨炸弹炮火。正是在此地，1968年7月24日，十位二十出头的女青年突击队员在填平弹坑时倒下，守护着交通命脉永不中断。如今的遗迹区静默矗立着十座白色坟茔、回荡钟声的钟楼，以及铭记那段烽火岁月的博物馆。来到这里，每一位越南儿女都会在同禄不朽之花崇高的牺牲前低头动容。","facts":["曾是长山公路上的重点轰炸要冲。","十位女青年突击队员于1968年7月24日牺牲。","被列为国家特别历史遗迹。","建有高37米的钟楼与纪念碑亭。"],"travelTips":["敬献香火以志缅怀，保持庄严肃穆。","结合参观博物馆，深入了解此地历史。"],"bestTime":"全年","visitDuration":"半天","ticket":"免费","openingHours":"07:00 - 17:30","galleryCaptions":["十位女青年突击队员之墓","覆满缅怀菊花的白色墓列","昔日弹坑的遗迹"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('thanh-co-quang-tri', 'thanh-co-quang-tri', 'quang-tri', 'Thành cổ Quảng Trị', 'Quang Tri Ancient Citadel', 'museum', 107.1889, 16.7506, 'Chứng tích 81 ngày đêm khốc liệt mùa hè 1972, nơi yên nghỉ của hàng nghìn chiến sĩ giữa lòng đất thiêng.', 'Thành cổ Quảng Trị là biểu tượng bất khuất của lịch sử dân tộc, nơi diễn ra trận chiến 81 ngày đêm rực lửa mùa hè năm 1972. Trên mảnh đất chỉ rộng vài cây số vuông, hàng vạn tấn bom đạn đã trút xuống, và biết bao người con ưu tú đã ngã xuống để giữ từng tấc đất. Người ta nói rằng mỗi nắm đất nơi đây đều thấm máu các anh, nên giữa lòng thành nay chỉ có một đài tưởng niệm hình ngôi mộ tập thể, không bia, không tên. Đến Thành cổ, du khách lặng người thắp nén hương, thả hoa xuống dòng Thạch Hãn, tưởng nhớ những người lính trẻ đã hóa thân thành bất tử.', '["Diễn ra trận chiến 81 ngày đêm năm 1972.","Được xây dựng từ thời vua Gia Long đầu thế kỷ 19.","Đài tưởng niệm trung tâm là ngôi mộ tập thể không tên.","Dòng Thạch Hãn bên cạnh được coi là dòng sông hoa."]', '["Thả hoa đăng xuống sông Thạch Hãn để tưởng niệm các liệt sĩ.","Nên có thuyết minh viên để cảm nhận trọn vẹn câu chuyện lịch sử."]', 'Quanh năm', 'Nửa ngày', '', '07:00 - 17:00', '["verified","popular"]', '["history","culture"]', '[{"seed":"thanh-co-dai-tuong-niem","caption":"Đài tưởng niệm trung tâm","ratio":"16/9"},{"seed":"thanh-co-cong-thanh","caption":"Cổng thành cổ rêu phong","ratio":"4/3"},{"seed":"thanh-co-thach-han","caption":"Lối vào đài tưởng niệm thành cổ rợp bóng cây","ratio":"1/1"}]', '["dia-dao-vinh-moc"]', 1, '{"en":{"name":"Quang Tri Ancient Citadel","summary":"A testament to the fierce 81 days and nights of summer 1972, the resting place of thousands of soldiers in sacred ground.","story":"Quang Tri Ancient Citadel is an indomitable symbol of the nation''s history, the site of the blazing 81-day-and-night battle of summer 1972. On a patch of land only a few square kilometers wide, tens of thousands of tons of bombs and shells rained down, and countless fine sons fell to hold every inch of soil. It is said that every handful of earth here is soaked with their blood, so at the heart of the citadel today stands only a memorial in the form of a collective grave — without stele, without names. At the citadel, visitors fall silent, lighting incense and casting flowers onto the Thach Han River in memory of the young soldiers who became immortal.","facts":["The 81-day-and-night battle took place in 1972.","Built during the reign of King Gia Long in the early 19th century.","The central memorial is a nameless collective grave.","The adjacent Thach Han River is regarded as a river of flowers."],"travelTips":["Float flower lanterns on the Thach Han River in memory of the fallen.","Have a guide to fully grasp the historical story."],"bestTime":"Year-round","visitDuration":"Half a day","ticket":"Free","openingHours":"07:00 - 17:00","galleryCaptions":["The central memorial","The moss-covered gate of the ancient citadel","The tree-shaded entrance to the citadel memorial"]},"ko":{"name":"꽝찌 고성","summary":"1972년 여름 81일 밤낮의 치열함을 증언하는 곳으로, 신성한 땅속에 수천 전사가 잠든 안식처입니다.","story":"꽝찌 고성은 1972년 여름 81일 밤낮의 불타는 전투가 벌어진, 민족 역사의 불굴의 상징입니다. 몇 제곱킬로미터에 불과한 땅에 수만 톤의 폭탄과 포탄이 쏟아졌고, 수많은 우수한 자식들이 한 뼘의 흙을 지키려 산화했습니다. 이곳의 흙 한 줌 한 줌에 그들의 피가 스몄다고 하여, 지금 성 한복판에는 비석도 이름도 없는 집단 묘 형태의 위령비만 서 있습니다. 고성에 오면 방문객은 말을 잃고 향을 올리며 타익한강에 꽃을 띄워, 불멸로 화한 젊은 병사들을 추모합니다.","facts":["1972년 81일 밤낮의 전투가 벌어졌습니다.","19세기 초 자롱 왕 때 지어졌습니다.","중앙 위령비는 이름 없는 집단 묘입니다.","곁을 흐르는 타익한강은 꽃의 강으로 여겨집니다."],"travelTips":["타익한강에 유등을 띄워 열사들을 추모하세요.","역사의 이야기를 온전히 느끼려면 해설사를 동반하세요."],"bestTime":"연중","visitDuration":"반나절","ticket":"무료","openingHours":"07:00 - 17:00","galleryCaptions":["중앙 위령비","이끼 낀 고성 성문","나무 그늘 우거진 고성 위령비 입구"]},"ja":{"name":"クアンチ古城","summary":"1972年夏の壮絶な81日間の証。数千の兵士が神聖な大地に眠る安息の地です。","story":"クアンチ古城は、1972年夏の燃え盛る81昼夜の戦いが繰り広げられた、民族の不屈の象徴です。わずか数平方キロメートルの土地に数万トンの爆弾と砲弾が降り注ぎ、数えきれない優れた息子たちが一寸の土を守るために散りました。ここの土ひと握りごとに彼らの血が染みこんでいるといわれ、今、城の中心には碑も名もない集団墓の形をした慰霊碑だけが立っています。古城を訪れると、人は言葉を失い、線香を捧げ、タックハン川に花を流して、不滅となった若き兵士たちを偲びます。","facts":["1972年に81昼夜の戦いが繰り広げられました。","19世紀初頭、嘉隆（ザロン）王の時代に築かれました。","中央の慰霊碑は名のない集団墓です。","そばを流れるタックハン川は花の川とみなされています。"],"travelTips":["タックハン川に灯籠を流して烈士たちを偲びましょう。","歴史の物語を余すことなく感じるにはガイドの解説を。"],"bestTime":"通年","visitDuration":"半日","ticket":"無料","openingHours":"07:00 - 17:00","galleryCaptions":["中央の慰霊碑","苔むした古城の城門","木陰が茂る古城の慰霊碑への入口"]},"zh":{"name":"广治古城","summary":"1972年夏天八十一昼夜惨烈战事的见证，数千将士长眠于这片圣土之中。","story":"广治古城是民族历史不屈的象征，1972年夏天八十一昼夜的烈火之战在此打响。在仅有数平方公里的土地上，数万吨炸弹炮火倾泻而下，无数优秀儿女为守住每一寸土地而倒下。人们说，这里的每一捧泥土都浸透了他们的鲜血，因此如今城中央只立着一座状如集体墓的纪念碑，无碑无名。来到古城，游人无不默然伫立，敬上一炷香，向石汉河中撒下鲜花，缅怀那些化为不朽的年轻战士。","facts":["1972年八十一昼夜之战在此打响。","建于19世纪初嘉隆王时期。","中央纪念碑为无名集体墓。","旁侧的石汉河被视为鲜花之河。"],"travelTips":["向石汉河放河灯，缅怀烈士。","建议聘请讲解员，以完整感受这段历史。"],"bestTime":"全年","visitDuration":"半天","ticket":"免费","openingHours":"07:00 - 17:00","galleryCaptions":["中央纪念碑","爬满青苔的古城城门","绿荫掩映的古城纪念碑入口"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dia-dao-vinh-moc', 'dia-dao-vinh-moc', 'quang-tri', 'Địa đạo Vịnh Mốc', 'Vinh Moc Tunnels', 'museum', 107.025, 17.0244, 'Làng hầm kỳ vĩ trong lòng đất, nơi cả cộng đồng kiên cường sống và chiến đấu suốt những năm mưa bom bão đạn.', 'Địa đạo Vịnh Mốc là kỳ tích của ý chí con người Quảng Trị, một ngôi làng nằm sâu trong lòng đất đỏ bazan vùng Vĩnh Linh. Suốt những năm bom đạn ác liệt, người dân nơi đây đã đào hệ thống hầm dài gần hai cây số với ba tầng sâu, đủ chỗ cho hàng trăm người sinh sống. Trong lòng đất ấy có giếng nước, nhà hộ sinh nơi mười bảy em bé chào đời, hội trường, trạm xá và cả những căn hộ gia đình. Bước vào địa đạo mát lạnh, du khách không khỏi cảm phục sức sống mãnh liệt và tinh thần bất khuất của một dân tộc, biến lòng đất thành pháo đài giữ làng giữ nước.', '["Hệ thống hầm dài gần 2km, chia làm ba tầng sâu.","Có 17 em bé được sinh ra ngay trong lòng địa đạo.","Đào trong điều kiện bom đạn từ năm 1965 đến 1967.","Là Di tích Lịch sử Quốc gia đặc biệt tiêu biểu."]', '["Mang theo đèn pin và mặc đồ gọn nhẹ khi xuống hầm.","Đi cùng hướng dẫn viên để nghe câu chuyện về làng hầm."]', 'Tháng 2 đến tháng 8', 'Nửa ngày', '40.000đ', '07:00 - 17:00', '["verified","ai-recommended","popular"]', '["history","culture"]', '[{"seed":"vinh-moc-cua-ham","caption":"Cửa hầm địa đạo Vịnh Mốc","ratio":"16/9"},{"seed":"vinh-moc-long-dat","caption":"Đường hầm trong lòng đất","ratio":"4/3"},{"seed":"vinh-moc-nha-ho-sinh","caption":"Căn nhà hộ sinh dưới hầm","ratio":"1/1"}]', '["thanh-co-quang-tri","dao-con-co"]', 0, '{"en":{"name":"Vinh Moc Tunnels","summary":"A magnificent tunnel village underground, where a whole community resiliently lived and fought through years of relentless bombing.","story":"The Vinh Moc Tunnels are a feat of the will of the people of Quang Tri, a village set deep within the red basalt earth of the Vinh Linh area. Through the fierce years of bombing, the people here dug a tunnel system nearly two kilometers long across three deep levels, enough to house hundreds. Within this earth were wells, a maternity room where seventeen babies were born, a meeting hall, a clinic and even family quarters. Stepping into the cool tunnels, visitors cannot help but admire the fierce vitality and indomitable spirit of a people who turned the earth into a fortress to guard their village and their country.","facts":["The tunnel system is nearly 2km long, divided into three deep levels.","Seventeen babies were born within the tunnels.","Dug under bombing conditions from 1965 to 1967.","An outstanding Special National Historical Relic."],"travelTips":["Bring a flashlight and wear light, compact clothing when descending.","Go with a guide to hear the story of the tunnel village."],"bestTime":"February to August","visitDuration":"Half a day","ticket":"40,000 VND","openingHours":"07:00 - 17:00","galleryCaptions":["The entrance to the Vinh Moc Tunnels","A tunnel passage underground","The maternity room beneath the tunnels"]},"ko":{"name":"빈목 땅굴","summary":"땅속에 자리한 웅장한 땅굴 마을로, 한 공동체가 끝없는 폭격의 세월 동안 굳세게 살고 싸운 곳입니다.","story":"빈목 땅굴은 빈린 지역의 붉은 현무암 땅속 깊이 자리한 마을로, 꽝찌 사람들의 의지가 빚은 기적입니다. 치열한 폭격의 세월 내내 이곳 주민들은 세 개 층 깊이로 거의 2킬로미터에 이르는 땅굴 시스템을 파내어 수백 명이 살 수 있게 했습니다. 그 땅속에는 우물과 열일곱 아기가 태어난 산실, 회의장, 진료소, 심지어 가족 거처까지 있었습니다. 시원한 땅굴로 들어서면 방문객은 땅속을 마을과 나라를 지키는 요새로 바꾼 한 민족의 강렬한 생명력과 불굴의 정신에 감탄하지 않을 수 없습니다.","facts":["땅굴 시스템은 세 개 층 깊이로 거의 2km에 이릅니다.","땅굴 안에서 열일곱 명의 아기가 태어났습니다.","1965년부터 1967년까지 폭격 속에서 파냈습니다.","대표적인 특별 국가 역사 유적입니다."],"travelTips":["땅굴로 내려갈 때는 손전등을 챙기고 가벼운 옷을 입으세요.","땅굴 마을의 이야기를 들으려면 가이드와 동행하세요."],"bestTime":"2월부터 8월까지","visitDuration":"반나절","ticket":"40,000동","openingHours":"07:00 - 17:00","galleryCaptions":["빈목 땅굴 입구","땅속의 땅굴 통로","땅굴 아래의 산실"]},"ja":{"name":"ヴィンモック地下トンネル","summary":"地中に広がる壮大なトンネルの村。ひとつの共同体が絶え間ない爆撃の歳月を、たくましく生き抜き戦った地です。","story":"ヴィンモック地下トンネルは、ヴィンリン地域の赤い玄武岩の地中深くに築かれた村で、クアンチの人々の意志が生んだ奇跡です。激しい爆撃の歳月の間、ここの人々は三層の深さで2キロ近くに及ぶトンネル網を掘り、数百人が暮らせるようにしました。その地中には井戸、17人の赤ん坊が生まれた産室、集会場、診療所、そして家族用の住居までありました。ひんやりとしたトンネルに足を踏み入れると、訪れる人は、地中を村と国を守る要塞に変えた民族の激しい生命力と不屈の精神に感嘆せずにはいられません。","facts":["トンネル網は三層の深さで2km近くに及びます。","トンネル内で17人の赤ん坊が生まれました。","1965年から1967年まで、爆撃の中で掘られました。","代表的な特別国家史跡です。"],"travelTips":["トンネルに下りる際は懐中電灯を持ち、軽装で。","トンネルの村の物語を聞くにはガイドと同行を。"],"bestTime":"2月から8月まで","visitDuration":"半日","ticket":"40,000ドン","openingHours":"07:00 - 17:00","galleryCaptions":["ヴィンモック地下トンネルの入口","地中のトンネルの通路","トンネルの下の産室"]},"zh":{"name":"永麻地道","summary":"地底宏伟的地道村落，整个社群在连绵的炮火岁月中坚韧地生活与战斗。","story":"永麻地道是广治人民意志的奇迹，一座深藏于永灵地区红色玄武岩地底的村落。在炮火惨烈的岁月里，这里的人们挖出近两公里、分三层深的地道系统，足以容纳数百人生活。在那地底之中，有水井、迎来十七个婴儿降生的产房、礼堂、医务站，甚至还有家庭住所。步入清凉的地道，游人无不叹服一个民族顽强的生命力与不屈的精神——他们将地底化为守村卫国的堡垒。","facts":["地道系统近2公里长，分三层深。","有17个婴儿在地道中降生。","于1965年至1967年在炮火中挖成。","是具有代表性的国家特别历史遗迹。"],"travelTips":["下地道时请携带手电、穿轻便衣物。","与向导同行，聆听地道村的故事。"],"bestTime":"2月至8月","visitDuration":"半天","ticket":"40,000越南盾","openingHours":"07:00 - 17:00","galleryCaptions":["永麻地道的洞口","地底的地道通道","地道下的产房"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dao-con-co', 'dao-con-co', 'quang-tri', 'Đảo Cồn Cỏ', 'Con Co Island', 'island', 107.3389, 17.1583, 'Hòn đảo tiền tiêu xanh ngắt giữa biển khơi, kết hợp vẻ đẹp hoang sơ với những trang sử hào hùng giữ đảo.', 'Cồn Cỏ là hòn đảo tiền tiêu thiêng liêng của Tổ quốc, nằm cách đất liền Quảng Trị khoảng ba mươi cây số. Từng là chiến địa anh hùng trong kháng chiến chống Mỹ, đảo nhỏ này đã kiên cường bám trụ giữa muôn trùng bom đạn, đi vào câu hát ngợi ca. Ngày nay, Cồn Cỏ khoác lên mình màu xanh tươi mát của rừng nguyên sinh và làn nước biển trong vắt ôm lấy những rạn san hô rực rỡ. Du khách có thể lặn ngắm san hô, dạo quanh ngọn hải đăng cổ, đạp xe vòng quanh đảo và thưởng thức cua đá, ốc biển tươi ngon. Một viên ngọc hoang sơ đang dần mở cửa đón những ai ưa khám phá.', '["Cách đất liền khoảng 30km, là đảo tiền tiêu của Quảng Trị.","Diện tích chỉ khoảng 2,3 km vuông nhưng giàu sinh thái.","Có rừng nguyên sinh và rạn san hô đa dạng.","Được phong tặng danh hiệu Anh hùng trong kháng chiến."]', '["Đặt tàu cao tốc và lưu trú trước vì dịch vụ trên đảo còn hạn chế.","Mang theo đồ lặn để khám phá rạn san hô quanh đảo."]', 'Tháng 4 đến tháng 7', '1 - 2 ngày', '', 'Cả ngày', '["hidden-gem","new","ai-recommended"]', '["island","nature","beach"]', '[{"seed":"con-co-bien-xanh","caption":"Biển xanh ôm đảo Cồn Cỏ","ratio":"16/9"},{"seed":"con-co-hai-dang","caption":"Ngọn hải đăng cổ trên đảo","ratio":"4/3"},{"seed":"con-co-san-ho","caption":"Rạn san hô rực rỡ","ratio":"1/1"}]', '["dia-dao-vinh-moc"]', 0, '{"en":{"name":"Con Co Island","summary":"A lush frontier island in the open sea, blending pristine beauty with a heroic history of island defense.","story":"Con Co is a sacred frontier island of the homeland, lying about thirty kilometers off the Quang Tri coast. Once a heroic battleground in the anti-American resistance, this small island held its ground amid endless bombs, entering songs of praise. Today, Con Co wears the fresh green of primeval forest, and crystal-clear waters embrace its vivid coral reefs. Visitors can dive to view the coral, stroll around the old lighthouse, cycle around the island and savor fresh stone crab and sea snails. It is a pristine gem gradually opening its doors to those who love discovery.","facts":["About 30km offshore, it is the frontier island of Quang Tri.","Only about 2.3 km² in area, yet rich in ecology.","It has primeval forest and diverse coral reefs.","Awarded the title of Hero during the resistance war."],"travelTips":["Book the speedboat and accommodation in advance, as island services are still limited.","Bring diving gear to explore the coral reefs around the island."],"bestTime":"April to July","visitDuration":"1 - 2 days","ticket":"Free","openingHours":"All day","galleryCaptions":["Blue sea embracing Con Co Island","The old lighthouse on the island","Vivid coral reefs"]},"ko":{"name":"꼰꼬섬","summary":"넓은 바다 한가운데 짙푸른 최전방 섬으로, 청정한 아름다움과 영웅적인 섬 수호의 역사를 함께 지녔습니다.","story":"꼰꼬는 꽝찌 해안에서 약 30킬로미터 떨어진, 조국의 신성한 최전방 섬입니다. 항미 항쟁 때 영웅적인 격전지였던 이 작은 섬은 끝없는 폭탄 속에서도 굳세게 버텨 노래로 칭송받았습니다. 오늘날 꼰꼬는 원시림의 싱그러운 초록을 두르고, 맑디맑은 바닷물이 화려한 산호초를 감쌉니다. 방문객은 잠수로 산호를 감상하고, 오래된 등대 주변을 거닐며, 섬을 자전거로 한 바퀴 돌고 신선한 바위게와 바다 소라를 맛볼 수 있습니다. 탐험을 즐기는 이들에게 서서히 문을 여는 청정한 보석입니다.","facts":["해안에서 약 30km 떨어진 꽝찌의 최전방 섬입니다.","면적은 약 2.3km²에 불과하지만 생태가 풍부합니다.","원시림과 다양한 산호초가 있습니다.","항쟁 시기에 영웅 칭호를 받았습니다."],"travelTips":["섬 내 서비스가 아직 제한적이니 고속선과 숙소를 미리 예약하세요.","섬 주변 산호초를 탐험하려면 잠수 장비를 챙기세요."],"bestTime":"4월부터 7월까지","visitDuration":"1~2일","ticket":"무료","openingHours":"종일","galleryCaptions":["꼰꼬섬을 감싼 푸른 바다","섬 위의 오래된 등대","화려한 산호초"]},"ja":{"name":"コンコー島","summary":"大海原に浮かぶ青々とした最前線の島。手つかずの美しさと、島を守った英雄的な歴史を併せ持ちます。","story":"コンコーは、クアンチの海岸から約30キロ離れた、祖国の神聖な最前線の島です。抗米抗戦では英雄的な戦場だったこの小さな島は、絶え間ない爆弾の中でたくましく踏みとどまり、歌に称えられました。今日、コンコーは原生林のみずみずしい緑をまとい、澄み切った海が色鮮やかなサンゴ礁を抱きます。訪れる人は潜ってサンゴを眺め、古い灯台のまわりを散策し、自転車で島を一周し、新鮮な岩ガニや巻貝を味わえます。探検を好む人へ少しずつ扉を開く、手つかずの宝石です。","facts":["海岸から約30km離れた、クアンチの最前線の島です。","面積は約2.3km²に過ぎませんが、生態系が豊かです。","原生林と多様なサンゴ礁があります。","抗戦時代に英雄の称号を授けられました。"],"travelTips":["島内のサービスはまだ限られているので、高速船と宿は早めに予約を。","島周辺のサンゴ礁を探検するなら潜水用具を持参しましょう。"],"bestTime":"4月から7月まで","visitDuration":"1〜2日","ticket":"無料","openingHours":"終日","galleryCaptions":["コンコー島を抱く青い海","島の上の古い灯台","色鮮やかなサンゴ礁"]},"zh":{"name":"昏果岛","summary":"大海之中苍翠的前哨岛屿，将原始之美与守岛的英雄历史融为一体。","story":"昏果是祖国神圣的前哨岛屿，距广治海岸约三十公里。这座小岛曾是抗美战争中的英雄战场，在连绵炮火中顽强坚守，被传唱入歌。如今，昏果披上原始森林的清新苍翠，清澈的海水环抱着绚丽的珊瑚礁。游客可潜水赏珊瑚，漫步于古老的灯塔周围，骑行环岛，品尝鲜美的石蟹与海螺。这是一颗正向探险者徐徐敞开大门的原始明珠。","facts":["距海岸约30公里，是广治的前哨岛屿。","面积仅约2.3平方公里，生态却十分丰富。","拥有原始森林与多样的珊瑚礁。","在抗战时期被授予英雄称号。"],"travelTips":["岛上服务尚有限，请提前预订快艇与住宿。","携带潜水装备，探索环岛珊瑚礁。"],"bestTime":"4月至7月","visitDuration":"1至2天","ticket":"免费","openingHours":"全天","galleryCaptions":["碧海环抱昏果岛","岛上的古老灯塔","绚丽的珊瑚礁"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('qng-ly-son', 'dao-ly-son', 'quang-ngai', 'Đảo Lý Sơn', 'Ly Son Island', 'island', 109.1167, 15.3833, 'Đảo núi lửa giữa biển khơi, vương quốc tỏi với những bãi đá đen, miệng núi lửa cổ và biển xanh ngắt.', 'Lý Sơn nổi lên giữa biển Đông như một bảo tàng địa chất sống, được kiến tạo từ năm ngọn núi lửa phun trào hàng triệu năm trước. Người dân nơi đây gọi đảo là quê hương của hùng binh Hoàng Sa, nơi mỗi năm tổ chức Lễ Khao lề thế lính tri ân những người con ra giữ biển. Đặt chân lên đỉnh Thới Lới, bạn nhìn thấy ruộng tỏi xanh mướt trải dài trên nền đá bazan, hồ nước ngọt phẳng lặng và cổng Tò Vò trầm mặc soi bóng hoàng hôn. Biển ở đây trong vắt, lặn ngắm san hô tựa lạc vào thủy cung. Lý Sơn vừa hùng vĩ vừa dung dị, níu chân lữ khách.', '["Hình thành từ 5 miệng núi lửa cổ phun trào cách đây khoảng 25-30 triệu năm.","Được mệnh danh là ''Vương quốc tỏi'' với giống tỏi cô đơn nổi tiếng cả nước.","Là nơi tổ chức Lễ Khao lề thế lính Hoàng Sa, di sản văn hóa phi vật thể quốc gia.","Cổng Tò Vò là vòm đá bazan tự nhiên được giới nhiếp ảnh săn đón.","Gồm đảo Lớn và đảo Bé (An Bình), cách đất liền khoảng 15 hải lý."]', '["Đặt vé tàu cao tốc từ cảng Sa Kỳ trước, mùa biển động nên kiểm tra lịch tàu.","Thuê xe máy chạy quanh đảo và mang theo kem chống nắng vì nắng đảo rất gắt."]', 'Tháng 6 đến tháng 9, biển êm và trời trong', '2 ngày 1 đêm', '', 'Cả ngày', '["trending","popular","verified"]', '["island","nature","photography","history"]', '[{"seed":"lyson-thoiloi","caption":"Đỉnh Thới Lới nhìn ra biển","ratio":"16/9"},{"seed":"lyson-tovo","caption":"Cổng Tò Vò lúc hoàng hôn","ratio":"4/3"},{"seed":"lyson-toi","caption":"Ruộng tỏi xanh trên nền đá bazan","ratio":"1/1"}]', '["qng-sa-huynh"]', 1, '{"en":{"name":"Ly Son Island","summary":"A volcanic island in the open sea, a kingdom of garlic with black-rock shores, ancient craters, and deep-blue waters.","story":"Ly Son rises from the East Sea like a living geological museum, formed by five volcanoes that erupted millions of years ago. Locals call the island the homeland of the Hoang Sa flotilla, where each year the Khao Le The Linh ceremony honors the sons who went to guard the seas. Atop Thoi Loi peak, you''ll see emerald garlic fields stretching over basalt rock, a placid freshwater lake, and the solemn To Vo Gate mirrored in the sunset. The sea here is crystal clear, and snorkeling among the coral feels like entering an underwater palace. Ly Son is both majestic and unpretentious, holding travelers in its spell.","facts":["Formed by 5 ancient craters that erupted about 25–30 million years ago.","Dubbed the ''Garlic Kingdom'', famous nationwide for its single-clove garlic.","Host of the Khao Le The Linh Hoang Sa ceremony, a national intangible cultural heritage.","To Vo Gate is a natural basalt arch sought after by photographers.","Comprises Big Island and Little Island (An Binh), about 15 nautical miles from the mainland."],"travelTips":["Book speedboat tickets from Sa Ky port in advance; check the schedule during rough-sea season.","Rent a motorbike to circle the island and bring sunscreen — the island sun is fierce."],"bestTime":"June to September, calm seas and clear skies","visitDuration":"2 days 1 night","ticket":"","openingHours":"All day","galleryCaptions":["Thoi Loi peak overlooking the sea","To Vo Gate at sunset","Green garlic fields on basalt rock"]},"ko":{"name":"리선 섬","summary":"바다 한가운데 화산섬으로, 검은 바위 해안과 고대 분화구, 짙푸른 바다를 품은 마늘의 왕국입니다.","story":"리선은 수백만 년 전 분출한 다섯 화산이 빚어낸 살아 있는 지질 박물관처럼 비엔동 바다 위에 솟아 있습니다. 주민들은 이 섬을 호앙사 수군의 고향이라 부르며, 해마다 바다를 지키러 떠난 아들들을 기리는 카오레테링 의례를 엽니다. 터이러이 봉우리에 오르면 현무암 위로 펼쳐진 푸른 마늘밭, 잔잔한 담수호, 그리고 노을에 비친 또보 관문이 보입니다. 이곳의 바다는 맑디맑아 산호를 보며 스쿠버다이빙을 하면 마치 용궁에 든 듯합니다. 리선은 웅장하면서도 소박해 여행객의 발길을 붙잡습니다.","facts":["약 2,500~3,000만 년 전 분출한 5개 고대 분화구로 형성.","전국적으로 유명한 외쪽마늘로 ''마늘의 왕국''이라 불림.","국가 무형문화유산인 호앙사 카오레테링 의례가 열리는 곳.","또보 관문은 사진작가들이 즐겨 찾는 천연 현무암 아치.","본섬과 작은 섬(안빈)으로 구성, 본토에서 약 15해리."],"travelTips":["사끼항에서 고속선 표를 미리 예매하고, 풍랑철에는 운항 일정을 확인하세요.","오토바이를 빌려 섬을 돌고, 섬 햇볕이 매우 강하니 자외선 차단제를 챙기세요."],"bestTime":"6월~9월, 잔잔한 바다와 맑은 하늘","visitDuration":"1박 2일","ticket":"","openingHours":"종일","galleryCaptions":["바다를 바라보는 터이러이 봉우리","노을 속 또보 관문","현무암 위 푸른 마늘밭"]},"ja":{"name":"リーソン島","summary":"大海原に浮かぶ火山島。黒い岩の海岸、古代の噴火口、深い青の海を抱くニンニクの王国です。","story":"リーソンは、数百万年前に噴火した5つの火山が形作った生きた地質博物館のように、ビエンドン海に浮かびます。島の人々はここをホアンサ水軍の故郷と呼び、毎年、海を守りに旅立った息子たちを称えるカオレー・テーリン儀礼を行います。トイロイ峰に立てば、玄武岩の上に広がる青いニンニク畑、静かな淡水湖、そして夕日に映るトーヴォー門が見えます。ここの海は澄み切り、サンゴを眺めるダイビングはまるで竜宮に迷い込んだようです。リーソンは雄大でありながら素朴で、旅人の足を引き留めます。","facts":["約2,500〜3,000万年前に噴火した5つの古代噴火口で形成。","全国的に有名な一片ニンニクで「ニンニクの王国」と呼ばれる。","国家無形文化遺産であるホアンサ・カオレー・テーリン儀礼が行われる地。","トーヴォー門は写真家に人気の天然玄武岩アーチ。","本島と小島（アンビン）からなり、本土から約15海里。"],"travelTips":["サキー港から高速船の切符を事前に予約し、時化の季節は運航予定を確認しましょう。","バイクを借りて島を巡り、島の日差しは非常に強いので日焼け止めを持参しましょう。"],"bestTime":"6月〜9月、穏やかな海と澄んだ空","visitDuration":"1泊2日","ticket":"","openingHours":"終日","galleryCaptions":["海を望むトイロイ峰","夕日のトーヴォー門","玄武岩の上の青いニンニク畑"]},"zh":{"name":"李山岛","summary":"大海中央的火山岛，是拥有黑岩海岸、古老火山口与湛蓝海水的大蒜王国。","story":"李山岛宛如一座活的地质博物馆，浮现于东海之上，由数百万年前喷发的五座火山塑造而成。岛上居民称这里为黄沙雄兵的故乡，每年举办告例祭兵仪式，缅怀那些出海守疆的儿郎。登上多里峰，你能看到玄武岩上铺展的青翠蒜田、平静的淡水湖，以及映在夕阳中静默的石拱门。这里海水清澈，潜水赏珊瑚仿佛误入龙宫。李山岛既雄伟又质朴，令旅人流连忘返。","facts":["由5座古火山口形成，喷发于约2500至3000万年前。","被誉为「大蒜王国」，独蒜闻名全国。","举办黄沙告例祭兵仪式，为国家级非物质文化遗产。","石拱门是摄影爱好者追捧的天然玄武岩拱门。","由大岛与小岛（安平岛）组成，距大陆约15海里。"],"travelTips":["提前订好沙奇港的高速船票，风浪季节请查看船期。","租摩托车环岛，岛上日照强烈，请携带防晒霜。"],"bestTime":"6月至9月，海面平静、天空晴朗","visitDuration":"2天1夜","ticket":"","openingHours":"全天","galleryCaptions":["眺望大海的多里峰","夕阳下的石拱门","玄武岩上的青翠蒜田"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('qng-sa-huynh', 'bien-sa-huynh', 'quang-ngai', 'Biển Sa Huỳnh', 'Sa Huynh Beach', 'beach', 108.9667, 14.6667, 'Bãi biển cát vàng óng ả nơi cực nam Quảng Ngãi, gắn với nền văn hóa Sa Huỳnh cổ và những đồng muối trắng.', 'Sa Huỳnh đẹp một vẻ đẹp hiền hòa với bờ cát vàng ánh lên dưới nắng, ôm lấy làn nước biển xanh biếc và những rặng dừa nghiêng mình trong gió. Vùng đất này còn là cái nôi của nền văn hóa Sa Huỳnh rực rỡ cách đây hơn hai ngàn năm, để lại những mộ chum và đồ trang sức tinh xảo khiến giới khảo cổ say mê. Bên cạnh biển là những cánh đồng muối trắng phau, nơi diêm dân cần mẫn cào muối dưới nắng trưa, tạo nên bức tranh lao động mộc mạc. Buổi sớm, làng chài thức giấc với thuyền thúng rộn ràng cập bến, cá tươi đầy khoang. Sa Huỳnh là điểm dừng bình yên cho ai muốn trốn ồn ào phố thị.', '["Là nơi phát hiện nền văn hóa Sa Huỳnh có niên đại hơn 2.000 năm.","Đồng muối Sa Huỳnh là một trong những vựa muối lâu đời của miền Trung.","Tên gọi xuất phát từ ''Sa Hoàng'' nghĩa là bãi cát vàng.","Nằm ngay quốc lộ 1A, giáp ranh tỉnh Bình Định."]', '["Ghé chợ cá làng chài buổi sáng sớm để mua hải sản tươi giá tốt.","Kết hợp tham quan bảo tàng và di chỉ văn hóa Sa Huỳnh gần đó."]', 'Tháng 4 đến tháng 8', 'Nửa ngày', '', 'Cả ngày', '["hidden-gem","verified"]', '["beach","history","nature","culture"]', '[{"seed":"sahuynh-bai","caption":"Bãi cát vàng cong hình lưỡi liềm","ratio":"16/9"},{"seed":"sahuynh-muoi","caption":"Bãi cát vàng cong dài ôm vịnh biển lặng","ratio":"4/3"},{"seed":"sahuynh-thuyen","caption":"Cung đường ven biển uốn lượn bên bờ cát","ratio":"1/1"}]', '["qng-ly-son"]', 0, '{"en":{"name":"Sa Huynh Beach","summary":"A glowing golden-sand beach at the southern tip of Quang Ngai, tied to the ancient Sa Huynh culture and white salt fields.","story":"Sa Huynh has a gentle beauty, its golden shore glowing in the sun, embracing turquoise waters and rows of coconut palms swaying in the wind. This land was also the cradle of the brilliant Sa Huynh culture more than two thousand years ago, leaving behind jar burials and exquisite jewelry that captivate archaeologists. Beside the sea lie fields of pure white salt, where salt-makers diligently rake the salt under the noon sun, painting a picture of humble labor. At dawn, the fishing village wakes with round basket boats bustling ashore, holds full of fresh fish. Sa Huynh is a peaceful stop for anyone seeking to escape the noise of the city.","facts":["Where the Sa Huynh culture, dating back over 2,000 years, was discovered.","The Sa Huynh salt fields are among central Vietnam''s oldest salt grounds.","The name comes from ''Sa Hoang'', meaning golden sand.","Located right on National Highway 1A, bordering Binh Dinh province."],"travelTips":["Visit the fishing village fish market early in the morning for fresh seafood at good prices.","Combine your visit with the nearby Sa Huynh culture museum and archaeological site."],"bestTime":"April to August","visitDuration":"Half a day","ticket":"","openingHours":"All day","galleryCaptions":["A crescent-shaped golden-sand beach","A long curving golden shore embracing a calm bay","A winding coastal road along the sandy shore"]},"ko":{"name":"사후인 해변","summary":"꽝응아이 최남단의 황금빛 모래해변으로, 고대 사후인 문화와 새하얀 소금밭이 깃들어 있습니다.","story":"사후인은 햇살에 반짝이는 황금빛 모래가 짙푸른 바닷물과 바람에 흔들리는 야자수를 감싸 안은 온화한 아름다움을 지녔습니다. 이 땅은 또한 이천여 년 전 찬란했던 사후인 문화의 요람으로, 고고학자들을 매료시킨 옹관묘와 정교한 장신구를 남겼습니다. 바닷가에는 새하얀 소금밭이 펼쳐져 한낮의 햇볕 아래 부지런히 소금을 긁는 염전 일꾼들이 소박한 노동의 풍경을 그려냅니다. 새벽이면 어촌이 깨어나 대바구니배가 분주히 포구에 닿고 배 안에는 싱싱한 물고기가 가득합니다. 사후인은 도시의 소란을 벗어나려는 이들에게 평화로운 쉼터입니다.","facts":["2,000년이 넘는 사후인 문화가 발견된 곳.","사후인 소금밭은 중부에서 가장 오래된 소금산지 중 하나.","지명은 ''황금 모래밭''을 뜻하는 ''사호앙''에서 유래.","국도 1A 바로 옆, 빈딘성과 접경."],"travelTips":["이른 아침 어촌 생선시장에 들러 싱싱한 해산물을 저렴하게 구입하세요.","인근 사후인 문화 박물관과 유적지 관람을 함께 즐기세요."],"bestTime":"4월~8월","visitDuration":"반나절","ticket":"","openingHours":"종일","galleryCaptions":["초승달 모양으로 굽은 황금빛 모래해변","잔잔한 만을 감싸 안은 길게 굽은 황금빛 해변","모래해변을 따라 굽이치는 해안 도로"]},"ja":{"name":"サーフィンビーチ","summary":"クアンガイ最南端の黄金の砂浜。古代サーフイン文化と真っ白な塩田が息づきます。","story":"サーフインは、日差しに輝く黄金の砂が、青く澄んだ海水と風になびく椰子並木を抱く穏やかな美しさを湛えています。この地はまた、二千年余り前に栄えたサーフイン文化の揺り籠でもあり、考古学者を魅了する甕棺墓と精巧な装身具を残しました。海辺には真っ白な塩田が広がり、真昼の日差しの下で塩を掻く塩田の人々が素朴な労働の風景を描き出します。夜明けには漁村が目覚め、丸い籠舟が賑やかに港に着き、船倉には新鮮な魚が満ちます。サーフインは、街の喧騒を逃れたい人々のための穏やかな憩いの地です。","facts":["2,000年を超えるサーフイン文化が発見された地。","サーフインの塩田は中部で最も古い塩産地の一つ。","地名は「黄金の砂浜」を意味する「サーホアン」に由来。","国道1A沿い、ビンディン省と接する。"],"travelTips":["早朝に漁村の魚市場に立ち寄り、新鮮な海の幸を手頃な値段で買いましょう。","近くのサーフイン文化博物館と遺跡の見学も合わせて楽しみましょう。"],"bestTime":"4月〜8月","visitDuration":"半日","ticket":"","openingHours":"終日","galleryCaptions":["三日月形に弧を描く黄金の砂浜","穏やかな湾を抱く長く弧を描く黄金の浜","砂浜沿いにうねる海岸道路"]},"zh":{"name":"沙黄海滩","summary":"广义最南端金光闪闪的沙滩，与古老的沙黄文化和雪白盐田相连。","story":"沙黄有一种温婉之美，金色的沙岸在阳光下闪烁，环抱着碧蓝的海水与随风摇曳的椰树。这片土地还是两千多年前灿烂的沙黄文化的摇篮，留下了令考古学家着迷的瓮棺墓与精美饰品。海边是一片片雪白的盐田，盐农在正午烈日下勤恳耙盐，勾勒出质朴的劳作画卷。清晨，渔村醒来，圆形竹篮船热闹靠岸，舱里装满鲜鱼。沙黄是想要逃离都市喧嚣之人的宁静驿站。","facts":["在此发现了距今逾2000年的沙黄文化。","沙黄盐田是中部最古老的盐场之一。","其名源自意为「金色沙滩」的「沙黄」。","紧邻1A国道，与平定省接壤。"],"travelTips":["清晨到渔村鱼市，以实惠价格选购新鲜海鲜。","可结合参观附近的沙黄文化博物馆与遗址。"],"bestTime":"4月至8月","visitDuration":"半天","ticket":"","openingHours":"全天","galleryCaptions":["弯如新月的金色沙滩","环抱平静海湾、绵长弯曲的金色沙岸","沿沙岸蜿蜒的海滨公路"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bdi-ky-co-eo-gio', 'ky-co-eo-gio', 'binh-dinh', 'Kỳ Co - Eo Gió', 'Ky Co - Eo Gio', 'beach', 109.3417, 13.7233, 'Bộ đôi tuyệt tác của Quy Nhơn: bãi tắm Kỳ Co nước xanh ngọc và eo biển Eo Gió uốn lượn giữa vách núi.', 'Được ví như ''Maldives của Việt Nam'', Kỳ Co khiến lữ khách ngỡ ngàng với làn nước trong vắt phân tầng từ xanh ngọc đến xanh thẳm, ôm lấy bãi cát trắng mịn nằm lọt giữa hai triền núi đá. Cách đó không xa, Eo Gió hiện ra như một dải lụa uốn cong, nơi gió biển luồn qua khe núi tạo thành âm thanh vi vu suốt ngày đêm. Con đường ven biển quanh Eo Gió được tô điểm bằng những giàn hoa giấy rực rỡ, là điểm ngắm bình minh và hoàng hôn tuyệt đẹp. Đứng trên vách đá nhìn xuống, từng con sóng bạc đầu vỗ vào ghềnh đá đen, đàn chim yến chao lượn. Kỳ Co và Eo Gió là hành trình không thể bỏ lỡ khi đến Bình Định.', '["Eo Gió được mệnh danh là nơi ngắm hoàng hôn đẹp nhất Việt Nam.","Kỳ Co được tiếp cận bằng ca nô hoặc đường bộ vượt núi Triều Châu.","Nước biển Kỳ Co phân tầng màu rõ rệt nhờ đáy cát trắng và san hô.","Eo Gió là vùng có nhiều hang yến tự nhiên ven biển.","Cả hai nằm tại bán đảo Nhơn Lý, cách trung tâm Quy Nhơn khoảng 20 km."]', '["Đi ca nô từ Nhơn Lý ra Kỳ Co để tiết kiệm sức và ngắm cảnh biển.","Mang giày bám tốt khi leo cầu thang quanh Eo Gió, nắng trưa khá gắt."]', 'Tháng 3 đến tháng 9', '1 ngày', '25.000đ (Eo Gió)', '06:00 - 18:00', '["trending","popular","verified"]', '["beach","nature","photography"]', '[{"seed":"kyco-bai","caption":"Bãi tắm Kỳ Co nước xanh ngọc","ratio":"16/9"},{"seed":"eogio-cong","caption":"Eo Gió uốn lượn giữa vách núi","ratio":"4/3"},{"seed":"eogio-hoa","caption":"Đường hoa giấy ven biển Eo Gió","ratio":"1/1"}]', '["bdi-thap-banh-it"]', 1, '{"en":{"name":"Ky Co - Eo Gio","summary":"Quy Nhon''s masterful duo: the jade-green waters of Ky Co beach and the cliff-lined cove of Eo Gio.","story":"Often called the ''Maldives of Vietnam'', Ky Co astonishes travelers with water so clear it shifts from jade green to deep blue, embracing a fine white-sand beach tucked between two rocky slopes. Not far away, Eo Gio appears like a curving silk ribbon, where the sea breeze slips through the mountain gap with a whistling sound day and night. The coastal road around Eo Gio is adorned with vivid bougainvillea, a beautiful spot for sunrise and sunset. Standing on the cliff and looking down, each white-capped wave crashes against the black rocks while swiftlets wheel overhead. Ky Co and Eo Gio are a journey not to be missed when visiting Binh Dinh.","facts":["Eo Gio is hailed as the most beautiful sunset-viewing spot in Vietnam.","Ky Co is reached by speedboat or by road over Trieu Chau mountain.","Ky Co''s waters show distinct color layers thanks to white sand and coral.","Eo Gio has many natural swiftlet caves along the coast.","Both lie on the Nhon Ly peninsula, about 20 km from central Quy Nhon."],"travelTips":["Take a speedboat from Nhon Ly to Ky Co to save energy and enjoy the sea views.","Wear grippy shoes when climbing the stairs around Eo Gio; the midday sun is fierce."],"bestTime":"March to September","visitDuration":"1 day","ticket":"25,000 VND (Eo Gio)","openingHours":"06:00 - 18:00","galleryCaptions":["Ky Co beach with jade-green water","Eo Gio winding between the cliffs","The bougainvillea road along the Eo Gio coast"]},"ko":{"name":"끼꼬 - 에오지오","summary":"꾸이년의 걸작 듀오: 비취빛 바다의 끼꼬 해변과 절벽 사이로 굽이치는 에오지오 해협.","story":"''베트남의 몰디브''로 불리는 끼꼬는 비취빛에서 짙은 푸른빛까지 층층이 변하는 맑은 물과 두 바위 비탈 사이에 자리한 고운 백사장으로 여행객을 사로잡습니다. 멀지 않은 곳의 에오지오는 굽이치는 비단 띠처럼 펼쳐져, 바닷바람이 산틈을 지나며 밤낮으로 휘파람 소리를 냅니다. 에오지오를 도는 해안 도로는 화사한 부겐빌레아로 단장되어 일출과 일몰을 감상하기에 더없이 아름답습니다. 절벽 위에서 내려다보면 하얀 포말을 인 파도가 검은 바위에 부딪치고 칼새 떼가 날아오릅니다. 끼꼬와 에오지오는 빈딘을 찾는다면 놓칠 수 없는 여정입니다.","facts":["에오지오는 베트남에서 가장 아름다운 일몰 명소로 손꼽힘.","끼꼬는 보트나 찌에우쩌우산을 넘는 육로로 접근.","끼꼬의 바닷물은 흰 모래와 산호 덕에 색이 뚜렷이 층을 이룸.","에오지오는 해안가에 천연 칼새 동굴이 많음.","둘 다 년리 반도에 위치, 꾸이년 중심에서 약 20km."],"travelTips":["체력을 아끼고 바다 풍경을 즐기려면 년리에서 끼꼬까지 보트를 타세요.","에오지오 계단을 오를 때 접지력 좋은 신발을 신으세요. 한낮 햇볕이 강합니다."],"bestTime":"3월~9월","visitDuration":"1일","ticket":"25,000동 (에오지오)","openingHours":"06:00 - 18:00","galleryCaptions":["비취빛 바다의 끼꼬 해변","절벽 사이로 굽이치는 에오지오","에오지오 해안의 부겐빌레아 길"]},"ja":{"name":"キーコー - エオジオ","summary":"クイニョンの傑作デュオ。翡翠色の海のキーコービーチと、断崖の間をうねるエオジオの入江。","story":"「ベトナムのモルディブ」と称されるキーコーは、翡翠色から濃い青へと層をなして変わる澄んだ海と、二つの岩の斜面の間に収まる白く細かな砂浜で旅人を魅了します。少し離れたエオジオは、うねる絹のリボンのように現れ、潮風が山の隙間を抜けて昼夜問わずひゅうひゅうと音を立てます。エオジオを巡る海岸道路は鮮やかなブーゲンビリアで彩られ、日の出と日の入りを眺める絶好の地です。断崖の上から見下ろせば、白波を立てる波が黒い岩に砕け、アマツバメの群れが舞います。キーコーとエオジオは、ビンディンを訪れるなら見逃せない道のりです。","facts":["エオジオはベトナムで最も美しい夕日の名所と称される。","キーコーはボート、またはチエウチャウ山を越える陸路でアクセス。","キーコーの海水は白砂とサンゴのおかげで色が明確に層をなす。","エオジオは海岸沿いに天然のアマツバメ洞窟が多い。","両者ともニョンリー半島に位置し、クイニョン中心部から約20km。"],"travelTips":["体力を温存し海景を楽しむには、ニョンリーからキーコーまでボートに乗りましょう。","エオジオの階段を登る際はグリップの良い靴を。真昼の日差しはかなり強いです。"],"bestTime":"3月〜9月","visitDuration":"1日","ticket":"25,000ドン（エオジオ）","openingHours":"06:00 - 18:00","galleryCaptions":["翡翠色の海のキーコービーチ","断崖の間をうねるエオジオ","エオジオ海岸のブーゲンビリアの道"]},"zh":{"name":"奇科 - 风坳","summary":"归仁的绝妙双景：海水碧绿的奇科海滩，与在山崖间蜿蜒的风坳海峡。","story":"被誉为「越南马尔代夫」的奇科，以从碧绿到深蓝层层渐变的清澈海水，以及夹在两座岩坡之间的细白沙滩，令旅人惊叹。不远处，风坳宛如一条蜿蜒的丝带，海风穿过山隙，日夜发出呜呜声响。环绕风坳的海滨公路点缀着绚烂的三角梅，是观赏日出与日落的绝佳之地。立于崖上俯瞰，朵朵白浪拍打黑色礁石，金丝燕群盘旋翱翔。奇科与风坳，是来平定不可错过的旅程。","facts":["风坳被誉为越南最美的观日落之地。","奇科可乘快艇，或经陆路翻越潮州山抵达。","奇科海水因白沙与珊瑚而呈现明显的色彩分层。","风坳沿海有许多天然金丝燕洞。","二者均位于仁李半岛，距归仁市中心约20公里。"],"travelTips":["从仁李乘快艇前往奇科，既省力又能饱览海景。","攀爬风坳台阶时请穿抓地力好的鞋，正午日照颇为强烈。"],"bestTime":"3月至9月","visitDuration":"1天","ticket":"25,000越南盾（风坳）","openingHours":"06:00 - 18:00","galleryCaptions":["海水碧绿的奇科海滩","在山崖间蜿蜒的风坳","风坳海滨的三角梅之路"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bdi-thap-banh-it', 'thap-banh-it', 'binh-dinh', 'Tháp Bánh Ít', 'Banh It Towers', 'temple', 109.1147, 13.8636, 'Cụm tháp Chăm cổ kính trên đỉnh đồi, một trong những quần thể tháp đẹp và còn nguyên vẹn nhất Bình Định.', 'Tháp Bánh Ít sừng sững trên ngọn đồi nhìn ra dòng sông Côn, là quần thể bốn ngôi tháp Chăm được xây dựng từ cuối thế kỷ XI đầu thế kỷ XII. Từ xa, cụm tháp gợi hình những chiếc bánh ít lá gai dân dã của xứ Nẫu, vì thế mà thành tên. Mỗi tháp một dáng vẻ: tháp Cổng vạm vỡ, tháp Bia thanh thoát, tháp Yên Ngựa với mái cong độc đáo và tháp Chính uy nghi cao gần hai mươi mét. Những phù điêu thần Shiva múa, các họa tiết hoa văn được chạm khắc tinh xảo trên gạch nung đỏ au, kể câu chuyện về một vương quốc Chăm Pa từng rực rỡ. Đứng giữa tháp đón gió đồng, ta như nghe vọng tiếng trống Chăm xa xưa.', '["Được xây dựng vào khoảng cuối thế kỷ XI - đầu thế kỷ XII.","Gồm 4 tháp với phong cách kiến trúc Chăm Pa khác nhau.","Được giới thiệu trong cuốn ''1.001 công trình kiến trúc phải đến trong cuộc đời''.","Tên gọi do hình dáng cụm tháp giống chiếc bánh ít lá gai.","Tháp Yên Ngựa có phần mái cong hình yên ngựa rất hiếm gặp."]', '["Đến vào sáng sớm hoặc chiều muộn để tránh nắng và chụp ảnh đẹp.","Leo bậc thang lên đỉnh đồi nên mang theo nước uống và đội mũ."]', 'Tháng 1 đến tháng 8', '1 - 2 giờ', '15.000đ', '07:00 - 17:30', '["verified","popular"]', '["temple","history","culture","photography"]', '[{"seed":"banhit-chinh","caption":"Tháp Chính uy nghi trên đồi","ratio":"16/9"},{"seed":"banhit-yenngua","caption":"Tháp Yên Ngựa mái cong độc đáo","ratio":"4/3"},{"seed":"banhit-phudieu","caption":"Cụm tháp Chăm cổ nhô lên giữa rừng xanh","ratio":"1/1"}]', '["bdi-ky-co-eo-gio"]', 0, '{"en":{"name":"Banh It Towers","summary":"An ancient cluster of Cham towers atop a hill, one of the most beautiful and best-preserved tower complexes in Binh Dinh.","story":"Banh It Towers stand tall on a hill overlooking the Con River, a complex of four Cham towers built from the late 11th to early 12th century. From afar, the cluster evokes the humble ''banh it la gai'' rice cakes of the Nau land, hence the name. Each tower has its own form: the sturdy Gate Tower, the graceful Stele Tower, the Saddle Tower with its uniquely curved roof, and the majestic Main Tower nearly twenty meters high. Reliefs of the dancing god Shiva and intricate patterns are carved into the russet fired brick, telling the story of a once-brilliant Champa kingdom. Standing among the towers in the field breeze, you seem to hear the echo of ancient Cham drums.","facts":["Built around the late 11th to early 12th century.","Comprises 4 towers in differing Champa architectural styles.","Featured in the book ''1,001 Buildings You Must See in Your Lifetime''.","Named for the cluster''s resemblance to ''banh it la gai'' rice cakes.","The Saddle Tower has a rare saddle-shaped curved roof."],"travelTips":["Visit in early morning or late afternoon to avoid the sun and take great photos.","Bring water and wear a hat when climbing the steps to the hilltop."],"bestTime":"January to August","visitDuration":"1 - 2 hours","ticket":"15,000 VND","openingHours":"07:00 - 17:30","galleryCaptions":["The majestic Main Tower on the hill","The Saddle Tower with its unique curved roof","Ancient Cham towers rising amid green forest"]},"ko":{"name":"반잇 탑","summary":"언덕 위 고풍스러운 참 탑 군으로, 빈딘에서 가장 아름답고 온전히 보존된 탑 군 중 하나입니다.","story":"반잇 탑은 꼰강을 굽어보는 언덕 위에 우뚝 서 있으며, 11세기 말에서 12세기 초에 세워진 네 기의 참 탑으로 이루어진 군입니다. 멀리서 보면 그 모습이 너 지방의 소박한 ''반잇 라가이'' 떡을 닮아 그 이름이 붙었습니다. 탑마다 모습이 다릅니다. 우람한 관문 탑, 우아한 비석 탑, 독특하게 굽은 지붕의 안장 탑, 그리고 스무 미터에 가까운 위풍당당한 본탑. 붉게 구운 벽돌에는 춤추는 시바 신의 부조와 정교한 문양이 새겨져 한때 찬란했던 참파 왕국의 이야기를 전합니다. 들바람을 맞으며 탑 사이에 서면 아득한 참 북소리가 들려오는 듯합니다.","facts":["11세기 말~12세기 초에 건립.","서로 다른 참파 건축 양식의 4개 탑으로 구성.","''평생 가봐야 할 1,001가지 건축물'' 책에 소개됨.","탑 군이 ''반잇 라가이'' 떡을 닮아 붙은 이름.","안장 탑은 보기 드문 안장 모양의 굽은 지붕을 지님."],"travelTips":["햇볕을 피하고 멋진 사진을 찍으려면 이른 아침이나 늦은 오후에 가세요.","언덕 정상까지 계단을 오르니 물을 챙기고 모자를 쓰세요."],"bestTime":"1월~8월","visitDuration":"1~2시간","ticket":"15,000동","openingHours":"07:00 - 17:30","galleryCaptions":["언덕 위 위풍당당한 본탑","독특하게 굽은 지붕의 안장 탑","푸른 숲 사이로 솟은 고대 참 탑 군"]},"ja":{"name":"バインイットタワー","summary":"丘の上の古風なチャム塔群。ビンディンで最も美しく、ほぼ完全な姿で残る塔群の一つです。","story":"バインイットタワーは、コン川を見下ろす丘の上にそびえ立ち、11世紀末から12世紀初頭に築かれた4基のチャム塔からなる群です。遠くから見ると、その姿がナウ地方の素朴な「バインイット・ラーガイ」餅に似ていることから、その名がつきました。塔ごとに姿が異なります。たくましい門塔、優美な碑塔、独特に反った屋根の鞍塔、そして20メートル近い荘厳な本塔。赤く焼かれた煉瓦には、踊るシヴァ神の浮彫と精巧な文様が刻まれ、かつて栄華を誇ったチャンパ王国の物語を伝えます。野の風を受けて塔の間に立てば、遠い昔のチャムの太鼓の音が響いてくるようです。","facts":["11世紀末〜12世紀初頭頃に建立。","異なるチャンパ建築様式の4つの塔からなる。","書籍『生涯に訪れるべき1,001の建築物』で紹介された。","塔群が「バインイット・ラーガイ」餅に似ていることに由来する名。","鞍塔は珍しい鞍形の反った屋根を持つ。"],"travelTips":["日差しを避けて美しい写真を撮るには、早朝か夕方遅くに行きましょう。","丘の頂まで階段を登るので、水を持参し帽子を被りましょう。"],"bestTime":"1月〜8月","visitDuration":"1〜2時間","ticket":"15,000ドン","openingHours":"07:00 - 17:30","galleryCaptions":["丘の上の荘厳な本塔","独特に反った屋根の鞍塔","緑の森の中にそびえる古代チャム塔群"]},"zh":{"name":"饼怡塔","summary":"矗立于山丘之上的古朴占族塔群，是平定最美、保存最完整的塔群之一。","story":"饼怡塔巍然矗立于俯瞰昆河的山丘之上，是建于11世纪末至12世纪初的四座占族塔群。远望塔群，形似乂地区那质朴的「饼怡叶」糕，因而得名。每座塔各有姿态：雄健的门塔、清秀的碑塔、屋顶独特弯曲的鞍塔，以及近二十米高、威严庄重的主塔。赭红的烧砖上雕刻着舞动的湿婆神浮雕与精致纹样，诉说着曾经灿烂的占婆王国的故事。立于塔间迎着原野的风，仿佛听见远古占族鼓声的回响。","facts":["约建于11世纪末至12世纪初。","由4座风格各异的占婆建筑塔组成。","被收录于《一生必访的1001座建筑》一书。","因塔群形似「饼怡叶」糕而得名。","鞍塔有着罕见的鞍形弯曲屋顶。"],"travelTips":["清晨或傍晚前往，既避烈日又能拍出美照。","需登台阶上山顶，请携带饮用水并戴帽。"],"bestTime":"1月至8月","visitDuration":"1至2小时","ticket":"15,000越南盾","openingHours":"07:00 - 17:30","galleryCaptions":["山丘上威严的主塔","屋顶独特弯曲的鞍塔","在青林中耸立的古老占族塔群"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('pye-ganh-da-dia', 'ganh-da-dia', 'phu-yen', 'Gành Đá Đĩa', 'Da Dia Reef', 'park', 109.2939, 13.4833, 'Kỳ quan địa chất với hàng vạn cột đá bazan đen xếp tầng tựa chồng đĩa khổng lồ vươn ra biển.', 'Gành Đá Đĩa là một tuyệt tác mà thiên nhiên dày công kiến tạo từ dòng dung nham núi lửa nguội lạnh hàng triệu năm trước. Khi đông cứng, đá bazan nứt vỡ thành những khối lăng trụ lục giác, ngũ giác đều đặn đến khó tin, xếp chồng khít nhau như những chồng đĩa được bàn tay người sắp đặt. Cả gành đá đen tuyền trải rộng hơn năm chục mét, một nửa ngâm mình dưới làn sóng biếc, nửa kia phơi mình đón nắng. Sóng vỗ vào ghềnh tung bọt trắng xóa, tạo nên khung cảnh vừa kỳ vĩ vừa nên thơ. Đây là một trong số ít thắng cảnh đá đĩa hiếm hoi trên thế giới, được công nhận là Di tích quốc gia đặc biệt và là niềm tự hào của xứ hoa vàng cỏ xanh.', '["Hình thành từ dung nham bazan nứt vỡ thành các cột đá lục giác, ngũ giác.","Được công nhận là Di tích quốc gia đặc biệt năm 2020.","Gành rộng khoảng 50m, dài 200m với hàng nghìn trụ đá.","Là một trong vài thắng cảnh đá đĩa hiếm có trên thế giới.","Gần đó có nhà thờ Mằng Lăng cổ và bãi Bàng hoang sơ."]', '["Đi vào sáng sớm khi thủy triều xuống để dạo trên gành đá an toàn.","Cẩn thận khi bước trên đá ướt vì khá trơn, nên mang giày bám tốt."]', 'Tháng 3 đến tháng 9', '2 - 3 giờ', '20.000đ', '06:30 - 18:00', '["trending","popular","verified"]', '["nature","photography","history"]', '[{"seed":"gddia-cot","caption":"Cột đá bazan xếp tầng kỳ vĩ","ratio":"16/9"},{"seed":"gddia-song","caption":"Sóng vỗ trắng xóa vào ghềnh đá","ratio":"4/3"},{"seed":"gddia-toancanh","caption":"Toàn cảnh gành đá vươn ra biển","ratio":"1/1"}]', '["pye-bai-xep"]', 1, '{"en":{"name":"Ganh Da Dia","summary":"A geological wonder of tens of thousands of stacked black basalt columns resembling giant piles of plates reaching into the sea.","story":"Ganh Da Dia is a masterpiece nature painstakingly crafted from volcanic lava that cooled millions of years ago. As it solidified, the basalt cracked into remarkably regular hexagonal and pentagonal prisms, stacked together so neatly they look arranged by human hands. The whole jet-black reef spreads over fifty meters, half submerged beneath the blue waves, half basking in the sun. Waves crash against the reef in white spray, creating a scene both grand and poetic. This is one of the few stone-plate landscapes in the world, recognized as a Special National Relic and the pride of the land of golden flowers on green grass.","facts":["Formed from basalt lava cracking into hexagonal and pentagonal stone columns.","Recognized as a Special National Relic in 2020.","The reef is about 50m wide and 200m long with thousands of stone columns.","One of the few stone-plate landscapes in the world.","Near the ancient Mang Lang Church and the pristine Bang beach."],"travelTips":["Go in early morning at low tide to walk on the rocks safely.","Be careful on the wet rocks as they are slippery; wear grippy shoes."],"bestTime":"March to September","visitDuration":"2 - 3 hours","ticket":"20,000 VND","openingHours":"06:30 - 18:00","galleryCaptions":["Majestic stacked basalt columns","Waves crashing white against the reef","A full view of the reef reaching into the sea"]},"ko":{"name":"간다디아","summary":"수만 개의 검은 현무암 기둥이 거대한 접시 더미처럼 켜켜이 쌓여 바다로 뻗은 지질 절경입니다.","story":"간다디아는 수백만 년 전 식은 화산 용암으로 자연이 공들여 빚어낸 걸작입니다. 굳으면서 현무암은 믿기 힘들 만큼 반듯한 육각·오각 기둥으로 갈라져, 마치 사람 손으로 쌓은 듯 빈틈없이 포개졌습니다. 새까만 암반 전체가 오십 미터 넘게 펼쳐져 절반은 푸른 파도에 잠기고 절반은 햇볕에 몸을 드러냅니다. 파도가 암반에 부딪쳐 하얀 포말을 일으키며 웅장하면서도 시적인 풍경을 자아냅니다. 세계에서도 보기 드문 접시바위 절경 중 하나로, 특별 국가유적으로 지정되어 ''푸른 풀밭의 노란 꽃'' 고장의 자랑입니다.","facts":["현무암 용암이 육각·오각 기둥으로 갈라져 형성.","2020년 특별 국가유적으로 지정.","암반은 폭 약 50m, 길이 200m로 수천 개의 돌기둥이 있음.","세계에서도 보기 드문 접시바위 절경 중 하나.","인근에 고풍스러운 망랑 성당과 청정한 방 해변이 있음."],"travelTips":["안전하게 암반을 거닐려면 썰물 때인 이른 아침에 가세요.","젖은 바위가 미끄러우니 조심하고 접지력 좋은 신발을 신으세요."],"bestTime":"3월~9월","visitDuration":"2~3시간","ticket":"20,000동","openingHours":"06:30 - 18:00","galleryCaptions":["웅장하게 켜켜이 쌓인 현무암 기둥","암반에 하얗게 부서지는 파도","바다로 뻗은 암반의 전경"]},"ja":{"name":"ガンダーディア","summary":"数万本の黒い玄武岩の柱が巨大な皿の山のように積み重なり、海へと伸びる地質の絶景です。","story":"ガンダーディアは、数百万年前に冷え固まった火山溶岩から自然が丹精込めて作り上げた傑作です。固まる際、玄武岩は信じがたいほど整った六角・五角の柱に割れ、まるで人の手で並べたかのように隙間なく積み重なりました。真っ黒な岩盤全体が50メートル以上にわたって広がり、半分は青い波に沈み、半分は日差しに身をさらします。波が岩盤に砕けて白い飛沫を立て、雄大かつ詩的な光景を作り出します。世界でも稀な皿岩の絶景の一つで、特別国家遺跡に指定され、「緑の草原の黄色い花」の地の誇りです。","facts":["玄武岩の溶岩が六角・五角の柱に割れて形成。","2020年に特別国家遺跡に指定。","岩盤は幅約50m、長さ200mで数千本の石柱がある。","世界でも稀な皿岩の絶景の一つ。","近くに古風なマンラン教会と手つかずのバン浜がある。"],"travelTips":["岩盤を安全に歩くには、引き潮の早朝に行きましょう。","濡れた岩は滑りやすいので注意し、グリップの良い靴を履きましょう。"],"bestTime":"3月〜9月","visitDuration":"2〜3時間","ticket":"20,000ドン","openingHours":"06:30 - 18:00","galleryCaptions":["雄大に積み重なる玄武岩の柱","岩盤に白く砕ける波","海へと伸びる岩盤の全景"]},"zh":{"name":"叠石滩","summary":"一处地质奇观，数以万计的黑色玄武岩柱层层堆叠，宛如巨型叠盘，伸向大海。","story":"叠石滩是大自然以数百万年前冷却的火山熔岩精心雕琢的杰作。凝固之时，玄武岩裂成规整得令人难以置信的六棱、五棱柱体，层层紧密堆叠，仿佛出自人手摆放。整片乌黑的岩盘绵延五十余米，半浸于碧波之下，半浴于阳光之中。海浪拍打岩盘，溅起雪白浪花，构成既壮丽又诗意的景致。这是世界上少有的叠盘石景之一，被列为国家级特别遗迹，是「黄花绿草」之乡的骄傲。","facts":["由玄武岩熔岩裂成六棱、五棱石柱而形成。","2020年被列为国家级特别遗迹。","岩盘宽约50米、长200米，有数千根石柱。","世界上少有的叠盘石景之一。","附近有古朴的莽榔教堂与原始的榜滩。"],"travelTips":["清晨退潮时前往，可安全地在岩盘上漫步。","湿滑岩石上行走需当心，请穿抓地力好的鞋。"],"bestTime":"3月至9月","visitDuration":"2至3小时","ticket":"20,000越南盾","openingHours":"06:30 - 18:00","galleryCaptions":["层层堆叠的壮丽玄武岩柱","拍打岩盘的雪白浪花","伸向大海的岩盘全景"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('pye-bai-xep', 'bai-xep', 'phu-yen', 'Bãi Xép', 'Xep Beach', 'beach', 109.3083, 13.3306, 'Bãi biển hoang sơ với đồi cỏ xanh và ghềnh đá, nổi tiếng qua phim ''Tôi thấy hoa vàng trên cỏ xanh''.', 'Bãi Xép trở thành cái tên trong mơ của bao người sau khi xuất hiện trong bộ phim ''Tôi thấy hoa vàng trên cỏ xanh'', với những thước phim đẹp đến nao lòng. Nơi đây là sự hòa quyện tuyệt vời giữa bãi cát vàng cong mềm mại, đồi cỏ xanh mướt thoai thoải và ghềnh đá đen nhô ra biển. Buổi sáng, ánh nắng đầu ngày trải vàng trên triền cỏ, gió biển mơn man mang theo vị mặn mòi. Lữ khách thích leo lên mỏm đá cao ngắm toàn cảnh vịnh biển trải dài, hoặc thả mình trên thảm cỏ ngắm những con thuyền đánh cá xa xa. Không gian yên tĩnh, mộc mạc của Bãi Xép gợi cảm giác bình yên hiếm có, như chạm vào một miền ký ức tuổi thơ trong trẻo.', '["Là bối cảnh chính của phim ''Tôi thấy hoa vàng trên cỏ xanh'' (2015).","Cách thành phố Tuy Hòa khoảng 13 km về phía bắc.","Nổi bật với đồi cỏ xanh, ghềnh đá đen và bãi cát vàng đan xen.","Có hai bãi nhỏ là Bãi Xép và bãi Cây Me liền kề."]', '["Đến lúc bình minh để ngắm nắng vàng trải trên đồi cỏ tuyệt đẹp.","Mang theo nước và đồ ăn nhẹ vì dịch vụ tại bãi còn hạn chế."]', 'Tháng 1 đến tháng 8', 'Nửa ngày', '20.000đ', '06:00 - 18:00', '["popular","verified","hidden-gem"]', '["beach","nature","photography"]', '[{"seed":"baixep-doico","caption":"Triền đồi xương rồng nghiêng xuống bãi biển vắng","ratio":"16/9"},{"seed":"baixep-binhminh","caption":"Mặt trời ló rạng sau mỏm núi, sóng vỗ bờ cát","ratio":"4/3"},{"seed":"baixep-ghenh","caption":"Ghềnh đá đen nhô ra biển","ratio":"1/1"}]', '["pye-ganh-da-dia"]', 0, '{"en":{"name":"Bai Xep","summary":"A pristine beach with green grassy hills and rocky reefs, made famous by the film ''Yellow Flowers on the Green Grass''.","story":"Bai Xep became a dream destination for many after appearing in the film ''Yellow Flowers on the Green Grass'', with cinematography heartbreakingly beautiful. Here is a wonderful blend of softly curving golden sand, gently sloping green grassy hills, and black rocky reefs jutting into the sea. In the morning, the first light spreads gold over the grassy slopes, and the sea breeze caresses with its salty tang. Travelers love climbing the high rocks to take in the whole sweeping bay, or lying on the grassy carpet watching fishing boats in the distance. The quiet, rustic space of Bai Xep evokes a rare sense of peace, like touching a clear memory of childhood.","facts":["The main setting of the film ''Yellow Flowers on the Green Grass'' (2015).","About 13 km north of Tuy Hoa city.","Notable for its interwoven green hills, black reefs, and golden sand.","Has two small beaches, Bai Xep and the adjacent Cay Me beach."],"travelTips":["Arrive at dawn to watch golden light spread beautifully over the grassy hills.","Bring water and snacks as services at the beach are still limited."],"bestTime":"January to August","visitDuration":"Half a day","ticket":"20,000 VND","openingHours":"06:00 - 18:00","galleryCaptions":["A cactus-covered slope leaning down to a deserted beach","The sun rising behind a rocky headland as waves lap the sand","Black rocky reefs jutting into the sea"]},"ko":{"name":"바이쎕","summary":"푸른 풀 언덕과 암반을 품은 청정 해변으로, 영화 ''푸른 풀밭의 노란 꽃''으로 유명해졌습니다.","story":"바이쎕은 영화 ''푸른 풀밭의 노란 꽃''에 가슴 시리도록 아름다운 장면으로 등장한 뒤 많은 이들의 꿈속 명소가 되었습니다. 이곳은 부드럽게 굽은 황금빛 모래, 완만하게 펼쳐진 푸른 풀 언덕, 바다로 솟은 검은 암반이 절묘하게 어우러진 곳입니다. 아침이면 첫 햇살이 풀 비탈에 황금빛을 펼치고 짭짤한 바닷바람이 어루만집니다. 여행객들은 높은 바위에 올라 길게 펼쳐진 만 전경을 바라보거나, 풀밭에 누워 멀리 고깃배를 바라보길 좋아합니다. 고요하고 소박한 바이쎕의 공간은 맑은 어린 시절의 기억을 어루만지는 듯 보기 드문 평온함을 자아냅니다.","facts":["영화 ''푸른 풀밭의 노란 꽃''(2015)의 주요 촬영지.","뚜이호아 시에서 북쪽으로 약 13km.","푸른 풀 언덕, 검은 암반, 황금빛 모래가 어우러진 풍경이 돋보임.","바이쎕과 인접한 꺼이메 해변, 두 작은 해변으로 구성."],"travelTips":["풀 언덕에 황금빛 햇살이 펼쳐지는 일출 때 가세요.","해변 편의시설이 아직 제한적이니 물과 간식을 챙기세요."],"bestTime":"1월~8월","visitDuration":"반나절","ticket":"20,000동","openingHours":"06:00 - 18:00","galleryCaptions":["한적한 해변으로 기운 선인장 비탈","바위 곶 뒤로 떠오르는 해, 모래밭에 부서지는 파도","바다로 솟은 검은 암반"]},"ja":{"name":"バイセップ","summary":"緑の草の丘と岩盤を抱く手つかずのビーチ。映画『草原に黄色い花を見つける』で有名になりました。","story":"バイセップは、映画『草原に黄色い花を見つける』に胸を締めつけるほど美しい映像で登場して以来、多くの人の夢の名所となりました。ここは柔らかく弧を描く黄金の砂、なだらかに広がる緑の草の丘、海へと突き出る黒い岩盤が見事に溶け合う場所です。朝には一日の最初の光が草の斜面に黄金色を広げ、潮の香りを含んだ海風が頬を撫でます。旅人は高い岩によじ登って長く広がる湾の全景を眺めたり、草の絨毯に身を横たえて遠くの漁船を眺めたりするのを好みます。静かで素朴なバイセップの空間は、澄んだ子供時代の記憶に触れるような、稀な安らぎを呼び起こします。","facts":["映画『草原に黄色い花を見つける』（2015年）の主要ロケ地。","トゥイホア市から北へ約13km。","緑の草の丘、黒い岩盤、黄金の砂が織りなす風景が際立つ。","バイセップと隣接するカイメー浜の2つの小さな浜からなる。"],"travelTips":["草の丘に黄金の光が広がる日の出時に行きましょう。","浜での施設はまだ限られているので、水と軽食を持参しましょう。"],"bestTime":"1月〜8月","visitDuration":"半日","ticket":"20,000ドン","openingHours":"06:00 - 18:00","galleryCaptions":["人気のない浜へと傾くサボテンの斜面","岩の岬の後ろから昇る太陽、砂浜に打ち寄せる波","海へと突き出る黒い岩盤"]},"zh":{"name":"瑞滩","summary":"拥有绿草丘与礁石的原始海滩，因电影《我看见草中黄花》而声名远扬。","story":"瑞滩在电影《我看见草中黄花》中以美得令人心碎的镜头登场后，成为无数人梦中的胜地。这里是柔和弯曲的金沙、缓缓起伏的青翠草丘，与伸入大海的黑色礁石的绝妙交融。清晨，一天的初阳为草坡铺上金光，海风轻拂，带来咸咸的气息。旅人喜欢攀上高耸的岩石，俯瞰绵延的海湾全景，或躺在草毯上眺望远处的渔船。瑞滩宁静质朴的空间，唤起一种难得的安宁，仿佛触及一段清澈的童年记忆。","facts":["电影《我看见草中黄花》（2015）的主要取景地。","距绥和市以北约13公里。","以青草丘、黑礁石与金沙交错的景致而著称。","包含瑞滩与紧邻的梅树滩两处小海滩。"],"travelTips":["日出时分前往，欣赏金光洒满草丘的绝美景象。","海滩配套设施仍有限，请自备饮水与点心。"],"bestTime":"1月至8月","visitDuration":"半天","ticket":"20,000越南盾","openingHours":"06:00 - 18:00","galleryCaptions":["长满仙人掌、斜倾向僻静海滩的山坡","太阳从岩岬后升起，海浪拍打沙岸","伸入大海的黑色礁石"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ntn-vinh-vinh-hy', 'vinh-vinh-hy', 'ninh-thuan', 'Vịnh Vĩnh Hy', 'Vinh Hy Bay', 'beach', 109.2058, 11.71, 'Một trong những vịnh biển đẹp nhất Việt Nam, nước trong vắt ôm trọn rừng núi Núi Chúa và rạn san hô rực rỡ.', 'Vĩnh Hy được xếp vào hàng những vịnh biển đẹp nhất Việt Nam, nơi rừng và biển giao hòa trong một bức tranh sơn thủy hữu tình. Vịnh nằm gọn trong lòng Vườn quốc gia Núi Chúa, ba bề là núi non trùng điệp ôm lấy mặt nước phẳng lặng xanh như ngọc. Ngồi trên thuyền đáy kính lướt trên vịnh, bạn ngắm những rạn san hô đủ sắc màu, đàn cá tung tăng và làn nước trong đến tận đáy. Cung đường ven biển dẫn đến Vĩnh Hy được mệnh danh là một trong những con đường ven biển đẹp nhất nước, với một bên là vách núi, một bên là biển khơi bao la. Làng chài Vĩnh Hy nhỏ bé nép mình bên vịnh, mang đến hải sản tươi rói và nhịp sống chậm rãi, an yên.', '["Là một trong 4 vịnh đẹp nhất Việt Nam theo nhiều bình chọn.","Nằm trong Khu dự trữ sinh quyển thế giới Núi Chúa.","Có thể ngắm san hô qua thuyền đáy kính hoặc lặn biển.","Cung đường ven biển DT702 dẫn vào vịnh nổi tiếng tuyệt đẹp.","Gần vịnh có Hang Rái với bãi san hô cổ độc đáo."]', '["Đi thuyền đáy kính buổi sáng khi nước trong để ngắm san hô rõ nhất.","Kết hợp ghé Hang Rái và vườn nho Ninh Thuận trên cùng cung đường."]', 'Tháng 1 đến tháng 8', '1 ngày', 'Tùy dịch vụ thuyền', 'Cả ngày', '["trending","popular","verified"]', '["beach","nature","island","photography"]', '[{"seed":"vinhhy-vinh","caption":"Vịnh Vĩnh Hy xanh ngọc ôm rừng núi","ratio":"16/9"},{"seed":"vinhhy-sanho","caption":"Vịnh nhỏ neo đậu hàng trăm thuyền cá","ratio":"4/3"},{"seed":"vinhhy-duongven","caption":"Cung đường ven biển Núi Chúa","ratio":"1/1"}]', '["ntn-po-klong-garai"]', 1, '{"en":{"name":"Vinh Hy Bay","summary":"One of Vietnam''s most beautiful bays, its crystal waters embracing the Nui Chua forest mountains and brilliant coral reefs.","story":"Vinh Hy ranks among Vietnam''s most beautiful bays, where forest and sea blend into a poetic landscape painting. The bay nestles within Nui Chua National Park, surrounded on three sides by ranges of mountains embracing waters as smooth and green as jade. Sitting on a glass-bottom boat gliding over the bay, you gaze at multicolored coral reefs, schools of fish, and water clear to the very bottom. The coastal road leading to Vinh Hy is hailed as one of the most beautiful seaside roads in the country, with cliffs on one side and the vast open sea on the other. The small Vinh Hy fishing village nestles by the bay, offering fresh seafood and a slow, peaceful pace of life.","facts":["One of Vietnam''s 4 most beautiful bays by many rankings.","Lies within the Nui Chua World Biosphere Reserve.","You can view coral by glass-bottom boat or by diving.","The DT702 coastal road into the bay is famously beautiful.","Near the bay is Hang Rai with its unique ancient coral reef."],"travelTips":["Take a glass-bottom boat in the morning when the water is clear to see coral best.","Combine a stop at Hang Rai and a Ninh Thuan vineyard along the same route."],"bestTime":"January to August","visitDuration":"1 day","ticket":"Depends on the boat service","openingHours":"All day","galleryCaptions":["Jade-green Vinh Hy Bay embracing the forest mountains","A small bay where hundreds of fishing boats are moored","The Nui Chua coastal road"]},"ko":{"name":"빈히 만","summary":"베트남에서 손꼽히는 아름다운 만으로, 맑은 물이 누이쭈아 산림과 화려한 산호초를 감싸 안습니다.","story":"빈히는 베트남에서 가장 아름다운 만 중 하나로 꼽히며, 숲과 바다가 한 폭의 산수화처럼 어우러진 곳입니다. 만은 누이쭈아 국립공원 품에 안겨 삼면이 첩첩 산으로 비취처럼 푸르고 잔잔한 수면을 둘러쌉니다. 유리바닥 배를 타고 만을 미끄러지듯 나아가면 형형색색의 산호초와 헤엄치는 물고기 떼, 바닥까지 비치는 맑은 물을 볼 수 있습니다. 빈히로 이어지는 해안 도로는 한쪽은 절벽, 다른 한쪽은 드넓은 바다로, 전국에서 가장 아름다운 해안 도로로 손꼽힙니다. 만 곁에 자리한 작은 빈히 어촌은 싱싱한 해산물과 느릿하고 평온한 삶의 리듬을 선사합니다.","facts":["여러 선정에서 베트남 4대 아름다운 만 중 하나.","누이쭈아 세계생물권보전지역 내에 위치.","유리바닥 배나 다이빙으로 산호를 감상 가능.","만으로 이어지는 DT702 해안 도로가 절경으로 유명.","만 인근에 독특한 고대 산호밭이 있는 항라이가 있음."],"travelTips":["산호를 가장 또렷이 보려면 물이 맑은 아침에 유리바닥 배를 타세요.","같은 길에 있는 항라이와 닌투언 포도밭을 함께 들르세요."],"bestTime":"1월~8월","visitDuration":"1일","ticket":"보트 서비스에 따라 다름","openingHours":"종일","galleryCaptions":["산림을 감싼 비취빛 빈히 만","수백 척의 고깃배가 정박한 작은 만","누이쭈아 해안 도로"]},"ja":{"name":"ヴィンヒー湾","summary":"ベトナム有数の美しい湾。澄んだ水がヌイチュアの森の山々と鮮やかなサンゴ礁を抱きます。","story":"ヴィンヒーはベトナムで最も美しい湾の一つに数えられ、森と海が一幅の山水画のように溶け合う場所です。湾はヌイチュア国立公園の懐に抱かれ、三方を連なる山々が翡翠のように青く静かな水面を囲みます。ガラス底の船に乗って湾を滑れば、色とりどりのサンゴ礁、泳ぐ魚の群れ、底まで見える澄んだ水を眺められます。ヴィンヒーへ続く海岸道路は、片側は断崖、もう片側は広大な海で、全国でも最も美しい海岸道路の一つと称されます。湾のそばに寄り添う小さなヴィンヒー漁村は、新鮮な海の幸とゆったりと穏やかな暮らしのリズムを届けてくれます。","facts":["多くの選定でベトナム4大美しい湾の一つ。","ヌイチュア世界生物圏保護区内に位置。","ガラス底の船やダイビングでサンゴを眺められる。","湾へ続くDT702海岸道路が絶景で有名。","湾の近くに独特の古代サンゴ礁を持つハンザイがある。"],"travelTips":["サンゴを最もはっきり見るには、水が澄んだ朝にガラス底の船に乗りましょう。","同じ道沿いのハンザイとニントゥアンのぶどう園も合わせて立ち寄りましょう。"],"bestTime":"1月〜8月","visitDuration":"1日","ticket":"ボートサービスにより異なる","openingHours":"終日","galleryCaptions":["森の山々を抱く翡翠色のヴィンヒー湾","数百隻の漁船が停泊する小さな湾","ヌイチュア海岸道路"]},"zh":{"name":"永希湾","summary":"越南最美海湾之一，清澈海水环抱主山的林峦与绚丽的珊瑚礁。","story":"永希跻身越南最美海湾之列，是森林与大海交融的一幅山水画卷。海湾安卧于主山国家公园的怀抱之中，三面群山环绕着碧玉般平静的水面。坐上玻璃底船滑过海湾，你能欣赏五彩珊瑚礁、成群游鱼，以及清澈见底的海水。通往永希的海滨公路被誉为全国最美海滨公路之一，一侧是峭壁，一侧是浩瀚大海。小小的永希渔村依偎在湾畔，带来鲜美的海产与悠然安宁的生活节奏。","facts":["在多项评选中跻身越南四大最美海湾。","位于主山世界生物圈保护区内。","可乘玻璃底船或潜水观赏珊瑚。","通往海湾的DT702海滨公路以绝美著称。","海湾附近有海獭洞，拥有独特的古珊瑚滩。"],"travelTips":["趁清晨水清时乘玻璃底船，最能清晰观赏珊瑚。","可结合同一线路上的海獭洞与宁顺葡萄园一同游览。"],"bestTime":"1月至8月","visitDuration":"1天","ticket":"视乘船服务而定","openingHours":"全天","galleryCaptions":["碧绿环抱林峦的永希湾","停泊数百艘渔船的小海湾","主山海滨公路"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ntn-po-klong-garai', 'thap-po-klong-garai', 'ninh-thuan', 'Tháp Po Klong Garai', 'Po Klong Garai Tower', 'temple', 108.9583, 11.5969, 'Cụm tháp Chăm hùng vĩ trên đồi Trầu, công trình kiến trúc và tín ngưỡng còn nguyên vẹn bậc nhất của người Chăm.', 'Tháp Po Klong Garai sừng sững trên đồi Trầu, là cụm tháp Chăm được xây dựng từ cuối thế kỷ XIII để thờ vua Po Klong Garai, vị vua có công trị thủy và dạy dân làm thủy lợi. Đây được xem là quần thể đền tháp Chăm Pa đẹp và còn nguyên vẹn nhất hiện nay, gồm tháp Chính cao hơn hai mươi mét, tháp Lửa và tháp Cổng. Trên thân tháp gạch đỏ au là vô số phù điêu thần Shiva, bò thần Nandin và các hoa văn được chạm khắc tinh xảo, tinh tế đến từng đường nét. Tháp không chỉ là di sản kiến trúc mà còn là trung tâm tín ngưỡng sống, nơi đồng bào Chăm tổ chức lễ hội Katê linh thiêng vào mỗi mùa thu, rộn ràng tiếng trống Ginăng và điệu múa quạt uyển chuyển.', '["Được xây dựng vào cuối thế kỷ XIII, thời vua Chăm Po Klong Garai.","Là quần thể đền tháp Chăm còn nguyên vẹn nhất Việt Nam.","Là Di tích kiến trúc nghệ thuật quốc gia đặc biệt.","Nơi tổ chức lễ hội Katê của người Chăm hằng năm.","Bên trong tháp Chính thờ tượng vua dưới dạng linga - Mukhalinga."]', '["Ghé vào dịp lễ hội Katê (khoảng tháng 9-10) để xem nghi lễ đặc sắc.","Đi buổi chiều mát, ánh nắng nghiêng làm tháp gạch lên màu rất đẹp."]', 'Tháng 1 đến tháng 9, đẹp nhất mùa lễ Katê', '1 - 2 giờ', '20.000đ', '07:00 - 17:00', '["verified","festival","popular"]', '["temple","history","culture","photography"]', '[{"seed":"poklong-chinh","caption":"Tháp Chính trên đồi Trầu","ratio":"16/9"},{"seed":"poklong-kate","caption":"Lễ hội Katê của người Chăm","ratio":"4/3"},{"seed":"poklong-phudieu","caption":"Quần thể tháp gạch Chăm rêu phong trên đồi cỏ","ratio":"1/1"}]', '["ntn-vinh-vinh-hy"]', 0, '{"en":{"name":"Po Klong Garai Towers","summary":"A majestic Cham tower cluster on Trau Hill, among the most intact architectural and religious monuments of the Cham people.","story":"Po Klong Garai Towers stand tall on Trau Hill, a Cham tower cluster built in the late 13th century to worship King Po Klong Garai, who tamed the waters and taught the people irrigation. It is considered the most beautiful and best-preserved Champa temple-tower complex today, comprising the Main Tower over twenty meters high, the Fire Tower, and the Gate Tower. On the russet brick towers are countless reliefs of the god Shiva, the sacred bull Nandin, and patterns carved with exquisite precision down to every detail. The towers are not only an architectural heritage but a living spiritual center, where the Cham people hold the sacred Kate festival each autumn, alive with Ginang drums and graceful fan dances.","facts":["Built in the late 13th century, in the era of Cham King Po Klong Garai.","The most intact Cham temple-tower complex in Vietnam.","A Special National Architectural and Artistic Relic.","Site of the Cham people''s annual Kate festival.","Inside the Main Tower stands a statue of the king as a linga - Mukhalinga."],"travelTips":["Visit during the Kate festival (around September–October) to see the remarkable rituals.","Go in the cool afternoon, when slanting light gives the brick towers a beautiful color."],"bestTime":"January to September, best during the Kate festival season","visitDuration":"1 - 2 hours","ticket":"20,000 VND","openingHours":"07:00 - 17:00","galleryCaptions":["The Main Tower on Trau Hill","The Cham people''s Kate festival","A weathered Cham brick tower complex on a grassy hill"]},"ko":{"name":"포클롱가라이 탑","summary":"쩌우 언덕 위 웅장한 참 탑 군으로, 참족의 건축물이자 신앙 유적 중 가장 온전히 보존된 곳입니다.","story":"포클롱가라이 탑은 쩌우 언덕 위에 우뚝 서 있으며, 치수에 공을 세우고 백성에게 수리 기술을 가르친 포클롱가라이 왕을 모시기 위해 13세기 말에 세워진 참 탑 군입니다. 오늘날 가장 아름답고 온전히 보존된 참파 사원탑 군으로 꼽히며, 스무 미터가 넘는 본탑, 화탑, 관문 탑으로 이루어졌습니다. 붉은 벽돌 탑신에는 시바 신과 성스러운 소 난딘, 그리고 결마다 정교하게 새겨진 문양이 무수히 펼쳐집니다. 탑은 건축 유산일 뿐 아니라 살아 있는 신앙의 중심으로, 참족이 매년 가을 신성한 카테 축제를 열어 기낭 북소리와 우아한 부채춤으로 흥겹게 채웁니다.","facts":["참 왕 포클롱가라이 시대인 13세기 말에 건립.","베트남에서 가장 온전히 보존된 참 사원탑 군.","특별 국가 건축예술 유적.","매년 참족의 카테 축제가 열리는 곳.","본탑 안에는 링가(무카링가) 형태의 왕상이 모셔져 있음."],"travelTips":["특색 있는 의례를 보려면 카테 축제(9~10월경)에 들르세요.","비스듬한 햇살이 벽돌 탑을 아름답게 물들이는 서늘한 오후에 가세요."],"bestTime":"1월~9월, 카테 축제철이 가장 아름다움","visitDuration":"1~2시간","ticket":"20,000동","openingHours":"07:00 - 17:00","galleryCaptions":["쩌우 언덕 위의 본탑","참족의 카테 축제","풀 언덕 위 이끼 낀 참 벽돌 탑 군"]},"ja":{"name":"ポークロンガライ塔","summary":"チャウの丘の上の雄大なチャム塔群。チャム族の建築物と信仰の遺跡の中で最も完全な姿で残ります。","story":"ポークロンガライ塔はチャウの丘の上にそびえ立ち、治水に功績を残し人々に灌漑を教えたポークロンガライ王を祀るため13世紀末に築かれたチャム塔群です。今日最も美しく完全な姿で残るチャンパ寺塔群とされ、20メートルを超える本塔、火塔、門塔からなります。赤い煉瓦の塔身には、シヴァ神や聖牛ナンディン、そして一筋一筋まで精巧に刻まれた文様が無数に広がります。塔は建築遺産であるだけでなく、生きた信仰の中心でもあり、チャム族が毎年秋に神聖なカテー祭を催し、ギナンの太鼓の音と優雅な扇の舞で賑やかに彩ります。","facts":["チャム王ポークロンガライの時代、13世紀末に建立。","ベトナムで最も完全な姿で残るチャム寺塔群。","特別国家建築芸術遺跡。","毎年チャム族のカテー祭が行われる地。","本塔の内部にはリンガ（ムカリンガ）の姿の王像が祀られている。"],"travelTips":["特色ある儀礼を見るには、カテー祭（9〜10月頃）に立ち寄りましょう。","斜めの日差しが煉瓦塔を美しく染める涼しい午後に行きましょう。"],"bestTime":"1月〜9月、カテー祭の季節が最も美しい","visitDuration":"1〜2時間","ticket":"20,000ドン","openingHours":"07:00 - 17:00","galleryCaptions":["チャウの丘の上の本塔","チャム族のカテー祭","草の丘の上の苔むしたチャム煉瓦塔群"]},"zh":{"name":"婆克朗加莱塔","summary":"矗立于槟榔丘上的雄伟占族塔群，是占族保存最完整的建筑与信仰遗迹之一。","story":"婆克朗加莱塔巍然矗立于槟榔丘之上，是建于13世纪末、为供奉治水有功并教民兴修水利的婆克朗加莱王而建的占族塔群。它被视为当今最美、保存最完整的占婆庙塔群，由二十余米高的主塔、火塔与门塔组成。赭红的砖塔身上，遍布湿婆神、神牛南迪的浮雕，以及雕刻精细入微的纹样。塔群不仅是建筑遗产，更是活的信仰中心，占族每逢秋季在此举办神圣的卡特节，吉囊鼓声与婉转的扇舞热闹非凡。","facts":["建于13世纪末，占族王婆克朗加莱时期。","越南保存最完整的占族庙塔群。","国家级特别建筑艺术遗迹。","占族每年举办卡特节之地。","主塔内供奉林伽（面林伽）形态的王像。"],"travelTips":["在卡特节期间（约9至10月）造访，可观赏独特的祭祀仪式。","选凉爽的午后前往，斜阳为砖塔染上绝美的色泽。"],"bestTime":"1月至9月，卡特节期间最美","visitDuration":"1至2小时","ticket":"20,000越南盾","openingHours":"07:00 - 17:00","galleryCaptions":["槟榔丘上的主塔","占族的卡特节","草丘上斑驳青苔的占族砖塔群"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ktm-nha-tho-go', 'nha-tho-go-kon-tum', 'kon-tum', 'Nhà thờ gỗ Kon Tum', 'Kon Tum Wooden Church', 'temple', 108.005, 14.3528, 'Nhà thờ Chính tòa hơn trăm tuổi làm hoàn toàn bằng gỗ, kết hợp tinh tế kiến trúc Roman và nhà sàn Tây Nguyên.', 'Nhà thờ gỗ Kon Tum là viên ngọc kiến trúc giữa lòng phố núi, được các linh mục người Pháp khởi dựng năm 1913 hoàn toàn bằng gỗ cà chít quý hiếm. Công trình là sự giao thoa độc đáo giữa phong cách Roman cổ kính của phương Tây và nét mộc mạc của nhà sàn đồng bào Ba Na bản địa. Toàn bộ khung gỗ được kết nối bằng mộng mà không dùng đến một cây đinh, trải qua hơn một thế kỷ vẫn vững chãi, vàng óng dưới nắng cao nguyên. Bước vào bên trong, ánh sáng len qua những ô cửa kính màu nhuộm không gian thành một dải lung linh huyền ảo. Sân nhà thờ rợp bóng cây, là nơi đồng bào các dân tộc tụ họp mỗi dịp lễ, lưu giữ trọn vẹn hồn cốt văn hóa Tây Nguyên trong từng thớ gỗ.', '["Được xây dựng năm 1913 bởi các linh mục người Pháp.","Làm hoàn toàn bằng gỗ cà chít, ghép mộng không dùng đinh.","Kết hợp kiến trúc Roman và phong cách nhà sàn Ba Na.","Là nhà thờ Chính tòa của giáo phận Kon Tum.","Khung gỗ và tường được kết dính bằng vữa trộn rơm truyền thống."]', '["Ghé buổi chiều khi nắng nghiêng làm thân gỗ và cửa kính lên màu đẹp.","Giữ yên tĩnh và trang phục lịch sự khi vào bên trong thánh đường."]', 'Tháng 11 đến tháng 4', '1 giờ', '', 'Cả ngày (lễ theo lịch nhà thờ)', '["popular","verified"]', '["temple","history","culture","city","photography"]', '[{"seed":"nhathogo-mattien","caption":"Mặt tiền nhà thờ gỗ trăm tuổi","ratio":"16/9"},{"seed":"nhathogo-noithat","caption":"Không gian gỗ và cửa kính màu bên trong","ratio":"4/3"},{"seed":"nhathogo-thapchuong","caption":"Tháp chuông vươn cao giữa phố núi","ratio":"1/1"}]', '["ktm-mang-den"]', 1, '{"en":{"name":"Kon Tum Wooden Church","summary":"A century-old cathedral built entirely of wood, finely blending Romanesque architecture with Central Highlands stilt houses.","story":"The Kon Tum Wooden Church is an architectural gem in the heart of the mountain town, begun by French priests in 1913 entirely of rare ca chit wood. The building is a unique fusion of the West''s ancient Romanesque style and the rustic stilt houses of the local Bahnar people. The entire wooden frame is joined by mortise and tenon without a single nail, and after more than a century it still stands firm, golden under the highland sun. Step inside, and light filters through stained-glass windows, bathing the space in a shimmering, magical glow. The church courtyard is shaded by trees, a gathering place for the ethnic peoples on each festival, preserving the very soul of Central Highlands culture in every grain of wood.","facts":["Built in 1913 by French priests.","Made entirely of ca chit wood, joined by mortise and tenon without nails.","Blends Romanesque architecture with Bahnar stilt-house style.","The cathedral of the Kon Tum diocese.","The wooden frame and walls are bound with traditional straw-mixed mortar."],"travelTips":["Visit in the afternoon when slanting light brings out the color of the wood and glass.","Stay quiet and dress modestly when entering the sanctuary."],"bestTime":"November to April","visitDuration":"1 hour","ticket":"","openingHours":"All day (services per the church schedule)","galleryCaptions":["The facade of the century-old wooden church","The wooden interior with stained-glass windows","The bell tower rising above the mountain town"]},"ko":{"name":"꼰뚬 목조 성당","summary":"백 년이 넘은 전체 목조 주교좌 성당으로, 로마네스크 건축과 떠이응우옌 고상가옥을 섬세하게 결합했습니다.","story":"꼰뚬 목조 성당은 산간 도시 한복판의 건축 보석으로, 프랑스 신부들이 1913년 귀한 까칫 나무로 전체를 짓기 시작했습니다. 이 건축물은 서구의 고풍스러운 로마네스크 양식과 토착 바나족 고상가옥의 소박함이 어우러진 독특한 융합입니다. 목조 골조 전체가 못 하나 없이 장부맞춤으로 이어져, 한 세기가 넘도록 견고하게 서서 고원의 햇살에 황금빛으로 빛납니다. 안으로 들어서면 스테인드글라스 창으로 스민 빛이 공간을 영롱하고 신비로운 빛결로 물들입니다. 나무 그늘 드리운 성당 마당은 명절마다 여러 민족이 모이는 곳으로, 나뭇결 하나하나에 떠이응우옌 문화의 혼을 온전히 간직하고 있습니다.","facts":["1913년 프랑스 신부들이 건립.","전체를 까칫 나무로 짓고 못 없이 장부맞춤으로 결구.","로마네스크 건축과 바나족 고상가옥 양식을 결합.","꼰뚬 교구의 주교좌 성당.","목조 골조와 벽은 전통 방식으로 짚을 섞은 회반죽으로 접착."],"travelTips":["비스듬한 햇살이 나무와 유리에 색을 입히는 오후에 들르세요.","성당 내부에서는 정숙하고 단정한 복장을 갖추세요."],"bestTime":"11월~4월","visitDuration":"1시간","ticket":"","openingHours":"종일 (미사는 성당 일정에 따름)","galleryCaptions":["백 년 된 목조 성당의 정면","스테인드글라스 창이 있는 목조 내부","산간 도시 위로 솟은 종탑"]},"ja":{"name":"コントゥム木造教会","summary":"百年を超える総木造の司教座聖堂。ロマネスク建築とタイグエン高原の高床式家屋を繊細に融合させています。","story":"コントゥム木造教会は山あいの町の真ん中に佇む建築の宝石で、フランス人神父たちが1913年に貴重なカチットの木で総木造で建て始めました。この建築は西洋の古風なロマネスク様式と、土着のバナ族の高床式家屋の素朴さが溶け合った独特の融合です。木の骨組み全体が釘を一本も使わず仕口で組まれ、一世紀を超えてなお堅固に立ち、高原の日差しに黄金色に輝きます。中に入れば、ステンドグラスの窓から射し込む光が空間を煌めく幻想的な光の帯に染めます。木陰の教会の庭は、祭りのたびに諸民族が集う場で、木目の一つ一つにタイグエン高原文化の魂を余すところなく宿しています。","facts":["1913年にフランス人神父たちが建立。","総カチットの木造で、釘を使わず仕口で組まれている。","ロマネスク建築とバナ族の高床式家屋様式を融合。","コントゥム教区の司教座聖堂。","木の骨組みと壁は伝統的な藁混じりの漆喰で接着されている。"],"travelTips":["斜めの日差しが木とガラスに色を添える午後に立ち寄りましょう。","聖堂の内部では静粛にし、礼儀正しい服装を心がけましょう。"],"bestTime":"11月〜4月","visitDuration":"1時間","ticket":"","openingHours":"終日（ミサは教会の予定による）","galleryCaptions":["百年を経た木造教会の正面","ステンドグラスの窓がある木造の内部","山あいの町にそびえる鐘楼"]},"zh":{"name":"昆嵩木教堂","summary":"一座逾百年的全木造主教座堂，精妙融合罗马式建筑与西原长屋风格。","story":"昆嵩木教堂是山城中心的一颗建筑明珠，由法国神父于1913年用珍稀的格栗木全木建造。这座建筑是西方古朴的罗马式风格与本土巴拿族长屋质朴气韵的独特交融。整座木构架以榫卯相连，未用一根铁钉，历经一个多世纪依然稳固，在高原阳光下泛着金黄。步入其中，光线透过彩色玻璃窗，将空间染成一片绚丽梦幻的光影。绿树成荫的教堂庭院是各民族每逢节庆相聚之处，在每一道木纹中完整地守护着西原文化的灵魂。","facts":["1913年由法国神父建造。","全部以格栗木建成，榫卯相接，未用铁钉。","融合罗马式建筑与巴拿族长屋风格。","昆嵩教区的主教座堂。","木构架与墙体以传统掺草灰浆黏合。"],"travelTips":["午后造访，斜阳为木材与彩窗染上美丽色泽。","进入圣堂内部请保持安静、着装得体。"],"bestTime":"11月至4月","visitDuration":"1小时","ticket":"","openingHours":"全天（弥撒依教堂时间）","galleryCaptions":["百年木教堂的正面","内部的木构与彩色玻璃窗","高耸于山城之上的钟楼"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ktm-mang-den', 'khu-du-lich-mang-den', 'kon-tum', 'Khu du lịch Măng Đen', 'Mang Den Resort Area', 'mountain', 108.2853, 14.63, 'Đà Lạt thứ hai của Tây Nguyên với rừng thông bạt ngàn, thác nước, hồ trong và khí hậu se lạnh quanh năm.', 'Nằm ở độ cao hơn một nghìn hai trăm mét, Măng Đen được ví như ''Đà Lạt thứ hai'' của Tây Nguyên với rừng thông nguyên sinh bạt ngàn và khí hậu mát lạnh quanh năm. Buổi sớm, sương mù giăng kín những con dốc thông, không gian tĩnh lặng và trong lành đến lạ. Vùng đất này được thiên nhiên hào phóng ban tặng những hồ nước phẳng lặng, các con thác trắng xóa như thác Pa Sỹ, cùng những vườn hoa, đồi chè xanh mướt. Măng Đen còn linh thiêng với tượng Đức Mẹ giữa rừng thông, thu hút đông đảo khách hành hương. Người Mơ Nâm, Xơ Đăng bản địa vẫn giữ nếp sống mộc mạc, mến khách. Đến Măng Đen là tìm về chốn bình yên, để hít căng lồng ngực hương thông và quên đi mọi muộn phiền.', '["Nằm ở độ cao khoảng 1.200m, khí hậu mát mẻ quanh năm.","Được mệnh danh là ''Đà Lạt thứ hai'' của Tây Nguyên.","Có thác Pa Sỹ, hồ Đăk Ke và nhiều rừng thông đẹp.","Tượng Đức Mẹ Măng Đen là điểm hành hương nổi tiếng.","Thuộc huyện Kon Plông, cách thành phố Kon Tum khoảng 50 km."]', '["Mang theo áo ấm vì đêm và sáng sớm ở Măng Đen khá lạnh.","Thuê xe máy hoặc ô tô để di chuyển giữa các điểm tham quan cách xa nhau."]', 'Tháng 11 đến tháng 3, mùa hoa và sương mù', '2 ngày 1 đêm', '', 'Cả ngày', '["trending","new","ai-recommended"]', '["mountain","nature","photography","food"]', '[{"seed":"mangden-thong","caption":"Thác nước trắng xóa đổ xuống hồ xanh giữa rừng","ratio":"16/9"},{"seed":"mangden-pasy","caption":"Thác Pa Sỹ trắng xóa giữa rừng","ratio":"4/3"},{"seed":"mangden-ho","caption":"Hồ Đăk Ke phẳng lặng buổi sớm","ratio":"1/1"}]', '["ktm-nha-tho-go"]', 0, '{"en":{"name":"Mang Den Tourist Area","summary":"The ''second Da Lat'' of the Central Highlands with vast pine forests, waterfalls, clear lakes, and cool weather year-round.","story":"Sitting at over twelve hundred meters, Mang Den is likened to the ''second Da Lat'' of the Central Highlands, with vast primeval pine forests and cool weather year-round. In the early morning, fog blankets the pine-covered slopes, the space strangely still and pure. This land is generously blessed with placid lakes, white waterfalls like Pa Sy Falls, and flower gardens and green tea hills. Mang Den is also sacred, with a statue of the Virgin Mary amid the pines drawing crowds of pilgrims. The local Mo Nam and Xo Dang peoples still keep their rustic, hospitable way of life. To visit Mang Den is to return to a place of peace, to fill your lungs with the scent of pine and forget every worry.","facts":["Sits at about 1,200m altitude, with cool weather year-round.","Dubbed the ''second Da Lat'' of the Central Highlands.","Has Pa Sy Falls, Dak Ke Lake, and many beautiful pine forests.","The Mang Den Virgin Mary statue is a famous pilgrimage site.","In Kon Plong district, about 50 km from Kon Tum city."],"travelTips":["Bring warm clothing as nights and early mornings in Mang Den are quite cold.","Rent a motorbike or car to travel between the far-apart attractions."],"bestTime":"November to March, the flower and fog season","visitDuration":"2 days 1 night","ticket":"","openingHours":"All day","galleryCaptions":["A white waterfall tumbling into a green lake amid the forest","Pa Sy Falls white amid the forest","Placid Dak Ke Lake in the early morning"]},"ko":{"name":"망덴 관광지","summary":"끝없는 소나무 숲과 폭포, 맑은 호수, 사계절 서늘한 기후를 지닌 떠이응우옌의 ''제2의 달랏''입니다.","story":"해발 천이백 미터가 넘는 곳에 자리한 망덴은 끝없는 원시 소나무 숲과 사계절 서늘한 기후로 떠이응우옌의 ''제2의 달랏''이라 불립니다. 새벽이면 안개가 소나무 비탈을 가득 덮어 공간이 신기할 만큼 고요하고 청량합니다. 이 땅은 잔잔한 호수, 빠시 폭포처럼 하얀 폭포들, 그리고 꽃밭과 푸른 차밭을 자연으로부터 넉넉히 선사받았습니다. 망덴은 소나무 숲 속 성모상으로 신성하기도 해 수많은 순례객을 끌어모읍니다. 토착 머넘족과 써당족은 여전히 소박하고 손님을 반기는 삶을 지킵니다. 망덴을 찾는 것은 평온한 곳으로 돌아가 소나무 향을 가슴 가득 들이켜고 온갖 시름을 잊는 일입니다.","facts":["해발 약 1,200m, 사계절 서늘한 기후.","떠이응우옌의 ''제2의 달랏''이라 불림.","빠시 폭포, 닥께 호수, 아름다운 소나무 숲이 많음.","망덴 성모상은 유명한 순례지.","꼰쁠롱 현 소속, 꼰뚬 시에서 약 50km."],"travelTips":["망덴의 밤과 새벽은 꽤 추우니 따뜻한 옷을 챙기세요.","멀리 떨어진 관광지 사이를 다니려면 오토바이나 차를 빌리세요."],"bestTime":"11월~3월, 꽃과 안개의 계절","visitDuration":"1박 2일","ticket":"","openingHours":"종일","galleryCaptions":["숲 속 푸른 호수로 쏟아지는 하얀 폭포","숲 속 하얗게 부서지는 빠시 폭포","이른 아침 잔잔한 닥께 호수"]},"ja":{"name":"マンデン観光地","summary":"果てしない松林、滝、澄んだ湖、一年中ひんやりした気候を持つタイグエン高原の「第二のダラット」です。","story":"標高千二百メートルを超える地に位置するマンデンは、果てしない原生の松林と一年中ひんやりした気候から、タイグエン高原の「第二のダラット」と称されます。早朝には霧が松の坂を覆い尽くし、空間は不思議なほど静かで清らかです。この地は、静かな湖、パシー滝のような白い滝の数々、そして花畑や青々とした茶畑を自然から惜しみなく授かりました。マンデンは松林の中の聖母像で神聖でもあり、多くの巡礼者を引き寄せます。土着のモナム族やセダン族は今も素朴で客を歓ぶ暮らしを守っています。マンデンを訪れることは、安らぎの地へと帰り、松の香りを胸いっぱいに吸い込み、あらゆる憂いを忘れることです。","facts":["標高約1,200mに位置し、一年中涼しい気候。","タイグエン高原の「第二のダラット」と称される。","パシー滝、ダクケ湖、美しい松林が多い。","マンデンの聖母像は有名な巡礼地。","コンプロン県に属し、コントゥム市から約50km。"],"travelTips":["マンデンの夜と早朝はかなり冷えるので、暖かい服を持参しましょう。","離れた観光地の間を移動するにはバイクか車を借りましょう。"],"bestTime":"11月〜3月、花と霧の季節","visitDuration":"1泊2日","ticket":"","openingHours":"終日","galleryCaptions":["森の中の青い湖へ流れ落ちる白い滝","森の中で白く砕けるパシー滝","早朝の静かなダクケ湖"]},"zh":{"name":"芒登旅游区","summary":"西原的「第二大叻」，拥有无边松林、瀑布、清湖与四季微凉的气候。","story":"海拔逾一千二百米的芒登，因无边的原始松林与四季微凉的气候，被誉为西原的「第二大叻」。清晨，雾气笼罩松坡，空间静谧清新得出奇。这片土地被自然慷慨赐予平静的湖泊、如巴西瀑布般雪白的瀑布，以及花园与青翠茶丘。芒登还因松林中的圣母像而显神圣，吸引众多朝圣者。本地的莫南族、色登族至今保持着质朴好客的生活。来到芒登，便是回归一处宁静之地，将松香深吸入肺，忘却一切烦忧。","facts":["位于海拔约1200米处，四季凉爽。","被誉为西原的「第二大叻」。","有巴西瀑布、达克客湖及众多优美松林。","芒登圣母像是著名的朝圣地。","隶属昆普隆县，距昆嵩市约50公里。"],"travelTips":["芒登夜晚与清晨颇为寒凉，请携带保暖衣物。","各景点相距较远，建议租用摩托车或汽车出行。"],"bestTime":"11月至3月，花季与雾季","visitDuration":"2天1夜","ticket":"","openingHours":"全天","galleryCaptions":["林间倾泻入碧湖的雪白瀑布","林中雪白的巴西瀑布","清晨平静的达克客湖"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('gli-bien-ho-tnung', 'bien-ho-tnung', 'gia-lai', 'Biển Hồ T''Nưng', 'T''Nung Lake (Bien Ho)', 'lake', 108.01, 14.0581, 'Hồ nước ngọt mênh mông trên miệng núi lửa cổ, được ví như ''đôi mắt Pleiku'' xanh trong giữa đại ngàn.', 'Biển Hồ T''Nưng là viên ngọc bích giữa cao nguyên Pleiku, một hồ nước ngọt rộng lớn hình thành từ miệng núi lửa đã ngủ yên hàng triệu năm. Người ta gọi nơi đây là ''đôi mắt Pleiku'' bởi mặt hồ xanh thẳm, trong veo, phản chiếu mây trời và những hàng thông reo vi vu trong gió. Con đường dẫn ra hồ rợp bóng thông cổ thụ, dẫn tới một đài vọng cảnh nhô ra mặt nước, nơi du khách phóng tầm mắt ôm trọn không gian bao la, tĩnh lặng. Buổi bình minh, sương mỏng giăng trên mặt hồ, từng đàn chim ríu rít, khung cảnh đẹp như tranh thủy mặc. Biển Hồ gắn với những truyền thuyết bi thương của người Gia Rai, càng tô thêm vẻ huyền bí và thơ mộng cho thắng cảnh trứ danh của phố núi.', '["Hình thành từ miệng núi lửa cổ đã ngừng hoạt động.","Được mệnh danh là ''đôi mắt Pleiku'' và đi vào thơ ca, âm nhạc.","Là hồ nước ngọt tự nhiên lớn, cung cấp nước cho thành phố Pleiku.","Cách trung tâm Pleiku khoảng 7 km về phía bắc.","Gần đó có hàng thông trăm tuổi và đồi chè Biển Hồ nổi tiếng."]', '["Đến lúc bình minh hoặc hoàng hôn để ngắm mặt hồ đẹp nhất.","Kết hợp ghé hàng thông trăm tuổi và đồi chè gần Biển Hồ."]', 'Tháng 11 đến tháng 4', '2 - 3 giờ', '', 'Cả ngày', '["popular","verified","trending"]', '["lake","nature","photography"]', '[{"seed":"bienho-matho","caption":"Mặt hồ xanh thẳm giữa đại ngàn","ratio":"16/9"},{"seed":"bienho-vongcanh","caption":"Đài vọng cảnh nhô ra mặt nước","ratio":"4/3"},{"seed":"bienho-thong","caption":"Hàng thông cổ thụ dẫn ra hồ","ratio":"1/1"}]', '["gli-chua-minh-thanh"]', 1, '{"en":{"name":"T''Nung Sea Lake","summary":"A vast freshwater lake on an ancient crater, likened to the ''eyes of Pleiku'' set blue and clear amid the great wilderness.","story":"T''Nung Sea Lake is an emerald jewel on the Pleiku plateau, a large freshwater lake formed from a crater that has slumbered for millions of years. People call it the ''eyes of Pleiku'' for its deep blue, clear surface reflecting the sky and the pines whispering in the wind. The road to the lake is shaded by ancient pines, leading to a viewing pavilion that juts over the water, where visitors take in the vast, still expanse. At dawn, thin mist drapes the lake''s surface, birds chirp in flocks, and the scene is as beautiful as an ink-wash painting. The lake is tied to the tragic legends of the Jarai people, adding to the mystery and poetry of this celebrated landmark of the mountain town.","facts":["Formed from an ancient, dormant crater.","Dubbed the ''eyes of Pleiku'' and immortalized in poetry and music.","A large natural freshwater lake supplying water to Pleiku city.","About 7 km north of central Pleiku.","Nearby are the century-old pine rows and the famous Sea Lake tea hills."],"travelTips":["Visit at dawn or dusk to see the lake at its most beautiful.","Combine a stop at the century-old pine rows and tea hills near the Sea Lake."],"bestTime":"November to April","visitDuration":"2 - 3 hours","ticket":"","openingHours":"All day","galleryCaptions":["The deep-blue lake surface amid the great wilderness","A viewing pavilion jutting over the water","Ancient pine rows leading to the lake"]},"ko":{"name":"비엔호 트능 호수","summary":"고대 분화구 위 드넓은 담수호로, 대자연 속 맑고 푸른 ''쁠래이꾸의 두 눈''이라 불립니다.","story":"비엔호 트능은 쁠래이꾸 고원의 비취 보석으로, 수백만 년 잠든 분화구에서 형성된 드넓은 담수호입니다. 사람들은 이곳을 ''쁠래이꾸의 두 눈''이라 부르는데, 깊고 맑은 호수면이 하늘과 바람에 일렁이는 소나무를 비추기 때문입니다. 호수로 가는 길은 고목 소나무 그늘이 드리워 물 위로 뻗은 전망대로 이어지고, 그곳에서 여행객은 드넓고 고요한 풍경을 한눈에 담습니다. 새벽이면 엷은 안개가 호수면에 드리우고 새들이 지저귀며, 풍경은 수묵화처럼 아름답습니다. 비엔호는 자라이족의 애틋한 전설과 얽혀 산간 도시의 명소에 신비와 시정을 더합니다.","facts":["활동을 멈춘 고대 분화구에서 형성.","''쁠래이꾸의 두 눈''이라 불리며 시와 음악에 등장.","쁠래이꾸 시에 물을 공급하는 큰 천연 담수호.","쁠래이꾸 중심에서 북쪽으로 약 7km.","인근에 백 년 된 소나무 길과 유명한 비엔호 차밭이 있음."],"travelTips":["호수면이 가장 아름다운 일출이나 일몰에 가세요.","비엔호 인근의 백 년 된 소나무 길과 차밭을 함께 들르세요."],"bestTime":"11월~4월","visitDuration":"2~3시간","ticket":"","openingHours":"종일","galleryCaptions":["대자연 속 깊고 푸른 호수면","물 위로 뻗은 전망대","호수로 이어지는 고목 소나무 길"]},"ja":{"name":"ビエンホー・トゥヌン湖","summary":"古代の噴火口の上の広大な淡水湖。大自然の中で青く澄んだ「プレイクの両眼」と称されます。","story":"ビエンホー・トゥヌンはプレイク高原の翡翠の宝石で、数百万年眠る噴火口から形成された広大な淡水湖です。人々はここを「プレイクの両眼」と呼びますが、それは深く澄んだ湖面が空と、風にそよぐ松を映すからです。湖へ続く道は古木の松の陰に覆われ、水面へ突き出た展望台へと続き、そこで旅人は広く静かな景色を一望します。夜明けには薄い霧が湖面に立ちこめ、鳥がさえずり、その景色は水墨画のように美しい。ビエンホーはジャライ族の哀しい伝説と結びつき、山あいの町の名所に神秘と詩情を添えます。","facts":["活動を止めた古代の噴火口から形成。","「プレイクの両眼」と称され、詩や音楽に登場。","プレイク市に水を供給する大きな天然淡水湖。","プレイク中心部から北へ約7km。","近くに百年を経た松並木と有名なビエンホー茶畑がある。"],"travelTips":["湖面が最も美しい日の出か日の入りに行きましょう。","ビエンホー近くの百年の松並木と茶畑も合わせて立ち寄りましょう。"],"bestTime":"11月〜4月","visitDuration":"2〜3時間","ticket":"","openingHours":"終日","galleryCaptions":["大自然の中の深く青い湖面","水面へ突き出た展望台","湖へ続く古木の松並木"]},"zh":{"name":"特能海湖","summary":"古老火山口上的辽阔淡水湖，被誉为大山深处湛蓝清澈的「波来古之眼」。","story":"特能海湖是波来古高原上的一颗碧玉，是由沉睡数百万年的火山口形成的辽阔淡水湖。人们称之为「波来古之眼」，因为那深蓝清澈的湖面，倒映着天空与随风低吟的松林。通往湖畔的道路掩映在古松浓荫之下，通向一座探出水面的观景台，旅人在此放眼，将辽阔静谧的景致尽收眼底。清晨，薄雾笼罩湖面，群鸟啁啾，景色美如水墨画。海湖与嘉莱族凄美的传说相连，为这山城名胜更添几分神秘与诗意。","facts":["由停止活动的古火山口形成。","被誉为「波来古之眼」，并入诗入歌。","是一座大型天然淡水湖，为波来古市供水。","距波来古市中心以北约7公里。","附近有百年松林与著名的海湖茶丘。"],"travelTips":["在日出或日落时分前往，欣赏最美的湖面。","可结合游览海湖附近的百年松林与茶丘。"],"bestTime":"11月至4月","visitDuration":"2至3小时","ticket":"","openingHours":"全天","galleryCaptions":["大山深处深蓝的湖面","探出水面的观景台","通往湖畔的古松林荫道"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('gli-chua-minh-thanh', 'chua-minh-thanh', 'gia-lai', 'Chùa Minh Thành', 'Minh Thanh Pagoda', 'temple', 107.9925, 13.965, 'Ngôi chùa lộng lẫy mang đậm phong cách kiến trúc Nhật Bản và Đài Loan, biểu tượng tâm linh của phố núi Pleiku.', 'Chùa Minh Thành nổi bật giữa phố núi Pleiku với lối kiến trúc độc đáo, gợi nhớ những ngôi chùa cổ kính của Nhật Bản và Đài Loan hơn là chùa Việt truyền thống. Điểm nhấn của chùa là bảo tháp xá lợi cao chín tầng vươn lên trời xanh, cùng chánh điện uy nghi với những đường mái cong vút, cột gỗ chạm trổ tinh xảo và tượng Phật dát vàng trang nghiêm. Khuôn viên chùa rộng rãi, thoáng đãng, điểm xuyết hồ nước, vườn cây và những bức tượng Phật, La Hán sống động. Mỗi góc nhỏ đều được chăm chút tỉ mỉ, hài hòa giữa thiên nhiên và kiến trúc tâm linh. Đến đây, lữ khách không chỉ chiêm bái mà còn đắm mình trong không gian tĩnh tại, an nhiên, bỏ lại sau lưng những bộn bề của cuộc sống thường nhật.', '["Mang phong cách kiến trúc Phật giáo Nhật Bản và Đài Loan.","Bảo tháp xá lợi cao 9 tầng là điểm nhấn nổi bật.","Khởi dựng từ năm 1964 và được trùng tu, mở rộng nhiều lần.","Cách trung tâm thành phố Pleiku khoảng 2 km.","Chánh điện có nhiều tượng Phật và La Hán được chạm khắc công phu."]', '["Mặc trang phục kín đáo, lịch sự khi vào khu vực chánh điện.","Đến buổi sáng để chụp ảnh chùa với ánh nắng đẹp và ít người."]', 'Tháng 11 đến tháng 4', '1 - 2 giờ', '', '06:00 - 20:00', '["popular","verified"]', '["temple","culture","city","photography"]', '[{"seed":"minhthanh-baothap","caption":"Bảo tháp xá lợi chín tầng","ratio":"16/9"},{"seed":"minhthanh-chanhdien","caption":"Chánh điện mái cong uy nghi","ratio":"4/3"},{"seed":"minhthanh-tuong","caption":"Tượng Phật dát vàng trong khuôn viên","ratio":"1/1"}]', '["gli-bien-ho-tnung"]', 0, '{"en":{"name":"Minh Thanh Pagoda","summary":"A magnificent pagoda steeped in Japanese and Taiwanese architectural style, a spiritual symbol of the mountain town of Pleiku.","story":"Minh Thanh Pagoda stands out in the mountain town of Pleiku with its unique architecture, evoking the ancient pagodas of Japan and Taiwan more than traditional Vietnamese temples. Its highlight is a nine-story relic stupa soaring into the blue sky, along with the majestic main hall with sweeping curved roofs, intricately carved wooden pillars, and a solemn gilded Buddha statue. The grounds are spacious and airy, dotted with ponds, gardens, and lively statues of Buddhas and Arhats. Every little corner is meticulously cared for, harmonizing nature with spiritual architecture. Here, travelers not only worship but also immerse themselves in a tranquil, serene space, leaving behind the burdens of everyday life.","facts":["Built in Japanese and Taiwanese Buddhist architectural style.","The nine-story relic stupa is a striking highlight.","Founded in 1964 and restored and expanded many times.","About 2 km from central Pleiku city.","The main hall has many elaborately carved Buddha and Arhat statues."],"travelTips":["Dress modestly and respectfully when entering the main hall area.","Visit in the morning to photograph the pagoda in beautiful light with fewer people."],"bestTime":"November to April","visitDuration":"1 - 2 hours","ticket":"","openingHours":"06:00 - 20:00","galleryCaptions":["The nine-story relic stupa","The majestic curved-roof main hall","A gilded Buddha statue in the grounds"]},"ko":{"name":"민탄 사원","summary":"일본과 대만 건축 양식이 짙게 밴 화려한 사원으로, 산간 도시 쁠래이꾸의 정신적 상징입니다.","story":"민탄 사원은 전통 베트남 사찰보다 일본과 대만의 고풍스러운 사원을 연상시키는 독특한 건축으로 산간 도시 쁠래이꾸에서 단연 돋보입니다. 사원의 백미는 푸른 하늘로 솟은 9층 사리탑과, 우아하게 굽은 처마와 정교하게 조각된 목조 기둥, 엄숙한 금빛 불상이 어우러진 위풍당당한 대웅전입니다. 넓고 탁 트인 경내는 연못, 정원, 그리고 생동감 넘치는 불상과 나한상으로 단장되어 있습니다. 구석구석 정성스레 가꾸어져 자연과 신앙 건축이 조화를 이룹니다. 이곳에서 여행객은 참배할 뿐 아니라 고요하고 평온한 공간에 잠겨 일상의 짐을 내려놓습니다.","facts":["일본과 대만 불교 건축 양식을 지님.","9층 사리탑이 돋보이는 백미.","1964년 창건되어 여러 차례 보수·확장.","쁠래이꾸 시 중심에서 약 2km.","대웅전에는 정교하게 조각된 불상과 나한상이 많음."],"travelTips":["대웅전 구역에 들어갈 때는 단정하고 정숙한 복장을 갖추세요.","아름다운 햇살에 사람도 적은 아침에 사원 사진을 찍으세요."],"bestTime":"11월~4월","visitDuration":"1~2시간","ticket":"","openingHours":"06:00 - 20:00","galleryCaptions":["9층 사리탑","위풍당당한 굽은 처마의 대웅전","경내의 금빛 불상"]},"ja":{"name":"ミンタイン寺","summary":"日本と台湾の建築様式が色濃い華麗な寺院。山あいの町プレイクの精神的シンボルです。","story":"ミンタイン寺は、伝統的なベトナムの寺院よりも日本や台湾の古風な寺院を思わせる独特の建築で、山あいの町プレイクで際立っています。寺の見どころは青空へそびえる九層の舎利塔と、優雅に反った軒、精巧に彫られた木の柱、荘厳な金箔の仏像が調和した堂々たる本堂です。広々とした境内は池や庭、生き生きとした仏像や羅漢像で彩られています。隅々まで丹念に手入れされ、自然と信仰の建築が調和しています。ここで旅人は参拝するだけでなく、静謐で安らかな空間に浸り、日常の重荷を背に置いていきます。","facts":["日本と台湾の仏教建築様式を持つ。","九層の舎利塔が際立つ見どころ。","1964年に創建され、幾度も改修・拡張された。","プレイク市中心部から約2km。","本堂には精巧に彫られた仏像や羅漢像が多い。"],"travelTips":["本堂の区域に入る際は、礼儀正しく控えめな服装を心がけましょう。","美しい日差しで人も少ない朝に寺の写真を撮りましょう。"],"bestTime":"11月〜4月","visitDuration":"1〜2時間","ticket":"","openingHours":"06:00 - 20:00","galleryCaptions":["九層の舎利塔","堂々たる反り屋根の本堂","境内の金箔の仏像"]},"zh":{"name":"明成寺","summary":"一座华美的寺院，浓郁地融汇日本与台湾的建筑风格，是山城波来古的精神象征。","story":"明成寺在山城波来古以独特的建筑格外醒目，比起传统越南寺院，它更令人想起日本与台湾的古刹。寺院的亮点是直插青空的九层舍利塔，以及威严的大殿——飞檐高翘，木柱精雕细琢，庄严的镀金佛像安坐其中。寺院庭院宽敞通透，点缀着水池、园林与栩栩如生的佛像、罗汉像。每一处小角落都精心打理，让自然与信仰建筑相得益彰。来到此处，旅人不仅可以朝拜，更能沉浸于宁静安详的空间，将日常的纷扰抛诸脑后。","facts":["采用日本与台湾佛教建筑风格。","九层舍利塔是格外醒目的亮点。","始建于1964年，历经多次修缮与扩建。","距波来古市中心约2公里。","大殿内有众多精雕细琢的佛像与罗汉像。"],"travelTips":["进入大殿区域时请着装端庄得体。","上午前往，光线优美、游人较少，宜于拍照。"],"bestTime":"11月至4月","visitDuration":"1至2小时","ticket":"","openingHours":"06:00 - 20:00","galleryCaptions":["九层舍利塔","威严的飞檐大殿","庭院中的镀金佛像"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dno-cong-vien-dia-chat', 'cong-vien-dia-chat-dak-nong', 'dak-nong', 'Công viên địa chất toàn cầu Đắk Nông', 'Dak Nong UNESCO Global Geopark', 'park', 107.69, 12.264, 'Công viên địa chất toàn cầu UNESCO với hệ thống hang động núi lửa dài nhất Đông Nam Á và cảnh quan núi lửa kỳ vĩ.', 'Công viên địa chất toàn cầu Đắk Nông được UNESCO công nhận năm 2020, là kho báu địa chất trải rộng trên sáu huyện với diện tích hơn bốn nghìn cây số vuông. Điểm độc đáo bậc nhất là hệ thống hang động núi lửa trong đá bazan dài và đẹp nhất Đông Nam Á, được hình thành từ những dòng dung nham phun trào cách đây hàng triệu năm. Bên cạnh đó là các miệng núi lửa cổ, thác nước hùng vĩ, hồ nước trong xanh và những cánh rừng nguyên sinh trù phú. Vùng đất này còn lưu giữ dấu tích của người tiền sử cùng kho tàng văn hóa đặc sắc của đồng bào M''Nông, Mạ với không gian văn hóa cồng chiêng Tây Nguyên. Đắk Nông là điểm đến lý tưởng cho những ai đam mê khám phá thiên nhiên và lịch sử kiến tạo của Trái Đất.', '["Được UNESCO công nhận là Công viên địa chất toàn cầu năm 2020.","Sở hữu hệ thống hang động núi lửa dài nhất Đông Nam Á.","Trải rộng trên 6 huyện với diện tích hơn 4.700 km².","Gắn với Không gian văn hóa cồng chiêng Tây Nguyên - di sản UNESCO.","Có 3 tuyến du lịch trải nghiệm với hàng chục điểm di sản."]', '["Thuê hướng dẫn viên địa phương khi khám phá hệ thống hang động núi lửa.","Mang đèn pin, giày bám tốt và mũ bảo hộ khi vào hang dung nham."]', 'Tháng 11 đến tháng 4, mùa khô', '2 - 3 ngày', 'Tùy điểm tham quan', '07:00 - 17:00', '["unesco","trending","verified","ai-recommended"]', '["park","nature","history","culture","mountain"]', '[{"seed":"daknong-hangnui","caption":"Hang động núi lửa trong đá bazan","ratio":"16/9"},{"seed":"daknong-miengnui","caption":"Miệng núi lửa cổ giữa rừng xanh","ratio":"4/3"},{"seed":"daknong-congchieng","caption":"Văn hóa cồng chiêng đồng bào M''Nông","ratio":"1/1"}]', '["dno-thac-dray-sap"]', 1, '{"en":{"name":"Dak Nong UNESCO Global Geopark","summary":"A UNESCO Global Geopark with the longest volcanic cave system in Southeast Asia and majestic volcanic landscapes.","story":"The Dak Nong UNESCO Global Geopark, recognized by UNESCO in 2020, is a geological treasure spread across six districts over more than four thousand square kilometers. Its most remarkable feature is the system of volcanic caves in basalt rock, the longest and most beautiful in Southeast Asia, formed from lava flows that erupted millions of years ago. Alongside it are ancient craters, majestic waterfalls, clear blue lakes, and lush primeval forests. This land also preserves traces of prehistoric people and the distinctive cultural treasures of the M''Nong and Ma peoples with the Central Highlands gong cultural space. Dak Nong is an ideal destination for those who love exploring nature and the tectonic history of the Earth.","facts":["Recognized by UNESCO as a Global Geopark in 2020.","Home to the longest volcanic cave system in Southeast Asia.","Spread across 6 districts over more than 4,700 km².","Tied to the Central Highlands Gong Cultural Space - a UNESCO heritage.","Has 3 experiential tourism routes with dozens of heritage sites."],"travelTips":["Hire a local guide when exploring the volcanic cave system.","Bring a flashlight, grippy shoes, and a safety helmet when entering the lava caves."],"bestTime":"November to April, the dry season","visitDuration":"2 - 3 days","ticket":"Depends on the site","openingHours":"07:00 - 17:00","galleryCaptions":["A volcanic cave in basalt rock","An ancient crater amid green forest","Gong culture of the M''Nong people"]},"ko":{"name":"닥농 유네스코 세계지질공원","summary":"동남아시아에서 가장 긴 화산 동굴계와 웅장한 화산 경관을 지닌 유네스코 세계지질공원입니다.","story":"닥농 유네스코 세계지질공원은 2020년 유네스코에 등재되었으며, 여섯 개 현을 아우르며 사천 평방킬로미터가 넘게 펼쳐진 지질의 보고입니다. 가장 돋보이는 특징은 수백만 년 전 분출한 용암류로 형성된, 동남아시아에서 가장 길고 아름다운 현무암 화산 동굴계입니다. 그 곁으로 고대 분화구, 웅장한 폭포, 맑고 푸른 호수, 그리고 울창한 원시림이 펼쳐집니다. 이 땅은 또한 선사인의 흔적과 떠이응우옌 공 문화 공간을 비롯한 므농족·마족의 독특한 문화 보고를 간직하고 있습니다. 닥농은 자연 탐험과 지구 형성의 역사를 사랑하는 이들에게 이상적인 목적지입니다.","facts":["2020년 유네스코 세계지질공원으로 등재.","동남아시아에서 가장 긴 화산 동굴계를 보유.","6개 현에 걸쳐 4,700km² 넘게 펼쳐짐.","유네스코 유산인 떠이응우옌 공 문화 공간과 연결.","수십 개 유산지를 잇는 3개 체험 관광 노선이 있음."],"travelTips":["화산 동굴계를 탐험할 때는 현지 가이드를 고용하세요.","용암 동굴에 들어갈 때는 손전등, 접지력 좋은 신발, 안전모를 챙기세요."],"bestTime":"11월~4월, 건기","visitDuration":"2~3일","ticket":"관광지에 따라 다름","openingHours":"07:00 - 17:00","galleryCaptions":["현무암 속 화산 동굴","푸른 숲 속 고대 분화구","므농족의 공 문화"]},"ja":{"name":"ダクノン・ユネスコ世界ジオパーク","summary":"東南アジア最長の火山洞窟系と雄大な火山景観を持つユネスコ世界ジオパークです。","story":"ダクノン・ユネスコ世界ジオパークは2020年にユネスコに登録され、六つの県にまたがり四千平方キロメートルを超えて広がる地質の宝庫です。最も際立つ特徴は、数百万年前に噴火した溶岩流から形成された、東南アジアで最も長く美しい玄武岩の火山洞窟系です。その傍らには古代の噴火口、雄大な滝、澄んだ青い湖、そして鬱蒼とした原生林が広がります。この地はまた、先史人の痕跡と、タイグエン高原の銅鑼文化空間をはじめとするムノン族・マ族の独特な文化の宝庫を留めています。ダクノンは、自然探検と地球の形成の歴史を愛する人々にとって理想の目的地です。","facts":["2020年にユネスコ世界ジオパークに登録。","東南アジア最長の火山洞窟系を有する。","6つの県にまたがり4,700km²を超えて広がる。","ユネスコ遺産であるタイグエン高原の銅鑼文化空間と結びつく。","数十の遺産地を結ぶ3つの体験観光ルートがある。"],"travelTips":["火山洞窟系を探検する際は現地ガイドを雇いましょう。","溶岩洞窟に入る際は懐中電灯、グリップの良い靴、ヘルメットを持参しましょう。"],"bestTime":"11月〜4月、乾季","visitDuration":"2〜3日","ticket":"観光地により異なる","openingHours":"07:00 - 17:00","galleryCaptions":["玄武岩の中の火山洞窟","緑の森の中の古代噴火口","ムノン族の銅鑼文化"]},"zh":{"name":"得农联合国教科文组织世界地质公园","summary":"拥有东南亚最长火山洞穴系统与雄伟火山景观的联合国教科文组织世界地质公园。","story":"得农世界地质公园于2020年获联合国教科文组织认证，是一座横跨六县、面积逾四千平方公里的地质宝库。其最为独特之处，是玄武岩中那东南亚最长、最美的火山洞穴系统，由数百万年前喷发的熔岩流形成。与之相伴的还有古火山口、雄伟瀑布、碧蓝清湖以及苍郁的原始森林。这片土地还留存着史前人类的遗迹，以及墨侬族、麻族独特的文化瑰宝与西原铜锣文化空间。得农是热爱探索自然与地球构造历史之人的理想之地。","facts":["2020年获联合国教科文组织认证为世界地质公园。","拥有东南亚最长的火山洞穴系统。","横跨6县，面积逾4700平方公里。","与联合国教科文组织遗产西原铜锣文化空间相连。","设有3条体验旅游线路，串联数十处遗产景点。"],"travelTips":["探索火山洞穴系统时请聘请当地向导。","进入熔岩洞时请携带手电筒、抓地力好的鞋与安全帽。"],"bestTime":"11月至4月，旱季","visitDuration":"2至3天","ticket":"视景点而定","openingHours":"07:00 - 17:00","galleryCaptions":["玄武岩中的火山洞穴","青林中的古火山口","墨侬族的铜锣文化"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dno-thac-dray-sap', 'thac-dray-sap', 'dak-nong', 'Thác Dray Sáp', 'Dray Sap Waterfall', 'waterfall', 107.9483, 12.5394, 'Thác ''khói'' hùng vĩ giữa rừng nguyên sinh, dòng nước tung bọt trắng xóa tạo màn sương mờ ảo quanh năm.', 'Thác Dray Sáp, theo tiếng Ê Đê nghĩa là ''thác khói'', là một trong những ngọn thác đẹp và hùng vĩ nhất Tây Nguyên. Từ trên cao, dòng sông Sêrêpốk đổ xuống vách đá bazan rộng hàng trăm mét, nước tung bọt trắng xóa va vào ghềnh đá tạo nên màn hơi nước mịt mù như khói sương, vì thế mà thành tên. Bao quanh thác là cánh rừng nguyên sinh rậm rạp với những thân cây cổ thụ, dây leo chằng chịt và bầu không khí mát lạnh, trong lành. Đứng trước thác, tiếng nước gầm vang dội cả một vùng, khiến lữ khách choáng ngợp trước sức mạnh hoang dã của thiên nhiên. Dray Sáp gắn liền với truyền thuyết tình yêu đẹp mà buồn của đôi trai gái Ê Đê, làm say lòng bao người đặt chân đến chốn đại ngàn kỳ vĩ này.', '["Tên ''Dray Sáp'' theo tiếng Ê Đê nghĩa là ''thác khói''.","Nằm trên dòng sông Sêrêpốk chảy ngược về phía tây.","Là một trong những thác lớn và đẹp nhất Tây Nguyên.","Nằm trong cụm thác Dray Sáp - Gia Long - Dray Nur.","Thuộc Công viên địa chất toàn cầu Đắk Nông."]', '["Đến vào mùa mưa (tháng 7-10) để ngắm thác cuộn trào hùng vĩ nhất.","Mang giày chống trượt vì đường xuống chân thác khá trơn và ẩm."]', 'Tháng 7 đến tháng 11 thác nhiều nước nhất', 'Nửa ngày', '30.000đ', '07:00 - 17:00', '["popular","verified","hidden-gem"]', '["waterfall","nature","photography","mountain"]', '[{"seed":"draysap-thac","caption":"Thác Dray Sáp tung bọt trắng xóa","ratio":"16/9"},{"seed":"draysap-khoi","caption":"Màn sương khói quanh chân thác","ratio":"4/3"},{"seed":"draysap-rung","caption":"Rừng nguyên sinh bao quanh thác","ratio":"1/1"}]', '["dno-cong-vien-dia-chat"]', 0, '{"en":{"name":"Dray Sap Waterfall","summary":"A majestic ''smoke'' waterfall amid primeval forest, its white spray creating a hazy mist year-round.","story":"Dray Sap Waterfall, meaning ''smoke waterfall'' in the Ede language, is one of the most beautiful and majestic falls in the Central Highlands. From high above, the Serepok River pours over a basalt cliff hundreds of meters wide, the water throwing up white spray against the rocks to create a hazy mist like smoke, hence the name. Surrounding the falls is dense primeval forest with ancient trees, tangled vines, and cool, fresh air. Standing before the falls, the roar of the water echoes across the whole region, leaving travelers awed by the wild power of nature. Dray Sap is tied to the beautiful yet sorrowful love legend of an Ede couple, captivating all who set foot in this majestic wilderness.","facts":["The name ''Dray Sap'' means ''smoke waterfall'' in the Ede language.","Lies on the Serepok River, which flows westward.","One of the largest and most beautiful falls in the Central Highlands.","Part of the Dray Sap - Gia Long - Dray Nur waterfall cluster.","Within the Dak Nong UNESCO Global Geopark."],"travelTips":["Visit in the rainy season (July–October) to see the falls at their most majestic.","Bring non-slip shoes as the path down to the foot of the falls is slippery and damp."],"bestTime":"July to November, when the falls have the most water","visitDuration":"Half a day","ticket":"30,000 VND","openingHours":"07:00 - 17:00","galleryCaptions":["Dray Sap Waterfall throwing up white spray","The misty haze around the foot of the falls","The primeval forest surrounding the falls"]},"ko":{"name":"드라이삽 폭포","summary":"원시림 속 웅장한 ''연기'' 폭포로, 하얀 물보라가 사계절 자욱한 물안개를 자아냅니다.","story":"에데어로 ''연기 폭포''를 뜻하는 드라이삽 폭포는 떠이응우옌에서 가장 아름답고 웅장한 폭포 중 하나입니다. 높은 곳에서 세레폭강이 수백 미터 폭의 현무암 절벽으로 쏟아지며, 물이 바위에 부딪쳐 하얀 물보라를 일으키고 연기처럼 자욱한 물안개를 만들어 그 이름이 붙었습니다. 폭포를 둘러싼 울창한 원시림에는 고목과 얽힌 덩굴, 그리고 서늘하고 청량한 공기가 가득합니다. 폭포 앞에 서면 물소리가 온 지역에 울려 퍼져, 여행객은 자연의 야성적인 힘에 압도됩니다. 드라이삽은 에데족 한 쌍의 아름답고도 애틋한 사랑 전설과 얽혀, 이 웅장한 대자연에 발 디딘 이들의 마음을 사로잡습니다.","facts":["''드라이삽''은 에데어로 ''연기 폭포''를 뜻함.","서쪽으로 흐르는 세레폭강에 위치.","떠이응우옌에서 가장 크고 아름다운 폭포 중 하나.","드라이삽 - 자롱 - 드라이누르 폭포 군에 속함.","닥농 유네스코 세계지질공원 내에 위치."],"travelTips":["폭포가 가장 웅장한 우기(7~10월)에 가세요.","폭포 아래로 가는 길이 미끄럽고 축축하니 미끄럼 방지 신발을 신으세요."],"bestTime":"7월~11월, 폭포 수량이 가장 많은 시기","visitDuration":"반나절","ticket":"30,000동","openingHours":"07:00 - 17:00","galleryCaptions":["하얀 물보라를 흩뿌리는 드라이삽 폭포","폭포 아래 자욱한 물안개","폭포를 둘러싼 원시림"]},"ja":{"name":"ドライサップ滝","summary":"原生林の中の雄大な「煙」の滝。白い飛沫が一年中もやのような水煙を作り出します。","story":"エデ語で「煙の滝」を意味するドライサップ滝は、タイグエン高原で最も美しく雄大な滝の一つです。高い所からセレポック川が幅数百メートルの玄武岩の崖へと流れ落ち、水が岩に砕けて白い飛沫を立て、煙のようにもやがかった水煙を作り出すことから、その名がつきました。滝を囲む鬱蒼とした原生林には古木や絡み合う蔓、そしてひんやりと清らかな空気が満ちています。滝の前に立てば水音が一帯に響き渡り、旅人は自然の野性的な力に圧倒されます。ドライサップはエデ族の一組の美しくも哀しい愛の伝説と結びつき、この雄大な大自然に足を踏み入れた人々の心を捉えます。","facts":["「ドライサップ」はエデ語で「煙の滝」を意味する。","西へ流れるセレポック川に位置する。","タイグエン高原で最も大きく美しい滝の一つ。","ドライサップ - ザーロン - ドライヌル滝群に属する。","ダクノン・ユネスコ世界ジオパーク内に位置。"],"travelTips":["滝が最も雄大な雨季（7〜10月）に行きましょう。","滝の下へ降りる道は滑りやすく湿っているので滑り止めの靴を履きましょう。"],"bestTime":"7月〜11月、滝の水量が最も多い時期","visitDuration":"半日","ticket":"30,000ドン","openingHours":"07:00 - 17:00","galleryCaptions":["白い飛沫を散らすドライサップ滝","滝の下のもやがかった水煙","滝を囲む原生林"]},"zh":{"name":"德雷萨瀑布","summary":"原始森林中雄伟的「烟」瀑布，雪白水花常年弥漫成朦胧水雾。","story":"德雷萨瀑布在埃地语中意为「烟瀑布」，是西原最美、最雄伟的瀑布之一。色雷波河自高处倾泻而下，越过宽达数百米的玄武岩崖壁，水花撞击岩石溅起雪白，弥漫成如烟似雾的水气，因而得名。瀑布四周是茂密的原始森林，古树参天，藤蔓交织，空气清凉宜人。立于瀑前，水声轰鸣回荡整片山野，令旅人惊叹于大自然狂野的力量。德雷萨与一对埃地族男女凄美的爱情传说相连，令每一位踏足这雄伟大山的人为之倾心。","facts":["「德雷萨」在埃地语中意为「烟瀑布」。","位于向西流淌的色雷波河上。","西原最大、最美的瀑布之一。","属于德雷萨 - 嘉龙 - 德雷努瀑布群。","位于得农世界地质公园内。"],"travelTips":["在雨季（7至10月）前往，可观赏瀑布最雄伟磅礴之态。","通往瀑底的路湿滑，请穿防滑鞋。"],"bestTime":"7月至11月，瀑布水量最丰","visitDuration":"半天","ticket":"30,000越南盾","openingHours":"07:00 - 17:00","galleryCaptions":["溅起雪白水花的德雷萨瀑布","瀑底朦胧的水雾","环绕瀑布的原始森林"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('vung-tau-bai-bien-tuong-chua', 'bai-bien-vung-tau-tuong-chua', 'ba-ria-vung-tau', 'Bãi biển Vũng Tàu & Tượng Chúa Kitô', 'Vung Tau Beach & Christ the King Statue', 'beach', 107.0843, 10.3349, 'Thành phố biển gần Sài Gòn với bãi tắm dài và tượng Chúa Kitô khổng lồ trên đỉnh Núi Nhỏ.', 'Vũng Tàu là thành phố biển thân quen của người Sài Gòn, chỉ cách trung tâm vài giờ xe. Bãi Sau trải dài cát vàng, sóng êm, đông vui mỗi cuối tuần; Bãi Trước lại lặng lẽ với hàng dừa nghiêng đón hoàng hôn. Trên đỉnh Núi Nhỏ, tượng Chúa Kitô cao 32 mét dang tay nhìn ra biển, du khách leo gần 800 bậc thang để lên tới chân tượng và phóng tầm mắt khắp thành phố. Hải sản tươi rói, gió biển mặn mòi và những con đường ven biển làm nên một Vũng Tàu hào sảng, phóng khoáng rất Nam Bộ.', '["Tượng Chúa Kitô Vũng Tàu cao 32 mét, hoàn thành năm 1994.","Bên trong tượng có cầu thang xoắn dẫn lên hai cánh tay dang rộng.","Bãi Sau (Thùy Vân) là bãi tắm chính, dài hơn 8 km.","Hải đăng Vũng Tàu xây từ năm 1862 là một trong những ngọn cổ nhất Việt Nam."]', '["Leo lên tượng Chúa vào sáng sớm để tránh nắng và đông người.","Thử bánh khọt Vũng Tàu, đặc sản trứ danh của thành phố."]', 'Tháng 11 đến tháng 4 (mùa khô, biển êm)', '1–2 ngày', '', 'Tượng Chúa: 07:00–17:00', '["popular","trending","verified"]', '["beach","city","nature","food","photography"]', '[{"seed":"vungtau-baisau","caption":"Bãi Sau cát vàng đông vui","ratio":"16/9"},{"seed":"vungtau-christ","caption":"Tượng Chúa Kitô trên Núi Nhỏ","ratio":"4/3"},{"seed":"vungtau-banhkhot","caption":"Bánh khọt giòn rụm đặc sản","ratio":"1/1"}]', '["con-dao"]', 1, '{"en":{"name":"Vung Tau Beach & Christ the King Statue","summary":"A seaside city near Saigon with a long beach and a giant statue of Christ atop Small Mountain.","story":"Vung Tau is Saigon''s familiar seaside getaway, just a few hours'' drive from the center. Back Beach stretches along golden sand with gentle waves, crowded every weekend; Front Beach is quieter, with leaning coconut palms welcoming the sunset. Atop Small Mountain, the 32-meter Christ the King statue stretches its arms toward the sea—visitors climb nearly 800 steps to reach its feet and take in views across the city. Fresh seafood, the salty sea breeze and coastal roads make for a Vung Tau that is generous and free-spirited, true to the southern soul.","facts":["The Christ the King statue in Vung Tau stands 32 meters tall, completed in 1994.","Inside the statue, a spiral staircase leads up to its two outstretched arms.","Back Beach (Thuy Van) is the main bathing beach, over 8 km long.","Vung Tau Lighthouse, built in 1862, is one of the oldest in Vietnam."],"travelTips":["Climb to the Christ statue early in the morning to avoid the heat and crowds.","Try banh khot, Vung Tau''s famous local specialty."],"bestTime":"November to April (dry season, calm seas)","visitDuration":"1–2 days","ticket":"","openingHours":"Christ statue: 07:00–17:00","galleryCaptions":["Golden-sand Back Beach, lively and crowded","Christ the King statue on Small Mountain","Crispy banh khot, the local specialty"]},"ko":{"name":"붕따우 해변 & 예수상","summary":"긴 해변과 작은 산 정상의 거대한 예수상이 있는, 사이공 인근의 해변 도시.","story":"붕따우는 시내에서 차로 몇 시간이면 닿는, 사이공 사람들에게 친숙한 해변 도시입니다. 뒤쪽 해변은 금빛 모래가 길게 펼쳐지고 파도가 잔잔해 주말마다 붐비고, 앞쪽 해변은 야자수가 기울어진 채 석양을 맞이하는 한적한 곳입니다. 작은 산 정상에는 높이 32미터의 예수상이 두 팔을 벌려 바다를 바라보고 있으며, 여행객은 약 800개의 계단을 올라 상의 발치에 닿아 도시 전경을 굽어봅니다. 싱싱한 해산물과 짭조름한 바닷바람, 해안 도로가 어우러져 남부 특유의 호방하고 자유로운 붕따우를 만듭니다.","facts":["붕따우 예수상은 높이 32미터로 1994년에 완공되었습니다.","상 내부에는 두 팔로 이어지는 나선 계단이 있습니다.","뒤쪽 해변(투이번)은 길이 8km가 넘는 주요 해수욕장입니다.","1862년에 세워진 붕따우 등대는 베트남에서 가장 오래된 등대 중 하나입니다."],"travelTips":["더위와 인파를 피하려면 이른 아침에 예수상에 올라가세요.","붕따우의 명물 특산품인 반콧을 맛보세요."],"bestTime":"11월~4월 (건기, 잔잔한 바다)","visitDuration":"1~2일","ticket":"","openingHours":"예수상: 07:00–17:00","galleryCaptions":["활기차고 붐비는 금빛 모래 뒤쪽 해변","작은 산 위의 예수상","바삭한 특산품 반콧"]},"ja":{"name":"ブンタウのビーチ＆キリスト像","summary":"長いビーチと小山の頂に立つ巨大なキリスト像を擁する、サイゴン近郊の海辺の街。","story":"ブンタウは市内から車で数時間の、サイゴンの人々にとって馴染み深い海辺の街です。バックビーチは黄金の砂浜が長く伸び、波も穏やかで週末ごとに賑わい、フロントビーチは傾いたヤシの並木が夕日を迎える静かな浜です。小山の頂には高さ32メートルのキリスト像が両腕を広げて海を見渡し、旅人は約800段の階段を登って像の足元に達し、街全体を一望します。新鮮な海の幸、潮の香る海風、海沿いの道が、南部らしい大らかで自由なブンタウを形づくっています。","facts":["ブンタウのキリスト像は高さ32メートルで、1994年に完成しました。","像の内部には両腕へと続く螺旋階段があります。","バックビーチ（トゥイヴァン）は全長8kmを超える主要な海水浴場です。","1862年に建てられたブンタウ灯台は、ベトナム最古の灯台のひとつです。"],"travelTips":["暑さと混雑を避けるため、キリスト像へは早朝に登りましょう。","ブンタウ名物の特産品バインコットを味わってみましょう。"],"bestTime":"11月〜4月（乾季、海が穏やか）","visitDuration":"1〜2日","ticket":"","openingHours":"キリスト像：07:00–17:00","galleryCaptions":["賑わう黄金の砂浜のバックビーチ","小山の上のキリスト像","さくさくの名物バインコット"]},"zh":{"name":"头顿海滩与基督像","summary":"西贡近郊的海滨城市，拥有绵长的海滩和矗立在小山顶上的巨型基督像。","story":"头顿是西贡人熟悉的海滨城市，距市中心仅数小时车程。后滩金沙绵延、海浪平缓，每逢周末便人头攒动；前滩则较为静谧，椰林斜倚迎接落日。小山顶上，高32米的基督像张开双臂俯瞰大海，游客攀登近800级台阶抵达像脚，将全城风光尽收眼底。新鲜的海产、咸润的海风和滨海大道，共同造就了一个豪爽奔放、极具南部风情的头顿。","facts":["头顿基督像高32米，于1994年建成。","像内有螺旋楼梯通往张开的双臂。","后滩（瑞云滩）是主要海水浴场，绵延8公里以上。","头顿灯塔建于1862年，是越南最古老的灯塔之一。"],"travelTips":["清晨登基督像，可避开烈日与人潮。","尝一尝头顿的招牌特产小煎饼（bánh khọt）。"],"bestTime":"11月至4月（旱季，海面平静）","visitDuration":"1–2天","ticket":"","openingHours":"基督像：07:00–17:00","galleryCaptions":["热闹的金沙后滩","小山上的基督像","酥脆的招牌小煎饼"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('con-dao', 'con-dao', 'ba-ria-vung-tau', 'Côn Đảo', 'Con Dao Islands', 'island', 106.6062, 8.6831, 'Quần đảo hoang sơ giữa Biển Đông, nổi tiếng với bãi biển nguyên sơ, hệ sinh thái biển và di tích nhà tù lịch sử.', 'Côn Đảo là quần đảo gồm 16 hòn đảo lớn nhỏ nằm ngoài khơi Biển Đông, từng được mệnh danh là ''địa ngục trần gian'' với hệ thống nhà tù khắc nghiệt thời thực dân. Ngày nay, Côn Đảo hồi sinh thành điểm đến tâm linh và sinh thái bậc nhất: nghĩa trang Hàng Dương với mộ chị Võ Thị Sáu linh thiêng, những bãi biển nước trong vắt, rạn san hô và rùa biển lên đẻ trứng mỗi mùa. Vẻ đẹp tĩnh lặng, trầm mặc xen lẫn hoang sơ khiến Côn Đảo trở thành nơi vừa để chiêm nghiệm vừa để nghỉ dưỡng giữa thiên nhiên thuần khiết.', '["Vườn quốc gia Côn Đảo bảo tồn rùa biển và rạn san hô quý hiếm.","Nghĩa trang Hàng Dương là nơi an nghỉ của hàng nghìn tù nhân yêu nước.","Du khách thường viếng mộ chị Võ Thị Sáu vào lúc nửa đêm.","Côn Đảo từng được tạp chí du lịch quốc tế bình chọn là đảo bí ẩn nhất thế giới."]', '["Đặt vé máy bay hoặc tàu cao tốc sớm vì lượng khách giới hạn.","Mang theo đồ lễ giản dị nếu muốn viếng nghĩa trang Hàng Dương ban đêm."]', 'Tháng 3 đến tháng 9 (biển lặng, dễ ra đảo nhỏ)', '2–3 ngày', '', 'Cả ngày', '["hidden-gem","verified","ai-recommended"]', '["island","beach","nature","history","photography"]', '[{"seed":"condao-beach","caption":"Bãi biển nước trong nguyên sơ","ratio":"16/9"},{"seed":"condao-prison","caption":"Di tích nhà tù Côn Đảo","ratio":"4/3"},{"seed":"condao-hangduong","caption":"Nghĩa trang Hàng Dương linh thiêng","ratio":"1/1"}]', '["vung-tau-bai-bien-tuong-chua"]', 0, '{"en":{"name":"Con Dao","summary":"A pristine archipelago in the East Sea, famous for untouched beaches, marine ecosystems and historic prison relics.","story":"Con Dao is an archipelago of 16 islands large and small lying off the East Sea, once known as ''hell on earth'' for its brutal colonial-era prison system. Today, Con Dao has been reborn as one of the country''s foremost spiritual and ecological destinations: the sacred Hang Duong Cemetery with the revered grave of Vo Thi Sau, crystal-clear beaches, coral reefs and sea turtles that come ashore to lay eggs each season. Its tranquil, contemplative beauty mingled with wildness makes Con Dao a place both for reflection and for resting amid pure nature.","facts":["Con Dao National Park protects sea turtles and rare coral reefs.","Hang Duong Cemetery is the resting place of thousands of patriotic prisoners.","Visitors often pay respects at Vo Thi Sau''s grave at midnight.","Con Dao was once voted the world''s most mysterious island by an international travel magazine."],"travelTips":["Book flights or fast-ferry tickets early, as visitor numbers are limited.","Bring simple offerings if you wish to visit Hang Duong Cemetery at night."],"bestTime":"March to September (calm seas, easy to reach the smaller islands)","visitDuration":"2–3 days","ticket":"","openingHours":"All day","galleryCaptions":["A pristine beach with clear water","Con Dao Prison relic","The sacred Hang Duong Cemetery"]},"ko":{"name":"꼰다오","summary":"동해(비엔동) 한가운데의 청정 군도로, 원시 해변과 해양 생태계, 역사적인 감옥 유적으로 유명합니다.","story":"꼰다오는 동해 앞바다에 자리한 크고 작은 16개 섬으로 이루어진 군도로, 식민지 시기 혹독한 감옥 체계 때문에 한때 ''지상의 지옥''이라 불렸습니다. 오늘날 꼰다오는 베트남 최고의 영적·생태 여행지로 되살아났습니다. 보티사우의 영험한 묘소가 있는 항즈엉 묘지, 투명한 바다, 산호초, 그리고 철마다 알을 낳으러 뭍에 오르는 바다거북이 있습니다. 고요하고 사색적인 아름다움과 원시성이 어우러져, 꼰다오는 사색하기에도 순수한 자연 속에서 쉬기에도 좋은 곳이 되었습니다.","facts":["꼰다오 국립공원은 바다거북과 희귀 산호초를 보호합니다.","항즈엉 묘지는 수천 명의 애국 수감자들이 잠든 곳입니다.","여행객들은 흔히 자정에 보티사우의 묘소를 참배합니다.","꼰다오는 한 국제 여행 잡지에서 세계에서 가장 신비로운 섬으로 선정된 적이 있습니다."],"travelTips":["방문객 수가 제한되므로 항공편이나 고속선 표를 일찍 예매하세요.","밤에 항즈엉 묘지를 참배하려면 소박한 제물을 준비하세요."],"bestTime":"3월~9월 (바다가 잔잔해 작은 섬에 가기 좋음)","visitDuration":"2~3일","ticket":"","openingHours":"종일","galleryCaptions":["물이 맑은 원시 해변","꼰다오 감옥 유적","영험한 항즈엉 묘지"]},"ja":{"name":"コンダオ","summary":"東海（ビエンドン）の只中にある手つかずの群島。原始的なビーチ、海洋生態系、歴史的な監獄遺跡で知られます。","story":"コンダオは東海の沖合に浮かぶ大小16の島からなる群島で、植民地時代の過酷な監獄制度ゆえに、かつて「地上の地獄」と呼ばれました。今日のコンダオは、ベトナム随一の精神性と生態の旅先として蘇りました。ヴォ・ティ・サウの霊験あらたかな墓があるハンズオン墓地、透き通った海、サンゴ礁、そして季節ごとに産卵に上陸するウミガメがいます。静謐で思索的な美しさと野生味が混ざり合い、コンダオは思索の場であると同時に、純粋な自然の中で憩う場ともなっています。","facts":["コンダオ国立公園はウミガメと希少なサンゴ礁を保護しています。","ハンズオン墓地は数千人の愛国的な囚人たちが眠る場所です。","旅人はしばしば真夜中にヴォ・ティ・サウの墓へ参拝します。","コンダオはかつて国際的な旅行雑誌で世界一神秘的な島に選ばれました。"],"travelTips":["来訪者数に限りがあるため、航空券や高速船のチケットは早めに予約しましょう。","夜にハンズオン墓地を参拝したい場合は、簡素な供物を持参しましょう。"],"bestTime":"3月〜9月（海が穏やかで小島へ渡りやすい）","visitDuration":"2〜3日","ticket":"","openingHours":"終日","galleryCaptions":["水の澄んだ手つかずのビーチ","コンダオ監獄の遺跡","霊験あらたかなハンズオン墓地"]},"zh":{"name":"昆岛","summary":"东海之中的原始群岛，以纯净的海滩、海洋生态系统和历史监狱遗迹而闻名。","story":"昆岛是东海海面上由16座大小岛屿组成的群岛，曾因殖民时期严酷的监狱体系而被称为「人间地狱」。如今，昆岛已重生为越南顶尖的灵性与生态旅游胜地：杭阳公墓中武氏六灵验的墓冢、清澈见底的海滩、珊瑚礁，以及每逢时令上岸产卵的海龟。宁静肃穆的美与原始野趣交织，使昆岛既适合静思冥想，又适合在纯净的自然中休憩。","facts":["昆岛国家公园保护海龟与珍稀珊瑚礁。","杭阳公墓是数千名爱国囚徒的长眠之地。","游客常在午夜拜谒武氏六之墓。","昆岛曾被国际旅游杂志评为世界上最神秘的岛屿。"],"travelTips":["由于游客名额有限，请尽早预订机票或高速船票。","若想夜间拜谒杭阳公墓，请备好简朴的供品。"],"bestTime":"3月至9月（海面平静，便于前往小岛）","visitDuration":"2–3天","ticket":"","openingHours":"全天","galleryCaptions":["水清原始的海滩","昆岛监狱遗迹","灵验的杭阳公墓"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('cat-tien-national-park', 'vuon-quoc-gia-cat-tien', 'dong-nai', 'Vườn quốc gia Cát Tiên', 'Cat Tien National Park', 'park', 107.4286, 11.4231, 'Khu dự trữ sinh quyển rộng lớn với rừng nhiệt đới nguyên sinh, đa dạng động thực vật và khu cứu hộ gấu, voọc.', 'Vườn quốc gia Cát Tiên trải rộng trên ba tỉnh, là một trong những khu rừng nhiệt đới nguyên sinh quý giá nhất còn sót lại ở Nam Bộ. Đây là khu dự trữ sinh quyển được UNESCO công nhận, mái nhà của hàng trăm loài chim, thú quý như voi, bò tót, vượn đen má vàng. Du khách đạp xe xuyên rừng tới cây tung cổ thụ ngàn năm, chèo thuyền trên Bàu Sấu ngắm cá sấu hoang dã, hay ghé Trung tâm cứu hộ Linh trưởng và gấu. Đêm xuống, tour soi đèn tìm thú hoang mang lại cảm giác phiêu lưu giữa thiên nhiên hoang dã đậm chất rừng già.', '["Cát Tiên được UNESCO công nhận là khu dự trữ sinh quyển thế giới năm 2001.","Bàu Sấu là vùng đất ngập nước Ramsar quan trọng quốc tế.","Vườn là nơi cư trú của loài tê giác Java cuối cùng ở Việt Nam (đã tuyệt chủng năm 2010).","Cây tung cổ thụ trong rừng có bộ rễ bạnh khổng lồ nổi tiếng."]', '["Đặt tour soi thú đêm và chèo thuyền Bàu Sấu trước với ban quản lý vườn.","Mang giày leo núi, áo dài tay và thuốc chống vắt khi đi rừng sâu."]', 'Tháng 12 đến tháng 5 (mùa khô, dễ di chuyển trong rừng)', '1–2 ngày', '60.000đ', '07:00–17:00', '["unesco","verified","ai-recommended"]', '["park","nature","photography"]', '[{"seed":"cattien-forest","caption":"Rừng nguyên sinh xanh thẳm","ratio":"16/9"},{"seed":"cattien-bausau","caption":"Hoàng hôn vàng rực, thuyền nhỏ trôi trên mặt hồ","ratio":"4/3"},{"seed":"cattien-tung","caption":"Gà rừng kiếm ăn trên thảm lá khô","ratio":"1/1"}]', '["thac-giang-dien"]', 1, '{"en":{"name":"Cat Tien National Park","summary":"A vast biosphere reserve of primary tropical forest, rich biodiversity and a rescue center for bears and langurs.","story":"Cat Tien National Park spreads across three provinces and is one of the most precious patches of primary tropical forest remaining in southern Vietnam. A UNESCO-recognized biosphere reserve, it is home to hundreds of rare bird and mammal species such as elephants, gaurs and yellow-cheeked gibbons. Visitors cycle through the forest to a thousand-year-old tung tree, paddle on Crocodile Lake to watch wild crocodiles, or visit the Primate and Bear Rescue Center. After dark, a spotlight tour in search of wildlife brings a sense of adventure deep in the ancient forest.","facts":["Cat Tien was recognized by UNESCO as a world biosphere reserve in 2001.","Crocodile Lake (Bau Sau) is an internationally important Ramsar wetland.","The park was home to Vietnam''s last Javan rhinoceros (declared extinct in 2010).","Its ancient tung tree is famous for its enormous buttress roots."],"travelTips":["Book the night wildlife-spotting tour and Crocodile Lake paddle in advance with park management.","Bring hiking shoes, long sleeves and anti-leech repellent for deep forest treks."],"bestTime":"December to May (dry season, easier travel within the forest)","visitDuration":"1–2 days","ticket":"60,000 VND","openingHours":"07:00–17:00","galleryCaptions":["Deep-green primary forest","Golden sunset, a small boat drifting on the lake","A jungle fowl foraging on the carpet of dry leaves"]},"ko":{"name":"깟띠엔 국립공원","summary":"원시 열대우림과 풍부한 동식물, 곰·랑구르 구조 센터를 갖춘 광활한 생물권 보전지역.","story":"깟띠엔 국립공원은 세 개 성에 걸쳐 펼쳐진, 남부 베트남에 남은 가장 귀중한 원시 열대우림 중 하나입니다. 유네스코가 인정한 생물권 보전지역으로, 코끼리·들소·노란뺨긴팔원숭이 같은 수백 종의 희귀 조류와 포유류의 보금자리입니다. 여행객은 숲을 가로질러 자전거를 타고 천 년 된 퉁나무 고목을 찾아가거나, 악어 호수에서 배를 저으며 야생 악어를 보거나, 영장류·곰 구조 센터에 들릅니다. 밤이 내리면 야생동물을 찾는 손전등 투어가 깊은 원시림 속 모험의 감각을 선사합니다.","facts":["깟띠엔은 2001년 유네스코 세계 생물권 보전지역으로 인정받았습니다.","악어 호수(바우사우)는 국제적으로 중요한 람사르 습지입니다.","이 공원은 베트남 마지막 자바코뿔소의 서식지였습니다(2010년 멸종 선언).","숲 속의 퉁나무 고목은 거대한 판근으로 유명합니다."],"travelTips":["야간 동물 탐사 투어와 바우사우 보트 체험은 공원 관리소에 미리 예약하세요.","깊은 숲을 걸을 때는 등산화와 긴소매 옷, 거머리 방지제를 챙기세요."],"bestTime":"12월~5월 (건기, 숲 안에서 이동이 수월함)","visitDuration":"1~2일","ticket":"60,000동","openingHours":"07:00–17:00","galleryCaptions":["짙푸른 원시림","황금빛 노을, 호수 위를 떠가는 작은 배","마른 낙엽 위에서 먹이를 찾는 들닭"]},"ja":{"name":"カットティエン国立公園","summary":"原生熱帯林と豊かな動植物、クマやドゥクラングールの保護センターを擁する広大な生物圏保護区。","story":"カットティエン国立公園は三つの省にまたがって広がり、南部ベトナムに残された最も貴重な原生熱帯林のひとつです。ユネスコに認定された生物圏保護区であり、ゾウ、ガウル、キバホオテナガザルなど数百種の希少な鳥獣の棲み家です。旅人は森を貫いて自転車をこぎ、樹齢千年のトゥンの巨木を訪ね、ワニ湖で舟を漕いで野生のワニを眺め、霊長類・クマ保護センターに立ち寄ります。夜が訪れると、野生動物を探すスポットライト・ツアーが、原生林の奥深くでの冒険の感覚をもたらします。","facts":["カットティエンは2001年にユネスコ世界生物圏保護区に認定されました。","ワニ湖（バウサウ）は国際的に重要なラムサール条約湿地です。","この公園はベトナム最後のジャワサイの生息地でした（2010年に絶滅宣言）。","森の中のトゥンの巨木は、巨大な板根で有名です。"],"travelTips":["夜間の動物探索ツアーとバウサウの舟下りは、公園管理事務所に事前予約しましょう。","深い森を歩く際は、登山靴、長袖、ヒル除けを用意しましょう。"],"bestTime":"12月〜5月（乾季、森の中の移動がしやすい）","visitDuration":"1〜2日","ticket":"60,000ドン","openingHours":"07:00–17:00","galleryCaptions":["深い緑の原生林","黄金色の夕暮れ、湖面を漂う小舟","枯れ葉の絨毯で餌をついばむ野鶏"]},"zh":{"name":"吉仙国家公园","summary":"广袤的生物圈保护区，拥有原始热带雨林、丰富的动植物，以及熊与叶猴救护中心。","story":"吉仙国家公园横跨三省，是越南南部仅存的最珍贵的原始热带雨林之一。这里是联合国教科文组织认定的生物圈保护区，是大象、野牛、黄颊长臂猿等数百种珍稀鸟兽的家园。游客可骑行穿越森林，探访千年董棕古树，划船游览鳄鱼湖观赏野生鳄鱼，或走访灵长类与熊救护中心。夜幕降临，手电探兽之旅在原始密林深处带来探险的刺激。","facts":["吉仙于2001年被联合国教科文组织认定为世界生物圈保护区。","鳄鱼湖（Bàu Sấu）是具有国际重要意义的拉姆萨尔湿地。","公园曾是越南最后一头爪哇犀牛的栖息地（2010年宣告灭绝）。","林中的董棕古树以其巨大的板根而闻名。"],"travelTips":["夜间探兽之旅和鳄鱼湖划船请提前向公园管理处预约。","深入密林时请带好登山鞋、长袖衣物和防蚂蝗药。"],"bestTime":"12月至5月（旱季，林中行进更便利）","visitDuration":"1–2天","ticket":"60,000越南盾","openingHours":"07:00–17:00","galleryCaptions":["苍翠的原始森林","金色夕阳下，小舟漂在湖面","在枯叶上觅食的野鸡"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('thac-giang-dien', 'thac-giang-dien', 'dong-nai', 'Thác Giang Điền', 'Giang Dien Waterfall', 'waterfall', 107.0167, 10.9333, 'Khu du lịch sinh thái với thác nước trải rộng, vườn hoa và không gian xanh mát gần Biên Hòa.', 'Thác Giang Điền nằm giữa vùng quê Đồng Nai, là điểm đến quen thuộc cho những chuyến dã ngoại cuối tuần của người Sài Gòn và Biên Hòa. Dòng thác không quá hùng vĩ nhưng trải rộng, nước đổ qua các bậc đá tạo nên bức tranh êm dịu giữa rừng cây. Khu du lịch được quy hoạch thành những thảm cỏ xanh, vườn hoa rực rỡ, hồ nước và khu cắm trại lý tưởng cho gia đình. Vào mùa mưa, thác trở nên cuồn cuộn và đẹp nhất; mùa khô nước hiền hòa, thích hợp ngồi bên bờ nghe tiếng nước reo và tận hưởng không khí trong lành.', '["Thác Giang Điền cao khoảng 20 mét, trải rộng nhiều tầng đá.","Khu du lịch có dịch vụ cắm trại, picnic và teambuilding.","Mùa mưa (tháng 6–10) là lúc thác đẹp và nhiều nước nhất.","Nơi đây thường được chọn làm bối cảnh chụp ảnh cưới."]', '["Đi vào mùa mưa nếu muốn ngắm thác nhiều nước và hùng vĩ.","Mang theo đồ ăn để picnic trên các thảm cỏ trong khu du lịch."]', 'Tháng 6 đến tháng 10 (mùa mưa, thác nhiều nước)', 'Nửa ngày', '70.000đ', '07:00–17:30', '["popular","verified"]', '["waterfall","nature","photography"]', '[{"seed":"giangdien-thac","caption":"Thác nước trải rộng nhiều tầng","ratio":"16/9"},{"seed":"giangdien-vuonhoa","caption":"Vườn hoa rực rỡ trong khu","ratio":"4/3"},{"seed":"giangdien-camtrai","caption":"Bãi cỏ cắm trại xanh mát","ratio":"1/1"}]', '["cat-tien-national-park"]', 0, '{"en":{"name":"Giang Dien Waterfall","summary":"An eco-tourism area with a broad waterfall, flower gardens and cool green spaces near Bien Hoa.","story":"Giang Dien Waterfall lies in the countryside of Dong Nai, a familiar weekend picnic spot for the people of Saigon and Bien Hoa. The falls are not towering but spread wide, the water cascading over stone steps to create a gentle scene amid the forest. The resort is laid out with green lawns, vivid flower gardens, lakes and camping areas ideal for families. In the rainy season the falls grow powerful and are at their most beautiful; in the dry season the water runs gentle, perfect for sitting by the bank to listen to its murmur and breathe the fresh air.","facts":["Giang Dien Waterfall is about 20 meters high, spreading across many rock tiers.","The resort offers camping, picnicking and team-building services.","The rainy season (June–October) is when the falls are most beautiful and full.","It is often chosen as a backdrop for wedding photos."],"travelTips":["Go in the rainy season if you want to see the falls full and majestic.","Bring food to picnic on the lawns within the resort."],"bestTime":"June to October (rainy season, the falls are full)","visitDuration":"Half a day","ticket":"70,000 VND","openingHours":"07:00–17:30","galleryCaptions":["The broad, multi-tiered waterfall","Vivid flower gardens within the grounds","Cool green camping lawns"]},"ko":{"name":"장디엔 폭포","summary":"넓게 펼쳐진 폭포와 꽃밭, 시원한 녹음을 갖춘 비엔호아 인근의 생태 관광지.","story":"장디엔 폭포는 동나이의 시골 한가운데 자리해, 사이공과 비엔호아 사람들의 주말 소풍지로 친숙한 곳입니다. 폭포는 그리 웅장하지 않지만 넓게 펼쳐지며, 물줄기가 바위 계단을 타고 흘러 숲 속에 부드러운 풍경을 그려냅니다. 관광지는 푸른 잔디밭과 화사한 꽃밭, 호수, 그리고 가족 단위에 이상적인 캠핑장으로 조성되어 있습니다. 우기에는 폭포가 세차게 흐르며 가장 아름답고, 건기에는 물이 잔잔해 강가에 앉아 물소리를 듣고 맑은 공기를 즐기기에 좋습니다.","facts":["장디엔 폭포는 높이 약 20미터로 여러 층의 바위로 넓게 펼쳐집니다.","관광지에서는 캠핑, 피크닉, 팀빌딩 서비스를 제공합니다.","우기(6~10월)는 폭포가 가장 아름답고 수량이 많을 때입니다.","이곳은 흔히 웨딩 촬영 배경으로 선택됩니다."],"travelTips":["수량이 많고 웅장한 폭포를 보려면 우기에 가세요.","관광지 내 잔디밭에서 피크닉을 즐기려면 음식을 챙겨 가세요."],"bestTime":"6월~10월 (우기, 폭포 수량이 풍부함)","visitDuration":"반나절","ticket":"70,000동","openingHours":"07:00–17:30","galleryCaptions":["여러 층으로 넓게 펼쳐진 폭포","관광지 안의 화사한 꽃밭","시원하고 푸른 캠핑 잔디밭"]},"ja":{"name":"ザンディエンの滝","summary":"広がる滝と花畑、涼やかな緑を備えた、ビエンホア近郊のエコツーリズム地。","story":"ザンディエンの滝はドンナイの田園の只中にあり、サイゴンやビエンホアの人々の週末のピクニック地として親しまれています。滝はさほど雄大ではありませんが幅広く広がり、水が岩の段を流れ落ちて、森の中に穏やかな絵を描き出します。観光地は緑の芝生や色鮮やかな花畑、湖、家族連れに理想的なキャンプ場へと整備されています。雨季には滝が勢いを増して最も美しく、乾季には水が穏やかになり、岸辺に座って水音を聴き、澄んだ空気を味わうのにぴったりです。","facts":["ザンディエンの滝は高さ約20メートルで、いくつもの岩の段に幅広く広がります。","観光地ではキャンプ、ピクニック、チームビルディングのサービスがあります。","雨季（6〜10月）は滝が最も美しく水量の多い時期です。","ここはしばしばウェディング撮影の背景に選ばれます。"],"travelTips":["水量が多く雄大な滝を眺めたいなら雨季に行きましょう。","観光地内の芝生でピクニックをするなら食べ物を持参しましょう。"],"bestTime":"6月〜10月（雨季、滝の水量が豊か）","visitDuration":"半日","ticket":"70,000ドン","openingHours":"07:00–17:30","galleryCaptions":["幾段にも幅広く広がる滝","敷地内の色鮮やかな花畑","涼やかで緑のキャンプ芝生"]},"zh":{"name":"江田瀑布","summary":"拥有宽阔瀑布、花园和清凉绿意的生态旅游区，邻近边和市。","story":"江田瀑布坐落于同奈的乡野之间，是西贡和边和人熟悉的周末郊游之地。瀑布并不雄伟，却宽阔铺展，流水跌过层层石阶，在林木间勾勒出一幅柔和的画卷。旅游区被规划成片片绿茵、绚丽花园、湖泊和适合家庭的露营地。雨季时瀑布水势汹涌、最为壮美；旱季水流温和，适合坐在岸边聆听水声、享受清新空气。","facts":["江田瀑布高约20米，分多层岩阶宽阔铺展。","旅游区提供露营、野餐和团建服务。","雨季（6–10月）是瀑布最美、水量最丰沛的时节。","这里常被选作婚纱摄影的取景地。"],"travelTips":["若想观赏水量丰沛、气势磅礴的瀑布，请在雨季前往。","带上食物，在旅游区的草坪上野餐。"],"bestTime":"6月至10月（雨季，瀑布水量丰沛）","visitDuration":"半天","ticket":"70,000越南盾","openingHours":"07:00–17:30","galleryCaptions":["多层宽阔铺展的瀑布","园区内绚丽的花园","清凉翠绿的露营草坪"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('chua-ba-thien-hau-binh-duong', 'chua-ba-thien-hau', 'binh-duong', 'Chùa Bà Thiên Hậu', 'Thien Hau Temple (Binh Duong)', 'temple', 106.6515, 10.9787, 'Ngôi miếu cổ thờ Bà Thiên Hậu, trung tâm lễ hội rước kiệu lớn nhất Bình Dương dịp rằm tháng Giêng.', 'Chùa Bà Thiên Hậu ở Thủ Dầu Một là ngôi miếu cổ do cộng đồng người Hoa lập nên để thờ Thiên Hậu Thánh Mẫu, vị thần bảo hộ cho người đi biển và cầu bình an. Kiến trúc đậm phong cách Hoa Nam với mái ngói âm dương, những hình rồng phượng tinh xảo và làn khói nhang nghi ngút quanh năm. Vào dịp rằm tháng Giêng, lễ rước kiệu Bà diễn ra tưng bừng, thu hút hàng vạn người từ khắp nơi đổ về, biến cả thành phố thành một biển người với cờ phướn, lân sư rồng rộn ràng. Đây là lễ hội văn hóa tâm linh lớn và đặc sắc bậc nhất miền Đông Nam Bộ.', '["Lễ rước kiệu Bà rằm tháng Giêng là lễ hội lớn nhất Bình Dương.","Miếu do bốn bang người Hoa ở Thủ Dầu Một cùng xây dựng.","Kiến trúc mang đậm phong cách đền miếu Hoa Nam truyền thống.","Người dân đến vay lộc đầu năm và trả lễ cuối năm tại miếu."]', '["Đến vào rằm tháng Giêng để xem lễ rước kiệu Bà hoành tráng.","Ăn mặc lịch sự, kín đáo khi vào dâng hương trong miếu."]', 'Rằm tháng Giêng âm lịch (mùa lễ hội)', '1–2 giờ', '', '05:00–18:00', '["festival","verified","popular"]', '["temple","culture","history","photography"]', '[{"seed":"thienhau-bd-mieu","caption":"Miếu cổ mái ngói âm dương","ratio":"4/3"},{"seed":"thienhau-bd-leruoc","caption":"Lễ rước kiệu Bà tưng bừng","ratio":"16/9"},{"seed":"thienhau-bd-nhang","caption":"Khói nhang nghi ngút trong miếu","ratio":"1/1"}]', '["dai-nam-binh-duong"]', 0, '{"en":{"name":"Ba Thien Hau Temple","summary":"An ancient temple to Lady Thien Hau, the center of Binh Duong''s largest palanquin procession festival on the 15th of the first lunar month.","story":"Ba Thien Hau Temple in Thu Dau Mot is an ancient temple built by the local Chinese community to worship the Heavenly Mother Thien Hau, patron of seafarers and bringer of peace. The architecture is richly southern-Chinese, with yin-yang tiled roofs, intricate dragon and phoenix figures and incense smoke curling year-round. On the 15th of the first lunar month, the procession of the Lady''s palanquin unfolds joyously, drawing tens of thousands from everywhere and turning the whole city into a sea of people, banners and lively lion-dragon dances. It is the largest and most distinctive spiritual-cultural festival in the southeastern region.","facts":["The palanquin procession on the 15th of the first lunar month is Binh Duong''s largest festival.","The temple was built jointly by four Chinese congregations of Thu Dau Mot.","Its architecture reflects the traditional southern-Chinese temple style.","Locals come to ''borrow fortune'' at the start of the year and repay it at year''s end."],"travelTips":["Come on the 15th of the first lunar month to witness the grand palanquin procession.","Dress neatly and modestly when entering to offer incense."],"bestTime":"The 15th of the first lunar month (festival season)","visitDuration":"1–2 hours","ticket":"","openingHours":"05:00–18:00","galleryCaptions":["The ancient temple with yin-yang tiled roofs","The lively palanquin procession of the Lady","Incense smoke curling inside the temple"]},"ko":{"name":"바 티엔하우 사원","summary":"티엔하우 여신을 모시는 고찰로, 정월 대보름에 빈즈엉 최대 규모의 가마 행렬 축제가 열리는 중심지.","story":"투저우못의 바 티엔하우 사원은 현지 화교 공동체가 뱃사람을 수호하고 평안을 비는 천후성모를 모시기 위해 세운 고찰입니다. 음양 기와지붕과 정교한 용·봉황 문양, 연중 피어오르는 향 연기로 화남 양식이 짙게 배어 있습니다. 정월 대보름이면 여신의 가마 행렬이 흥겹게 펼쳐지며 사방에서 수만 명이 몰려들어, 깃발과 흥겨운 사자·용춤으로 온 도시가 인파의 바다로 변합니다. 이는 동남부 지역에서 가장 크고 독특한 영적 문화 축제입니다.","facts":["정월 대보름 가마 행렬은 빈즈엉 최대의 축제입니다.","이 사원은 투저우못의 네 화교 방회가 함께 건립했습니다.","건축은 전통 화남 사원 양식이 짙게 배어 있습니다.","주민들은 연초에 사원에서 복을 빌리고 연말에 이를 갚습니다."],"travelTips":["성대한 가마 행렬을 보려면 정월 대보름에 방문하세요.","사원 안에서 분향할 때는 단정하고 정숙하게 차려입으세요."],"bestTime":"음력 정월 대보름 (축제철)","visitDuration":"1~2시간","ticket":"","openingHours":"05:00–18:00","galleryCaptions":["음양 기와지붕의 고찰","흥겨운 여신 가마 행렬","사원 안에 피어오르는 향 연기"]},"ja":{"name":"バー・ティエンハウ廟","summary":"天后女神を祀る古い廟で、旧正月の小正月にビンズオン最大規模の神輿行列の祭りが行われる中心地。","story":"トゥーザウモットのバー・ティエンハウ廟は、現地の華人コミュニティが、航海者を守り平安をもたらす天后聖母を祀るために建てた古い廟です。陰陽瓦の屋根、精巧な龍と鳳凰の意匠、年中立ちのぼる線香の煙と、華南様式が色濃く漂います。旧正月の小正月には女神の神輿行列が賑やかに繰り広げられ、各地から数万の人々が押し寄せ、旗や賑やかな獅子舞・龍舞で街全体が人の海となります。これは東南部地域で最も大きく独特な精神文化の祭りです。","facts":["小正月の神輿行列はビンズオン最大の祭りです。","この廟はトゥーザウモットの四つの華人帮会が共同で建立しました。","建築は伝統的な華南の廟様式が色濃く表れています。","人々は年始に廟で福を借り、年末にこれを返します。"],"travelTips":["壮大な神輿行列を見るには小正月に訪れましょう。","廟内で焼香する際は、きちんと控えめな装いをしましょう。"],"bestTime":"旧暦の小正月（祭りの季節）","visitDuration":"1〜2時間","ticket":"","openingHours":"05:00–18:00","galleryCaptions":["陰陽瓦の屋根の古い廟","賑やかな女神の神輿行列","廟内に立ちのぼる線香の煙"]},"zh":{"name":"天后庙","summary":"供奉天后娘娘的古庙，是平阳正月十五最盛大的抬轿巡游庙会中心。","story":"土龙木的天后庙是当地华人社群兴建、用以供奉护佑航海、祈求平安的天后圣母的古庙。建筑充满华南风格，覆以阴阳瓦顶，龙凤雕饰精巧，香烟终年缭绕。每逢正月十五，天后娘娘的抬轿巡游热闹非凡，吸引各地数万人涌来，旌旗招展、舞狮舞龙喧腾，整座城市化作人潮的海洋。这是东南部地区最盛大、最独特的灵性文化庙会。","facts":["正月十五的抬轿巡游是平阳最大的庙会。","此庙由土龙木的四个华人帮会共同兴建。","建筑深具传统华南庙宇风格。","民众在年初到庙中「借禄」，年末再来「还愿」。"],"travelTips":["正月十五前往，可观赏盛大的抬轿巡游。","进庙上香时请着装得体、端庄。"],"bestTime":"农历正月十五（庙会时节）","visitDuration":"1–2小时","ticket":"","openingHours":"05:00–18:00","galleryCaptions":["阴阳瓦顶的古庙","热闹的天后娘娘抬轿巡游","庙中缭绕的香烟"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dai-nam-binh-duong', 'khu-du-lich-dai-nam', 'binh-duong', 'Khu du lịch Đại Nam', 'Dai Nam Tourist Park', 'park', 106.6219, 11.0331, 'Khu du lịch khổng lồ kết hợp đền thờ, vườn thú, biển nhân tạo và công viên giải trí bậc nhất miền Nam.', 'Khu du lịch Đại Nam (Lạc Cảnh Đại Nam Văn Hiến) là một trong những tổ hợp giải trí lớn nhất Việt Nam, trải rộng hàng trăm hecta giữa Bình Dương. Nơi đây quy tụ đủ mọi sắc thái: đền thờ Đại Nam Quốc Tự nguy nga dát vàng, dãy núi Ngũ Hành Sơn nhân tạo, vườn thú safari với cả nghìn loài, biển nhân tạo nhân tạo rộng nhất nước và khu trò chơi cảm giác mạnh. Một ngày ở Đại Nam có thể vừa chiêm bái tâm linh, vừa cho trẻ con vui chơi, vừa tắm biển nhân tạo, khiến đây thành điểm đến gia đình lý tưởng dịp cuối tuần và lễ tết.', '["Đại Nam là một trong những khu du lịch có diện tích lớn nhất Việt Nam.","Biển nhân tạo tại đây từng được ghi nhận là lớn nhất nước.","Đền Đại Nam Quốc Tự được dát vàng và xây bằng vật liệu quý.","Vườn thú safari nuôi nhiều loài quý hiếm trong môi trường bán hoang dã."]', '["Mua vé combo trọn gói để tiết kiệm khi chơi nhiều khu.","Đi sớm và mang đồ bơi nếu muốn trải nghiệm khu biển nhân tạo."]', 'Tháng 11 đến tháng 4 (mùa khô, trời mát)', '1 ngày', '150.000đ', '08:00–17:00', '["popular","trending"]', '["park","culture","city"]', '[{"seed":"dainam-den","caption":"Đền Đại Nam Quốc Tự dát vàng","ratio":"16/9"},{"seed":"dainam-bien","caption":"Biển nhân tạo rộng lớn","ratio":"4/3"},{"seed":"dainam-safari","caption":"Vườn thú safari bán hoang dã","ratio":"1/1"}]', '["chua-ba-thien-hau-binh-duong"]', 0, '{"en":{"name":"Dai Nam Tourist Park","summary":"A colossal tourist park combining a temple, a zoo, an artificial sea and the South''s leading amusement park.","story":"Dai Nam Tourist Park (Lac Canh Dai Nam Van Hien) is one of Vietnam''s largest entertainment complexes, sprawling across hundreds of hectares in Binh Duong. It gathers every shade of attraction: the magnificent gold-gilded Dai Nam National Temple, an artificial Marble Mountains range, a safari zoo with thousands of species, the country''s largest man-made sea, and a thrill-ride zone. A day at Dai Nam can combine spiritual worship, fun for children and a swim in the artificial sea—making it an ideal family destination for weekends and holidays.","facts":["Dai Nam is one of the largest tourist areas by size in Vietnam.","Its artificial sea was once recorded as the largest in the country.","The Dai Nam National Temple is gilded in gold and built with precious materials.","The safari zoo keeps many rare species in a semi-wild environment."],"travelTips":["Buy a combo ticket to save when visiting multiple zones.","Go early and bring swimwear if you want to experience the artificial sea."],"bestTime":"November to April (dry season, cool weather)","visitDuration":"1 day","ticket":"150,000 VND","openingHours":"08:00–17:00","galleryCaptions":["The gold-gilded Dai Nam National Temple","The vast artificial sea","The semi-wild safari zoo"]},"ko":{"name":"다이남 관광지","summary":"사원과 동물원, 인공 바다, 남부 최고의 놀이공원을 결합한 거대한 관광 단지.","story":"다이남 관광지(락까잉 다이남 반히엔)는 빈즈엉 한가운데 수백 헥타르에 걸쳐 펼쳐진, 베트남에서 가장 큰 위락 단지 중 하나입니다. 이곳은 모든 색채를 한데 모았습니다. 금박을 입힌 웅장한 다이남 국사(國寺), 인공 오행산, 수천 종을 갖춘 사파리 동물원, 베트남 최대의 인공 바다, 그리고 스릴 넘치는 놀이기구 구역까지. 다이남에서의 하루는 영적인 참배와 아이들의 놀이, 인공 바다에서의 물놀이를 함께 누릴 수 있어, 주말과 명절에 이상적인 가족 여행지가 됩니다.","facts":["다이남은 베트남에서 면적이 가장 큰 관광지 중 하나입니다.","이곳의 인공 바다는 한때 베트남 최대 규모로 기록되었습니다.","다이남 국사는 금박을 입히고 귀한 재료로 지어졌습니다.","사파리 동물원은 여러 희귀종을 반(半)야생 환경에서 사육합니다."],"travelTips":["여러 구역을 즐긴다면 콤보 통합 입장권을 사서 절약하세요.","인공 바다를 체험하려면 일찍 가서 수영복을 챙기세요."],"bestTime":"11월~4월 (건기, 시원한 날씨)","visitDuration":"1일","ticket":"150,000동","openingHours":"08:00–17:00","galleryCaptions":["금박을 입힌 다이남 국사","광활한 인공 바다","반야생 사파리 동물원"]},"ja":{"name":"ダイナム観光地","summary":"寺院、動物園、人工の海、南部随一の遊園地を組み合わせた巨大な観光複合施設。","story":"ダイナム観光地（ラッカイン・ダイナム・ヴァンヒエン）は、ビンズオンの只中に数百ヘクタールにわたって広がる、ベトナム最大級の娯楽複合施設のひとつです。金箔を施した壮麗なダイナム国寺、人工の五行山、数千種を擁するサファリ動物園、国内最大の人工の海、そして絶叫マシンの区画まで、あらゆる趣を一堂に集めています。ダイナムでの一日は、精神的な参拝も、子どもの遊びも、人工の海での海水浴も同時に楽しめ、週末や祝祭日に理想的な家族向けの行き先となっています。","facts":["ダイナムはベトナムで面積最大級の観光地のひとつです。","ここの人工の海は、かつて国内最大と記録されました。","ダイナム国寺は金箔を施し、貴重な材料で建てられました。","サファリ動物園は多くの希少種を半野生の環境で飼育しています。"],"travelTips":["複数の区画で遊ぶなら、コンボ通し券を買うと節約できます。","人工の海を体験したいなら、早めに行き水着を持参しましょう。"],"bestTime":"11月〜4月（乾季、涼しい気候）","visitDuration":"1日","ticket":"150,000ドン","openingHours":"08:00–17:00","galleryCaptions":["金箔を施したダイナム国寺","広大な人工の海","半野生のサファリ動物園"]},"zh":{"name":"大南旅游区","summary":"集庙宇、动物园、人工海与南部一流游乐园于一体的巨型旅游区。","story":"大南旅游区（乐景大南文献）是越南最大的娱乐综合体之一，在平阳绵延数百公顷。这里汇聚了各种风貌：金碧辉煌的大南国寺、人工五行山、拥有上千物种的野生动物园、全国最大的人工海，以及刺激的游乐项目区。在大南待上一天，既可朝拜祈福，又能让孩子尽情玩耍，还能在人工海中戏水，使其成为周末和节假日理想的家庭出游目的地。","facts":["大南是越南占地最大的旅游区之一。","这里的人工海曾被记录为全国最大。","大南国寺贴有金箔，以珍贵材料建成。","野生动物园在半野生环境中饲养着众多珍稀物种。"],"travelTips":["若想多区游玩，购买套票更省钱。","若想体验人工海，请早点前往并带上泳衣。"],"bestTime":"11月至4月（旱季，天气凉爽）","visitDuration":"1天","ticket":"150,000越南盾","openingHours":"08:00–17:00","galleryCaptions":["贴金的大南国寺","广阔的人工海","半野生的野生动物园"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bu-gia-map-national-park', 'vuon-quoc-gia-bu-gia-map', 'binh-phuoc', 'Vườn quốc gia Bù Gia Mập', 'Bu Gia Map National Park', 'park', 107.1833, 12.1833, 'Khu rừng nguyên sinh giáp biên giới Campuchia, giàu đa dạng sinh học với thác nước, suối ngầm và văn hóa người S''tiêng.', 'Vườn quốc gia Bù Gia Mập nằm ở vùng cực bắc Bình Phước, giáp biên giới Campuchia, là vạt rừng nguyên sinh hiếm hoi còn giữ được vẻ hoang sơ của Đông Nam Bộ. Rừng ở đây xanh thẫm quanh năm, ẩn chứa nhiều loài thú quý, chim, bướm và cây gỗ cổ thụ. Du khách ưa khám phá có thể trekking xuyên rừng, lội suối, ngắm những thác nước và hang ngầm còn nguyên nét thiên nhiên. Vùng đệm là nơi cư trú của đồng bào S''tiêng và M''nông với văn hóa cồng chiêng, rượu cần độc đáo. Bù Gia Mập là điểm đến cho ai khao khát một chuyến đi thực sự gần gũi với rừng già.', '["Bù Gia Mập giáp biên giới Campuchia và tỉnh Đắk Nông.","Vườn bảo tồn nhiều loài linh trưởng và chim quý hiếm.","Vùng đệm là địa bàn sinh sống của người S''tiêng và M''nông.","Rừng còn giữ nhiều cây gỗ quý cổ thụ hàng trăm năm tuổi."]', '["Liên hệ ban quản lý vườn để có kiểm lâm dẫn đường trekking.","Chuẩn bị đồ chống vắt, nước uống và giày lội suối chắc chắn."]', 'Tháng 11 đến tháng 4 (mùa khô, an toàn khi đi rừng)', '1–2 ngày', '', '07:00–16:30', '["hidden-gem","verified","new"]', '["park","nature","culture","photography"]', '[{"seed":"bugiamap-rung","caption":"Rừng nguyên sinh xanh thẳm","ratio":"16/9"},{"seed":"bugiamap-suoi","caption":"Suối trong giữa rừng già","ratio":"4/3"},{"seed":"bugiamap-stieng","caption":"Văn hóa cồng chiêng S''tiêng","ratio":"1/1"}]', '["trang-co-bu-lach"]', 1, '{"en":{"name":"Bu Gia Map National Park","summary":"A primary forest along the Cambodian border, rich in biodiversity with waterfalls, underground streams and S''tieng culture.","story":"Bu Gia Map National Park lies in the far north of Binh Phuoc, along the Cambodian border—a rare swath of primary forest that still keeps the wild beauty of the southeast. The forest here is deep green year-round, sheltering many rare animals, birds, butterflies and ancient timber trees. Adventurous visitors can trek through the forest, wade across streams and admire waterfalls and underground caves untouched by time. The buffer zone is home to the S''tieng and M''nong peoples with their distinctive gong culture and rice wine. Bu Gia Map is a destination for anyone yearning for a journey truly close to the ancient forest.","facts":["Bu Gia Map borders Cambodia and Dak Nong province.","The park protects many primate and rare bird species.","The buffer zone is home to the S''tieng and M''nong peoples.","The forest still holds many precious ancient timber trees hundreds of years old."],"travelTips":["Contact park management to arrange a ranger guide for trekking.","Prepare anti-leech gear, drinking water and sturdy stream-wading shoes."],"bestTime":"November to April (dry season, safe for forest trekking)","visitDuration":"1–2 days","ticket":"","openingHours":"07:00–16:30","galleryCaptions":["Deep-green primary forest","A clear stream in the ancient forest","S''tieng gong culture"]},"ko":{"name":"부자맙 국립공원","summary":"캄보디아 국경에 접한 원시림으로, 폭포와 지하 수로, 스띠엥족 문화가 어우러진 풍부한 생물 다양성을 자랑합니다.","story":"부자맙 국립공원은 빈프억 최북단 캄보디아 국경에 자리한, 동남부의 원시적인 아름다움을 간직한 보기 드문 원시림입니다. 이곳의 숲은 연중 짙푸르며 여러 희귀 동물과 새, 나비, 고목을 품고 있습니다. 탐험을 즐기는 여행객은 숲을 가로질러 트레킹하고 계곡을 건너며, 시간의 손길이 닿지 않은 폭포와 지하 동굴을 감상할 수 있습니다. 완충 지대는 독특한 공 문화와 깐 술을 지닌 스띠엥족·므농족의 터전입니다. 부자맙은 원시림과 진정으로 가까운 여정을 갈망하는 이들을 위한 여행지입니다.","facts":["부자맙은 캄보디아와 닥농성에 접해 있습니다.","공원은 여러 영장류와 희귀 조류를 보호합니다.","완충 지대는 스띠엥족과 므농족이 살아가는 곳입니다.","숲에는 수백 년 된 귀한 고목이 여전히 많이 남아 있습니다."],"travelTips":["트레킹 안내를 받으려면 공원 관리소에 연락해 산림 감시원을 동행하세요.","거머리 방지 용품과 식수, 튼튼한 계곡용 신발을 준비하세요."],"bestTime":"11월~4월 (건기, 숲 트레킹에 안전함)","visitDuration":"1~2일","ticket":"","openingHours":"07:00–16:30","galleryCaptions":["짙푸른 원시림","원시림 속의 맑은 계곡","스띠엥족 공 문화"]},"ja":{"name":"ブザマップ国立公園","summary":"カンボジア国境沿いの原生林で、滝や地下の流れ、ストゥエン族の文化を擁し生物多様性に富みます。","story":"ブザマップ国立公園はビンフオック最北部のカンボジア国境沿いにあり、東南部の野生の美しさを今なお保つ、数少ない原生林です。ここの森は年中深い緑をたたえ、多くの希少な獣や鳥、蝶、巨木を秘めています。探検好きの旅人は森を貫いてトレッキングし、渓流を渡り、時の手つかずの滝や地下の洞窟を眺めることができます。緩衝地帯は、独特な銅鑼文化と壺酒を持つストゥエン族・ムノン族の住まいです。ブザマップは、原生林と真に近づく旅を渇望する人のための行き先です。","facts":["ブザマップはカンボジアとダクノン省に接しています。","公園は多くの霊長類と希少な鳥類を保護しています。","緩衝地帯はストゥエン族とムノン族が暮らす地です。","森には今なお樹齢数百年の貴重な巨木が多く残っています。"],"travelTips":["トレッキングの案内を受けるには、公園管理事務所に連絡して森林警備員に同行してもらいましょう。","ヒル除けの用品、飲み水、丈夫な渓流用の靴を準備しましょう。"],"bestTime":"11月〜4月（乾季、森のトレッキングに安全）","visitDuration":"1〜2日","ticket":"","openingHours":"07:00–16:30","galleryCaptions":["深い緑の原生林","原生林の中の澄んだ渓流","ストゥエン族の銅鑼文化"]},"zh":{"name":"布嘉霉国家公园","summary":"毗邻柬埔寨边境的原始森林，生物多样性丰富，拥有瀑布、地下溪流和斯丁族文化。","story":"布嘉霉国家公园位于平福省最北端，与柬埔寨接壤，是东南部难得仍保留原始野趣的一片原始森林。这里林木终年苍翠，藏有众多珍稀走兽、飞鸟、蝴蝶和参天古木。喜爱探险的游客可穿林徒步、涉溪而行，欣赏仍保有天然风貌的瀑布与地下洞穴。缓冲区是斯丁族和墨侬族的居住地，拥有独特的锣钲文化和坛酒。布嘉霉是渴望来一场真正亲近原始森林之旅者的目的地。","facts":["布嘉霉与柬埔寨及多农省接壤。","公园保护着多种灵长类和珍稀鸟类。","缓冲区是斯丁族和墨侬族的聚居之地。","森林中仍保有许多树龄数百年的珍贵古木。"],"travelTips":["联系公园管理处安排护林员带路徒步。","备好防蚂蝗用品、饮用水和结实的涉溪鞋。"],"bestTime":"11月至4月（旱季，进山更安全）","visitDuration":"1–2天","ticket":"","openingHours":"07:00–16:30","galleryCaptions":["苍翠的原始森林","原始森林中的清澈溪流","斯丁族的锣钲文化"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('trang-co-bu-lach', 'trang-co-bu-lach', 'binh-phuoc', 'Trảng cỏ Bù Lạch', 'Bu Lach Grasslands', 'village', 107.1167, 11.8833, 'Quần thể trảng cỏ rộng mênh mông giữa rừng, gắn với đời sống và truyền thuyết của đồng bào M''nông ở Bình Phước.', 'Trảng cỏ Bù Lạch là một quần thể gồm khoảng hai mươi trảng cỏ lớn nhỏ nằm xen giữa những cánh rừng ở huyện Bù Đăng, Bình Phước. Điều kỳ lạ là giữa rừng già lại trải ra những thảm cỏ xanh mượt phẳng lì như sân golf tự nhiên, ôm lấy hồ nước trong vắt soi bóng mây trời. Người M''nông bản địa lưu truyền nhiều truyền thuyết về sự hình thành huyền bí của các trảng cỏ này. Du khách đến đây để cắm trại, dã ngoại, ngắm hoàng hôn buông trên thảo nguyên thu nhỏ và trải nghiệm nét văn hóa mộc mạc của buôn làng M''nông quanh vùng.', '["Bù Lạch gồm khoảng 20 trảng cỏ lớn nhỏ nối nhau giữa rừng.","Giữa trảng cỏ có hồ nước tự nhiên trong vắt quanh năm.","Người M''nông gắn nhiều truyền thuyết với sự hình thành trảng cỏ.","Cỏ ở đây xanh mượt, phẳng lì như thảo nguyên tự nhiên."]', '["Mang lều và đồ ăn để cắm trại, ngắm hoàng hôn trên trảng cỏ.","Thuê người địa phương dẫn đường vì lối vào khá hoang sơ."]', 'Tháng 11 đến tháng 3 (cỏ xanh, trời mát)', 'Nửa ngày đến 1 ngày', '', 'Cả ngày', '["hidden-gem","new","ai-recommended"]', '["nature","culture","photography"]', '[{"seed":"bulach-trangco","caption":"Thảm cỏ xanh mượt giữa rừng","ratio":"16/9"},{"seed":"bulach-ho","caption":"Hồ nước trong soi bóng mây","ratio":"4/3"},{"seed":"bulach-hoanghon","caption":"Hoàng hôn buông trên trảng cỏ","ratio":"1/1"}]', '["bu-gia-map-national-park"]', 0, '{"en":{"name":"Bu Lach Grasslands","summary":"A sprawling complex of grassy meadows amid the forest, tied to the life and legends of the M''nong people of Binh Phuoc.","story":"Bu Lach Grasslands is a complex of about twenty meadows large and small, nestled among the forests of Bu Dang district, Binh Phuoc. Strangely, in the midst of the ancient forest stretch smooth green carpets, flat as natural golf courses, embracing crystal-clear lakes that mirror the sky and clouds. The local M''nong people pass down many legends about the mysterious origin of these meadows. Visitors come to camp, picnic, watch the sunset descend over the miniature savanna and experience the rustic culture of the M''nong villages around the area.","facts":["Bu Lach comprises about 20 meadows large and small, linked together amid the forest.","At the heart of the grasslands lies a natural lake, crystal-clear year-round.","The M''nong people associate many legends with the formation of the meadows.","The grass here is smooth and flat, like a natural savanna."],"travelTips":["Bring a tent and food to camp and watch the sunset over the grasslands.","Hire a local guide, as the way in is quite wild."],"bestTime":"November to March (green grass, cool weather)","visitDuration":"Half a day to 1 day","ticket":"","openingHours":"All day","galleryCaptions":["Smooth green grass amid the forest","A clear lake mirroring the clouds","Sunset descending over the grasslands"]},"ko":{"name":"부락 초원","summary":"숲 한가운데 드넓게 펼쳐진 초원 군락으로, 빈프억 므농족의 삶과 전설이 깃든 곳.","story":"부락 초원은 빈프억 부당현의 숲 사이에 자리한 크고 작은 약 스무 개의 초원으로 이루어진 군락입니다. 신기하게도 원시림 한가운데 천연 골프장처럼 평평한 푸른 잔디가 펼쳐져, 하늘과 구름을 비추는 맑은 호수를 감싸 안고 있습니다. 토박이 므농족은 이 초원들의 신비로운 형성에 관한 여러 전설을 전해 옵니다. 여행객은 이곳에서 캠핑과 소풍을 즐기고, 작은 초원 위로 내리는 노을을 바라보며, 주변 므농족 마을의 소박한 문화를 체험하러 찾아옵니다.","facts":["부락은 숲 사이로 이어진 크고 작은 약 20개의 초원으로 이루어집니다.","초원 한가운데에는 연중 맑은 천연 호수가 있습니다.","므농족은 초원의 형성에 여러 전설을 결부시킵니다.","이곳의 잔디는 천연 초원처럼 매끄럽고 평평합니다."],"travelTips":["초원 위에서 캠핑하고 노을을 보려면 텐트와 음식을 챙겨 가세요.","들어가는 길이 꽤 험하므로 현지인 안내인을 고용하세요."],"bestTime":"11월~3월 (잔디가 푸르고 날씨가 시원함)","visitDuration":"반나절~1일","ticket":"","openingHours":"종일","galleryCaptions":["숲 한가운데 매끄럽고 푸른 잔디","구름을 비추는 맑은 호수","초원 위로 내리는 노을"]},"ja":{"name":"ブーラックの草原","summary":"森の只中に広々と広がる草原の群で、ビンフオックのムノン族の暮らしと伝説に結びつく地。","story":"ブーラックの草原は、ビンフオック・ブーダン県の森々の間に位置する、大小およそ二十の草原からなる群です。不思議なことに、原生林の只中に、天然のゴルフ場のように平らで滑らかな緑の絨毯が広がり、空と雲を映す澄んだ湖を抱いています。土地のムノン族は、これらの草原の神秘的な成り立ちについて多くの伝説を伝えています。旅人はここでキャンプやピクニックを楽しみ、小さな草原に降りる夕日を眺め、周辺のムノン族の村の素朴な文化を体験しに訪れます。","facts":["ブーラックは森の間に連なる大小およそ20の草原からなります。","草原の只中には年中澄んだ天然の湖があります。","ムノン族は草原の成り立ちに多くの伝説を結びつけています。","ここの草は天然の草原のように滑らかで平らです。"],"travelTips":["草原でキャンプし夕日を眺めるには、テントと食べ物を持参しましょう。","入り口の道がかなり荒れているため、地元の案内人を雇いましょう。"],"bestTime":"11月〜3月（草が青く、気候が涼しい）","visitDuration":"半日〜1日","ticket":"","openingHours":"終日","galleryCaptions":["森の只中の滑らかで青い草","雲を映す澄んだ湖","草原に降りる夕日"]},"zh":{"name":"布勒草甸","summary":"森林之中辽阔铺展的草甸群落，与平福省墨侬族的生活和传说紧密相连。","story":"布勒草甸是位于平福省福龙县森林之间、由约二十片大小草甸组成的群落。奇妙的是，在原始森林之中却铺展出片片平整如天然高尔夫球场的翠绿草毯，环抱着倒映云天的清澈湖水。当地墨侬族流传着关于这些草甸神秘成因的诸多传说。游客来此露营、郊游，观赏落日洒在这片缩小版草原之上，并体验周边墨侬族村寨质朴的文化。","facts":["布勒由约20片大小草甸在森林间相连而成。","草甸中央有一汪终年清澈的天然湖泊。","墨侬族将诸多传说与草甸的成因联系在一起。","这里的草翠绿平整，宛如天然草原。"],"travelTips":["带上帐篷和食物，在草甸上露营、观赏落日。","入口颇为荒僻，请雇当地人带路。"],"bestTime":"11月至3月（草色青翠，天气凉爽）","visitDuration":"半天至1天","ticket":"","openingHours":"全天","galleryCaptions":["森林之中翠绿平整的草甸","倒映云天的清澈湖水","落日洒在草甸之上"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('nui-ba-den-tay-ninh', 'nui-ba-den', 'tay-ninh', 'Núi Bà Đen', 'Ba Den Mountain', 'mountain', 106.1719, 11.3833, 'Ngọn núi cao nhất Nam Bộ, ''nóc nhà'' miền Đông với hệ thống chùa linh thiêng, cáp treo hiện đại và biển mây huyền ảo.', 'Núi Bà Đen cao 986 mét, là đỉnh núi cao nhất Nam Bộ và được mệnh danh là ''nóc nhà'' của vùng đất này. Núi gắn với truyền thuyết về nàng Lý Thị Thiên Hương (Bà Đen) trinh tiết, linh thiêng, nên sườn núi là nơi quần tụ nhiều ngôi chùa cổ thu hút hành hương quanh năm. Ngày nay, hệ thống cáp treo hiện đại đưa du khách lên tận đỉnh, nơi đặt tượng Phật Bà Tây Bổ Đà Sơn bằng đồng cao nhất châu Á và quảng trường rộng lớn. Những sớm mai, biển mây trắng cuồn cuộn dưới chân khiến đỉnh Bà Đen như chốn bồng lai giữa miền Đông nắng gió.', '["Núi Bà Đen cao 986 mét, là đỉnh cao nhất Nam Bộ.","Tượng Phật Bà Tây Bổ Đà Sơn trên đỉnh là tượng Phật bằng đồng cao nhất châu Á.","Hệ thống cáp treo tại đây từng lập nhiều kỷ lục thế giới.","Hội xuân Núi Bà Đen diễn ra suốt tháng Giêng âm lịch."]', '["Lên đỉnh vào sáng sớm để có cơ hội ngắm biển mây tuyệt đẹp.","Mua vé cáp treo khứ hồi và mang áo khoác vì đỉnh núi se lạnh."]', 'Tháng 11 đến tháng 4 và mùa lễ hội tháng Giêng', 'Nửa ngày đến 1 ngày', '350.000đ (cáp treo)', '06:00–22:00', '["festival","trending","popular","verified"]', '["mountain","temple","culture","nature","photography"]', '[{"seed":"badennui-bienmay","caption":"Núi Bà Đen in bóng tím dưới hoàng hôn ven hồ","ratio":"16/9"},{"seed":"badennui-phatba","caption":"Tượng Phật Bà trên đỉnh núi","ratio":"4/3"},{"seed":"badennui-captreo","caption":"Tượng Phật Bà vươn lên giữa biển mây trắng","ratio":"1/1"}]', '["toa-thanh-cao-dai-tay-ninh"]', 1, '{"en":{"name":"Ba Den Mountain","summary":"The highest peak in the South, the ''rooftop'' of the southeast with sacred temples, a modern cable car and ethereal seas of cloud.","story":"Ba Den Mountain rises 986 meters, the highest peak in southern Vietnam and dubbed the ''rooftop'' of this land. The mountain is tied to the legend of the chaste, sacred Ly Thi Thien Huong (Lady Den), so its slopes are clustered with ancient temples drawing pilgrims year-round. Today, a modern cable car carries visitors all the way to the summit, where the bronze Tay Bo Da Son Buddha statue—the tallest of its kind in Asia—stands above a vast plaza. At dawn, a white sea of cloud rolls below your feet, making the summit of Ba Den feel like a fairyland amid the sun-and-wind of the southeast.","facts":["Ba Den Mountain is 986 meters high, the highest peak in southern Vietnam.","The Tay Bo Da Son Buddha statue at the summit is the tallest bronze Buddha in Asia.","The cable-car system here has set several world records.","The Ba Den Mountain spring festival runs throughout the first lunar month."],"travelTips":["Reach the summit early in the morning for a chance to see the magnificent sea of cloud.","Buy a round-trip cable-car ticket and bring a jacket, as the summit is chilly."],"bestTime":"November to April and the festival season in the first lunar month","visitDuration":"Half a day to 1 day","ticket":"350,000 VND (cable car)","openingHours":"06:00–22:00","galleryCaptions":["Ba Den Mountain casting a purple silhouette at lakeside sunset","The Buddha statue at the mountain summit","The Buddha statue rising amid a white sea of cloud"]},"ko":{"name":"바덴산","summary":"남부 최고봉이자 동남부의 ''지붕''으로, 영험한 사원과 현대식 케이블카, 환상적인 운해를 갖춘 산.","story":"바덴산은 높이 986미터로 남부 베트남에서 가장 높은 봉우리이며 이 땅의 ''지붕''이라 불립니다. 산은 정절을 지킨 영험한 리티티엔흐엉(바덴) 낭자의 전설과 얽혀 있어, 산비탈에는 연중 순례객을 끌어모으는 고찰이 모여 있습니다. 오늘날 현대식 케이블카가 여행객을 정상까지 실어 나르며, 그곳에는 아시아에서 가장 높은 청동 부처상인 떠이보다선 불상과 드넓은 광장이 자리합니다. 새벽이면 하얀 운해가 발밑에서 굽이치며, 바덴 정상은 햇볕과 바람의 동남부 한가운데 봉래선경처럼 느껴집니다.","facts":["바덴산은 높이 986미터로 남부 베트남 최고봉입니다.","정상의 떠이보다선 불상은 아시아에서 가장 높은 청동 부처상입니다.","이곳의 케이블카 시스템은 여러 세계 기록을 세웠습니다.","바덴산 봄 축제는 음력 정월 내내 열립니다."],"travelTips":["아름다운 운해를 볼 기회를 잡으려면 이른 아침에 정상에 오르세요.","케이블카 왕복권을 사고, 정상이 쌀쌀하므로 외투를 챙기세요."],"bestTime":"11월~4월과 음력 정월 축제철","visitDuration":"반나절~1일","ticket":"350,000동 (케이블카)","openingHours":"06:00–22:00","galleryCaptions":["호숫가 노을에 보랏빛 실루엣을 드리운 바덴산","산 정상의 부처상","하얀 운해 위로 솟아오른 부처상"]},"ja":{"name":"バーデン山","summary":"南部最高峰にして東南部の「屋根」。霊験あらたかな寺、近代的なロープウェイ、幻想的な雲海を備えた山。","story":"バーデン山は高さ986メートルで、南部ベトナムの最高峰であり、この地の「屋根」と称されます。山は貞節で霊験あらたかなリー・ティ・ティエンフオン（バーデン）の伝説と結びつき、その山腹には年中巡礼者を集める古寺が立ち並びます。今日では近代的なロープウェイが旅人を頂上まで運び、そこにはアジア最大の青銅仏であるタイボーダーソン仏像と広大な広場があります。明け方には白い雲海が足下に渦巻き、バーデンの頂は陽と風の東南部の只中にある蓬莱の地のように感じられます。","facts":["バーデン山は高さ986メートルで、南部ベトナムの最高峰です。","頂上のタイボーダーソン仏像はアジア最大の青銅仏です。","ここのロープウェイは数々の世界記録を打ち立てました。","バーデン山の春祭りは旧暦正月の間ずっと行われます。"],"travelTips":["美しい雲海を見る機会を得るには、早朝に頂上へ登りましょう。","ロープウェイの往復券を買い、頂上は肌寒いので上着を持参しましょう。"],"bestTime":"11月〜4月と旧暦正月の祭りの季節","visitDuration":"半日〜1日","ticket":"350,000ドン（ロープウェイ）","openingHours":"06:00–22:00","galleryCaptions":["湖畔の夕日に紫の影を落とすバーデン山","山頂の仏像","白い雲海の上にそびえ立つ仏像"]},"zh":{"name":"婆田山","summary":"南部最高峰，东南部的「屋脊」，拥有灵验的寺庙群、现代缆车和如梦似幻的云海。","story":"婆田山海拔986米，是越南南部最高的山峰，被誉为这片土地的「屋脊」。此山与贞洁灵验的李氏天香（婆田）传说相连，因此山坡上汇聚着众多古寺，终年吸引香客前来朝拜。如今，现代缆车将游客直送至山顶，那里矗立着亚洲最高的铜铸佛像——西补陀山佛像，以及一座宽阔的广场。每逢清晨，洁白的云海在脚下翻腾，使婆田之巅宛如阳光与劲风的东南部之中的蓬莱仙境。","facts":["婆田山海拔986米，是越南南部最高峰。","山顶的西补陀山佛像是亚洲最高的铜铸佛像。","这里的缆车系统曾创下多项世界纪录。","婆田山春季庙会贯穿整个农历正月。"],"travelTips":["清晨登顶，有望饱览绝美的云海。","购买往返缆车票，山顶微凉，请带上外套。"],"bestTime":"11月至4月及正月庙会时节","visitDuration":"半天至1天","ticket":"350,000越南盾（缆车）","openingHours":"06:00–22:00","galleryCaptions":["湖畔夕照中投下紫色剪影的婆田山","山顶上的佛像","在白色云海中拔地而起的佛像"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('toa-thanh-cao-dai-tay-ninh', 'toa-thanh-cao-dai', 'tay-ninh', 'Tòa Thánh Cao Đài Tây Ninh', 'Cao Dai Holy See (Tay Ninh)', 'temple', 106.1281, 11.3036, 'Thánh địa trung tâm của đạo Cao Đài, công trình tôn giáo rực rỡ với kiến trúc giao thoa Đông – Tây độc nhất vô nhị.', 'Tòa Thánh Cao Đài Tây Ninh là trung tâm tôn giáo của đạo Cao Đài, một tôn giáo bản địa ra đời tại Việt Nam đầu thế kỷ 20. Công trình đồ sộ với hai tháp chuông cao vút, mái ngói uốn lượn, sắc màu rực rỡ và những hoa văn rồng, hoa sen, Thiên Nhãn phủ khắp nội thất. Đặc biệt, kiến trúc giao thoa độc đáo giữa đền chùa Á Đông và nhà thờ phương Tây, mang vẻ đẹp huyền ảo khó nơi nào sánh được. Mỗi ngày bốn buổi, các tín đồ áo dài trắng cùng làm lễ trang nghiêm trong tiếng nhạc lễ, tạo nên khung cảnh thiêng liêng thu hút đông đảo du khách tới chiêm ngưỡng.', '["Đạo Cao Đài là tôn giáo bản địa lớn của Việt Nam, lập năm 1926.","Tòa Thánh khởi công năm 1933 và hoàn thành sau nhiều năm xây dựng.","Biểu tượng Thiên Nhãn (con mắt) xuất hiện khắp công trình.","Lễ đại đàn diễn ra bốn lần mỗi ngày với nghi thức trang nghiêm."]', '["Đến dự lễ trưa (12:00) để xem nghi thức cúng đông tín đồ nhất.","Ăn mặc lịch sự, tháo giày và giữ trật tự khi vào bên trong điện."]', 'Quanh năm, đẹp nhất mùa khô tháng 11–4', '1–2 giờ', '', '06:00–18:00', '["verified","popular","ai-recommended"]', '["temple","culture","history","photography"]', '[{"seed":"caodai-toathanh","caption":"Tòa Thánh Cao Đài rực rỡ sắc màu","ratio":"16/9"},{"seed":"caodai-thiennhan","caption":"Biểu tượng Thiên Nhãn linh thiêng","ratio":"4/3"},{"seed":"caodai-lehoi","caption":"Tín đồ áo trắng làm lễ trang nghiêm","ratio":"1/1"}]', '["nui-ba-den-tay-ninh"]', 0, '{"en":{"name":"Cao Dai Holy See of Tay Ninh","summary":"The central holy land of the Cao Dai religion, a dazzling religious monument with a uniquely East–West blended architecture.","story":"The Cao Dai Holy See of Tay Ninh is the religious center of Caodaism, a homegrown Vietnamese faith born in the early 20th century. The grand complex features two soaring bell towers, curving tiled roofs, brilliant colors and motifs of dragons, lotuses and the Divine Eye covering its interior. Most strikingly, its architecture is a singular blend of East Asian temple and Western church, with an ethereal beauty matched almost nowhere else. Four times a day, followers in white robes perform solemn rites amid ceremonial music, creating a sacred scene that draws crowds of visitors to behold.","facts":["Caodaism is a major homegrown religion of Vietnam, founded in 1926.","The Holy See broke ground in 1933 and was completed after many years of construction.","The Divine Eye symbol appears throughout the structure.","The grand ceremony is held four times a day with solemn ritual."],"travelTips":["Attend the noon ceremony (12:00) to see the rite with the most followers.","Dress neatly, remove your shoes and stay quiet when entering the main hall."],"bestTime":"Year-round, most beautiful in the dry season from November to April","visitDuration":"1–2 hours","ticket":"","openingHours":"06:00–18:00","galleryCaptions":["The vividly colorful Cao Dai Holy See","The sacred Divine Eye symbol","Followers in white performing the solemn rite"]},"ko":{"name":"떠이닌 까오다이교 대성전","summary":"까오다이교의 중심 성지로, 동서양이 어우러진 유일무이한 건축의 화려한 종교 건축물.","story":"떠이닌 까오다이교 대성전은 20세기 초 베트남에서 탄생한 토착 종교인 까오다이교의 종교 중심지입니다. 이 거대한 건축물은 하늘 높이 솟은 두 개의 종탑과 굽이치는 기와지붕, 화려한 색채, 그리고 내부 곳곳을 뒤덮은 용·연꽃·천안(天眼) 문양을 자랑합니다. 특히 동아시아 사원과 서양 교회가 어우러진 독특한 건축은 어디에도 견주기 어려운 환상적인 아름다움을 자아냅니다. 하루 네 차례, 흰 아오자이를 입은 신도들이 의례 음악 속에서 엄숙하게 예배를 올리며, 수많은 여행객이 찾아와 우러러보는 성스러운 풍경을 만들어 냅니다.","facts":["까오다이교는 1926년에 창시된 베트남의 주요 토착 종교입니다.","대성전은 1933년에 착공되어 여러 해의 공사를 거쳐 완공되었습니다.","천안(눈) 상징이 건축물 전체에 등장합니다.","대법회는 엄숙한 의례와 함께 하루 네 차례 거행됩니다."],"travelTips":["가장 많은 신도가 참여하는 예배를 보려면 정오(12:00) 의례에 가세요.","전(殿) 안에 들어갈 때는 단정하게 차려입고 신발을 벗으며 정숙하세요."],"bestTime":"연중, 11~4월 건기에 가장 아름다움","visitDuration":"1~2시간","ticket":"","openingHours":"06:00–18:00","galleryCaptions":["화려한 색채의 까오다이교 대성전","영험한 천안 상징","흰옷 차림으로 엄숙하게 예배하는 신도들"]},"ja":{"name":"タイニン・カオダイ教総本山","summary":"カオダイ教の中心となる聖地。東西が融合した唯一無二の建築を持つ、絢爛たる宗教建築。","story":"タイニン・カオダイ教総本山は、20世紀初頭にベトナムで生まれた土着宗教カオダイ教の宗教的中心地です。この壮大な建造物は、天を衝く二つの鐘楼、うねる瓦屋根、鮮やかな色彩、そして内部一面を覆う龍・蓮・天眼の意匠を誇ります。とりわけ、東アジアの寺院と西洋の教会が融合した独特の建築は、ほかに比類のない幻想的な美しさを醸し出します。一日に四度、白いアオザイを纏った信徒たちが儀礼の音楽の中で厳かに礼拝を行い、多くの旅人が訪れて見入る神聖な光景を作り出します。","facts":["カオダイ教は1926年に創始されたベトナムの主要な土着宗教です。","総本山は1933年に着工し、長年の建設を経て完成しました。","天眼（目）のシンボルが建造物全体に現れます。","大祭典は厳かな儀礼とともに一日に四度行われます。"],"travelTips":["最も多くの信徒が参加する礼拝を見るには、正午（12:00）の儀礼に行きましょう。","殿内に入る際は、きちんとした装いで靴を脱ぎ、静粛にしましょう。"],"bestTime":"通年、11〜4月の乾季が最も美しい","visitDuration":"1〜2時間","ticket":"","openingHours":"06:00–18:00","galleryCaptions":["色鮮やかなカオダイ教総本山","霊験あらたかな天眼のシンボル","白い装いで厳かに礼拝する信徒たち"]},"zh":{"name":"西宁高台教圣座","summary":"高台教的核心圣地，一座绚丽的宗教建筑，融汇东西方的建筑风格独一无二。","story":"西宁高台教圣座是高台教的宗教中心，这是一种20世纪初诞生于越南的本土宗教。建筑宏伟，两座钟楼高耸入云，瓦顶起伏蜿蜒，色彩绚丽，内部满布龙、莲花和天眼的纹饰。尤为特别的是，其建筑独特地融汇了东方庙宇与西方教堂，呈现出别处难以比拟的梦幻之美。每天四次，身着白色奥黛的信徒在礼乐声中庄严举行礼拜，营造出庄严神圣的景象，吸引众多游客前来观瞻。","facts":["高台教是越南重要的本土宗教，创立于1926年。","圣座于1933年动工，历经多年建设方才落成。","天眼（眼睛）的象征遍布整座建筑。","大法会每日举行四次，仪式庄严肃穆。"],"travelTips":["参加正午（12:00）的礼拜，可看到信徒最多的祭仪。","进入殿内时请着装得体、脱鞋并保持肃静。"],"bestTime":"全年皆宜，11月至4月旱季最美","visitDuration":"1–2小时","ticket":"","openingHours":"06:00–18:00","galleryCaptions":["色彩绚丽的高台教圣座","灵验的天眼象征","身着白衣庄严礼拜的信徒"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('long-an-lang-noi-tan-lap', 'lang-noi-tan-lap', 'long-an', 'Làng nổi Tân Lập', 'Tan Lap Floating Village', 'park', 105.8214, 10.7689, 'Rừng tràm xanh ngút ngàn của Đồng Tháp Mười, với con đường xuyên rừng và tháp ngắm cảnh trên vùng đất ngập nước.', 'Nằm giữa lòng Đồng Tháp Mười, Làng nổi Tân Lập là khu sinh thái rừng tràm rộng hơn 600 hecta. Du khách đi bộ trên con đường bê tông dài gần năm cây số luồn lách giữa hai hàng tràm xanh mát, ánh nắng len qua tán lá tạo nên khung cảnh huyền ảo. Một chuyến xuồng nhỏ len lỏi qua những rạch nước phủ kín bèo, tiếng chim ríu rít hòa cùng hương tràm thoang thoảng. Lên đỉnh tháp quan sát cao gần ba mươi mét, cả vùng đất ngập nước mênh mông hiện ra như một tấm thảm xanh trải dài tới chân trời. Đây là nơi lý tưởng để cảm nhận nhịp sống chậm rãi của miền Tây sông nước.', '["Khu rừng tràm rộng khoảng 635 hecta thuộc vùng Đồng Tháp Mười.","Con đường xuyên rừng dài gần 5 km được đổ bê tông giữa rừng tràm.","Tháp quan sát cao gần 30 mét cho tầm nhìn toàn cảnh vùng đất ngập nước.","Là điểm quay nhiều bộ phim và MV nhờ cảnh rừng tràm thơ mộng."]', '["Mang theo nón, áo chống nắng và thuốc chống côn trùng khi đi sâu vào rừng.","Đi sớm buổi sáng để có ánh sáng đẹp và tránh nắng gắt giữa trưa."]', 'Tháng 9 đến tháng 11, mùa nước nổi rừng tràm xanh tốt nhất', 'Nửa ngày', '60.000đ', '07:00 - 17:00 hằng ngày', '["popular","verified","hidden-gem"]', '["nature","park","photography"]', '[{"seed":"tanlap-tram-road","caption":"Con đường bê tông xuyên rừng tràm","ratio":"16/9"},{"seed":"tanlap-watchtower","caption":"Tháp quan sát giữa vùng đất ngập nước","ratio":"4/3"},{"seed":"tanlap-boat","caption":"Xuồng nhỏ len qua rạch nước phủ bèo","ratio":"1/1"}]', '["long-an-lang-sen"]', 1, '{"en":{"name":"Tan Lap Floating Village","summary":"An endless green cajuput forest in the Plain of Reeds, with a path through the trees and an observation tower over the wetlands.","story":"Set in the heart of the Plain of Reeds, Tan Lap Floating Village is a cajuput forest eco-zone spanning more than 600 hectares. Visitors walk along a concrete path nearly five kilometers long, winding between two rows of cool green cajuput trees, with sunlight filtering through the canopy to create a magical scene. A small boat threads through duckweed-covered canals, birdsong mingling with the faint scent of cajuput. From the top of the nearly thirty-meter observation tower, the vast wetland spreads out like a green carpet stretching to the horizon. This is an ideal place to feel the unhurried pace of the Mekong''s waterland.","facts":["The cajuput forest spans around 635 hectares within the Plain of Reeds.","The path through the forest runs nearly 5 km, paved in concrete amid the cajuput trees.","The nearly 30-meter observation tower offers a panoramic view of the wetlands.","It is a popular filming location for movies and music videos thanks to its poetic cajuput scenery."],"travelTips":["Bring a hat, sun-protective clothing and insect repellent when venturing deep into the forest.","Go early in the morning for beautiful light and to avoid the harsh midday sun."],"bestTime":"September to November, flood season when the cajuput forest is greenest","visitDuration":"Half a day","ticket":"60,000 VND","openingHours":"07:00 - 17:00 daily","galleryCaptions":["The concrete path through the cajuput forest","The observation tower amid the wetlands","A small boat threading through duckweed-covered canals"]},"ko":{"name":"떤럽 수상마을","summary":"동탑므어이의 끝없는 초록 멜라루카 숲, 숲을 가로지르는 길과 습지 위 전망탑이 있는 곳.","story":"동탑므어이 한가운데 자리한 떤럽 수상마을은 600헥타르가 넘는 멜라루카 숲 생태구역입니다. 여행객은 두 줄의 시원한 초록 멜라루카 숲 사이를 굽이도는 약 5km 길이의 콘크리트 길을 걷고, 잎새 사이로 스며드는 햇살은 환상적인 풍경을 자아냅니다. 작은 배가 부평초로 뒤덮인 수로 사이를 누비며, 새소리가 은은한 멜라루카 향과 어우러집니다. 약 30m 높이의 전망탑에 오르면 드넓은 습지가 지평선까지 펼쳐진 초록 융단처럼 모습을 드러냅니다. 메콩 물의 고장의 느긋한 삶의 리듬을 느끼기에 더없이 좋은 곳입니다.","facts":["동탑므어이 지역에 속한 약 635헥타르 규모의 멜라루카 숲입니다.","숲을 가로지르는 길은 약 5km로, 멜라루카 숲 사이에 콘크리트로 포장되어 있습니다.","약 30m 높이의 전망탑에서 습지 전경을 조망할 수 있습니다.","시적인 멜라루카 숲 풍경 덕분에 영화와 뮤직비디오 촬영지로 인기가 많습니다."],"travelTips":["숲 깊숙이 들어갈 때는 모자, 자외선 차단 의류, 모기 기피제를 챙기세요.","아름다운 빛을 담고 한낮의 뙤약볕을 피하려면 이른 아침에 가세요."],"bestTime":"9~11월, 멜라루카 숲이 가장 푸르른 물난리 시기","visitDuration":"반나절","ticket":"60,000동","openingHours":"매일 07:00 - 17:00","galleryCaptions":["멜라루카 숲을 가로지르는 콘크리트 길","습지 한가운데의 전망탑","부평초로 뒤덮인 수로를 누비는 작은 배"]},"ja":{"name":"タンラップ水上村","summary":"ドンタップムオイの果てしない緑のメラルーカ林、林を貫く道と湿地を望む展望塔がある場所。","story":"ドンタップムオイの真ん中に位置するタンラップ水上村は、600ヘクタールを超えるメラルーカ林のエコゾーンです。旅人は二列の涼しげな緑のメラルーカ林の間を縫う、全長約5キロのコンクリートの道を歩き、葉の間から差し込む陽光が幻想的な景色を生み出します。小さな舟が浮草に覆われた水路を縫い、鳥のさえずりがほのかなメラルーカの香りと溶け合います。高さ約30メートルの展望塔に登れば、広大な湿地が地平線まで続く緑の絨毯のように姿を現します。メコンの水の里のゆったりした暮らしのリズムを感じるのに最適な場所です。","facts":["ドンタップムオイ地域にある約635ヘクタールのメラルーカ林です。","林を貫く道は約5kmで、メラルーカ林の間にコンクリートで舗装されています。","高さ約30メートルの展望塔から湿地の全景を望めます。","詩情あふれるメラルーカ林の景色から、映画やMVの撮影地として人気です。"],"travelTips":["林の奥へ入る際は、帽子、日よけの衣類、虫よけを持参しましょう。","美しい光をとらえ、真昼の強い日差しを避けるため、早朝に行きましょう。"],"bestTime":"9〜11月、メラルーカ林が最も緑豊かな増水期","visitDuration":"半日","ticket":"60,000ドン","openingHours":"毎日07:00 - 17:00","galleryCaptions":["メラルーカ林を貫くコンクリートの道","湿地の真ん中の展望塔","浮草に覆われた水路を縫う小さな舟"]},"zh":{"name":"新立浮村","summary":"同塔梅地区一望无际的翠绿白千层林，林间穿行的栈道和湿地之上的观景塔。","story":"坐落于同塔梅腹地的新立浮村，是一片占地六百多公顷的白千层林生态区。游客沿着近五公里长的混凝土栈道，在两排清凉翠绿的白千层林间穿行，阳光透过枝叶洒落，营造出梦幻般的景致。一叶小舟在布满浮萍的水道中穿梭，鸟鸣与淡淡的白千层香气交融。登上近三十米高的观景塔，辽阔的湿地宛如一张绿毯铺展至天际。这里是感受湄公水乡悠然生活节奏的理想之地。","facts":["白千层林面积约635公顷，属同塔梅地区。","穿林栈道近5公里，在白千层林间以混凝土铺成。","近30米高的观景塔可俯瞰湿地全景。","凭借诗意的白千层林景，是许多电影和MV的取景地。"],"travelTips":["深入林中时请带上帽子、防晒衣和驱虫剂。","清晨前来，光线优美，可避开正午烈日。"],"bestTime":"9月至11月，白千层林最翠绿的涨水季节","visitDuration":"半天","ticket":"60,000越南盾","openingHours":"每日07:00 - 17:00","galleryCaptions":["穿过白千层林的混凝土栈道","湿地之中的观景塔","在布满浮萍的水道中穿梭的小舟"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('long-an-lang-sen', 'lang-sen', 'long-an', 'Khu bảo tồn đất ngập nước Láng Sen', 'Lang Sen Wetland Reserve', 'park', 105.7333, 10.7667, 'Vùng lõi Đồng Tháp Mười với hệ sinh thái đất ngập nước phong phú, nơi trú ngụ của nhiều loài chim nước quý hiếm.', 'Khu bảo tồn đất ngập nước Láng Sen được ví như một Đồng Tháp Mười thu nhỏ, lưu giữ gần như nguyên vẹn hệ sinh thái ngập nước đặc trưng của miền Tây. Trên diện tích hơn năm nghìn hecta, nơi đây là mái nhà của hàng trăm loài thực vật, cá nước ngọt và nhiều loài chim quý như cò, vạc, điên điển. Vào mùa nước nổi, những cánh đồng sen, súng và lúa ma trải dài bất tận, từng đàn chim bay rợp trời lúc chiều buông. Đi xuồng giữa kênh rạch yên ả, du khách có thể quan sát đời sống hoang dã nguyên sơ và lắng nghe thiên nhiên thở nhẹ giữa vùng đồng bưng.', '["Diện tích bảo tồn rộng hơn 5.000 hecta thuộc vùng lõi Đồng Tháp Mười.","Được công nhận là khu Ramsar - vùng đất ngập nước có tầm quan trọng quốc tế.","Là nơi trú ngụ của nhiều loài chim nước và cá nước ngọt quý hiếm.","Cảnh quan sen, súng và lúa ma đặc trưng cho hệ sinh thái đồng bưng."]', '["Liên hệ trước với ban quản lý để được bố trí xuồng và hướng dẫn.","Mang ống nhòm nếu muốn quan sát chim, đẹp nhất lúc bình minh và hoàng hôn."]', 'Tháng 8 đến tháng 11 mùa nước nổi, nhiều chim về trú ngụ', 'Nửa ngày', '', '07:00 - 17:00 hằng ngày', '["verified","hidden-gem","ai-recommended"]', '["nature","park","photography"]', '[{"seed":"langsen-birds","caption":"Lạch nước lặng lờ len giữa bụi cây ngập nước","ratio":"16/9"},{"seed":"langsen-lotus","caption":"Đồng cỏ ngập nước xanh trải tới chân trời","ratio":"4/3"},{"seed":"langsen-canal","caption":"Xuồng len giữa kênh rạch yên ả","ratio":"1/1"}]', '["long-an-lang-noi-tan-lap"]', 0, '{"en":{"name":"Lang Sen Wetland Reserve","summary":"The core of the Plain of Reeds, with a rich wetland ecosystem that shelters many rare waterbird species.","story":"The Lang Sen Wetland Reserve is often called a miniature Plain of Reeds, preserving almost intact the wetland ecosystem characteristic of the Mekong. Across more than five thousand hectares, it is home to hundreds of plant species, freshwater fish and rare birds such as storks, night herons and water cocks. In flood season, fields of lotus, water lilies and wild rice stretch endlessly, and flocks of birds fill the sky at dusk. Drifting by boat through peaceful canals, visitors can observe pristine wildlife and listen to nature breathe gently across the floodplain.","facts":["The reserve spans more than 5,000 hectares in the core of the Plain of Reeds.","It is recognized as a Ramsar site — a wetland of international importance.","It shelters many rare species of waterbird and freshwater fish.","Its landscape of lotus, water lily and wild rice is characteristic of the floodplain ecosystem."],"travelTips":["Contact the management board in advance to arrange a boat and a guide.","Bring binoculars for birdwatching, best at sunrise and sunset."],"bestTime":"August to November, the flood season when many birds gather","visitDuration":"Half a day","ticket":"","openingHours":"07:00 - 17:00 daily","galleryCaptions":["A still stream winding through flooded shrubs","A green flooded meadow stretching to the horizon","A boat threading through peaceful canals"]},"ko":{"name":"랑센 습지보호구역","summary":"여러 희귀 물새가 서식하는 풍부한 습지 생태계를 간직한 동탑므어이의 중심부.","story":"랑센 습지보호구역은 축소판 동탑므어이라 불리며, 메콩 특유의 습지 생태계를 거의 원형 그대로 간직하고 있습니다. 5천 헥타르가 넘는 면적에 수백 종의 식물과 민물고기, 그리고 두루미·해오라기·물닭 같은 희귀 새들의 보금자리입니다. 물난리 철이면 연꽃, 수련, 야생벼 들판이 끝없이 펼쳐지고, 해 질 녘 새 떼가 하늘을 가득 메웁니다. 고요한 수로를 배로 떠돌며 여행객은 원시 그대로의 야생을 관찰하고 범람원에서 자연이 가만히 숨 쉬는 소리에 귀 기울일 수 있습니다.","facts":["동탑므어이 중심부에 위치한 5,000헥타르가 넘는 보호구역입니다.","람사르 습지 — 국제적으로 중요한 습지로 인정받았습니다.","여러 희귀 물새와 민물고기의 서식지입니다.","연꽃, 수련, 야생벼 경관은 범람원 생태계의 특징을 보여 줍니다."],"travelTips":["사전에 관리사무소에 연락해 배와 안내를 준비하세요.","새를 관찰하려면 쌍안경을 챙기세요. 일출과 일몰 때가 가장 아름답습니다."],"bestTime":"8~11월, 새가 많이 모여드는 물난리 시기","visitDuration":"반나절","ticket":"","openingHours":"매일 07:00 - 17:00","galleryCaptions":["침수된 덤불 사이를 잔잔히 흐르는 물길","지평선까지 펼쳐진 초록 침수 초원","고요한 수로를 누비는 배"]},"ja":{"name":"ランセン湿地保護区","summary":"多くの希少な水鳥が生息する豊かな湿地生態系を擁するドンタップムオイの中核。","story":"ランセン湿地保護区はミニ・ドンタップムオイと呼ばれ、メコン特有の湿地生態系をほぼ原形のまま保っています。5千ヘクタールを超える面積に、数百種の植物や淡水魚、そしてコウノトリ・ゴイサギ・バンといった希少な鳥たちの住処があります。増水期には蓮、睡蓮、野生稲の畑が果てしなく広がり、夕暮れには鳥の群れが空を埋めます。穏やかな水路を舟で漂いながら、旅人は手つかずの野生を観察し、氾濫原で自然が静かに息づく音に耳を傾けられます。","facts":["ドンタップムオイの中核に位置する5,000ヘクタールを超える保護区です。","ラムサール条約湿地 — 国際的に重要な湿地として認定されています。","多くの希少な水鳥や淡水魚の生息地です。","蓮、睡蓮、野生稲の景観は氾濫原の生態系の特徴を示します。"],"travelTips":["事前に管理事務所に連絡し、舟とガイドを手配しましょう。","野鳥観察には双眼鏡を持参しましょう。日の出と日の入りが最も美しい時間です。"],"bestTime":"8〜11月、多くの鳥が集まる増水期","visitDuration":"半日","ticket":"","openingHours":"毎日07:00 - 17:00","galleryCaptions":["冠水した茂みの間を静かに流れる水路","地平線まで広がる緑の冠水草原","穏やかな水路を縫う舟"]},"zh":{"name":"莨莲湿地保护区","summary":"同塔梅核心区，湿地生态丰富，是众多珍稀水鸟的栖息地。","story":"莨莲湿地保护区被誉为缩小版的同塔梅，几乎原封不动地保留了湄公特有的湿地生态系统。在五千多公顷的土地上，这里是数百种植物、淡水鱼以及鹭、夜鹭、董鸡等多种珍稀鸟类的家园。涨水季节，莲花、睡莲和野稻田一望无际，黄昏时分鸟群遮天蔽日。坐船漂荡在宁静的河渠间，游客可观赏原始的野生景象，聆听大自然在洼地间轻轻呼吸。","facts":["保护区面积超过5,000公顷，位于同塔梅核心区。","被列为拉姆萨尔湿地——具有国际重要意义的湿地。","是众多珍稀水鸟和淡水鱼的栖息地。","莲花、睡莲和野稻的景观体现了洼地生态系统的特色。"],"travelTips":["提前联系管理处，安排船只和向导。","若想观鸟请带望远镜，日出和日落时最美。"],"bestTime":"8月至11月涨水季节，众多鸟类前来栖息","visitDuration":"半天","ticket":"","openingHours":"每日07:00 - 17:00","galleryCaptions":["在水淹灌木丛间静静流淌的水道","延伸至天际的翠绿水淹草原","在宁静河渠间穿梭的小舟"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tien-giang-cu-lao-thoi-son', 'cu-lao-thoi-son', 'tien-giang', 'Cù lao Thới Sơn', 'Thoi Son Islet', 'village', 106.3636, 10.3389, 'Cù lao xanh mát giữa sông Tiền nổi tiếng với vườn cây trái, mật ong và những điệu đờn ca tài tử ngọt ngào.', 'Cù lao Thới Sơn, hay còn gọi là cồn Lân, là một trong tứ linh nổi giữa dòng sông Tiền hiền hòa. Đặt chân lên cù lao, du khách lạc vào miệt vườn sum suê nhãn, sầu riêng và bưởi da xanh. Người dân mời khách thưởng trà mật ong pha tắc, nếm trái cây hái tận vườn và nghe các nghệ nhân ngân nga đờn ca tài tử, di sản văn hóa của vùng Nam Bộ. Thú vị nhất là ngồi xuồng ba lá để các cô gái mặc áo bà ba chèo len lỏi qua những con rạch nhỏ rợp bóng dừa nước. Một ngày ở Thới Sơn gói trọn hồn quê miền Tây chân chất và mến khách.', '["Là một trong bốn cù lao mang tên tứ linh Long, Lân, Quy, Phụng trên sông Tiền.","Nổi tiếng với nghề nuôi ong lấy mật và các vườn cây ăn trái sum suê.","Đờn ca tài tử Nam Bộ thường được biểu diễn phục vụ du khách tại đây.","Trải nghiệm chèo xuồng ba lá qua rạch dừa nước là đặc trưng không thể bỏ qua."]', '["Đi tàu từ bến Mỹ Tho để ngắm cảnh sông Tiền trên đường ra cù lao.","Nên đi theo tour ghép để trải nghiệm trọn gói vườn trái cây và đờn ca tài tử."]', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', 'Nửa ngày', '150.000đ trọn gói tour', '08:00 - 17:00 hằng ngày', '["popular","verified","trending"]', '["village","culture","nature","food"]', '[{"seed":"thoison-sampan","caption":"Chèo xuồng ba lá qua rạch dừa nước","ratio":"16/9"},{"seed":"thoison-honey","caption":"Thưởng trà mật ong và trái cây miệt vườn","ratio":"4/3"},{"seed":"thoison-music","caption":"Nghệ nhân biểu diễn đờn ca tài tử","ratio":"1/1"}]', '["tien-giang-cho-noi-cai-be"]', 1, '{"en":{"name":"Thoi Son Islet","summary":"A green islet in the Tien River, famous for fruit orchards, honey and the sweet melodies of don ca tai tu.","story":"Thoi Son Islet, also known as Lan Islet, is one of the four ''sacred-animal'' islets adrift in the gentle Tien River. Setting foot on the islet, visitors wander into lush orchards of longan, durian and green-skinned pomelo. Locals offer guests honey tea with kumquat, fresh fruit picked straight from the garden, and the chance to hear artists perform don ca tai tu, the cultural heritage of southern Vietnam. Best of all is riding a sampan as ao-ba-ba-clad girls paddle through small canals shaded by water-coconut palms. A day in Thoi Son captures the wholehearted, hospitable soul of the Mekong countryside.","facts":["It is one of four islets named after the sacred animals — Dragon, Unicorn, Tortoise and Phoenix — on the Tien River.","It is famous for beekeeping for honey and lush fruit orchards.","Southern don ca tai tu is regularly performed for visitors here.","Paddling a sampan through water-coconut canals is a signature experience not to be missed."],"travelTips":["Take a boat from My Tho pier to enjoy the Tien River scenery on the way to the islet.","Join a group tour for the full package of fruit orchards and don ca tai tu."],"bestTime":"May to August, when the fruit is in full season","visitDuration":"Half a day","ticket":"150,000 VND full tour package","openingHours":"08:00 - 17:00 daily","galleryCaptions":["Paddling a sampan through water-coconut canals","Enjoying honey tea and orchard fruit","Artists performing don ca tai tu"]},"ko":{"name":"터이선섬","summary":"과수원과 꿀, 달콤한 던까따이뜨로 유명한 띠엔강의 초록빛 섬.","story":"런섬이라고도 불리는 터이선섬은 잔잔한 띠엔강에 떠 있는 사령(四靈)의 섬 중 하나입니다. 섬에 발을 디디면 용안, 두리안, 초록 껍질 포멜로가 무성한 과수원에 들어서게 됩니다. 주민들은 손님에게 금귤을 탄 꿀차를 권하고, 정원에서 갓 딴 과일을 맛보게 하며, 남부의 문화유산 던까따이뜨를 부르는 명인들의 노랫가락을 들려줍니다. 가장 흥미로운 것은 아오바바를 입은 처자들이 물야자수 그늘이 드리운 작은 수로 사이로 젓는 나룻배를 타는 것입니다. 터이선에서의 하루는 메콩 시골의 순박하고 손님을 반기는 정취를 고스란히 담아냅니다.","facts":["띠엔강 위 사령 — 용·기린·거북·봉황 — 의 이름을 딴 네 섬 중 하나입니다.","꿀을 얻는 양봉업과 무성한 과수원으로 유명합니다.","남부 던까따이뜨가 이곳에서 여행객을 위해 정기적으로 공연됩니다.","물야자수 수로를 나룻배로 젓는 체험은 빼놓을 수 없는 명물입니다."],"travelTips":["미토 선착장에서 배를 타고 섬으로 가는 길에 띠엔강 풍경을 감상하세요.","과수원과 던까따이뜨를 모두 즐기려면 패키지 합류 투어를 이용하세요."],"bestTime":"5~8월, 과일이 무르익는 철","visitDuration":"반나절","ticket":"투어 패키지 150,000동","openingHours":"매일 08:00 - 17:00","galleryCaptions":["물야자수 수로를 나룻배로 젓기","꿀차와 과수원 과일 즐기기","던까따이뜨를 공연하는 명인"]},"ja":{"name":"トイソン島","summary":"果樹園と蜂蜜、甘いドンカータイトゥで知られるティエン川の緑の島。","story":"ラン島とも呼ばれるトイソン島は、穏やかなティエン川に浮かぶ四霊の島の一つです。島に足を踏み入れると、リュウガン、ドリアン、緑皮ザボンが茂る果樹園に分け入ることになります。住民は客にキンカン入りの蜂蜜茶を勧め、庭で採れたての果物を味わわせ、南部の文化遺産ドンカータイトゥを奏でる名手たちの歌声を聞かせてくれます。最も興味深いのは、アオババを着た娘たちがニッパヤシの陰が落ちる小さな水路を縫って漕ぐ小舟に乗ることです。トイソンでの一日は、メコンの田舎の素朴でもてなしの心に満ちた情緒を余すところなく映し出します。","facts":["ティエン川の四霊 — 龍・麒麟・亀・鳳凰 — の名を冠する四つの島の一つです。","蜂蜜を採る養蜂業と茂った果樹園で有名です。","南部のドンカータイトゥがここで旅人のために定期的に演奏されます。","ニッパヤシの水路を小舟で漕ぐ体験は外せない名物です。"],"travelTips":["ミトーの船着場から舟に乗り、島へ向かう道中でティエン川の景色を楽しみましょう。","果樹園とドンカータイトゥをすべて楽しむには、相乗りツアーを利用しましょう。"],"bestTime":"5〜8月、果物が熟す季節","visitDuration":"半日","ticket":"ツアーパッケージ150,000ドン","openingHours":"毎日08:00 - 17:00","galleryCaptions":["ニッパヤシの水路を小舟で漕ぐ","蜂蜜茶と果樹園の果物を楽しむ","ドンカータイトゥを演奏する名手"]},"zh":{"name":"泰山岛","summary":"前江中翠绿的小岛，以果园、蜂蜜和甜美的才子弹唱闻名。","story":"泰山岛又名麟洲，是漂浮在温和前江中的四灵之一。踏上小岛，游客便走进果实累累的果园，龙眼、榴莲、青皮柚琳琅满目。岛民招待客人喝金桔蜂蜜茶，品尝园中现摘的水果，聆听艺人吟唱南部文化遗产才子弹唱。最有趣的是坐三板小舟，看身着奥巴巴的姑娘划桨，穿行于水椰遮荫的小水道间。在泰山岛的一天，尽显湄公乡村质朴好客的乡土风情。","facts":["是前江上以四灵——龙、麟、龟、凤——命名的四岛之一。","以养蜂取蜜和果实累累的果园闻名。","南部才子弹唱常在此为游客表演。","划三板小舟穿行水椰水道是不可错过的特色体验。"],"travelTips":["从美湫码头乘船，在前往小岛途中欣赏前江风光。","建议参加拼团游，一次体验果园和才子弹唱的全套行程。"],"bestTime":"5月至8月，水果成熟旺季","visitDuration":"半天","ticket":"全套行程150,000越南盾","openingHours":"每日08:00 - 17:00","galleryCaptions":["划三板小舟穿行水椰水道","品尝蜂蜜茶和果园水果","表演才子弹唱的艺人"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tien-giang-cho-noi-cai-be', 'cho-noi-cai-be', 'tien-giang', 'Chợ nổi Cái Bè', 'Cai Be Floating Market', 'market', 105.9486, 10.3556, 'Chợ nổi lâu đời trên sông Tiền, nơi ghe thuyền tấp nập buôn bán trái cây và đặc sản miền Tây từ tinh mơ.', 'Chợ nổi Cái Bè từng là một trong những chợ nổi sầm uất nhất đồng bằng sông Cửu Long, nằm ở ngã ba sông giáp ranh Tiền Giang, Vĩnh Long và Bến Tre. Từ lúc trời còn nhập nhoạng, hàng trăm ghe thuyền chở đầy trái cây, rau củ đã tụ về, mỗi ghe treo một cây bẹo cắm hàng hóa lủng lẳng để rao bán. Tiếng máy nổ, tiếng cười nói và mùi hủ tiếu nóng hổi từ ghe hàng rong tạo nên một bức tranh sông nước sống động. Du khách ngồi trên thuyền nhỏ luồn giữa chợ, mua trái cây tươi rói và cảm nhận nhịp giao thương đậm chất miền Tây vẫn còn được gìn giữ qua bao thế hệ.', '["Nằm ở ngã ba sông giáp ranh ba tỉnh Tiền Giang, Vĩnh Long và Bến Tre.","Các ghe dùng cây bẹo treo hàng hóa để giới thiệu mặt hàng đang bán.","Là một trong những chợ nổi hình thành sớm nhất ở miền Tây Nam Bộ.","Chuyên buôn bán sỉ trái cây, rau củ và đặc sản vùng đồng bằng."]', '["Đi từ 5h đến 7h sáng để thấy chợ nổi nhộn nhịp nhất.","Kết hợp tham quan lò kẹo dừa và làng nghề thủ công ven sông gần đó."]', 'Quanh năm, sáng sớm là thời điểm chợ đông nhất', '2-3 giờ', '', 'Họp chợ từ 04:00 - 08:00 hằng ngày', '["popular","verified"]', '["market","culture","food","photography"]', '[{"seed":"caibe-floating","caption":"Ghe thuyền tấp nập họp chợ trên sông","ratio":"16/9"},{"seed":"caibe-beo","caption":"Người chèo ghe nón lá qua sông dưới chân cầu","ratio":"4/3"},{"seed":"caibe-fruits","caption":"Trái cây tươi chất đầy ghe","ratio":"1/1"}]', '["tien-giang-cu-lao-thoi-son"]', 0, '{"en":{"name":"Cai Be Floating Market","summary":"A long-established floating market on the Tien River, where boats bustle from dawn trading fruit and Mekong specialties.","story":"Cai Be Floating Market was once among the busiest floating markets in the Mekong Delta, sitting at a river junction bordering Tien Giang, Vinh Long and Ben Tre. From the first dim light, hundreds of boats laden with fruit and vegetables gather, each hoisting a beo pole hung with dangling samples of its wares. The rumble of engines, the laughter and the aroma of steaming hu tieu from vendor boats create a lively river scene. Visitors ride small boats threading through the market, buy fresh fruit and feel the distinctly Mekong rhythm of trade preserved through generations.","facts":["It sits at a river junction bordering the three provinces of Tien Giang, Vinh Long and Ben Tre.","Boats use a beo pole to display the goods on offer.","It is one of the earliest floating markets formed in the southwestern Mekong region.","It specializes in wholesale fruit, vegetables and delta specialties."],"travelTips":["Go between 5 and 7 a.m. to see the floating market at its busiest.","Combine your visit with nearby coconut-candy workshops and riverside craft villages."],"bestTime":"Year-round, early morning is when the market is busiest","visitDuration":"2-3 hours","ticket":"","openingHours":"Market runs 04:00 - 08:00 daily","galleryCaptions":["Boats bustling at market on the river","A conical-hatted rower crossing the river beneath a bridge","Fresh fruit piled high on a boat"]},"ko":{"name":"까이베 수상시장","summary":"띠엔강의 유서 깊은 수상시장, 새벽부터 배들이 과일과 메콩 특산물을 사고파는 곳.","story":"까이베 수상시장은 한때 메콩델타에서 가장 번화한 수상시장 중 하나로, 띠엔장·빈롱·벤쩨가 맞닿는 강 합류점에 자리합니다. 동이 트기 전 어스름할 때부터 과일과 채소를 가득 실은 수백 척의 배가 모여들고, 저마다 베오 장대에 상품을 주렁주렁 매달아 호객합니다. 엔진 소리, 웃음소리, 그리고 행상선에서 풍기는 김 모락모락 나는 후띠에우 향이 생동감 넘치는 강 풍경을 빚어냅니다. 여행객은 작은 배를 타고 시장 사이를 누비며 싱싱한 과일을 사고, 여러 세대에 걸쳐 이어 온 메콩 특유의 교역 리듬을 느낄 수 있습니다.","facts":["띠엔장·빈롱·벤쩨 세 성이 맞닿는 강 합류점에 위치합니다.","배들은 베오 장대로 판매 중인 상품을 내걸어 소개합니다.","메콩 남서부에서 가장 일찍 형성된 수상시장 중 하나입니다.","과일, 채소, 델타 특산물의 도매 거래를 전문으로 합니다."],"travelTips":["수상시장이 가장 붐비는 오전 5~7시에 가세요.","인근의 코코넛 캔디 공방과 강변 수공예 마을 방문을 함께 즐겨 보세요."],"bestTime":"연중, 이른 아침이 시장이 가장 붐비는 시간","visitDuration":"2~3시간","ticket":"","openingHours":"매일 04:00 - 08:00 장이 섬","galleryCaptions":["강 위에서 분주히 장을 보는 배들","다리 아래로 강을 건너는 논라를 쓴 뱃사공","배에 가득 쌓인 싱싱한 과일"]},"ja":{"name":"カイベー水上市場","summary":"ティエン川の歴史ある水上市場、早朝から舟が果物やメコンの特産品を売り買いする場所。","story":"カイベー水上市場はかつてメコンデルタ屈指の賑わいを誇る水上市場で、ティエンザン・ヴィンロン・ベンチェが接する川の合流点に位置します。空がまだ薄暗いうちから、果物や野菜を満載した何百艘もの舟が集まり、それぞれベオ竿に商品をぶら下げて客を呼びます。エンジン音、笑い声、そして行商舟から漂う湯気立つフーティウの香りが、生き生きとした川の風景を織りなします。旅人は小舟に乗って市場の間を縫い、新鮮な果物を買い、幾世代にもわたり受け継がれてきたメコン特有の商いのリズムを感じます。","facts":["ティエンザン・ヴィンロン・ベンチェの三省が接する川の合流点に位置します。","舟はベオ竿で販売中の商品を掲げて紹介します。","メコン南西部で最も早く形成された水上市場の一つです。","果物、野菜、デルタの特産品の卸売を専門とします。"],"travelTips":["水上市場が最も賑わう午前5〜7時に行きましょう。","近くのココナッツキャンディー工房や川辺の手工芸の村も合わせて訪れましょう。"],"bestTime":"通年。早朝が市場の最も賑わう時間","visitDuration":"2〜3時間","ticket":"","openingHours":"毎日04:00 - 08:00 に市が立つ","galleryCaptions":["川の上で賑わう市の舟","橋の下を、ノンラーをかぶり川を渡る漕ぎ手","舟に山と積まれた新鮮な果物"]},"zh":{"name":"丐皮水上市场","summary":"前江上历史悠久的水上市场，破晓时分船只熙攘，买卖水果和湄公特产。","story":"丐皮水上市场曾是湄公河三角洲最繁华的水上市场之一，位于前江、永隆与槟椥三省交界的江口。天色尚昏暗时，数百艘满载水果蔬菜的船只已汇聚而来，每艘都竖起吆喝竿挂满货物招揽生意。马达声、谈笑声，以及行商船上飘来的热腾腾河粉香气，勾勒出一幅生动的水乡画卷。游客坐小船穿行市场之间，买下新鲜水果，感受世代相传、充满湄公韵味的交易节奏。","facts":["位于前江、永隆与槟椥三省交界的江口。","船只用吆喝竿挂出货物，介绍正在售卖的商品。","是湄公西南部最早形成的水上市场之一。","专营水果、蔬菜和三角洲特产的批发。"],"travelTips":["在早晨5至7点前来，可见水上市场最热闹的景象。","可结合参观附近的椰子糖作坊和河边手工艺村。"],"bestTime":"全年，清晨是市场最热闹的时段","visitDuration":"2至3小时","ticket":"","openingHours":"每日04:00 - 08:00 开市","galleryCaptions":["河上熙攘开市的船只","桥下戴斗笠划船过江的人","船上堆满的新鲜水果"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ben-tre-con-phung', 'con-phung-xu-dua', 'ben-tre', 'Cồn Phụng - xứ dừa', 'Con Phung - Coconut Land', 'village', 106.3756, 10.3303, 'Cù lao trên sông Tiền nổi tiếng với di tích đạo Dừa, làng nghề thủ công từ dừa và đặc sản kẹo dừa Bến Tre.', 'Cồn Phụng là một cù lao xanh mướt giữa sông Tiền, gắn liền với câu chuyện kỳ lạ về ông Đạo Dừa và những công trình kiến trúc độc đáo còn sót lại. Đến đây, du khách được dạo qua khu di tích với tháp Hòa bình chạm khắc rồng phượng cầu kỳ, rồi lạc vào không gian xứ dừa đặc sệt của Bến Tre. Khắp nơi là tiếng máy ép kẹo dừa thơm lừng, những bàn tay khéo léo đan giỏ, làm đồ mỹ nghệ từ thân và xơ dừa. Khách có thể nhâm nhi nước dừa mát lạnh, xem nuôi ong lấy mật và đi xuồng qua rạch dừa nước rợp bóng. Cồn Phụng là nơi cảm nhận trọn vẹn hồn cốt của quê hương xứ dừa.', '["Gắn với di tích đạo Dừa do ông Nguyễn Thành Nam lập nên từ giữa thế kỷ 20.","Tháp Hòa bình với hoa văn rồng phượng là công trình biểu tượng của cồn.","Bến Tre được mệnh danh là xứ dừa với hàng loạt làng nghề thủ công từ dừa.","Kẹo dừa Bến Tre là đặc sản nổi tiếng được sản xuất ngay tại các lò trên cồn."]', '["Mua kẹo dừa và đồ mỹ nghệ làm quà ngay tại các lò sản xuất trên cồn.","Kết hợp đi tour 4 cù lao Long Lân Quy Phụng để khám phá trọn vùng sông Tiền."]', 'Tháng 11 đến tháng 4, mùa khô mát mẻ thuận tiện đi lại', 'Nửa ngày', '20.000đ tham quan di tích', '07:30 - 17:00 hằng ngày', '["popular","verified","trending"]', '["village","culture","history","food"]', '[{"seed":"conphung-tower","caption":"Tháp Hòa bình của di tích đạo Dừa","ratio":"16/9"},{"seed":"conphung-candy","caption":"Lò làm kẹo dừa thơm lừng","ratio":"4/3"},{"seed":"conphung-handicraft","caption":"Đồ thủ công mỹ nghệ từ dừa","ratio":"1/1"}]', '["tien-giang-cu-lao-thoi-son"]', 1, '{"en":{"name":"Con Phung - the Coconut Land","summary":"An islet on the Tien River famous for the relics of the Coconut Religion, coconut handicraft villages and Ben Tre''s signature coconut candy.","story":"Con Phung is a lush green islet in the Tien River, tied to the curious story of the ''Coconut Monk'' and the unique architectural works he left behind. Here, visitors stroll through a relic site with the Peace Tower, intricately carved with dragons and phoenixes, then lose themselves in the quintessential coconut land of Ben Tre. Everywhere is the fragrant hum of coconut-candy presses, and skilled hands weaving baskets and crafting wares from coconut trunk and fiber. Guests can sip cool coconut water, watch beekeeping for honey, and ride boats through shaded water-coconut canals. Con Phung is the place to feel the full soul of the coconut homeland.","facts":["It is tied to the relics of the Coconut Religion founded by Nguyen Thanh Nam in the mid-20th century.","The Peace Tower with dragon-and-phoenix motifs is the islet''s iconic structure.","Ben Tre is known as the coconut land, with a host of coconut handicraft villages.","Ben Tre coconut candy is a famous specialty produced right in the workshops on the islet."],"travelTips":["Buy coconut candy and handicrafts as gifts straight from the workshops on the islet.","Combine it with a four-islet tour of Dragon, Unicorn, Tortoise and Phoenix to explore the whole Tien River area."],"bestTime":"November to April, the cool, dry season convenient for getting around","visitDuration":"Half a day","ticket":"20,000 VND to visit the relic site","openingHours":"07:30 - 17:00 daily","galleryCaptions":["The Peace Tower of the Coconut Religion relic","A fragrant coconut-candy workshop","Handicrafts made from coconut"]},"ko":{"name":"꼰풍 - 코코넛의 고장","summary":"코코넛교 유적, 코코넛 수공예 마을, 벤쩨의 명물 코코넛 캔디로 유명한 띠엔강의 섬.","story":"꼰풍은 띠엔강 한가운데 자리한 싱그러운 초록 섬으로, ''코코넛 도사''에 얽힌 기이한 이야기와 그가 남긴 독특한 건축물로 잘 알려져 있습니다. 이곳에서 여행객은 용과 봉황이 정교하게 새겨진 평화의 탑이 있는 유적지를 거닐다가, 벤쩨 특유의 코코넛 고장 정취에 흠뻑 빠져듭니다. 곳곳에서 향긋한 코코넛 캔디 압착기 소리가 울리고, 능숙한 손길이 코코넛 줄기와 껍질로 바구니를 엮고 공예품을 만듭니다. 시원한 코코넛 워터를 마시고, 꿀 채취 양봉을 구경하며, 그늘진 물야자수 수로를 배로 누빌 수 있습니다. 꼰풍은 코코넛 고향의 혼을 온전히 느끼는 곳입니다.","facts":["20세기 중반 응우옌타인남이 세운 코코넛교 유적과 연결되어 있습니다.","용·봉황 문양의 평화의 탑은 섬의 상징적 건축물입니다.","벤쩨는 수많은 코코넛 수공예 마을이 있는 코코넛 고장으로 불립니다.","벤쩨 코코넛 캔디는 섬의 공방에서 직접 생산되는 유명한 특산물입니다."],"travelTips":["섬의 공방에서 코코넛 캔디와 공예품을 선물용으로 직접 구입하세요.","용·기린·거북·봉황 사령 4개 섬 투어와 함께 띠엔강 일대를 두루 둘러보세요."],"bestTime":"11~4월, 이동이 편한 시원한 건기","visitDuration":"반나절","ticket":"유적 관람 20,000동","openingHours":"매일 07:30 - 17:00","galleryCaptions":["코코넛교 유적의 평화의 탑","향긋한 코코넛 캔디 공방","코코넛으로 만든 수공예품"]},"ja":{"name":"コンフン - ココナッツの里","summary":"ココナッツ教の遺跡、ココナッツ手工芸の村、ベンチェ名物のココナッツキャンディーで知られるティエン川の島。","story":"コンフンはティエン川の真ん中に浮かぶみずみずしい緑の島で、「ココナッツ道士」にまつわる奇妙な物語と、彼が遺した独特な建築物でよく知られています。ここで旅人は、龍と鳳凰が精巧に彫られた平和の塔のある遺跡を歩いた後、ベンチェ特有のココナッツの里の情緒にどっぷり浸ります。あちこちで香ばしいココナッツキャンディーの圧搾機の音が響き、巧みな手がココナッツの幹や繊維で籠を編み工芸品を作ります。冷たいココナッツウォーターを味わい、蜂蜜採りの養蜂を見学し、陰の落ちるニッパヤシの水路を舟で巡れます。コンフンはココナッツの故郷の魂を余すところなく感じる場所です。","facts":["20世紀半ばにグエン・タイン・ナムが創始したココナッツ教の遺跡と結びついています。","龍・鳳凰の文様の平和の塔は島の象徴的な建築物です。","ベンチェは数多くのココナッツ手工芸の村があるココナッツの里と呼ばれます。","ベンチェのココナッツキャンディーは島の工房で直接作られる有名な特産品です。"],"travelTips":["島の工房でココナッツキャンディーや工芸品を土産に直接買いましょう。","龍・麒麟・亀・鳳凰の四霊四島ツアーと合わせ、ティエン川一帯をくまなく巡りましょう。"],"bestTime":"11〜4月、移動しやすい涼しい乾季","visitDuration":"半日","ticket":"遺跡見学20,000ドン","openingHours":"毎日07:30 - 17:00","galleryCaptions":["ココナッツ教遺跡の平和の塔","香ばしいココナッツキャンディー工房","ココナッツで作った手工芸品"]},"zh":{"name":"凤洲——椰乡","summary":"前江上的小岛，以椰道教遗迹、椰子手工艺村和槟椥特产椰子糖闻名。","story":"凤洲是前江中一座翠绿的小岛，与「椰道」和尚的奇异故事以及他留下的独特建筑紧密相连。来到这里，游客可漫步于遗迹之中，欣赏雕饰着龙凤的和平塔，继而沉浸在槟椥浓郁的椰乡风情里。处处是椰子糖压榨机飘出的香气，灵巧的双手用椰干和椰丝编织篮子、制作工艺品。游客可品一口清凉的椰汁，看养蜂取蜜，坐船穿行于绿荫遮蔽的水椰水道。凤洲是尽情感受椰乡灵魂的地方。","facts":["与阮成南于20世纪中叶创立的椰道教遗迹相连。","饰有龙凤纹样的和平塔是小岛的标志性建筑。","槟椥被誉为椰乡，拥有众多椰子手工艺村。","槟椥椰子糖是著名特产，就在岛上的作坊里生产。"],"travelTips":["在岛上的作坊里直接购买椰子糖和工艺品作伴手礼。","结合龙麟龟凤四岛游，探索整个前江一带。"],"bestTime":"11月至4月，凉爽干燥、出行便利的旱季","visitDuration":"半天","ticket":"参观遗迹20,000越南盾","openingHours":"每日07:30 - 17:00","galleryCaptions":["椰道教遗迹的和平塔","香气四溢的椰子糖作坊","用椰子制成的手工艺品"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tra-vinh-ao-ba-om', 'ao-ba-om', 'tra-vinh', 'Ao Bà Om', 'Ba Om Pond', 'lake', 106.3186, 9.9183, 'Hồ nước cổ linh thiêng của người Khmer, bao quanh bởi rừng cây cổ thụ với bộ rễ trồi lên kỳ vĩ.', 'Ao Bà Om là thắng cảnh nổi tiếng nhất của Trà Vinh, gắn liền với truyền thuyết về cuộc thi đào ao giữa phe nam và phe nữ để phân định việc cưới hỏi. Hồ nước hình chữ nhật rộng lớn quanh năm trong xanh, soi bóng những hàng sao, dầu cổ thụ hàng trăm năm tuổi. Điều kỳ lạ khiến du khách trầm trồ là bộ rễ khổng lồ của các cây cổ thụ trồi hẳn lên khỏi mặt đất, uốn lượn tạo nên những hình thù độc đáo như tác phẩm điêu khắc của thiên nhiên. Bên cạnh ao là ngôi chùa Khmer cổ kính và bảo tàng văn hóa dân tộc, nơi lưu giữ hồn cốt của cộng đồng Khmer Nam Bộ giữa lòng Trà Vinh thanh bình.', '["Hồ nước cổ gắn với truyền thuyết cuộc thi đào ao giữa phe nam và phe nữ.","Bao quanh là rừng cây sao, dầu cổ thụ hàng trăm năm tuổi.","Bộ rễ cây trồi lên mặt đất tạo hình thù độc đáo là điểm nhấn nổi tiếng.","Gắn liền với văn hóa Khmer Nam Bộ và chùa Âng cổ kính bên cạnh."]', '["Ghé chùa Âng và bảo tàng văn hóa Khmer ngay cạnh ao để hiểu thêm văn hóa địa phương.","Đến vào dịp lễ Ok Om Bok để hòa mình vào không khí lễ hội của người Khmer."]', 'Tháng 11 đến tháng 1, dịp lễ Ok Om Bok của người Khmer', '1-2 giờ', '', 'Cả ngày', '["verified","hidden-gem","festival"]', '["lake","culture","nature","photography"]', '[{"seed":"baom-roots","caption":"Bộ rễ cây cổ thụ trồi lên kỳ vĩ","ratio":"16/9"},{"seed":"baom-pond","caption":"Hồ nước trong xanh soi bóng cây","ratio":"4/3"},{"seed":"baom-khmer","caption":"Chùa Khmer cổ kính bên ao","ratio":"1/1"}]', '["tra-vinh-chua-vam-ray"]', 1, '{"en":{"name":"Ba Om Pond","summary":"An ancient sacred pond of the Khmer people, ringed by old-growth trees with majestically exposed roots.","story":"Ba Om Pond is the most famous landscape in Tra Vinh, tied to a legend of a pond-digging contest between the men''s team and the women''s team to settle who would propose marriage. The large rectangular pond stays clear and green all year, mirroring rows of centuries-old hopea and dipterocarp trees. What amazes visitors is the enormous roots of the old trees rising right out of the ground, twisting into striking shapes like nature''s own sculptures. Beside the pond stand an ancient Khmer pagoda and an ethnic-culture museum, preserving the soul of the southern Khmer community in peaceful Tra Vinh.","facts":["It is an ancient pond tied to a legend of a pond-digging contest between the men''s and women''s teams.","It is surrounded by a forest of centuries-old hopea and dipterocarp trees.","The tree roots rising above the ground in striking shapes are its famous highlight.","It is linked to southern Khmer culture and the ancient Ang Pagoda nearby."],"travelTips":["Visit Ang Pagoda and the Khmer culture museum right beside the pond to learn more about local culture.","Come during the Ok Om Bok festival to immerse yourself in the Khmer festive atmosphere."],"bestTime":"November to January, around the Khmer Ok Om Bok festival","visitDuration":"1-2 hours","ticket":"","openingHours":"All day","galleryCaptions":["Majestic old-tree roots rising from the ground","Clear green water mirroring the trees","An ancient Khmer pagoda beside the pond"]},"ko":{"name":"바옴 연못","summary":"웅장하게 솟은 뿌리를 드러낸 노거수에 둘러싸인 크메르족의 영험한 고대 연못.","story":"바옴 연못은 짜빈에서 가장 유명한 명소로, 혼사를 정하기 위해 남자 편과 여자 편이 벌인 연못 파기 시합 전설과 얽혀 있습니다. 큰 직사각형 연못은 일 년 내내 푸르고 맑아, 수백 년 된 호페아와 딥테로카르푸스 노거수가 늘어선 모습을 비춥니다. 여행객을 감탄하게 하는 것은 노거수의 거대한 뿌리가 땅 위로 그대로 솟아올라 자연의 조각 작품처럼 독특한 형상으로 굽이치는 모습입니다. 연못 곁에는 고풍스러운 크메르 사원과 민족문화 박물관이 있어, 평온한 짜빈 한복판에서 남부 크메르 공동체의 혼을 간직하고 있습니다.","facts":["남자 편과 여자 편이 벌인 연못 파기 시합 전설과 얽힌 고대 연못입니다.","수백 년 된 호페아·딥테로카르푸스 노거수 숲에 둘러싸여 있습니다.","땅 위로 솟아 독특한 형상을 이룬 나무뿌리가 유명한 볼거리입니다.","남부 크메르 문화 및 인근의 고풍스러운 앙 사원과 연결되어 있습니다."],"travelTips":["연못 바로 옆 앙 사원과 크메르 문화 박물관에 들러 지역 문화를 더 알아보세요.","크메르족의 옥옴복 축제 때 방문해 축제 분위기에 흠뻑 빠져 보세요."],"bestTime":"11~1월, 크메르족 옥옴복 축제 시기","visitDuration":"1~2시간","ticket":"","openingHours":"종일","galleryCaptions":["웅장하게 솟은 노거수 뿌리","나무를 비추는 맑고 푸른 연못","연못 곁의 고풍스러운 크메르 사원"]},"ja":{"name":"バーオム池","summary":"雄大に隆起した根を露わにした古木に囲まれた、クメール族の霊験あらたかな古池。","story":"バーオム池はチャヴィンで最も有名な景勝地で、縁談を決めるため男組と女組が競った池掘り競争の伝説と結びついています。大きな長方形の池は一年中澄んで緑で、数百年を経たホペアやフタバガキの古木の並びを映します。旅人を感嘆させるのは、古木の巨大な根が地面からそのまま隆起し、自然の彫刻のように独特な形にうねる様です。池のそばには古色蒼然としたクメール寺院と民族文化博物館があり、穏やかなチャヴィンの只中で南部クメール共同体の魂を守り伝えています。","facts":["男組と女組が競った池掘り競争の伝説と結びつく古池です。","数百年を経たホペア・フタバガキの古木の林に囲まれています。","地面から隆起し独特な形を成す木の根が有名な見どころです。","南部クメール文化および近くの古色蒼然としたアン寺院と結びついています。"],"travelTips":["池のすぐ隣のアン寺院とクメール文化博物館に立ち寄り、地元の文化をさらに知りましょう。","クメール族のオクオムボク祭りの時期に訪れ、祭りの雰囲気に浸りましょう。"],"bestTime":"11〜1月、クメール族のオクオムボク祭りの時期","visitDuration":"1〜2時間","ticket":"","openingHours":"終日","galleryCaptions":["雄大に隆起した古木の根","木々を映す澄んだ緑の池","池のそばの古色蒼然としたクメール寺院"]},"zh":{"name":"婆嗡池","summary":"高棉族灵验的古池，四周环绕着根系雄奇隆起的参天古树。","story":"婆嗡池是茶荣最著名的胜景，与一段男队女队比赛挖池以决定婚事的传说相连。这片宽阔的长方形池水常年清澈碧绿，倒映着数百年树龄的桫木和龙脑香古树。最令游客惊叹的，是古树巨大的根系直接隆出地面，蜿蜒成各种独特的形状，宛如大自然的雕塑。池畔矗立着古朴的高棉寺庙和民族文化博物馆，在宁静的茶荣腹地守护着南部高棉族群的灵魂。","facts":["与男队女队比赛挖池的传说相连的古池。","四周环绕着数百年树龄的桫木和龙脑香古树。","隆出地面、形态独特的树根是著名看点。","与南部高棉文化及池畔古朴的瓮寺相连。"],"travelTips":["顺道参观池畔的瓮寺和高棉文化博物馆，进一步了解当地文化。","在高棉族的送水节期间前来，融入节庆氛围。"],"bestTime":"11月至1月，高棉族送水节期间","visitDuration":"1至2小时","ticket":"","openingHours":"全天","galleryCaptions":["雄奇隆起的古树根系","倒映树影的清澈碧池","池畔古朴的高棉寺庙"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('tra-vinh-chua-vam-ray', 'chua-vam-ray', 'tra-vinh', 'Chùa Vàm Ray', 'Vam Ray Pagoda', 'temple', 106.2461, 9.7547, 'Ngôi chùa Khmer dát vàng lộng lẫy, được xem là một trong những chùa Khmer lớn và đẹp bậc nhất Việt Nam.', 'Chùa Vàm Ray tọa lạc tại huyện Trà Cú, là ngôi chùa Khmer mang vẻ đẹp tráng lệ hiếm có ở miền Tây. Toàn bộ ngôi chùa được sơn son thếp vàng rực rỡ, lấp lánh dưới ánh nắng với kiến trúc Angkor đặc trưng, mái nhọn nhiều tầng và những phù điêu chạm khắc tinh xảo. Bên trong chính điện là tượng Phật nằm dài hơn năm mươi mét uy nghi, một trong những tượng Phật nằm lớn nhất Việt Nam. Khắp khuôn viên là tượng tiên nữ Kẽn nair, thần rắn Naga và những hoa văn dát vàng cầu kỳ. Đến đây, du khách không chỉ chiêm bái mà còn được chiêm ngưỡng đỉnh cao nghệ thuật kiến trúc và điêu khắc của văn hóa Phật giáo Nam tông Khmer.', '["Mang kiến trúc Angkor đặc trưng với mái nhọn nhiều tầng dát vàng rực rỡ.","Tượng Phật nằm trong chùa dài hơn 50 mét, thuộc loại lớn nhất Việt Nam.","Khuôn viên trang trí tượng tiên nữ Kẽn nair và thần rắn Naga tinh xảo.","Là chùa Phật giáo Nam tông Khmer tiêu biểu của tỉnh Trà Vinh."]', '["Ăn mặc kín đáo, lịch sự khi vào tham quan và chiêm bái trong chính điện.","Đến vào buổi sáng để ánh nắng làm nổi bật vẻ lộng lẫy dát vàng của chùa."]', 'Quanh năm, đẹp nhất vào mùa khô tháng 11 đến tháng 4', '1-2 giờ', '', '06:00 - 18:00 hằng ngày', '["verified","hidden-gem"]', '["temple","culture","history","photography"]', '[{"seed":"vamray-golden","caption":"Kiến trúc Angkor dát vàng rực rỡ","ratio":"16/9"},{"seed":"vamray-buddha","caption":"Tượng Phật nằm uy nghi trong chính điện","ratio":"4/3"},{"seed":"vamray-naga","caption":"Phù điêu thần rắn Naga tinh xảo","ratio":"1/1"}]', '["tra-vinh-ao-ba-om"]', 0, '{"en":{"name":"Vam Ray Pagoda","summary":"A dazzling gilded Khmer pagoda, considered one of the largest and most beautiful Khmer pagodas in Vietnam.","story":"Vam Ray Pagoda, in Tra Cu district, is a Khmer pagoda of rare splendor in the Mekong Delta. The entire pagoda is lacquered and gilded in brilliant gold, glittering in the sunlight with signature Angkor architecture, multi-tiered pointed roofs and exquisitely carved reliefs. Inside the main hall lies a majestic reclining Buddha more than fifty meters long, one of the largest in Vietnam. Throughout the grounds stand statues of the Kinnari celestial maiden, the Naga serpent deity and elaborate gilded motifs. Here, visitors not only pay homage but also behold the pinnacle of Theravada Khmer Buddhist architecture and sculpture.","facts":["It features signature Angkor architecture with brilliantly gilded multi-tiered pointed roofs.","The reclining Buddha inside is over 50 meters long, among the largest in Vietnam.","The grounds are decorated with exquisite statues of the Kinnari maiden and the Naga serpent deity.","It is a representative Theravada Khmer Buddhist pagoda of Tra Vinh province."],"travelTips":["Dress modestly and respectfully when visiting and worshiping in the main hall.","Come in the morning, when the sunlight highlights the pagoda''s gilded splendor."],"bestTime":"Year-round, most beautiful in the dry season from November to April","visitDuration":"1-2 hours","ticket":"","openingHours":"06:00 - 18:00 daily","galleryCaptions":["Brilliantly gilded Angkor architecture","The majestic reclining Buddha in the main hall","Exquisite relief of the Naga serpent deity"]},"ko":{"name":"밤라이 사원","summary":"베트남에서 가장 크고 아름다운 크메르 사원으로 꼽히는 눈부신 금박 크메르 사원.","story":"짜꾸현에 자리한 밤라이 사원은 메콩델타에서 보기 드물게 화려한 크메르 사원입니다. 사원 전체가 찬란한 금빛으로 칠해지고 도금되어 햇빛에 반짝이며, 다층의 뾰족한 지붕과 정교하게 새겨진 부조 등 앙코르 양식이 특징입니다. 본전 안에는 50m가 넘는 위엄 있는 와불상이 있는데, 베트남에서 가장 큰 와불상 중 하나입니다. 경내 곳곳에는 천녀 낀나라상, 뱀신 나가상, 그리고 정교한 금박 문양이 가득합니다. 이곳에서 여행객은 참배할 뿐 아니라 남방 크메르 불교 건축과 조각 예술의 정점을 감상할 수 있습니다.","facts":["다층의 뾰족한 지붕을 찬란하게 도금한 앙코르 양식이 특징입니다.","사원 안의 와불상은 길이 50m가 넘어 베트남에서 가장 큰 축에 듭니다.","경내는 낀나라 천녀상과 나가 뱀신상으로 정교하게 장식되어 있습니다.","짜빈성을 대표하는 남방 크메르 불교 사원입니다."],"travelTips":["본전에서 참배하고 관람할 때는 단정하고 예의 바르게 옷을 입으세요.","햇빛이 사원의 금박 화려함을 돋보이게 하는 오전에 가세요."],"bestTime":"연중, 11~4월 건기에 가장 아름다움","visitDuration":"1~2시간","ticket":"","openingHours":"매일 06:00 - 18:00","galleryCaptions":["찬란하게 도금된 앙코르 양식 건축","본전의 위엄 있는 와불상","정교한 나가 뱀신 부조"]},"ja":{"name":"ヴァムライ寺院","summary":"ベトナム屈指の大きさと美しさを誇るとされる、まばゆい金箔のクメール寺院。","story":"チャクー県に佇むヴァムライ寺院は、メコンデルタでは稀な絢爛たる美しさのクメール寺院です。寺院全体が鮮やかな金で塗られ金箔が施され、陽光にきらめき、多層の尖った屋根や精緻に彫られたレリーフなどアンコール様式が特徴です。本堂の中には全長50メートルを超える威厳ある涅槃仏があり、ベトナム最大級の一つです。境内のいたるところに天女キンナリー像、蛇神ナーガ像、そして精緻な金箔の文様が満ちています。ここで旅人は参拝するだけでなく、南方クメール仏教の建築と彫刻芸術の頂点を堪能できます。","facts":["多層の尖った屋根を鮮やかに金箔で覆ったアンコール様式が特徴です。","寺院の中の涅槃仏は全長50メートルを超え、ベトナム最大級です。","境内は天女キンナリー像と蛇神ナーガ像で精緻に飾られています。","チャヴィン省を代表する南方クメール仏教寺院です。"],"travelTips":["本堂で参拝・見学する際は、慎ましく端正な服装をしましょう。","陽光が寺院の金箔の華やかさを際立たせる午前中に行きましょう。"],"bestTime":"通年。11〜4月の乾季が最も美しい","visitDuration":"1〜2時間","ticket":"","openingHours":"毎日06:00 - 18:00","galleryCaptions":["鮮やかに金箔を施されたアンコール様式の建築","本堂の威厳ある涅槃仏","精緻な蛇神ナーガのレリーフ"]},"zh":{"name":"湾莱寺","summary":"金碧辉煌的高棉寺庙，被誉为越南最大、最美的高棉寺庙之一。","story":"湾莱寺坐落于茶句县，是湄公河三角洲难得一见的富丽堂皇的高棉寺庙。整座寺庙髹金贴金，光彩夺目，在阳光下熠熠生辉，具有典型的吴哥建筑风格——多层尖顶和雕饰精美的浮雕。主殿内是一尊长逾五十米、庄严肃穆的卧佛，是越南最大的卧佛之一。寺内处处可见紧那罗天女像、那伽蛇神像和繁复的贴金纹饰。来到这里，游客不仅可以参拜，还能领略南传高棉佛教建筑与雕刻艺术的巅峰。","facts":["具有典型的吴哥建筑风格，多层尖顶金碧辉煌。","寺内卧佛长逾50米，属越南最大之列。","寺院内饰有精美的紧那罗天女像和那伽蛇神像。","是茶荣省具代表性的南传高棉佛教寺庙。"],"travelTips":["在主殿参拜参观时，着装应庄重得体。","上午前来，阳光更能凸显寺庙贴金的辉煌。"],"bestTime":"全年，11月至4月旱季最美","visitDuration":"1至2小时","ticket":"","openingHours":"每日06:00 - 18:00","galleryCaptions":["金碧辉煌的吴哥风格建筑","主殿中庄严的卧佛","精美的那伽蛇神浮雕"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('vinh-long-cu-lao-an-binh', 'cu-lao-an-binh', 'vinh-long', 'Cù lao An Bình', 'An Binh Islet', 'village', 106, 10.2667, 'Cù lao trù phú giữa sông Tiền và sông Cổ Chiên, thiên đường miệt vườn với homestay sinh thái và trái cây bốn mùa.', 'Cù lao An Bình nằm giữa hai dòng sông Tiền và Cổ Chiên, là vùng đất phù sa màu mỡ với những vườn cây trái sai trĩu quanh năm. Đây là điểm đến lý tưởng cho ai muốn trải nghiệm cuộc sống miệt vườn đích thực: ngủ homestay nhà sàn ven sông, đạp xe qua những con đường làng rợp bóng cây, hái chôm chôm, nhãn, bòn bon ngay trong vườn. Buổi tối, khách quây quần thưởng thức cá tai tượng chiên xù, cá lóc nướng trui và nghe đờn ca tài tử bên ánh đèn dầu. Sáng sớm, một chuyến xuồng len qua rạch nhỏ đưa du khách ra chợ nổi Trà Ôn gần đó. An Bình là nơi nhịp sống miền Tây chậm rãi và đong đầy tình người.', '["Nằm giữa sông Tiền và sông Cổ Chiên, đối diện thành phố Vĩnh Long.","Nổi tiếng với mô hình du lịch homestay miệt vườn đầu tiên ở miền Tây.","Vườn trái cây cho thu hoạch chôm chôm, nhãn, bòn bon quanh năm.","Là điểm trải nghiệm đờn ca tài tử và ẩm thực sông nước đặc trưng."]', '["Đặt homestay trước để có trải nghiệm ngủ lại nhà vườn ven sông trọn vẹn.","Thuê xe đạp dạo quanh cù lao và hái trái cây tại vườn vào buổi sáng."]', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', '1-2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["village","nature","food","culture"]', '[{"seed":"anbinh-orchard","caption":"Vườn trái cây sai trĩu quả","ratio":"16/9"},{"seed":"anbinh-homestay","caption":"Homestay nhà sàn ven sông","ratio":"4/3"},{"seed":"anbinh-bike","caption":"Đạp xe qua con đường làng rợp bóng cây","ratio":"1/1"}]', '["vinh-long-lo-gach-mang-thit"]', 1, '{"en":{"name":"An Binh Islet","summary":"A fertile islet between the Tien and Co Chien rivers, an orchard paradise with eco-homestays and fruit all year round.","story":"An Binh Islet lies between the Tien and Co Chien rivers, a land of fertile alluvial soil with orchards heavy with fruit year-round. It is an ideal destination for anyone wanting to experience authentic orchard life: sleeping in a riverside stilt-house homestay, cycling along tree-shaded village lanes, picking rambutan, longan and langsat straight from the garden. In the evening, guests gather to enjoy crispy fried elephant-ear fish, grilled snakehead and don ca tai tu by oil-lamp light. At dawn, a boat threads through small canals to the nearby Tra On floating market. An Binh is where the Mekong''s unhurried rhythm of life is filled with warmth.","facts":["It lies between the Tien and Co Chien rivers, across from Vinh Long city.","It is famous for the first orchard-homestay tourism model in the Mekong Delta.","The orchards yield rambutan, longan and langsat all year round.","It is a place to experience don ca tai tu and signature river cuisine."],"travelTips":["Book a homestay in advance for the full experience of an overnight stay at a riverside garden house.","Rent a bicycle to ride around the islet and pick fruit in the orchards in the morning."],"bestTime":"May to August, when the fruit is in full season","visitDuration":"1-2 days","ticket":"","openingHours":"All day","galleryCaptions":["Orchards heavy with fruit","A riverside stilt-house homestay","Cycling along a tree-shaded village lane"]},"ko":{"name":"안빈섬","summary":"생태 홈스테이와 사계절 과일이 있는 과수원 천국, 띠엔강과 꼬찌엔강 사이의 비옥한 섬.","story":"안빈섬은 띠엔강과 꼬찌엔강 사이에 자리한 비옥한 충적토의 땅으로, 일 년 내내 과일이 주렁주렁 달린 과수원이 가득합니다. 진정한 과수원 생활을 체험하고 싶은 이에게 더없이 좋은 곳입니다. 강변 수상가옥 홈스테이에서 자고, 나무 그늘이 드리운 마을 길을 자전거로 달리며, 정원에서 람부탄·용안·랑삿을 직접 땁니다. 저녁이면 손님들이 모여 바삭하게 튀긴 코끼리귀 물고기와 가물치 구이를 맛보고 등잔불 아래 던까따이뜨를 듣습니다. 이른 새벽, 작은 배가 수로를 누비며 인근 짜온 수상시장으로 여행객을 데려갑니다. 안빈은 메콩의 느긋한 삶의 리듬이 정으로 가득한 곳입니다.","facts":["띠엔강과 꼬찌엔강 사이, 빈롱시 맞은편에 위치합니다.","메콩델타 최초의 과수원 홈스테이 관광 모델로 유명합니다.","과수원에서는 일 년 내내 람부탄, 용안, 랑삿을 수확합니다.","던까따이뜨와 특유의 강변 음식을 체험할 수 있는 곳입니다."],"travelTips":["강변 정원집에서 하룻밤 묵는 체험을 온전히 즐기려면 홈스테이를 미리 예약하세요.","자전거를 빌려 섬을 둘러보고 오전에 과수원에서 과일을 따 보세요."],"bestTime":"5~8월, 과일이 무르익는 철","visitDuration":"1~2일","ticket":"","openingHours":"종일","galleryCaptions":["과일이 주렁주렁 달린 과수원","강변 수상가옥 홈스테이","나무 그늘이 드리운 마을 길을 자전거로 달리기"]},"ja":{"name":"アンビン島","summary":"エコ・ホームステイと四季の果物がある果樹園の楽園、ティエン川とコーチエン川に挟まれた肥沃な島。","story":"アンビン島はティエン川とコーチエン川に挟まれた肥沃な沖積土の地で、一年中果実を実らせる果樹園に満ちています。本物の果樹園の暮らしを体験したい人に最適な場所です。川辺の高床式ホームステイに泊まり、木陰の落ちる村道を自転車で走り、庭でランブータン、リュウガン、ランサットを直接摘みます。夕方には客が集い、カラッと揚げたゾウミミウオや雷魚の炙りを味わい、ランプの灯りの下でドンカータイトゥを聴きます。早朝、小さな舟が水路を縫い、近くのチャオン水上市場へ旅人を運びます。アンビンはメコンのゆったりした暮らしのリズムが人情に満ちた場所です。","facts":["ティエン川とコーチエン川の間、ヴィンロン市の対岸に位置します。","メコンデルタ初の果樹園ホームステイ観光モデルで有名です。","果樹園では一年中ランブータン、リュウガン、ランサットを収穫します。","ドンカータイトゥと川辺の特有の料理を体験できる場所です。"],"travelTips":["川辺の庭家に一泊する体験を存分に楽しむには、ホームステイを事前に予約しましょう。","自転車を借りて島を巡り、午前中に果樹園で果物を摘みましょう。"],"bestTime":"5〜8月、果物が熟す季節","visitDuration":"1〜2日","ticket":"","openingHours":"終日","galleryCaptions":["果実を実らせた果樹園","川辺の高床式ホームステイ","木陰の落ちる村道を自転車で走る"]},"zh":{"name":"安平岛","summary":"前江与古战江之间的富饶小岛，是拥有生态民宿和四季鲜果的果园天堂。","story":"安平岛位于前江与古战江之间，是一片沃土，果园常年硕果累累。这里是体验地道果园生活的理想之地：住在江畔高脚屋民宿，骑车穿行绿荫遮蔽的乡间小路，在园中亲手采摘红毛丹、龙眼和兰撒果。夜晚，客人围坐品尝酥炸象耳鱼、烤雷鱼，在油灯下聆听才子弹唱。清晨，一叶小舟穿行小水道，载游客前往附近的茶温水上市场。安平岛正是湄公悠然生活节奏与浓浓人情交织的地方。","facts":["位于前江与古战江之间，与永隆市隔江相望。","以湄公河三角洲首创的果园民宿旅游模式闻名。","果园常年盛产红毛丹、龙眼和兰撒果。","是体验才子弹唱和特色水乡美食的地方。"],"travelTips":["提前预订民宿，尽享在江畔园林屋过夜的完整体验。","租辆自行车环岛骑行，上午到果园采摘水果。"],"bestTime":"5月至8月，水果成熟旺季","visitDuration":"1至2天","ticket":"","openingHours":"全天","galleryCaptions":["硕果累累的果园","江畔高脚屋民宿","骑车穿行绿荫遮蔽的乡间小路"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('vinh-long-lo-gach-mang-thit', 'lo-gach-mang-thit', 'vinh-long', 'Lò gạch Mang Thít', 'Mang Thit Brick Kilns', 'village', 106.0639, 10.1414, 'Vương quốc lò gạch gốm trăm năm tuổi ven sông Cổ Chiên, với những tháp lò màu gạch đỏ cam đẹp như cổ tích.', 'Làng nghề gạch gốm Mang Thít được mệnh danh là vương quốc lò gạch của miền Tây, hình thành cách đây hơn một thế kỷ ven dòng sông Cổ Chiên. Hàng nghìn lò nung hình tròn cao vút bằng gạch đỏ cam nằm san sát nhau, soi bóng xuống mặt nước, tạo nên một khung cảnh vừa hoài niệm vừa siêu thực. Những lò gạch hình củ tỏi cũ kỹ rêu phong này từng đỏ lửa ngày đêm, làm ra loại gạch và gốm đỏ nức tiếng khắp Nam Bộ. Ngày nay, dù nhiều lò đã ngưng hoạt động, khung cảnh kỳ vĩ ấy lại trở thành điểm check-in được giới trẻ săn đón, đồng thời được tỉnh quy hoạch thành di sản đương đại để gìn giữ hồn nghề cho mai sau.', '["Làng nghề gạch gốm hình thành hơn 100 năm bên sông Cổ Chiên.","Từng có hàng nghìn lò nung hình tròn nằm san sát thành vương quốc lò gạch.","Gạch và gốm đỏ Mang Thít nổi tiếng khắp vùng Nam Bộ một thời.","Đang được quy hoạch thành di sản đương đại gắn với phát triển du lịch."]', '["Đi xuồng dọc sông Cổ Chiên để ngắm toàn cảnh những hàng lò gạch ven nước.","Đến lúc hoàng hôn khi ánh nắng nhuộm vàng cam các tháp lò để chụp ảnh đẹp nhất."]', 'Tháng 11 đến tháng 4, mùa khô thuận tiện tham quan', '2-3 giờ', '', 'Cả ngày', '["hidden-gem","trending","verified"]', '["village","culture","history","photography"]', '[{"seed":"mangthit-kilns","caption":"Hàng lò gạch đỏ cam ven sông","ratio":"16/9"},{"seed":"mangthit-sunset","caption":"Tháp lò nhuộm vàng lúc hoàng hôn","ratio":"4/3"},{"seed":"mangthit-old","caption":"Lò nung cũ kỹ rêu phong","ratio":"1/1"}]', '["vinh-long-cu-lao-an-binh"]', 0, '{"en":{"name":"Mang Thit Brick Kilns","summary":"A century-old kingdom of brick and pottery kilns by the Co Chien River, with fairy-tale orange-red kiln towers.","story":"The Mang Thit brick-and-pottery craft village is dubbed the kingdom of brick kilns in the Mekong Delta, formed more than a century ago along the Co Chien River. Thousands of towering round kilns of orange-red brick stand side by side, mirrored in the water, creating a scene at once nostalgic and surreal. These old, moss-covered garlic-bulb-shaped kilns once burned day and night, producing the red brick and pottery famed throughout the south. Today, though many kilns have ceased operating, the magnificent scenery has become a sought-after check-in spot for young people, and the province is planning it as a contemporary heritage site to preserve the craft''s soul for the future.","facts":["The brick-and-pottery craft village formed over 100 years ago by the Co Chien River.","It once had thousands of round kilns standing side by side, a true kingdom of brick kilns.","Mang Thit''s red brick and pottery were once famous throughout the south.","It is being planned as a contemporary heritage site tied to tourism development."],"travelTips":["Take a boat along the Co Chien River to take in the full sweep of riverside kilns.","Come at sunset, when the light turns the kiln towers golden-orange, for the best photos."],"bestTime":"November to April, the dry season convenient for visiting","visitDuration":"2-3 hours","ticket":"","openingHours":"All day","galleryCaptions":["Rows of orange-red brick kilns by the river","Kiln towers glowing golden at sunset","An old, moss-covered kiln"]},"ko":{"name":"망팃 벽돌 가마","summary":"꼬찌엔강변에 자리한 백 년 된 벽돌·도자기 가마 왕국, 동화 같은 주황빛 가마탑이 늘어선 곳.","story":"망팃 벽돌·도자기 공예 마을은 메콩델타의 벽돌 가마 왕국이라 불리며, 한 세기 전 꼬찌엔강변에 형성되었습니다. 주황빛 벽돌로 높이 솟은 둥근 가마 수천 개가 나란히 늘어서 물에 비치며, 향수를 자아내는 동시에 초현실적인 풍경을 빚어냅니다. 마늘 모양의 오래되고 이끼 낀 이 가마들은 한때 밤낮으로 불을 지펴 남부 전역에 이름난 붉은 벽돌과 도자기를 구워 냈습니다. 오늘날 많은 가마가 가동을 멈췄지만, 그 웅장한 풍경은 젊은이들이 찾는 인증샷 명소가 되었고, 성에서는 이를 현대 유산으로 계획해 후대를 위한 장인의 혼을 지키고 있습니다.","facts":["벽돌·도자기 공예 마을은 100여 년 전 꼬찌엔강변에 형성되었습니다.","한때 둥근 가마 수천 개가 나란히 늘어선 벽돌 가마 왕국이었습니다.","망팃 붉은 벽돌과 도자기는 한때 남부 전역에 이름났습니다.","관광 개발과 연계된 현대 유산으로 계획되고 있습니다."],"travelTips":["꼬찌엔강을 따라 배를 타고 강변에 늘어선 가마의 전경을 감상하세요.","가장 멋진 사진을 위해 햇빛이 가마탑을 황금빛으로 물들이는 일몰 무렵에 가세요."],"bestTime":"11~4월, 관람이 편한 건기","visitDuration":"2~3시간","ticket":"","openingHours":"종일","galleryCaptions":["강변에 늘어선 주황빛 벽돌 가마","일몰에 황금빛으로 물든 가마탑","오래되고 이끼 낀 가마"]},"ja":{"name":"マンティット煉瓦窯","summary":"コーチエン川辺に佇む百年の煉瓦・陶器窯の王国、おとぎ話のようなオレンジ色の窯塔が並ぶ場所。","story":"マンティットの煉瓦・陶器の工芸村はメコンデルタの煉瓦窯の王国と称され、一世紀以上前にコーチエン川辺に形成されました。オレンジ色の煉瓦で高くそびえる円い窯が何千も立ち並び、水面に映って、郷愁と非現実が同居する景色を織りなします。ニンニク形の古びて苔むしたこれらの窯は、かつて昼夜を問わず火を焚き、南部一帯に名高い赤煉瓦と陶器を焼いていました。今日、多くの窯は操業を止めましたが、その雄大な景色は若者が訪れる撮影スポットとなり、省はこれを現代遺産として計画し、後世のために職人の魂を守っています。","facts":["煉瓦・陶器の工芸村は100年以上前にコーチエン川辺に形成されました。","かつて円い窯が何千も立ち並ぶ煉瓦窯の王国でした。","マンティットの赤煉瓦と陶器はかつて南部一帯に名高いものでした。","観光開発と結びついた現代遺産として計画されています。"],"travelTips":["コーチエン川沿いに舟で巡り、川辺に並ぶ窯の全景を眺めましょう。","最高の写真には、陽光が窯塔を黄金色に染める夕暮れ時に行きましょう。"],"bestTime":"11〜4月、見学しやすい乾季","visitDuration":"2〜3時間","ticket":"","openingHours":"終日","galleryCaptions":["川辺に並ぶオレンジ色の煉瓦窯","夕日に黄金色に染まる窯塔","古びて苔むした窯"]},"zh":{"name":"莛织砖窑","summary":"古战江畔百年历史的砖陶窑王国，砖红橙色的窑塔林立，宛如童话。","story":"莛织砖陶手工艺村被誉为湄公河三角洲的砖窑王国，一个多世纪前在古战江畔形成。成千上万座砖红橙色的高耸圆窑鳞次栉比，倒映水面，营造出既怀旧又超现实的景致。这些蒜头形、古旧斑驳长满青苔的窑炉，昔日昼夜烧火，烧制出名扬南部的红砖和红陶。如今虽然许多窑炉已停止运作，那雄奇的景色却成了年轻人争相打卡的胜地，省里也将其规划为当代遗产，为后世守护这门手艺的灵魂。","facts":["砖陶手工艺村百余年前在古战江畔形成。","昔日曾有成千上万座圆窑鳞次栉比，堪称砖窑王国。","莛织的红砖和红陶曾名扬南部一带。","正被规划为与旅游开发相结合的当代遗产。"],"travelTips":["沿古战江坐船，饱览江畔窑炉成排的全景。","在阳光将窑塔染成金橙色的黄昏时分前来，拍摄效果最佳。"],"bestTime":"11月至4月，便于参观的旱季","visitDuration":"2至3小时","ticket":"","openingHours":"全天","galleryCaptions":["江畔成排的砖红橙色窑炉","黄昏时分染成金色的窑塔","古旧斑驳长满青苔的窑炉"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dong-thap-tram-chim', 'vuon-quoc-gia-tram-chim', 'dong-thap', 'Vườn quốc gia Tràm Chim', 'Tram Chim National Park', 'park', 105.5, 10.7167, 'Khu Ramsar tái hiện thu nhỏ Đồng Tháp Mười, thiên đường của sếu đầu đỏ và hàng trăm loài chim nước quý.', 'Vườn quốc gia Tràm Chim là vùng đất ngập nước nổi tiếng nhất Đồng Tháp, được công nhận là khu Ramsar quan trọng của thế giới. Trên diện tích hơn bảy nghìn hecta, nơi đây tái hiện sinh động hệ sinh thái Đồng Tháp Mười nguyên thủy với rừng tràm, đồng cỏ năng, lúa ma và sen súng bạt ngàn. Tràm Chim là ngôi nhà của hơn hai trăm loài chim, trong đó quý giá nhất là sếu đầu đỏ, loài chim trong sách đỏ thường về đây tìm ăn vào mùa khô. Ngồi tắc ráng lướt trên kênh nước, du khách được ngắm những đàn cò, vạc, điên điển bay rợp trời và đắm mình giữa thiên nhiên hoang dã thuần khiết của miền Tây sông nước.', '["Diện tích hơn 7.300 hecta, được công nhận là khu Ramsar thứ tư của Việt Nam.","Là nơi trú ngụ của hơn 200 loài chim, nổi bật là sếu đầu đỏ quý hiếm.","Tái hiện hệ sinh thái Đồng Tháp Mười nguyên thủy với rừng tràm và đồng năng.","Mùa nước nổi và mùa sen nở là hai mùa cảnh quan đẹp nhất trong năm."]', '["Đi tắc ráng vào sáng sớm để ngắm chim và tránh nắng gắt buổi trưa.","Mùa sếu về thường từ tháng 12 đến tháng 4, cần liên hệ trước để quan sát."]', 'Tháng 12 đến tháng 4 mùa sếu về, hoặc tháng 9-11 mùa nước nổi', 'Nửa ngày', '10.000đ vé vào, thuê tắc ráng riêng', '07:00 - 17:00 hằng ngày', '["unesco","verified","popular","ai-recommended"]', '["nature","park","photography"]', '[{"seed":"tramchim-crane","caption":"Sếu đầu đỏ về tìm ăn mùa khô","ratio":"16/9"},{"seed":"tramchim-lotus","caption":"Cánh đồng sen súng bạt ngàn","ratio":"4/3"},{"seed":"tramchim-boat","caption":"Tháp canh gỗ giữa đầm sen ngày mưa","ratio":"1/1"}]', '["dong-thap-lang-hoa-sa-dec"]', 1, '{"en":{"name":"Tram Chim National Park","summary":"A Ramsar site recreating a miniature Plain of Reeds, a paradise of red-crowned cranes and hundreds of rare waterbird species.","story":"Tram Chim National Park is the most famous wetland in Dong Thap, recognized as a globally important Ramsar site. Across more than seven thousand hectares, it vividly recreates the primeval Plain of Reeds ecosystem with cajuput forest, eleocharis meadows, wild rice and endless lotus and water lilies. Tram Chim is home to more than two hundred bird species, the most precious being the red-crowned crane, a Red Book bird that comes here to feed in the dry season. Skimming the canals on a tac rang boat, visitors watch flocks of storks, night herons and water cocks fill the sky and immerse themselves in the pristine wild nature of the Mekong waterland.","facts":["It spans over 7,300 hectares and is recognized as Vietnam''s fourth Ramsar site.","It shelters more than 200 bird species, notably the rare red-crowned crane.","It recreates the primeval Plain of Reeds ecosystem with cajuput forest and eleocharis meadows.","Flood season and lotus-blooming season are the two most beautiful times of year."],"travelTips":["Take a tac rang boat early in the morning to watch the birds and avoid the harsh midday sun.","The cranes usually arrive from December to April; contact in advance to observe them."],"bestTime":"December to April for crane season, or September–November for flood season","visitDuration":"Half a day","ticket":"10,000 VND entry, private tac rang boat rental","openingHours":"07:00 - 17:00 daily","galleryCaptions":["Red-crowned cranes feeding in the dry season","Endless fields of lotus and water lily","A wooden watchtower amid the lotus marsh on a rainy day"]},"ko":{"name":"짬찜 국립공원","summary":"축소판 동탑므어이를 재현한 람사르 습지, 붉은머리두루미와 수백 종 희귀 물새의 천국.","story":"짬찜 국립공원은 동탑에서 가장 유명한 습지로, 세계적으로 중요한 람사르 습지로 인정받았습니다. 7천 헥타르가 넘는 면적에 멜라루카 숲, 골풀 초원, 야생벼, 끝없는 연꽃과 수련으로 원시 동탑므어이 생태계를 생생히 재현합니다. 짬찜은 200종이 넘는 새의 보금자리이며, 그중 가장 귀한 것은 적색목록에 오른 붉은머리두루미로, 건기에 먹이를 찾아 이곳을 찾습니다. 딱랑 배로 수로를 누비며 여행객은 두루미·해오라기·물닭 떼가 하늘을 메우는 모습을 보고 메콩 물의 고장의 순수한 야생 자연에 흠뻑 빠집니다.","facts":["면적 7,300헥타르가 넘으며, 베트남의 네 번째 람사르 습지로 인정받았습니다.","200종이 넘는 새의 서식지이며, 특히 희귀한 붉은머리두루미가 돋보입니다.","멜라루카 숲과 골풀 초원으로 원시 동탑므어이 생태계를 재현합니다.","물난리 철과 연꽃 개화철이 일 년 중 경관이 가장 아름다운 두 시기입니다."],"travelTips":["새를 관찰하고 한낮의 뙤약볕을 피하려면 이른 아침에 딱랑 배를 타세요.","두루미는 보통 12~4월에 찾아오니, 관찰하려면 사전에 연락하세요."],"bestTime":"12~4월 두루미 철, 또는 9~11월 물난리 철","visitDuration":"반나절","ticket":"입장료 10,000동, 딱랑 배 개별 대여","openingHours":"매일 07:00 - 17:00","galleryCaptions":["건기에 먹이를 찾는 붉은머리두루미","끝없이 펼쳐진 연꽃·수련 들판","비 오는 날 연꽃 늪 한가운데의 목조 망루"]},"ja":{"name":"チャムチム国立公園","summary":"ミニ・ドンタップムオイを再現したラムサール湿地、オオヅルと数百種の希少な水鳥の楽園。","story":"チャムチム国立公園はドンタップで最も有名な湿地で、世界的に重要なラムサール条約湿地として認定されています。7千ヘクタールを超える面積に、メラルーカ林、ハリイの草原、野生稲、果てしない蓮と睡蓮で原始のドンタップムオイ生態系を生き生きと再現します。チャムチムは200種を超える鳥の住処であり、最も貴重なのはレッドリストに載るオオヅルで、乾季に餌を求めてここを訪れます。タックランの舟で水路を滑りながら、旅人はコウノトリ・ゴイサギ・バンの群れが空を埋める様を眺め、メコンの水の里の純粋な野生の自然に浸ります。","facts":["面積7,300ヘクタールを超え、ベトナム4番目のラムサール条約湿地として認定されています。","200種を超える鳥の生息地で、とくに希少なオオヅルが際立ちます。","メラルーカ林とハリイの草原で原始のドンタップムオイ生態系を再現します。","増水期と蓮の開花期が一年で最も景観の美しい二つの時期です。"],"travelTips":["野鳥を観察し真昼の強い日差しを避けるため、早朝にタックランの舟に乗りましょう。","ツルは通常12〜4月に飛来します。観察には事前に連絡しましょう。"],"bestTime":"12〜4月のツルの季節、または9〜11月の増水期","visitDuration":"半日","ticket":"入場料10,000ドン、タックラン舟は別途貸切","openingHours":"毎日07:00 - 17:00","galleryCaptions":["乾季に餌を求めるオオヅル","果てしなく広がる蓮と睡蓮の畑","雨の日、蓮の沼の真ん中の木造の見張り台"]},"zh":{"name":"茶钦国家公园","summary":"再现缩小版同塔梅的拉姆萨尔湿地，是赤颈鹤和数百种珍稀水鸟的天堂。","story":"茶钦国家公园是同塔最著名的湿地，被列为具有世界重要意义的拉姆萨尔湿地。在七千多公顷的土地上，这里以白千层林、荸荠草原、野稻和漫山遍野的莲花睡莲，生动再现了原始的同塔梅生态系统。茶钦是两百多种鸟类的家园，其中最珍贵的是列入红皮书的赤颈鹤，旱季常来此觅食。坐着小机动船在水渠中滑行，游客可观赏鹭、夜鹭、董鸡成群飞过、遮天蔽日，沉醉于湄公水乡纯净的原始自然之中。","facts":["面积超过7,300公顷，被列为越南第四个拉姆萨尔湿地。","是两百多种鸟类的栖息地，尤以珍稀的赤颈鹤为代表。","以白千层林和荸荠草原再现原始的同塔梅生态系统。","涨水季节和荷花盛开季是一年中景色最美的两个时节。"],"travelTips":["清晨乘小机动船观鸟，可避开正午烈日。","鹤群通常在12月至4月前来，观鹤需提前联系。"],"bestTime":"12月至4月观鹤季，或9至11月涨水季","visitDuration":"半天","ticket":"门票10,000越南盾，另需包租小机动船","openingHours":"每日07:00 - 17:00","galleryCaptions":["旱季前来觅食的赤颈鹤","漫山遍野的莲花睡莲田","雨天荷塘中央的木制瞭望塔"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('dong-thap-lang-hoa-sa-dec', 'lang-hoa-sa-dec', 'dong-thap', 'Làng hoa Sa Đéc', 'Sa Dec Flower Village', 'village', 105.7556, 10.3, 'Làng hoa trăm năm tuổi rực rỡ sắc màu, một trong những vựa hoa kiểng lớn nhất miền Tây Nam Bộ.', 'Làng hoa Sa Đéc, hay làng hoa Tân Quy Đông, là một trong những vựa hoa kiểng lâu đời và lớn nhất đồng bằng sông Cửu Long, đã có hơn một trăm năm tuổi. Trải dài bên dòng sông Sa Giang, hàng trăm hecta vườn hoa khoe sắc quanh năm với cúc mâm xôi, hồng, vạn thọ, cát tường và vô số loại kiểng quý. Điều độc đáo là người dân trồng hoa trên những giàn cao để tránh ngập nước, tạo nên khung cảnh hoa nở lơ lửng trên mặt nước rất riêng. Vào dịp giáp Tết, cả làng rộn ràng nhộn nhịp, ghe thuyền chở hoa tỏa đi khắp miền Nam. Dạo bước giữa biển hoa muôn màu, du khách như lạc vào một khu vườn cổ tích rực rỡ và đầy hương sắc.', '["Làng nghề trồng hoa kiểng có lịch sử hơn 100 năm bên sông Sa Giang.","Là một trong những vựa hoa lớn nhất miền Tây, cung cấp hoa cho cả miền Nam.","Người dân trồng hoa trên giàn cao để tránh ngập nước, tạo cảnh quan độc đáo.","Sa Đéc còn gắn với bối cảnh tiểu thuyết Người Tình của Marguerite Duras."]', '["Đến vào dịp giáp Tết để thấy làng hoa rực rỡ và nhộn nhịp nhất.","Ghé nhà cổ Huỳnh Thủy Lê gần đó để tìm hiểu câu chuyện Người Tình nổi tiếng."]', 'Tháng 12 đến tháng 1, dịp giáp Tết hoa nở rộ', '2-3 giờ', '', 'Cả ngày', '["popular","verified","festival"]', '["village","nature","culture","photography"]', '[{"seed":"sadec-flowers","caption":"Biển hoa muôn màu rực rỡ","ratio":"16/9"},{"seed":"sadec-racks","caption":"Hoa trồng trên giàn cao tránh ngập","ratio":"4/3"},{"seed":"sadec-boat","caption":"Ghe thuyền chở hoa trên sông","ratio":"1/1"}]', '["dong-thap-tram-chim"]', 0, '{"en":{"name":"Sa Dec Flower Village","summary":"A century-old flower village ablaze with color, one of the largest flower and ornamental-plant hubs in the Mekong Delta.","story":"Sa Dec Flower Village, also called Tan Quy Dong flower village, is one of the oldest and largest flower and ornamental-plant hubs in the Mekong Delta, with over a hundred years of history. Stretching along the Sa Giang River, hundreds of hectares of flower gardens bloom year-round with chrysanthemums, roses, marigolds, lisianthus and countless prized ornamentals. What makes it unique is that growers raise the flowers on high racks to avoid flooding, creating a distinctive scene of blossoms suspended above the water. As Tet approaches, the whole village bustles, and boats carry flowers across the south. Strolling through this sea of color, visitors feel as if they''ve wandered into a dazzling, fragrant fairy-tale garden.","facts":["The flower-growing craft village has over 100 years of history along the Sa Giang River.","It is one of the largest flower hubs in the Mekong Delta, supplying flowers across the south.","Growers raise flowers on high racks to avoid flooding, creating a unique landscape.","Sa Dec is also linked to the setting of Marguerite Duras''s novel ''The Lover''."],"travelTips":["Come as Tet approaches to see the flower village at its most vibrant and lively.","Visit the nearby Huynh Thuy Le ancient house to learn the famous story of ''The Lover''."],"bestTime":"December to January, as Tet approaches and the flowers bloom","visitDuration":"2-3 hours","ticket":"","openingHours":"All day","galleryCaptions":["A vibrant sea of multicolored flowers","Flowers grown on high racks to avoid flooding","Boats carrying flowers on the river"]},"ko":{"name":"사덱 꽃마을","summary":"색색으로 물든 백 년 된 꽃마을, 메콩델타 남서부 최대의 화훼·관상수 단지 중 하나.","story":"떤꾸이동 꽃마을이라고도 불리는 사덱 꽃마을은 메콩델타에서 가장 오래되고 큰 화훼·관상수 단지 중 하나로, 백 년이 넘는 역사를 자랑합니다. 사장강을 따라 수백 헥타르의 꽃밭이 국화, 장미, 메리골드, 리시안서스 등 헤아릴 수 없이 많은 귀한 관상화로 일 년 내내 만발합니다. 독특한 점은 주민들이 침수를 막기 위해 높은 선반 위에 꽃을 길러, 물 위에 꽃이 떠 있는 듯한 색다른 풍경을 빚어낸다는 것입니다. 설 무렵이면 온 마을이 분주해지고, 배들이 꽃을 싣고 남부 전역으로 퍼져 나갑니다. 색색의 꽃바다를 거닐면 여행객은 화려하고 향기로운 동화 속 정원에 들어선 듯한 기분을 느낍니다.","facts":["화훼 재배 공예 마을은 사장강변에서 100년이 넘는 역사를 지녔습니다.","메콩델타 최대 화훼 단지 중 하나로, 남부 전역에 꽃을 공급합니다.","주민들은 침수를 막기 위해 높은 선반에 꽃을 길러 독특한 경관을 빚어냅니다.","사덱은 마르그리트 뒤라스의 소설 ''연인''의 배경과도 연결되어 있습니다."],"travelTips":["꽃마을이 가장 화려하고 분주한 설 무렵에 방문하세요.","인근의 후인투이레 고택에 들러 유명한 ''연인'' 이야기를 알아보세요."],"bestTime":"12~1월, 꽃이 만발하는 설 무렵","visitDuration":"2~3시간","ticket":"","openingHours":"종일","galleryCaptions":["색색으로 화려한 꽃바다","침수를 막기 위해 높은 선반에 기른 꽃","강 위에서 꽃을 실어 나르는 배들"]},"ja":{"name":"サーデック花の村","summary":"色とりどりに彩られた百年の花の村、メコンデルタ南西部屈指の花卉・観賞植物の産地。","story":"タンクイドン花の村とも呼ばれるサーデック花の村は、メコンデルタで最も古く大きい花卉・観賞植物の産地の一つで、百年を超える歴史を誇ります。サーザン川沿いに数百ヘクタールの花畑が、菊、バラ、マリーゴールド、トルコギキョウなど数えきれない貴重な観賞花で一年中咲き誇ります。独特なのは、住民が冠水を避けるため高い棚の上に花を育て、水面に花が浮かぶような独特の景色を生み出すことです。テト前になると村中が活気づき、舟が花を載せて南部一帯へ広がっていきます。色とりどりの花の海を歩けば、旅人は華やかで香り高いおとぎ話の庭に迷い込んだような気分になります。","facts":["花卉栽培の工芸村はサーザン川辺で100年を超える歴史を持ちます。","メコンデルタ最大級の花の産地の一つで、南部一帯に花を供給します。","住民は冠水を避けるため高い棚に花を育て、独特の景観を生み出します。","サーデックはマルグリット・デュラスの小説『愛人』の舞台とも結びついています。"],"travelTips":["花の村が最も華やかで賑わうテト前に訪れましょう。","近くのフインフイレー古民家に立ち寄り、有名な『愛人』の物語を知りましょう。"],"bestTime":"12〜1月、花が咲き誇るテト前","visitDuration":"2〜3時間","ticket":"","openingHours":"終日","galleryCaptions":["色とりどりに華やかな花の海","冠水を避けるため高い棚に育てた花","川の上で花を運ぶ舟"]},"zh":{"name":"沙沥花村","summary":"色彩绚烂的百年花村，是湄公河西南地区最大的花卉盆景产地之一。","story":"沙沥花村又名新归东花村，是湄公河三角洲最古老、最大的花卉盆景产地之一，已有一百多年历史。沿沙江绵延数百公顷的花圃常年争奇斗艳，绣球菊、玫瑰、万寿菊、洋桔梗和无数珍贵盆景竞相绽放。独特之处在于，花农将花种在高架上以避水患，营造出花朵悬浮于水面的别样景致。临近春节，全村热闹非凡，船只载着鲜花驶向南部各地。漫步在五彩花海之中，游客仿佛走进了一座绚烂芬芳的童话花园。","facts":["花卉种植手工艺村在沙江畔已有100多年历史。","是湄公河三角洲最大的花卉产地之一，向南部各地供花。","花农在高架上种花以避水患，营造出独特景观。","沙沥还与玛格丽特·杜拉斯小说《情人》的背景相连。"],"travelTips":["临近春节前来，可见花村最绚烂热闹的景象。","顺道参观附近的黄水黎古宅，了解著名的《情人》故事。"],"bestTime":"12月至1月，临近春节、鲜花盛放之时","visitDuration":"2至3小时","ticket":"","openingHours":"全天","galleryCaptions":["五彩绚烂的花海","种在高架上以避水患的鲜花","河上载花的船只"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hau-giang-cho-noi-nga-bay', 'cho-noi-nga-bay', 'hau-giang', 'Chợ nổi Ngã Bảy', 'Nga Bay Floating Market', 'market', 105.8175, 9.8156, 'Chợ nổi huyền thoại nơi bảy nhánh sông gặp nhau, từng là chợ nổi sầm uất và nổi tiếng bậc nhất miền Tây.', 'Chợ nổi Ngã Bảy, còn gọi là chợ nổi Phụng Hiệp, là một biểu tượng văn hóa sông nước của Hậu Giang, hình thành từ đầu thế kỷ hai mươi tại nơi bảy con sông tụ về một điểm. Đây từng là chợ nổi lớn và sầm uất nhất miền Tây, đi vào câu hát Tình anh bán chiếu nổi tiếng của soạn giả Viễn Châu. Sáng sớm, hàng trăm ghe thuyền chở đầy nông sản, trái cây, đồ gia dụng tấp nập mua bán, mỗi ghe treo cây bẹo rao hàng đặc trưng. Du khách ngồi thuyền len giữa chợ, thưởng thức tô bún riêu nóng hổi ngay trên sông và cảm nhận nhịp sống thương hồ phóng khoáng, nghĩa tình của người dân miền Tây sông nước.', '["Hình thành đầu thế kỷ 20 tại nơi bảy nhánh sông gặp nhau ở Phụng Hiệp.","Từng là chợ nổi lớn và sầm uất bậc nhất đồng bằng sông Cửu Long.","Đi vào bài vọng cổ Tình anh bán chiếu nổi tiếng của soạn giả Viễn Châu.","Các ghe dùng cây bẹo treo hàng hóa làm dấu hiệu rao bán trên sông."]', '["Đi từ 5h đến 7h sáng để bắt trọn không khí chợ nổi đông đúc nhất.","Thử ăn sáng ngay trên thuyền với bún riêu, hủ tiếu để trải nghiệm trọn vẹn."]', 'Quanh năm, sáng sớm là lúc chợ nhộn nhịp nhất', '2-3 giờ', '', 'Họp chợ từ 05:00 - 08:00 hằng ngày', '["popular","verified","festival"]', '["market","culture","food","photography"]', '[{"seed":"ngabay-market","caption":"Ghe thuyền tấp nập nơi bảy sông gặp nhau","ratio":"16/9"},{"seed":"ngabay-beo","caption":"Cây bẹo treo hàng hóa rao bán","ratio":"4/3"},{"seed":"ngabay-noodle","caption":"Ăn sáng bún riêu ngay trên thuyền","ratio":"1/1"}]', '["hau-giang-lung-ngoc-hoang"]', 1, '{"en":{"name":"Nga Bay Floating Market","summary":"A legendary floating market where seven river branches meet, once the busiest and most famous in the Mekong Delta.","story":"Nga Bay Floating Market, also known as Phung Hiep Floating Market, is a cultural icon of the Hau Giang waterland, formed in the early twentieth century where seven rivers converge at a single point. It was once the largest and busiest floating market in the Mekong Delta, immortalized in the famous song ''Tinh anh ban chieu'' by playwright Vien Chau. At dawn, hundreds of boats laden with produce, fruit and household goods bustle in trade, each hoisting a signature beo pole. Visitors ride boats threading through the market, savor a hot bowl of bun rieu right on the river and feel the free-spirited, warm-hearted rhythm of life of the Mekong''s river traders.","facts":["It formed in the early 20th century where seven river branches meet at Phung Hiep.","It was once the largest and busiest floating market in the Mekong Delta.","It is immortalized in the famous vong co song ''Tinh anh ban chieu'' by playwright Vien Chau.","Boats use a beo pole to hang goods as a signal of what''s for sale on the river."],"travelTips":["Go between 5 and 7 a.m. to catch the floating market at its most crowded.","Try breakfast right on the boat with bun rieu or hu tieu for the full experience."],"bestTime":"Year-round, early morning is when the market is liveliest","visitDuration":"2-3 hours","ticket":"","openingHours":"Market runs 05:00 - 08:00 daily","galleryCaptions":["Boats bustling where seven rivers meet","A beo pole hung with goods for sale","Eating bun rieu breakfast right on the boat"]},"ko":{"name":"응아바이 수상시장","summary":"일곱 갈래 강이 만나는 전설의 수상시장, 한때 메콩델타에서 가장 번화하고 이름난 곳.","story":"풍히엡 수상시장이라고도 불리는 응아바이 수상시장은 후장의 강 문화 상징으로, 일곱 갈래 강이 한 지점에 모이는 곳에 20세기 초 형성되었습니다. 한때 메콩델타에서 가장 크고 번화한 수상시장으로, 극작가 비엔쩌우의 유명한 노래 ''띤안반찌에우''에 길이 남았습니다. 새벽이면 농산물·과일·생활용품을 가득 실은 수백 척의 배가 분주히 거래하며, 저마다 특유의 베오 장대를 세웁니다. 여행객은 배를 타고 시장 사이를 누비며 강 위에서 따끈한 분리에우 한 그릇을 즐기고, 메콩 물의 고장 뱃사람들의 자유롭고 정 깊은 삶의 리듬을 느낍니다.","facts":["20세기 초 풍히엡에서 일곱 갈래 강이 만나는 곳에 형성되었습니다.","한때 메콩델타에서 가장 크고 번화한 수상시장이었습니다.","극작가 비엔쩌우의 유명한 보꼬 노래 ''띤안반찌에우''에 길이 남았습니다.","배들은 베오 장대에 물건을 걸어 강 위에서 판매 신호로 삼습니다."],"travelTips":["수상시장이 가장 붐비는 모습을 보려면 오전 5~7시에 가세요.","온전한 체험을 위해 배 위에서 분리에우나 후띠에우로 아침을 즐겨 보세요."],"bestTime":"연중, 이른 아침이 시장이 가장 활기찬 시간","visitDuration":"2~3시간","ticket":"","openingHours":"매일 05:00 - 08:00 장이 섬","galleryCaptions":["일곱 강이 만나는 곳에 분주한 배들","판매할 물건을 건 베오 장대","배 위에서 분리에우로 아침 먹기"]},"ja":{"name":"ガーバイ水上市場","summary":"七本の川が出会う伝説の水上市場、かつてメコンデルタ屈指の賑わいと名声を誇った場所。","story":"フンヒエップ水上市場とも呼ばれるガーバイ水上市場は、ハウザンの川の文化の象徴で、七つの川が一点に集まる場所に20世紀初頭に形成されました。かつてメコンデルタで最も大きく賑わう水上市場で、劇作家ヴィエンチャウの有名な歌『ティンアン・バンチエウ』に歌い継がれました。夜明けには農産物・果物・日用品を満載した何百艘もの舟が忙しく取引し、それぞれ特有のベオ竿を立てます。旅人は舟で市場の間を縫い、川の上で熱々のブンリエウを味わい、メコンの水の里の舟人たちの自由で情に厚い暮らしのリズムを感じます。","facts":["20世紀初頭、フンヒエップで七本の川が出会う場所に形成されました。","かつてメコンデルタで最も大きく賑わう水上市場でした。","劇作家ヴィエンチャウの有名なヴォンコー『ティンアン・バンチエウ』に歌い継がれました。","舟はベオ竿に品物を掛け、川の上での販売の合図とします。"],"travelTips":["水上市場が最も賑わう様子を見るには午前5〜7時に行きましょう。","存分に体験するには、舟の上でブンリエウやフーティウの朝食を楽しみましょう。"],"bestTime":"通年。早朝が市場の最も活気づく時間","visitDuration":"2〜3時間","ticket":"","openingHours":"毎日05:00 - 08:00 に市が立つ","galleryCaptions":["七本の川が出会う場所で賑わう舟","販売する品物を掛けたベオ竿","舟の上でブンリエウの朝食をとる"]},"zh":{"name":"七岔水上市场","summary":"七条河汊交汇处的传奇水上市场，曾是湄公河三角洲数一数二繁华著名的水上市场。","story":"七岔水上市场又名凤合水上市场，是后江水乡的文化象征，于二十世纪初在七条河汊交汇的地方形成。它曾是湄公河三角洲最大、最繁华的水上市场，被写进作曲家远洲著名的曲子《卖席郎之情》。清晨，数百艘满载农产品、水果、日用品的船只熙攘交易，每艘都竖起特有的吆喝竿。游客坐船穿行市场之间，在河上品一碗热腾腾的蟹肉米粉，感受湄公水乡商旅豪爽重情的生活节奏。","facts":["20世纪初在凤合七条河汊交汇处形成。","曾是湄公河三角洲最大、最繁华的水上市场。","被写进作曲家远洲著名的望古曲《卖席郎之情》。","船只用吆喝竿挂出货物，作为河上售卖的标志。"],"travelTips":["在早晨5至7点前来，可捕捉水上市场最拥挤的氛围。","在船上品尝蟹肉米粉、河粉早餐，体验最完整。"],"bestTime":"全年，清晨是市场最热闹的时段","visitDuration":"2至3小时","ticket":"","openingHours":"每日05:00 - 08:00 开市","galleryCaptions":["七河交汇处熙攘的船只","挂着货物招揽的吆喝竿","在船上吃蟹肉米粉早餐"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('hau-giang-lung-ngoc-hoang', 'lung-ngoc-hoang', 'hau-giang', 'Khu bảo tồn Lung Ngọc Hoàng', 'Lung Ngoc Hoang Nature Reserve', 'park', 105.6539, 9.7197, 'Lá phổi xanh của Hậu Giang với hệ sinh thái đất ngập nước nguyên sinh, được ví như Đồng Tháp Mười thu nhỏ.', 'Khu bảo tồn thiên nhiên Lung Ngọc Hoàng được mệnh danh là lá phổi xanh của vùng Tây sông Hậu, lưu giữ một trong những mảng đất ngập nước nguyên sinh hiếm hoi còn sót lại ở đồng bằng. Trải rộng trên hơn hai nghìn tám trăm hecta, nơi đây là vùng trũng tự nhiên với rừng tràm, đồng năng, lung bàu chằng chịt và thảm thực vật phong phú. Lung Ngọc Hoàng là mái nhà của hàng trăm loài động thực vật, trong đó có nhiều loài chim, cá và bò sát quý hiếm. Đi xuồng len lỏi giữa rừng tràm tĩnh lặng, du khách được hòa mình vào thiên nhiên hoang sơ, lắng nghe tiếng chim gọi bầy và cảm nhận sự trong lành nguyên thủy của vùng đồng bưng Nam Bộ.', '["Diện tích hơn 2.800 hecta, là khu bảo tồn thiên nhiên trọng điểm của Hậu Giang.","Được ví như Đồng Tháp Mười thu nhỏ với hệ sinh thái đất ngập nước nguyên sinh.","Là nơi trú ngụ của hàng trăm loài động thực vật, nhiều loài quý hiếm.","Lung là tên gọi địa phương chỉ những vùng trũng ngập nước tự nhiên."]', '["Liên hệ ban quản lý trước để được sắp xếp xuồng và hướng dẫn tham quan.","Mang giày chống trơn và đồ chống muỗi khi đi sâu vào rừng tràm."]', 'Tháng 8 đến tháng 11, mùa nước nổi cảnh quan đẹp nhất', 'Nửa ngày', '', '07:00 - 17:00 hằng ngày', '["verified","hidden-gem","ai-recommended"]', '["nature","park","photography"]', '[{"seed":"lungngochoang-tram","caption":"Rừng tràm nguyên sinh tĩnh lặng","ratio":"16/9"},{"seed":"lungngochoang-canal","caption":"Xuồng len giữa lung bàu chằng chịt","ratio":"4/3"},{"seed":"lungngochoang-birds","caption":"Cầu tre len giữa rừng tràm dưới trời xanh","ratio":"1/1"}]', '["hau-giang-cho-noi-nga-bay"]', 0, '{"en":{"name":"Lung Ngoc Hoang Reserve","summary":"The green lung of Hau Giang, with a primeval wetland ecosystem likened to a miniature Plain of Reeds.","story":"The Lung Ngoc Hoang Nature Reserve is dubbed the green lung of the western Hau River region, preserving one of the rare remaining patches of primeval wetland in the delta. Spanning more than two thousand eight hundred hectares, it is a natural lowland of cajuput forest, eleocharis meadows, tangled marsh ponds and rich vegetation. Lung Ngoc Hoang is home to hundreds of plant and animal species, including many rare birds, fish and reptiles. Drifting by boat through the silent cajuput forest, visitors immerse themselves in pristine nature, listening to birds calling to their flocks and breathing the primeval freshness of the southern floodplain.","facts":["It spans over 2,800 hectares and is a key nature reserve of Hau Giang.","It is likened to a miniature Plain of Reeds with a primeval wetland ecosystem.","It shelters hundreds of plant and animal species, many of them rare.","''Lung'' is the local term for natural low-lying flooded areas."],"travelTips":["Contact the management board in advance to arrange a boat and a guided tour.","Wear non-slip shoes and mosquito protection when venturing deep into the cajuput forest."],"bestTime":"August to November, the flood season when the scenery is most beautiful","visitDuration":"Half a day","ticket":"","openingHours":"07:00 - 17:00 daily","galleryCaptions":["A silent primeval cajuput forest","A boat threading through tangled marsh ponds","A bamboo bridge through the cajuput forest under a blue sky"]},"ko":{"name":"룽응옥호앙 보호구역","summary":"축소판 동탑므어이에 비견되는 원시 습지 생태계를 간직한 후장의 초록 허파.","story":"룽응옥호앙 자연보호구역은 후강 서부 지역의 초록 허파라 불리며, 델타에 드물게 남은 원시 습지 가운데 하나를 간직하고 있습니다. 2천 8백 헥타르가 넘는 면적에 멜라루카 숲, 골풀 초원, 얽히고설킨 늪 못, 풍부한 식생이 펼쳐진 자연 저지대입니다. 룽응옥호앙은 수백 종의 동식물의 보금자리이며, 그중에는 여러 희귀 새, 물고기, 파충류가 있습니다. 고요한 멜라루카 숲 사이를 배로 누비며 여행객은 원시 자연에 흠뻑 빠져 무리를 부르는 새소리에 귀 기울이고, 남부 범람원의 원초적 청량함을 느낍니다.","facts":["면적 2,800헥타르가 넘는 후장의 핵심 자연보호구역입니다.","원시 습지 생태계로 축소판 동탑므어이에 비견됩니다.","수백 종의 동식물의 서식지이며, 그중 다수가 희귀종입니다.","''룽''은 자연적으로 물이 고인 저지대를 일컫는 현지 말입니다."],"travelTips":["사전에 관리사무소에 연락해 배와 안내 관람을 준비하세요.","멜라루카 숲 깊숙이 들어갈 때는 미끄럼 방지 신발과 모기 기피제를 챙기세요."],"bestTime":"8~11월, 경관이 가장 아름다운 물난리 시기","visitDuration":"반나절","ticket":"","openingHours":"매일 07:00 - 17:00","galleryCaptions":["고요한 원시 멜라루카 숲","얽히고설킨 늪 못 사이를 누비는 배","푸른 하늘 아래 멜라루카 숲을 가로지르는 대나무 다리"]},"ja":{"name":"ルンゴックホアン保護区","summary":"ミニ・ドンタップムオイにたとえられる原生湿地生態系を擁するハウザンの緑の肺。","story":"ルンゴックホアン自然保護区はハウ川西部地域の緑の肺と称され、デルタに稀に残る原生湿地の一つを保っています。2千8百ヘクタールを超える面積に、メラルーカ林、ハリイの草原、入り組んだ沼地、豊かな植生が広がる自然の低地です。ルンゴックホアンは数百種の動植物の住処で、その中には多くの希少な鳥、魚、爬虫類がいます。静かなメラルーカ林の間を舟で縫いながら、旅人は手つかずの自然に浸り、仲間を呼ぶ鳥の声に耳を傾け、南部氾濫原の原初の清々しさを感じます。","facts":["面積2,800ヘクタールを超えるハウザンの中核的な自然保護区です。","原生湿地生態系を持ち、ミニ・ドンタップムオイにたとえられます。","数百種の動植物の生息地で、その多くが希少種です。","「ルン」は自然に水が溜まった低地を指す現地の言葉です。"],"travelTips":["事前に管理事務所に連絡し、舟とガイド付き見学を手配しましょう。","メラルーカ林の奥へ入る際は、滑り止めの靴と蚊よけを着用しましょう。"],"bestTime":"8〜11月、景観が最も美しい増水期","visitDuration":"半日","ticket":"","openingHours":"毎日07:00 - 17:00","galleryCaptions":["静かな原生メラルーカ林","入り組んだ沼地を縫う舟","青空の下、メラルーカ林を貫く竹の橋"]},"zh":{"name":"玉皇洼保护区","summary":"后江的绿肺，拥有原始的湿地生态系统，被誉为缩小版的同塔梅。","story":"玉皇洼自然保护区被誉为后江西部地区的绿肺，保存着三角洲难得仅存的一片原始湿地。这里横跨两千八百多公顷，是一片天然洼地，拥有白千层林、荸荠草原、纵横交错的洼塘和丰富的植被。玉皇洼是数百种动植物的家园，其中包括许多珍稀的鸟类、鱼类和爬行动物。坐船穿行于寂静的白千层林间，游客沉浸在原始的自然之中，聆听呼伴的鸟鸣，感受南部洼地原初的清新。","facts":["面积超过2,800公顷，是后江的重点自然保护区。","拥有原始湿地生态系统，被誉为缩小版的同塔梅。","是数百种动植物的栖息地，其中许多为珍稀物种。","「洼（Lung）」是当地对天然积水低地的称呼。"],"travelTips":["提前联系管理处，安排船只和向导参观。","深入白千层林时请穿防滑鞋、做好防蚊措施。"],"bestTime":"8月至11月，景色最美的涨水季节","visitDuration":"半天","ticket":"","openingHours":"每日07:00 - 17:00","galleryCaptions":["寂静的原始白千层林","穿行于纵横交错洼塘间的小舟","蓝天下穿过白千层林的竹桥"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('soc-trang-chua-doi', 'chua-doi', 'soc-trang', 'Chùa Dơi', 'Bat Pagoda', 'temple', 105.9869, 9.5908, 'Ngôi chùa Khmer cổ kính nổi tiếng với hàng nghìn con dơi quạ treo mình trên những tán cây cổ thụ.', 'Chùa Dơi, tên Khmer là Mahatup, là một trong những ngôi chùa Khmer cổ và linh thiêng nhất Sóc Trăng, có lịch sử hơn bốn trăm năm. Chùa mang kiến trúc Phật giáo Nam tông đặc trưng với mái cong nhiều tầng, cột chạm tiên nữ và những hoa văn rực rỡ. Điều khiến nơi đây nổi tiếng khắp cả nước là hàng nghìn con dơi quạ khổng lồ treo mình lủng lẳng trên các tán sao, dầu cổ thụ trong khuôn viên chùa. Mỗi chiều, đàn dơi đồng loạt thức giấc, bay rợp trời đi kiếm ăn tạo nên cảnh tượng kỳ thú. Người dân tin rằng đàn dơi là điềm lành, được nhà chùa che chở qua bao thế kỷ. Chùa Dơi là điểm đến giao hòa giữa tâm linh, văn hóa Khmer và thiên nhiên kỳ diệu.', '["Tên Khmer là chùa Mahatup, có lịch sử hơn 400 năm tại Sóc Trăng.","Hàng nghìn con dơi quạ khổng lồ treo mình trên cây cổ thụ trong khuôn viên.","Mang kiến trúc Phật giáo Nam tông Khmer với mái cong nhiều tầng đặc trưng.","Người dân xem đàn dơi là điềm lành và được nhà chùa bảo vệ qua nhiều thế kỷ."]', '["Đến lúc chiều tà để xem đàn dơi đồng loạt bay đi kiếm ăn rợp trời.","Ăn mặc lịch sự và giữ yên tĩnh khi tham quan khuôn viên chùa."]', 'Quanh năm, dịp lễ Khmer và buổi chiều là thời điểm đẹp nhất', '1-2 giờ', '5.000đ', '07:00 - 18:00 hằng ngày', '["popular","verified","trending"]', '["temple","culture","history","nature"]', '[{"seed":"chuadoi-bats","caption":"Đàn dơi quạ treo mình trên cây cổ thụ","ratio":"16/9"},{"seed":"chuadoi-temple","caption":"Kiến trúc Khmer mái cong nhiều tầng","ratio":"4/3"},{"seed":"chuadoi-flight","caption":"Dơi bay rợp trời lúc chiều tà","ratio":"1/1"}]', '["soc-trang-chua-dat-set"]', 1, '{"en":{"name":"Bat Pagoda","summary":"An ancient Khmer pagoda famous for the thousands of flying foxes hanging from its old-growth trees.","story":"Bat Pagoda, known in Khmer as Mahatup, is one of the oldest and most sacred Khmer pagodas in Soc Trang, with over four hundred years of history. It features signature Theravada Buddhist architecture with multi-tiered curved roofs, columns carved with celestial maidens and brilliant motifs. What makes it famous nationwide is the thousands of giant flying foxes hanging from the old hopea and dipterocarp trees in the grounds. Each evening, the colony wakes all at once and fills the sky as it flies off to feed, creating a remarkable spectacle. Locals believe the bats are a good omen, sheltered by the pagoda through the centuries. Bat Pagoda is a place where spirituality, Khmer culture and wondrous nature meet.","facts":["Its Khmer name is Mahatup Pagoda, with over 400 years of history in Soc Trang.","Thousands of giant flying foxes hang from the old-growth trees in the grounds.","It features signature Theravada Khmer Buddhist architecture with multi-tiered curved roofs.","Locals regard the bats as a good omen, protected by the pagoda through the centuries."],"travelTips":["Come at dusk to watch the bat colony fly off to feed, filling the sky.","Dress respectfully and stay quiet when visiting the pagoda grounds."],"bestTime":"Year-round; Khmer festivals and the evening are the best times","visitDuration":"1-2 hours","ticket":"5,000 VND","openingHours":"07:00 - 18:00 daily","galleryCaptions":["Flying foxes hanging from old-growth trees","Khmer architecture with multi-tiered curved roofs","Bats filling the sky at dusk"]},"ko":{"name":"박쥐 사원","summary":"노거수에 매달린 수천 마리 큰박쥐로 유명한 고풍스러운 크메르 사원.","story":"크메르어로 마하툽이라 불리는 박쥐 사원은 속짱에서 가장 오래되고 영험한 크메르 사원 중 하나로, 400년이 넘는 역사를 지녔습니다. 다층의 곡선 지붕, 천녀가 새겨진 기둥, 찬란한 문양 등 남방 불교 특유의 건축이 돋보입니다. 이곳을 전국적으로 유명하게 만든 것은 경내의 오래된 호페아·딥테로카르푸스 나무에 주렁주렁 매달린 수천 마리의 거대한 큰박쥐입니다. 저녁마다 무리가 한꺼번에 깨어나 먹이를 찾아 하늘을 가득 메우며 날아올라 장관을 이룹니다. 주민들은 박쥐를 길조로 여기며, 사원은 수 세기에 걸쳐 이들을 보살펴 왔습니다. 박쥐 사원은 영성과 크메르 문화, 경이로운 자연이 어우러지는 곳입니다.","facts":["크메르어로 마하툽 사원이며, 속짱에서 400년이 넘는 역사를 지녔습니다.","경내의 노거수에는 수천 마리의 거대한 큰박쥐가 매달려 있습니다.","다층의 곡선 지붕이 특징인 남방 크메르 불교 건축을 갖추고 있습니다.","주민들은 박쥐를 길조로 여기며, 사원은 수 세기에 걸쳐 이들을 보호해 왔습니다."],"travelTips":["박쥐 무리가 하늘을 메우며 먹이를 찾아 날아오르는 해 질 녘에 가세요.","사원 경내를 관람할 때는 단정히 입고 정숙하세요."],"bestTime":"연중, 크메르 축제와 저녁 무렵이 가장 좋음","visitDuration":"1~2시간","ticket":"5,000동","openingHours":"매일 07:00 - 18:00","galleryCaptions":["노거수에 매달린 큰박쥐 무리","다층 곡선 지붕의 크메르 건축","해 질 녘 하늘을 메우며 나는 박쥐"]},"ja":{"name":"コウモリ寺","summary":"古木にぶら下がる数千匹のオオコウモリで有名な、古色蒼然としたクメール寺院。","story":"クメール語でマハトゥップと呼ばれるコウモリ寺は、ソクチャンで最も古く霊験あらたかなクメール寺院の一つで、400年を超える歴史を持ちます。多層の反り屋根、天女が彫られた柱、鮮やかな文様など南方仏教特有の建築が際立ちます。ここを全国的に有名にしているのは、境内の古いホペアやフタバガキの木にぶら下がる数千匹の巨大なオオコウモリです。毎夕、群れが一斉に目覚め、餌を求めて空を埋めて飛び立ち、壮観を成します。住民はコウモリを吉兆とみなし、寺院は幾世紀にもわたり彼らを守ってきました。コウモリ寺は霊性とクメール文化、驚異の自然が交わる場所です。","facts":["クメール語でマハトゥップ寺で、ソクチャンで400年を超える歴史を持ちます。","境内の古木に数千匹の巨大なオオコウモリがぶら下がっています。","多層の反り屋根が特徴の南方クメール仏教建築を備えます。","住民はコウモリを吉兆とみなし、寺院は幾世紀にもわたり彼らを守ってきました。"],"travelTips":["コウモリの群れが空を埋めて餌を求め飛び立つ夕暮れ時に行きましょう。","寺院の境内を見学する際は端正な服装をし、静かにしましょう。"],"bestTime":"通年。クメールの祭りと夕暮れ時が最も良い","visitDuration":"1〜2時間","ticket":"5,000ドン","openingHours":"毎日07:00 - 18:00","galleryCaptions":["古木にぶら下がるオオコウモリの群れ","多層の反り屋根のクメール建築","夕暮れに空を埋めて飛ぶコウモリ"]},"zh":{"name":"蝙蝠寺","summary":"古朴的高棉寺庙，以倒挂在参天古树上的数千只狐蝠闻名。","story":"蝙蝠寺，高棉语名马哈图，是朔庄最古老、最灵验的高棉寺庙之一，已有四百多年历史。寺庙具有典型的南传佛教建筑风格，多层飞檐、雕饰天女的廊柱和绚丽的纹饰。让这里闻名全国的，是寺院内古老桫木、龙脑香树上倒挂着的成千上万只巨大狐蝠。每到傍晚，蝙蝠群同时苏醒，遮天蔽日地飞出觅食，蔚为奇观。当地人相信蝙蝠是吉兆，寺庙世世代代庇护着它们。蝙蝠寺是灵性、高棉文化与奇妙自然交融之地。","facts":["高棉语名马哈图寺，在朔庄已有400多年历史。","寺院内的古树上倒挂着成千上万只巨大狐蝠。","具有以多层飞檐为特色的南传高棉佛教建筑风格。","当地人视蝙蝠为吉兆，寺庙数百年来一直保护它们。"],"travelTips":["傍晚前来，观看蝙蝠群遮天蔽日地飞出觅食。","参观寺院时着装得体、保持安静。"],"bestTime":"全年，高棉节庆和傍晚是最佳时段","visitDuration":"1至2小时","ticket":"5,000越南盾","openingHours":"每日07:00 - 18:00","galleryCaptions":["倒挂在古树上的狐蝠群","多层飞檐的高棉建筑","傍晚遮天蔽日飞翔的蝙蝠"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('soc-trang-chua-dat-set', 'chua-dat-set', 'soc-trang', 'Chùa Đất Sét', 'Clay Pagoda', 'temple', 105.9764, 9.6022, 'Ngôi chùa độc đáo với hàng nghìn tượng nặn từ đất sét và những cây nến khổng lồ cháy suốt hàng chục năm.', 'Chùa Đất Sét, tên chính thức là Bửu Sơn Tự, là ngôi chùa có một không hai ở Sóc Trăng và cả Việt Nam. Suốt mấy chục năm ròng, một người trong dòng họ cai quản chùa đã miệt mài nặn nên hàng nghìn pho tượng Phật, linh thú, tháp và đồ thờ hoàn toàn bằng đất sét pha bột nhang, tô màu tỉ mỉ. Nổi bật là tháp Đa Bảo và bảo tòa Liên Hoa đồ sộ với hàng nghìn cánh sen đất sét. Chùa còn lưu giữ những cây nến khổng lồ nặng hàng trăm ký, có cây thắp liên tục đã mấy chục năm vẫn chưa cháy hết, cùng những cây hương cao vút. Mỗi chi tiết đều là kết tinh của lòng thành kính và sự kiên nhẫn phi thường, khiến du khách không khỏi thán phục khi ghé thăm.', '["Tên chính thức là Bửu Sơn Tự, nổi tiếng với tượng nặn hoàn toàn từ đất sét.","Có hàng nghìn pho tượng Phật, linh thú và tháp được nặn thủ công tỉ mỉ.","Lưu giữ những cây nến khổng lồ nặng hàng trăm ký, cháy liên tục hàng chục năm.","Tháp Đa Bảo và bảo tòa Liên Hoa là hai công trình đất sét tiêu biểu của chùa."]', '["Quan sát kỹ các cây nến và cây hương khổng lồ, điểm độc đáo nhất của chùa.","Kết hợp tham quan cùng Chùa Dơi gần đó trong một buổi khám phá Sóc Trăng."]', 'Quanh năm, mát mẻ nhất vào mùa khô tháng 11 đến tháng 4', '1 giờ', '', '07:00 - 18:00 hằng ngày', '["verified","hidden-gem"]', '["temple","culture","history"]', '[{"seed":"datset-statues","caption":"Tượng Phật nặn từ đất sét tỉ mỉ","ratio":"16/9"},{"seed":"datset-candles","caption":"Cây nến khổng lồ cháy hàng chục năm","ratio":"4/3"},{"seed":"datset-tower","caption":"Bảo tòa Liên Hoa bằng đất sét","ratio":"1/1"}]', '["soc-trang-chua-doi"]', 0, '{"en":{"name":"Clay Pagoda","summary":"A unique pagoda with thousands of clay-molded statues and giant candles that have burned for decades.","story":"Clay Pagoda, officially named Buu Son Tu, is a one-of-a-kind pagoda in Soc Trang and all of Vietnam. For several decades, a member of the family that tends the pagoda painstakingly molded thousands of statues of Buddha, sacred beasts, towers and ritual objects entirely from clay mixed with incense powder, meticulously painted. Standout works include the imposing Da Bao Tower and Lien Hoa altar with thousands of clay lotus petals. The pagoda also keeps giant candles weighing hundreds of kilograms, some burning continuously for decades and still not spent, along with towering incense sticks. Every detail is the crystallization of devotion and extraordinary patience, leaving visitors in awe.","facts":["Its official name is Buu Son Tu, famous for statues molded entirely from clay.","It holds thousands of statues of Buddha, sacred beasts and towers, painstakingly hand-molded.","It keeps giant candles weighing hundreds of kilograms, burning continuously for decades.","The Da Bao Tower and Lien Hoa altar are the pagoda''s two signature clay works."],"travelTips":["Look closely at the giant candles and incense sticks, the pagoda''s most unique feature.","Combine your visit with the nearby Bat Pagoda for a day of exploring Soc Trang."],"bestTime":"Year-round, coolest in the dry season from November to April","visitDuration":"1 hour","ticket":"","openingHours":"07:00 - 18:00 daily","galleryCaptions":["A meticulously clay-molded Buddha statue","A giant candle that has burned for decades","The Lien Hoa altar made of clay"]},"ko":{"name":"흙 사원","summary":"흙으로 빚은 수천 점의 조각상과 수십 년간 타 온 거대한 양초가 있는 독특한 사원.","story":"정식 명칭이 부어선뜨인 흙 사원은 속짱은 물론 베트남 전역에서도 유일무이한 사원입니다. 수십 년에 걸쳐 사원을 돌보던 집안의 한 사람이 향가루를 섞은 흙으로 수천 점의 불상, 영수, 탑, 제기를 정성껏 빚고 세심하게 색을 입혔습니다. 대표작으로는 웅장한 다바오 탑과 수천 장의 흙 연꽃잎으로 만든 연화대가 있습니다. 사원에는 또한 수백 킬로그램에 달하는 거대한 양초가 있는데, 일부는 수십 년간 계속 타고도 아직 다 닳지 않았으며, 하늘 높이 솟은 향대도 함께 있습니다. 모든 세부가 정성과 비범한 인내의 결정체로, 찾는 이들을 경탄하게 합니다.","facts":["정식 명칭은 부어선뜨이며, 전부 흙으로 빚은 조각상으로 유명합니다.","정성껏 손으로 빚은 수천 점의 불상, 영수, 탑이 있습니다.","수백 킬로그램에 달하는 거대한 양초가 수십 년간 계속 타고 있습니다.","다바오 탑과 연화대는 사원을 대표하는 두 흙 작품입니다."],"travelTips":["사원에서 가장 독특한 거대한 양초와 향대를 자세히 살펴보세요.","인근의 박쥐 사원과 함께 둘러보며 속짱을 하루 동안 탐방하세요."],"bestTime":"연중, 11~4월 건기에 가장 시원함","visitDuration":"1시간","ticket":"","openingHours":"매일 07:00 - 18:00","galleryCaptions":["정성껏 흙으로 빚은 불상","수십 년간 타 온 거대한 양초","흙으로 만든 연화대"]},"ja":{"name":"土の寺","summary":"土で形作られた数千の像と、数十年燃え続ける巨大な蝋燭がある独特な寺院。","story":"正式名をブウソン寺という土の寺は、ソクチャンはもとよりベトナム全土でも唯一無二の寺院です。数十年にわたり、寺を守る一族の一人が、線香の粉を混ぜた土で数千もの仏像、霊獣、塔、祭具を丹念に形作り、細やかに彩色しました。代表作には壮大なダーバオ塔と、数千枚の土の蓮の花弁で作った蓮華座があります。寺にはまた、数百キロもの巨大な蝋燭があり、数十年燃え続けてなお燃え尽きないものもあり、天高くそびえる線香も並びます。一つひとつの細部が真心と並外れた忍耐の結晶で、訪れる人を感嘆させます。","facts":["正式名はブウソン寺で、すべて土で形作った像で有名です。","丹念に手で形作った数千の仏像、霊獣、塔があります。","数百キロもの巨大な蝋燭が数十年燃え続けています。","ダーバオ塔と蓮華座は寺を代表する二つの土の作品です。"],"travelTips":["寺で最も独特な巨大な蝋燭と線香をじっくり眺めましょう。","近くのコウモリ寺と合わせて巡り、ソクチャンを一日かけて探訪しましょう。"],"bestTime":"通年。11〜4月の乾季が最も涼しい","visitDuration":"1時間","ticket":"","openingHours":"毎日07:00 - 18:00","galleryCaptions":["丹念に土で形作った仏像","数十年燃え続ける巨大な蝋燭","土で作った蓮華座"]},"zh":{"name":"泥土寺","summary":"独一无二的寺庙，拥有数千尊泥塑像和燃烧了数十年的巨型蜡烛。","story":"泥土寺，正式名称宝山寺，是朔庄乃至全越南独一无二的寺庙。数十年间，掌管寺庙的家族中的一人潜心用掺了香粉的泥土塑出数千尊佛像、灵兽、宝塔和供器，并细致上色。其中最引人注目的是宏伟的多宝塔和用数千片泥莲花瓣制成的莲华宝座。寺中还保存着重达数百公斤的巨型蜡烛，有的连续燃烧了数十年仍未烧尽，还有高耸的香柱。每一处细节都是虔诚之心和非凡耐心的结晶，令到访者无不叹服。","facts":["正式名称宝山寺，以完全由泥土塑成的塑像闻名。","拥有数千尊精心手工塑造的佛像、灵兽和宝塔。","保存着重达数百公斤、连续燃烧数十年的巨型蜡烛。","多宝塔和莲华宝座是寺中具代表性的两件泥土作品。"],"travelTips":["仔细观赏巨型蜡烛和香柱，这是寺中最独特之处。","结合附近的蝙蝠寺一同参观，用半天探访朔庄。"],"bestTime":"全年，11月至4月旱季最为凉爽","visitDuration":"1小时","ticket":"","openingHours":"每日07:00 - 18:00","galleryCaptions":["精心用泥土塑成的佛像","燃烧了数十年的巨型蜡烛","用泥土制成的莲华宝座"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bac-lieu-canh-dong-dien-gio', 'canh-dong-dien-gio', 'bac-lieu', 'Cánh đồng điện gió Bạc Liêu', 'Bac Lieu Wind Farm', 'park', 105.7842, 9.1986, 'Cánh đồng quạt gió khổng lồ vươn ra biển, biểu tượng năng lượng xanh và điểm check-in mê hoặc của Bạc Liêu.', 'Cánh đồng điện gió Bạc Liêu là một trong những nhà máy điện gió ven biển đầu tiên và lớn nhất Việt Nam, nằm trên vùng bãi bồi ven biển huyện Hòa Bình. Hàng chục tua bin gió khổng lồ cao hơn tám mươi mét sừng sững vươn lên giữa mênh mông trời nước, những cánh quạt trắng quay đều trong gió biển tạo nên khung cảnh vừa hùng vĩ vừa nên thơ. Du khách đi trên con đường dẫn ra giữa cánh đồng quạt gió, phóng tầm mắt ra biển và đắm mình trong làn gió mặn mòi. Đây không chỉ là biểu tượng cho khát vọng phát triển năng lượng sạch của miền Tây, mà còn trở thành điểm check-in cực kỳ ấn tượng, nhất là khi hoàng hôn buông xuống nhuộm đỏ cả chân trời.', '["Là một trong những nhà máy điện gió ven biển đầu tiên và lớn của Việt Nam.","Hàng chục tua bin gió cao hơn 80 mét đặt trên vùng bãi bồi ven biển.","Biểu tượng cho phát triển năng lượng sạch của tỉnh Bạc Liêu.","Trở thành điểm check-in nổi tiếng, đẹp nhất vào lúc hoàng hôn."]', '["Đến vào cuối chiều để ngắm hoàng hôn tuyệt đẹp giữa cánh đồng quạt gió.","Mang theo áo khoác mỏng vì gió biển khá mạnh, nhất là buổi chiều tối."]', 'Tháng 11 đến tháng 4, mùa khô trời trong gió đẹp', '1-2 giờ', '60.000đ tham quan', '07:00 - 18:00 hằng ngày', '["trending","verified","popular"]', '["nature","photography","city"]', '[{"seed":"baclieu-turbines","caption":"Tua bin gió vươn ra biển","ratio":"16/9"},{"seed":"baclieu-path","caption":"Con đường dẫn ra giữa cánh đồng quạt gió","ratio":"4/3"},{"seed":"baclieu-sunset","caption":"Hàng tuabin điện gió mọc sau rặng cây xanh","ratio":"1/1"}]', '["bac-lieu-nha-cong-tu"]', 1, '{"en":{"name":"Bac Lieu Wind Farm","summary":"A vast field of wind turbines reaching out to sea, a symbol of green energy and a mesmerizing check-in spot in Bac Lieu.","story":"The Bac Lieu Wind Farm is one of Vietnam''s first and largest coastal wind power plants, set on the tidal flats off Hoa Binh district. Dozens of giant wind turbines over eighty meters tall rise above the vast expanse of sea and sky, their white blades turning steadily in the sea breeze to create a scene both grand and poetic. Visitors walk along the path leading into the middle of the wind farm, gaze out to sea and bask in the salty breeze. This is not only a symbol of the Mekong''s aspiration for clean energy but also a strikingly impressive check-in spot, especially when sunset reddens the entire horizon.","facts":["It is one of Vietnam''s first and largest coastal wind power plants.","Dozens of wind turbines over 80 meters tall stand on the coastal tidal flats.","It is a symbol of clean-energy development for Bac Lieu province.","It has become a famous check-in spot, most beautiful at sunset."],"travelTips":["Come in late afternoon to watch a gorgeous sunset amid the wind turbines.","Bring a light jacket, as the sea breeze is quite strong, especially in the evening."],"bestTime":"November to April, the dry season with clear skies and lovely winds","visitDuration":"1-2 hours","ticket":"60,000 VND admission","openingHours":"07:00 - 18:00 daily","galleryCaptions":["Wind turbines reaching out to sea","The path leading into the middle of the wind farm","Rows of wind turbines rising behind a green tree line"]},"ko":{"name":"박리에우 풍력발전 단지","summary":"바다로 뻗은 거대한 풍력 터빈 들판, 녹색 에너지의 상징이자 박리에우의 매혹적인 인증샷 명소.","story":"박리에우 풍력발전 단지는 베트남 최초이자 최대 규모의 해안 풍력발전소 중 하나로, 호아빈현 앞바다 갯벌에 자리합니다. 80m가 넘는 거대한 풍력 터빈 수십 기가 드넓은 바다와 하늘 사이로 우뚝 솟아 있고, 흰 날개가 바닷바람에 꾸준히 돌며 웅장하고도 시적인 풍경을 빚어냅니다. 여행객은 풍력 단지 한가운데로 이어지는 길을 걸으며 바다를 바라보고 짭짤한 바닷바람에 흠뻑 젖어듭니다. 이곳은 메콩의 청정에너지 염원의 상징일 뿐 아니라, 특히 노을이 온 수평선을 붉게 물들일 때 더없이 인상적인 인증샷 명소입니다.","facts":["베트남 최초이자 최대 규모의 해안 풍력발전소 중 하나입니다.","80m가 넘는 풍력 터빈 수십 기가 해안 갯벌에 세워져 있습니다.","박리에우성의 청정에너지 발전을 상징합니다.","유명한 인증샷 명소가 되었으며, 일몰 때 가장 아름답습니다."],"travelTips":["풍력 터빈 사이로 펼쳐지는 멋진 일몰을 감상하려면 늦은 오후에 가세요.","특히 저녁에는 바닷바람이 꽤 세니 얇은 겉옷을 챙기세요."],"bestTime":"11~4월, 하늘이 맑고 바람이 좋은 건기","visitDuration":"1~2시간","ticket":"관람 60,000동","openingHours":"매일 07:00 - 18:00","galleryCaptions":["바다로 뻗은 풍력 터빈","풍력 단지 한가운데로 이어지는 길","푸른 나무 줄기 너머로 솟은 풍력 터빈들"]},"ja":{"name":"バクリエウ風力発電所","summary":"海へ延びる巨大な風車の原、グリーンエネルギーの象徴でありバクリエウの魅惑の撮影スポット。","story":"バクリエウ風力発電所はベトナム初・最大級の沿岸風力発電所の一つで、ホアビン県沖の干潟に位置します。80メートルを超える巨大な風車が数十基、広大な海と空の間にそびえ立ち、白い羽根が海風に淡々と回って雄大かつ詩情あふれる景色を生み出します。旅人は風車の原の真ん中へ続く道を歩き、海を眺め、潮の香りの風に浸ります。ここはメコンのクリーンエネルギーへの願いの象徴であるだけでなく、とくに夕日が水平線一面を赤く染めるとき、この上なく印象的な撮影スポットとなります。","facts":["ベトナム初・最大級の沿岸風力発電所の一つです。","80メートルを超える風車が数十基、沿岸の干潟に立っています。","バクリエウ省のクリーンエネルギー開発を象徴します。","有名な撮影スポットとなり、夕日の時が最も美しい。"],"travelTips":["風車の間に広がる見事な夕日を眺めるには、夕方遅くに行きましょう。","とくに夕方は海風がかなり強いので、薄い上着を持参しましょう。"],"bestTime":"11〜4月、空が澄み風の心地よい乾季","visitDuration":"1〜2時間","ticket":"見学60,000ドン","openingHours":"毎日07:00 - 18:00","galleryCaptions":["海へ延びる風車","風車の原の真ん中へ続く道","緑の木立の向こうにそびえる風車の列"]},"zh":{"name":"薄辽风电场","summary":"向海延伸的巨型风车之原，是绿色能源的象征，也是薄辽迷人的打卡胜地。","story":"薄辽风电场是越南最早、最大的沿海风电场之一，位于和平县沿海的淤积滩涂上。数十座高逾八十米的巨型风车在辽阔的海天之间巍然耸立，白色叶片在海风中匀速旋转，营造出既雄伟又诗意的景致。游客走在通往风车原中央的栈道上，远眺大海，沉浸在咸湿的海风里。这里不仅是湄公发展清洁能源雄心的象征，更成了极具震撼力的打卡胜地，尤其当落日将整个天际染红之时。","facts":["是越南最早、最大的沿海风电场之一。","数十座高逾80米的风车矗立在沿海淤积滩涂上。","是薄辽省发展清洁能源的象征。","已成为著名打卡胜地，落日时分最美。"],"travelTips":["傍晚前来，观赏风车原间绝美的落日。","带上薄外套，海风颇大，尤其在傍晚。"],"bestTime":"11月至4月，天清风爽的旱季","visitDuration":"1至2小时","ticket":"参观60,000越南盾","openingHours":"每日07:00 - 18:00","galleryCaptions":["向海延伸的风车","通往风车原中央的栈道","在绿树之后耸立的成排风车"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('bac-lieu-nha-cong-tu', 'nha-cong-tu-bac-lieu', 'bac-lieu', 'Nhà Công tử Bạc Liêu', 'House of Bac Lieu''s Prince', 'museum', 105.7244, 9.2853, 'Dinh thự cổ bề thế của Công tử Bạc Liêu, lưu giữ giai thoại ăn chơi lừng lẫy một thời của giới điền chủ Nam Bộ.', 'Nhà Công tử Bạc Liêu là một dinh thự cổ tráng lệ tọa lạc bên dòng sông Bạc Liêu, gắn liền với giai thoại nổi tiếng về Trần Trinh Huy, vị công tử ăn chơi khét tiếng nhất Nam Bộ đầu thế kỷ hai mươi. Ngôi nhà được xây dựng theo lối kiến trúc phương Tây sang trọng với vật liệu nhập từ Pháp, nội thất gỗ quý chạm trổ tinh xảo, đèn chùm pha lê lộng lẫy. Bên trong còn lưu giữ nhiều kỷ vật quý như bộ bàn ghế cẩn xà cừ, chiếc giường nóng lạnh và những món đồ cổ giá trị. Câu chuyện về vị công tử đốt tiền nấu trứng, lái máy bay riêng đi thăm ruộng đã trở thành huyền thoại. Tham quan nơi đây, du khách như ngược dòng thời gian về thời vàng son của tầng lớp đại điền chủ miền Tây.', '["Gắn với giai thoại về Trần Trinh Huy, công tử ăn chơi nổi tiếng nhất Nam Bộ.","Dinh thự xây theo kiến trúc phương Tây với vật liệu nhập khẩu từ Pháp.","Lưu giữ nhiều cổ vật quý như bàn ghế cẩn xà cừ, đèn chùm pha lê.","Giai thoại đốt tiền nấu trứng và sở hữu máy bay riêng đã thành huyền thoại."]', '["Thuê hướng dẫn viên tại chỗ để nghe trọn vẹn các giai thoại thú vị về công tử.","Có thể nghỉ lại khách sạn trong khuôn viên để trải nghiệm không gian xưa."]', 'Quanh năm, mát mẻ nhất vào mùa khô tháng 11 đến tháng 4', '1 giờ', '30.000đ', '07:00 - 17:30 hằng ngày', '["popular","verified"]', '["museum","history","culture","city"]', '[{"seed":"congtu-mansion","caption":"Dinh thự cổ kiến trúc phương Tây","ratio":"16/9"},{"seed":"congtu-interior","caption":"Nội thất gỗ quý chạm trổ tinh xảo","ratio":"4/3"},{"seed":"congtu-antiques","caption":"Cổ vật cẩn xà cừ giá trị","ratio":"1/1"}]', '["bac-lieu-canh-dong-dien-gio"]', 0, '{"en":{"name":"House of the Bac Lieu Playboy","summary":"A grand old mansion of the Bac Lieu Playboy, preserving the legendary tales of a famous high-living landlord of the south.","story":"The House of the Bac Lieu Playboy is a magnificent old mansion on the bank of the Bac Lieu River, tied to the famous legend of Tran Trinh Huy, the most notorious high-living playboy in the south in the early twentieth century. The house was built in a luxurious Western style with materials imported from France, with exquisitely carved fine-wood interiors and dazzling crystal chandeliers. Inside, it still preserves many precious relics such as mother-of-pearl-inlaid furniture, a hot-and-cold bed and valuable antiques. Stories of the playboy burning money to boil eggs and flying his own plane to tour his fields have become legend. Visiting here, travelers feel as if they''ve traveled back in time to the golden age of the great landlord class of the Mekong.","facts":["It is tied to the legend of Tran Trinh Huy, the most famous high-living playboy of the south.","The mansion was built in Western architecture with materials imported from France.","It preserves many precious antiques such as mother-of-pearl-inlaid furniture and crystal chandeliers.","The tales of burning money to boil eggs and owning a private plane have become legend."],"travelTips":["Hire an on-site guide to hear the full, fascinating tales of the playboy.","You can stay at the hotel within the grounds to experience the old-time atmosphere."],"bestTime":"Year-round, coolest in the dry season from November to April","visitDuration":"1 hour","ticket":"30,000 VND","openingHours":"07:00 - 17:30 daily","galleryCaptions":["The old mansion in Western architecture","Exquisitely carved fine-wood interiors","Valuable mother-of-pearl-inlaid antiques"]},"ko":{"name":"박리에우 공자 저택","summary":"한 시대를 풍미한 남부 지주의 화려한 일화를 간직한 박리에우 공자의 웅장한 고택.","story":"박리에우 공자 저택은 박리에우강변에 자리한 화려한 고택으로, 20세기 초 남부에서 가장 악명 높던 풍류 공자 쩐찐후이에 얽힌 유명한 일화와 연결되어 있습니다. 이 집은 프랑스에서 들여온 자재로 호화로운 서양식 건축으로 지어졌으며, 정교하게 조각된 고급 목재 내장과 눈부신 크리스털 샹들리에를 갖추었습니다. 내부에는 자개를 박은 가구, 냉온 침대, 값진 골동품 등 귀중한 유물이 다수 보존되어 있습니다. 돈을 태워 달걀을 삶고 개인 비행기로 논을 둘러봤다는 공자의 이야기는 전설이 되었습니다. 이곳을 둘러보면 여행객은 메콩 대지주 계층의 황금기로 시간을 거슬러 오른 듯한 기분을 느낍니다.","facts":["남부에서 가장 유명한 풍류 공자 쩐찐후이의 일화와 연결되어 있습니다.","저택은 프랑스에서 수입한 자재로 서양식 건축으로 지어졌습니다.","자개 가구, 크리스털 샹들리에 등 값진 골동품이 다수 보존되어 있습니다.","돈을 태워 달걀을 삶고 개인 비행기를 소유했다는 일화는 전설이 되었습니다."],"travelTips":["공자에 얽힌 흥미로운 일화를 온전히 들으려면 현지 가이드를 고용하세요.","옛 정취를 체험하려면 저택 경내의 호텔에서 묵을 수 있습니다."],"bestTime":"연중, 11~4월 건기에 가장 시원함","visitDuration":"1시간","ticket":"30,000동","openingHours":"매일 07:00 - 17:30","galleryCaptions":["서양식 건축의 고택","정교하게 조각된 고급 목재 내장","값진 자개 골동품"]},"ja":{"name":"バクリエウの貴公子の邸宅","summary":"一時代を風靡した南部の地主の華やかな逸話を伝える、バクリエウの貴公子の壮麗な古邸宅。","story":"バクリエウの貴公子の邸宅はバクリエウ川辺に佇む壮麗な古邸宅で、20世紀初頭、南部で最も悪名高い遊蕩の貴公子チャン・チン・フイにまつわる有名な逸話と結びついています。この邸宅はフランスから取り寄せた資材で豪奢な西洋様式で建てられ、精緻に彫られた高級木材の内装と、まばゆいクリスタルのシャンデリアを備えます。内部には螺鈿細工の家具、冷温ベッド、貴重な骨董品など、多くの貴重な遺品が保存されています。札を燃やして卵を茹で、自家用飛行機で田を見回ったという貴公子の話は伝説となりました。ここを巡れば、旅人はメコンの大地主階層の黄金期へ時を遡ったような気分になります。","facts":["南部で最も有名な遊蕩の貴公子チャン・チン・フイの逸話と結びついています。","邸宅はフランスから輸入した資材で西洋様式で建てられました。","螺鈿細工の家具、クリスタルのシャンデリアなど貴重な骨董品を保存しています。","札を燃やして卵を茹で、自家用飛行機を所有したという逸話は伝説となりました。"],"travelTips":["貴公子の興味深い逸話を存分に聞くには、現地ガイドを雇いましょう。","昔の趣を体験するため、邸宅の敷地内のホテルに泊まることもできます。"],"bestTime":"通年。11〜4月の乾季が最も涼しい","visitDuration":"1時間","ticket":"30,000ドン","openingHours":"毎日07:00 - 17:30","galleryCaptions":["西洋様式の古邸宅","精緻に彫られた高級木材の内装","貴重な螺鈿細工の骨董品"]},"zh":{"name":"薄辽公子宅","summary":"薄辽公子气派的古宅邸，留存着南部地主阶层昔日声名显赫的奢华轶事。","story":"薄辽公子宅是矗立于薄辽河畔的一座华丽古宅邸，与二十世纪初南部最声名狼藉的纨绔公子陈仲辉的著名轶事相连。这座宅邸采用奢华的西式建筑风格，建材从法国进口，室内雕饰精美的名贵木器，悬挂华丽的水晶吊灯。宅内还保存着许多珍贵遗物，如螺钿镶嵌的桌椅、冷暖床和价值连城的古董。公子烧钞票煮鸡蛋、开私人飞机巡视田地的故事，早已成为传奇。参观此处，游客仿佛穿越时光，回到湄公大地主阶层的黄金年代。","facts":["与南部最著名的纨绔公子陈仲辉的轶事相连。","宅邸采用西式建筑风格，建材从法国进口。","保存着螺钿镶嵌家具、水晶吊灯等众多珍贵古董。","烧钞票煮鸡蛋、拥有私人飞机的轶事已成传奇。"],"travelTips":["聘请现场导游，完整聆听关于公子的有趣轶事。","可入住宅邸内的酒店，体验昔日的氛围。"],"bestTime":"全年，11月至4月旱季最为凉爽","visitDuration":"1小时","ticket":"30,000越南盾","openingHours":"每日07:00 - 17:30","galleryCaptions":["西式建筑风格的古宅邸","雕饰精美的名贵木器内饰","价值连城的螺钿古董"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ca-mau-mui-ca-mau', 'mui-ca-mau', 'ca-mau', 'Mũi Cà Mau', 'Ca Mau Cape', 'park', 104.7233, 8.6, 'Điểm cực Nam thiêng liêng của Tổ quốc, nơi đất rừng ngập mặn lấn biển và mặt trời mọc lặn cùng nhìn thấy.', 'Mũi Cà Mau là vùng đất cực Nam thiêng liêng của Tổ quốc, điểm mà mỗi người Việt đều mong một lần đặt chân tới. Nằm trong vườn quốc gia Mũi Cà Mau, khu Ramsar và dự trữ sinh quyển thế giới, nơi đây là vùng đất bãi bồi liên tục lấn ra biển nhờ phù sa, với rừng đước, rừng mắm ngập mặn xanh thẳm. Du khách check-in bên cột mốc tọa độ quốc gia hình con tàu, đứng trên đài quan sát phóng tầm mắt ra biển Đông và vịnh Thái Lan, nơi hiếm hoi có thể ngắm cả bình minh lẫn hoàng hôn trên biển. Đi cano xuyên rừng ngập mặn, thưởng thức cua, ba khía, ốc len tươi rói, du khách cảm nhận trọn vẹn vẻ hoang sơ và niềm tự hào nơi chót mũi đất nước.', '["Là điểm cực Nam trên đất liền của Việt Nam, thuộc vườn quốc gia Mũi Cà Mau.","Được công nhận là khu Ramsar và khu dự trữ sinh quyển thế giới.","Vùng bãi bồi liên tục lấn ra biển nhờ phù sa, mỗi năm thêm vài chục mét.","Nơi hiếm hoi có thể ngắm cả mặt trời mọc và lặn trên biển trong cùng một ngày."]', '["Check-in cột mốc tọa độ quốc gia và biểu tượng con tàu Mũi Cà Mau.","Đi cano xuyên rừng ngập mặn và thưởng thức hải sản tươi như cua, ba khía."]', 'Tháng 12 đến tháng 4, mùa khô biển êm thuận tiện đi lại', 'Nửa ngày', '50.000đ vào khu du lịch', '07:00 - 17:00 hằng ngày', '["unesco","verified","popular","trending"]', '["park","nature","photography","island"]', '[{"seed":"muicamau-landmark","caption":"Cột mốc tọa độ quốc gia cực Nam","ratio":"16/9"},{"seed":"muicamau-mangrove","caption":"Rừng đước ngập mặn xanh thẳm","ratio":"4/3"},{"seed":"muicamau-ship","caption":"Biểu tượng con tàu nơi chót mũi","ratio":"1/1"}]', '["ca-mau-rung-u-minh-ha"]', 1, '{"en":{"name":"Ca Mau Cape","summary":"The sacred southernmost point of the country, where mangrove forest pushes into the sea and sunrise and sunset are both visible.","story":"Ca Mau Cape is the sacred southernmost point of the country, a place every Vietnamese hopes to set foot on at least once. Within Mui Ca Mau National Park, a Ramsar site and world biosphere reserve, it is a tidal flat continuously pushing out to sea on alluvium, with deep-green mangrove forests of rhizophora and avicennia. Visitors check in by the ship-shaped national coordinate marker, stand on the observation deck and gaze out over the East Sea and the Gulf of Thailand, one of the rare places where you can watch both sunrise and sunset over the sea. Riding a speedboat through the mangroves and savoring fresh crab, ba khia and len snails, visitors fully feel the wild beauty and the pride of standing at the very tip of the country.","facts":["It is Vietnam''s southernmost point on the mainland, within Mui Ca Mau National Park.","It is recognized as a Ramsar site and a world biosphere reserve.","The tidal flat continuously pushes out to sea on alluvium, gaining dozens of meters each year.","It is a rare place where you can watch both sunrise and sunset over the sea in a single day."],"travelTips":["Check in at the national coordinate marker and the ship symbol of Ca Mau Cape.","Ride a speedboat through the mangroves and enjoy fresh seafood like crab and ba khia."],"bestTime":"December to April, the dry season with calm seas convenient for getting around","visitDuration":"Half a day","ticket":"50,000 VND to enter the tourist area","openingHours":"07:00 - 17:00 daily","galleryCaptions":["The southernmost national coordinate marker","Deep-green mangrove rhizophora forest","The ship symbol at the very tip of the cape"]},"ko":{"name":"까마우곶","summary":"맹그로브 숲이 바다로 뻗어 나가고 일출과 일몰을 함께 볼 수 있는 조국의 성스러운 최남단.","story":"까마우곶은 베트남 사람이라면 누구나 한 번쯤 발을 디뎌 보고 싶어 하는 조국의 성스러운 최남단입니다. 람사르 습지이자 세계 생물권보전지역인 무이까마우 국립공원 안에 자리한 이곳은, 충적토 덕분에 끊임없이 바다로 뻗어 나가는 갯벌이며 짙푸른 리조포라·아비센니아 맹그로브 숲이 우거져 있습니다. 여행객은 배 모양의 국가 좌표 표지석 옆에서 인증샷을 찍고, 전망대에 올라 동해(비엔동)와 타이만을 바라보는데, 이곳은 바다 위로 일출과 일몰을 모두 볼 수 있는 드문 곳입니다. 스피드보트로 맹그로브 숲을 누비고 싱싱한 게, 바키아, 렌 고둥을 맛보며, 여행객은 야성적인 아름다움과 국토 맨 끝에 선 자부심을 온전히 느낍니다.","facts":["무이까마우 국립공원에 속한, 베트남 본토 최남단입니다.","람사르 습지이자 세계 생물권보전지역으로 인정받았습니다.","충적토 덕분에 끊임없이 바다로 뻗어 나가며, 매년 수십 미터씩 늘어납니다.","하루에 바다 위로 일출과 일몰을 모두 볼 수 있는 드문 곳입니다."],"travelTips":["국가 좌표 표지석과 까마우곶의 배 상징물에서 인증샷을 찍으세요.","스피드보트로 맹그로브 숲을 누비고 게, 바키아 같은 싱싱한 해산물을 즐기세요."],"bestTime":"12~4월, 바다가 잔잔해 이동이 편한 건기","visitDuration":"반나절","ticket":"관광지 입장 50,000동","openingHours":"매일 07:00 - 17:00","galleryCaptions":["최남단 국가 좌표 표지석","짙푸른 리조포라 맹그로브 숲","곶 맨 끝의 배 상징물"]},"ja":{"name":"カマウ岬","summary":"マングローブ林が海へ延び、日の出と日の入りをともに望める祖国の聖なる最南端。","story":"カマウ岬はベトナム人なら誰もが一度は足を踏み入れたいと願う祖国の聖なる最南端です。ラムサール条約湿地かつ世界生物圏保存地域であるムイカマウ国立公園内にあり、沖積土のおかげで絶えず海へ延びる干潟であり、深緑のオヒルギ・ヒルギダマシのマングローブ林が茂ります。旅人は船形の国家座標標識の傍らで写真を撮り、展望台に登って東海（ビエンドン）とタイランド湾を眺めます。ここは海上に日の出と日の入りの両方を望める稀な場所です。スピードボートでマングローブ林を巡り、新鮮なカニ、バーキア、レン貝を味わいながら、旅人は野性的な美しさと国土の最果てに立つ誇りを存分に感じます。","facts":["ムイカマウ国立公園にある、ベトナム本土の最南端です。","ラムサール条約湿地かつ世界生物圏保存地域として認定されています。","沖積土のおかげで絶えず海へ延び、毎年数十メートルずつ広がります。","一日のうちに海上に日の出と日の入りの両方を望める稀な場所です。"],"travelTips":["国家座標標識とカマウ岬の船の象徴で写真を撮りましょう。","スピードボートでマングローブ林を巡り、カニやバーキアなど新鮮なシーフードを楽しみましょう。"],"bestTime":"12〜4月、海が穏やかで移動しやすい乾季","visitDuration":"半日","ticket":"観光地入場50,000ドン","openingHours":"毎日07:00 - 17:00","galleryCaptions":["最南端の国家座標標識","深緑のオヒルギのマングローブ林","岬の最果ての船の象徴"]},"zh":{"name":"金瓯角","summary":"祖国神圣的最南端，红树林向海延伸，日出与日落皆可同时望见。","story":"金瓯角是祖国神圣的最南端，每个越南人都渴望一生至少踏足一次。它位于金瓯角国家公园内——拉姆萨尔湿地兼世界生物圈保护区，是一片靠淤泥不断向海延伸的滩涂，水笔仔、海榄雌红树林郁郁葱葱。游客在船形的国家坐标标志旁打卡，登上观景台远眺东海与泰国湾，这里是难得能同时观赏海上日出与日落的地方。乘快艇穿行红树林，品尝新鲜的螃蟹、相手蟹、笋螺，游客尽情感受国土最南端的原始之美与自豪。","facts":["是越南陆地最南端，属金瓯角国家公园。","被列为拉姆萨尔湿地和世界生物圈保护区。","靠淤泥不断向海延伸的滩涂，每年增加数十米。","是难得能在同一天观赏海上日出与日落的地方。"],"travelTips":["在国家坐标标志和金瓯角的船形标志处打卡。","乘快艇穿行红树林，品尝螃蟹、相手蟹等新鲜海鲜。"],"bestTime":"12月至4月，海面平静、出行便利的旱季","visitDuration":"半天","ticket":"进入景区50,000越南盾","openingHours":"每日07:00 - 17:00","galleryCaptions":["最南端的国家坐标标志","郁郁葱葱的水笔仔红树林","最南端的船形标志"]}}');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured, i18n) VALUES ('ca-mau-rung-u-minh-ha', 'rung-u-minh-ha', 'ca-mau', 'Rừng U Minh Hạ', 'U Minh Ha Forest', 'park', 104.9667, 9.3167, 'Rừng tràm nguyên sinh trên đất than bùn nổi tiếng với mật ong rừng, cá đồng và hệ sinh thái độc đáo.', 'Rừng U Minh Hạ là cánh rừng tràm ngập nước nổi tiếng của Cà Mau, được công nhận là vườn quốc gia và nằm trong khu dự trữ sinh quyển thế giới. Đặc trưng của U Minh Hạ là lớp đất than bùn dày, nước có màu đỏ nâu như nước trà, nuôi dưỡng rừng tràm bạt ngàn cùng hệ động thực vật phong phú. Đây là vùng đất gắn với nghề gác kèo ong lấy mật truyền thống, với những giọt mật vàng óng thơm lừng nức tiếng. Du khách đi xuồng len qua rừng tràm tĩnh lặng, ngắm chim, câu cá đồng và thưởng thức đặc sản dân dã như cá lóc nướng trui, lươn um, mật ong rừng. U Minh Hạ là nơi cảm nhận trọn vẹn vẻ đẹp hoang sơ và đời sống mộc mạc của vùng đất phương Nam.', '["Vườn quốc gia rừng tràm trên đất than bùn, thuộc khu dự trữ sinh quyển thế giới.","Nước rừng có màu đỏ nâu như nước trà do ngấm chất từ lớp than bùn.","Nổi tiếng với nghề gác kèo ong lấy mật truyền thống lâu đời.","Hệ sinh thái phong phú với nhiều loài chim, cá đồng và động vật quý hiếm."]', '["Thử trải nghiệm ăn ong rừng và mua mật ong nguyên chất làm quà.","Đi xuồng xuyên rừng vào mùa khô để câu cá và thưởng thức ẩm thực đồng quê."]', 'Tháng 12 đến tháng 4, mùa khô thuận tiện đi rừng và bắt cá', 'Nửa ngày', '30.000đ', '07:00 - 17:00 hằng ngày', '["verified","hidden-gem","ai-recommended"]', '["park","nature","food","photography"]', '[{"seed":"uminh-tram","caption":"Rừng tràm nguyên sinh trên đất than bùn","ratio":"16/9"},{"seed":"uminh-honey","caption":"Nghề gác kèo ong lấy mật truyền thống","ratio":"4/3"},{"seed":"uminh-fishing","caption":"Câu cá đồng giữa rừng tràm","ratio":"1/1"}]', '["ca-mau-mui-ca-mau"]', 0, '{"en":{"name":"U Minh Ha Forest","summary":"A primeval cajuput forest on peat soil, famous for wild honey, field fish and a unique ecosystem.","story":"U Minh Ha Forest is a famous flooded cajuput forest of Ca Mau, recognized as a national park and part of a world biosphere reserve. U Minh Ha is defined by its thick layer of peat soil and tea-colored reddish-brown water, which nourishes a vast cajuput forest and rich wildlife. This is a land tied to the traditional craft of beam-hanging beekeeping, with golden, fragrant honey famed far and wide. Visitors ride boats through the silent cajuput forest, watch birds, fish for field catch and savor rustic specialties such as grilled snakehead, braised eel and wild honey. U Minh Ha is the place to fully feel the wild beauty and simple life of the southern land.","facts":["It is a cajuput national park on peat soil, part of a world biosphere reserve.","The forest water is tea-colored reddish-brown from the peat layer leaching into it.","It is famous for the long-standing traditional craft of beam-hanging beekeeping.","Its rich ecosystem holds many species of bird, field fish and rare animals."],"travelTips":["Try the experience of harvesting wild honey and buy pure honey as a gift.","Ride a boat through the forest in the dry season to fish and enjoy country cuisine."],"bestTime":"December to April, the dry season convenient for forest trips and fishing","visitDuration":"Half a day","ticket":"30,000 VND","openingHours":"07:00 - 17:00 daily","galleryCaptions":["Primeval cajuput forest on peat soil","The traditional craft of beam-hanging beekeeping","Fishing for field catch amid the cajuput forest"]},"ko":{"name":"우민하 숲","summary":"야생 꿀, 민물고기, 독특한 생태계로 유명한 토탄 위의 원시 멜라루카 숲.","story":"우민하 숲은 까마우의 이름난 침수 멜라루카 숲으로, 국립공원으로 지정되었고 세계 생물권보전지역에 속합니다. 우민하의 특징은 두꺼운 토탄층과 차처럼 적갈색을 띠는 물로, 드넓은 멜라루카 숲과 풍부한 야생을 길러 냅니다. 이곳은 막대를 걸어 꿀을 얻는 전통 양봉업과 얽힌 땅으로, 황금빛 향긋한 꿀 방울이 멀리까지 이름났습니다. 여행객은 고요한 멜라루카 숲 사이를 배로 누비며 새를 관찰하고 민물고기를 낚으며, 가물치 구이, 장어 조림, 야생 꿀 같은 소박한 특산물을 맛봅니다. 우민하는 남부 땅의 야성적인 아름다움과 소박한 삶을 온전히 느끼는 곳입니다.","facts":["토탄 위의 멜라루카 국립공원으로, 세계 생물권보전지역에 속합니다.","숲의 물은 토탄층 성분이 스며들어 차처럼 적갈색을 띱니다.","오랜 전통의 막대 걸이 양봉업으로 유명합니다.","풍부한 생태계에 여러 새, 민물고기, 희귀 동물이 서식합니다."],"travelTips":["야생 꿀 채취를 체험해 보고 순수한 꿀을 선물용으로 구입하세요.","건기에 배로 숲을 누비며 낚시를 하고 시골 음식을 즐기세요."],"bestTime":"12~4월, 숲 탐방과 낚시가 편한 건기","visitDuration":"반나절","ticket":"30,000동","openingHours":"매일 07:00 - 17:00","galleryCaptions":["토탄 위의 원시 멜라루카 숲","막대를 걸어 꿀을 얻는 전통 양봉업","멜라루카 숲에서 민물고기 낚기"]},"ja":{"name":"ウーミンハー林","summary":"野生の蜂蜜、田の魚、独特な生態系で有名な泥炭土の上の原生メラルーカ林。","story":"ウーミンハー林はカマウの名高い冠水メラルーカ林で、国立公園に指定され世界生物圏保存地域に含まれます。ウーミンハーの特徴は厚い泥炭層と、茶のような赤褐色の水で、広大なメラルーカ林と豊かな野生を育みます。ここは棒を掛けて蜂蜜を採る伝統的な養蜂業と結びついた地で、黄金色の香り高い蜂蜜の滴が遠くまで名高いものです。旅人は静かなメラルーカ林の間を舟で巡り、野鳥を観察し田の魚を釣り、雷魚の炙り、鰻の煮込み、野生の蜂蜜など素朴な特産品を味わいます。ウーミンハーは南部の地の野性的な美しさと素朴な暮らしを存分に感じる場所です。","facts":["泥炭土の上のメラルーカ国立公園で、世界生物圏保存地域に含まれます。","林の水は泥炭層の成分が染み出し、茶のような赤褐色を帯びます。","古くからの伝統的な棒掛け養蜂業で有名です。","豊かな生態系に、多くの鳥、田の魚、希少な動物が生息します。"],"travelTips":["野生の蜂蜜採りを体験し、純粋な蜂蜜を土産に買いましょう。","乾季に舟で林を巡り、釣りをして田舎料理を楽しみましょう。"],"bestTime":"12〜4月、林の散策と釣りに便利な乾季","visitDuration":"半日","ticket":"30,000ドン","openingHours":"毎日07:00 - 17:00","galleryCaptions":["泥炭土の上の原生メラルーカ林","棒を掛けて蜂蜜を採る伝統的な養蜂業","メラルーカ林で田の魚を釣る"]},"zh":{"name":"下游民森林","summary":"泥炭地上的原始白千层林，以野生蜂蜜、田鱼和独特的生态系统闻名。","story":"下游民森林是金瓯著名的水淹白千层林，被列为国家公园，并属世界生物圈保护区。下游民的特色在于厚厚的泥炭层和茶色般的红褐色水，滋养着茫茫白千层林和丰富的动植物。这里与传统的搭架养蜂取蜜技艺紧密相连，金黄香浓的蜜滴远近闻名。游客坐船穿行寂静的白千层林，观鸟、钓田鱼，品尝烤雷鱼、焖黄鳝、野生蜂蜜等乡土特产。下游民是尽情感受南方大地原始之美与质朴生活的地方。","facts":["是泥炭地上的白千层国家公园，属世界生物圈保护区。","林中之水因泥炭层渗出物质而呈茶色般的红褐色。","以历史悠久的传统搭架养蜂取蜜技艺闻名。","生态丰富，栖息着多种鸟类、田鱼和珍稀动物。"],"travelTips":["体验取野生蜂蜜，购买纯正蜂蜜作伴手礼。","在旱季坐船穿林，钓鱼并品尝乡村美食。"],"bestTime":"12月至4月，便于穿林捕鱼的旱季","visitDuration":"半天","ticket":"30,000越南盾","openingHours":"每日07:00 - 17:00","galleryCaptions":["泥炭地上的原始白千层林","传统的搭架养蜂取蜜技艺","在白千层林中钓田鱼"]}}');
PRAGMA foreign_keys = ON;
